#[tauri::command(rename_all = "snake_case")]
async fn cloud_mcp_create_loopspace_trigger(
    state: State<'_, CloudMcpState>,
    name: String,
    trigger_type: String,
    loopspace_ids: Option<Vec<String>>,
    config: Option<Value>,
    enabled: Option<bool>,
    webhook_auth_mode: Option<String>,
    webhook_signature_tolerance_sec: Option<i64>,
    public_webhook_confirmed: Option<bool>,
) -> Result<Value, String> {
    let name = name.trim().chars().take(120).collect::<String>();
    if name.is_empty() {
        return Err("Trigger name is required.".to_string());
    }
    let trigger_type = trigger_type.trim().to_ascii_lowercase();
    if !matches!(trigger_type.as_str(), "cron" | "webhook" | "manual") {
        return Err("Trigger type must be cron, webhook, or manual.".to_string());
    }
    let webhook_auth_mode = if trigger_type == "webhook" {
        let mode = cloud_mcp_normalize_webhook_auth_mode(webhook_auth_mode.as_deref())?
            .unwrap_or_else(|| "signed_hmac".to_string());
        if mode == "public_token" && !public_webhook_confirmed.unwrap_or(false) {
            return Err("Creating a public webhook requires explicit confirmation.".to_string());
        }
        Some(mode)
    } else {
        None
    };
    let mut config = cloud_mcp_loopspace_trigger_config_for_command(config, Some(&trigger_type));
    if trigger_type == "cron" {
        if let Some(object) = config.as_object_mut() {
            object
                .entry("schedule".to_string())
                .or_insert_with(|| json!("@every 5m"));
        }
    }
    let loopspace_ids = cloud_mcp_loopspace_trigger_ids_for_command(loopspace_ids);
    let client_request_id = format!(
        "loopspace-trigger-create-{}-{}",
        cloud_mcp_now_ms(),
        uuid::Uuid::new_v4()
    );
    let mut payload =
        cloud_mcp_loopspace_trigger_request_base("commit", "loopspace_trigger_create");
    if let Some(object) = payload.as_object_mut() {
        object.insert("pid".to_string(), json!(client_request_id.clone()));
        object.insert(
            "client_request_id".to_string(),
            json!(client_request_id.clone()),
        );
        object.insert(
            "ops".to_string(),
            json!([{
                "op": "create",
                "type": trigger_type,
                "trigger_type": trigger_type,
                "name": name,
                "enabled": enabled.unwrap_or(true),
                "loopspace_ids": loopspace_ids,
                "config": config,
                "idempotency_key": client_request_id,
            }]),
        );
        if trigger_type == "webhook" {
            if let Some(ops) = object.get_mut("ops").and_then(Value::as_array_mut) {
                if let Some(op) = ops.first_mut().and_then(Value::as_object_mut) {
                    if let Some(mode) = webhook_auth_mode.as_deref() {
                        op.insert("webhook_auth_mode".to_string(), json!(mode));
                    }
                    if let Some(tolerance) = webhook_signature_tolerance_sec {
                        op.insert(
                            "webhook_signature_tolerance_sec".to_string(),
                            json!(tolerance.clamp(30, 86_400)),
                        );
                    }
                }
            }
        }
    }
    cloud_mcp_send_loopspace_trigger_mutation(state.inner(), payload, "loopspace_trigger_create")
        .await
}

#[tauri::command(rename_all = "snake_case")]
async fn cloud_mcp_update_loopspace_trigger(
    state: State<'_, CloudMcpState>,
    trigger_id: String,
    name: Option<String>,
    enabled: Option<bool>,
    loopspace_ids: Option<Vec<String>>,
    config: Option<Value>,
    rotate_secret: Option<bool>,
    webhook_auth_mode: Option<String>,
    webhook_signature_tolerance_sec: Option<i64>,
    public_webhook_confirmed: Option<bool>,
) -> Result<Value, String> {
    let trigger_id = trigger_id.trim().to_string();
    if trigger_id.is_empty() {
        return Err("Trigger id is required.".to_string());
    }
    let mut op = json!({
        "op": "update",
        "id": trigger_id,
        "trigger_id": trigger_id,
    });
    let mut changed = false;
    if let Some(name) = name {
        let name = name.trim().chars().take(120).collect::<String>();
        if name.is_empty() {
            return Err("Trigger name is required.".to_string());
        }
        op["name"] = json!(name);
        changed = true;
    }
    if let Some(enabled) = enabled {
        op["enabled"] = json!(enabled);
        changed = true;
    }
    if let Some(loopspace_ids) = loopspace_ids {
        let loopspace_ids = cloud_mcp_loopspace_trigger_ids_for_command(Some(loopspace_ids));
        op["loopspace_ids"] = json!(loopspace_ids);
        changed = true;
    }
    if let Some(config) = config {
        op["config"] = cloud_mcp_loopspace_trigger_config_for_command(Some(config), None);
        changed = true;
    }
    if rotate_secret.unwrap_or(false) {
        op["rotate_secret"] = json!(true);
        changed = true;
    }
    if let Some(mode) = cloud_mcp_normalize_webhook_auth_mode(webhook_auth_mode.as_deref())? {
        if mode == "public_token" && !public_webhook_confirmed.unwrap_or(false) {
            return Err(
                "Switching to a public webhook requires explicit confirmation.".to_string(),
            );
        }
        op["webhook_auth_mode"] = json!(mode);
        changed = true;
    }
    if let Some(tolerance) = webhook_signature_tolerance_sec {
        op["webhook_signature_tolerance_sec"] = json!(tolerance.clamp(30, 86_400));
        changed = true;
    }
    if !changed {
        return Err("No trigger changes were provided.".to_string());
    }
    let client_request_id = format!(
        "loopspace-trigger-update-{}-{}",
        cloud_mcp_now_ms(),
        uuid::Uuid::new_v4()
    );
    op["idempotency_key"] = json!(client_request_id.clone());
    let mut payload =
        cloud_mcp_loopspace_trigger_request_base("commit", "loopspace_trigger_update");
    if let Some(object) = payload.as_object_mut() {
        object.insert("pid".to_string(), json!(client_request_id.clone()));
        object.insert("client_request_id".to_string(), json!(client_request_id));
        object.insert("ops".to_string(), json!([op]));
    }
    cloud_mcp_send_loopspace_trigger_mutation(state.inner(), payload, "loopspace_trigger_update")
        .await
}

