fn cloud_mcp_account_sync_resume_todo_domain(reason: &str) -> Value {
    let (scope_key, account_id, last_applied_seq, cursor) = match cloud_mcp_open_todo_mirror_conn()
        .and_then(|conn| {
            let scope_key = cloud_mcp_current_account_todo_scope_key();
            cloud_mcp_account_todo_sync_state_from_conn(&conn, &scope_key, "").map(|sync_state| {
                (
                    scope_key,
                    String::new(),
                    sync_state.last_applied_seq,
                    sync_state.cursor,
                )
            })
        }) {
        Ok(value) => value,
        Err(error) => {
            log_cloud_sync_event(
                "account_sync_resume.todo_state_error",
                json!({
                    "reason": reason,
                    "error": clean_terminal_telemetry_text(&error),
                }),
            );
            (
                cloud_mcp_current_account_todo_scope_key(),
                String::new(),
                0,
                String::new(),
            )
        }
    };
    let device_profile = cloud_mcp_desktop_device_profile();
    json!({
        "c": "todo.sync",
        "m": if last_applied_seq > 0 { "delta" } else { "hello" },
        "v": 1,
        "contract": "diffforge.todo.live_state.v1",
        "aseq": last_applied_seq,
        "dseq": 0,
        "cursor": cursor,
        "did": device_profile["device_id"].clone(),
        "device_id": device_profile["device_id"].clone(),
        "scope_key": scope_key,
        "account_id": account_id,
        "lim": 500,
        "reason": reason,
        "source": "rust-diffforge-account-sync-resume",
    })
}

async fn cloud_mcp_account_sync_resume_payload(reason: &str) -> Value {
    let asset_have = tauri::async_runtime::spawn_blocking(cloud_mcp_asset_library_local_have_refs)
        .await
        .unwrap_or_default();
    let identity = cloud_mcp_account_sync_identity();
    let install_id = cloud_mcp_payload_text(&identity, &["install_id"])
        .unwrap_or_else(|| "rust-install-unknown".to_string());
    let store_epoch = cloud_mcp_payload_i64(&identity, &["store_epoch"])
        .unwrap_or(1)
        .max(1);
    let mut assets = json!({
        "asset_scope": "account",
        "compact": true,
        "event_based": true,
        "h": asset_have,
        "limit": 500,
        "reason": reason,
        "source": "rust-diffforge-account-sync-resume",
    });
    if let Some(sync_cursor) = cloud_mcp_asset_library_local_sync_cursor() {
        if let Some(object) = assets.as_object_mut() {
            object.insert("since_sync_cursor".to_string(), json!(sync_cursor.clone()));
            object.insert("sync_cursor".to_string(), json!(sync_cursor));
        }
    }
    if let Some(object) = assets.as_object_mut() {
        let store_empty = object
            .get("h")
            .and_then(Value::as_array)
            .map(|rows| rows.is_empty())
            .unwrap_or(true)
            && object.get("sync_cursor").is_none();
        object.insert("store_empty".to_string(), json!(store_empty));
    }
    let device_profile = cloud_mcp_desktop_device_profile();
    let mut todo_domain = cloud_mcp_account_sync_resume_todo_domain(reason);
    let todo_store_empty = cloud_mcp_payload_i64(&todo_domain, &["aseq"]).unwrap_or(0) <= 0
        && cloud_mcp_payload_text(&todo_domain, &["cursor"])
            .unwrap_or_default()
            .trim()
            .is_empty();
    if let Some(object) = todo_domain.as_object_mut() {
        object.insert("store_empty".to_string(), json!(todo_store_empty));
    }
    let loopspaces_domain = cloud_mcp_loopspace_sync_resume_domain(reason);
    let loopspace_triggers_domain = cloud_mcp_loopspace_trigger_sync_resume_domain(reason);
    let documents_have = cloud_mcp_account_document_have_refs();
    let documents_store_empty = documents_have.is_empty();
    json!({
    "kind": "account_sync_resume",
    "contract": "diffforge.account_sync.v1",
    "source": "rust-diffforge",
    "reason": reason,
    "install_id": install_id,
    "store_epoch": store_epoch,
    "device": device_profile.clone(),
    "device_id": device_profile["device_id"].clone(),
    "domains": {
        "todos": todo_domain,
        "loopspaces": loopspaces_domain,
        "loopspace_triggers": loopspace_triggers_domain,
        "documents": {
            "c": "doc.sync",
            "d": "documents",
            "contract": CLOUD_MCP_ACCOUNT_DOCUMENTS_CONTRACT,
            "m": "delta",
            "v": 1,
            "h": documents_have,
            "store_empty": documents_store_empty,
            "reason": reason,
            "source": "rust-diffforge-account-sync-resume",
        },
        "assets": assets,
        "clis": { "enabled": true },
        "mcps": { "enabled": true },
    }})
}

async fn cloud_mcp_apply_account_sync_resume_response(
    state: &CloudMcpState,
    response: &Value,
    reason: &str,
) {
    if let Some(todos) =
        cloud_mcp_account_sync_resume_domain(response, &["todos", "todo", "account_todos"])
    {
        match cloud_mcp_apply_account_todo_inbound_event(state, "todo.live_state", &todos).await {
            Ok(result) => {
                let reconciliation_commits =
                    todo_store_account_resume_reconciliation_commits(&todos);
                let mut reconciliation_items = 0usize;
                for commit in reconciliation_commits {
                    reconciliation_items = reconciliation_items.saturating_add(commit.item_count);
                    let response = cloud_mcp_enqueue_workspace_todo_sync_commit(
                        state,
                        commit.payload,
                        "account_sync_resume_authoritative_reconcile",
                    )
                    .await;
                    log_cloud_sync_event(
                        "account_sync_resume.todo_authoritative_reconcile_queued",
                        json!({
                            "item_count": commit.item_count,
                            "operation": commit.operation,
                            "response": response,
                            "workspace_id": commit.workspace_id,
                        }),
                    );
                }
                let _ =
                    cloud_mcp_send_account_todo_delta_ack(state, &result, "account_sync_resume")
                        .await;
                log_cloud_sync_event(
                    "account_sync_resume.todos_ok",
                    json!({
                        "reason": reason,
                        "applied": result.applied,
                        "deleted": result.deleted,
                        "highest_seq": result.highest_seq,
                        "cursor": result.cursor,
                        "reconciliation_items": reconciliation_items,
                    }),
                );
            }
            Err(error) => {
                log_cloud_sync_event(
                    "account_sync_resume.todos_apply_error",
                    json!({
                        "reason": reason,
                        "error": clean_terminal_telemetry_text(&error),
                    }),
                );
            }
        }
    }
    if let Some(assets) =
        cloud_mcp_account_sync_resume_domain(response, &["assets", "asset", "account_assets"])
    {
        cloud_mcp_update_asset_library_from_response(
            "account_sync_resume_assets",
            Some("/v1/events"),
            &json!({"asset_scope": "account"}),
            &assets,
        );
        let _ = state
            .global_ws_events
            .send(cloud_mcp_account_asset_local_projection_event(reason));
    }
    if let Some(loopspaces) =
        cloud_mcp_account_sync_resume_domain(response, &["loopspaces", "loops", "loop_spaces"])
    {
        match cloud_mcp_apply_loopspaces_sync_data(state, &loopspaces, "account_sync_resume").await
        {
            Ok(snapshot) => {
                let _ = state.global_ws_events.send(json!({
                    "kind": "loopspaces.sync",
                    "event_kind": "loopspaces.sync",
                    "contract": CLOUD_MCP_LOOPSPACES_CONTRACT,
                    "reason": reason,
                    "payload": snapshot,
                }));
            }
            Err(error) => {
                log_cloud_sync_event(
                    "account_sync_resume.loopspaces_apply_error",
                    json!({
                        "reason": reason,
                        "error": clean_terminal_telemetry_text(&error),
                    }),
                );
            }
        }
    }
    if let Some(loopspace_triggers) = cloud_mcp_account_sync_resume_domain(
        response,
        &["loopspace_triggers", "triggers", "loop_triggers"],
    ) {
        match cloud_mcp_apply_loopspace_triggers_sync_data(
            state,
            &loopspace_triggers,
            "account_sync_resume",
        )
        .await
        {
            Ok(snapshot) => {
                let _ = state.global_ws_events.send(json!({
                    "kind": "loopspace_triggers.sync",
                    "event_kind": "loopspace_triggers.sync",
                    "contract": CLOUD_MCP_LOOPSPACE_TRIGGERS_CONTRACT,
                    "reason": reason,
                    "payload": snapshot,
                }));
            }
            Err(error) => {
                log_cloud_sync_event(
                    "account_sync_resume.loopspace_triggers_apply_error",
                    json!({
                        "reason": reason,
                        "error": clean_terminal_telemetry_text(&error),
                    }),
                );
            }
        }
    }
    if let Some(documents) = cloud_mcp_account_sync_resume_domain(response, &["documents"]) {
        match cloud_mcp_apply_account_documents_sync_data_with_hydration(
            state,
            &documents,
            "account_sync_resume",
        )
        .await
        {
            Ok(snapshot) => {
                let _ = state.global_ws_events.send(json!({
                    "kind": "doc.sync",
                    "event_kind": "doc.sync",
                    "contract": CLOUD_MCP_ACCOUNT_DOCUMENTS_CONTRACT,
                    "c": "doc.sync",
                    "d": "documents",
                    "reason": reason,
                    "payload": snapshot,
                }));
            }
            Err(error) => {
                log_cloud_sync_event(
                    "account_sync_resume.documents_apply_error",
                    json!({
                        "reason": reason,
                        "error": clean_terminal_telemetry_text(&error),
                    }),
                );
            }
        }
    }
    for (payload, event_kind, contract) in [
        (
            cloud_mcp_account_sync_resume_domain(response, &["clis", "cli", "account_clis"]),
            "account_clis_snapshot",
            "diffforge.account_clis.v1",
        ),
        (
            cloud_mcp_account_sync_resume_domain(response, &["mcps", "mcp", "account_mcps"]),
            "account_mcps_snapshot",
            "diffforge.account_mcps.v1",
        ),
    ] {
        if let Some(payload) = payload {
            cloud_mcp_emit_initial_account_tools_snapshot(state, event_kind, contract, payload)
                .await;
        }
    }
}

async fn cloud_mcp_apply_account_sync_resume_remote_commands(
    state: &CloudMcpState,
    todos: &Value,
    reason: &str,
) {
    let events = [
        todos.get("remote_command_events"),
        todos.get("pending_remote_command_events"),
    ]
    .into_iter()
    .flatten()
    .filter_map(Value::as_array)
    .flat_map(|items| items.iter())
    .filter(|value| value.is_object())
    .cloned()
    .collect::<Vec<_>>();
    if events.is_empty() {
        return;
    }
    let Some(app) = CLOUD_MCP_SYNC_STATUS_APP.get().cloned() else {
        log_cloud_sync_event(
            "account_sync_resume.remote_commands_no_app",
            json!({
                "reason": reason,
                "count": events.len(),
            }),
        );
        return;
    };
    let mut applied = 0usize;
    let mut duplicate = 0usize;
    let mut skipped_device = 0usize;
    for event in events {
        if !cloud_mcp_remote_command_matches_device(&event) {
            skipped_device += 1;
            continue;
        }
        if cloud_mcp_handle_remote_command_cancel(state, &event).await {
            applied += 1;
            continue;
        }
        if cloud_mcp_remote_command_cancelled_before_receipt(state, &event).await {
            let _ = cloud_mcp_send_remote_command_status_event(
                state,
                &event,
                "cancelled",
                "Remote command was cancelled before desktop execution.",
                None,
            )
            .await;
            applied += 1;
            continue;
        }
        if !cloud_mcp_claim_remote_command_receipt(state, &event).await {
            duplicate += 1;
            cloud_mcp_ack_duplicate_remote_command(&app, state, &event).await;
            continue;
        }
        let _ = cloud_mcp_send_remote_command_status_event(
            state,
            &event,
            "received",
            "Remote command received by desktop.",
            None,
        )
        .await;
        let _ = app.emit(CLOUD_MCP_WORKSPACE_TODOS_UPDATED_EVENT, event.clone());
        let intake_outcome = todo_dispatch_record_remote_intake(&app, &event);
        if let Some(outcome) = intake_outcome.as_ref() {
            let status = cloud_mcp_payload_text(outcome, &["status"]).unwrap_or_default();
            let message = cloud_mcp_payload_text(outcome, &["message"]).unwrap_or_default();
            let details = outcome.get("details");
            let _ = cloud_mcp_send_remote_command_status_event(
                state, &event, &status, &message, details,
            )
            .await;
            cloud_mcp_ack_remote_todo_intake(state, &event, outcome).await;
        }
        let delete_outcome = todo_dispatch_apply_remote_delete(&app, &event);
        if let Some(outcome) = delete_outcome.as_ref() {
            let status = cloud_mcp_payload_text(outcome, &["status"]).unwrap_or_default();
            let message = cloud_mcp_payload_text(outcome, &["message"]).unwrap_or_default();
            let details = outcome.get("details");
            let _ = cloud_mcp_send_remote_command_status_event(
                state, &event, &status, &message, details,
            )
            .await;
            cloud_mcp_ack_remote_todo_delete(state, &event, outcome).await;
        }
        if crate::daemon_mode_active() && (intake_outcome.is_some() || delete_outcome.is_some()) {
            applied += 1;
            continue;
        }
        if cloud_mcp_apply_daemon_remote_command_guard(state, &event).await {
            applied += 1;
            continue;
        }
        let remote_lever_handled = cloud_mcp_apply_remote_workspace_lever(&app, state, &event)
            || orchestrator_pool_apply_remote_send_lever(&app, state, &event)
            || cloud_mcp_apply_remote_terminal_interrupt_lever(&app, state, &event)
            || cloud_mcp_apply_remote_terminal_lever(&app, state, &event)
            || cloud_mcp_apply_remote_agent_lever(&app, state, &event)
            || cloud_mcp_apply_remote_agent_prompt_lever(&app, state, &event)
            || cloud_mcp_apply_remote_asset_lever(&app, state, &event)
            || cloud_mcp_apply_remote_local_script_lever(&app, state, &event)
            || cloud_mcp_apply_remote_device_lever(&app, state, &event);
        if !remote_lever_handled && !cloud_mcp_remote_command_is_rust_owned(&event) {
            if crate::daemon_mode_active() {
                let details = json!({
                    "reason": "daemon_mode",
                    "daemon_mode": true,
                    "command_kind": cloud_mcp_remote_command_kind(&event),
                });
                let _ = cloud_mcp_send_remote_command_status_event(
                    state,
                    &event,
                    "failed",
                    "Remote command requires the desktop UI and is unavailable in daemon mode.",
                    Some(&details),
                )
                .await;
            } else {
                let _ = app.emit(CLOUD_MCP_REMOTE_COMMAND_EVENT, event.clone());
            }
        }
        applied += 1;
    }
    log_cloud_sync_event(
        "account_sync_resume.remote_commands_applied",
        json!({
            "reason": reason,
            "applied": applied,
            "duplicate": duplicate,
            "skipped_device": skipped_device,
        }),
    );
}

fn cloud_mcp_spawn_account_sync_resume(state: &CloudMcpState, reason: &'static str) {
    let state = state.clone();
    tauri::async_runtime::spawn(async move {
        let payload = cloud_mcp_account_sync_resume_payload(reason).await;
        match cloud_mcp_ws_request_with_timeout(
            &state,
            "account_sync_resume",
            &payload,
            Duration::from_secs(16),
        )
        .await
        {
            Ok(response) => {
                cloud_mcp_apply_account_sync_resume_response(&state, &response, reason).await;
                log_cloud_sync_event(
                    "account_sync_resume.ok",
                    json!({
                        "reason": reason,
                        "domains": response
                            .get("data")
                            .and_then(|data| data.get("domains"))
                            .and_then(Value::as_object)
                            .map(|domains| domains.keys().cloned().collect::<Vec<_>>())
                            .unwrap_or_default(),
                    }),
                );
            }
            Err(error) => {
                log_cloud_sync_event(
                    "account_sync_resume.error",
                    json!({
                        "reason": reason,
                        "error": clean_terminal_telemetry_text(&error),
                    }),
                );
            }
        }
    });
}

fn cloud_mcp_initial_account_snapshot(message: &Value, key: &str) -> Option<Value> {
    message.get(key).cloned().filter(|value| !value.is_null())
}

async fn cloud_mcp_emit_initial_account_tools_snapshot(
    state: &CloudMcpState,
    event_kind: &'static str,
    contract: &'static str,
    payload: Value,
) {
    let event = json!({
        "kind": event_kind,
        "event_kind": event_kind,
        "contract": contract,
        "reason": "global_ws_ready",
        "payload": payload,
    });
    let _ = state.global_ws_events.send(event);
}

fn cloud_mcp_chat_attachment_encoded_limit(decoded_bytes: usize) -> usize {
    decoded_bytes.saturating_add(2) / 3 * 4
}

fn cloud_mcp_chat_attachment_add_total(
    current_total: usize,
    image_bytes: usize,
) -> Result<usize, String> {
    let total = current_total.saturating_add(image_bytes);
    if total > CLOUD_MCP_CHAT_ATTACHMENT_MAX_TOTAL_BYTES {
        return Err("chat attachment images must total 20 MiB or less".to_string());
    }
    Ok(total)
}

fn cloud_mcp_decode_chat_attachment_push(
    message: &Value,
) -> Result<(String, Vec<ChatAttachmentPushImage>), String> {
    let request = message
        .get("request")
        .or_else(|| message.get("payload"))
        .ok_or_else(|| "chat_attachment_push request is missing".to_string())?;
    let workspace_id = cloud_mcp_payload_text(request, &["workspace_id"])
        .ok_or_else(|| {
            "chat_attachment_push workspace_id is missing; use __diffforge_app_control__ for orchestrator targets"
                .to_string()
        })?;
    let images = request
        .get("images")
        .and_then(Value::as_array)
        .ok_or_else(|| "chat_attachment_push images are missing".to_string())?;
    if images.is_empty() {
        return Err("chat_attachment_push requires at least one image".to_string());
    }
    if images.len() > CLOUD_MCP_CHAT_ATTACHMENT_MAX_IMAGES {
        return Err(format!(
            "chat_attachment_push accepts at most {CLOUD_MCP_CHAT_ATTACHMENT_MAX_IMAGES} images"
        ));
    }

    let mut decoded_images = Vec::with_capacity(images.len());
    let mut total_bytes = 0usize;
    for (image_index, image) in images.iter().enumerate() {
        let name = cloud_mcp_payload_text(image, &["name"])
            .ok_or_else(|| format!("chat attachment image {} name is missing", image_index + 1))?;
        let mime = cloud_mcp_payload_text(image, &["mime", "mime_type"])
            .map(|value| {
                value
                    .split(';')
                    .next()
                    .unwrap_or_default()
                    .trim()
                    .to_ascii_lowercase()
            })
            .unwrap_or_default();
        if !matches!(
            mime.as_str(),
            "image/png" | "image/jpeg" | "image/webp" | "image/gif"
        ) {
            return Err(format!(
                "chat attachment image {} must be PNG, JPEG, WebP, or GIF",
                image_index + 1
            ));
        }
        let sha256 = cloud_mcp_payload_text(image, &["sha256"])
            .unwrap_or_default()
            .to_ascii_lowercase();
        if sha256.len() != 64 || !sha256.bytes().all(|byte| byte.is_ascii_hexdigit()) {
            return Err(format!(
                "chat attachment image {} SHA-256 is invalid",
                image_index + 1
            ));
        }
        let declared_bytes = image
            .get("bytes")
            .and_then(Value::as_u64)
            .and_then(|value| usize::try_from(value).ok())
            .ok_or_else(|| {
                format!(
                    "chat attachment image {} decoded byte length is missing",
                    image_index + 1
                )
            })?;
        if declared_bytes == 0 || declared_bytes > CLOUD_MCP_CHAT_ATTACHMENT_MAX_IMAGE_BYTES {
            return Err(format!(
                "chat attachment image {} must be non-empty and no larger than 10 MiB",
                image_index + 1
            ));
        }
        let inline = image.get("base64").and_then(Value::as_str);
        let chunks = image.get("chunks").and_then(Value::as_array);
        if inline.is_some() == chunks.is_some() {
            return Err(format!(
                "chat attachment image {} must contain exactly one of base64 or chunks",
                image_index + 1
            ));
        }
        let encoded = if let Some(inline) = inline {
            if inline.is_empty() || inline.len() > CLOUD_MCP_CHAT_ATTACHMENT_MAX_INLINE_BASE64_CHARS
            {
                return Err(format!(
                    "chat attachment image {} inline base64 exceeds 1 MiB; use ordered chunks",
                    image_index + 1
                ));
            }
            inline.to_string()
        } else {
            let chunks = chunks.expect("chunks checked above");
            if chunks.is_empty() {
                return Err(format!(
                    "chat attachment image {} chunks are empty",
                    image_index + 1
                ));
            }
            if chunks.len() > CLOUD_MCP_CHAT_ATTACHMENT_MAX_CHUNKS_PER_IMAGE {
                return Err(format!(
                    "chat attachment image {} exceeds the limit of {CLOUD_MCP_CHAT_ATTACHMENT_MAX_CHUNKS_PER_IMAGE} chunks",
                    image_index + 1
                ));
            }
            let mut encoded = String::new();
            for (expected_index, chunk) in chunks.iter().enumerate() {
                let index = chunk.get("index").and_then(Value::as_u64);
                let total = chunk.get("total").and_then(Value::as_u64);
                let data = chunk.get("data").and_then(Value::as_str);
                if index != Some(expected_index as u64)
                    || total != Some(chunks.len() as u64)
                    || data.is_none()
                {
                    return Err(format!(
                        "chat attachment image {} chunks must be ordered, zero-based, contiguous, and share total={}",
                        image_index + 1,
                        chunks.len()
                    ));
                }
                let data = data.unwrap_or_default();
                if data.is_empty() || data.len() > CLOUD_MCP_CHAT_ATTACHMENT_MAX_CHUNK_BASE64_CHARS
                {
                    return Err(format!(
                        "chat attachment image {} chunk {} exceeds 512 KiB of base64 text",
                        image_index + 1,
                        expected_index
                    ));
                }
                if encoded.len().saturating_add(data.len())
                    > cloud_mcp_chat_attachment_encoded_limit(
                        CLOUD_MCP_CHAT_ATTACHMENT_MAX_IMAGE_BYTES,
                    )
                    .saturating_add(4)
                {
                    return Err(format!(
                        "chat attachment image {} exceeds 10 MiB decoded",
                        image_index + 1
                    ));
                }
                encoded.push_str(data);
            }
            encoded
        };
        if encoded.starts_with("data:") {
            return Err(format!(
                "chat attachment image {} must use raw base64 without a data URL prefix",
                image_index + 1
            ));
        }
        if encoded.trim().len() != encoded.len() {
            return Err(format!(
                "chat attachment image {} base64 must not contain surrounding whitespace",
                image_index + 1
            ));
        }
        let bytes = general_purpose::STANDARD
            .decode(encoded.as_bytes())
            .map_err(|_| {
                format!(
                    "chat attachment image {} contains invalid base64",
                    image_index + 1
                )
            })?;
        if bytes.len() != declared_bytes {
            return Err(format!(
                "chat attachment image {} decoded to {} bytes but declared {}",
                image_index + 1,
                bytes.len(),
                declared_bytes
            ));
        }
        if chat_attachment_sha256_hex(&bytes) != sha256 {
            return Err(format!(
                "chat attachment image {} SHA-256 did not match its bytes",
                image_index + 1
            ));
        }
        if chat_attachment_signature_mime(&bytes) != Some(mime.as_str()) {
            return Err(format!(
                "chat attachment image {} MIME did not match its bytes",
                image_index + 1
            ));
        }
        total_bytes = cloud_mcp_chat_attachment_add_total(total_bytes, bytes.len())?;
        decoded_images.push(ChatAttachmentPushImage {
            name,
            mime,
            sha256,
            bytes,
        });
    }
    Ok((workspace_id, decoded_images))
}

async fn cloud_mcp_receive_chat_attachment_push(message: &Value) -> Result<Value, String> {
    let (workspace_id, images) = cloud_mcp_decode_chat_attachment_push(message)?;
    let image_count = images.len();
    let total_bytes = images.iter().map(|image| image.bytes.len()).sum::<usize>();
    let stage_workspace_id = workspace_id.clone();
    let result = tauri::async_runtime::spawn_blocking(move || {
        stage_chat_attachment_push_images(&stage_workspace_id, images)
    })
    .await
    .map_err(|error| format!("chat attachment staging worker failed: {error}"))??;
    Ok(json!({
        "workspace_id": workspace_id,
        "image_count": image_count,
        "total_bytes": total_bytes,
        "staged": result.staged,
        "attachments": result.attachments,
        "marker_block": result.marker_block,
    }))
}

fn cloud_mcp_is_list_agent_models_request(
    message: &Value,
    direct_kind: &str,
    direct_request_kind: &str,
) -> bool {
    let normalize_kind = |value: &str| {
        value
            .trim()
            .to_ascii_lowercase()
            .replace(['.', ' ', '-'], "_")
    };
    let matches_list_agent_models = |value: &str| normalize_kind(value) == "list_agent_models";
    let matches_remote_command_requested =
        |value: &str| normalize_kind(value) == "remote_command_requested";
    let direct_matches =
        matches_list_agent_models(direct_kind) || matches_list_agent_models(direct_request_kind);
    let outer_kind = cloud_mcp_nested_payload_text(message, &["kind"])
        .unwrap_or_else(|| direct_kind.to_string());
    let outer_kind = normalize_kind(&outer_kind);
    let outer_is_cloud_event = outer_kind == "cloud_event";
    let outer_is_remote_command =
        outer_kind == "remote_command_requested" || matches_remote_command_requested(direct_kind);
    let event_kind = [
        cloud_mcp_nested_payload_text(message, &["event", "event_kind"]),
        cloud_mcp_nested_payload_text(message, &["event", "kind"]),
        cloud_mcp_nested_payload_text(message, &["payload", "event_kind"]),
        cloud_mcp_nested_payload_text(message, &["event_kind"]),
    ]
    .into_iter()
    .flatten()
    .next()
    .unwrap_or_default();
    let event_kind_is_list_agent_models =
        outer_is_cloud_event && matches_list_agent_models(&event_kind);
    let event_kind_is_remote_command_requested =
        matches_remote_command_requested(&event_kind) || outer_is_remote_command;
    let command_kind_is_list_agent_models =
        cloud_mcp_remote_command_field_text(message, &["command_kind"])
            .as_deref()
            .map(matches_list_agent_models)
            .unwrap_or(false);
    let is_request = direct_matches
        || event_kind_is_list_agent_models
        || ((outer_is_cloud_event || outer_is_remote_command)
            && event_kind_is_remote_command_requested
            && command_kind_is_list_agent_models);
    if !is_request {
        return false;
    }
    let target_device_id =
        cloud_mcp_remote_command_field_text(message, &["target_device_id"]).unwrap_or_default();
    target_device_id.trim().is_empty() || cloud_mcp_remote_command_matches_device(message)
}

fn cloud_mcp_nested_payload_text(payload: &Value, path: &[&str]) -> Option<String> {
    let mut current = payload;
    for key in path {
        current = current.get(*key)?;
    }
    current
        .as_str()
        .map(str::to_string)
        .filter(|value| !value.trim().is_empty())
}

fn cloud_mcp_list_agent_models_request_id(message: &Value) -> String {
    cloud_mcp_remote_command_field_text(message, &["request_id"])
        .or_else(|| cloud_mcp_payload_text(message, &["id"]))
        .unwrap_or_else(|| format!("agent-models-{}", uuid::Uuid::new_v4()))
}

fn cloud_mcp_agent_models_result_payload(
    request: &Value,
    agent_kind: &str,
    models: Vec<AgentModelCatalogEntry>,
    complete: bool,
    harness_version: Option<String>,
    error: Option<String>,
) -> Value {
    let request_id = cloud_mcp_list_agent_models_request_id(request);
    let mut payload = json!({
        "kind": "agent_models_result",
        "event_kind": "agent_models_result",
        "request_id": request_id,
        "source_request_id": cloud_mcp_payload_text(request, &["id"]).unwrap_or_default(),
        "agent_kind": agent_kind,
        "models": models,
        "complete": complete,
        "harness_version": harness_version.unwrap_or_default(),
        "workspace_id": cloud_mcp_remote_command_field_text(request, &["workspace_id"]).unwrap_or_default(),
        "target_device_id": cloud_mcp_remote_command_field_text(request, &["target_device_id"]).unwrap_or_default(),
        "target_terminal_id": cloud_mcp_remote_command_field_text(request, &["target_terminal_id", "terminal_id"]).unwrap_or_default(),
        "ts_ms": cloud_mcp_now_ms(),
    });
    if let Some(error) = error
        .map(|value| clean_terminal_telemetry_text(&value))
        .filter(|value| !value.trim().is_empty())
    {
        payload["error"] = json!(error);
    }
    payload
}

async fn cloud_mcp_send_agent_models_result(
    state: &CloudMcpState,
    source_request: &Value,
    payload: Value,
) -> Result<(), String> {
    let auth = cloud_mcp_ws_auth_object(state).await?;
    let envelope = cloud_mcp_agent_models_result_envelope(source_request, &payload, auth);
    let Some(tx) = state.global_ws_tx.lock().await.as_ref().cloned() else {
        return Err("Cloud MCP app websocket is not connected.".to_string());
    };
    tx.send(envelope)
        .map_err(|_| "Cloud MCP app websocket sender is closed.".to_string())
}

fn cloud_mcp_agent_models_result_envelope(
    source_request: &Value,
    payload: &Value,
    auth: Value,
) -> Value {
    let request = cloud_mcp_event_envelope("agent_models_result", payload);
    json!({
        "kind": "agent_models_result",
        "event_kind": "agent_models_result",
        "id": format!("agent-models-result-{}-{}", cloud_mcp_now_ms(), uuid::Uuid::new_v4()),
        "contract": "diffforge.app_ws.v1",
        "auth": auth,
        "client_id": CLOUD_MCP_RUST_CLIENT_ID,
        "request_id": payload.get("request_id").cloned().unwrap_or(Value::Null),
        "source_request_id": cloud_mcp_payload_text(source_request, &["id"]).unwrap_or_default(),
        "repo_id": cloud_mcp_payload_text(source_request, &["repo_id"])
            .or_else(|| cloud_mcp_payload_text(source_request, &["payload", "repo_id"]))
            .or_else(|| cloud_mcp_payload_text(&request, &["repo_id"]))
            .or_else(|| cloud_mcp_payload_text(&request, &["payload", "repo_id"])),
        "workspace_id": cloud_mcp_payload_text(source_request, &["workspace_id"])
            .or_else(|| cloud_mcp_payload_text(source_request, &["payload", "workspace_id"]))
            .or_else(|| cloud_mcp_payload_text(&request, &["workspace_id"]))
            .or_else(|| cloud_mcp_payload_text(&request, &["payload", "workspace_id"])),
        "payload": payload,
        "request": request,
    })
}

async fn cloud_mcp_handle_list_agent_models_request(state: CloudMcpState, request: Value) {
    let agent_kind = cloud_mcp_remote_command_field_text(&request, &["agent_kind"])
        .unwrap_or_default()
        .trim()
        .to_ascii_lowercase()
        .replace('-', "_");
    let payload = if agent_kind != "opencode" {
        cloud_mcp_agent_models_result_payload(
            &request,
            if agent_kind.is_empty() {
                "unknown"
            } else {
                agent_kind.as_str()
            },
            Vec::new(),
            false,
            None,
            Some("list_agent_models currently supports agent_kind opencode.".to_string()),
        )
    } else {
        let list = opencode_list_models(Some(false)).await;
        let models = opencode_model_catalog_entries_from_ids(&list.models, &list.source);
        let complete = list.error.is_none();
        cloud_mcp_agent_models_result_payload(
            &request,
            "opencode",
            models,
            complete,
            list.harness_version
                .clone()
                .or_else(opencode_current_harness_version),
            list.error.clone(),
        )
    };
    if let Err(error) = cloud_mcp_send_agent_models_result(&state, &request, payload).await {
        log_terminal_status_event(
            "backend.cloud_mcp.agent_models_result.send_failed",
            json!({ "error": clean_terminal_telemetry_text(&error) }),
        );
    }
}

async fn cloud_mcp_handle_global_ws_message(state: &CloudMcpState, text: &str) {
    let Ok(message) = serde_json::from_str::<Value>(text) else {
        return;
    };
    let message_kind = cloud_mcp_payload_text(&message, &["kind", "event_kind"])
        .unwrap_or_else(|| "message".to_string());
    cloud_mcp_store_ws_inbound(
        &message_kind,
        text.len() as u64,
        json!({
            "id": message.get("id").cloned().unwrap_or(Value::Null),
            "request_kind": message.get("request_kind").cloned().unwrap_or(Value::Null),
            "event_kind": message.get("event_kind").cloned().unwrap_or(Value::Null),
            "repo_id": message.get("repo_id").cloned().unwrap_or(Value::Null),
            "workspace_id": message.get("workspace_id").cloned().unwrap_or(Value::Null),
        }),
    );
    if message_kind == "pong" {
        CLOUD_MCP_WS_LAST_PONG_RECEIVED_MS.store(cloud_mcp_now_ms(), Ordering::Release);
        return;
    }
    if let Some((error_message, details)) = cloud_mcp_registration_blocked_error(&message) {
        cloud_mcp_mark_registration_blocked(state, error_message, details).await;
        return;
    }
    if message.get("kind").and_then(Value::as_str) == Some("cloud_app_ws_ready") {
        let connection_id = message["message_auth"]["connection_id"]
            .as_str()
            .or_else(|| message["connection_id"].as_str())
            .map(str::to_string);
        let message_token = message["message_auth"]["message_token"]
            .as_str()
            .map(str::to_string);
        let (Some(connection_id), Some(message_token)) = (connection_id, message_token) else {
            let mut runtime = state.inner.lock().await;
            runtime.connected = false;
            runtime.status = "websocket_auth_missing".to_string();
            runtime.global_ws_connected = false;
            runtime.global_ws_status = "auth_missing".to_string();
            runtime.global_ws_last_error =
                "Cloud MCP app websocket ready message omitted message auth.".to_string();
            drop(runtime);
            cloud_mcp_record_signin_diagnostic(
                state,
                "websocket.ready",
                "error",
                "Cloud MCP app websocket ready message omitted message auth.",
                json!({}),
            )
            .await;
            cloud_mcp_record_connection_diagnostic(
                state,
                "rust.cloud_mcp.websocket.ready",
                "error",
                "Cloud MCP app websocket ready message omitted message auth.",
                json!({
                    "client_identity": "appwrite_account",
                    "source_client_id": CLOUD_MCP_RUST_CLIENT_ID,
                }),
            )
            .await;
            return;
        };
        let initial_account_asset_state = message
            .get("initial_account_asset_state")
            .cloned()
            .filter(|value| !value.is_null());
        {
            let mut runtime = state.inner.lock().await;
            runtime.connected = false;
            runtime.status = "desktop_registering".to_string();
            runtime.last_error.clear();
            runtime.last_connected_ms = Some(cloud_mcp_now_ms());
            runtime.global_ws_connected = true;
            runtime.global_ws_status = "desktop_registering".to_string();
            runtime.global_ws_last_error.clear();
            runtime.global_ws_last_connected_ms = Some(cloud_mcp_now_ms());
            runtime.global_ws_connection_id = Some(connection_id.clone());
            runtime.global_ws_message_token = Some(message_token.clone());
        }
        CLOUD_MCP_WS_TIMEOUT_STRIKES.store(0, Ordering::Release);
        log_cloud_sync_event(
            "ws.ready",
            json!({ "connection_id": connection_id.clone() }),
        );
        agent_chat_session_sync_mark_all_workspace_history_dirty();
        cloud_mcp_note_sync_connection(false, "desktop_registering");
        let ready_message = message.clone();
        let state_for_initial = state.clone();
        tauri::async_runtime::spawn(async move {
            if let Some(initial_account_asset_state) = initial_account_asset_state {
                let bytes = cloud_mcp_sync_payload_bytes(&initial_account_asset_state);
                let count = cloud_mcp_sync_payload_count(&initial_account_asset_state);
                let activity_key = cloud_mcp_record_sync_activity(
                    "assets",
                    "down",
                    "hydrating",
                    count,
                    bytes,
                    false,
                    cloud_mcp_sync_activity_size_class("hydrating", count, bytes, "assets"),
                    "global_ws_ready:account_assets_snapshot",
                );
                cloud_mcp_update_asset_library_from_response(
                    "asset_library_list_snapshot",
                    Some("/v1/events"),
                    &json!({"asset_scope": "account"}),
                    &initial_account_asset_state,
                );
                let _ = state_for_initial.global_ws_events.send(
                    cloud_mcp_account_asset_local_projection_event("global_ws_ready"),
                );
                cloud_mcp_clear_sync_activity_key(&activity_key);
            }
            if let Some(initial_account_usage) = ready_message
                .get("initial_account_usage")
                .cloned()
                .filter(|value| !value.is_null())
            {
                let event = json!({
                    "kind": "account_usage_snapshot",
                    "event_kind": "account_usage_snapshot",
                    "contract": "diffforge.account_usage.v1",
                    "reason": "global_ws_ready",
                    "payload": initial_account_usage,
                });
                cloud_mcp_cache_account_usage_snapshot(&state_for_initial, &event).await;
                let _ = state_for_initial.global_ws_events.send(event);
            }
            if let Some(initial_native_sessions) = ready_message
                .get("initial_native_sessions")
                .cloned()
                .filter(|value| !value.is_null())
            {
                let _ = state_for_initial.global_ws_events.send(json!({
                    "kind": "native_sessions_status",
                    "event_kind": "native_sessions_status",
                    "contract": "diffforge.native_sessions.v1",
                    "reason": "global_ws_ready",
                    "payload": initial_native_sessions,
                }));
            }
            for (payload, event_kind, contract) in [
                (
                    cloud_mcp_initial_account_snapshot(&ready_message, "initial_account_clis"),
                    "account_clis_snapshot",
                    "diffforge.account_clis.v1",
                ),
                (
                    cloud_mcp_initial_account_snapshot(&ready_message, "initial_account_mcps"),
                    "account_mcps_snapshot",
                    "diffforge.account_mcps.v1",
                ),
            ] {
                if let Some(payload) = payload {
                    let state_for_tools = state_for_initial.clone();
                    tauri::async_runtime::spawn(async move {
                        cloud_mcp_emit_initial_account_tools_snapshot(
                            &state_for_tools,
                            event_kind,
                            contract,
                            payload,
                        )
                        .await;
                    });
                }
            }
            if let Some(initial_account_documents) =
                cloud_mcp_initial_account_snapshot(&ready_message, "initial_account_documents")
                    .or_else(|| {
                        cloud_mcp_initial_account_snapshot(&ready_message, "initial_account_docs")
                    })
            {
                match cloud_mcp_apply_account_documents_sync_data_with_hydration(
                    &state_for_initial,
                    &initial_account_documents,
                    "global_ws_ready",
                )
                .await
                {
                    Ok(applied) => {
                        let _ = state_for_initial.global_ws_events.send(json!({
                            "kind": "doc.sync",
                            "event_kind": "doc.sync",
                            "contract": CLOUD_MCP_ACCOUNT_DOCUMENTS_CONTRACT,
                            "c": "doc.sync",
                            "d": "documents",
                            "reason": "global_ws_ready",
                            "payload": applied,
                        }));
                    }
                    Err(error) => {
                        log_cloud_sync_event(
                            "account_documents.initial_apply_error",
                            json!({"error": clean_terminal_telemetry_text(&error)}),
                        );
                    }
                }
            }
            if let Some(initial_account_live_state) = ready_message
                .get("initial_account_live_state")
                .cloned()
                .filter(|value| !value.is_null())
            {
                cloud_mcp_apply_account_device_live_state_snapshot(
                    &state_for_initial,
                    initial_account_live_state,
                    "global_ws_ready",
                    "global_ws_ready:account_device_live_state_snapshot",
                )
                .await;
            }
            cloud_mcp_spawn_registered_device_registry_refresh(
                &state_for_initial,
                "websocket_ready",
            );
        });
        cloud_mcp_record_signin_diagnostic(
            state,
            "websocket.ready",
            "ok",
            "Cloud MCP app websocket ready frame received",
            json!({"connection_id": connection_id.clone()}),
        )
        .await;
        cloud_mcp_record_connection_diagnostic(
            state,
            "rust.cloud_mcp.websocket.ready",
            "ok",
            "Cloud MCP app websocket ready frame received",
            json!({
                "connection_id": connection_id.clone(),
                "client_identity": "appwrite_account",
                "hello_client_id": CLOUD_MCP_RUST_CLIENT_ID,
            }),
        )
        .await;
        let device_profile = cloud_mcp_desktop_device_profile();
        let (plan_name, device_limit) = cloud_mcp_account_plan(state).await;
        let connection_epoch = state.global_ws_epoch.load(Ordering::SeqCst);
        let (hello_workspaces, workspace_catalog_ready) =
            cloud_mcp_lifecycle_workspaces(state).await;
        let mut hello = json!({
            "kind": "hello",
            "id": format!("hello-{}", cloud_mcp_now_ms()),
            "client_id": CLOUD_MCP_RUST_CLIENT_ID,
            "source": "rust-diffforge",
            "connection_epoch": connection_epoch,
            "device": device_profile.clone(),
            "device_id": device_profile["device_id"].clone(),
            "device_name": device_profile["device_name"].clone(),
            "machine_name": device_profile["machine_name"].clone(),
            "platform": device_profile["platform"].clone(),
            "app_update": app_update_device_payload(),
            "form_factor": device_profile["form_factor"].clone(),
            "client_kind": device_profile["client_kind"].clone(),
            "client_type": device_profile["client_type"].clone(),
            "connection_source": device_profile["connection_source"].clone(),
            "plan_name": plan_name,
            "device_limit": device_limit,
            "contract": "diffforge.app_ws.v1",
            "auth": {
                "connection_id": connection_id.clone(),
                "message_token": message_token.clone(),
            },
            "workspace_catalog_ready": workspace_catalog_ready,
            "workspace_snapshot_complete": workspace_catalog_ready,
        });
        if workspace_catalog_ready {
            hello["workspaces"] = Value::Array(hello_workspaces);
        }
        if let Some(tx) = state.global_ws_tx.lock().await.as_ref().cloned() {
            let _ = tx.send(hello);
        }
        return;
    }
    if message.get("kind").and_then(Value::as_str) == Some("response")
        && message.get("request_kind").and_then(Value::as_str) == Some("hello")
        && message.get("ok").and_then(Value::as_bool).unwrap_or(false)
    {
        {
            let mut runtime = state.inner.lock().await;
            runtime.connected = true;
            runtime.status = "connected".to_string();
            runtime.last_error.clear();
            runtime.last_connected_ms = Some(cloud_mcp_now_ms());
            runtime.global_ws_connected = true;
            runtime.global_ws_status = "connected".to_string();
            runtime.global_ws_last_error.clear();
            runtime.global_ws_last_connected_ms = Some(cloud_mcp_now_ms());
        }
        cloud_mcp_note_sync_connection(true, "connected");
        agent_chat_session_sync_mark_all_workspace_history_dirty();
        log_cloud_sync_event(
            "ws.desktop_registered",
            json!({
                "id": message.get("id").cloned().unwrap_or(Value::Null),
            }),
        );
        let (connection_id, message_token) = {
            let runtime = state.inner.lock().await;
            (
                runtime.global_ws_connection_id.clone(),
                runtime.global_ws_message_token.clone(),
            )
        };
        if let (Some(connection_id), Some(message_token)) = (connection_id, message_token) {
            cloud_mcp_replay_runtime_snapshots(state, &connection_id, &message_token).await;
        }
        let _ = cloud_mcp_outbox_release_backoff_now();
        cloud_mcp_background_sync_ensure_started(state);
        state.background_sync.notify.notify_one();
        cloud_mcp_spawn_registered_device_registry_refresh(state, "websocket_hello_ack");
        cloud_mcp_spawn_account_live_state_reconcile(state, "websocket_hello_ack");
        cloud_mcp_spawn_account_sync_resume(state, "websocket_hello_ack");
        cloud_mcp_spawn_account_asset_inventory_sync(state, "websocket_hello_ack");
        cloud_mcp_spawn_local_scripts_inventory_sync(state, "websocket_hello_ack");
        return;
    }
    if message.get("kind").and_then(Value::as_str) == Some(CLOUD_MCP_CHAT_ATTACHMENT_PUSH_KIND) {
        let source_request_id = message
            .get("source_request_id")
            .cloned()
            .unwrap_or(Value::Null);
        match cloud_mcp_receive_chat_attachment_push(&message).await {
            Ok(result) => {
                log_cloud_sync_event(
                    "chat_attachment_push.staged",
                    json!({
                        "source_request_id": source_request_id,
                        "workspace_id": result.get("workspace_id").cloned().unwrap_or(Value::Null),
                        "image_count": result.get("image_count").cloned().unwrap_or(Value::Null),
                        "total_bytes": result.get("total_bytes").cloned().unwrap_or(Value::Null),
                        "attachments": result.get("attachments").cloned().unwrap_or_else(|| json!([])),
                        "staged_count": result.get("staged").and_then(Value::as_array).map(Vec::len).unwrap_or(0),
                    }),
                );
            }
            Err(error) => {
                log_cloud_sync_event(
                    "chat_attachment_push.stage_failed",
                    json!({
                        "source_request_id": source_request_id,
                        "error": clean_terminal_telemetry_text(&error),
                    }),
                );
            }
        }
        return;
    }
    if let Some(id) = message.get("id").and_then(Value::as_str) {
        if let Some(sender) = state.global_ws_pending.lock().await.remove(id) {
            let _ = sender.send(message);
            return;
        }
    }
    let direct_kind = cloud_mcp_payload_text(&message, &["event_kind", "kind"]).unwrap_or_default();
    if matches!(
        direct_kind.as_str(),
        "session.gap" | "session_gap" | "agent_session_gap"
    ) {
        agent_chat_session_sync_mark_payload_workspace_history_dirty(&message);
    }
    let direct_request_kind =
        cloud_mcp_payload_text(&message, &["request_kind"]).unwrap_or_default();
    if cloud_mcp_is_list_agent_models_request(&message, &direct_kind, &direct_request_kind) {
        let state = state.clone();
        tauri::async_runtime::spawn(async move {
            cloud_mcp_handle_list_agent_models_request(state, message).await;
        });
        return;
    }
    if cloud_mcp_value_is_account_usage(&message) {
        cloud_mcp_cache_account_usage_snapshot(state, &message).await;
        let _ = state.global_ws_events.send(message);
        return;
    }
    if cloud_mcp_handle_agent_session_observer_subscription(state, &message, &direct_kind) {
        return;
    }
    if cloud_mcp_handle_terminal_io_message(state, &message, &direct_kind).await {
        return;
    }
    if cloud_mcp_is_account_asset_wake_event(&direct_kind, &message) {
        let event = message
            .get("data")
            .or_else(|| message.get("payload"))
            .cloned()
            .unwrap_or_else(|| message.clone());
        let event_kind = cloud_mcp_payload_text(&event, &["event_kind", "kind"])
            .unwrap_or_else(|| direct_kind.clone());
        let inbound_bytes = cloud_mcp_sync_payload_bytes(&event);
        let inbound_count = cloud_mcp_sync_payload_count(&event);
        let source_id = cloud_mcp_payload_text(&event, &["cloud_event_id"])
            .or_else(|| cloud_mcp_payload_text(&event, &["event_id", "id"]))
            .unwrap_or_else(|| uuid::Uuid::new_v4().to_string());
        let activity_key = cloud_mcp_record_sync_activity(
            "assets",
            "down",
            "applying",
            inbound_count,
            inbound_bytes,
            false,
            cloud_mcp_sync_activity_size_class("applying", inbound_count, inbound_bytes, "assets"),
            &format!("direct_asset_event:{event_kind}:{source_id}"),
        );
        cloud_mcp_update_asset_library_from_response(
            "asset_library_direct_event",
            Some("/v1/events"),
            &event,
            &event,
        );
        let _ = state
            .global_ws_events
            .send(cloud_mcp_account_asset_local_projection_event(&event_kind));
        cloud_mcp_clear_sync_activity_key(&activity_key);
        return;
    }
    if direct_kind == CLOUD_MCP_TOKENOMICS_INGEST_ACK_EVENT
        || direct_request_kind == CLOUD_MCP_TOKENOMICS_INGEST_ACK_EVENT
        || cloud_mcp_tokenomics_strict_ingest_ack_response(&message)
    {
        cloud_mcp_handle_tokenomics_ingest_ack(state, &message, "direct").await;
        return;
    }
    if direct_kind == "account_device_live_state_snapshot" {
        cloud_mcp_cache_account_device_live_state_snapshot(state, &message).await;
        let _ = state.global_ws_events.send(message);
        return;
    }
    if cloud_mcp_is_loopspaces_sync_event_kind(&direct_kind)
        || cloud_mcp_is_loopspaces_sync_event_kind(&direct_request_kind)
        || cloud_mcp_payload_text(&message, &["contract"]).as_deref()
            == Some(CLOUD_MCP_LOOPSPACES_CONTRACT)
    {
        if message.get("ok").and_then(Value::as_bool) == Some(false) {
            return;
        }
        let event = message
            .get("data")
            .or_else(|| message.get("payload"))
            .cloned()
            .unwrap_or_else(|| message.clone());
        match cloud_mcp_apply_loopspaces_sync_data(state, &event, "direct_loopspaces_event").await {
            Ok(snapshot) => {
                let _ = state.global_ws_events.send(json!({
                    "kind": "loopspaces.sync",
                    "event_kind": "loopspaces.sync",
                    "contract": CLOUD_MCP_LOOPSPACES_CONTRACT,
                    "payload": snapshot,
                }));
            }
            Err(error) => {
                log_cloud_sync_event(
                    "loopspaces.direct_apply_error",
                    json!({ "error": clean_terminal_telemetry_text(&error) }),
                );
            }
        }
        return;
    }
    if cloud_mcp_is_loopspace_triggers_sync_event_kind(&direct_kind)
        || cloud_mcp_is_loopspace_triggers_sync_event_kind(&direct_request_kind)
        || cloud_mcp_payload_text(&message, &["contract"]).as_deref()
            == Some(CLOUD_MCP_LOOPSPACE_TRIGGERS_CONTRACT)
    {
        if message.get("ok").and_then(Value::as_bool) == Some(false) {
            return;
        }
        let event = message
            .get("data")
            .or_else(|| message.get("payload"))
            .cloned()
            .unwrap_or_else(|| message.clone());
        match cloud_mcp_apply_loopspace_triggers_sync_data(
            state,
            &event,
            "direct_loopspace_triggers_event",
        )
        .await
        {
            Ok(snapshot) => {
                let _ = state.global_ws_events.send(json!({
                    "kind": "loopspace_triggers.sync",
                    "event_kind": "loopspace_triggers.sync",
                    "contract": CLOUD_MCP_LOOPSPACE_TRIGGERS_CONTRACT,
                    "payload": snapshot,
                }));
            }
            Err(error) => {
                log_cloud_sync_event(
                    "loopspace_triggers.direct_apply_error",
                    json!({ "error": clean_terminal_telemetry_text(&error) }),
                );
            }
        }
        return;
    }
    if cloud_mcp_is_account_documents_sync_wake_event(&direct_kind, &message)
        || cloud_mcp_is_account_documents_sync_wake_event(&direct_request_kind, &message)
    {
        if message.get("ok").and_then(Value::as_bool) == Some(false) {
            return;
        }
        let event = message
            .get("data")
            .or_else(|| message.get("payload"))
            .cloned()
            .unwrap_or_else(|| message.clone());
        match cloud_mcp_apply_account_documents_sync_data_with_hydration(
            state,
            &event,
            "direct_documents_event",
        )
        .await
        {
            Ok(applied) => {
                let _ = state.global_ws_events.send(json!({
                    "kind": "doc.sync",
                    "event_kind": "doc.sync",
                    "contract": CLOUD_MCP_ACCOUNT_DOCUMENTS_CONTRACT,
                    "c": "doc.sync",
                    "d": "documents",
                    "payload": applied,
                }));
            }
            Err(error) => {
                log_cloud_sync_event(
                    "account_documents.direct_apply_error",
                    json!({ "error": clean_terminal_telemetry_text(&error) }),
                );
            }
        }
        return;
    }
    let direct_account_todo_delta = cloud_mcp_is_account_todo_delta_event_kind(&direct_kind)
        || matches!(direct_request_kind.as_str(), "todo.live_state");
    if direct_account_todo_delta {
        if message.get("ok").and_then(Value::as_bool) == Some(false) {
            return;
        }
        let event = message
            .get("data")
            .or_else(|| message.get("payload"))
            .cloned()
            .unwrap_or_else(|| message.clone());
        if cloud_mcp_account_todo_is_control(&message) || cloud_mcp_account_todo_is_control(&event)
        {
            return;
        }
        let event_kind = cloud_mcp_account_todo_event_kind(&event, "todo.live_state");
        log_cloud_sync_event(
            "todo_sync.received",
            json!({
                "event_kind": event_kind,
                "source": "direct_app_ws",
                "bytes": cloud_mcp_sync_payload_bytes(&event),
                "count": cloud_mcp_sync_payload_count(&event),
            }),
        );
        match cloud_mcp_apply_account_todo_inbound_event(state, &event_kind, &event).await {
            Ok(result) => {
                let suppress_local_echo = result.applied == 0
                    && result.deleted == 0
                    && result.skipped_local_echo > 0
                    && result.skipped_stale == 0
                    && result.ignored == 0;
                if !suppress_local_echo {
                    let _ = state.global_ws_events.send(event);
                }
            }
            Err(error) => {
                log_cloud_sync_event(
                    "todo_sync.delta_error",
                    json!({
                        "event_kind": event_kind,
                        "error": clean_terminal_telemetry_text(&error),
                    }),
                );
            }
        }
        return;
    }
    if message.get("kind").and_then(Value::as_str) == Some("cloud_event") {
        // The graph/spec sync loops still own local cache materialization.
        // This global channel is the durable wake signal shared by every workspace.
        let event = message
            .get("event")
            .cloned()
            .unwrap_or_else(|| message.clone());
        let event_kind = event
            .get("event_kind")
            .or_else(|| event.get("kind"))
            .and_then(Value::as_str)
            .unwrap_or_default()
            .to_string();
        if cloud_mcp_handle_agent_session_observer_subscription(state, &event, &event_kind) {
            return;
        }
        if cloud_mcp_handle_terminal_io_message(state, &event, &event_kind).await {
            return;
        }
        if event_kind == "account_device_live_state_snapshot" {
            cloud_mcp_cache_account_device_live_state_snapshot(state, &event).await;
        }
        if cloud_mcp_value_is_account_usage(&event) {
            cloud_mcp_cache_account_usage_snapshot(state, &event).await;
        }
        if event_kind == CLOUD_MCP_TOKENOMICS_INGEST_ACK_EVENT
            || cloud_mcp_tokenomics_strict_ingest_ack_response(&event)
        {
            cloud_mcp_handle_tokenomics_ingest_ack(state, &event, "cloud_event").await;
            return;
        }
        let is_liveness_event = matches!(
            event_kind.as_str(),
            "client_liveness_ping" | "dashboard_liveness_ping"
        );
        let is_account_todo_delta_event = cloud_mcp_is_account_todo_inbound_event_kind(&event_kind)
            && !cloud_mcp_account_todo_is_control(&event);
        let is_loopspaces_sync_event = cloud_mcp_is_loopspaces_sync_event_kind(&event_kind)
            || cloud_mcp_payload_text(&event, &["contract"]).as_deref()
                == Some(CLOUD_MCP_LOOPSPACES_CONTRACT);
        let is_loopspace_triggers_sync_event =
            cloud_mcp_is_loopspace_triggers_sync_event_kind(&event_kind)
                || cloud_mcp_payload_text(&event, &["contract"]).as_deref()
                    == Some(CLOUD_MCP_LOOPSPACE_TRIGGERS_CONTRACT);
        let is_account_documents_sync_event =
            cloud_mcp_is_account_documents_sync_wake_event(&event_kind, &event);
        let inbound_domain = if is_account_documents_sync_event {
            "documents"
        } else {
            cloud_mcp_sync_activity_domain(&event_kind)
        };
        let inbound_bytes = cloud_mcp_sync_payload_bytes(&event);
        let inbound_count = cloud_mcp_sync_payload_count(&event);
        let inbound_state = if is_account_todo_delta_event
            || cloud_mcp_is_workspace_todo_wake_event(&event_kind, &event)
            || cloud_mcp_is_account_asset_wake_event(&event_kind, &event)
            || is_account_documents_sync_event
            || is_loopspaces_sync_event
            || is_loopspace_triggers_sync_event
        {
            "applying"
        } else {
            "active"
        };
        let inbound_direction = if is_liveness_event { "control" } else { "down" };
        let inbound_source_id = cloud_mcp_payload_text(&event, &["cloud_event_id"])
            .or_else(|| cloud_mcp_payload_text(&event, &["event_id", "id"]))
            .unwrap_or_else(|| uuid::Uuid::new_v4().to_string());
        let inbound_activity_key = cloud_mcp_record_sync_activity(
            inbound_domain,
            inbound_direction,
            inbound_state,
            inbound_count,
            inbound_bytes,
            false,
            cloud_mcp_sync_activity_size_class(
                inbound_state,
                inbound_count,
                inbound_bytes,
                inbound_domain,
            ),
            &format!("cloud_event:{event_kind}:{inbound_source_id}"),
        );
        if event_kind.starts_with("voice_agent_") {
            cloud_mcp_log_voice_shared_ws(
                "voice_agent.shared_ws.event_received",
                &event_kind,
                "received",
                "Rust websocket reader received a voice event from cloud.",
                json!({
                    "repo_id": event.get("repo_id").cloned().unwrap_or(Value::Null),
                    "workspace_id": event.get("workspace_id").cloned().unwrap_or(Value::Null),
                    "voice_session_id": event.get("voice_session_id").cloned().unwrap_or(Value::Null),
                }),
            );
        }
        if is_liveness_event {
            let _ = cloud_mcp_send_liveness_pong_event(state, &event).await;
        }
        {
            let mut runtime = state.inner.lock().await;
            runtime.connected = true;
            runtime.status = "connected".to_string();
            runtime.global_ws_connected = true;
            runtime.global_ws_status = "connected".to_string();
            runtime.global_ws_last_connected_ms = Some(cloud_mcp_now_ms());
        }
        let mut suppress_cloud_event = false;
        if is_account_todo_delta_event {
            log_cloud_sync_event(
                "todo_sync.received",
                json!({
                    "event_kind": event_kind,
                    "source": "cloud_event",
                    "bytes": inbound_bytes,
                    "count": inbound_count,
                }),
            );
            match cloud_mcp_apply_account_todo_inbound_event(state, &event_kind, &event).await {
                Ok(result) => {
                    suppress_cloud_event = result.applied == 0
                        && result.deleted == 0
                        && result.skipped_local_echo > 0
                        && result.skipped_stale == 0
                        && result.ignored == 0;
                }
                Err(error) => {
                    log_cloud_sync_event(
                        "todo_sync.delta_error",
                        json!({
                            "event_kind": event_kind,
                            "error": clean_terminal_telemetry_text(&error),
                        }),
                    );
                }
            }
        } else if is_account_documents_sync_event {
            match cloud_mcp_apply_account_documents_sync_data_with_hydration(
                state,
                &event,
                "documents_cloud_event",
            )
            .await
            {
                Ok(applied) => {
                    let _ = state.global_ws_events.send(json!({
                        "kind": "doc.sync",
                        "event_kind": "doc.sync",
                        "contract": CLOUD_MCP_ACCOUNT_DOCUMENTS_CONTRACT,
                        "c": "doc.sync",
                        "d": "documents",
                        "payload": applied,
                    }));
                    suppress_cloud_event = true;
                }
                Err(error) => {
                    log_cloud_sync_event(
                        "account_documents.cloud_event_apply_error",
                        json!({ "error": clean_terminal_telemetry_text(&error) }),
                    );
                }
            }
        } else if cloud_mcp_is_workspace_todo_wake_event(&event_kind, &event) {
            cloud_mcp_update_todo_mirror_from_response(
                state,
                "workspace_todo_event",
                "/v1/events",
                &event,
                &event,
            )
            .await;
        } else if cloud_mcp_is_account_asset_wake_event(&event_kind, &event) {
            cloud_mcp_update_asset_library_from_response(
                "asset_library_event",
                Some("/v1/events"),
                &event,
                &event,
            );
            suppress_cloud_event = true;
            let _ = state
                .global_ws_events
                .send(cloud_mcp_account_asset_local_projection_event(&event_kind));
        } else if is_loopspaces_sync_event {
            match cloud_mcp_apply_loopspaces_sync_data(state, &event, "loopspaces_cloud_event")
                .await
            {
                Ok(snapshot) => {
                    let _ = state.global_ws_events.send(json!({
                        "kind": "loopspaces.sync",
                        "event_kind": "loopspaces.sync",
                        "contract": CLOUD_MCP_LOOPSPACES_CONTRACT,
                        "payload": snapshot,
                    }));
                    suppress_cloud_event = true;
                }
                Err(error) => {
                    log_cloud_sync_event(
                        "loopspaces.cloud_event_apply_error",
                        json!({ "error": clean_terminal_telemetry_text(&error) }),
                    );
                }
            }
        } else if is_loopspace_triggers_sync_event {
            match cloud_mcp_apply_loopspace_triggers_sync_data(
                state,
                &event,
                "loopspace_triggers_cloud_event",
            )
            .await
            {
                Ok(snapshot) => {
                    let _ = state.global_ws_events.send(json!({
                        "kind": "loopspace_triggers.sync",
                        "event_kind": "loopspace_triggers.sync",
                        "contract": CLOUD_MCP_LOOPSPACE_TRIGGERS_CONTRACT,
                        "payload": snapshot,
                    }));
                    suppress_cloud_event = true;
                }
                Err(error) => {
                    log_cloud_sync_event(
                        "loopspace_triggers.cloud_event_apply_error",
                        json!({ "error": clean_terminal_telemetry_text(&error) }),
                    );
                }
            }
        }
        if !suppress_cloud_event {
            let _ = state.global_ws_events.send(event);
        }
        cloud_mcp_clear_sync_activity_key(&inbound_activity_key);
    }
}

async fn cloud_mcp_refresh_runtime_base_url(state: &CloudMcpState) -> String {
    let resolved_base_url = cloud_mcp_base_url();
    let mut runtime = state.inner.lock().await;
    if runtime.base_url != resolved_base_url {
        let previous_base_url = runtime.base_url.clone();
        runtime.base_url = resolved_base_url.clone();
        drop(runtime);
        log_cloud_sync_event(
            "ws.base_url_refreshed",
            json!({
                "previous_base_url": previous_base_url,
                "base_url": resolved_base_url,
            }),
        );
        return resolved_base_url;
    }
    resolved_base_url
}

async fn cloud_mcp_send_liveness_pong_event(
    state: &CloudMcpState,
    event: &Value,
) -> Result<(), String> {
    let received_ms = cloud_mcp_now_ms();
    let ping_id = cloud_mcp_payload_text(event, &["ping_id"])
        .or_else(|| cloud_mcp_payload_text(event, &["payload", "ping_id"]))
        .unwrap_or_else(|| format!("rust-liveness-{received_ms}"));
    let snapshot = cloud_mcp_status_snapshot(state).await;
    let sent_ms = cloud_mcp_now_ms();
    let auth = cloud_mcp_ws_auth_object(state).await?;
    let device_profile = cloud_mcp_desktop_device_profile();
    let (lifecycle_workspaces, workspace_catalog_ready) =
        cloud_mcp_lifecycle_workspaces(state).await;
    let mut payload = json!({
        "source": "rust-diffforge-liveness",
        "event_kind": "desktop_liveness_pong",
        "agent_id": "rust-diffforge",
        "agent_label": "Diff Forge Desktop",
        "device": device_profile.clone(),
        "device_id": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "platform": device_profile["platform"].clone(),
        "app_update": app_update_device_payload(),
        "form_factor": device_profile["form_factor"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "client_type": device_profile["client_type"].clone(),
        "connection_source": device_profile["connection_source"].clone(),
        "ping_id": ping_id,
        "repo_id": cloud_mcp_payload_text(event, &["repo_id"])
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "repo_id"])),
        "workspace_id": cloud_mcp_payload_text(event, &["workspace_id"])
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "workspace_id"])),
        "origin_connection_id": cloud_mcp_payload_text(event, &["origin_connection_id"]),
        "browser_sent_ms": cloud_mcp_payload_u64(event, &["browser_sent_ms"])
            .or_else(|| cloud_mcp_payload_u64(event, &["payload", "browser_sent_ms"])),
        "cloud_received_ms": cloud_mcp_payload_u64(event, &["cloud_received_ms"])
            .or_else(|| cloud_mcp_payload_u64(event, &["payload", "cloud_received_ms"])),
        "cloud_sent_ms": cloud_mcp_payload_u64(event, &["cloud_sent_ms"])
            .or_else(|| cloud_mcp_payload_u64(event, &["payload", "cloud_sent_ms"])),
        "rust_received_ms": received_ms,
        "rust_sent_ms": sent_ms,
        "rust_elapsed_ms": sent_ms.saturating_sub(received_ms),
        "registered_workspace_count": snapshot.registered_workspaces.len(),
        "global_ws_connected": snapshot.global_ws_connected,
        "workspace_catalog_ready": workspace_catalog_ready,
        "workspace_snapshot_complete": workspace_catalog_ready,
        "status": "connected",
        "ts_ms": sent_ms,
    });
    if workspace_catalog_ready {
        payload["workspaces"] = Value::Array(lifecycle_workspaces);
    }
    let request = cloud_mcp_event_envelope("desktop_liveness_pong", &payload);
    let envelope = json!({
        "kind": "event",
        "id": format!("liveness-pong-{}-{}", sent_ms, uuid::Uuid::new_v4()),
        "contract": "diffforge.app_ws.v1",
        "auth": auth,
        "client_id": CLOUD_MCP_RUST_CLIENT_ID,
        "repo_id": cloud_mcp_payload_text(&request, &["repo_id"])
            .or_else(|| cloud_mcp_payload_text(&request, &["payload", "repo_id"])),
        "workspace_id": cloud_mcp_payload_text(&request, &["workspace_id"])
            .or_else(|| cloud_mcp_payload_text(&request, &["payload", "workspace_id"])),
        "request": request,
    });
    let Some(tx) = state.global_ws_tx.lock().await.as_ref().cloned() else {
        return Err("Cloud MCP app websocket is not connected.".to_string());
    };
    tx.send(envelope)
        .map_err(|_| "Cloud MCP app websocket sender is closed.".to_string())
}

async fn cloud_mcp_handle_tokenomics_ingest_ack(_state: &CloudMcpState, ack: &Value, source: &str) {
    match cloud_mcp_tokenomics_persist_ingest_ack(None, ack) {
        Ok(result) => {
            let requires_snapshot = result
                .get("requires_snapshot")
                .and_then(Value::as_bool)
                .unwrap_or(false);
            cloud_mcp_record_tokenomics_sync_log(
                "ingest_ack",
                if requires_snapshot {
                    "snapshot_ignored_client_owned"
                } else {
                    "synced"
                },
                source,
                json!({
                    "accepted": result.get("accepted").cloned().unwrap_or_else(|| json!(true)),
                    "ads": result.get("ads").or_else(|| result.get("acked_device_seq")).cloned().unwrap_or(Value::Null),
                    "scp": result
                        .get("sc")
                        .or_else(|| result.get("server_cursor"))
                        .and_then(Value::as_str)
                        .map(|cursor| !cursor.trim().is_empty())
                        .unwrap_or(false),
                    "requires_snapshot": requires_snapshot,
                }),
            );
            log_cloud_sync_event(
                "tokenomics.ingest_ack",
                json!({
                    "source": source,
                    "ok": result.get("ok").cloned().unwrap_or_else(|| json!(true)),
                    "accepted": result.get("accepted").cloned().unwrap_or_else(|| json!(true)),
                    "ads": result.get("ads").or_else(|| result.get("acked_device_seq")).cloned().unwrap_or(Value::Null),
                    "sc": result.get("sc").or_else(|| result.get("server_cursor")).cloned().unwrap_or(Value::Null),
                    "requires_snapshot": requires_snapshot,
                    "snapshot_action": if requires_snapshot {
                        "ignored_client_owned"
                    } else {
                        "not_requested"
                    },
                }),
            );
            if requires_snapshot {
                log_cloud_sync_event(
                    "tokenomics.ingest_ack_snapshot_ignored",
                    json!({
                        "source": source,
                        "reason": "client_owned_tokenomics",
                    }),
                );
            }
        }
        Err(error) => {
            cloud_mcp_record_tokenomics_sync_error("ingest_ack_error", source, &error);
            log_cloud_sync_event(
                "tokenomics.ingest_ack_error",
                json!({
                    "source": source,
                    "error": clean_terminal_telemetry_text(&error),
                }),
            );
        }
    }
}

async fn cloud_mcp_send_tokenomics_delivery_ack(
    state: &CloudMcpState,
    event: &Value,
    recorded: Option<&Value>,
    status: &str,
    reason: &str,
) -> Result<Value, String> {
    let Some(delivery_id) = cloud_mcp_tokenomics_delivery_id_from_value(event) else {
        return Ok(json!({
            "skipped": true,
            "reason": "missing_delivery_id",
        }));
    };
    let device_profile = cloud_mcp_desktop_device_profile();
    let device_id = cloud_mcp_tokenomics_device_id_from_profile(&device_profile)?;
    let (billing_scope_type, team_id) = cloud_mcp_account_scope(state).await;
    let scope_key = cloud_mcp_account_scope_key_from_parts(&billing_scope_type, team_id.as_deref());
    let server_cursor = cloud_mcp_tokenomics_server_cursor_from_value(event).unwrap_or_default();
    let applied_server_cursor = recorded
        .and_then(cloud_mcp_tokenomics_server_cursor_from_value)
        .or_else(|| cloud_mcp_tokenomics_server_cursor_from_value(event))
        .unwrap_or_else(|| server_cursor.clone());
    let stored_count = recorded
        .and_then(|value| cloud_mcp_payload_u64(value, &["stored_count"]))
        .unwrap_or(0);
    let stored_limit_count = recorded
        .and_then(|value| cloud_mcp_payload_u64(value, &["stored_limit_count"]))
        .unwrap_or(0);
    let stored_limit_sample_count = recorded
        .and_then(|value| cloud_mcp_payload_u64(value, &["stored_limit_sample_count"]))
        .unwrap_or(0);
    let status = if status.trim().is_empty() {
        "applied"
    } else {
        status.trim()
    };
    let payload = json!({
        "c": CLOUD_MCP_TOKENOMICS_CONTRACT,
        "m": "delivery_ack",
        "src": "rust-diffforge-desktop",
        "r": reason,
        "st": status,
        "del": delivery_id.clone(),
        "fid": cloud_mcp_tokenomics_response_text(event, &["fid", "fanout_event_id"]).unwrap_or_else(|| delivery_id.clone()),
        "sem": cloud_mcp_tokenomics_event_kind_from_value(event),
        "pid": cloud_mcp_tokenomics_response_text(event, &["pid", "packet_id"]).unwrap_or_default(),
        "sdm": cloud_mcp_tokenomics_day_start_from_value(event),
        "sd": cloud_mcp_tokenomics_response_text(event, &["sd", "sync_day", "day_key"]).unwrap_or_default(),
        "h": cloud_mcp_tokenomics_day_content_hash_from_value(event).unwrap_or_default(),
        "sdid": cloud_mcp_tokenomics_response_text(event, &["sdid", "source_device_id"]).unwrap_or_default(),
        "sc": server_cursor,
        "asc": applied_server_cursor,
        "cdid": device_id.clone(),
        "did": device_id.clone(),
        "d": device_profile,
        "ck": "rust_desktop",
        "sk": scope_key,
        "cnt": stored_count,
        "lcnt": stored_limit_count,
        "slcnt": stored_limit_sample_count,
        "se": false,
        "tms": cloud_mcp_now_ms(),
    });
    let response = cloud_mcp_ws_request_with_timeout(
        state,
        CLOUD_MCP_TOKENOMICS_DELIVERY_ACK_EVENT,
        &payload,
        Duration::from_millis(CLOUD_MCP_APP_WS_FAST_LANE_ACK_TIMEOUT_MS),
    )
    .await?;
    log_cloud_sync_event(
        "tokenomics.delivery_ack_ok",
        json!({
            "delivery_id": delivery_id,
            "status": status,
            "reason": reason,
            "stored_count": stored_count,
            "stored_limit_count": stored_limit_count,
            "stored_limit_sample_count": stored_limit_sample_count,
        }),
    );
    Ok(response)
}

async fn cloud_mcp_send_lifecycle_event(
    state: &CloudMcpState,
    event_kind: &str,
    status: &str,
    reason: Option<&str>,
) -> Result<Value, String> {
    let now = cloud_mcp_now_ms();
    let connection_epoch = state.global_ws_epoch.load(Ordering::SeqCst);
    let snapshot = cloud_mcp_status_snapshot(state).await;
    let auth = cloud_mcp_ws_auth_object(state).await?;
    let device_profile = cloud_mcp_desktop_device_profile();
    let (lifecycle_workspaces, workspace_catalog_ready) =
        cloud_mcp_lifecycle_workspaces(state).await;
    let mut payload = json!({
        "source": "rust-diffforge-lifecycle",
        "event_kind": event_kind,
        "agent_id": "rust-diffforge",
        "agent_label": "Diff Forge Desktop",
        "device": device_profile.clone(),
        "device_id": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "platform": device_profile["platform"].clone(),
        "app_update": app_update_device_payload(),
        "form_factor": device_profile["form_factor"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "client_type": device_profile["client_type"].clone(),
        "connection_source": device_profile["connection_source"].clone(),
        "reason": reason.unwrap_or(status),
        "status": status,
        "connection_epoch": connection_epoch,
        "registered_workspace_count": snapshot.registered_workspace_count,
        "global_ws_connected": snapshot.global_ws_connected,
        "workspace_catalog_ready": workspace_catalog_ready,
        "workspace_snapshot_complete": workspace_catalog_ready,
        "ts_ms": now,
    });
    if workspace_catalog_ready {
        payload["workspaces"] = Value::Array(lifecycle_workspaces);
    }
    let request = cloud_mcp_event_envelope(event_kind, &payload);
    let envelope = json!({
        "kind": "event",
        "id": format!("desktop-lifecycle-{}-{}", now, uuid::Uuid::new_v4()),
        "contract": "diffforge.app_ws.v1",
        "auth": auth,
        "client_id": CLOUD_MCP_RUST_CLIENT_ID,
        "repo_id": cloud_mcp_payload_text(&request, &["repo_id"])
            .or_else(|| cloud_mcp_payload_text(&request, &["payload", "repo_id"])),
        "workspace_id": cloud_mcp_payload_text(&request, &["workspace_id"])
            .or_else(|| cloud_mcp_payload_text(&request, &["payload", "workspace_id"])),
        "request": request,
    });
    let Some(tx) = state.global_ws_tx.lock().await.as_ref().cloned() else {
        return Err("Cloud MCP app websocket is not connected.".to_string());
    };
    tx.send(envelope)
        .map_err(|_| "Cloud MCP app websocket sender is closed.".to_string())?;

    Ok(json!({
        "ok": true,
        "sent": true,
        "event_kind": event_kind,
        "status": status,
        "ts_ms": now,
    }))
}

async fn cloud_mcp_send_app_ws_close_request(
    state: &CloudMcpState,
    reason: &str,
) -> Result<(), String> {
    let auth = cloud_mcp_ws_auth_object(state).await?;
    let reason = reason.trim();
    let now = cloud_mcp_now_ms();
    let envelope = json!({
        "kind": "cloud_app_ws_close",
        "id": format!("desktop-close-{}-{}", now, uuid::Uuid::new_v4()),
        "contract": "diffforge.app_ws.v1",
        "auth": auth,
        "client_id": CLOUD_MCP_RUST_CLIENT_ID,
        "reason": if reason.is_empty() { "app_shutdown" } else { reason },
        "source": "rust-diffforge",
    });
    let Some(tx) = state.global_ws_tx.lock().await.as_ref().cloned() else {
        return Err("Cloud MCP app websocket is not connected.".to_string());
    };
    tx.send(envelope)
        .map_err(|_| "Cloud MCP app websocket sender is closed.".to_string())
}

fn cloud_mcp_remote_command_field_text(event: &Value, keys: &[&str]) -> Option<String> {
    cloud_mcp_payload_text(event, keys)
        .or_else(|| {
            keys.iter()
                .find_map(|key| cloud_mcp_payload_text(event, &["payload", key]))
        })
        .or_else(|| {
            keys.iter()
                .find_map(|key| cloud_mcp_payload_text(event, &["request", key]))
        })
        .or_else(|| {
            keys.iter()
                .find_map(|key| cloud_mcp_payload_text(event, &["event", key]))
        })
        .or_else(|| {
            keys.iter()
                .find_map(|key| cloud_mcp_payload_text(event, &["event", "payload", key]))
        })
        .or_else(|| {
            keys.iter()
                .find_map(|key| cloud_mcp_payload_text(event, &["event", "request", key]))
        })
}

fn cloud_mcp_remote_command_field_i64(event: &Value, keys: &[&str]) -> Option<i64> {
    cloud_mcp_payload_i64(event, keys)
        .or_else(|| {
            keys.iter()
                .find_map(|key| cloud_mcp_payload_i64(event, &["payload", *key]))
        })
        .or_else(|| {
            keys.iter()
                .find_map(|key| cloud_mcp_payload_i64(event, &["request", *key]))
        })
}

fn cloud_mcp_remote_command_field_bool(event: &Value, keys: &[&str]) -> Option<bool> {
    let parse = |value: &Value| match value {
        Value::Bool(value) => Some(*value),
        Value::Number(value) => value.as_i64().map(|value| value != 0),
        Value::String(value) => match value.trim().to_ascii_lowercase().as_str() {
            "1" | "true" | "yes" | "on" => Some(true),
            "0" | "false" | "no" | "off" => Some(false),
            _ => None,
        },
        _ => None,
    };
    let payload = event.get("payload").filter(|value| value.is_object());
    let request = event.get("request").filter(|value| value.is_object());
    let payload_request = payload
        .and_then(|value| value.get("request"))
        .filter(|value| value.is_object());
    let nested_event = event.get("event").filter(|value| value.is_object());
    let nested_event_payload = nested_event
        .and_then(|value| value.get("payload"))
        .filter(|value| value.is_object());
    let nested_event_request = nested_event
        .and_then(|value| value.get("request"))
        .filter(|value| value.is_object());
    for key in keys {
        for source in [
            Some(event),
            payload,
            request,
            payload_request,
            nested_event,
            nested_event_payload,
            nested_event_request,
        ]
        .into_iter()
        .flatten()
        {
            if let Some(value) = source.get(*key).and_then(&parse) {
                return Some(value);
            }
        }
    }
    None
}

fn cloud_mcp_remote_workspace_requires_foreground(event: &Value) -> bool {
    cloud_mcp_remote_command_field_bool(event, &["show_window"]).unwrap_or(true)
}

fn cloud_mcp_remote_command_matches_device(event: &Value) -> bool {
    let device = cloud_mcp_desktop_device_profile();
    let profile_matches = |candidate: &str| {
        let candidate_key = cloud_mcp_device_id_match_key(candidate);
        if candidate_key.is_empty() {
            return false;
        }
        let scalar_match = ["device_id", "web_device_id", "machine_id"]
            .iter()
            .filter_map(|key| device.get(*key).and_then(Value::as_str))
            .any(|value| cloud_mcp_device_id_match_key(value) == candidate_key);
        scalar_match
            || ["device_aliases"]
                .iter()
                .filter_map(|key| device.get(*key).and_then(Value::as_array))
                .flatten()
                .filter_map(Value::as_str)
                .any(|value| cloud_mcp_device_id_match_key(value) == candidate_key)
    };

    // This root-only field is stamped by the cloud immediately before delivery to
    // the authenticated desktop socket. Do not read it from the user payload/request.
    let routed_field_present = ["cloud_routed_native_device_id"]
        .iter()
        .any(|key| event.get(*key).is_some());
    if routed_field_present {
        return ["cloud_routed_native_device_id"]
            .iter()
            .filter_map(|key| event.get(*key).and_then(Value::as_str))
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .any(profile_matches);
    }

    let Some(target_device_id) = cloud_mcp_remote_command_field_text(event, &["target_device_id"])
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
    else {
        return false;
    };
    profile_matches(&target_device_id)
}

fn cloud_mcp_remote_command_receipt_key(event: &Value) -> Option<String> {
    let command_id = cloud_mcp_remote_command_field_text(event, &["command_id"])?
        .trim()
        .to_string();
    if command_id.is_empty() {
        return None;
    }

    let client_id = cloud_mcp_payload_text(event, &["client_id"]).unwrap_or_default();
    let command_kind =
        cloud_mcp_remote_command_field_text(event, &["command_kind"]).unwrap_or_default();
    let workspace_id = cloud_mcp_remote_command_field_text(event, &["workspace_id"])
        .map(|value| {
            cloud_mcp_canonical_workspace_id_from_value(&value, event, cloud_mcp_desktop_platform())
        })
        .unwrap_or_default();
    let intent_id = cloud_mcp_remote_command_field_text(event, &["intent_id"]).unwrap_or_default();
    Some(format!(
        "remote-command-receipt::{command_id}::{}",
        cloud_mcp_outbox_payload_hash(&json!([
            client_id.trim(),
            workspace_id,
            command_kind.trim(),
            command_id.as_str(),
            intent_id.trim(),
        ]))
    ))
}

fn cloud_mcp_tokenomics_wake_receipt_key(event: &Value) -> Option<String> {
    let event_kind = cloud_mcp_tokenomics_event_kind_from_value(event);
    let packet_id =
        cloud_mcp_tokenomics_response_text(event, &["pid", "packet_id"]).unwrap_or_default();
    let source_device_id = cloud_mcp_tokenomics_response_text(event, &["sdid", "source_device_id"])
        .unwrap_or_default();
    let day_start_ms = cloud_mcp_tokenomics_day_start_from_value(event)
        .map(|value| value.to_string())
        .unwrap_or_default();
    let sync_day = cloud_mcp_tokenomics_response_text(event, &["sd", "sync_day", "day_key"])
        .unwrap_or_default();
    let content_hash = cloud_mcp_tokenomics_day_content_hash_from_value(event).unwrap_or_default();
    let server_cursor = cloud_mcp_tokenomics_server_cursor_from_value(event).unwrap_or_default();
    if packet_id.is_empty()
        && source_device_id.is_empty()
        && day_start_ms.is_empty()
        && sync_day.is_empty()
        && content_hash.is_empty()
        && server_cursor.is_empty()
    {
        return None;
    }
    Some(format!(
        "{}::{}::{}::{}::{}::{}::{}",
        event_kind,
        source_device_id,
        packet_id,
        day_start_ms,
        sync_day,
        content_hash,
        server_cursor
    ))
}

fn cloud_mcp_remote_command_id(event: &Value) -> String {
    cloud_mcp_remote_command_field_text(event, &["command_id"])
        .unwrap_or_default()
        .trim()
        .to_string()
}

fn cloud_mcp_remote_command_kind(event: &Value) -> String {
    cloud_mcp_remote_command_field_text(event, &["command_kind", "action", "command"])
        .unwrap_or_default()
        .trim()
        .to_ascii_lowercase()
        .replace(['.', ' ', '-'], "_")
}

fn cloud_mcp_daemon_gui_block_message(command_kind: &str) -> Option<&'static str> {
    match command_kind {
        "app_show_window" | "show_window" | "open_app_window" | "app_open_window"
        | "app_hide_window" | "hide_window" | "app_background" | "hide_app_window" => {
            Some("Window visibility controls are unavailable in daemon mode.")
        }
        // workspace_activate/open_workspace intentionally NOT blocked: its
        // complete command is journaled to shared disk and answered "queued",
        // so a later GUI listener can replay and acknowledge the UI handoff.
        "app_view_select"
        | "select_app_view"
        | "switch_app_view"
        | "app_navigate"
        | "app_open_view"
        | "workspace_select"
        | "select_workspace"
        | "switch_workspace"
        | "workspace_tab_select"
        | "select_workspace_tab"
        | "switch_workspace_tab"
        | "workspace_open_tab" => {
            Some("Remote navigation controls are unavailable in daemon mode.")
        }
        "workspace_panel_close"
        | "close_workspace_panel"
        | "panel_close"
        | "close_panel"
        | "terminal_window_breakout"
        | "breakout_terminal"
        | "breakout_terminals"
        | "terminal_breakout"
        | "open_terminal_window"
        | "terminal_window_open"
        | "terminal_window_return"
        | "return_terminal_window"
        | "return_terminal_to_grid"
        | "close_terminal_window"
        | "terminal_window_close" => {
            Some("Remote panel and window controls are unavailable in daemon mode.")
        }
        "terminal_open"
        | "open_terminal"
        | "open_terminals"
        | "terminal_spawn"
        | "spawn_terminals"
        | "agent_chat_session_open"
        | "open_agent_chat_session"
        | "session_open"
        | "open_session"
        | "resume_agent_chat_session"
        | "resume_session"
        | "terminal_relaunch_agent"
        | "relaunch_terminal_agent"
        | "relaunch_terminal"
        | "terminal_relaunch"
        | "terminal_restart"
        | "terminal_restart_agent"
        | "restart_terminal"
        | "restart_terminal_agent"
        | "terminal_switch_agent"
        | "switch_terminal_agent" => {
            Some("Remote terminal foreground controls are unavailable in daemon mode.")
        }
        "agent_chat_change_model"
        | "change_agent_chat_model"
        | "agent_chat_model_change"
        | "change_session_model"
        | "session_model_change"
        | "agent_chat_change_effort"
        | "change_agent_chat_effort"
        | "agent_chat_effort_change"
        | "change_session_effort"
        | "session_effort_change" => {
            Some("Remote live-session configuration is unavailable in daemon mode.")
        }
        "agent_account_login"
        | "terminal_provider_login"
        | "provider_login"
        | "agent_login"
        | "sign_in_agent" => Some("Provider sign-in requires the desktop application UI."),
        "todo_requeue"
        | "requeue_todo"
        | "todo_retry"
        | "retry_todo"
        | "todo_unqueue"
        | "unqueue_todo"
        | "workspace_todo_unqueue"
        | "todo_dequeue"
        | "dequeue_todo" => {
            Some("Remote todo queue panel controls are unavailable in daemon mode.")
        }
        _ => None,
    }
}

async fn cloud_mcp_apply_daemon_remote_command_guard(state: &CloudMcpState, event: &Value) -> bool {
    if !crate::daemon_mode_active() {
        return false;
    }
    let command_kind = cloud_mcp_remote_command_kind(event);
    let Some(message) = cloud_mcp_daemon_gui_block_message(command_kind.as_str()) else {
        return false;
    };
    let details = json!({
        "reason": "daemon_mode",
        "daemon_mode": true,
        "requires_gui": true,
        "command_kind": command_kind});
    let _ = cloud_mcp_send_remote_command_status_event(
        state,
        event,
        "blocked",
        message,
        Some(&details),
    )
    .await;
    true
}

fn cloud_mcp_remote_command_is_cancel(event: &Value) -> bool {
    matches!(
        cloud_mcp_remote_command_kind(event).as_str(),
        "remote_command_cancel" | "cancel_remote_command" | "command_cancel"
    )
}

fn cloud_mcp_remote_command_cancel_target_id(event: &Value) -> String {
    cloud_mcp_remote_command_field_text(event, &["cancel_command_id", "target_command_id"])
        .unwrap_or_default()
        .trim()
        .to_string()
}

fn cloud_mcp_remote_command_receipts_contains_id(
    receipts: &HashMap<String, u64>,
    command_id: &str,
) -> bool {
    if command_id.trim().is_empty() {
        return false;
    }
    let needle = format!("::{command_id}::");
    receipts.keys().any(|key| key.contains(&needle))
}

async fn cloud_mcp_claim_remote_command_receipt(state: &CloudMcpState, event: &Value) -> bool {
    log_cloud_sync_event(
        "remote_command.received",
        json!({
            "command_id": cloud_mcp_remote_command_id(event),
            "command_kind": cloud_mcp_remote_command_kind(event),
            "target_device_id": cloud_mcp_remote_command_field_text(event, &["target_device_id"]),
            "workspace_id": cloud_mcp_remote_command_field_text(event, &["workspace_id"]),
        }),
    );
    let Some(receipt_key) = cloud_mcp_remote_command_receipt_key(event) else {
        return true;
    };

    let now = cloud_mcp_now_ms();
    let mut receipts = state.remote_command_receipts.lock().await;
    receipts.retain(|_, received_ms| {
        now.saturating_sub(*received_ms) <= CLOUD_MCP_REMOTE_COMMAND_RECEIPT_TTL_MS
    });
    if receipts.contains_key(&receipt_key) {
        return false;
    }
    if receipts.len() >= CLOUD_MCP_REMOTE_COMMAND_RECEIPT_MAX {
        if let Some(oldest_key) = receipts
            .iter()
            .min_by_key(|(_, received_ms)| *received_ms)
            .map(|(key, _)| key.clone())
        {
            receipts.remove(&oldest_key);
        }
    }
    receipts.insert(receipt_key, now);
    true
}

fn cloud_mcp_duplicate_remote_command_is_ui_retry_for(
    event: &Value,
    webview_dispatcher_active: bool,
    daemon_mode_active: bool,
) -> bool {
    webview_dispatcher_active
        && !daemon_mode_active
        && !cloud_mcp_remote_command_is_rust_owned(event)
}

fn cloud_mcp_duplicate_remote_command_is_ui_retry(event: &Value) -> bool {
    cloud_mcp_duplicate_remote_command_is_ui_retry_for(
        event,
        todo_dispatch_webview_dispatcher_active(),
        crate::daemon_mode_active(),
    )
}

async fn cloud_mcp_ack_duplicate_remote_command(
    app: &AppHandle,
    state: &CloudMcpState,
    event: &Value,
) {
    let ui_retry = cloud_mcp_duplicate_remote_command_is_ui_retry(event);
    if ui_retry {
        // Rust claims the network receipt before handing UI-owned commands to
        // React. If that first Tauri event raced a webview remount, a delivery
        // retry must cross the bridge again. React has its own command-id
        // receipt guard, so an already handled command remains exactly-once.
        let _ = app.emit(CLOUD_MCP_REMOTE_COMMAND_EVENT, event.clone());
    }
    let details = json!({
        "duplicate_delivery": true,
        "ui_redelivered": ui_retry,
    });
    let _ = cloud_mcp_send_remote_command_status_event(
        state,
        event,
        "received",
        if ui_retry {
            "Remote command delivery retried to the desktop UI."
        } else {
            "Remote command was already received by the desktop."
        },
        Some(&details),
    )
    .await;
}

async fn cloud_mcp_remote_command_cancelled_before_receipt(
    state: &CloudMcpState,
    event: &Value,
) -> bool {
    let command_id = cloud_mcp_remote_command_id(event);
    if command_id.is_empty() {
        return false;
    }
    let now = cloud_mcp_now_ms();
    let mut cancellations = state.remote_command_cancellations.lock().await;
    cancellations.retain(|_, received_ms| {
        now.saturating_sub(*received_ms) <= CLOUD_MCP_REMOTE_COMMAND_RECEIPT_TTL_MS
    });
    cancellations.contains_key(&command_id)
}

async fn cloud_mcp_handle_remote_command_cancel(state: &CloudMcpState, event: &Value) -> bool {
    if !cloud_mcp_remote_command_is_cancel(event) {
        return false;
    }
    let cancel_target_id = cloud_mcp_remote_command_cancel_target_id(event);
    if cancel_target_id.is_empty() {
        let _ = cloud_mcp_send_remote_command_status_event(
            state,
            event,
            "failed",
            "Remote command cancellation did not include cancel_command_id.",
            None,
        )
        .await;
        return true;
    }

    let now = cloud_mcp_now_ms();
    let already_received = {
        let mut receipts = state.remote_command_receipts.lock().await;
        receipts.retain(|_, received_ms| {
            now.saturating_sub(*received_ms) <= CLOUD_MCP_REMOTE_COMMAND_RECEIPT_TTL_MS
        });
        cloud_mcp_remote_command_receipts_contains_id(&receipts, &cancel_target_id)
    };
    if already_received {
        let details = json!({ "cancel_command_id": cancel_target_id });
        let _ = cloud_mcp_send_remote_command_status_event(
            state,
            event,
            "blocked",
            "Remote command was already received by the desktop, so it cannot be cancelled from the dashboard.",
            Some(&details),
        )
        .await;
        return true;
    }

    {
        let mut cancellations = state.remote_command_cancellations.lock().await;
        cancellations.retain(|_, received_ms| {
            now.saturating_sub(*received_ms) <= CLOUD_MCP_REMOTE_COMMAND_RECEIPT_TTL_MS
        });
        if cancellations.len() >= CLOUD_MCP_REMOTE_COMMAND_RECEIPT_MAX {
            if let Some(oldest_key) = cancellations
                .iter()
                .min_by_key(|(_, received_ms)| *received_ms)
                .map(|(key, _)| key.clone())
            {
                cancellations.remove(&oldest_key);
            }
        }
        cancellations.insert(cancel_target_id.clone(), now);
    }

    let mut cancelled_event = event.clone();
    if let Some(object) = cancelled_event.as_object_mut() {
        object.insert("command_id".to_string(), json!(cancel_target_id.clone()));
        if let Some(original_kind) = cloud_mcp_payload_text(event, &["cancel_command_kind"])
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "cancel_command_kind"]))
            .filter(|value| !value.trim().is_empty())
        {
            object.insert("command_kind".to_string(), json!(original_kind));
        }
    }
    let cancelled_details = json!({ "cancelled_before_receipt": true });
    let _ = cloud_mcp_send_remote_command_status_event(
        state,
        &cancelled_event,
        "cancelled",
        "Remote command cancelled before the desktop received it.",
        Some(&cancelled_details),
    )
    .await;
    let cancel_details = json!({ "cancel_command_id": cancel_target_id });
    let _ = cloud_mcp_send_remote_command_status_event(
        state,
        event,
        "completed",
        "Cancellation request accepted.",
        Some(&cancel_details),
    )
    .await;
    true
}

async fn cloud_mcp_claim_tokenomics_wake_receipt(state: &CloudMcpState, event: &Value) -> bool {
    let Some(receipt_key) = cloud_mcp_tokenomics_wake_receipt_key(event) else {
        return true;
    };

    let now = cloud_mcp_now_ms();
    let mut receipts = state.tokenomics_wake_receipts.lock().await;
    receipts.retain(|_, received_ms| {
        now.saturating_sub(*received_ms) <= CLOUD_MCP_TOKENOMICS_WAKE_RECEIPT_TTL_MS
    });
    if receipts.contains_key(&receipt_key) {
        return false;
    }
    if receipts.len() >= CLOUD_MCP_TOKENOMICS_WAKE_RECEIPT_MAX {
        if let Some(oldest_key) = receipts
            .iter()
            .min_by_key(|(_, received_ms)| *received_ms)
            .map(|(key, _)| key.clone())
        {
            receipts.remove(&oldest_key);
        }
    }
    receipts.insert(receipt_key, now);
    true
}

async fn cloud_mcp_send_remote_command_status_event(
    state: &CloudMcpState,
    event: &Value,
    status: &str,
    message: &str,
    details: Option<&Value>,
) -> Result<Value, String> {
    let now = cloud_mcp_now_ms();
    let device_profile = cloud_mcp_desktop_device_profile();
    let target_terminal_nickname = cloud_mcp_terminal_nickname_text(
        event,
        &[
            "target_terminal_nickname",
            "terminal_nickname",
            "target_terminal_name",
            "terminal_name",
            "target_name",
            "name",
        ],
    )
    .or_else(|| {
        event.get("payload").and_then(|payload| {
            cloud_mcp_terminal_nickname_text(
                payload,
                &[
                    "target_terminal_nickname",
                    "terminal_nickname",
                    "target_terminal_name",
                    "terminal_name",
                    "target_name",
                    "name",
                ],
            )
        })
    });
    let status_kind = if matches!(
        status,
        "blocked"
            | "completed"
            | "dropped"
            | "error"
            | "failed"
            | "rejected"
            | "cancelled"
            | "canceled"
            | "paused"
            | "parked"
            | "resume_ready"
            | "resume_requested"
            | "interrupted"
            | "timed_out"
            | "timeout"
    ) {
        "remote_command_result"
    } else {
        "remote_command_ack"
    };
    let mut payload = json!({
        "source": "rust-diffforge-remote-control",
        "event_kind": status_kind,
        "command_id": cloud_mcp_remote_command_field_text(event, &["command_id"]),
        "todo_dispatch_id": cloud_mcp_payload_text(event, &["todo_dispatch_id"])
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "todo_dispatch_id"])),
        "todo_id": cloud_mcp_payload_text(event, &["todo_id"])
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "todo_id"])),
        "asset_id": cloud_mcp_payload_text(event, &["asset_id"])
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "asset_id"])),
        "cloud_id": cloud_mcp_payload_text(event, &["cloud_id"])
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "cloud_id"])),
        "todo_workspace_id": cloud_mcp_payload_text(event, &["todo_workspace_id"])
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "todo_workspace_id"])),
        "todo_device_id": cloud_mcp_payload_text(event, &["todo_device_id"])
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "todo_device_id"])),
        "command_kind": cloud_mcp_remote_command_field_text(event, &["command_kind"]),
        "intent_id": cloud_mcp_payload_text(event, &["intent_id"])
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "intent_id"])),
        "loop_runtime_run_id": cloud_mcp_payload_text(event, &["loop_runtime_run_id"])
            .or_else(|| cloud_mcp_payload_text(event, &["run_id"]))
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "loop_runtime_run_id"]))
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "run_id"])),
        "loop_runtime_node_id": cloud_mcp_payload_text(event, &["loop_runtime_node_id"])
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "loop_runtime_node_id"])),
        "loop_runtime_edge_id": cloud_mcp_payload_text(event, &["loop_runtime_edge_id"])
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "loop_runtime_edge_id"])),
        "loopspace_id": cloud_mcp_payload_text(event, &["loopspace_id"])
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "loopspace_id"])),
        "trigger_id": cloud_mcp_payload_text(event, &["trigger_id"])
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "trigger_id"])),
        "trigger_run_id": cloud_mcp_payload_text(event, &["trigger_run_id"])
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "trigger_run_id"])),
        "target_agent_id": cloud_mcp_payload_text(event, &["target_agent_id"])
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "target_agent_id"])),
        "target_device_id": cloud_mcp_remote_command_field_text(event, &["target_device_id"]),
        "target_terminal_id": cloud_mcp_remote_command_field_text(
            event,
            &["target_terminal_id", "terminal_id", "pane_id"],
        ),
        "target_terminal_nickname": target_terminal_nickname.clone(),
        "target_terminal_name": target_terminal_nickname,
        "target_terminal_index": cloud_mcp_payload_text(event, &["target_terminal_index"])
            .or_else(|| cloud_mcp_payload_text(event, &["terminal_index"]))
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "target_terminal_index"]))
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "terminal_index"])),
        "target_thread_id": cloud_mcp_payload_text(event, &["target_thread_id"])
            .or_else(|| cloud_mcp_payload_text(event, &["thread_id"]))
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "target_thread_id"]))
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "thread_id"])),
        "target_terminal_color": cloud_mcp_payload_text(event, &["target_terminal_color"])
            .or_else(|| cloud_mcp_payload_text(event, &["terminal_color"]))
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "target_terminal_color"]))
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "terminal_color"])),
        "target_color_slot": cloud_mcp_payload_text(event, &["target_color_slot"])
            .or_else(|| cloud_mcp_payload_text(event, &["color_slot"]))
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "target_color_slot"]))
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "color_slot"])),
        "device": device_profile.clone(),
        "device_id": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "origin_connection_id": cloud_mcp_payload_text(event, &["origin_connection_id"]),
        "repo_id": cloud_mcp_payload_text(event, &["repo_id"])
            .or_else(|| cloud_mcp_payload_text(event, &["payload", "repo_id"])),
        "workspace_id": cloud_mcp_remote_command_field_text(event, &["workspace_id"]),
        "status": status,
        "message": message,
        "rust_received_ms": now,
        "ts_ms": now});
    if let Some(dispatch_source) =
        cloud_mcp_payload_object(event, &["dispatch_source"]).or_else(|| {
            event
                .get("payload")
                .and_then(|payload| cloud_mcp_payload_object(payload, &["dispatch_source"]))
        })
    {
        payload["dispatch_source"] = dispatch_source;
    }
    if let Some(dispatch_target) =
        cloud_mcp_payload_object(event, &["dispatch_target"]).or_else(|| {
            event
                .get("payload")
                .and_then(|payload| cloud_mcp_payload_object(payload, &["dispatch_target"]))
        })
    {
        payload["dispatch_target"] = dispatch_target;
    }
    if let Some(details) = details {
        if !details.is_null() {
            payload["details"] = details.clone();
            payload["result"] = details.clone();
        }
    }
    // Remote controls are user-visible state transitions, so their callbacks
    // need the same durable delivery contract as todo/live-state writes. A
    // direct websocket send could succeed locally and then disappear during a
    // reconnect, leaving the dashboard stuck in pending even though the
    // desktop already performed the action. The outbox retries the exact
    // status payload (and its command id) until Cloud acknowledges it.
    let command_id = cloud_mcp_remote_command_id(event);
    log_cloud_sync_event(
        "remote_command.status_queued",
        json!({
            "command_id": command_id.clone(),
            "command_kind": cloud_mcp_remote_command_kind(event),
            "status": status,
            "workspace_id": cloud_mcp_remote_command_field_text(event, &["workspace_id"]),
        }),
    );
    let direct_state = state.clone();
    let direct_payload = payload.clone();
    let direct_status_kind = status_kind.to_string();
    tauri::async_runtime::spawn(async move {
        let result = cloud_mcp_send_event_over_app_ws_once(
            &direct_state,
            &direct_status_kind,
            &direct_payload,
            "remote-command-status-live",
        )
        .await;
        log_cloud_sync_event(
            "remote_command.status_live_sent",
            json!({
                "event_kind": direct_status_kind,
                "ok": result.is_ok(),
                "error": result.err().map(|error| clean_terminal_telemetry_text(&error)),
            }),
        );
    });
    cloud_mcp_enqueue_background_sync(
        state,
        format!("remote-command-status:{command_id}:{status}:{now}"),
        status_kind,
        payload.clone(),
        cloud_mcp_outbox_priority_for_event(status_kind),
        "remote_command_status",
    )
    .await;
    if cloud_mcp_payload_text(&payload, &["todo_dispatch_id"]).is_some() {
        let _ = cloud_mcp_apply_local_workspace_todo_event(
            state,
            "workspace_todo_dispatch_status",
            &payload,
            "remote_command_todo_status_local",
        )
        .await;
    }
    Ok(json!({
        "ok": true,
        "queued": true,
        "durable": true,
        "status": status,
    }))
}

fn cloud_mcp_client_action_ack_payload(
    client_action_id: &str,
    action_kind: &str,
    result: &str,
    entity_id: Option<&str>,
    error: Option<&str>,
) -> Value {
    let mut payload = json!({
        "client_action_id": client_action_id.trim(),
        "action_kind": action_kind.trim(),
        "result": result.trim(),
    });
    if let Some(object) = payload.as_object_mut() {
        if let Some(entity_id) = entity_id.map(str::trim).filter(|value| !value.is_empty()) {
            object.insert("entity_id".to_string(), json!(entity_id));
        }
        if let Some(error) = error.map(str::trim).filter(|value| !value.is_empty()) {
            object.insert("error".to_string(), json!(error));
        }
    }
    payload
}

pub(crate) async fn cloud_mcp_send_client_action_ack(
    state: &CloudMcpState,
    event: &Value,
    action_kind: &str,
    result: &str,
    entity_id: Option<&str>,
    error: Option<&str>,
) -> Result<Value, String> {
    let client_action_id =
        cloud_mcp_remote_command_field_text(event, &["client_action_id"]).unwrap_or_default();
    if client_action_id.trim().is_empty() {
        return Ok(json!({"ok": true, "skipped": true, "reason": "missing_client_action_id"}));
    }
    if !matches!(action_kind, "message" | "todo") {
        return Err("client_action_ack action_kind must be message or todo.".to_string());
    }
    if !matches!(result, "applied" | "failed") {
        return Err("client_action_ack result must be applied or failed.".to_string());
    }
    let payload = cloud_mcp_client_action_ack_payload(
        &client_action_id,
        action_kind,
        result,
        entity_id,
        error,
    );
    cloud_mcp_send_event_over_app_ws_once(state, "client_action_ack", &payload, "client-action-ack")
        .await
}

async fn cloud_mcp_ack_remote_todo_intake(state: &CloudMcpState, event: &Value, outcome: &Value) {
    let status = cloud_mcp_payload_text(outcome, &["status"])
        .unwrap_or_default()
        .to_ascii_lowercase();
    let failed = matches!(status.as_str(), "failed" | "rejected" | "error");
    let entity_id = cloud_mcp_payload_text(outcome, &["details", "todo_id"])
        .or_else(|| cloud_mcp_payload_text(outcome, &["details", "todo_id"]))
        .or_else(|| cloud_mcp_remote_command_field_text(event, &["todo_id"]))
        .or_else(|| cloud_mcp_remote_command_field_text(event, &["command_id"]));
    let error = failed
        .then(|| cloud_mcp_payload_text(outcome, &["message"]).unwrap_or_else(|| status.clone()));
    let Some(action_kind) = cloud_mcp_remote_todo_intake_ack_action_kind(event, failed) else {
        return;
    };
    let _ = cloud_mcp_send_client_action_ack(
        state,
        event,
        action_kind,
        if failed { "failed" } else { "applied" },
        entity_id.as_deref(),
        error.as_deref(),
    )
    .await;
}

async fn cloud_mcp_ack_remote_todo_delete(state: &CloudMcpState, event: &Value, outcome: &Value) {
    let status = cloud_mcp_payload_text(outcome, &["status"])
        .unwrap_or_default()
        .trim()
        .to_ascii_lowercase();
    let failed = matches!(status.as_str(), "failed" | "rejected" | "error");
    let entity_id = cloud_mcp_payload_text(outcome, &["details", "todo_id"])
        .or_else(|| cloud_mcp_payload_text(outcome, &["details", "todo_id"]))
        .or_else(|| cloud_mcp_remote_command_field_text(event, &["todo_id"]));
    let error = failed
        .then(|| cloud_mcp_payload_text(outcome, &["message"]).unwrap_or_else(|| status.clone()));
    let _ = cloud_mcp_send_client_action_ack(
        state,
        event,
        "todo",
        if failed { "failed" } else { "applied" },
        entity_id.as_deref(),
        error.as_deref(),
    )
    .await;
}

fn cloud_mcp_remote_todo_intake_ack_action_kind(
    event: &Value,
    failed: bool,
) -> Option<&'static str> {
    if todo_dispatch_remote_command_is_message_intent(event) {
        failed.then_some("message")
    } else {
        Some("todo")
    }
}

#[tauri::command(rename_all = "snake_case")]
async fn cloud_mcp_record_client_action_ack(
    state: State<'_, CloudMcpState>,
    client_action_id: String,
    action_kind: String,
    result: String,
    entity_id: Option<String>,
    error: Option<String>,
) -> Result<Value, String> {
    let event = json!({"client_action_id": client_action_id});
    cloud_mcp_send_client_action_ack(
        state.inner(),
        &event,
        action_kind.trim(),
        result.trim(),
        entity_id.as_deref(),
        error.as_deref(),
    )
    .await
}

#[tauri::command(rename_all = "snake_case")]
async fn cloud_mcp_start_remote_command_listener(
    app: AppHandle,
    state: State<'_, CloudMcpState>,
) -> Result<Value, String> {
    if state
        .remote_command_listener_started
        .swap(true, Ordering::SeqCst)
    {
        return Ok(json!({"ok": true, "already_running": true}));
    }

    let state_clone = state.inner().clone();
    cloud_mcp_start_global_ws(&state_clone).await;
    let mut ws_events = state.global_ws_events.subscribe();
    tauri::async_runtime::spawn(async move {
        loop {
            if crate::app_shutdown_requested() {
                break;
            }
            let event = match ws_events.recv().await {
                Ok(event) => event,
                Err(tokio::sync::broadcast::error::RecvError::Lagged(_)) => continue,
                Err(tokio::sync::broadcast::error::RecvError::Closed) => break,
            };
            let event_kind = cloud_mcp_payload_text(&event, &["event_kind"])
                .or_else(|| cloud_mcp_payload_text(&event, &["kind"]))
                .unwrap_or_default();
            let contract = cloud_mcp_payload_text(&event, &["contract"]).unwrap_or_default();
            if contract == "diffforge.account_usage.v1"
                || event_kind == "account_usage_snapshot"
                || event_kind.starts_with("credit_wallet_")
            {
                let _ = app.emit(CLOUD_MCP_ACCOUNT_USAGE_EVENT, event.clone());
                continue;
            }
            if (contract == "diffforge.native_sessions.v1"
                || event_kind == "native_sessions_status")
                && event_kind != "native_sessions_changed"
            {
                if cloud_mcp_native_sessions_from_value(&event).is_some() {
                    let _ = app.emit(CLOUD_MCP_NATIVE_SESSIONS_UPDATED_EVENT, event.clone());
                }
                continue;
            }
            if event_kind == "native_sessions_changed" {
                let has_native_sessions_payload =
                    cloud_mcp_native_sessions_from_value(&event).is_some();
                let _ = app.emit(CLOUD_MCP_NATIVE_SESSIONS_UPDATED_EVENT, event.clone());
                if !has_native_sessions_payload {
                    cloud_mcp_spawn_native_sessions_status_request(
                        &app,
                        &state_clone,
                        "native_sessions_changed",
                    );
                }
                continue;
            }
            if event_kind == "account_device_live_state_snapshot" {
                cloud_mcp_apply_audio_preferences_from_account_live_state(
                    &app,
                    &state_clone,
                    &event,
                )
                .await;
                cloud_mcp_apply_notification_preferences_from_account_live_state(
                    &app,
                    &state_clone,
                    &event,
                )
                .await;
                let _ = app.emit(CLOUD_MCP_ACCOUNT_DEVICE_LIVE_STATE_EVENT, event.clone());
                continue;
            }
            if cloud_mcp_is_notification_preferences_sync_unit_event(&event_kind, &event) {
                cloud_mcp_apply_notification_preferences_from_account_live_state(
                    &app,
                    &state_clone,
                    &event,
                )
                .await;
                continue;
            }
            if cloud_mcp_is_account_documents_sync_wake_event(&event_kind, &event) {
                let event_to_emit = match cloud_mcp_account_documents_preapplied_payload(&event) {
                    Some(applied) => applied,
                    None => {
                        match cloud_mcp_apply_account_documents_sync_data_with_hydration(
                            &state_clone,
                            &event,
                            "remote_command_listener_documents",
                        )
                        .await
                        {
                            Ok(applied) => applied,
                            Err(error) => {
                                log_cloud_sync_event(
                                    "account_documents.listener_apply_error",
                                    json!({
                                        "event_kind": event_kind,
                                        "error": clean_terminal_telemetry_text(&error),
                                    }),
                                );
                                event.clone()
                            }
                        }
                    }
                };
                let _ = app.emit(CLOUD_MCP_ACCOUNT_DOCUMENTS_UPDATED_EVENT, event_to_emit);
                continue;
            }
            if matches!(
                contract.as_str(),
                "diffforge.account_clis.v1" | "diffforge.account_mcps.v1"
            ) || matches!(
                event_kind.as_str(),
                "account_cli_changed" | "account_mcp_changed"
            ) {
                let _ = app.emit(CLOUD_MCP_ACCOUNT_TOOLS_UPDATED_EVENT, event.clone());
                continue;
            }
            if event_kind == "tokenomics_refresh_requested" {
                log_cloud_sync_event(
                    "tokenomics.server_refresh_ignored",
                    json!({
                        "reason": "client_owned_tokenomics",
                        "event_kind": event_kind,
                    }),
                );
                continue;
            }
            if event_kind == "device_deleted" || event_kind == "device.removed" {
                if cloud_mcp_remote_command_matches_device(&event) {
                    let _ = app.emit(CLOUD_MCP_DEVICE_DELETED_EVENT, event.clone());
                }
                continue;
            }
            if event_kind == "workspace_catalog_changed" {
                continue;
            }
            if cloud_mcp_is_tokenomics_delta_signal_event(&event_kind) {
                let has_summary = cloud_mcp_tokenomics_event_has_summary(&event);
                log_cloud_sync_event(
                    "tokenomics.server_delta_ignored",
                    json!({
                        "event_kind": event_kind,
                        "delivery_id": cloud_mcp_tokenomics_delivery_id_from_value(&event),
                        "has_summary": has_summary,
                        "originated_from_this_device": cloud_mcp_event_originated_from_this_device(&event),
                        "server_cursor": cloud_mcp_tokenomics_server_cursor_from_value(&event),
                        "reason": "client_owned_tokenomics",
                    }),
                );
                continue;
            }
            if cloud_mcp_is_tokenomics_state_event(&event_kind) {
                log_cloud_sync_event(
                    "tokenomics.server_state_ignored",
                    json!({
                        "event_kind": event_kind,
                        "delivery_id": cloud_mcp_tokenomics_delivery_id_from_value(&event),
                        "server_cursor": cloud_mcp_tokenomics_server_cursor_from_value(&event),
                        "reason": "client_owned_tokenomics",
                    }),
                );
                continue;
            }
            if agent_account_push_handle_remote_status(&app, &event) {
                continue;
            }
            if cloud_mcp_is_workspace_todo_wake_event(&event_kind, &event) {
                let _ = app.emit(CLOUD_MCP_WORKSPACE_TODOS_UPDATED_EVENT, event.clone());
                if event_kind != "remote_command_requested" {
                    continue;
                }
            }
            if contract == CLOUD_MCP_LOOPSPACES_CONTRACT
                || cloud_mcp_is_loopspaces_sync_event_kind(&event_kind)
            {
                let payload = match cloud_mcp_apply_loopspaces_sync_data(
                    &state_clone,
                    &event,
                    "remote_command_listener_loopspaces",
                )
                .await
                {
                    Ok(snapshot) => snapshot,
                    Err(error) => {
                        log_cloud_sync_event(
                            "loopspaces.listener_apply_error",
                            json!({ "error": clean_terminal_telemetry_text(&error) }),
                        );
                        event.clone()
                    }
                };
                let _ = app.emit(CLOUD_MCP_LOOPSPACES_UPDATED_EVENT, payload);
                continue;
            }
            if contract == CLOUD_MCP_LOOPSPACE_TRIGGERS_CONTRACT
                || cloud_mcp_is_loopspace_triggers_sync_event_kind(&event_kind)
            {
                let payload = match cloud_mcp_apply_loopspace_triggers_sync_data(
                    &state_clone,
                    &event,
                    "remote_command_listener_loopspace_triggers",
                )
                .await
                {
                    Ok(snapshot) => snapshot,
                    Err(error) => {
                        log_cloud_sync_event(
                            "loopspace_triggers.listener_apply_error",
                            json!({ "error": clean_terminal_telemetry_text(&error) }),
                        );
                        event.clone()
                    }
                };
                let _ = app.emit(CLOUD_MCP_LOOPSPACE_TRIGGERS_UPDATED_EVENT, payload);
                continue;
            }
            if cloud_mcp_is_account_asset_wake_event(&event_kind, &event) {
                let event_for_ingest = event.clone();
                let event_for_emit = tauri::async_runtime::spawn_blocking(move || {
                    cloud_mcp_update_asset_library_from_response(
                        "account_asset_fanout",
                        None,
                        &Value::Null,
                        &event_for_ingest,
                    );
                    event_for_ingest
                })
                .await
                .unwrap_or_else(|_| event.clone());
                let _ = app.emit(CLOUD_MCP_ACCOUNT_ASSETS_UPDATED_EVENT, event_for_emit);
                continue;
            }
            if cloud_mcp_is_voice_plan_result_event(&event_kind) {
                let result = event
                    .get("result")
                    .cloned()
                    .or_else(|| {
                        event
                            .get("stored")
                            .and_then(|stored| stored.get("result"))
                            .cloned()
                    })
                    .unwrap_or_else(|| event.clone());
                let workspace_id = cloud_mcp_payload_text(&event, &["workspace_id"])
                    .or_else(|| cloud_mcp_payload_text(&result, &["workspace_id"]))
                    .unwrap_or_default();
                let _ = app.emit(
                    VOICE_PLAN_SERVER_RESULT_EVENT,
                    json!({
                        "result": result,
                        "source": "cloud_voice_plan_graph_event",
                        "workspace_id": workspace_id,
                    }),
                );
                continue;
            }
            if event_kind != "remote_command_requested" {
                continue;
            }
            if !cloud_mcp_remote_command_matches_device(&event) {
                continue;
            }
            if cloud_mcp_handle_remote_command_cancel(&state_clone, &event).await {
                continue;
            }
            if cloud_mcp_remote_command_cancelled_before_receipt(&state_clone, &event).await {
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state_clone,
                    &event,
                    "cancelled",
                    "Remote command was cancelled before desktop execution.",
                    None,
                )
                .await;
                continue;
            }
            if !cloud_mcp_claim_remote_command_receipt(&state_clone, &event).await {
                cloud_mcp_ack_duplicate_remote_command(&app, &state_clone, &event).await;
                continue;
            }
            let _ = cloud_mcp_send_remote_command_status_event(
                &state_clone,
                &event,
                "received",
                "Remote command received by desktop.",
                None,
            )
            .await;
            let intake_outcome = todo_dispatch_record_remote_intake(&app, &event);
            if let Some(outcome) = intake_outcome.as_ref() {
                let status = cloud_mcp_payload_text(outcome, &["status"]).unwrap_or_default();
                let message = cloud_mcp_payload_text(outcome, &["message"]).unwrap_or_default();
                let details = outcome.get("details");
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state_clone,
                    &event,
                    &status,
                    &message,
                    details,
                )
                .await;
                cloud_mcp_ack_remote_todo_intake(&state_clone, &event, outcome).await;
            }
            let delete_outcome = todo_dispatch_apply_remote_delete(&app, &event);
            if let Some(outcome) = delete_outcome.as_ref() {
                let status = cloud_mcp_payload_text(outcome, &["status"]).unwrap_or_default();
                let message = cloud_mcp_payload_text(outcome, &["message"]).unwrap_or_default();
                let details = outcome.get("details");
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state_clone,
                    &event,
                    &status,
                    &message,
                    details,
                )
                .await;
                cloud_mcp_ack_remote_todo_delete(&state_clone, &event, outcome).await;
            }
            if crate::daemon_mode_active() && (intake_outcome.is_some() || delete_outcome.is_some())
            {
                continue;
            }
            if cloud_mcp_apply_daemon_remote_command_guard(&state_clone, &event).await {
                continue;
            }
            let remote_lever_handled =
                cloud_mcp_apply_remote_workspace_lever(&app, &state_clone, &event)
                    || orchestrator_pool_apply_remote_send_lever(&app, &state_clone, &event)
                    || cloud_mcp_apply_remote_terminal_interrupt_lever(&app, &state_clone, &event)
                    || cloud_mcp_apply_remote_terminal_lever(&app, &state_clone, &event)
                    || cloud_mcp_apply_remote_agent_lever(&app, &state_clone, &event)
                    || cloud_mcp_apply_remote_agent_prompt_lever(&app, &state_clone, &event)
                    || cloud_mcp_apply_remote_asset_lever(&app, &state_clone, &event)
                    || cloud_mcp_apply_remote_local_script_lever(&app, &state_clone, &event)
                    || cloud_mcp_apply_remote_device_lever(&app, &state_clone, &event);
            if remote_lever_handled || cloud_mcp_remote_command_is_rust_owned(&event) {
                continue;
            }
            if crate::daemon_mode_active() {
                let details = json!({
                    "reason": "daemon_mode",
                    "daemon_mode": true,
                    "command_kind": cloud_mcp_remote_command_kind(&event),
                });
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state_clone,
                    &event,
                    "failed",
                    "Remote command requires the desktop UI and is unavailable in daemon mode.",
                    Some(&details),
                )
                .await;
                continue;
            }
            let emit_result = app.emit(CLOUD_MCP_REMOTE_COMMAND_EVENT, event.clone());
            let (status, message) = if emit_result.is_ok() {
                ("received", "Remote command received by desktop.")
            } else {
                (
                    "failed",
                    "Desktop UI was not available for the remote command.",
                )
            };
            let _ = cloud_mcp_send_remote_command_status_event(
                &state_clone,
                &event,
                status,
                message,
                None,
            )
            .await;
        }
    });
    Ok(json!({"ok": true, "started": true}))
}

/// Headless actuation for remote workspace lifecycle levers. Only runs when
/// no webview dispatcher is alive (the webview owns actuation when open).
fn cloud_mcp_apply_remote_workspace_lever(
    app: &AppHandle,
    state: &CloudMcpState,
    event: &Value,
) -> bool {
    let webview_dispatcher_active = todo_dispatch_webview_dispatcher_active();
    let command_kind = cloud_mcp_remote_command_kind(event);
    let requested_workspace_id =
        cloud_mcp_remote_command_field_text(event, &["workspace_id"]).unwrap_or_default();
    let workspace_id = cloud_mcp_resolve_local_workspace_id(&requested_workspace_id)
        .unwrap_or(requested_workspace_id);
    if workspace_id.is_empty() {
        return false;
    }
    match command_kind.as_str() {
        "workspace_activate" | "activate_workspace" | "open_workspace" | "workspace_open" => {
            // The public workspace_activate contract includes selecting the
            // workspace and opening its terminal tab. A hidden webview can
            // miss its short heartbeat lease even though it is healthy; do
            // not silently downgrade that request to runtime-only headless
            // activation. Journal the exact command, reveal the app, and let
            // AppShell acknowledge and apply the UI lifecycle atomically.
            if cloud_mcp_remote_workspace_requires_foreground(event) {
                let dropped = match cloud_mcp_defer_remote_command_for_foreground(app, event) {
                    Ok(dropped) => dropped,
                    Err(error) => {
                        let state = state.clone();
                        let event = event.clone();
                        tauri::async_runtime::spawn(async move {
                            let details = json!({
                                "handoff_persisted": false,
                                "persistence_error": clean_terminal_telemetry_text(&error),
                            });
                            let _ = cloud_mcp_send_remote_command_status_event(
                                &state,
                                &event,
                                "failed",
                                "Workspace activation could not be handed to the desktop UI safely.",
                                Some(&details),
                            )
                            .await;
                        });
                        return true;
                    }
                };
                app_exit_background_internal(app);
                if webview_dispatcher_active {
                    // The command was journaled before emit. If AppShell is
                    // between listener registrations this emit can be missed,
                    // but dispatcher_ready will replay the retained entry.
                    todo_dispatch_flush_deferred_remote_commands(app);
                }
                let state = state.clone();
                let event = event.clone();
                let workspace_id = workspace_id.clone();
                tauri::async_runtime::spawn(async move {
                    for dropped_event in dropped {
                        let _ = cloud_mcp_send_remote_command_status_event(
                            &state,
                            &dropped_event,
                            "dropped",
                            "Queued remote command was dropped because the foreground replay queue is full.",
                            None,
                        )
                        .await;
                    }
                    if !webview_dispatcher_active {
                        let details = json!({
                            "runtime_active": false,
                            "ui_handoff_pending": true,
                            "ui_selected": false,
                            "workspace_id": workspace_id,
                        });
                        let _ = cloud_mcp_send_remote_command_status_event(
                            &state,
                            &event,
                            "queued",
                            "Workspace activation queued for the desktop UI; opening Diff Forge.",
                            Some(&details),
                        )
                        .await;
                    }
                });
                return true;
            }
            if webview_dispatcher_active {
                return false;
            }
            let app = app.clone();
            let state = state.clone();
            let event = event.clone();
            tauri::async_runtime::spawn(async move {
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state,
                    &event,
                    "running",
                    "Activating workspace runtime headless.",
                    None,
                )
                .await;
                let result = workspace_activate_runtime_internal(
                    &app,
                    &workspace_id,
                    "remote_control_headless",
                )
                .await;
                match result {
                    Ok(mut result) => {
                        if let Some(details) = result.as_object_mut() {
                            details.insert("runtime_active".to_string(), json!(true));
                            details.insert("ui_selected".to_string(), json!(false));
                        }
                        let _ = cloud_mcp_send_remote_command_status_event(
                            &state,
                            &event,
                            "completed",
                            "Workspace runtime activated headless; the desktop UI was not selected.",
                            Some(&result),
                        )
                        .await;
                    }
                    Err(error) => {
                        let fallback_allowed =
                            cloud_mcp_remote_workspace_activation_error_allows_pending(&error);
                        if fallback_allowed {
                            let _ = app_local_state_merge(
                                &app,
                                "remote-intents",
                                &json!({
                                    "pendingActivationWorkspaceId": workspace_id,
                                    "pendingActivationReason": "remote_control_headless_fallback",
                                    "pendingActivationAtMs": cloud_mcp_now_ms(),
                                    "pendingActivationSelectWorkspace": true,
                                    "pendingActivationWorkspaceTab": "terminals",
                                }),
                            );
                        }
                        let details = json!({
                            "error": clean_terminal_telemetry_text(&error),
                            "pending_activation_stored": fallback_allowed,
                            "workspace_id": workspace_id,
                        });
                        let _ = cloud_mcp_send_remote_command_status_event(
                            &state,
                            &event,
                            "failed",
                            "Workspace runtime could not be activated headless.",
                            Some(&details),
                        )
                        .await;
                    }
                }
            });
            true
        }
        "terminal_relaunch_agent"
        | "relaunch_terminal_agent"
        | "relaunch_terminal"
        | "terminal_relaunch"
        | "terminal_switch_agent"
        | "switch_terminal_agent" => {
            // Terminal slots and agent threads live in webview state, so a
            // relaunch cannot actuate headless; tell the dashboard instead of
            // leaving the command pending forever.
            let state = state.clone();
            let event = event.clone();
            tauri::async_runtime::spawn(async move {
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state,
                    &event,
                    "blocked",
                    "The Diff Forge window is closed on this desktop; open it to relaunch terminals.",
                    None,
                )
                .await;
            });
            true
        }
        _ if webview_dispatcher_active => false,
        "workspace_deactivate_if_idle"
        | "deactivate_workspace_if_idle"
        | "workspace_deactivate" => {
            let busy = todo_dispatch_workspace_has_busy_terminals(&workspace_id);
            let app = app.clone();
            let state = state.clone();
            let event = event.clone();
            tauri::async_runtime::spawn(async move {
                if busy {
                    let _ = cloud_mcp_send_remote_command_status_event(
                        &state,
                        &event,
                        "blocked",
                        "Workspace still has busy terminals, so it was not deactivated.",
                        None,
                    )
                    .await;
                    return;
                }
                let result = deactivate_workspace_runtime(
                    app,
                    None,
                    Some("remote_control_headless".to_string()),
                    Some(workspace_id.clone()),
                    Some(true),
                )
                .await;
                let (status, message) = match result {
                    Ok(_) => (
                        "completed",
                        "Workspace deactivated headless from the web dashboard.",
                    ),
                    Err(_) => (
                        "failed",
                        "Workspace runtime could not be deactivated headless.",
                    ),
                };
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state, &event, status, message, None,
                )
                .await;
            });
            true
        }
        _ => false,
    }
}

fn cloud_mcp_remote_workspace_activation_error_allows_pending(error: &str) -> bool {
    let error = error.trim().to_ascii_lowercase();
    // "webview dispatcher active" DOES store the pending intent: the webview
    // came alive between the lever's gate and the orchestrator's own guard,
    // and it never saw this command (the lever consumed it) — the persisted
    // intent is how it still gets fulfilled.
    !(error.contains("unknown workspace") || error.contains("workspace root does not exist"))
}

fn cloud_mcp_agent_prompt_answer_details_failed(details: &Value) -> bool {
    details
        .get("status")
        .and_then(Value::as_str)
        .is_some_and(|status| status.eq_ignore_ascii_case("failed"))
        || details.get("answered").and_then(Value::as_bool) == Some(false)
}

fn cloud_mcp_apply_remote_agent_prompt_lever(
    app: &AppHandle,
    state: &CloudMcpState,
    event: &Value,
) -> bool {
    let command_kind = cloud_mcp_remote_command_kind(event);
    if !cloud_mcp_remote_command_is_agent_prompt_answer(&command_kind)
        || todo_dispatch_webview_dispatcher_active()
    {
        return false;
    }
    let app = app.clone();
    let state = state.clone();
    let event = event.clone();
    tauri::async_runtime::spawn(async move {
        match crate::terminal_answer_agent_prompt_remote_command(app, event.clone()).await {
            Ok(details) if cloud_mcp_agent_prompt_answer_details_failed(&details) => {
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state,
                    &event,
                    "failed",
                    "Agent prompt answer was rejected or did not dismiss the prompt.",
                    Some(&details),
                )
                .await;
            }
            Ok(details) => {
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state,
                    &event,
                    "completed",
                    "Agent prompt answer sent to the terminal.",
                    Some(&details),
                )
                .await;
            }
            Err(error) => {
                let details = json!({
                    "error": clean_terminal_telemetry_text(&error),
                });
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state,
                    &event,
                    "failed",
                    "Agent prompt answer could not be sent to the terminal.",
                    Some(&details),
                )
                .await;
            }
        }
    });
    true
}

#[cfg(test)]
mod cloud_mcp_agent_prompt_answer_tests {
    use super::*;

    #[test]
    fn failed_prompt_answer_details_are_not_remote_completion() {
        assert!(cloud_mcp_agent_prompt_answer_details_failed(&json!({
            "status": "failed",
            "answered": true,
        })));
        assert!(cloud_mcp_agent_prompt_answer_details_failed(&json!({
            "status": "applied",
            "answered": false,
        })));
        assert!(!cloud_mcp_agent_prompt_answer_details_failed(&json!({
            "status": "applied",
            "answered": true,
        })));
    }
}

/// Architecture file changes are local drafts. The webview listens to the store
/// event for live preview/dirty state, and explicit Save owns Cloud fanout.
pub(crate) fn cloud_mcp_start_architecture_event_sync(app: AppHandle, state: CloudMcpState) {
    let _ = (app, state);
}

const CLOUD_MCP_AGENT_INVENTORY_EVENT: &str = "agent-inventory-changed";
const CLOUD_MCP_AGENT_INVENTORY_INITIAL_DELAY_SECS: u64 = 90;
const CLOUD_MCP_AGENT_INVENTORY_FALLBACK_INTERVAL_SECS: u64 = 6 * 60 * 60;
const CLOUD_MCP_AGENT_INVENTORY_WATCH_DEBOUNCE_MS: u64 = 10_000;

static CLOUD_MCP_AGENT_INVENTORY_SIGNATURE: OnceLock<StdMutex<String>> = OnceLock::new();
static CLOUD_MCP_AGENT_INVENTORY_WATCHER: OnceLock<StdMutex<Option<notify::RecommendedWatcher>>> =
    OnceLock::new();
static CLOUD_MCP_AGENT_MODEL_CATALOGS: OnceLock<StdMutex<HashMap<String, AgentModelCatalog>>> =
    OnceLock::new();

fn cloud_mcp_agent_model_catalog_cache() -> &'static StdMutex<HashMap<String, AgentModelCatalog>> {
    CLOUD_MCP_AGENT_MODEL_CATALOGS.get_or_init(|| StdMutex::new(HashMap::new()))
}

fn cloud_mcp_store_agent_model_catalog(catalog: AgentModelCatalog) {
    if let Ok(mut cache) = cloud_mcp_agent_model_catalog_cache().lock() {
        cache.insert(catalog.agent_kind.clone(), catalog);
    }
}

fn cloud_mcp_latest_agent_model_catalog(agent_kind: &str) -> Option<AgentModelCatalog> {
    cloud_mcp_agent_model_catalog_cache()
        .lock()
        .ok()
        .and_then(|cache| cache.get(agent_kind).cloned())
}

fn cloud_mcp_latest_agent_model_catalog_value(agent_kind: &str) -> Option<Value> {
    cloud_mcp_latest_agent_model_catalog(agent_kind)
        .and_then(|catalog| serde_json::to_value(catalog).ok())
}

fn cloud_mcp_agent_model_catalog_contains_model(agent_kind: &str, model_id: &str) -> bool {
    let model_id = model_id.trim();
    if model_id.is_empty() {
        return false;
    }
    cloud_mcp_latest_agent_model_catalog(agent_kind)
        .map(|catalog| {
            catalog
                .models
                .iter()
                .any(|model| model.id.eq_ignore_ascii_case(model_id))
        })
        .unwrap_or_else(|| {
            agent_model_baseline_catalog_entries(agent_kind)
                .iter()
                .any(|model| model.id.eq_ignore_ascii_case(model_id))
        })
}

fn cloud_mcp_agent_model_catalog_entry_for_model(
    agent_kind: &str,
    model_id: &str,
) -> Option<AgentModelCatalogEntry> {
    let model_id = model_id.trim();
    if model_id.is_empty() {
        return None;
    }
    cloud_mcp_latest_agent_model_catalog(agent_kind)
        .and_then(|catalog| {
            catalog
                .models
                .into_iter()
                .find(|model| model.id.eq_ignore_ascii_case(model_id))
        })
        .or_else(|| {
            agent_model_baseline_catalog_entries(agent_kind)
                .into_iter()
                .find(|model| model.id.eq_ignore_ascii_case(model_id))
        })
}

fn cloud_mcp_agent_model_catalog_models_for_capabilities(
    agent_kind: &str,
) -> Vec<AgentModelCatalogEntry> {
    cloud_mcp_latest_agent_model_catalog(agent_kind)
        .map(|catalog| catalog.models)
        .filter(|models| !models.is_empty())
        .unwrap_or_else(|| agent_model_baseline_catalog_entries(agent_kind))
}

fn cloud_mcp_agent_status_payload_has_model_catalogs(agent_statuses: &Value) -> bool {
    agent_statuses
        .as_array()
        .map(|items| items.iter().any(|item| item.get("model_catalog").is_some()))
        .unwrap_or(false)
}

fn cloud_mcp_enrich_agent_status_payload_with_cached_catalogs(agent_statuses: &mut Value) {
    let Some(items) = agent_statuses.as_array_mut() else {
        return;
    };
    for item in items {
        let Some(raw_id) = cloud_mcp_payload_text(item, &["id", "agent_id"]) else {
            continue;
        };
        let Some(agent_kind) = cloud_mcp_canonical_coding_agent_id(&raw_id) else {
            continue;
        };
        if !matches!(agent_kind.as_str(), "codex" | "claude") {
            continue;
        }
        let Some(catalog) = cloud_mcp_latest_agent_model_catalog_value(&agent_kind) else {
            continue;
        };
        if let Some(object) = item.as_object_mut() {
            object.insert("model_catalog".to_string(), catalog);
        }
    }
}

fn cloud_mcp_json_array_strings(value: Option<&Value>) -> Vec<String> {
    value
        .and_then(Value::as_array)
        .map(|items| {
            items
                .iter()
                .filter_map(Value::as_str)
                .map(|item| clean_agent_model_catalog_text(item, 80))
                .filter(|item| !item.is_empty())
                .collect::<Vec<_>>()
        })
        .unwrap_or_default()
}

fn cloud_mcp_codex_model_list_array(response: &Value) -> Option<&Vec<Value>> {
    response
        .get("result")
        .and_then(|result| result.get("data"))
        .and_then(Value::as_array)
        .or_else(|| {
            response
                .get("result")
                .and_then(|result| result.get("models"))
                .and_then(Value::as_array)
        })
        .or_else(|| response.get("data").and_then(Value::as_array))
        .or_else(|| response.get("models").and_then(Value::as_array))
        .or_else(|| response.as_array())
}

fn cloud_mcp_codex_catalog_entries_from_model_list_response(
    response: &Value,
) -> Vec<AgentModelCatalogEntry> {
    let Some(models) = cloud_mcp_codex_model_list_array(response) else {
        return Vec::new();
    };
    let mut entries = Vec::new();
    let mut seen = HashSet::new();
    for model in models.iter().take(512) {
        let id = cloud_mcp_payload_text(model, &["id"])
            .or_else(|| cloud_mcp_payload_text(model, &["model"]))
            .unwrap_or_default();
        let id = clean_agent_model_catalog_text(&id, 180);
        if id.is_empty() || !seen.insert(id.to_ascii_lowercase()) {
            continue;
        }
        let display_name = cloud_mcp_payload_text(model, &["displayName"])
            .or_else(|| cloud_mcp_payload_text(model, &["display_name"]))
            .unwrap_or_else(|| agent_model_catalog_display_from_id(&id));
        let description = cloud_mcp_payload_text(model, &["description"]);
        let reasoning_efforts = cloud_mcp_json_array_strings(
            model
                .get("supportedReasoningEfforts")
                .or_else(|| model.get("supported_reasoning_efforts")),
        );
        let default_reasoning_effort = cloud_mcp_payload_text(model, &["defaultReasoningEffort"])
            .or_else(|| cloud_mcp_payload_text(model, &["default_reasoning_effort"]));
        let input_modalities = cloud_mcp_json_array_strings(
            model
                .get("inputModalities")
                .or_else(|| model.get("input_modalities")),
        );
        let supports_images = input_modalities
            .iter()
            .any(|modality| modality.eq_ignore_ascii_case("image"));
        let speed_modes = cloud_mcp_json_array_strings(
            model
                .get("serviceTiers")
                .or_else(|| model.get("service_tiers")),
        );
        entries.push(agent_model_catalog_entry(
            "codex",
            &id,
            &display_name,
            description.as_deref(),
            "harness_api",
            cloud_mcp_payload_bool(model, &["isDefault"], false)
                || cloud_mcp_payload_bool(model, &["is_default"], false),
            supports_images,
            !reasoning_efforts.is_empty() || default_reasoning_effort.is_some(),
            reasoning_efforts,
            default_reasoning_effort.as_deref(),
            if speed_modes.is_empty() {
                None
            } else {
                Some(speed_modes.iter().map(String::as_str).collect())
            },
            None,
            cloud_mcp_payload_bool(model, &["hidden"], false),
            cloud_mcp_payload_bool(model, &["deprecated"], false),
        ));
    }
    entries
}

fn cloud_mcp_jsonrpc_response_matches_id(value: &Value, id: i64) -> bool {
    value
        .get("id")
        .and_then(Value::as_i64)
        .is_some_and(|candidate| candidate == id)
        || value
            .get("id")
            .and_then(Value::as_str)
            .and_then(|candidate| candidate.parse::<i64>().ok())
            .is_some_and(|candidate| candidate == id)
}

fn cloud_mcp_try_parse_codex_jsonrpc_response(buffer: &str, id: i64) -> Option<Value> {
    for line in buffer.lines().rev() {
        let line = line.trim();
        if line.is_empty() {
            continue;
        }
        if let Ok(value) = serde_json::from_str::<Value>(line) {
            if cloud_mcp_jsonrpc_response_matches_id(&value, id) {
                return Some(value);
            }
        }
    }
    let trimmed = buffer.trim();
    if trimmed.is_empty() {
        return None;
    }
    serde_json::from_str::<Value>(trimmed)
        .ok()
        .filter(|value| cloud_mcp_jsonrpc_response_matches_id(value, id))
}

fn cloud_mcp_spawn_codex_app_server_stdout_reader<R: Read + Send + 'static>(
    mut pipe: R,
    sender: std::sync::mpsc::Sender<String>,
) -> thread::JoinHandle<()> {
    thread::spawn(move || {
        let mut buffer = [0_u8; 4096];
        loop {
            match pipe.read(&mut buffer) {
                Ok(0) => break,
                Ok(read) => {
                    let chunk = String::from_utf8_lossy(&buffer[..read]).to_string();
                    if sender.send(chunk).is_err() {
                        break;
                    }
                }
                Err(_) => break,
            }
        }
    })
}

fn cloud_mcp_run_codex_app_server_candidate(candidate: &str) -> Result<Value, String> {
    let mut command = Command::new(candidate);
    command.env("PATH", desktop_command_path());
    command.arg("app-server");
    command.stdin(Stdio::piped());
    command.stdout(Stdio::piped());
    command.stderr(Stdio::piped());

    #[cfg(windows)]
    {
        use std::os::windows::process::CommandExt;

        const CREATE_NO_WINDOW: u32 = 0x0800_0000;
        command.creation_flags(CREATE_NO_WINDOW);
    }

    let mut child = command
        .spawn()
        .map_err(|error| format!("Unable to start {candidate} app-server: {error}"))?;
    let mut stdin = child
        .stdin
        .take()
        .ok_or_else(|| format!("{candidate} app-server stdin was unavailable."))?;
    let stdout = child
        .stdout
        .take()
        .ok_or_else(|| format!("{candidate} app-server stdout was unavailable."))?;
    let stderr_reader = child
        .stderr
        .take()
        .map(|stderr| spawn_opencode_models_pipe_reader("stderr", stderr));
    let (stdout_sender, stdout_receiver) = std::sync::mpsc::channel();
    let stdout_reader = cloud_mcp_spawn_codex_app_server_stdout_reader(stdout, stdout_sender);
    let initialize = json!({
        "jsonrpc": "2.0",
        "id": 1,
        "method": "initialize",
        "params": {
            "clientInfo": {
                "name": "diff-forge",
                "version": env!("CARGO_PKG_VERSION")
            },
            "capabilities": {}
        },
    });
    let initialized = json!({
        "jsonrpc": "2.0",
        "method": "initialized",
        "params": {},
    });
    let request_id = 2_i64;
    let request = json!({
        "jsonrpc": "2.0",
        "id": request_id,
        "method": "model/list",
        "params": {},
    });
    stdin
        .write_all(format!("{initialize}\n{initialized}\n{request}\n").as_bytes())
        .map_err(|error| {
            format!("Unable to initialize Codex app-server model discovery: {error}")
        })?;
    let _ = stdin.flush();
    drop(stdin);

    let started_at = Instant::now();
    let mut stdout_buffer = String::new();
    loop {
        if app_shutdown_requested() {
            let _ = child.kill();
            let _ = child.wait();
            let _ = stdout_reader.join();
            if let Some(stderr_reader) = stderr_reader {
                let _ = stderr_reader.join();
            }
            return Err(app_shutdown_blocked_message(candidate));
        }
        match stdout_receiver.recv_timeout(Duration::from_millis(80)) {
            Ok(chunk) => {
                stdout_buffer.push_str(&chunk);
                if let Some(response) =
                    cloud_mcp_try_parse_codex_jsonrpc_response(&stdout_buffer, request_id)
                {
                    let _ = child.kill();
                    let _ = child.wait();
                    let _ = stdout_reader.join();
                    if let Some(stderr_reader) = stderr_reader {
                        let _ = stderr_reader.join();
                    }
                    return Ok(response);
                }
            }
            Err(std::sync::mpsc::RecvTimeoutError::Timeout) => {}
            Err(std::sync::mpsc::RecvTimeoutError::Disconnected) => {
                break;
            }
        }
        if started_at.elapsed() >= Duration::from_secs(10) {
            let _ = child.kill();
            let _ = child.wait();
            let _ = stdout_reader.join();
            let stderr = stderr_reader
                .and_then(|reader| reader.join().ok())
                .and_then(Result::ok)
                .unwrap_or_default();
            return Err(if stderr.trim().is_empty() {
                format!("{candidate} app-server model/list timed out.")
            } else {
                format!(
                    "{candidate} app-server model/list timed out: {}",
                    first_output_line(&stderr)
                )
            });
        }
        if matches!(child.try_wait(), Ok(Some(_))) {
            break;
        }
    }

    let _ = child.kill();
    let _ = child.wait();
    let _ = stdout_reader.join();
    let stderr = stderr_reader
        .and_then(|reader| reader.join().ok())
        .and_then(Result::ok)
        .unwrap_or_default();
    Err(if stderr.trim().is_empty() {
        format!("{candidate} app-server ended without a model/list response.")
    } else {
        format!(
            "{candidate} app-server ended without a model/list response: {}",
            first_output_line(&stderr)
        )
    })
}

fn cloud_mcp_fetch_codex_model_list_response() -> Result<Value, String> {
    let definition = agent_definition(AgentProvider::Codex);
    let mut last_error = format!(
        "{} is not installed or not available on PATH.",
        definition.label
    );
    for candidate in agent_command_candidates(definition) {
        match cloud_mcp_run_codex_app_server_candidate(&candidate) {
            Ok(response) => return Ok(response),
            Err(error) => {
                last_error = error;
            }
        }
    }
    Err(last_error)
}

fn cloud_mcp_read_claude_state_file() -> Result<Option<Value>, String> {
    let state_path = if let Some(config_dir) = env::var_os("CLAUDE_CONFIG_DIR").map(PathBuf::from) {
        Some(config_dir.join(".claude.json"))
    } else {
        cloud_mcp_home_dir().map(|home| home.join(".claude.json"))
    };
    let Some(state_path) = state_path else {
        return Ok(None);
    };
    if !state_path.is_file() {
        return Ok(None);
    }
    let body = fs::read_to_string(&state_path)
        .map_err(|error| format!("Unable to read {}: {error}", state_path.display()))?;
    let value = serde_json::from_str::<Value>(&body)
        .map_err(|error| format!("Unable to parse {}: {error}", state_path.display()))?;
    Ok(Some(value))
}

fn cloud_mcp_claude_cache_entry_from_option(
    option: &Value,
    object_key: Option<&str>,
) -> Option<AgentModelCatalogEntry> {
    let id = cloud_mcp_payload_text(option, &["value", "id", "model", "model_id"])
        .or_else(|| object_key.map(str::to_string))
        .map(|value| clean_agent_model_catalog_text(&value, 180))
        .filter(|value| !value.is_empty())?;
    let label = cloud_mcp_payload_text(option, &["label", "display_name", "displayName", "name"])
        .unwrap_or_else(|| agent_model_catalog_display_from_id(&id));
    let description = cloud_mcp_payload_text(option, &["description", "detail"]);
    Some(agent_model_catalog_entry(
        "claude",
        &id,
        &label,
        description.as_deref(),
        "harness_cache",
        false,
        true,
        true,
        AGENT_MODEL_CATALOG_CLAUDE_REASONING_EFFORTS
            .iter()
            .map(|effort| effort.to_string())
            .collect(),
        Some("default"),
        None,
        None,
        false,
        cloud_mcp_payload_bool(option, &["deprecated"], false),
    ))
}

fn cloud_mcp_claude_cache_entries_from_value(value: &Value) -> Vec<AgentModelCatalogEntry> {
    let Some(cache) = value.get("additionalModelOptionsCache") else {
        return Vec::new();
    };
    let mut entries = Vec::new();
    match cache {
        Value::Array(items) => {
            for item in items {
                if let Some(entry) = cloud_mcp_claude_cache_entry_from_option(item, None) {
                    entries.push(entry);
                }
            }
        }
        Value::Object(map) => {
            for (key, item) in map {
                match item {
                    Value::Array(items) => {
                        for nested in items {
                            if let Some(entry) =
                                cloud_mcp_claude_cache_entry_from_option(nested, None)
                            {
                                entries.push(entry);
                            }
                        }
                    }
                    Value::Object(_) => {
                        if let Some(entry) =
                            cloud_mcp_claude_cache_entry_from_option(item, Some(key))
                        {
                            entries.push(entry);
                        }
                    }
                    Value::String(label) => {
                        let entry = agent_model_catalog_entry(
                            "claude",
                            key,
                            label,
                            None,
                            "harness_cache",
                            false,
                            true,
                            true,
                            AGENT_MODEL_CATALOG_CLAUDE_REASONING_EFFORTS
                                .iter()
                                .map(|effort| effort.to_string())
                                .collect(),
                            Some("default"),
                            None,
                            None,
                            false,
                            false,
                        );
                        entries.push(entry);
                    }
                    _ => {}
                }
            }
        }
        _ => {}
    }
    entries
}

async fn cloud_mcp_discover_codex_model_catalog(
    harness_version: &str,
    installed: bool,
) -> AgentModelCatalog {
    if !installed {
        return agent_model_catalog_fallback("codex", harness_version);
    }
    let harness_version = harness_version.to_string();
    let result = tauri::async_runtime::spawn_blocking(cloud_mcp_fetch_codex_model_list_response)
        .await
        .unwrap_or_else(|error| Err(format!("Codex model/list worker failed: {error}")));
    match result {
        Ok(response) => {
            let live_models = cloud_mcp_codex_catalog_entries_from_model_list_response(&response);
            if live_models.is_empty() {
                agent_model_catalog_fallback("codex", &harness_version)
            } else {
                let models = agent_model_catalog_merge_live_with_baseline("codex", live_models);
                agent_model_catalog("codex", &harness_version, "harness_api", true, models)
            }
        }
        Err(error) => {
            log_terminal_status_event(
                "backend.cloud_mcp.agent_model_catalog.codex_probe_failed",
                json!({ "error": clean_terminal_telemetry_text(&error) }),
            );
            agent_model_catalog_fallback("codex", &harness_version)
        }
    }
}

async fn cloud_mcp_discover_claude_model_catalog(harness_version: &str) -> AgentModelCatalog {
    let harness_version = harness_version.to_string();
    let result = tauri::async_runtime::spawn_blocking(cloud_mcp_read_claude_state_file)
        .await
        .unwrap_or_else(|error| Err(format!("Claude cache worker failed: {error}")));
    match result {
        Ok(Some(value)) => {
            let live_models = cloud_mcp_claude_cache_entries_from_value(&value);
            let source = if live_models.is_empty() {
                "device_baseline"
            } else {
                "harness_cache"
            };
            let models = agent_model_catalog_merge_live_with_baseline("claude", live_models);
            agent_model_catalog("claude", &harness_version, source, true, models)
        }
        Ok(None) => {
            let models = agent_model_catalog_merge_live_with_baseline("claude", Vec::new());
            agent_model_catalog("claude", &harness_version, "device_baseline", true, models)
        }
        Err(error) => {
            log_terminal_status_event(
                "backend.cloud_mcp.agent_model_catalog.claude_cache_failed",
                json!({ "error": clean_terminal_telemetry_text(&error) }),
            );
            agent_model_catalog_fallback("claude", &harness_version)
        }
    }
}

async fn cloud_mcp_refresh_agent_model_catalogs_from_status_payload(
    agent_statuses: &Value,
    reason: &str,
) {
    let Some(items) = agent_statuses.as_array() else {
        return;
    };
    for item in items {
        let Some(raw_id) = cloud_mcp_payload_text(item, &["id", "agent_id"]) else {
            continue;
        };
        let Some(agent_kind) = cloud_mcp_canonical_coding_agent_id(&raw_id) else {
            continue;
        };
        let harness_version =
            cloud_mcp_payload_text(item, &["version"]).unwrap_or_else(|| "unknown".to_string());
        let installed = cloud_mcp_payload_bool(item, &["installed"], false);
        match agent_kind.as_str() {
            "codex" => {
                let catalog =
                    cloud_mcp_discover_codex_model_catalog(&harness_version, installed).await;
                cloud_mcp_store_agent_model_catalog(catalog);
            }
            "claude" => {
                let catalog = cloud_mcp_discover_claude_model_catalog(&harness_version).await;
                cloud_mcp_store_agent_model_catalog(catalog);
            }
            "opencode" => {
                if opencode_note_harness_version(&harness_version) {
                    log_terminal_status_event(
                        "backend.cloud_mcp.agent_model_catalog.opencode_version_invalidated",
                        json!({
                            "harness_version": harness_version,
                            "reason": reason,
                        }),
                    );
                }
            }
            _ => {}
        }
    }
}

#[cfg(test)]
mod cloud_mcp_agent_model_catalog_tests {
    use super::*;

    #[test]
    fn codex_catalog_maps_model_list_with_novel_effort() {
        let response = json!({
            "jsonrpc": "2.0",
            "id": 1,
            "result": {
                "data": [{
                    "id": "gpt-5.6-sol",
                    "displayName": "GPT-5.6 Sol",
                    "description": "Novel Codex model",
                    "hidden": false,
                    "isDefault": true,
                    "defaultReasoningEffort": "ultra",
                    "supportedReasoningEfforts": ["low", "medium", "ultra"],
                    "inputModalities": ["text", "image"],
                    "serviceTiers": ["standard", "fast"]
                }]
            }
        });

        let entries = cloud_mcp_codex_catalog_entries_from_model_list_response(&response);
        assert_eq!(entries.len(), 1);
        assert_eq!(entries[0].id, "gpt-5.6-sol");
        assert_eq!(entries[0].display_name, "GPT-5.6 Sol");
        assert!(entries[0].supports_images);
        assert!(entries[0].supports_effort);
        assert_eq!(
            entries[0].reasoning_efforts,
            vec!["low".to_string(), "medium".to_string(), "ultra".to_string()]
        );
        assert_eq!(
            entries[0].default_reasoning_effort.as_deref(),
            Some("ultra")
        );
    }

    #[test]
    fn opencode_agent_models_result_maps_provider_scoped_catalog() {
        let request = json!({
            "id": "models-request-1",
            "kind": "list_agent_models",
            "target_device_id": "desktop-primary",
            "target_terminal_id": "term-1",
            "agent_kind": "opencode",
            "workspace_id": "workspace-1"
        });
        let models = opencode_model_catalog_entries_from_ids(
            &[
                "openai/gpt-5.5".to_string(),
                "anthropic/claude-sonnet-4-5".to_string(),
            ],
            "cli",
        );
        let payload = cloud_mcp_agent_models_result_payload(
            &request,
            "opencode",
            models,
            true,
            Some("opencode 1.2.3".to_string()),
            None,
        );

        assert_eq!(payload["kind"], json!("agent_models_result"));
        assert_eq!(payload["request_id"], json!("models-request-1"));
        assert_eq!(payload["agent_kind"], json!("opencode"));
        assert_eq!(payload["complete"], json!(true));
        assert_eq!(payload["harness_version"], json!("opencode 1.2.3"));
        assert_eq!(payload["models"][0]["id"], json!("openai/gpt-5.5"));
        assert_eq!(payload["models"][0]["provider"], json!("openai"));
        assert_eq!(payload["models"][0]["source"], json!("harness_api"));
    }

    #[test]
    fn list_agent_models_detector_accepts_cloud_event_wrapped_event_kind() {
        let message = json!({
            "kind": "cloud_event",
            "event": {
                "kind": "list_agent_models",
                "request_id": "models-request-2",
                "target_terminal_id": "term-2",
                "agent_kind": "opencode",
                "workspace_id": "workspace-2"
            }
        });

        assert!(cloud_mcp_is_list_agent_models_request(
            &message,
            "cloud_event",
            ""
        ));
        assert_eq!(
            cloud_mcp_list_agent_models_request_id(&message),
            "models-request-2"
        );
        assert_eq!(
            cloud_mcp_remote_command_field_text(&message, &["agent_kind"]).as_deref(),
            Some("opencode")
        );
        assert_eq!(
            cloud_mcp_remote_command_field_text(&message, &["target_terminal_id"]).as_deref(),
            Some("term-2")
        );
    }

    #[test]
    fn list_agent_models_detector_accepts_cloud_event_wrapped_command_kind() {
        let message = json!({
            "kind": "cloud_event",
            "event": {
                "event_kind": "remote_command_requested",
                "command_kind": "list_agent_models",
                "request_id": "models-request-3",
                "agent_kind": "opencode"
            }
        });

        assert!(cloud_mcp_is_list_agent_models_request(
            &message,
            "cloud_event",
            ""
        ));
    }

    #[test]
    fn list_agent_models_detector_ignores_unrelated_nested_lifecycle_kind() {
        let message = json!({
            "kind": "workspace_lifecycle",
            "payload": {
                "kind": "list_agent_models",
                "workspace_id": "workspace-1"
            }
        });

        assert!(!cloud_mcp_is_list_agent_models_request(
            &message,
            "workspace_lifecycle",
            ""
        ));
    }

    #[test]
    fn list_agent_models_detector_ignores_unrelated_nested_settings_kind() {
        let message = json!({
            "kind": "workspace_settings_update",
            "request": {
                "kind": "list_agent_models",
                "workspace_id": "workspace-1"
            }
        });

        assert!(!cloud_mcp_is_list_agent_models_request(
            &message,
            "workspace_settings_update",
            ""
        ));
    }

    #[test]
    fn list_agent_models_detector_ignores_unrelated_nested_terminal_kind() {
        let message = json!({
            "kind": "terminal_open",
            "payload": {
                "kind": "list_agent_models",
                "target_terminal_id": "term-1"
            },
            "command_kind": "terminal_open"
        });

        assert!(!cloud_mcp_is_list_agent_models_request(
            &message,
            "terminal_open",
            ""
        ));
    }

    #[test]
    fn agent_models_result_envelope_uses_first_class_app_ws_kind() {
        let request = json!({
            "kind": "cloud_event",
            "event": {
                "kind": "list_agent_models",
                "request_id": "models-request-4",
                "agent_kind": "opencode",
                "workspace_id": "workspace-4"
            }
        });
        let payload = cloud_mcp_agent_models_result_payload(
            &request,
            "opencode",
            Vec::new(),
            true,
            Some("opencode 1.2.3".to_string()),
            None,
        );
        let envelope =
            cloud_mcp_agent_models_result_envelope(&request, &payload, json!({"token": "test"}));

        assert_eq!(envelope["kind"], json!("agent_models_result"));
        assert_eq!(envelope["event_kind"], json!("agent_models_result"));
        assert_eq!(envelope["request_id"], json!("models-request-4"));
        assert_eq!(envelope["payload"]["kind"], json!("agent_models_result"));
        assert_eq!(envelope["payload"]["request_id"], json!("models-request-4"));
        assert_eq!(
            envelope["request"]["event_kind"],
            json!("agent_models_result")
        );
        assert_eq!(
            envelope["request"]["payload"]["kind"],
            json!("agent_models_result")
        );
    }
}

fn cloud_mcp_agent_inventory_watcher_slot() -> &'static StdMutex<Option<notify::RecommendedWatcher>>
{
    CLOUD_MCP_AGENT_INVENTORY_WATCHER.get_or_init(|| StdMutex::new(None))
}

fn cloud_mcp_agent_inventory_add_watch_root(
    roots: &mut Vec<PathBuf>,
    seen: &mut HashSet<PathBuf>,
    path: PathBuf,
) {
    if !path.is_dir() {
        return;
    }
    let path = fs::canonicalize(&path).unwrap_or(path);
    if seen.insert(path.clone()) {
        roots.push(path);
    }
}

fn cloud_mcp_agent_inventory_add_npm_roots(
    roots: &mut Vec<PathBuf>,
    seen: &mut HashSet<PathBuf>,
    prefix: &Path,
) {
    #[cfg(windows)]
    let node_modules = prefix.join("node_modules");
    #[cfg(not(windows))]
    let node_modules = prefix.join("lib").join("node_modules");

    cloud_mcp_agent_inventory_add_watch_root(roots, seen, node_modules.clone());
    for provider in [
        AgentProvider::Codex,
        AgentProvider::Claude,
        AgentProvider::OpenCode,
    ] {
        let package = agent_definition(provider).install_package;
        if let Some((scope, name)) = package.split_once('/') {
            let scope_root = node_modules.join(scope);
            cloud_mcp_agent_inventory_add_watch_root(roots, seen, scope_root.clone());
            cloud_mcp_agent_inventory_add_watch_root(roots, seen, scope_root.join(name));
        } else {
            cloud_mcp_agent_inventory_add_watch_root(roots, seen, node_modules.join(package));
        }
    }

    #[cfg(windows)]
    cloud_mcp_agent_inventory_add_watch_root(roots, seen, prefix.to_path_buf());
    #[cfg(not(windows))]
    cloud_mcp_agent_inventory_add_watch_root(roots, seen, prefix.join("bin"));
}

fn cloud_mcp_agent_inventory_binary_candidates(directory: &Path, binary: &str) -> Vec<PathBuf> {
    #[cfg(windows)]
    {
        let suffixes = [".cmd", ".exe", ".bat", ""];
        suffixes
            .iter()
            .map(|suffix| directory.join(format!("{binary}{suffix}")))
            .collect()
    }
    #[cfg(not(windows))]
    {
        vec![directory.join(binary)]
    }
}

fn cloud_mcp_agent_inventory_resolve_command_path(command: &str) -> Option<PathBuf> {
    let command = command.trim();
    if command.is_empty() {
        return None;
    }
    let path = PathBuf::from(command);
    if (path.is_absolute() || path.components().count() > 1) && path.is_file() {
        return Some(fs::canonicalize(&path).unwrap_or(path));
    }

    let path_value = env::var_os("PATH")?;
    for directory in env::split_paths(&path_value) {
        for candidate in cloud_mcp_agent_inventory_binary_candidates(&directory, command) {
            if candidate.is_file() {
                return Some(fs::canonicalize(&candidate).unwrap_or(candidate));
            }
        }
    }
    None
}

fn cloud_mcp_agent_inventory_watch_roots() -> Vec<PathBuf> {
    let mut roots = Vec::new();
    let mut seen = HashSet::new();

    if let Some(prefix) = npm_global_prefix() {
        cloud_mcp_agent_inventory_add_npm_roots(&mut roots, &mut seen, &prefix);
    } else {
        log_terminal_status_event(
            "backend.cloud_mcp.agent_inventory_watcher.npm_prefix_unavailable",
            json!({}),
        );
    }

    for provider in [
        AgentProvider::Codex,
        AgentProvider::Claude,
        AgentProvider::OpenCode,
    ] {
        let definition = agent_definition(provider);
        if let Some(path) = cloud_mcp_agent_inventory_resolve_command_path(definition.binary) {
            if let Some(parent) = path.parent() {
                cloud_mcp_agent_inventory_add_watch_root(
                    &mut roots,
                    &mut seen,
                    parent.to_path_buf(),
                );
            }
        }
    }

    roots
}

fn cloud_mcp_clear_agent_inventory_command_candidate_cache() {
    for provider in [
        AgentProvider::Codex,
        AgentProvider::Claude,
        AgentProvider::OpenCode,
    ] {
        clear_agent_command_candidate_cache(provider);
    }
}

fn cloud_mcp_agent_inventory_watch_changed(_changed_paths: &[PathBuf]) {
    cloud_mcp_clear_agent_inventory_command_candidate_cache();
}

fn cloud_mcp_start_agent_inventory_fs_watcher(notify: Arc<tokio::sync::Notify>) -> bool {
    use notify::Watcher as _;

    let slot = cloud_mcp_agent_inventory_watcher_slot();
    let Ok(mut guard) = slot.lock() else {
        return false;
    };
    if guard.is_some() {
        return true;
    }

    let roots = cloud_mcp_agent_inventory_watch_roots();
    if roots.is_empty() {
        log_terminal_status_event(
            "backend.cloud_mcp.agent_inventory_watcher.watch_roots_empty",
            json!({}),
        );
        return false;
    }

    let (sender, receiver) = std::sync::mpsc::channel::<notify::Result<notify::Event>>();
    let mut watcher = match notify::recommended_watcher(sender) {
        Ok(watcher) => watcher,
        Err(error) => {
            log_terminal_status_event(
                "backend.cloud_mcp.agent_inventory_watcher.watch_create_error",
                json!({ "error": clean_terminal_telemetry_text(&error.to_string()) }),
            );
            return false;
        }
    };

    let mut watched_roots = Vec::new();
    for root in roots {
        match watcher.watch(&root, notify::RecursiveMode::NonRecursive) {
            Ok(()) => watched_roots.push(root.display().to_string()),
            Err(error) => {
                log_terminal_status_event(
                    "backend.cloud_mcp.agent_inventory_watcher.watch_root_error",
                    json!({
                        "root": root.display().to_string(),
                        "error": clean_terminal_telemetry_text(&error.to_string()),
                    }),
                );
            }
        }
    }
    if watched_roots.is_empty() {
        return false;
    }

    cloud_mcp_spawn_fs_event_debounce_forwarder(
        "agent_inventory",
        receiver,
        notify,
        Duration::from_millis(CLOUD_MCP_AGENT_INVENTORY_WATCH_DEBOUNCE_MS),
        Some(cloud_mcp_agent_inventory_watch_changed),
    );
    *guard = Some(watcher);
    log_terminal_status_event(
        "backend.cloud_mcp.agent_inventory_watcher.watch_started",
        json!({ "roots": watched_roots }),
    );
    true
}

/// Probes the coding-agent CLI inventory (installed, version, npm latest,
/// auth, update availability) natively, and on change emits the webview event
/// plus the durable cloud snapshot. Signature-deduped so quiet scans cost a
/// few subprocess/npm checks and nothing else.
pub(crate) async fn cloud_mcp_agent_inventory_probe_and_sync(
    app: &AppHandle,
    state: &CloudMcpState,
    reason: &str,
    force: bool,
) {
    let Ok(statuses) = agent_statuses().await else {
        return;
    };
    let mut payload = serde_json::to_value(&statuses).unwrap_or_else(|_| json!([]));
    cloud_mcp_refresh_agent_model_catalogs_from_status_payload(&payload, reason).await;
    cloud_mcp_enrich_agent_status_payload_with_cached_catalogs(&mut payload);
    let signature = format!("{:x}", Sha256::digest(payload.to_string().as_bytes()));
    {
        let lock = CLOUD_MCP_AGENT_INVENTORY_SIGNATURE.get_or_init(|| StdMutex::new(String::new()));
        let Ok(mut last) = lock.lock() else {
            return;
        };
        if !force && *last == signature {
            return;
        }
        *last = signature;
    }
    let _ = app.emit(
        CLOUD_MCP_AGENT_INVENTORY_EVENT,
        json!({
            "statuses": payload.clone(),
            "reason": reason,
            "updated_at_ms": cloud_mcp_now_ms(),
        }),
    );
    let _ = cloud_mcp_sync_agent_installations_internal(
        state,
        String::new(),
        None,
        None,
        payload,
        Some(reason.to_string()),
    )
    .await;
}

/// Headless agent inventory watcher: keeps the cloud (and an open webview)
/// current when agents are installed/updated outside the app — for example
/// `npm i -g @openai/codex` in a terminal — including in background mode.
pub(crate) fn cloud_mcp_start_agent_inventory_watcher(app: AppHandle, state: CloudMcpState) {
    tauri::async_runtime::spawn(async move {
        let inventory_wake = Arc::new(tokio::sync::Notify::new());
        let inventory_wake_for_setup = inventory_wake.clone();
        let _ = tauri::async_runtime::spawn_blocking(move || {
            cloud_mcp_start_agent_inventory_fs_watcher(inventory_wake_for_setup)
        });

        if !cloud_mcp_wait_for_background_scheduler_delay(Duration::from_secs(
            CLOUD_MCP_AGENT_INVENTORY_INITIAL_DELAY_SECS,
        ))
        .await
        {
            return;
        }
        if app_shutdown_requested() {
            return;
        }
        cloud_mcp_agent_inventory_probe_and_sync(&app, &state, "agent_inventory_watcher", false)
            .await;

        loop {
            if app_shutdown_requested() {
                break;
            }
            if !cloud_mcp_wait_for_background_scheduler_wake(
                &inventory_wake,
                Duration::from_secs(CLOUD_MCP_AGENT_INVENTORY_FALLBACK_INTERVAL_SECS),
            )
            .await
            {
                break;
            }
            if app_shutdown_requested() {
                break;
            }
            cloud_mcp_clear_agent_inventory_command_candidate_cache();
            cloud_mcp_agent_inventory_probe_and_sync(
                &app,
                &state,
                "agent_inventory_watcher",
                false,
            )
            .await;
        }
    });
}

/// Headless actuation for remote agent package levers (install/update/
/// uninstall of codex, claude code, opencode). Installs can use the foreground
/// UI, while updates remain Rust-owned so every delivery passes through the
/// active-terminal safety gate. Replies with running → completed/failed and
/// re-probes the inventory afterwards so cloud and any later webview converge.
fn cloud_mcp_provider_matches_terminal_metadata(
    provider: &str,
    metadata: &TerminalInstanceMetadata,
) -> bool {
    let provider = terminal_normalize_agent_kind(Some(provider));
    let terminal_provider = terminal_normalize_agent_kind(Some(&metadata.agent_kind))
        .or_else(|| terminal_normalize_agent_kind(Some(&metadata.agent_id)));
    provider.is_some() && provider == terminal_provider
}

async fn cloud_mcp_active_provider_terminal_labels(app: &AppHandle, provider: &str) -> Vec<String> {
    let terminal_state = app.state::<TerminalState>();
    let terminals = terminal_state.terminals.read().await;
    terminals
        .values()
        .filter(|instance| {
            cloud_mcp_provider_matches_terminal_metadata(provider, &instance.metadata)
        })
        .map(|instance| {
            [
                instance.metadata.terminal_nickname.as_str(),
                instance.metadata.terminal_name.as_str(),
                instance.metadata.pane_id.as_str(),
            ]
            .into_iter()
            .find(|value| !value.trim().is_empty())
            .unwrap_or("agent terminal")
            .to_string()
        })
        .collect()
}

#[cfg(test)]
#[test]
fn remote_agent_update_idle_gate_matches_provider_aliases_only() {
    let mut metadata = TerminalInstanceMetadata {
        agent_id: "claude-code".to_string(),
        agent_kind: "Claude Code".to_string(),
        ..TerminalInstanceMetadata::default()
    };
    assert!(cloud_mcp_provider_matches_terminal_metadata(
        "claude", &metadata
    ));
    assert!(!cloud_mcp_provider_matches_terminal_metadata(
        "codex", &metadata
    ));
    metadata.agent_id = "open-code".to_string();
    metadata.agent_kind = "opencode".to_string();
    assert!(cloud_mcp_provider_matches_terminal_metadata(
        "OpenCode", &metadata
    ));
}

fn cloud_mcp_apply_remote_agent_lever(
    app: &AppHandle,
    state: &CloudMcpState,
    event: &Value,
) -> bool {
    let command_kind = cloud_mcp_payload_text(event, &["command_kind", "action", "command"])
        .unwrap_or_default()
        .to_ascii_lowercase()
        .replace(['.', ' ', '-'], "_");
    let action = match command_kind.as_str() {
        "agent_install" | "install_agent" | "cli_install" => "install",
        "agent_update" | "update_agent" | "cli_update" => "update",
        "agent_uninstall" | "uninstall_agent" | "cli_uninstall" => "uninstall",
        _ => return false,
    };
    // Installs remain lease-gated to the richer webview flow. Updates are
    // always Rust-owned so an open webview cannot bypass the active-terminal
    // safety gate below; uninstall has no webview path either.
    if action == "install" && todo_dispatch_webview_dispatcher_active() {
        return false;
    }
    let provider = cloud_mcp_payload_text(
        event,
        &["provider", "agent_provider", "agent_id", "target_agent_id"],
    )
    .unwrap_or_default();
    let app = app.clone();
    let state = state.clone();
    let event = event.clone();
    let action = action.to_string();
    tauri::async_runtime::spawn(async move {
        if provider.is_empty() {
            let _ = cloud_mcp_send_remote_command_status_event(
                &state,
                &event,
                "failed",
                "Remote agent package command did not include a provider.",
                None,
            )
            .await;
            return;
        }
        let update_lifecycle_guard = if action == "update" {
            let lifecycle_lock = app.state::<TerminalState>().lifecycle_lock.clone();
            let mut deferred_status_sent = false;
            loop {
                if app_shutdown_requested() {
                    let _ = cloud_mcp_send_remote_command_status_event(
                        &state,
                        &event,
                        "cancelled",
                        "Deferred agent update was cancelled because Diff Forge is shutting down.",
                        None,
                    )
                    .await;
                    return;
                }

                let mut active_terminals =
                    cloud_mcp_active_provider_terminal_labels(&app, &provider).await;
                if active_terminals.is_empty() {
                    // Terminal opens/relaunches take this same lifecycle lock. Hold
                    // it from the final idle recheck through npm so a new provider
                    // session cannot race the binary replacement.
                    let guard = lifecycle_lock.clone().lock_owned().await;
                    if app_shutdown_requested() {
                        drop(guard);
                        let _ = cloud_mcp_send_remote_command_status_event(
                            &state,
                            &event,
                            "cancelled",
                            "Deferred agent update was cancelled because Diff Forge is shutting down.",
                            None,
                        )
                        .await;
                        return;
                    }
                    active_terminals =
                        cloud_mcp_active_provider_terminal_labels(&app, &provider).await;
                    if active_terminals.is_empty() {
                        break Some(guard);
                    }
                    drop(guard);
                }

                if !deferred_status_sent {
                    let details = json!({
                        "reason": "provider_in_use",
                        "provider": provider.clone(),
                        "active_terminal_count": active_terminals.len(),
                        "active_terminals": active_terminals,
                        "will_update_when_idle": true,
                    });
                    let _ = cloud_mcp_send_remote_command_status_event(
                        &state,
                        &event,
                        "deferred",
                        &format!("{provider} is in use — will update when idle."),
                        Some(&details),
                    )
                    .await;
                    deferred_status_sent = true;
                }
                tokio::time::sleep(Duration::from_secs(2)).await;
            }
        } else {
            None
        };
        let _ = cloud_mcp_send_remote_command_status_event(
            &state,
            &event,
            "running",
            &format!("Running headless agent {action} on this desktop."),
            None,
        )
        .await;
        let result = match action.as_str() {
            "install" => install_agent(provider.clone()).await,
            "update" => update_agent(provider.clone()).await,
            _ => uninstall_agent(provider.clone()).await,
        };
        drop(update_lifecycle_guard);
        let (status, message) = match &result {
            Ok(outcome) => {
                let succeeded = if action == "uninstall" {
                    !outcome.installed
                } else {
                    outcome.installed
                };
                if succeeded {
                    (
                        "completed",
                        if outcome.message.is_empty() {
                            format!("Agent {action} completed headless.")
                        } else {
                            outcome.message.clone()
                        },
                    )
                } else {
                    (
                        "failed",
                        if outcome.message.is_empty() {
                            format!("Agent {action} did not complete.")
                        } else {
                            outcome.message.clone()
                        },
                    )
                }
            }
            Err(error) => ("failed", error.clone()),
        };
        let _ = cloud_mcp_send_remote_command_status_event(&state, &event, status, &message, None)
            .await;
        // Converge inventory everywhere after the action.
        cloud_mcp_agent_inventory_probe_and_sync(
            &app,
            &state,
            &format!("remote_agent_{action}_headless"),
            true,
        )
        .await;
    });
    true
}

fn cloud_mcp_defer_remote_command_for_foreground(
    app: &AppHandle,
    event: &Value,
) -> Result<Vec<Value>, String> {
    let lock = CLOUD_MCP_REMOTE_COMMAND_HANDOFF_LOCK.get_or_init(|| StdMutex::new(()));
    let _guard = lock
        .lock()
        .map_err(|_| "remote command handoff lock is poisoned".to_string())?;
    // Remote command handoffs have their own state file. Sharing the older
    // remote-intents object with activation hints allowed unrelated whole-file
    // read/merge/write cycles to overwrite this delivery journal.
    let current = app_local_state_read(app, CLOUD_MCP_REMOTE_COMMAND_HANDOFF_STATE_KEY);
    let mut pending = current
        .get("pendingRemoteCommands")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let command_id = cloud_mcp_remote_command_id(event);
    let already_pending = !command_id.is_empty()
        && pending
            .iter()
            .any(|queued| cloud_mcp_remote_command_id(queued) == command_id);
    if !already_pending {
        pending.push(event.clone());
    }
    let mut dropped = Vec::new();
    if pending.len() > 8 {
        let overflow = pending.len() - 8;
        dropped.extend(pending.drain(0..overflow));
    }
    app_local_state_merge(
        app,
        CLOUD_MCP_REMOTE_COMMAND_HANDOFF_STATE_KEY,
        &json!({ "pendingRemoteCommands": pending }),
    )?;
    CLOUD_MCP_REMOTE_COMMAND_HANDOFF_PENDING.store(true, Ordering::Release);
    Ok(dropped)
}

fn cloud_mcp_headless_terminal_panel_close_command(
    original_event: &Value,
    workspace_id: &str,
    terminal: &Value,
) -> Option<Value> {
    let workspace_id = cloud_mcp_canonical_workspace_id_from_value(
        workspace_id,
        original_event,
        cloud_mcp_desktop_platform(),
    );
    if workspace_id.is_empty() {
        return None;
    }
    let target_panel_index = cloud_mcp_payload_i64(
        terminal,
        &["terminal_index", "target_terminal_index", "index"],
    )?;
    if target_panel_index < 0 {
        return None;
    }
    let target_panel_id = cloud_mcp_payload_text(
        terminal,
        &["pane_id", "target_terminal_id", "terminal_id", "panel_id"],
    )
    .filter(|value| !value.trim().is_empty())?;
    let original_command_id = cloud_mcp_remote_command_id(original_event);
    let command_id = if original_command_id.is_empty() {
        format!(
            "headless-terminal-panel-close-{}-{}-{}",
            workspace_id, target_panel_index, target_panel_id
        )
    } else {
        format!("{original_command_id}:panel-close")
    };
    let target_device_id =
        cloud_mcp_remote_command_field_text(original_event, &["target_device_id"]);
    let client_id = cloud_mcp_payload_text(original_event, &["client_id"]);
    let source = cloud_mcp_payload_text(original_event, &["source"])
        .unwrap_or_else(|| "rust-diffforge-headless".to_string());
    let mut command = json!({
        "command_id": command_id,
        "command_kind": "workspace_panel_close",
        "event_kind": "remote_command_requested",
        "source": source,
        "workspace_id": workspace_id,
        "target_panel_id": target_panel_id,
        "panel_id": target_panel_id,
        "pane_id": target_panel_id,
        "target_terminal_id": target_panel_id,
        "target_panel_index": target_panel_index,
        "panel_index": target_panel_index,
        "target_terminal_index": target_panel_index,
        "terminal_index": target_panel_index,
        "synthetic": true,
        "synthetic_reason": "headless_terminal_close",
    });
    if let Some(target_device_id) = target_device_id.filter(|value| !value.trim().is_empty()) {
        if let Some(object) = command.as_object_mut() {
            object.insert("target_device_id".to_string(), json!(target_device_id));
        }
    }
    if let Some(client_id) = client_id.filter(|value| !value.trim().is_empty()) {
        if let Some(object) = command.as_object_mut() {
            object.insert("client_id".to_string(), json!(client_id));
        }
    }
    Some(command)
}

fn cloud_mcp_terminal_agent_identity(value: &str) -> String {
    let normalized = value.trim().to_ascii_lowercase().replace(['_', ' '], "-");
    match normalized.as_str() {
        "claude-code" => "claude".to_string(),
        "plain-shell" | "generic-shell" | "terminal" => "shell".to_string(),
        _ => normalized,
    }
}

fn cloud_mcp_terminal_identity_values(workspace_id: &str, terminal: &Value) -> Vec<String> {
    let workspace_id = cloud_mcp_workspace_id_match_key(workspace_id);
    let mut values = Vec::<String>::new();
    let mut push = |value: String| {
        let trimmed = value.trim();
        if !trimmed.is_empty() && !values.iter().any(|existing| existing == trimmed) {
            values.push(trimmed.to_string());
        }
    };

    for key in ["id", "pane_id", "terminal_id", "target_terminal_id"] {
        if let Some(value) = cloud_mcp_payload_text(terminal, &[key]) {
            push(value);
        }
    }

    if !workspace_id.is_empty() {
        if let Some(terminal_index) = cloud_mcp_payload_i64(terminal, &["terminal_index", "index"])
        {
            if terminal_index >= 0 {
                let base_id = format!("workspace-terminal-{}-{}", workspace_id, terminal_index);
                push(base_id.clone());
                if let Some(agent_id) = cloud_mcp_payload_text(
                    terminal,
                    &[
                        "agent_id",
                        "agent_kind",
                        "agent_type",
                        "agent",
                        "provider",
                        "role",
                    ],
                )
                .map(|value| cloud_mcp_terminal_agent_identity(&value))
                .filter(|value| !value.is_empty())
                {
                    push(format!("{base_id}-{agent_id}"));
                }
            }
        }
    }

    values
}

fn cloud_mcp_terminal_matches_target_id(
    workspace_id: &str,
    terminal: &Value,
    target_terminal_id: &str,
) -> bool {
    let target_terminal_id = target_terminal_id.trim();
    !target_terminal_id.is_empty()
        && cloud_mcp_terminal_identity_values(workspace_id, terminal)
            .iter()
            .any(|value| value == target_terminal_id)
}

/// Conservative headless idle assessment for one presence-snapshot terminal:
/// hook registry wins when fresh; otherwise the snapshot's own input-ready /
/// status fields decide. Unknown leans busy only for explicit busy markers.
fn cloud_mcp_presence_terminal_is_idle(terminal: &Value) -> bool {
    let pane_id = cloud_mcp_payload_text(terminal, &["pane_id"]).unwrap_or_default();
    if !pane_id.is_empty() {
        if let Some(input_ready) = todo_dispatch_pane_input_ready(&pane_id) {
            return input_ready;
        }
    }
    if let Some(input_ready) = terminal.get("input_ready").and_then(Value::as_bool) {
        return input_ready;
    }
    let status = cloud_mcp_payload_text(terminal, &["status", "state"])
        .unwrap_or_default()
        .to_ascii_lowercase();
    !matches!(
        status.as_str(),
        "busy" | "running" | "working" | "sending" | "submitted" | "starting"
    )
}

/// Headless actuation for the `terminal_interrupt` remote command. Unlike the
/// broader terminal lever this always runs natively — webview alive or not —
/// because the PTY Escape write and task-interrupt bookkeeping are Rust-owned,
/// so the dashboard lever never waits on a webview round trip.
fn cloud_mcp_apply_remote_terminal_interrupt_lever(
    app: &AppHandle,
    state: &CloudMcpState,
    event: &Value,
) -> bool {
    let command_kind = cloud_mcp_remote_command_kind(event);
    if !matches!(
        command_kind.as_str(),
        "terminal_interrupt"
            | "interrupt"
            | "terminal_send_escape"
            | "interrupt_terminal"
            | "terminal_stop"
            | "stop_terminal"
            | "terminal_cancel"
    ) {
        return false;
    }
    let workspace_id =
        cloud_mcp_remote_command_field_text(event, &["workspace_id"]).unwrap_or_default();
    let target_terminal_id = cloud_mcp_remote_command_field_text(
        event,
        &["target_terminal_id", "terminal_id", "pane_id"],
    )
    .unwrap_or_default();
    let instance_id = cloud_mcp_remote_command_field_i64(event, &["terminal_instance_id"])
        .and_then(|value| u64::try_from(value).ok())
        .filter(|value| *value > 0);
    let app = app.clone();
    let state = state.clone();
    let event = event.clone();
    tauri::async_runtime::spawn(async move {
        if target_terminal_id.is_empty() {
            let _ = cloud_mcp_send_remote_command_status_event(
                &state,
                &event,
                "failed",
                "Terminal interrupt requires an exact terminal id.",
                None,
            )
            .await;
            return;
        }
        // Prefer the presence snapshot's pane id for the targeted terminal;
        // fall back to treating the target id as the pane id (the prompt
        // answer lever's convention).
        let snapshot = {
            let snapshots = state.runtime_snapshots.lock().await;
            snapshots.workspace_terminals.clone()
        };
        let resolved_pane_id = snapshot
            .as_ref()
            .and_then(|payload| payload.get("workspaces"))
            .and_then(Value::as_array)
            .and_then(|workspaces| {
                workspaces
                    .iter()
                    .filter(|workspace| {
                        workspace_id.is_empty()
                            || cloud_mcp_payload_text(workspace, &["workspace_id"])
                                .map(|value| cloud_mcp_workspace_id_match_key(&value))
                                .as_deref()
                                == Some(workspace_id.as_str())
                    })
                    .flat_map(|workspace| {
                        workspace
                            .get("terminals")
                            .and_then(Value::as_array)
                            .cloned()
                            .unwrap_or_default()
                    })
                    .find(|terminal| {
                        cloud_mcp_terminal_matches_target_id(
                            &workspace_id,
                            terminal,
                            &target_terminal_id,
                        )
                    })
                    .and_then(|terminal| cloud_mcp_payload_text(&terminal, &["pane_id"]))
            })
            .map(|pane_id| pane_id.trim().to_string())
            .filter(|pane_id| !pane_id.is_empty())
            .unwrap_or_else(|| target_terminal_id.clone());
        match crate::terminal_interrupt_agent_remote(
            app,
            resolved_pane_id,
            instance_id,
            "remote_command".to_string(),
        )
        .await
        {
            Ok(result) if result.wrote_escape => {
                let details = serde_json::to_value(&result).unwrap_or_else(|_| json!({}));
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state,
                    &event,
                    "completed",
                    "Escape interrupt sent to the terminal headless.",
                    Some(&details),
                )
                .await;
            }
            Ok(_) => {
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state,
                    &event,
                    "failed",
                    "No live terminal session matched the requested terminal id.",
                    None,
                )
                .await;
            }
            Err(error) => {
                let details = json!({
                    "error": clean_terminal_telemetry_text(&error),
                });
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state,
                    &event,
                    "failed",
                    "Unable to interrupt the terminal.",
                    Some(&details),
                )
                .await;
            }
        }
    });
    true
}

/// Headless actuation for remote terminal levers. Close-idle commands run
/// natively against the live PTY sessions (resolved from the cached presence
/// snapshot by exact pane id); relaunch is deferred as a replayed remote
/// command for the next foreground session, because agent
/// relaunch orchestration lives in the webview. Lease-gated: an open webview
/// owns all of these itself.
fn cloud_mcp_apply_remote_terminal_lever(
    app: &AppHandle,
    state: &CloudMcpState,
    event: &Value,
) -> bool {
    if todo_dispatch_webview_dispatcher_active() {
        return false;
    }
    let command_kind = cloud_mcp_payload_text(event, &["command_kind", "action", "command"])
        .unwrap_or_default()
        .to_ascii_lowercase()
        .replace(['.', ' ', '-'], "_");
    let action = match command_kind.as_str() {
        "terminal_close_idle" | "close_idle_terminal" => "close_one",
        "workspace_close_idle_terminals" | "close_idle_terminals" => "close_workspace",
        "terminal_close" | "close_terminal" | "terminal_force_close" | "force_close_terminal" => {
            "close_force"
        }
        "terminal_relaunch_agent"
        | "relaunch_terminal_agent"
        | "relaunch_terminal"
        | "terminal_relaunch"
        | "terminal_switch_agent"
        | "switch_terminal_agent" => "relaunch",
        // Terminal spawn, todo dispatch, and breakout-window actuation live
        // in the webview, so these replay as remote commands on the next
        // foreground session.
        "terminal_open" | "open_terminal" | "open_terminals" | "terminal_spawn"
        | "spawn_terminals" => "defer_open",
        "agent_chat_session_open"
        | "open_agent_chat_session"
        | "session_open"
        | "open_session"
        | "resume_agent_chat_session"
        | "resume_session" => "defer_session_open",
        "todo_requeue" | "requeue_todo" | "todo_retry" | "retry_todo" => "defer_requeue",
        "todo_queue" | "queue_todo" | "workspace_todo_queue" => "defer_queue",
        "todo_unqueue"
        | "unqueue_todo"
        | "workspace_todo_unqueue"
        | "todo_dequeue"
        | "dequeue_todo" => "defer_unqueue",
        "terminal_window_breakout"
        | "breakout_terminal"
        | "breakout_terminals"
        | "terminal_breakout"
        | "open_terminal_window"
        | "terminal_window_open"
        | "terminal_window_return"
        | "return_terminal_window"
        | "return_terminal_to_grid"
        | "close_terminal_window"
        | "terminal_window_close" => "defer_window",
        "workspace_panel_close" | "close_workspace_panel" | "panel_close" | "close_panel" => {
            "defer_panel_close"
        }
        _ => return false,
    };
    let workspace_id = cloud_mcp_payload_text(event, &["workspace_id"])
        .map(|value| cloud_mcp_workspace_id_match_key(&value))
        .unwrap_or_default();
    let target_terminal_id =
        cloud_mcp_payload_text(event, &["target_terminal_id", "terminal_id"]).unwrap_or_default();
    let target_terminal_name =
        cloud_mcp_payload_text(event, &["target_terminal_name", "terminal_name"])
            .unwrap_or_default()
            .to_ascii_lowercase();
    let target_terminal_index = event.get("target_terminal_index").and_then(Value::as_i64);
    let target_thread_id =
        cloud_mcp_payload_text(event, &["target_thread_id", "thread_id"]).unwrap_or_default();
    let terminal_hint_without_id = target_terminal_id.is_empty()
        && (!target_terminal_name.is_empty()
            || !target_thread_id.is_empty()
            || target_terminal_index.is_some());
    let app = app.clone();
    let state = state.clone();
    let event = event.clone();
    let action = action.to_string();
    tauri::async_runtime::spawn(async move {
        if matches!(
            action.as_str(),
            "relaunch"
                | "defer_open"
                | "defer_session_open"
                | "defer_requeue"
                | "defer_queue"
                | "defer_unqueue"
                | "defer_window"
                | "defer_panel_close"
        ) {
            if action == "relaunch" && target_terminal_id.is_empty() {
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state,
                    &event,
                    "failed",
                    "Terminal relaunch requires an exact terminal id.",
                    None,
                )
                .await;
                return;
            }
            if action == "defer_window" && terminal_hint_without_id {
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state,
                    &event,
                    "failed",
                    "Terminal window targeting requires an exact terminal id.",
                    None,
                )
                .await;
                return;
            }
            let dropped = match cloud_mcp_defer_remote_command_for_foreground(&app, &event) {
                Ok(dropped) => dropped,
                Err(error) => {
                    let details = json!({
                        "handoff_persisted": false,
                        "persistence_error": clean_terminal_telemetry_text(&error),
                    });
                    let _ = cloud_mcp_send_remote_command_status_event(
                        &state,
                        &event,
                        "failed",
                        "Remote command could not be handed to the desktop UI safely.",
                        Some(&details),
                    )
                    .await;
                    return;
                }
            };
            for dropped_event in dropped {
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state,
                    &dropped_event,
                    "dropped",
                    "Queued remote command was dropped because the foreground replay queue is full.",
                    None,
                )
                .await;
            }
            let deferred_message = match action.as_str() {
                "defer_open" => {
                    "Terminal open queued; it completes when the desktop window next opens."
                }
                "defer_session_open" => {
                    "Session open queued; it completes when the desktop window next opens."
                }
                "defer_requeue" => {
                    "Todo requeue queued; it completes when the desktop window next opens."
                }
                "defer_queue" => {
                    "Todo queue command queued; it completes when the desktop window next opens."
                }
                "defer_unqueue" => {
                    "Todo unqueue command queued; it completes when the desktop window next opens."
                }
                "defer_window" => {
                    "Terminal window breakout queued; it completes when the desktop window next opens."
                }
                "defer_panel_close" => {
                    "Workspace panel close queued; it completes when the desktop window next opens."
                }
                _ => "Terminal relaunch queued; it completes when the desktop window next opens.",
            };
            let _ = cloud_mcp_send_remote_command_status_event(
                &state,
                &event,
                "queued",
                deferred_message,
                None,
            )
            .await;
            return;
        }
        if workspace_id.is_empty() {
            let _ = cloud_mcp_send_remote_command_status_event(
                &state,
                &event,
                "failed",
                "Terminal command did not include a workspace id.",
                None,
            )
            .await;
            return;
        }
        let snapshot = {
            let snapshots = state.runtime_snapshots.lock().await;
            snapshots.workspace_terminals.clone()
        };
        let workspace_terminals = snapshot
            .as_ref()
            .and_then(|payload| payload.get("workspaces"))
            .and_then(Value::as_array)
            .map(|workspaces| {
                workspaces
                    .iter()
                    .filter(|workspace| {
                        cloud_mcp_payload_text(workspace, &["workspace_id"])
                            .map(|value| cloud_mcp_workspace_id_match_key(&value))
                            .as_deref()
                            == Some(workspace_id.as_str())
                    })
                    .flat_map(|workspace| {
                        workspace
                            .get("terminals")
                            .and_then(Value::as_array)
                            .cloned()
                            .unwrap_or_default()
                    })
                    .collect::<Vec<_>>()
            })
            .unwrap_or_default();
        if workspace_terminals.is_empty() {
            let _ = cloud_mcp_send_remote_command_status_event(
                &state,
                &event,
                "blocked",
                "No live terminals are known for that workspace on this desktop.",
                None,
            )
            .await;
            return;
        }
        if matches!(action.as_str(), "close_one" | "close_force") && target_terminal_id.is_empty() {
            let _ = cloud_mcp_send_remote_command_status_event(
                &state,
                &event,
                "failed",
                "Terminal command requires an exact terminal id.",
                None,
            )
            .await;
            return;
        }
        let matches_target = |terminal: &Value| -> bool {
            cloud_mcp_terminal_matches_target_id(&workspace_id, terminal, &target_terminal_id)
        };
        let candidates = if matches!(action.as_str(), "close_one" | "close_force") {
            let matched = workspace_terminals
                .iter()
                .find(|terminal| matches_target(terminal))
                .cloned();
            match matched {
                Some(terminal) => vec![terminal],
                None => {
                    let _ = cloud_mcp_send_remote_command_status_event(
                        &state,
                        &event,
                        "failed",
                        "No terminal matched the requested terminal id.",
                        None,
                    )
                    .await;
                    return;
                }
            }
        } else {
            workspace_terminals
        };
        let mut closed = 0usize;
        let mut skipped_busy = 0usize;
        let mut failed = 0usize;
        let terminal_state = app.state::<TerminalState>();
        for terminal in candidates {
            if action != "close_force" && !cloud_mcp_presence_terminal_is_idle(&terminal) {
                skipped_busy += 1;
                continue;
            }
            let pane_id = cloud_mcp_payload_text(&terminal, &["pane_id"]).unwrap_or_default();
            if pane_id.is_empty() {
                failed += 1;
                continue;
            }
            match close_terminal_session(
                Some(app.clone()),
                terminal_state.inner(),
                Some(&state),
                &pane_id,
                None,
                false,
                false,
                None,
            )
            .await
            {
                Ok(true) => {
                    closed += 1;
                    if let Some(panel_close_command) =
                        cloud_mcp_headless_terminal_panel_close_command(
                            &event,
                            &workspace_id,
                            &terminal,
                        )
                    {
                        let dropped = match cloud_mcp_defer_remote_command_for_foreground(
                            &app,
                            &panel_close_command,
                        ) {
                            Ok(dropped) => dropped,
                            Err(error) => {
                                let details = json!({
                                    "handoff_persisted": false,
                                    "persistence_error": clean_terminal_telemetry_text(&error),
                                });
                                let _ = cloud_mcp_send_remote_command_status_event(
                                    &state,
                                    &panel_close_command,
                                    "failed",
                                    "Panel-close follow-up could not be handed to the desktop UI safely.",
                                    Some(&details),
                                )
                                .await;
                                continue;
                            }
                        };
                        for dropped_event in dropped {
                            let _ = cloud_mcp_send_remote_command_status_event(
                                &state,
                                &dropped_event,
                                "dropped",
                                "Queued remote command was dropped because the foreground replay queue is full.",
                                None,
                            )
                            .await;
                        }
                    }
                }
                Ok(false) => failed += 1,
                Err(_) => failed += 1,
            }
        }
        let (status, message) = if action == "close_force" {
            if closed > 0 {
                (
                    "completed",
                    "Terminal force-closed headless; its process tree was killed.".to_string(),
                )
            } else {
                ("failed", "Terminal could not be force-closed.".to_string())
            }
        } else if action == "close_one" {
            if closed > 0 {
                ("completed", "Terminal closed headless.".to_string())
            } else if skipped_busy > 0 {
                (
                    "blocked",
                    "Terminal is busy, so it was not closed.".to_string(),
                )
            } else {
                ("failed", "Terminal could not be closed.".to_string())
            }
        } else {
            (
                "completed",
                format!(
                    "Closed {closed} idle terminal(s) headless; {skipped_busy} busy skipped{}.",
                    if failed > 0 {
                        format!(", {failed} failed")
                    } else {
                        String::new()
                    }
                ),
            )
        };
        let _ = cloud_mcp_send_remote_command_status_event(&state, &event, status, &message, None)
            .await;
        // Presence convergence: push a fresh snapshot composed from what
        // remains cached, so dashboards drop the closed terminals quickly.
        cloud_mcp_emit_sync_status(None);
    });
    true
}

/// Shows an OS-native notification (Notification Center on macOS, toast on
/// Windows) from the Rust side, so it works identically headless — main
/// window hidden in background/tray mode included. macOS uses the bundled
/// app icon automatically; Windows/Linux get the Diff Forge logo from the
/// bundled resource when present.
fn cloud_mcp_show_native_notification(
    app: &AppHandle,
    title: &str,
    body: &str,
) -> Result<(), String> {
    // The notification plugin is not registered in daemon mode, so
    // diffforge_native_notify silently no-ops there. A remote device_notify
    // must not report "shown" for a notification nobody saw — cloud Web Push
    // is the daemon-mode notification channel.
    if crate::daemon_mode_active() {
        return Err(
            "Native notifications are unavailable in daemon mode; use web push instead."
                .to_string(),
        );
    }
    diffforge_native_notify(
        app,
        title,
        body,
        NativeNotificationUrgency::Attention,
        false,
    )
}

/// Asset transfer commands are Rust-owned because local file presence and
/// managed asset paths live on the target device. Cloud/voice sends only ids and
/// metadata; this function resolves the local library row and performs the
/// upload/download through the existing asset endpoints.
fn cloud_mcp_apply_remote_asset_lever(
    app: &AppHandle,
    state: &CloudMcpState,
    event: &Value,
) -> bool {
    let command_kind = cloud_mcp_payload_text(event, &["command_kind", "action", "command"])
        .unwrap_or_default()
        .to_ascii_lowercase()
        .replace(['.', ' ', '-'], "_");
    let action = match command_kind.as_str() {
        "upload_asset" | "asset_upload" => "upload",
        "download_asset" | "asset_download" => "download",
        _ => return false,
    };
    let asset_id = cloud_mcp_payload_text(event, &["asset_id", "id"])
        .or_else(|| cloud_mcp_payload_text(event, &["payload", "asset_id"]))
        .unwrap_or_default();
    let base_url = cloud_mcp_payload_text(event, &["base_url"])
        .or_else(|| cloud_mcp_payload_text(event, &["payload", "base_url"]));
    let app = app.clone();
    let state = state.clone();
    let event = event.clone();
    let action = action.to_string();
    tauri::async_runtime::spawn(async move {
        if asset_id.trim().is_empty() {
            let _ = cloud_mcp_send_remote_command_status_event(
                &state,
                &event,
                "failed",
                "Asset transfer command did not include an asset id.",
                None,
            )
            .await;
            return;
        }
        let _ = cloud_mcp_send_remote_command_status_event(
            &state,
            &event,
            "running",
            if action == "upload" {
                "Uploading tracked asset from this desktop."
            } else {
                "Downloading cloud asset to this desktop."
            },
            None,
        )
        .await;

        let base_url = cloud_mcp_clean_optional_text(&base_url);
        let input = event.clone();
        let action_for_worker = action.clone();
        let transfer_result = tokio::task::spawn_blocking(move || {
            if action_for_worker == "upload" {
                cloud_mcp_forward_agent_upload_asset(None, None, base_url.as_deref(), &input)
            } else {
                cloud_mcp_forward_agent_download_asset(None, None, base_url.as_deref(), &input)
            }
        })
        .await
        .map_err(|error| format!("Asset transfer worker failed: {error}"))
        .and_then(|result| result);

        match transfer_result {
            Ok(result) => {
                let message = if action == "upload" {
                    "Asset upload completed from this desktop."
                } else {
                    "Asset download completed on this desktop."
                };
                let _ = app.emit(CLOUD_MCP_ACCOUNT_ASSETS_UPDATED_EVENT, result.clone());
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state,
                    &event,
                    "completed",
                    message,
                    Some(&result),
                )
                .await;
            }
            Err(error) => {
                let details = json!({
                    "asset_id": asset_id,
                    "action": action,
                    "error": error,
                });
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state,
                    &event,
                    "failed",
                    "Asset transfer failed on this desktop.",
                    Some(&details),
                )
                .await;
            }
        }
    });
    true
}

/// Local script execution is device-owned. Cloud and voice route only script
/// identity/name; the target Rust client resolves its own local scripts folder,
/// emits the normal script-run UI events, and reports completion to Cloud.
fn cloud_mcp_apply_remote_local_script_lever(
    app: &AppHandle,
    state: &CloudMcpState,
    event: &Value,
) -> bool {
    let command_kind = cloud_mcp_payload_text(event, &["command_kind", "action", "command"])
        .unwrap_or_default()
        .to_ascii_lowercase()
        .replace(['.', ' ', '-'], "_");
    if !matches!(
        command_kind.as_str(),
        "local_script_run" | "run_local_script" | "script_run" | "run_script"
    ) {
        return false;
    }
    let script_id = cloud_mcp_payload_text(event, &["script_id", "id"])
        .or_else(|| cloud_mcp_payload_text(event, &["payload", "script_id"]))
        .unwrap_or_default();
    let script_name = cloud_mcp_payload_text(event, &["script_name", "name", "title"])
        .or_else(|| cloud_mcp_payload_text(event, &["payload", "script_name"]))
        .unwrap_or_default();
    let path_key = cloud_mcp_payload_text(event, &["path_key"])
        .or_else(|| cloud_mcp_payload_text(event, &["payload", "path_key"]))
        .unwrap_or_default();
    let working_directory = cloud_mcp_payload_text(event, &["working_directory", "cwd"])
        .or_else(|| cloud_mcp_payload_text(event, &["payload", "working_directory"]))
        .or_else(|| cloud_mcp_payload_text(event, &["payload", "cwd"]))
        .unwrap_or_default();
    let shell = cloud_mcp_payload_text(event, &["shell"])
        .or_else(|| cloud_mcp_payload_text(event, &["payload", "shell"]))
        .unwrap_or_default();
    let app = app.clone();
    let state = state.clone();
    let event = event.clone();
    tauri::async_runtime::spawn(async move {
        if script_id.trim().is_empty()
            && script_name.trim().is_empty()
            && path_key.trim().is_empty()
        {
            let _ = cloud_mcp_send_remote_command_status_event(
                &state,
                &event,
                "failed",
                "Local script run did not include script_id, script_name, or path_key.",
                None,
            )
            .await;
            return;
        }
        let run_id = cloud_mcp_payload_text(&event, &["run_id"])
            .or_else(|| cloud_mcp_payload_text(&event, &["command_id"]))
            .unwrap_or_else(|| format!("remote-script-run-{}", uuid::Uuid::new_v4()));
        let command_id =
            cloud_mcp_payload_text(&event, &["command_id"]).unwrap_or_else(|| run_id.clone());
        let trigger_id = cloud_mcp_payload_text(&event, &["trigger_id"])
            .or_else(|| cloud_mcp_payload_text(&event, &["payload", "trigger_id"]))
            .unwrap_or_default();
        let trigger_run_id = cloud_mcp_payload_text(&event, &["trigger_run_id"])
            .or_else(|| cloud_mcp_payload_text(&event, &["payload", "trigger_run_id"]))
            .unwrap_or_default();
        let voice_session_id = cloud_mcp_payload_text(&event, &["voice_session_id"])
            .or_else(|| cloud_mcp_payload_text(&event, &["payload", "voice_session_id"]))
            .unwrap_or_default();
        let workspace_id = cloud_mcp_payload_text(&event, &["workspace_id"])
            .or_else(|| cloud_mcp_payload_text(&event, &["payload", "workspace_id"]))
            .unwrap_or_default();
        let terminal_id = cloud_mcp_payload_text(&event, &["terminal_id"])
            .or_else(|| cloud_mcp_payload_text(&event, &["payload", "terminal_id"]))
            .unwrap_or_default();
        let loopspace_id = cloud_mcp_payload_text(&event, &["loopspace_id"])
            .or_else(|| cloud_mcp_payload_text(&event, &["payload", "loopspace_id"]))
            .unwrap_or_default();
        let loop_runtime_run_id = cloud_mcp_payload_text(&event, &["loop_runtime_run_id"])
            .or_else(|| cloud_mcp_payload_text(&event, &["payload", "loop_runtime_run_id"]))
            .unwrap_or_else(|| run_id.clone());
        let loop_runtime_node_id = cloud_mcp_payload_text(&event, &["loop_runtime_node_id"])
            .or_else(|| cloud_mcp_payload_text(&event, &["payload", "loop_runtime_node_id"]))
            .unwrap_or_default();
        let loop_runtime_edge_id = cloud_mcp_payload_text(&event, &["loop_runtime_edge_id"])
            .or_else(|| cloud_mcp_payload_text(&event, &["payload", "loop_runtime_edge_id"]))
            .unwrap_or_default();
        let request_id = cloud_mcp_payload_text(&event, &["request_id"])
            .or_else(|| cloud_mcp_payload_text(&event, &["payload", "request_id"]))
            .unwrap_or_else(|| command_id.clone());
        let cause = cloud_mcp_payload_text(&event, &["cause", "run_cause", "trigger_cause"])
            .or_else(|| cloud_mcp_payload_text(&event, &["payload", "cause"]))
            .or_else(|| cloud_mcp_payload_text(&event, &["payload", "run_cause"]))
            .or_else(|| cloud_mcp_payload_text(&event, &["payload", "trigger_cause"]))
            .unwrap_or_else(|| {
                if !trigger_id.is_empty() || !loopspace_id.is_empty() {
                    "loop".to_string()
                } else if !voice_session_id.is_empty() {
                    "orchestrator_voice".to_string()
                } else {
                    "orchestrator".to_string()
                }
            });
        let source_kind =
            cloud_mcp_payload_text(&event, &["source_kind", "source", "trigger_source"])
                .or_else(|| cloud_mcp_payload_text(&event, &["payload", "source_kind"]))
                .or_else(|| cloud_mcp_payload_text(&event, &["payload", "source"]))
                .or_else(|| cloud_mcp_payload_text(&event, &["payload", "trigger_source"]))
                .unwrap_or_else(|| "cloud_remote_command".to_string());
        let request = json!({
            "cause": cause,
            "command_id": command_id,
            "loop_runtime_edge_id": loop_runtime_edge_id,
            "loop_runtime_node_id": loop_runtime_node_id,
            "loop_runtime_run_id": loop_runtime_run_id,
            "loopspace_id": loopspace_id,
            "path_key": path_key,
            "request_id": request_id,
            "run_id": run_id,
            "script_id": script_id,
            "script_name": script_name,
            "shell": shell,
            "source_kind": source_kind,
            "terminal_id": terminal_id,
            "trigger_id": trigger_id,
            "trigger_run_id": trigger_run_id,
            "voice_session_id": voice_session_id,
            "working_directory": working_directory,
            "workspace_id": workspace_id,
        });
        match local_scripts_enqueue_run(app.clone(), request).await {
            Ok(details) => {
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state,
                    &event,
                    "queued",
                    "Local script queued on this desktop.",
                    Some(&details),
                )
                .await;
            }
            Err(error) => {
                let details = json!({
                    "error": error,
                    "script_id": cloud_mcp_payload_text(&event, &["script_id", "id"]),
                    "script_name": cloud_mcp_payload_text(&event, &["script_name", "name", "title"]),
                });
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state,
                    &event,
                    "failed",
                    "Local script could not be run on this desktop.",
                    Some(&details),
                )
                .await;
            }
        }
    });
    true
}

/// Device-level levers Rust always owns, with or without the webview: window
/// visibility, native notifications, agent account switching, and terminal
/// output status (served from the native PTY tail buffer). The webview
/// remote-command listener stays silent on these kinds, so this function is
/// the single reply path. Plan release is cloud-owned and answered here only
/// so a stray desktop-routed command does not hang.
fn cloud_mcp_remote_device_lever_action(command_kind: &str) -> Option<&'static str> {
    match command_kind {
        "app_show_window" | "show_window" | "open_app_window" | "app_open_window" => {
            Some("show")
        }
        "app_hide_window" | "hide_window" | "app_background" | "hide_app_window" => {
            Some("hide")
        }
        "device_notify" | "notify_device" | "device_notification" | "send_notification" => {
            Some("notify")
        }
        "app_update_now" | "update_app" | "app_update" => Some("app_update_now"),
        "agent_account_start_login_transaction" => Some("account_login_transaction"),
        "agent_account_switch"
        | "switch_agent_account"
        | "agent_profile_switch"
        | "account_switch" => Some("account_switch"),
        "agent_account_push" | "push_agent_account" | "account_push" => {
            Some("agent_account_push")
        }
        "terminal_output_status"
        | "terminal_status"
        | "terminal_output"
        | "terminal_activity_status" => Some("output_status"),
        "plan_release_stage" | "release_plan_stage" | "plan_release" | "release_stage" => {
            Some("plan_release")
        }
        _ => None,
    }
}

fn cloud_mcp_apply_remote_device_lever(
    app: &AppHandle,
    state: &CloudMcpState,
    event: &Value,
) -> bool {
    let command_kind = cloud_mcp_payload_text(event, &["command_kind", "action", "command"])
        .unwrap_or_default()
        .to_ascii_lowercase()
        .replace(['.', ' ', '-'], "_");
    let Some(action) = cloud_mcp_remote_device_lever_action(&command_kind) else {
        return false;
    };
    let app = app.clone();
    let state = state.clone();
    let event = event.clone();
    let action = action.to_string();
    tauri::async_runtime::spawn(async move {
        match action.as_str() {
            "show" => {
                app_exit_background_internal(&app);
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state,
                    &event,
                    "completed",
                    "Diff Forge window shown on this desktop.",
                    None,
                )
                .await;
            }
            "hide" => {
                app_enter_background_internal(&app);
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state,
                    &event,
                    "completed",
                    "Diff Forge window hidden into background mode; terminals and queues keep running.",
                    None,
                )
                .await;
            }
            "notify" => {
                let message = cloud_mcp_payload_text(&event, &["message", "text", "body"])
                    .or_else(|| cloud_mcp_payload_text(&event, &["payload", "message"]))
                    .or_else(|| cloud_mcp_payload_text(&event, &["payload", "text"]))
                    .or_else(|| cloud_mcp_payload_text(&event, &["payload", "body"]))
                    .unwrap_or_default();
                if message.is_empty() {
                    let _ = cloud_mcp_send_remote_command_status_event(
                        &state,
                        &event,
                        "failed",
                        "Notification command did not include a message.",
                        None,
                    )
                    .await;
                    return;
                }
                let title = cloud_mcp_payload_text(&event, &["notification_title"])
                    .or_else(|| cloud_mcp_payload_text(&event, &["payload", "notification_title"]))
                    .or_else(|| cloud_mcp_payload_text(&event, &["payload", "notification_title"]))
                    .or_else(|| cloud_mcp_payload_text(&event, &["title"]))
                    .or_else(|| cloud_mcp_payload_text(&event, &["payload", "title"]))
                    .unwrap_or_else(|| "Diff Forge AI".to_string());
                let notify_result = cloud_mcp_show_native_notification(&app, &title, &message);
                let (status, reply, error) = match notify_result {
                    Ok(()) => (
                        "completed",
                        "Notification shown on this desktop.",
                        String::new(),
                    ),
                    Err(error) => (
                        "failed",
                        "Notification could not be shown on this desktop.",
                        error,
                    ),
                };
                let details = json!({
                    "native_notification": status == "completed",
                    "notification_title": title,
                    "notification_error": error,
                });
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state,
                    &event,
                    status,
                    reply,
                    Some(&details),
                )
                .await;
            }
            "account_switch" => {
                let provider = cloud_mcp_payload_text(
                    &event,
                    &["provider", "agent_provider", "agent_id", "target_agent_id"],
                )
                .unwrap_or_default();
                let profile_id = cloud_mcp_payload_text(&event, &["account_id", "profile_id"])
                    .or_else(|| cloud_mcp_payload_text(&event, &["payload", "account_id"]))
                    .unwrap_or_default();
                let result =
                    agent_accounts_set_active(app.clone(), provider.clone(), profile_id.clone())
                        .await;
                let (status, message) = match result {
                    Ok(_) => (
                        "completed",
                        format!("Active {provider} account switched to {profile_id}."),
                    ),
                    Err(error) => ("failed", error),
                };
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state, &event, status, &message, None,
                )
                .await;
            }
            "account_login_transaction" => {
                let provider = cloud_mcp_remote_command_field_text(
                    &event,
                    &[
                        "provider",
                        "agent_kind",
                        "agent_provider",
                        "agent_id",
                        "target_agent_id",
                    ],
                )
                .unwrap_or_default()
                .to_ascii_lowercase();
                let profile_id = cloud_mcp_remote_command_field_text(
                    &event,
                    &["profile_id", "account_id", "account_profile_id"],
                )
                .unwrap_or_default();
                if provider != "codex" {
                    let details = json!({
                        "provider": provider,
                        "profile_id": profile_id,
                        "required_provider": "codex",
                    });
                    let _ = cloud_mcp_send_remote_command_status_event(
                        &state,
                        &event,
                        "failed",
                        "The login transaction action is reserved for Codex device authorization.",
                        Some(&details),
                    )
                    .await;
                    return;
                }
                let result = agent_accounts_start_profile_login(
                    app.clone(),
                    provider.clone(),
                    profile_id.clone(),
                )
                .await;
                match result {
                    Ok(details) => {
                        let _ = cloud_mcp_send_remote_command_status_event(
                            &state,
                            &event,
                            "completed",
                            "Codex device authorization started; activation remains pending until the expected changed login is validated.",
                            Some(&details),
                        )
                        .await;
                    }
                    Err(error) => {
                        let details = json!({
                            "provider": provider,
                            "profile_id": profile_id,
                            "error": error,
                        });
                        let _ = cloud_mcp_send_remote_command_status_event(
                            &state,
                            &event,
                            "failed",
                            details
                                .get("error")
                                .and_then(Value::as_str)
                                .unwrap_or("Unable to start Codex device authorization."),
                            Some(&details),
                        )
                        .await;
                    }
                }
            }
            "agent_account_push" => {
                let push_id = cloud_mcp_remote_command_field_text(&event, &["push_id"])
                    .or_else(|| cloud_mcp_remote_command_field_text(&event, &["intent_id"]))
                    .unwrap_or_default();
                let agent_kind = cloud_mcp_remote_command_field_text(
                    &event,
                    &["agent_kind", "provider", "agent_provider"],
                )
                .unwrap_or_default();
                let sealed_blob = cloud_mcp_remote_command_field_text(&event, &["sealed_blob"])
                    .unwrap_or_default();
                let sealed_algorithm =
                    cloud_mcp_remote_command_field_text(&event, &["sealed_algorithm"])
                        .unwrap_or_default();
                let result = (|| -> Result<Value, String> {
                    if push_id.trim().is_empty() {
                        return Err("Agent account push is missing push_id.".to_string());
                    }
                    if sealed_blob.trim().is_empty() {
                        return Err("Agent account push is missing the sealed payload.".to_string());
                    }
                    if sealed_algorithm != AGENT_ACCOUNT_PUSH_SEALED_ALGORITHM {
                        return Err(
                            "Agent account push uses an unsupported sealed payload algorithm."
                                .to_string(),
                        );
                    }
                    let expected_kind =
                        agent_accounts_supported_kind(&agent_kind).ok_or_else(|| {
                            "Agent account push is missing a supported agent kind.".to_string()
                        })?;
                    let plaintext = agent_account_push_open_blob(&sealed_blob)?;
                    let blob = agent_account_push_decode_blob(&plaintext)?;
                    let now_ms = todo_dispatch_now_ms();
                    let current_device = cloud_mcp_desktop_device_profile();
                    let current_device_id =
                        cloud_mcp_payload_text(&current_device, &["device_id"]).unwrap_or_default();
                    let blob = agent_account_push_verify_received_blob(
                        blob,
                        &push_id,
                        &current_device_id,
                        now_ms,
                    )?;
                    agent_account_push_reject_if_applied(&push_id, now_ms)?;
                    if blob.agent_kind != expected_kind {
                        return Err("Agent account push kind does not match the sealed payload."
                            .to_string());
                    }
                    let expires_at_ms = blob.expires_at_ms;
                    let mut details = agent_accounts_materialize_pushed_account(blob)?;
                    agent_account_push_mark_applied(&push_id, expires_at_ms, now_ms)?;
                    if let Some(object) = details.as_object_mut() {
                        object.insert("push_id".to_string(), json!(push_id.clone()));
                        object.insert(
                            "sealed_algorithm".to_string(),
                            json!(sealed_algorithm.clone()),
                        );
                    }
                    Ok(details)
                })();
                match result {
                    Ok(details) => {
                        let kind = details
                            .get("agent_kind")
                            .and_then(Value::as_str)
                            .unwrap_or(agent_kind.as_str());
                        let _ = app.emit(AGENT_ACCOUNTS_CHANGED_EVENT, json!({ "kind": kind }));
                        let _ = cloud_mcp_send_remote_command_status_event(
                            &state,
                            &event,
                            "completed",
                            "Agent account push applied on this desktop.",
                            Some(&details),
                        )
                        .await;
                    }
                    Err(error) => {
                        let details = json!({
                            "push_id": push_id,
                            "agent_kind": agent_kind,
                            "sealed_algorithm": sealed_algorithm,
                            "error": clean_terminal_telemetry_text(&error),
                        });
                        let _ = cloud_mcp_send_remote_command_status_event(
                            &state,
                            &event,
                            "failed",
                            &error,
                            Some(&details),
                        )
                        .await;
                    }
                }
            }
            "output_status" => {
                cloud_mcp_report_terminal_output_status(&app, &state, &event).await;
            }
            "app_update_now" => {
                let result = app_update_remote_now(app.clone()).await;
                let ok = result.get("ok").and_then(Value::as_bool).unwrap_or(false);
                let queued = result
                    .get("queued")
                    .or_else(|| result.get("restart_when_idle"))
                    .and_then(Value::as_bool)
                    .unwrap_or(false);
                let message = if ok && queued {
                    "App update accepted; daemon will restart when terminals are idle."
                } else if ok {
                    "App update command completed on this desktop."
                } else {
                    "App update command failed on this desktop."
                };
                let status = if ok && queued {
                    "queued"
                } else if ok {
                    "completed"
                } else {
                    "failed"
                };
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state,
                    &event,
                    status,
                    message,
                    Some(&result),
                )
                .await;
                cloud_mcp_emit_sync_status(None);
            }
            "plan_release" => {
                let _ = cloud_mcp_send_remote_command_status_event(
                    &state,
                    &event,
                    "failed",
                    "Plan stages are cloud-owned; release them through the voice orchestrator's plan_release_stage action instead of a desktop command.",
                    None,
                )
                .await;
            }
            _ => {}
        }
    });
    true
}

fn cloud_mcp_remote_command_is_agent_prompt_answer(command_kind: &str) -> bool {
    matches!(
        command_kind,
        "agent_prompt_answer"
            | "answer_agent_prompt"
            | "agent_input_answer"
            | "terminal_prompt_answer"
            | "prompt_answer"
    )
}

fn cloud_mcp_remote_command_is_rust_owned(event: &Value) -> bool {
    let command_kind = cloud_mcp_remote_command_kind(event);
    if cloud_mcp_remote_command_is_agent_prompt_answer(&command_kind)
        && todo_dispatch_webview_dispatcher_active()
    {
        return false;
    }
    matches!(
        command_kind.as_str(),
        "agent_uninstall"
            | "uninstall_agent"
            | "cli_uninstall"
            | "agent_update"
            | "update_agent"
            | "cli_update"
            | "app_show_window"
            | "show_window"
            | "open_app_window"
            | "app_open_window"
            | "app_hide_window"
            | "hide_window"
            | "app_background"
            | "hide_app_window"
            | "device_notify"
            | "notify_device"
            | "device_notification"
            | "send_notification"
            | "app_update_now"
            | "update_app"
            | "app_update"
            | "agent_account_start_login_transaction"
            | "agent_account_switch"
            | "switch_agent_account"
            | "agent_profile_switch"
            | "account_switch"
            | "agent_account_push"
            | "push_agent_account"
            | "account_push"
            | "terminal_output_status"
            | "terminal_status"
            | "terminal_output"
            | "terminal_activity_status"
            | "agent_prompt_answer"
            | "answer_agent_prompt"
            | "agent_input_answer"
            | "terminal_prompt_answer"
            | "prompt_answer"
            | "todo_create"
            | "create_todo"
            | "workspace_todo_create"
            | "todo_update"
            | "update_todo"
            | "workspace_todo_update"
            | "todo_delete"
            | "delete_todo"
            | "workspace_todo_delete"
            | "remote_todo_delete"
            | "upload_asset"
            | "asset_upload"
            | "download_asset"
            | "asset_download"
            | "local_script_run"
            | "run_local_script"
            | "script_run"
            | "run_script"
            | "plan_release_stage"
            | "release_plan_stage"
            | "plan_release"
            | "release_stage"
    )
}

/// Answers `terminal_output_status`: resolves the target terminal from the
/// cached presence snapshot, then reads the native PTY tail buffer so the
/// answer works identically headless and with the webview open.
async fn cloud_mcp_report_terminal_output_status(
    app: &AppHandle,
    state: &CloudMcpState,
    event: &Value,
) {
    let workspace_id = cloud_mcp_payload_text(event, &["workspace_id"])
        .map(|value| cloud_mcp_workspace_id_match_key(&value))
        .unwrap_or_default();
    let target_terminal_id =
        cloud_mcp_payload_text(event, &["target_terminal_id", "terminal_id"]).unwrap_or_default();
    if workspace_id.is_empty() {
        let _ = cloud_mcp_send_remote_command_status_event(
            state,
            event,
            "failed",
            "Terminal output status requires a workspace id.",
            None,
        )
        .await;
        return;
    }
    if target_terminal_id.is_empty() {
        let _ = cloud_mcp_send_remote_command_status_event(
            state,
            event,
            "failed",
            "Terminal output status requires an exact terminal id.",
            None,
        )
        .await;
        return;
    }
    let snapshot = {
        let snapshots = state.runtime_snapshots.lock().await;
        snapshots.workspace_terminals.clone()
    };
    let terminal = snapshot
        .as_ref()
        .and_then(|payload| payload.get("workspaces"))
        .and_then(Value::as_array)
        .map(|workspaces| {
            workspaces
                .iter()
                .filter(|workspace| {
                    cloud_mcp_payload_text(workspace, &["workspace_id"])
                        .as_deref()
                        .map(cloud_mcp_workspace_id_match_key)
                        .as_deref()
                        == Some(workspace_id.as_str())
                })
                .flat_map(|workspace| {
                    workspace
                        .get("terminals")
                        .and_then(Value::as_array)
                        .cloned()
                        .unwrap_or_default()
                })
                .collect::<Vec<_>>()
        })
        .unwrap_or_default()
        .into_iter()
        .find(|terminal| {
            cloud_mcp_terminal_matches_target_id(&workspace_id, terminal, &target_terminal_id)
        });
    let Some(terminal) = terminal else {
        let _ = cloud_mcp_send_remote_command_status_event(
            state,
            event,
            "failed",
            "No terminal matched the requested terminal id.",
            None,
        )
        .await;
        return;
    };
    let pane_id = cloud_mcp_payload_text(&terminal, &["pane_id"]).unwrap_or_default();
    let terminal_label = cloud_mcp_payload_text(&terminal, &["terminal_nickname", "terminal_name"])
        .unwrap_or_else(|| pane_id.clone());
    let busy = !cloud_mcp_presence_terminal_is_idle(&terminal);
    let agent = cloud_mcp_payload_text(&terminal, &["agent_id", "agent_type"]).unwrap_or_default();
    let tail_text = {
        let terminal_state = app.state::<TerminalState>();
        let instance = {
            let terminals = terminal_state.terminals.read().await;
            terminals.get(&pane_id).cloned()
        };
        instance
            .and_then(|instance| {
                instance
                    .headless_output
                    .lock()
                    .ok()
                    .map(|output| output.tail.iter().copied().collect::<Vec<u8>>())
            })
            .map(|bytes| {
                let text = String::from_utf8_lossy(&bytes).to_string();
                let cleaned = clean_terminal_telemetry_text(&text);
                cleaned
                    .chars()
                    .rev()
                    .take(600)
                    .collect::<Vec<_>>()
                    .into_iter()
                    .rev()
                    .collect::<String>()
            })
            .unwrap_or_default()
    };
    let state_label = if busy { "busy" } else { "idle" };
    let message = if tail_text.is_empty() {
        format!(
            "Terminal '{terminal_label}'{} is {state_label}; no recent output is buffered.",
            if agent.is_empty() {
                String::new()
            } else {
                format!(" ({agent})")
            }
        )
    } else {
        format!(
            "Terminal '{terminal_label}'{} is {state_label}. Recent output: {tail_text}",
            if agent.is_empty() {
                String::new()
            } else {
                format!(" ({agent})")
            }
        )
    };
    let details = json!({
        "agent_id": agent,
        "busy": busy,
        "pane_id": pane_id,
        "terminal_name": terminal_label,
        "output_tail": tail_text,
        "workspace_id": workspace_id,
    });
    let _ = cloud_mcp_send_remote_command_status_event(
        state,
        event,
        "completed",
        &message,
        Some(&details),
    )
    .await;
}

fn cloud_mcp_is_tokenomics_state_event(event_kind: &str) -> bool {
    matches!(event_kind, "tokenomics_status")
}

fn cloud_mcp_is_tokenomics_delta_signal_event(event_kind: &str) -> bool {
    matches!(
        event_kind,
        CLOUD_MCP_TOKENOMICS_DELTA_AVAILABLE_EVENT
            | CLOUD_MCP_TOKENOMICS_DEVICE_DELTA_EVENT
            | CLOUD_MCP_TOKENOMICS_DEVICE_SNAPSHOT_EVENT
    )
}

fn cloud_mcp_is_workspace_todo_wake_event(event_kind: &str, _event: &Value) -> bool {
    if matches!(
        event_kind,
        "todo.live_state"
            | "account_todo_delta"
            | "workspace_todo_upserted"
            | "workspace_todo_deleted"
            | "workspace_todo_listed_created"
            | "workspace_todo_workspace_removed"
            | "workspace_todo_dispatch_requested"
            | "todo_dispatch_requested"
            | "workspace_todo_dispatch_status"
            | "todo_dispatch_status"
            | "todo_dispatch_update"
            | "remote_command_ack"
            | "remote_command_result"
    ) {
        return true;
    }
    false
}

fn cloud_mcp_event_originated_from_this_device(event: &Value) -> bool {
    let Some(event_device_id) = cloud_mcp_payload_text(event, &["device_id"])
        .or_else(|| cloud_mcp_payload_text(event, &["source_device_id"]))
        .or_else(|| cloud_mcp_payload_text(event, &["origin_device_id"]))
        .or_else(|| cloud_mcp_payload_text(event, &["payload", "device_id"]))
        .or_else(|| cloud_mcp_payload_text(event, &["payload", "source_device_id"]))
        .or_else(|| cloud_mcp_payload_text(event, &["payload", "origin_device_id"]))
        .or_else(|| cloud_mcp_payload_text(event, &["device", "device_id"]))
        .map(|value| value.trim().to_lowercase())
        .filter(|value| !value.is_empty())
    else {
        return false;
    };
    let device = cloud_mcp_desktop_device_profile();
    [cloud_mcp_payload_text(&device, &["device_id"])]
        .into_iter()
        .flatten()
        .map(|value| value.trim().to_lowercase())
        .any(|value| value == event_device_id)
}

fn cloud_mcp_doc_wire_text(event: &Value, key: &str) -> Option<String> {
    cloud_mcp_payload_text(event, &[key])
        .or_else(|| cloud_mcp_payload_text(event, &["payload", key]))
        .or_else(|| cloud_mcp_payload_text(event, &["data", key]))
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
}

fn cloud_mcp_doc_domain(event: &Value) -> Option<String> {
    cloud_mcp_doc_wire_text(event, "d")
        .or_else(|| cloud_mcp_doc_wire_text(event, "doc_domain"))
        .map(|value| value.to_ascii_lowercase())
}

fn cloud_mcp_is_account_documents_sync_wake_event(event_kind: &str, event: &Value) -> bool {
    let contract = cloud_mcp_doc_wire_text(event, "contract");
    if contract.as_deref() == Some(CLOUD_MCP_ACCOUNT_DOCUMENTS_CONTRACT) {
        return cloud_mcp_doc_domain(event).as_deref() == Some("documents");
    }
    let wire_kind = cloud_mcp_doc_wire_text(event, "c")
        .or_else(|| cloud_mcp_doc_wire_text(event, "event_kind"))
        .or_else(|| Some(event_kind.trim().to_string()).filter(|value| !value.is_empty()))
        .unwrap_or_default();
    if matches!(wire_kind.as_str(), "doc.sync" | "doc.content") {
        return cloud_mcp_doc_domain(event).as_deref() == Some("documents");
    }
    false
}

fn cloud_mcp_is_account_asset_wake_event(event_kind: &str, event: &Value) -> bool {
    if cloud_mcp_payload_text(event, &["contract"]).as_deref()
        == Some("diffforge.account_assets.v2")
    {
        return true;
    }
    if event_kind == "account_assets_hello" || event_kind.starts_with("account_assets_") {
        return true;
    }
    false
}

fn cloud_mcp_is_voice_plan_result_event(event_kind: &str) -> bool {
    matches!(
        event_kind,
        "voice_plan_task_status"
            | "voice_plan_task_update"
            | "voice_plan_step_update"
            | "voice_plan_step_tasks_update"
            | "voice_plan_steps_update"
            | "voice_plan_plan_update"
    )
}

fn cloud_mcp_raw_string_field(value: &Value, keys: &[&str]) -> Option<String> {
    keys.iter().find_map(|key| {
        value.get(*key).and_then(|candidate| match candidate {
            Value::String(text) => Some(text.clone()),
            Value::Number(number) => Some(number.to_string()),
            _ => None,
        })
    })
}

fn cloud_mcp_clean_audio_polishing_prompt(value: &str) -> String {
    value
        .replace("\r\n", "\n")
        .replace('\r', "\n")
        .replace('\0', "")
        .chars()
        .take(CLOUD_MCP_AUDIO_POLISHING_SYSTEM_PROMPT_MAX_CHARS)
        .collect()
}

fn cloud_mcp_default_audio_polishing_prompt() -> String {
    cloud_mcp_clean_audio_polishing_prompt(CLOUD_MCP_DEFAULT_AUDIO_POLISHING_SYSTEM_PROMPT)
}

fn cloud_mcp_audio_preferences_timestamp(value: &Value) -> u64 {
    ["updated_at_ms", "prompt_updated_at_ms"]
        .iter()
        .find_map(|key| {
            value.get(*key).and_then(|candidate| {
                candidate
                    .as_u64()
                    .or_else(|| {
                        candidate
                            .as_i64()
                            .and_then(|number| u64::try_from(number).ok())
                    })
                    .or_else(|| {
                        candidate
                            .as_str()
                            .and_then(|text| text.trim().parse::<u64>().ok())
                    })
            })
        })
        .unwrap_or_default()
}

fn cloud_mcp_sanitize_audio_preferences(value: &Value) -> Option<Value> {
    let source = value
        .get("preferences")
        .or_else(|| value.get("audio_preferences"))
        .unwrap_or(value);
    let prompt_present = [
        "polishing_system_prompt",
        "polishing_prompt",
        "system_prompt",
        "prompt",
    ]
    .iter()
    .any(|key| source.get(*key).is_some());
    let prompt = cloud_mcp_raw_string_field(
        source,
        &[
            "polishing_system_prompt",
            "polishing_prompt",
            "system_prompt",
            "prompt",
        ],
    )
    .map(|value| cloud_mcp_clean_audio_polishing_prompt(&value))
    .unwrap_or_default();
    let updated_at_ms = cloud_mcp_audio_preferences_timestamp(source);

    if !prompt_present && updated_at_ms == 0 {
        return None;
    }

    let mut object = serde_json::Map::new();
    object.insert("polishing_system_prompt".to_string(), json!(prompt));
    object.insert(
        "max_chars".to_string(),
        json!(CLOUD_MCP_AUDIO_POLISHING_SYSTEM_PROMPT_MAX_CHARS),
    );
    object.insert("updated_at_ms".to_string(), json!(updated_at_ms));
    Some(Value::Object(object))
}

fn cloud_mcp_audio_preferences_from_app(app: &AppHandle) -> Value {
    let current = app_local_state_read(app, CLOUD_MCP_AUDIO_PREFERENCES_STATE_KEY);
    let default_prompt = cloud_mcp_default_audio_polishing_prompt();
    cloud_mcp_sanitize_audio_preferences(&current).unwrap_or_else(|| {
        json!({
            "polishing_system_prompt": default_prompt,
            "max_chars": CLOUD_MCP_AUDIO_POLISHING_SYSTEM_PROMPT_MAX_CHARS,
            "updated_at_ms": 0})
    })
}

fn cloud_mcp_audio_preferences_write_app(
    app: &AppHandle,
    preferences: &Value,
) -> Result<(), String> {
    app_local_state_write(app, CLOUD_MCP_AUDIO_PREFERENCES_STATE_KEY, preferences)
}

async fn cloud_mcp_audio_preferences_set_runtime_snapshot(
    state: &CloudMcpState,
    preferences: Value,
) {
    let mut snapshots = state.runtime_snapshots.lock().await;
    snapshots.audio_preferences = Some(preferences);
}

fn cloud_mcp_audio_preferences_unit_payload(preferences: &Value, reason: &str) -> Value {
    let device_profile = cloud_mcp_desktop_device_profile();
    let device_id = cloud_mcp_payload_text(&device_profile, &["device_id"])
        .unwrap_or_else(|| "desktop".to_string());
    let content_hash = cloud_mcp_outbox_payload_hash(&json!({
        "device_id": device_id,
        "sync_unit": "audio_preferences",
        "audio_preferences": preferences,
    }));
    json!({
        "source": "rust-diffforge-device-live-unit",
        "reason": reason,
        "event_kind": "device_audio_preferences",
        "sync_unit": "audio_preferences",
        "sync_content_hash": content_hash,
        "device_id": device_id.clone(),
        "device": {
            "id": device_id,
            "name": device_profile["device_name"].clone(),
            "host": device_profile["machine_name"].clone(),
            "os": device_profile["platform"].clone(),
            "platform": device_profile["platform"].clone(),
            "kind": device_profile["form_factor"].clone(),
            "native": true,
            "web": false,
            "connected": true,
        },
        "audio_preferences": preferences.clone(),
    })
}

async fn cloud_mcp_publish_audio_preferences_unit(
    state: &CloudMcpState,
    preferences: &Value,
    reason: &str,
) -> Result<Value, String> {
    cloud_mcp_sync_device_live_unit_event(
        state,
        "device_audio_preferences",
        cloud_mcp_audio_preferences_unit_payload(preferences, reason),
    )
    .await
}

fn cloud_mcp_audio_preferences_from_account_live_state(value: &Value) -> Option<Value> {
    let live = cloud_mcp_account_live_state_from_value(value).unwrap_or_else(|| value.clone());
    for candidate in [
        live.get("audio_preferences"),
        live.pointer("/data/audio_preferences"),
    ]
    .into_iter()
    .flatten()
    {
        if let Some(preferences) = cloud_mcp_sanitize_audio_preferences(candidate) {
            return Some(preferences);
        }
    }

    let devices = live.get("devices").or_else(|| live.get("device_map"));
    let mut latest: Option<Value> = None;
    match devices {
        Some(Value::Object(map)) => {
            for device in map.values() {
                let Some(preferences) = device
                    .get("audio_preferences")
                    .and_then(cloud_mcp_sanitize_audio_preferences)
                else {
                    continue;
                };
                if cloud_mcp_audio_preferences_timestamp(&preferences)
                    >= latest
                        .as_ref()
                        .map(cloud_mcp_audio_preferences_timestamp)
                        .unwrap_or_default()
                {
                    latest = Some(preferences);
                }
            }
        }
        Some(Value::Array(items)) => {
            for device in items {
                let Some(preferences) = device
                    .get("audio_preferences")
                    .and_then(cloud_mcp_sanitize_audio_preferences)
                else {
                    continue;
                };
                if cloud_mcp_audio_preferences_timestamp(&preferences)
                    >= latest
                        .as_ref()
                        .map(cloud_mcp_audio_preferences_timestamp)
                        .unwrap_or_default()
                {
                    latest = Some(preferences);
                }
            }
        }
        _ => {}
    }
    latest
}

async fn cloud_mcp_apply_audio_preferences_from_account_live_state(
    app: &AppHandle,
    state: &CloudMcpState,
    event: &Value,
) {
    let Some(preferences) = cloud_mcp_audio_preferences_from_account_live_state(event) else {
        return;
    };
    let incoming_updated_at_ms = cloud_mcp_audio_preferences_timestamp(&preferences);
    if incoming_updated_at_ms == 0 {
        return;
    }
    let current = cloud_mcp_audio_preferences_from_app(app);
    let current_updated_at_ms = cloud_mcp_audio_preferences_timestamp(&current);
    if current_updated_at_ms > incoming_updated_at_ms {
        return;
    }
    if current_updated_at_ms == incoming_updated_at_ms && current == preferences {
        return;
    }
    if cloud_mcp_audio_preferences_write_app(app, &preferences).is_err() {
        return;
    }
    cloud_mcp_audio_preferences_set_runtime_snapshot(state, preferences.clone()).await;
    let _ = app.emit(
        CLOUD_MCP_AUDIO_PREFERENCES_CHANGED_EVENT,
        json!({
            "preferences": preferences,
            "reason": "account_device_live_state_snapshot",
            "source": "cloud",
        }),
    );
}

#[tauri::command(rename_all = "snake_case")]
async fn cloud_mcp_get_audio_preferences(
    app: AppHandle,
    state: State<'_, CloudMcpState>,
) -> Result<Value, String> {
    let preferences = cloud_mcp_audio_preferences_from_app(&app);
    if cloud_mcp_audio_preferences_timestamp(&preferences) > 0 {
        cloud_mcp_audio_preferences_set_runtime_snapshot(state.inner(), preferences.clone()).await;
    }
    Ok(json!({
        "ok": true,
        "preferences": preferences.clone(),
        "polishing_system_prompt": preferences["polishing_system_prompt"].clone(),
        "updated_at_ms": preferences["updated_at_ms"].clone(),
    }))
}

#[tauri::command(rename_all = "snake_case")]
async fn cloud_mcp_set_audio_preferences(
    app: AppHandle,
    state: State<'_, CloudMcpState>,
    preferences: Value,
    reason: Option<String>,
) -> Result<Value, String> {
    let now_ms = cloud_mcp_now_ms();
    let default_prompt = cloud_mcp_default_audio_polishing_prompt();
    let mut preferences = cloud_mcp_sanitize_audio_preferences(&preferences).unwrap_or_else(|| {
        json!({
            "polishing_system_prompt": default_prompt,
            "max_chars": CLOUD_MCP_AUDIO_POLISHING_SYSTEM_PROMPT_MAX_CHARS,
            "updated_at_ms": now_ms})
    });
    if cloud_mcp_audio_preferences_timestamp(&preferences) == 0 {
        if let Some(object) = preferences.as_object_mut() {
            object.insert("updated_at_ms".to_string(), json!(now_ms));
        }
    }
    cloud_mcp_audio_preferences_write_app(&app, &preferences)?;
    cloud_mcp_audio_preferences_set_runtime_snapshot(state.inner(), preferences.clone()).await;
    let reason = reason
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| "audio_preferences_changed".to_string());
    let _ = app.emit(
        CLOUD_MCP_AUDIO_PREFERENCES_CHANGED_EVENT,
        json!({
            "preferences": preferences.clone(),
            "reason": reason.clone(),
            "source": "local",
        }),
    );
    let sync_result =
        cloud_mcp_publish_audio_preferences_unit(state.inner(), &preferences, &reason).await?;
    Ok(json!({
        "ok": true,
        "preferences": preferences,
        "event_kind": "device_audio_preferences",
        "sync": sync_result,
        "reason": reason,
    }))
}

fn cloud_mcp_notification_preferences_timestamp(value: &Value) -> u64 {
    ["updated_at_ms"]
        .iter()
        .find_map(|key| {
            value.get(*key).and_then(|candidate| {
                candidate
                    .as_u64()
                    .or_else(|| {
                        candidate
                            .as_i64()
                            .and_then(|number| u64::try_from(number).ok())
                    })
                    .or_else(|| {
                        candidate
                            .as_str()
                            .and_then(|text| text.trim().parse::<u64>().ok())
                    })
            })
        })
        .unwrap_or_default()
}

fn cloud_mcp_notification_preferences_timestamp_is_plausible(value: &Value, now_ms: u64) -> bool {
    let timestamp = cloud_mcp_notification_preferences_timestamp(value);
    timestamp > 0
        && timestamp <= now_ms.saturating_add(CLOUD_MCP_NOTIFICATION_PREFERENCES_MAX_CLOCK_SKEW_MS)
}

fn cloud_mcp_notification_preferences_source(value: &Value) -> &Value {
    value
        .get("preferences")
        .or_else(|| value.get("notification_preferences"))
        .unwrap_or(value)
}

fn cloud_mcp_notification_preferences_bool(source: &Value, keys: &[&str], fallback: bool) -> bool {
    for key in keys {
        let Some(candidate) = source.get(*key) else {
            continue;
        };
        if let Some(value) = candidate.as_bool() {
            return value;
        }
        if let Some(value) = candidate.as_i64() {
            return value != 0;
        }
        if let Some(text) = candidate.as_str() {
            match text.trim().to_ascii_lowercase().as_str() {
                "true" | "1" | "yes" | "on" | "enabled" => return true,
                "false" | "0" | "no" | "off" | "disabled" => return false,
                _ => {}
            }
        }
    }
    fallback
}

fn cloud_mcp_notification_preferences_push_alias(key: &str) -> bool {
    matches!(
        key,
        "uir_prompts"
            | "terminal_errors"
            | "loop_run_started"
            | "loop_run_completed"
            | "loop_run_failed"
            | "loop_run_blocked"
            | "awaiting_device"
            | "account_events"
    )
}

fn cloud_mcp_notification_preferences_top_level_alias(key: &str) -> bool {
    matches!(
        key,
        "version" | "push" | "loopspace_overrides" | "updated_at_ms"
    )
}

fn cloud_mcp_notification_override_value(value: Option<&Value>) -> Value {
    let Some(candidate) = value else {
        return Value::Null;
    };
    if candidate.is_null() {
        return Value::Null;
    }
    if let Some(value) = candidate.as_bool() {
        return json!(value);
    }
    if let Some(value) = candidate.as_i64() {
        return json!(value != 0);
    }
    if let Some(text) = candidate.as_str() {
        match text.trim().to_ascii_lowercase().as_str() {
            "true" | "1" | "yes" | "on" | "enabled" => return json!(true),
            "false" | "0" | "no" | "off" | "disabled" => return json!(false),
            _ => return Value::Null,
        }
    }
    Value::Null
}

fn cloud_mcp_default_notification_preferences() -> Value {
    json!({
        "version": 1,
        "push": {
            "uir_prompts": true,
            "terminal_errors": true,
            "loop_run_started": false,
            "loop_run_completed": true,
            "loop_run_failed": true,
            "loop_run_blocked": true,
            "awaiting_device": true,
            "account_events": true,
        },
        "loopspace_overrides": {},
        "updated_at_ms": 0,
    })
}

fn cloud_mcp_sanitize_notification_preferences(value: &Value) -> Option<Value> {
    let source = cloud_mcp_notification_preferences_source(value);
    let source_object = source.as_object()?;
    let has_shape = source_object.contains_key("push")
        || source_object.contains_key("loopspace_overrides")
        || source_object.contains_key("updated_at_ms")
        || source_object.contains_key("version");
    if !has_shape {
        return None;
    }

    let mut object = serde_json::Map::new();
    for (key, entry) in source_object {
        if !cloud_mcp_notification_preferences_top_level_alias(key) {
            object.insert(key.clone(), entry.clone());
        }
    }

    let source_push = source
        .get("push")
        .and_then(Value::as_object)
        .cloned()
        .unwrap_or_default();
    let mut push = serde_json::Map::new();
    for (key, entry) in &source_push {
        if !cloud_mcp_notification_preferences_push_alias(key) {
            push.insert(key.clone(), entry.clone());
        }
    }
    let source_push_value = Value::Object(source_push);
    for (key, aliases, fallback) in [
        ("uir_prompts", ["uir_prompts"], true),
        ("terminal_errors", ["terminal_errors"], true),
        ("loop_run_started", ["loop_run_started"], false),
        ("loop_run_completed", ["loop_run_completed"], true),
        ("loop_run_failed", ["loop_run_failed"], true),
        ("loop_run_blocked", ["loop_run_blocked"], true),
        ("awaiting_device", ["awaiting_device"], true),
        ("account_events", ["account_events"], true),
    ] {
        push.insert(
            key.to_string(),
            json!(cloud_mcp_notification_preferences_bool(
                &source_push_value,
                &aliases,
                fallback,
            )),
        );
    }

    let source_overrides = source
        .get("loopspace_overrides")
        .and_then(Value::as_object)
        .cloned()
        .unwrap_or_default();
    let mut loopspace_overrides = serde_json::Map::new();
    for (loopspace_id, raw_override) in source_overrides {
        let loopspace_id = loopspace_id.trim();
        if loopspace_id.is_empty() {
            continue;
        }
        let Some(source_override) = raw_override.as_object() else {
            continue;
        };
        let mut override_object = serde_json::Map::new();
        for (key, entry) in source_override {
            if !matches!(key.as_str(), "started" | "completed" | "failed" | "blocked") {
                override_object.insert(key.clone(), entry.clone());
            }
        }
        for key in ["started", "completed", "failed", "blocked"] {
            override_object.insert(
                key.to_string(),
                cloud_mcp_notification_override_value(source_override.get(key)),
            );
        }
        loopspace_overrides.insert(loopspace_id.to_string(), Value::Object(override_object));
    }

    object.insert("version".to_string(), json!(1));
    object.insert("push".to_string(), Value::Object(push));
    object.insert(
        "loopspace_overrides".to_string(),
        Value::Object(loopspace_overrides),
    );
    object.insert(
        "updated_at_ms".to_string(),
        json!(cloud_mcp_notification_preferences_timestamp(source)),
    );
    Some(Value::Object(object))
}

fn cloud_mcp_notification_preferences_from_app(app: &AppHandle) -> Value {
    let current = app_local_state_read(app, CLOUD_MCP_NOTIFICATION_PREFERENCES_STATE_KEY);
    let mut preferences = cloud_mcp_sanitize_notification_preferences(&current)
        .unwrap_or_else(cloud_mcp_default_notification_preferences);
    if cloud_mcp_notification_preferences_timestamp(&preferences) > 0
        && !cloud_mcp_notification_preferences_timestamp_is_plausible(
            &preferences,
            cloud_mcp_now_ms(),
        )
    {
        // Old clients could persist an arbitrarily future-stamped snapshot.
        // Treat its timestamp as untrusted so a valid edit can recover instead
        // of leaving the account pinned until that wall clock is reached.
        if let Some(object) = preferences.as_object_mut() {
            object.insert("updated_at_ms".to_string(), json!(0));
        }
    }
    preferences
}

fn cloud_mcp_notification_preferences_write_app(
    app: &AppHandle,
    preferences: &Value,
) -> Result<(), String> {
    app_local_state_write(
        app,
        CLOUD_MCP_NOTIFICATION_PREFERENCES_STATE_KEY,
        preferences,
    )
}

static CLOUD_MCP_NOTIFICATION_PREFERENCES_WRITE_LOCK: OnceLock<StdMutex<()>> = OnceLock::new();

fn cloud_mcp_notification_preferences_write_lock() -> &'static StdMutex<()> {
    CLOUD_MCP_NOTIFICATION_PREFERENCES_WRITE_LOCK.get_or_init(|| StdMutex::new(()))
}

async fn cloud_mcp_notification_preferences_set_runtime_snapshot(
    state: &CloudMcpState,
    preferences: Value,
) {
    let mut snapshots = state.runtime_snapshots.lock().await;
    let should_replace = snapshots
        .notification_preferences
        .as_ref()
        .map(|current| {
            current == &preferences
                || cloud_mcp_notification_preferences_should_apply(current, &preferences)
        })
        .unwrap_or(true);
    if should_replace {
        snapshots.notification_preferences = Some(preferences);
    }
}

fn cloud_mcp_notification_preferences_unit_payload(preferences: &Value, reason: &str) -> Value {
    let device_profile = cloud_mcp_desktop_device_profile();
    let device_id = cloud_mcp_payload_text(&device_profile, &["device_id"])
        .unwrap_or_else(|| "desktop".to_string());
    let content_hash = cloud_mcp_outbox_payload_hash(&json!({
        "device_id": device_id,
        "sync_unit": "notification_preferences",
        "notification_preferences": preferences,
    }));
    json!({
        "source": "rust-diffforge-device-live-unit",
        "reason": reason,
        "event_kind": "device_notification_preferences",
        "sync_unit": "notification_preferences",
        "sync_content_hash": content_hash,
        "device_id": device_id.clone(),
        "device": {
            "id": device_id,
            "name": device_profile["device_name"].clone(),
            "host": device_profile["machine_name"].clone(),
            "os": device_profile["platform"].clone(),
            "platform": device_profile["platform"].clone(),
            "kind": device_profile["form_factor"].clone(),
            "native": true,
            "web": false,
            "connected": true,
        },
        "notification_preferences": preferences.clone(),
    })
}

async fn cloud_mcp_publish_notification_preferences_unit(
    state: &CloudMcpState,
    preferences: &Value,
    reason: &str,
) -> Result<Value, String> {
    cloud_mcp_sync_device_live_unit_event(
        state,
        "device_notification_preferences",
        cloud_mcp_notification_preferences_unit_payload(preferences, reason),
    )
    .await
}

fn cloud_mcp_notification_preferences_consider_candidate(
    latest: &mut Option<Value>,
    candidate: &Value,
    now_ms: u64,
) {
    let Some(preferences) = cloud_mcp_sanitize_notification_preferences(candidate) else {
        return;
    };
    let Some(candidate_rank) = cloud_mcp_notification_preferences_rank(&preferences, now_ms) else {
        return;
    };
    let should_replace = latest
        .as_ref()
        .map(|current| {
            cloud_mcp_notification_preferences_rank(current, now_ms)
                .map(|current_rank| candidate_rank > current_rank)
                .unwrap_or(true)
        })
        .unwrap_or(true);
    if should_replace {
        *latest = Some(preferences);
    }
}

fn cloud_mcp_notification_preferences_from_account_live_state_at(
    value: &Value,
    now_ms: u64,
) -> Option<Value> {
    let live = cloud_mcp_account_live_state_from_value(value).unwrap_or_else(|| value.clone());
    let mut latest: Option<Value> = None;
    for candidate in [
        live.get("notification_preferences"),
        live.pointer("/data/notification_preferences"),
    ]
    .into_iter()
    .flatten()
    {
        cloud_mcp_notification_preferences_consider_candidate(&mut latest, candidate, now_ms);
    }

    let devices = live.get("devices").or_else(|| live.get("device_map"));
    match devices {
        Some(Value::Object(map)) => {
            for device in map.values() {
                for candidate in [device.get("notification_preferences")]
                    .into_iter()
                    .flatten()
                {
                    cloud_mcp_notification_preferences_consider_candidate(
                        &mut latest,
                        candidate,
                        now_ms,
                    );
                }
            }
        }
        Some(Value::Array(items)) => {
            for device in items {
                for candidate in [device.get("notification_preferences")]
                    .into_iter()
                    .flatten()
                {
                    cloud_mcp_notification_preferences_consider_candidate(
                        &mut latest,
                        candidate,
                        now_ms,
                    );
                }
            }
        }
        _ => {}
    }
    latest
}

fn cloud_mcp_notification_preferences_from_account_live_state(value: &Value) -> Option<Value> {
    cloud_mcp_notification_preferences_from_account_live_state_at(value, cloud_mcp_now_ms())
}

fn cloud_mcp_is_notification_preferences_sync_unit_event(event_kind: &str, event: &Value) -> bool {
    if event_kind
        .trim()
        .eq_ignore_ascii_case("device_notification_preferences")
    {
        return true;
    }
    cloud_mcp_payload_text(event, &["sync_unit"])
        .map(|sync_unit| {
            sync_unit
                .trim()
                .eq_ignore_ascii_case("notification_preferences")
        })
        .unwrap_or(false)
}

fn cloud_mcp_notification_preferences_fingerprint(value: &Value) -> String {
    let normalized = cloud_mcp_sanitize_notification_preferences(value)
        .unwrap_or_else(cloud_mcp_default_notification_preferences);
    cloud_mcp_outbox_payload_hash(&normalized)
}

fn cloud_mcp_notification_preferences_rank(value: &Value, now_ms: u64) -> Option<(u64, String)> {
    if !cloud_mcp_notification_preferences_timestamp_is_plausible(value, now_ms) {
        return None;
    }
    Some((
        cloud_mcp_notification_preferences_timestamp(value),
        cloud_mcp_notification_preferences_fingerprint(value),
    ))
}

fn cloud_mcp_notification_preferences_should_apply_at(
    current: &Value,
    incoming: &Value,
    now_ms: u64,
) -> bool {
    let Some(incoming_rank) = cloud_mcp_notification_preferences_rank(incoming, now_ms) else {
        return false;
    };
    cloud_mcp_notification_preferences_rank(current, now_ms)
        .map(|current_rank| incoming_rank > current_rank)
        .unwrap_or(true)
}

fn cloud_mcp_notification_preferences_should_apply(current: &Value, incoming: &Value) -> bool {
    cloud_mcp_notification_preferences_should_apply_at(current, incoming, cloud_mcp_now_ms())
}

fn cloud_mcp_notification_preferences_authoritative_local_timestamp(
    current: &Value,
    now_ms: u64,
) -> u64 {
    let max_timestamp = now_ms.saturating_add(CLOUD_MCP_NOTIFICATION_PREFERENCES_MAX_CLOCK_SKEW_MS);
    let current_timestamp =
        if cloud_mcp_notification_preferences_timestamp_is_plausible(current, now_ms) {
            cloud_mcp_notification_preferences_timestamp(current)
        } else {
            0
        };
    now_ms
        .max(current_timestamp.saturating_add(1))
        .min(max_timestamp)
}

async fn cloud_mcp_apply_notification_preferences_from_account_live_state_inner<F>(
    state: &CloudMcpState,
    event: &Value,
    current: Value,
    mut write_preferences: F,
) -> Option<Value>
where
    F: FnMut(&Value) -> bool,
{
    let preferences = cloud_mcp_notification_preferences_from_account_live_state(event)?;
    if !cloud_mcp_notification_preferences_should_apply(&current, &preferences) {
        return None;
    }
    if !write_preferences(&preferences) {
        return None;
    }
    cloud_mcp_notification_preferences_set_runtime_snapshot(state, preferences.clone()).await;
    Some(preferences)
}

async fn cloud_mcp_apply_notification_preferences_from_account_live_state(
    app: &AppHandle,
    state: &CloudMcpState,
    event: &Value,
) {
    let Some(preferences) = cloud_mcp_notification_preferences_from_account_live_state(event)
    else {
        return;
    };
    let applied = {
        let Ok(_write_guard) = cloud_mcp_notification_preferences_write_lock().lock() else {
            return;
        };
        let current = cloud_mcp_notification_preferences_from_app(app);
        cloud_mcp_notification_preferences_should_apply(&current, &preferences)
            && cloud_mcp_notification_preferences_write_app(app, &preferences).is_ok()
    };
    if !applied {
        return;
    }
    cloud_mcp_notification_preferences_set_runtime_snapshot(state, preferences.clone()).await;
    let _ = app.emit(
        CLOUD_MCP_NOTIFICATION_PREFERENCES_CHANGED_EVENT,
        json!({
            "preferences": preferences,
            "reason": "account_device_live_state_snapshot",
            "source": "cloud",
        }),
    );
}

#[tauri::command(rename_all = "snake_case")]
async fn cloud_mcp_get_notification_preferences(
    app: AppHandle,
    state: State<'_, CloudMcpState>,
) -> Result<Value, String> {
    let preferences = cloud_mcp_notification_preferences_from_app(&app);
    if cloud_mcp_notification_preferences_timestamp(&preferences) > 0 {
        cloud_mcp_notification_preferences_set_runtime_snapshot(state.inner(), preferences.clone())
            .await;
    }
    Ok(json!({
        "ok": true,
        "contract": "diffforge.notification_prefs.v1",
        "preferences": preferences.clone(),
        "notification_preferences": preferences,
    }))
}

#[tauri::command(rename_all = "snake_case")]
async fn cloud_mcp_set_notification_preferences(
    app: AppHandle,
    state: State<'_, CloudMcpState>,
    preferences: Value,
    reason: Option<String>,
) -> Result<Value, String> {
    let now_ms = cloud_mcp_now_ms();
    let mut preferences = cloud_mcp_sanitize_notification_preferences(&preferences)
        .unwrap_or_else(cloud_mcp_default_notification_preferences);
    {
        let _write_guard = cloud_mcp_notification_preferences_write_lock()
            .lock()
            .map_err(|_| "Notification preference write state is unavailable.".to_string())?;
        let current = cloud_mcp_notification_preferences_from_app(&app);
        let authoritative_timestamp =
            cloud_mcp_notification_preferences_authoritative_local_timestamp(&current, now_ms);
        if let Some(object) = preferences.as_object_mut() {
            // Client wall clocks are advisory only. The desktop serializes
            // writes and assigns a bounded authoritative timestamp so a
            // future-stamped client cannot pin every other device's edits.
            object.insert("updated_at_ms".to_string(), json!(authoritative_timestamp));
        }
        cloud_mcp_notification_preferences_write_app(&app, &preferences)?;
    }
    cloud_mcp_notification_preferences_set_runtime_snapshot(state.inner(), preferences.clone())
        .await;
    let reason = reason
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| "notification_preferences_changed".to_string());
    let _ = app.emit(
        CLOUD_MCP_NOTIFICATION_PREFERENCES_CHANGED_EVENT,
        json!({
            "preferences": preferences.clone(),
            "reason": reason.clone(),
            "source": "local",
        }),
    );
    let sync_result =
        cloud_mcp_publish_notification_preferences_unit(state.inner(), &preferences, &reason)
            .await?;
    Ok(json!({
        "ok": true,
        "contract": "diffforge.notification_prefs.v1",
        "preferences": preferences,
        "event_kind": "device_notification_preferences",
        "sync": sync_result,
        "reason": reason,
    }))
}

#[tauri::command(rename_all = "snake_case")]
