fn cloud_mcp_desktop_device_profile() -> Value {
    static DEVICE_PROFILE: OnceLock<Value> = OnceLock::new();
    let mut profile = DEVICE_PROFILE
        .get_or_init(|| {
            let platform = cloud_mcp_desktop_platform();
            let device_name = cloud_mcp_desktop_device_name();
            let device_id = cloud_mcp_stable_desktop_device_id(&device_name, platform);
            let (device_key_id, device_public_key) =
                cloud_mcp_stable_desktop_device_key_metadata(&device_id);
            let push_key_metadata = agent_account_push_public_key_metadata().ok();
            let push_public_key = push_key_metadata
                .as_ref()
                .map(|metadata| metadata.public_key_b64.clone())
                .unwrap_or_default();
            let push_key_algorithm = push_key_metadata
                .as_ref()
                .map(|metadata| metadata.algorithm.clone())
                .unwrap_or_else(|| AGENT_ACCOUNT_PUSH_SEALED_ALGORITHM.to_string());
            let push_capable = push_key_metadata.is_some() && !push_public_key.is_empty();
            json!({
                    "device_id": device_id,
                    "device_name": device_name,
                    "machine_name": device_name,
                    "hostname": device_name,
                "device_key_id": device_key_id,
                "device_public_key": device_public_key,
                "device_key_algorithm": "sha256-local-anchor-v1",
                "push_capable": push_capable,
                "push_public_key": push_public_key,
                "push_key_algorithm": push_key_algorithm,
                    "platform": platform,
                    "os": platform,
                    "architecture": env::consts::ARCH,
                    "app_version": env!("CARGO_PKG_VERSION"),
                    "build_channel": if cfg!(debug_assertions) { "dev" } else { "stable" },
                    "form_factor": "desktop",
                    "device_type": "pc",
                    "client_kind": "client",
                    "client_type": "rust_desktop",
                    "connection_source": "rust-diffforge",
            })
        })
        .clone();
    desktop_auth_apply_provisioning_profile_correlation(&mut profile);
    profile
}

fn cloud_mcp_start_local_device_bridge() {
    if CLOUD_MCP_LOCAL_DEVICE_BRIDGE_STARTED.swap(true, Ordering::SeqCst) {
        return;
    }

    tauri::async_runtime::spawn(async {
        if let Err(error) = cloud_mcp_local_device_bridge_loop().await {
            eprintln!("Diff Forge local device bridge stopped: {error}");
        }
    });
}

async fn cloud_mcp_local_device_bridge_loop() -> Result<(), String> {
    let listener = TcpListener::bind(("127.0.0.1", DIFFFORGE_LOCAL_DEVICE_BRIDGE_PORT))
        .await
        .map_err(|error| {
            CLOUD_MCP_LOCAL_DEVICE_BRIDGE_STARTED.store(false, Ordering::SeqCst);
            format!(
                "unable to bind 127.0.0.1:{}: {error}",
                DIFFFORGE_LOCAL_DEVICE_BRIDGE_PORT
            )
        })?;

    loop {
        let (stream, _) = listener
            .accept()
            .await
            .map_err(|error| format!("unable to accept local bridge request: {error}"))?;
        tauri::async_runtime::spawn(async move {
            let _ = cloud_mcp_handle_local_device_bridge_request(stream).await;
        });
    }
}

async fn cloud_mcp_handle_local_device_bridge_request(mut stream: TcpStream) -> Result<(), String> {
    let Some(request) = cloud_mcp_read_local_bridge_http_request(&mut stream).await else {
        return cloud_mcp_write_local_bridge_response(
            &mut stream,
            400,
            None,
            json!({
                "ok": false,
                "error": "invalid_request",
            }),
        )
        .await;
    };

    let origin = request
        .headers
        .get("origin")
        .map(String::as_str)
        .unwrap_or("");
    let allowed_origin = cloud_mcp_local_bridge_allowed_origin(origin);
    if request.method == "OPTIONS" {
        return cloud_mcp_write_local_bridge_preflight(&mut stream, allowed_origin).await;
    }

    if request.method != "POST" || request.path != DIFFFORGE_LOCAL_DEVICE_BRIDGE_PATH {
        return cloud_mcp_write_local_bridge_response(
            &mut stream,
            404,
            allowed_origin,
            json!({
                "ok": false,
                "error": "not_found",
            }),
        )
        .await;
    }

    if allowed_origin.is_none() {
        return cloud_mcp_write_local_bridge_response(
            &mut stream,
            403,
            None,
            json!({
                "ok": false,
                "error": "origin_not_allowed",
            }),
        )
        .await;
    }

    let body: Value = serde_json::from_slice(&request.body).unwrap_or(Value::Null);
    let nonce = cloud_mcp_payload_text(&body, &["nonce"])
        .filter(|value| value.len() <= 160)
        .unwrap_or_else(|| uuid::Uuid::new_v4().to_string());
    let web_device_id = cloud_mcp_payload_text(&body, &["web_device_id", "device_id"])
        .filter(|value| value.len() <= 180)
        .unwrap_or_else(|| "dashboard-web".to_string());
    let web_session_id = cloud_mcp_payload_text(&body, &["web_session_id", "session_id"])
        .filter(|value| value.len() <= 180)
        .unwrap_or_default();

    let proof = cloud_mcp_local_device_bridge_proof(&nonce, &web_device_id, &web_session_id);
    cloud_mcp_write_local_bridge_response(
        &mut stream,
        200,
        allowed_origin,
        json!({
            "ok": true,
            "contract": "diffforge.local_device_bridge.v1",
            "bridge_port": DIFFFORGE_LOCAL_DEVICE_BRIDGE_PORT,
            "proof": proof,
        }),
    )
    .await
}

fn cloud_mcp_local_device_bridge_proof(
    nonce: &str,
    web_device_id: &str,
    web_session_id: &str,
) -> Value {
    let device_profile = cloud_mcp_desktop_device_profile();
    let native_device_id = cloud_mcp_payload_text(&device_profile, &["device_id", "machine_id"])
        .unwrap_or_else(|| "rust-diffforge-desktop".to_string());
    let native_device_name =
        cloud_mcp_payload_text(&device_profile, &["device_name", "machine_name"])
            .unwrap_or_else(|| "Diff Forge desktop".to_string());
    let device_key_id =
        cloud_mcp_payload_text(&device_profile, &["device_key_id"]).unwrap_or_default();
    let device_public_key =
        cloud_mcp_payload_text(&device_profile, &["device_public_key"]).unwrap_or_default();
    let issued_at_ms = cloud_mcp_now_ms();
    let expires_at_ms = issued_at_ms.saturating_add(DIFFFORGE_LOCAL_DEVICE_BRIDGE_PROOF_TTL_MS);
    let signature = cloud_mcp_local_device_bridge_signature(
        &native_device_id,
        &device_key_id,
        &device_public_key,
        web_device_id,
        web_session_id,
        nonce,
        issued_at_ms,
        expires_at_ms,
        DIFFFORGE_LOCAL_DEVICE_BRIDGE_PORT,
    );
    let (billing_scope_type, team_id) = cloud_mcp_process_account_scope();

    json!({
        "v": 1,
        "contract": "diffforge.local_device_bridge.v1",
        "source": "rust-diffforge",
        "bridge_port": DIFFFORGE_LOCAL_DEVICE_BRIDGE_PORT,
        "nonce": nonce,
        "issued_at_ms": issued_at_ms,
        "expires_at_ms": expires_at_ms,
        "native_device_id": native_device_id,
        "native_device_name": native_device_name,
        "device_key_id": device_key_id,
        "device_public_key": device_public_key,
        "device_key_algorithm": "sha256-local-anchor-v1",
        "platform": device_profile["platform"].clone(),
        "form_factor": device_profile["form_factor"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "client_type": device_profile["client_type"].clone(),
        "connection_source": device_profile["connection_source"].clone(),
        "billing_scope_type": billing_scope_type,
        "team_id": team_id,
        "web_device_id": web_device_id,
        "web_session_id": web_session_id,
        "signature_algorithm": "sha256-local-bridge-v1",
        "signature": signature,
    })
}

fn cloud_mcp_local_device_bridge_signature(
    native_device_id: &str,
    device_key_id: &str,
    device_public_key: &str,
    web_device_id: &str,
    web_session_id: &str,
    nonce: &str,
    issued_at_ms: u64,
    expires_at_ms: u64,
    bridge_port: u16,
) -> String {
    let digest = Sha256::digest(
        format!(
            "diffforge-local-device-proof-v1\n{native_device_id}\n{device_key_id}\n{device_public_key}\n{web_device_id}\n{web_session_id}\n{nonce}\n{issued_at_ms}\n{expires_at_ms}\n{bridge_port}"
        )
        .as_bytes(),
    );
    format!("{digest:x}")
}

struct CloudMcpLocalBridgeRequest {
    method: String,
    path: String,
    headers: HashMap<String, String>,
    body: Vec<u8>,
}

async fn cloud_mcp_read_local_bridge_http_request(
    stream: &mut TcpStream,
) -> Option<CloudMcpLocalBridgeRequest> {
    let mut buffer = Vec::with_capacity(2048);
    let mut chunk = [0_u8; 2048];
    let mut header_end = None;

    loop {
        let read = stream.read(&mut chunk).await.ok()?;
        if read == 0 {
            break;
        }
        buffer.extend_from_slice(&chunk[..read]);
        if buffer.len() > DIFFFORGE_LOCAL_DEVICE_BRIDGE_MAX_REQUEST_BYTES {
            return None;
        }
        if header_end.is_none() {
            header_end = buffer.windows(4).position(|window| window == b"\r\n\r\n");
        }
        if let Some(end) = header_end {
            let content_length = cloud_mcp_local_bridge_content_length(&buffer[..end])?;
            let expected_len = end.saturating_add(4).saturating_add(content_length);
            if buffer.len() >= expected_len {
                break;
            }
        }
    }

    let header_end = header_end?;
    let header_text = String::from_utf8_lossy(&buffer[..header_end]);
    let mut lines = header_text.lines();
    let request_line = lines.next()?.trim();
    let mut request_parts = request_line.split_whitespace();
    let method = request_parts.next()?.to_ascii_uppercase();
    let path = request_parts
        .next()
        .unwrap_or("/")
        .split('?')
        .next()
        .unwrap_or("/")
        .to_string();
    let mut headers = HashMap::new();
    for line in lines {
        let Some((name, value)) = line.split_once(':') else {
            continue;
        };
        headers.insert(name.trim().to_ascii_lowercase(), value.trim().to_string());
    }
    let content_length = headers
        .get("content-length")
        .and_then(|value| value.parse::<usize>().ok())
        .unwrap_or(0)
        .min(DIFFFORGE_LOCAL_DEVICE_BRIDGE_MAX_REQUEST_BYTES);
    let body_start = header_end.saturating_add(4);
    let body_end = body_start.saturating_add(content_length).min(buffer.len());
    Some(CloudMcpLocalBridgeRequest {
        method,
        path,
        headers,
        body: buffer[body_start..body_end].to_vec(),
    })
}

fn cloud_mcp_local_bridge_content_length(header_bytes: &[u8]) -> Option<usize> {
    let header_text = String::from_utf8_lossy(header_bytes);
    for line in header_text.lines().skip(1) {
        let Some((name, value)) = line.split_once(':') else {
            continue;
        };
        if name.trim().eq_ignore_ascii_case("content-length") {
            return value
                .trim()
                .parse::<usize>()
                .ok()
                .filter(|value| *value <= DIFFFORGE_LOCAL_DEVICE_BRIDGE_MAX_REQUEST_BYTES);
        }
    }
    Some(0)
}

fn cloud_mcp_local_bridge_allowed_origin(origin: &str) -> Option<String> {
    let trimmed = origin.trim();
    if trimmed.is_empty() || trimmed.len() > 256 {
        return None;
    }
    let lower = trimmed.to_ascii_lowercase();
    if lower.starts_with("http://localhost:")
        || lower.starts_with("http://127.0.0.1:")
        || lower.starts_with("http://[::1]:")
    {
        return Some(trimmed.to_string());
    }

    let Some(rest) = lower.strip_prefix("https://") else {
        return None;
    };
    let host = rest
        .split('/')
        .next()
        .unwrap_or_default()
        .split(':')
        .next()
        .unwrap_or_default();
    if host == "diffforge.ai" || host.ends_with(".diffforge.ai") {
        Some(trimmed.to_string())
    } else {
        None
    }
}

async fn cloud_mcp_write_local_bridge_preflight(
    stream: &mut TcpStream,
    allowed_origin: Option<String>,
) -> Result<(), String> {
    let status = if allowed_origin.is_some() { 204 } else { 403 };
    let origin_header = allowed_origin
        .as_ref()
        .map(|origin| format!("Access-Control-Allow-Origin: {origin}\r\n"))
        .unwrap_or_default();
    let response = format!(
        "HTTP/1.1 {status} {}\r\n{origin_header}Access-Control-Allow-Methods: POST, OPTIONS\r\nAccess-Control-Allow-Headers: Content-Type, X-DiffForge-Bridge\r\nAccess-Control-Allow-Private-Network: true\r\nAccess-Control-Max-Age: 300\r\nVary: Origin\r\nContent-Length: 0\r\nConnection: close\r\n\r\n",
        if status == 204 {
            "No Content"
        } else {
            "Forbidden"
        },
    );
    stream
        .write_all(response.as_bytes())
        .await
        .map_err(|error| format!("unable to write bridge preflight: {error}"))
}

async fn cloud_mcp_write_local_bridge_response(
    stream: &mut TcpStream,
    status: u16,
    allowed_origin: Option<String>,
    body: Value,
) -> Result<(), String> {
    let reason = match status {
        200 => "OK",
        400 => "Bad Request",
        403 => "Forbidden",
        404 => "Not Found",
        _ => "Internal Server Error",
    };
    let body = serde_json::to_vec(&body).unwrap_or_else(|_| b"{\"ok\":false}".to_vec());
    let origin_header = allowed_origin
        .as_ref()
        .map(|origin| format!("Access-Control-Allow-Origin: {origin}\r\n"))
        .unwrap_or_default();
    let response = format!(
        "HTTP/1.1 {status} {reason}\r\n{origin_header}Access-Control-Allow-Private-Network: true\r\nVary: Origin\r\nContent-Type: application/json\r\nContent-Length: {}\r\nConnection: close\r\n\r\n",
        body.len(),
    );
    stream
        .write_all(response.as_bytes())
        .await
        .map_err(|error| format!("unable to write bridge response headers: {error}"))?;
    stream
        .write_all(&body)
        .await
        .map_err(|error| format!("unable to write bridge response body: {error}"))
}

#[tauri::command(rename_all = "snake_case")]
async fn cloud_mcp_get_desktop_device_profile() -> Result<Value, String> {
    Ok(cloud_mcp_desktop_device_profile())
}

fn cloud_mcp_stable_desktop_device_id(device_name: &str, platform: &str) -> String {
    if let Some(path) = cloud_mcp_desktop_device_id_path() {
        if let Ok(existing) = fs::read_to_string(&path) {
            let trimmed = existing.trim();
            if cloud_mcp_valid_device_id(trimmed) {
                return trimmed.to_string();
            }
        }

        let generated = format!("{}-{}", platform, uuid::Uuid::new_v4());
        if let Some(parent) = path.parent() {
            let _ = fs::create_dir_all(parent);
        }
        if fs::write(&path, generated.as_bytes()).is_ok() {
            return generated;
        }
    }

    cloud_mcp_desktop_device_id(device_name, platform)
}

fn cloud_mcp_desktop_device_id_path() -> Option<PathBuf> {
    cloud_mcp_local_data_file_path(CLOUD_MCP_DEVICE_ID_FILE)
}

fn cloud_mcp_desktop_device_key_path() -> Option<PathBuf> {
    cloud_mcp_local_data_file_path(CLOUD_MCP_DEVICE_KEY_FILE)
}

fn cloud_mcp_valid_device_secret(value: &str) -> bool {
    let trimmed = value.trim();
    (24..=200).contains(&trimmed.len())
        && trimmed.chars().all(|character| {
            character.is_ascii_alphanumeric() || matches!(character, '-' | '_' | '.')
        })
}

fn cloud_mcp_stable_desktop_device_secret(device_id: &str) -> String {
    if let Some(path) = cloud_mcp_desktop_device_key_path() {
        if let Ok(existing) = fs::read_to_string(&path) {
            let trimmed = existing.trim();
            if cloud_mcp_valid_device_secret(trimmed) {
                return trimmed.to_string();
            }
        }

        let generated = format!("native-key-{}-{}", device_id, uuid::Uuid::new_v4());
        if let Some(parent) = path.parent() {
            let _ = fs::create_dir_all(parent);
        }
        if fs::write(&path, generated.as_bytes()).is_ok() {
            return generated;
        }
    }

    format!(
        "native-key-fallback-{}-{}",
        device_id,
        cloud_mcp_short_hash(device_id)
    )
}

fn cloud_mcp_stable_desktop_device_key_metadata(device_id: &str) -> (String, String) {
    let secret = cloud_mcp_stable_desktop_device_secret(device_id);
    cloud_mcp_desktop_device_key_metadata_for_secret(device_id, &secret)
}

fn cloud_mcp_desktop_device_key_metadata_for_secret(
    device_id: &str,
    secret: &str,
) -> (String, String) {
    let digest = Sha256::digest(
        format!("diffforge-native-device-anchor-v1:{device_id}:{secret}").as_bytes(),
    );
    let public_key = format!("{digest:x}");
    let key_id_suffix = public_key.chars().take(24).collect::<String>();
    (format!("df-native-key-{key_id_suffix}"), public_key)
}

fn cloud_mcp_valid_device_id(value: &str) -> bool {
    let trimmed = value.trim();
    !trimmed.is_empty()
        && trimmed.len() <= 120
        && trimmed
            .chars()
            .all(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '-' | '_' | '.'))
}

fn cloud_mcp_desktop_platform() -> &'static str {
    if cfg!(target_os = "macos") {
        "macos"
    } else if cfg!(target_os = "windows") {
        "windows"
    } else if cfg!(target_os = "linux") {
        "linux"
    } else if cfg!(target_os = "ios") {
        "ios"
    } else if cfg!(target_os = "android") {
        "android"
    } else {
        "unknown"
    }
}

fn cloud_mcp_desktop_device_name() -> String {
    cloud_mcp_platform_device_name()
        .or_else(sysinfo::System::host_name)
        .or_else(|| env::var("COMPUTERNAME").ok())
        .or_else(|| env::var("HOSTNAME").ok())
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| "Diff Forge Desktop".to_string())
        .chars()
        .filter(|ch| !ch.is_control())
        .take(80)
        .collect()
}

fn cloud_mcp_platform_device_name() -> Option<String> {
    if cfg!(target_os = "macos") {
        cloud_mcp_device_name_from_command("scutil", &["--get", "ComputerName"])
    } else {
        None
    }
}

fn cloud_mcp_device_name_from_command(command: &str, args: &[&str]) -> Option<String> {
    Command::new(command)
        .args(args)
        .output()
        .ok()
        .filter(|output| output.status.success())
        .and_then(|output| String::from_utf8(output.stdout).ok())
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
}

fn cloud_mcp_desktop_device_id(device_name: &str, platform: &str) -> String {
    let mut hasher = Sha1::new();
    hasher.update(platform.as_bytes());
    hasher.update(b":");
    hasher.update(device_name.as_bytes());
    let digest = hasher.finalize();
    let fingerprint = digest
        .iter()
        .take(8)
        .map(|byte| format!("{byte:02x}"))
        .collect::<String>();
    format!("{}-{}", platform, fingerprint)
}

fn cloud_mcp_device_id_match_key(value: &str) -> String {
    let trimmed = value.trim();
    if trimmed.is_empty() {
        return String::new();
    }
    let cleaned = trimmed
        .chars()
        .map(|ch| {
            if ch.is_ascii_alphanumeric() || matches!(ch, '-' | '_' | '.') {
                ch
            } else {
                '_'
            }
        })
        .collect::<String>();
    let cleaned = cleaned.trim_matches(['.', '_', '-']);
    if cleaned.is_empty() {
        "dev-client".to_string()
    } else {
        cleaned
            .chars()
            .take(96)
            .collect::<String>()
            .to_ascii_lowercase()
    }
}

fn cloud_mcp_workspace_id_match_key(value: &str) -> String {
    cloud_mcp_workspace_id_match_key_for_platform(value, cloud_mcp_desktop_platform())
}

fn cloud_mcp_platform_is_windows(platform: &str) -> bool {
    let platform = platform.trim().to_ascii_lowercase();
    matches!(platform.as_str(), "windows" | "win32" | "win64") || platform.starts_with("windows ")
}

fn cloud_mcp_workspace_id_match_key_for_platform(value: &str, platform: &str) -> String {
    // Workspace match keys trim surrounding whitespace. Windows paths then
    // convert backslashes to '/', strip a leading '//?/' device prefix, restore
    // 'UNC/' to '//', remove a leading slash before drive roots, collapse
    // repeated slashes, drop trailing slashes except drive roots, and lowercase.
    // Non-Windows keys only trim and drop trailing slashes; they keep case.
    let raw = value.trim();
    let windows_path = cloud_mcp_platform_is_windows(platform);
    let mut normalized = if windows_path {
        raw.replace('\\', "/")
    } else {
        raw.to_string()
    };
    if normalized.is_empty() {
        return normalized;
    }
    if windows_path {
        if let Some(stripped) = normalized.strip_prefix("//?/") {
            normalized = stripped.to_string();
        }
        if normalized
            .get(..4)
            .map(|prefix| prefix.eq_ignore_ascii_case("UNC/"))
            .unwrap_or(false)
        {
            normalized = format!("//{}", &normalized[4..]);
        }
        if normalized.starts_with('/')
            && normalized
                .as_bytes()
                .get(1..3)
                .map(|slice| slice.len() == 2 && slice[0].is_ascii_alphabetic() && slice[1] == b':')
                .unwrap_or(false)
        {
            normalized.remove(0);
        }
        while normalized.contains("//") {
            normalized = normalized.replace("//", "/");
        }
    }
    let drive_root = normalized.len() == 3
        && normalized.as_bytes()[0].is_ascii_alphabetic()
        && normalized.as_bytes()[1] == b':'
        && normalized.as_bytes()[2] == b'/';
    if normalized.len() > 1 && !drive_root {
        normalized = normalized.trim_end_matches('/').to_string();
    }
    if windows_path {
        normalized.to_lowercase()
    } else {
        normalized
    }
}

fn cloud_mcp_workspace_platform_hint(value: &Value, fallback: &str) -> String {
    if let Some(platform) =
        cloud_mcp_payload_text(value, &["device_platform", "platform", "os", "system"])
    {
        return platform;
    }
    for key in ["device", "payload", "request", "state"] {
        let Some(nested) = value.get(key) else {
            continue;
        };
        if let Some(platform) =
            cloud_mcp_payload_text(nested, &["device_platform", "platform", "os", "system"])
        {
            return platform;
        }
    }
    fallback.trim().to_string()
}

fn cloud_mcp_canonical_workspace_id_from_value(
    workspace_id: &str,
    value: &Value,
    fallback_platform: &str,
) -> String {
    let platform = cloud_mcp_workspace_platform_hint(value, fallback_platform);
    cloud_mcp_workspace_id_match_key_for_platform(workspace_id, &platform)
}

fn cloud_mcp_legacy_sanitized_workspace_id(value: &str) -> String {
    let cleaned = value
        .trim()
        .chars()
        .map(|ch| {
            if ch.is_ascii_alphanumeric() || matches!(ch, '-' | '_' | '.') {
                ch
            } else {
                '_'
            }
        })
        .collect::<String>();
    let cleaned = cleaned.trim_matches(['.', '_', '-']);
    if cleaned.is_empty() {
        // Match the deployed cloud sanitizer exactly so legacy tombstones and
        // outbox rows for non-ASCII/separator-only ids remain addressable.
        "dev-client".to_string()
    } else {
        cleaned.chars().take(96).collect()
    }
}

fn cloud_mcp_workspace_id_matches_canonical_or_legacy(
    candidate_id: &str,
    stored_id: &str,
    platform: &str,
) -> bool {
    let candidate = cloud_mcp_workspace_id_match_key_for_platform(candidate_id, platform);
    if candidate.is_empty() {
        return false;
    }
    if cloud_mcp_workspace_id_match_key_for_platform(stored_id, platform) == candidate {
        return true;
    }
    let legacy = cloud_mcp_legacy_sanitized_workspace_id(&candidate);
    let canonical_stored = cloud_mcp_workspace_id_match_key_for_platform(stored_id, platform);
    let stored_legacy = cloud_mcp_legacy_sanitized_workspace_id(&canonical_stored);
    if cloud_mcp_platform_is_windows(platform) {
        stored_id.eq_ignore_ascii_case(&legacy) || candidate_id.eq_ignore_ascii_case(&stored_legacy)
    } else {
        stored_id == legacy || candidate_id == stored_legacy
    }
}

fn cloud_mcp_canonicalize_workspace_fields(value: &mut Value, fallback_platform: &str) {
    match value {
        Value::Array(items) => {
            for item in items {
                cloud_mcp_canonicalize_workspace_fields(item, fallback_platform);
            }
        }
        Value::Object(object) => {
            let object_value = Value::Object(object.clone());
            let platform = cloud_mcp_workspace_platform_hint(&object_value, fallback_platform);
            let source_platform =
                cloud_mcp_payload_text(&object_value, &["source_platform", "origin_platform"])
                    .or_else(|| {
                        object_value
                            .get("source_device")
                            .or_else(|| object_value.get("dispatch_source"))
                            .map(|source| cloud_mcp_workspace_platform_hint(source, &platform))
                    })
                    .unwrap_or_else(|| platform.clone());
            let target_platform = cloud_mcp_payload_text(&object_value, &["target_platform"])
                .or_else(|| {
                    object_value
                        .get("target_device")
                        .or_else(|| object_value.get("dispatch_target"))
                        .map(|target| cloud_mcp_workspace_platform_hint(target, &platform))
                })
                .unwrap_or_else(|| platform.clone());
            for key in ["workspace_id", "observer_workspace_id", "w", "wid"] {
                if let Some(Value::String(workspace_id)) = object.get_mut(key) {
                    *workspace_id =
                        cloud_mcp_workspace_id_match_key_for_platform(workspace_id, &platform);
                }
            }
            for key in [
                "source_workspace_id",
                "todo_workspace_id",
                "origin_workspace_id",
                "requested_by_workspace_id",
            ] {
                if let Some(Value::String(workspace_id)) = object.get_mut(key) {
                    *workspace_id = cloud_mcp_workspace_id_match_key_for_platform(
                        workspace_id,
                        &source_platform,
                    );
                }
            }
            for key in ["target_workspace_id"] {
                if let Some(Value::String(workspace_id)) = object.get_mut(key) {
                    *workspace_id = cloud_mcp_workspace_id_match_key_for_platform(
                        workspace_id,
                        &target_platform,
                    );
                }
            }
            for key in ["workspace_ids"] {
                if let Some(Value::Array(ids)) = object.get_mut(key) {
                    for id in ids.iter_mut() {
                        if let Value::String(workspace_id) = id {
                            *workspace_id = cloud_mcp_workspace_id_match_key_for_platform(
                                workspace_id,
                                &platform,
                            );
                        }
                    }
                }
            }
            for (keys, key_platform) in [
                (
                    &["source_workspace_ids", "origin_workspace_ids"][..],
                    source_platform.as_str(),
                ),
                (&["target_workspace_ids"][..], target_platform.as_str()),
            ] {
                for key in keys {
                    if let Some(Value::Array(ids)) = object.get_mut(*key) {
                        for id in ids.iter_mut() {
                            if let Value::String(workspace_id) = id {
                                *workspace_id = cloud_mcp_workspace_id_match_key_for_platform(
                                    workspace_id,
                                    key_platform,
                                );
                            }
                        }
                    }
                }
            }
            for (key, nested) in object.iter_mut() {
                if nested.is_object() || nested.is_array() {
                    let nested_platform = match key.as_str() {
                        "target" | "target_device" | "dispatch_target" => target_platform.as_str(),
                        "source" | "source_device" | "dispatch_source" => source_platform.as_str(),
                        _ => platform.as_str(),
                    };
                    cloud_mcp_canonicalize_workspace_fields(nested, nested_platform);
                }
            }
        }
        _ => {}
    }
}

fn cloud_mcp_resolve_local_workspace_id(requested_workspace_id: &str) -> Option<String> {
    cloud_mcp_resolve_local_workspace_id_for_platform(
        requested_workspace_id,
        cloud_mcp_desktop_platform(),
    )
}

fn cloud_mcp_resolve_local_workspace_id_for_platform(
    requested_workspace_id: &str,
    platform: &str,
) -> Option<String> {
    let requested_key =
        cloud_mcp_workspace_id_match_key_for_platform(requested_workspace_id, platform);
    if requested_key.is_empty() {
        return None;
    }
    cloud_mcp_authoritative_local_workspace_catalog()
        .ok()
        .flatten()?
        .into_iter()
        .find_map(|workspace| {
            let workspace_id = cloud_mcp_payload_text(&workspace, &["workspace_id", "id"])?;
            (cloud_mcp_workspace_id_match_key_for_platform(&workspace_id, platform)
                == requested_key)
                .then_some(workspace_id)
        })
}

/// Read the Rust-owned workspace catalog that backs `local_workspaces_load`.
/// Merely having an in-memory runtime row is not proof that the catalog finished
/// hydrating after startup, so a missing or malformed file deliberately returns
/// `None` and blocks authoritative workspace publication.
fn cloud_mcp_authoritative_local_workspace_catalog() -> Result<Option<Vec<Value>>, String> {
    let path = if let Some(app) = CLOUD_MCP_SYNC_STATUS_APP.get() {
        local_workspace_store_path(app, &cloud_mcp_process_account_scope_key())?
    } else {
        // Daemon/startup paths can run before the AppHandle is registered. Use
        // the same device-data root and scope filename as local_workspaces_load
        // so readiness never depends on a test-only or secondary cache.
        let Some(root) = cloud_mcp_native_data_root() else {
            return Ok(None);
        };
        root.join(DEVICE_WORKSPACE_CATALOG_DIR).join(format!(
            "{}.json",
            local_workspace_scope_file_key(&cloud_mcp_process_account_scope_key())
        ))
    };
    if !path.is_file() {
        return Ok(None);
    }
    let text = fs::read_to_string(&path).map_err(|error| {
        format!("Unable to read authoritative local workspace catalog: {error}")
    })?;
    let value = serde_json::from_str::<Value>(&text).map_err(|error| {
        format!("Unable to parse authoritative local workspace catalog: {error}")
    })?;
    let items = value
        .get("workspaces")
        .and_then(Value::as_array)
        .cloned()
        .ok_or_else(|| {
            "Authoritative local workspace catalog is missing its workspaces array.".to_string()
        })?;
    let deleted_workspace_ids = cloud_mcp_deleted_workspace_ids();
    let platform = cloud_mcp_desktop_platform();
    Ok(Some(
        local_workspace_catalog_visible_items(items)
            .into_iter()
            .filter_map(|mut workspace| {
                if cloud_mcp_workspace_snapshot_is_locally_archived(&workspace) {
                    return None;
                }
                let workspace_id = local_workspace_catalog_entry_id(&workspace)?;
                let canonical_id =
                    cloud_mcp_workspace_id_match_key_for_platform(&workspace_id, platform);
                if canonical_id.is_empty()
                    || deleted_workspace_ids.iter().any(|deleted_id| {
                        cloud_mcp_workspace_id_matches_canonical_or_legacy(
                            &canonical_id,
                            deleted_id,
                            platform,
                        )
                    })
                {
                    return None;
                }
                if let Some(object) = workspace.as_object_mut() {
                    object.insert("workspace_id".to_string(), json!(canonical_id.clone()));
                    object.insert("id".to_string(), json!(canonical_id));
                }
                Some(workspace)
            })
            .collect(),
    ))
}

fn cloud_mcp_overlay_workspace_catalog_rows(
    authoritative: Vec<Value>,
    incoming: &[Value],
) -> Vec<Value> {
    let platform = cloud_mcp_desktop_platform();
    let mut incoming_by_id = HashMap::<String, Value>::new();
    for workspace in incoming {
        let workspace_id =
            cloud_mcp_payload_text(workspace, &["workspace_id", "id"]).unwrap_or_default();
        let key = cloud_mcp_workspace_id_match_key_for_platform(&workspace_id, platform);
        if !key.is_empty() {
            if let Some(existing) = incoming_by_id.get_mut(&key) {
                cloud_mcp_live_state_merge_object(existing, workspace.clone());
            } else {
                incoming_by_id.insert(key, workspace.clone());
            }
        }
    }
    authoritative
        .into_iter()
        .filter_map(|mut workspace| {
            let workspace_id = cloud_mcp_payload_text(&workspace, &["workspace_id", "id"])?;
            let key = cloud_mcp_workspace_id_match_key_for_platform(&workspace_id, platform);
            if let Some(incoming_workspace) = incoming_by_id.get(&key) {
                cloud_mcp_live_state_merge_object(&mut workspace, incoming_workspace.clone());
            }
            Some(workspace)
        })
        .collect()
}

fn cloud_mcp_event_carries_authoritative_workspace_snapshot(event_kind: &str) -> bool {
    matches!(
        event_kind.trim().to_ascii_lowercase().as_str(),
        "device_workspaces_snapshot" | "device_live_state_snapshot"
    )
}

const CLOUD_MCP_AUTHORITATIVE_WORKSPACE_SNAPSHOT_REBUILD_PREFIX: &str =
    "authoritative_workspace_snapshot_rebuild:";

fn cloud_mcp_authoritative_workspace_snapshot_rebuild_reason(error: &str) -> Option<&str> {
    error
        .strip_prefix(CLOUD_MCP_AUTHORITATIVE_WORKSPACE_SNAPSHOT_REBUILD_PREFIX)
        .map(str::trim)
        .filter(|reason| !reason.is_empty())
}

fn cloud_mcp_workspace_membership_keys(workspaces: &[Value]) -> HashSet<String> {
    workspaces
        .iter()
        .filter_map(|workspace| {
            let workspace_id = cloud_mcp_payload_text(workspace, &["workspace_id", "id"])?;
            let key = cloud_mcp_workspace_id_match_key(&workspace_id);
            (!key.is_empty()).then_some(key)
        })
        .collect()
}

/// Reject stale pre-upgrade outbox rows and any future partial producer before
/// bytes reach the websocket. A valid empty catalog is distinguishable from an
/// unhydrated one because the former has a parsed on-disk `workspaces: []`.
fn cloud_mcp_validate_authoritative_workspace_snapshot_payload(
    event_kind: &str,
    payload: &Value,
) -> Result<(), String> {
    if !cloud_mcp_event_carries_authoritative_workspace_snapshot(event_kind) {
        return Ok(());
    }
    let authoritative = cloud_mcp_authoritative_local_workspace_catalog()?
        .ok_or_else(|| "workspace_catalog_not_ready".to_string())?;
    let expected = cloud_mcp_workspace_membership_keys(&authoritative);
    let actual = cloud_mcp_workspace_membership_keys(
        payload
            .get("workspaces")
            .and_then(Value::as_array)
            .map(Vec::as_slice)
            .unwrap_or(&[]),
    );
    let complete = cloud_mcp_payload_bool(payload, &["workspace_snapshot_complete"], false)
        || cloud_mcp_payload_bool(payload, &["workspace_catalog_complete"], false);
    if !complete || actual != expected {
        return Err("workspace_catalog_snapshot_superseded".to_string());
    }
    Ok(())
}

fn cloud_mcp_normalize_lifecycle_workspace(
    mut workspace: Value,
    default_status: &str,
) -> Option<(String, Value)> {
    let workspace_id = cloud_mcp_payload_text(&workspace, &["workspace_id", "id"])?;
    let workspace_key = cloud_mcp_workspace_id_match_key(&workspace_id);
    if workspace_key.is_empty() {
        return None;
    }
    let workspace_name = cloud_mcp_payload_text(&workspace, &["workspace_name", "name"])
        .unwrap_or_else(|| workspace_id.clone());
    let workspace_status = cloud_mcp_payload_text(&workspace, &["workspace_status", "status"])
        .unwrap_or_else(|| default_status.to_string());
    let workspace_active = workspace
        .get("workspace_active")
        .or_else(|| workspace.get("active"))
        .cloned()
        .unwrap_or_else(|| json!(false));
    let workspace_root = cloud_mcp_workspace_root_text(&workspace);
    if let Some(object) = workspace.as_object_mut() {
        object.insert("workspace_id".to_string(), json!(workspace_id));
        object.insert("workspace_name".to_string(), json!(workspace_name));
        object
            .entry("workspace_role".to_string())
            .or_insert_with(|| json!("desktop_workspace"));
        object
            .entry("display_surface".to_string())
            .or_insert_with(|| json!("dashboard_workspace"));
        object.insert("workspace_status".to_string(), json!(workspace_status));
        object.insert("workspace_active".to_string(), workspace_active);
        if let Some(workspace_root) = workspace_root {
            object
                .entry("workspace_root".to_string())
                .or_insert_with(|| json!(workspace_root));
        }
    }
    let source = workspace.clone();
    cloud_mcp_copy_workspace_runtime_ordering(&mut workspace, &source);
    Some((workspace_key, workspace))
}

async fn cloud_mcp_lifecycle_workspaces(state: &CloudMcpState) -> (Vec<Value>, bool) {
    let mut workspaces = Vec::<Value>::new();
    let mut indexes_by_id = HashMap::<String, usize>::new();
    let authoritative_catalog = match cloud_mcp_authoritative_local_workspace_catalog() {
        Ok(catalog) => catalog,
        Err(error) => {
            log_terminal_status_event(
                "backend.cloud_mcp.workspace_catalog.not_ready",
                json!({
                    "reason": "catalog_read_failed",
                    "error": clean_terminal_telemetry_text(&error),
                }),
            );
            None
        }
    };
    let catalog_ready = authoritative_catalog.is_some();
    let authoritative_by_id = authoritative_catalog.as_ref().map(|items| {
        items
            .iter()
            .filter_map(|workspace| {
                let workspace_id = cloud_mcp_payload_text(workspace, &["workspace_id", "id"])?;
                let key = cloud_mcp_workspace_id_match_key(&workspace_id);
                (!key.is_empty()).then_some(key)
            })
            .collect::<HashSet<_>>()
    });

    for workspace in authoritative_catalog.iter().flatten().cloned() {
        let Some((workspace_key, workspace)) =
            cloud_mcp_normalize_lifecycle_workspace(workspace, "registered")
        else {
            continue;
        };
        indexes_by_id.insert(workspace_key, workspaces.len());
        workspaces.push(workspace);
    }

    {
        let snapshots = state.runtime_snapshots.lock().await;
        for snapshot in [
            snapshots.workspace_terminals.as_ref(),
            snapshots.workspace_servers.as_ref(),
            snapshots.workspace_catalog.as_ref(),
        ]
        .into_iter()
        .flatten()
        {
            let Some(items) = snapshot.get("workspaces").and_then(Value::as_array) else {
                continue;
            };
            for workspace in items {
                let Some((workspace_match_id, workspace_value)) =
                    cloud_mcp_normalize_lifecycle_workspace(workspace.clone(), "registered")
                else {
                    continue;
                };
                if authoritative_by_id
                    .as_ref()
                    .is_some_and(|ids| !ids.contains(&workspace_match_id))
                {
                    continue;
                }
                if let Some(index) = indexes_by_id.get(&workspace_match_id).copied() {
                    cloud_mcp_live_state_merge_object(&mut workspaces[index], workspace_value);
                } else {
                    indexes_by_id.insert(workspace_match_id, workspaces.len());
                    workspaces.push(workspace_value);
                }
            }
        }
    }

    let runtime = state.inner.lock().await;
    for workspace in runtime.registered_workspaces.values() {
        let workspace_match_id = cloud_mcp_workspace_id_match_key(&workspace.workspace_id);
        if authoritative_by_id
            .as_ref()
            .is_some_and(|ids| !ids.contains(&workspace_match_id))
            || indexes_by_id.contains_key(&workspace_match_id)
        {
            continue;
        }
        let mut workspace_value = json!({
            "workspace_id": workspace.workspace_id,
            "workspace_name": workspace.workspace_name,
            "workspace_role": "desktop_workspace",
            "display_surface": "dashboard_workspace",
            "workspace_active": false,
            "workspace_status": "registered",
        });
        if !workspace.root.trim().is_empty() {
            if let Some(object) = workspace_value.as_object_mut() {
                object.insert("workspace_root".to_string(), json!(workspace.root.trim()));
            }
        }
        indexes_by_id.insert(workspace_match_id, workspaces.len());
        workspaces.push(workspace_value);
    }

    (workspaces, catalog_ready)
}

fn cloud_mcp_live_state_merge_object(target: &mut Value, incoming: Value) {
    if !target.is_object() || !incoming.is_object() {
        *target = incoming;
        return;
    }
    let target = target.as_object_mut().expect("checked object");
    let incoming = incoming.as_object().expect("checked object");
    let incoming_workspace = Value::Object(incoming.clone());
    for (key, value) in incoming {
        if key == "workspaces" {
            let existing = target.entry(key.clone()).or_insert_with(|| json!({}));
            cloud_mcp_live_state_merge_object(existing, value.clone());
        } else if key == "terminals" || key == "panels" || key == "mcps" || key == "cli_states" {
            if key == "terminals" {
                let incoming_terminals_empty = cloud_mcp_live_state_values(Some(value)).is_empty();
                let existing_terminals_non_empty = target
                    .get(key)
                    .map(|terminals| !cloud_mcp_live_state_values(Some(terminals)).is_empty())
                    .unwrap_or(false);
                let workspace_active =
                    cloud_mcp_workspace_explicit_active_state(&incoming_workspace).unwrap_or(true);
                let requested_terminal_clear_reason =
                    cloud_mcp_payload_text(&incoming_workspace, &["terminal_clear_reason"])
                        .unwrap_or_default();
                let empty_authoritative = (cloud_mcp_payload_bool(
                    &incoming_workspace,
                    &["terminal_list_empty_authoritative"],
                    false,
                ))
                    && cloud_mcp_workspace_inactive_terminal_empty_clear_is_explicit(
                        &incoming_workspace,
                        "",
                        &requested_terminal_clear_reason,
                        workspace_active,
                    );
                if incoming_terminals_empty
                    && (existing_terminals_non_empty || !empty_authoritative)
                    && !empty_authoritative
                {
                    continue;
                }
            }
            if key == "panels" {
                let incoming_panels_empty = cloud_mcp_live_state_values(Some(value)).is_empty();
                let existing_panels_non_empty = target
                    .get(key)
                    .map(|panels| !cloud_mcp_live_state_values(Some(panels)).is_empty())
                    .unwrap_or(false);
                let workspace_active =
                    cloud_mcp_workspace_explicit_active_state(&incoming_workspace).unwrap_or(true);
                let requested_panel_clear_reason =
                    cloud_mcp_payload_text(&incoming_workspace, &["panel_clear_reason"])
                        .unwrap_or_default();
                let empty_authoritative = (cloud_mcp_payload_bool(
                    &incoming_workspace,
                    &["panel_list_empty_authoritative"],
                    false,
                )) && cloud_mcp_workspace_panel_empty_clear_is_explicit(
                    &incoming_workspace,
                    "",
                    &requested_panel_clear_reason,
                    workspace_active,
                );
                if incoming_panels_empty
                    && (existing_panels_non_empty || !empty_authoritative)
                    && !empty_authoritative
                {
                    continue;
                }
            }
            target.insert(key.clone(), value.clone());
        } else {
            target.insert(key.clone(), value.clone());
        }
    }
}

fn cloud_mcp_live_state_values(value: Option<&Value>) -> Vec<Value> {
    match value {
        Some(Value::Array(items)) => items.clone(),
        Some(Value::Object(items)) => items.values().cloned().collect(),
        _ => Vec::new(),
    }
}

fn cloud_mcp_live_state_workspace_key(workspace: &Value, index: usize) -> String {
    let workspace_id = cloud_mcp_payload_text(workspace, &["workspace_id", "id"])
        .unwrap_or_else(|| format!("workspace-{index}"));
    let match_key = cloud_mcp_workspace_id_match_key(&workspace_id);
    if match_key.is_empty() {
        workspace_id
    } else {
        match_key
    }
}

fn cloud_mcp_stamp_workspace_device_identity(
    workspace: &mut Value,
    device_id: &str,
    device_aliases: &[String],
    platform: &str,
) {
    let raw_workspace_id = cloud_mcp_payload_text(workspace, &["workspace_id", "id"]);
    let canonical_workspace_id = raw_workspace_id
        .as_deref()
        .map(|workspace_id| cloud_mcp_workspace_id_match_key_for_platform(workspace_id, platform));
    let Some(workspace) = workspace.as_object_mut() else {
        return;
    };
    workspace.insert("device_id".to_string(), json!(device_id));
    workspace.insert("machine_id".to_string(), json!(device_id));
    workspace.insert("device_aliases".to_string(), json!(device_aliases));
    workspace.insert("device_platform".to_string(), json!(platform));
    if let Some(workspace_id) = canonical_workspace_id.filter(|value| !value.is_empty()) {
        workspace.insert("workspace_id".to_string(), json!(workspace_id.clone()));
        workspace.insert("id".to_string(), json!(workspace_id));
    }
}

fn cloud_mcp_compact_insert_value(
    target: &mut serde_json::Map<String, Value>,
    key: &str,
    source: &Value,
    aliases: &[&str],
) {
    if let Some(value) = aliases
        .iter()
        .find_map(|alias| source.get(*alias).filter(|value| !value.is_null()))
    {
        target.insert(key.to_string(), value.clone());
    }
}

fn cloud_mcp_remove_unauthored_terminal_prompt_fields(source: &Value, target: &mut Value) {
    let Some(target) = target.as_object_mut() else {
        return;
    };
    for aliases in [
        &["prompt_id"][..],
        &["prompt_kind"][..],
        &["prompt_options"][..],
        &["allows_free_text"][..],
        &["prompt_default_option"][..],
        &["prompt_ttl_ms"][..],
        &["manual_approval_required"][..],
        &["provider_blocked_for_user"][..],
        &["terminal_is_prompting_user"][..],
        &["prompting_user_text"][..],
    ] {
        if aliases.iter().all(|key| source.get(*key).is_none()) {
            for key in aliases {
                target.remove(*key);
            }
        }
    }
}

fn cloud_mcp_compact_terminal_live_state(terminal: &Value, index: usize) -> Value {
    let mut item = terminal.as_object().cloned().unwrap_or_default();
    cloud_mcp_compact_insert_value(
        &mut item,
        "id",
        terminal,
        &["terminal_id", "target_terminal_id", "pane_id", "id"],
    );
    if let Some(terminal_id) = item.get("id").cloned() {
        item.entry("terminal_id".to_string())
            .or_insert_with(|| terminal_id.clone());
        item.entry("pane_id".to_string()).or_insert(terminal_id);
    }
    if let Some(pane_id) = item
        .get("pane_id")
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        if let Some(stamp) = agent_accounts_pane_profile_stamp(pane_id) {
            for (target, source) in [
                ("provider_account_id", "profile_id"),
                ("provider_account_label", "profile_label"),
                ("provider_auth_revision", "auth_revision"),
                ("provider_workspace_trust_state", "workspace_trust_state"),
                ("provider_workspace_trust_source", "workspace_trust_source"),
            ] {
                if let Some(value) = stamp.get(source).cloned() {
                    item.insert(target.to_string(), value);
                }
            }
        }
    }
    cloud_mcp_compact_insert_value(
        &mut item,
        "terminal_instance_id",
        terminal,
        &[
            "terminal_instance_id",
            "target_terminal_instance_id",
            "instance_id",
        ],
    );
    if let Some(instance_id) = item.get("terminal_instance_id").cloned() {
        item.entry("terminal_instance_id".to_string())
            .or_insert_with(|| instance_id.clone());
        item.entry("instance_id".to_string()).or_insert(instance_id);
    }
    cloud_mcp_compact_insert_value(
        &mut item,
        "name",
        terminal,
        &["terminal_nickname", "display_name", "terminal_name", "name"],
    );
    item.entry("index".to_string()).or_insert_with(|| {
        terminal
            .get("terminal_index")
            .or_else(|| terminal.get("index"))
            .cloned()
            .unwrap_or_else(|| json!(index))
    });
    for (key, aliases) in [
        (
            "agent",
            &["agent_kind", "agent_id", "agent", "role", "provider"][..],
        ),
        ("status", &["status", "state"][..]),
        ("activity_status", &["activity_status"][..]),
        ("native_rail_state", &["native_rail_state"][..]),
        ("readiness", &["readiness"][..]),
        ("turn_status", &["turn_status"][..]),
        ("prompt_event_id", &["prompt_event_id"][..]),
        ("user_message", &["user_message"][..]),
        ("current_prompt", &["current_prompt"][..]),
        ("last_prompt", &["last_prompt"][..]),
        ("commandable", &["commandable"][..]),
        ("connected", &["connected"][..]),
        ("native_connected", &["native_connected"][..]),
        ("last_known_runtime", &["last_known_runtime"][..]),
        ("runtime_read_only", &["runtime_read_only"][..]),
        ("status_seq", &["status_seq"][..]),
        ("input_ready", &["input_ready"][..]),
        (
            "session_id",
            &["provider_session_id", "native_session_id", "session_id"][..],
        ),
        ("thread_id", &["thread_id", "target_thread_id"][..]),
        ("todo_id", &["todo_id", "current_todo_id"][..]),
        ("dispatch_id", &["todo_dispatch_id", "dispatch_id"][..]),
    ] {
        cloud_mcp_compact_insert_value(&mut item, key, terminal, aliases);
    }
    // Session/thread identity is live terminal state, not optional chat
    // history metadata. Mirror the aliases on the compact wire shape so web
    // clients can bind a live row before the first transcript record exists.
    let session_identity_keys = ["provider_session_id", "native_session_id", "session_id"];
    let session_id = session_identity_keys
        .iter()
        .filter_map(|key| terminal.get(*key).filter(|value| !value.is_null()))
        .find(|value| value.as_str().is_some_and(|value| !value.trim().is_empty()))
        .cloned()
        .or_else(|| {
            session_identity_keys
                .iter()
                .find_map(|key| terminal.get(*key).filter(|value| !value.is_null()))
                .cloned()
        });
    if let Some(session_id) = session_id {
        item.insert("provider_session_id".to_string(), session_id.clone());
        item.insert("native_session_id".to_string(), session_id.clone());
        item.insert("session_id".to_string(), session_id);
    }
    let thread_identity_keys = ["thread_id", "target_thread_id"];
    let thread_id = thread_identity_keys
        .iter()
        .filter_map(|key| terminal.get(*key).filter(|value| !value.is_null()))
        .find(|value| value.as_str().is_some_and(|value| !value.trim().is_empty()))
        .cloned()
        .or_else(|| {
            thread_identity_keys
                .iter()
                .find_map(|key| terminal.get(*key).filter(|value| !value.is_null()))
                .cloned()
        });
    if let Some(thread_id) = thread_id {
        item.insert("thread_id".to_string(), thread_id.clone());
        item.insert("target_thread_id".to_string(), thread_id);
    }
    if !item.contains_key("busy") {
        let status = cloud_mcp_payload_text(&Value::Object(item.clone()), &["status"])
            .or_else(|| cloud_mcp_payload_text(terminal, &["status", "state"]))
            .unwrap_or_default()
            .trim()
            .to_ascii_lowercase();
        let busy = !matches!(
            status.as_str(),
            "" | "idle" | "ready" | "available" | "complete" | "completed" | "failed"
        );
        item.insert("busy".to_string(), json!(busy));
    }
    Value::Object(item)
}

fn cloud_mcp_compact_workspace_live_state(workspace: &Value, index: usize) -> (String, Value) {
    let workspace_key = cloud_mcp_live_state_workspace_key(workspace, index);
    let workspace_id = cloud_mcp_payload_text(workspace, &["workspace_id", "id"])
        .unwrap_or_else(|| format!("workspace-{index}"));
    let mut item = serde_json::Map::new();
    item.insert("id".to_string(), json!(workspace_id));
    item.insert("workspace_id".to_string(), json!(workspace_id));
    for (key, aliases) in [
        ("name", &["workspace_name", "name"][..]),
        ("active", &["workspace_active", "active"][..]),
        ("status", &["workspace_status", "status", "state"][..]),
        (
            "order",
            &["workspace_order", "workspace_index", "sort_order", "order"][..],
        ),
        ("commandable", &["commandable"][..]),
        ("last_known_runtime", &["last_known_runtime"][..]),
        ("runtime_read_only", &["runtime_read_only"][..]),
        (
            "last_known_terminal_fallback",
            &["last_known_terminal_fallback"][..],
        ),
        ("terminal_clear_reason", &["terminal_clear_reason"][..]),
        ("terminal_count", &["terminal_count"][..]),
        (
            "terminal_list_authoritative",
            &["terminal_list_authoritative"][..],
        ),
        (
            "terminal_list_empty_authoritative",
            &["terminal_list_empty_authoritative"][..],
        ),
        ("workspace_runtime_seq", &["workspace_runtime_seq"][..]),
        ("workspace_runtime_epoch", &["workspace_runtime_epoch"][..]),
        (
            "workspace_snapshot_fallback",
            &["workspace_snapshot_fallback"][..],
        ),
        ("path", &["path", "workspace_root", "root_directory"][..]),
    ] {
        cloud_mcp_compact_insert_value(&mut item, key, workspace, aliases);
    }
    if let Some(workspace_root) = cloud_mcp_workspace_root_text(workspace) {
        item.insert("workspace_root".to_string(), json!(workspace_root));
    }
    if let Some(terminal_value) = workspace.get("terminals") {
        let terminal_values = cloud_mcp_live_state_values(Some(terminal_value));
        let workspace_active = cloud_mcp_workspace_explicit_active_state(workspace).unwrap_or(true);
        let requested_terminal_clear_reason =
            cloud_mcp_payload_text(workspace, &["terminal_clear_reason"]).unwrap_or_default();
        let terminal_empty_authoritative =
            (cloud_mcp_payload_bool(workspace, &["terminal_list_empty_authoritative"], false)
                || cloud_mcp_payload_bool(
                    workspace,
                    &["terminal_list_empty_authoritative"],
                    false,
                ))
                && cloud_mcp_workspace_inactive_terminal_empty_clear_is_explicit(
                    workspace,
                    "",
                    &requested_terminal_clear_reason,
                    workspace_active,
                );
        if !terminal_values.is_empty() || terminal_empty_authoritative {
            let terminals = terminal_values
                .into_iter()
                .enumerate()
                .map(|(terminal_index, terminal)| {
                    cloud_mcp_compact_terminal_live_state(&terminal, terminal_index)
                })
                .collect::<Vec<_>>();
            item.entry("terminal_count".to_string())
                .or_insert_with(|| json!(terminals.len()));
            item.insert("terminals".to_string(), Value::Array(terminals));
        } else {
            item.remove("terminal_count");
            item.remove("terminal_list_empty_authoritative");
        }
    }
    if workspace.get("mcps").is_some() || workspace.get("servers").is_some() {
        let mcps =
            cloud_mcp_live_state_values(workspace.get("mcps").or_else(|| workspace.get("servers")))
                .into_iter()
                .enumerate()
                .map(|(server_index, server)| {
                    cloud_mcp_compact_mcp_live_state(&server, server_index)
                })
                .collect::<Vec<_>>();
        item.entry("mcp_server_count".to_string())
            .or_insert_with(|| json!(mcps.len()));
        item.insert("mcps".to_string(), Value::Array(mcps));
    }
    (workspace_key, Value::Object(item))
}

fn cloud_mcp_compact_mcp_live_state(server: &Value, index: usize) -> Value {
    let server_key = cloud_mcp_payload_text(server, &["server_key", "key", "id", "name", "label"])
        .unwrap_or_else(|| format!("server-{}", index + 1));
    let mut item = serde_json::Map::new();
    item.insert("server_key".to_string(), json!(server_key));
    for (key, aliases) in [
        ("name", &["name", "label", "display_name"][..]),
        ("version", &["version"][..]),
        ("transport", &["transport"][..]),
        ("install_state", &["install_state", "status", "state"][..]),
        ("workspace_enabled", &["workspace_enabled", "enabled"][..]),
        ("tool_count", &["tool_count"][..]),
    ] {
        cloud_mcp_compact_insert_value(&mut item, key, server, aliases);
    }
    if server.get("tools").is_some() {
        let tools = cloud_mcp_live_state_values(server.get("tools"))
            .into_iter()
            .take(CLOUD_MCP_WORKSPACE_MCP_TOOL_NAME_LIMIT)
            .filter_map(|tool| {
                cloud_mcp_payload_text(&tool, &["name", "tool_name", "id"])
                    .or_else(|| tool.as_str().map(str::to_string))
                    .map(|name| json!({ "name": name }))
            })
            .collect::<Vec<_>>();
        item.entry("tool_count".to_string())
            .or_insert_with(|| json!(tools.len()));
        item.insert("tools".to_string(), Value::Array(tools));
    }
    Value::Object(item)
}

fn cloud_mcp_live_state_workspace_from_snapshot(
    workspace: &Value,
    index: usize,
) -> (String, Value) {
    cloud_mcp_compact_workspace_live_state(workspace, index)
}

fn cloud_mcp_compact_app_live_state(app_context: &Value) -> Value {
    let mut item = serde_json::Map::new();
    cloud_mcp_compact_insert_value(&mut item, "active_view", app_context, &["active_view"]);
    cloud_mcp_compact_insert_value(&mut item, "visible_view", app_context, &["visible_view"]);
    cloud_mcp_compact_insert_value(
        &mut item,
        "activated_workspace_id",
        app_context,
        &["activated_workspace_id"],
    );
    if let Some(selected_workspace) = app_context
        .get("selected_workspace")
        .filter(|value| value.is_object())
    {
        if let Some(workspace_id) =
            cloud_mcp_payload_text(selected_workspace, &["workspace_id", "id"])
        {
            item.insert("selected_workspace_id".to_string(), json!(workspace_id));
        }
    }
    Value::Object(item)
}

fn cloud_mcp_device_live_unit_event_kind(event_kind: &str) -> bool {
    matches!(
        event_kind.trim().to_ascii_lowercase().as_str(),
        "device_agent_installation_status"
            | "workspace_mcp_server_status"
            | "device_audio_preferences"
            | "device_notification_preferences"
            | "provider_account_identity"
    )
}

fn cloud_mcp_device_live_sync_identity_from_payload(
    payload: &Value,
) -> Option<(String, String, String, String, String, String)> {
    let scope_key =
        cloud_mcp_payload_scope_key(payload).unwrap_or_else(cloud_mcp_process_account_scope_key);
    let device = payload.get("device").filter(|value| value.is_object());
    let device_id =
        cloud_mcp_payload_text(payload, &["device_id", "machine_id"]).or_else(|| {
            device.and_then(|device| {
                cloud_mcp_payload_text(device, &["device_id", "machine_id", "id"])
            })
        })?;
    let sync_unit = cloud_mcp_payload_text(payload, &["sync_unit"])
        .unwrap_or_else(|| "device_live_state_snapshot".to_string());
    let hash_seed =
        cloud_mcp_outbox_stable_snapshot_hash_value("device_live_state_snapshot", payload);
    let content_hash = cloud_mcp_payload_text(payload, &["sync_content_hash", "content_hash"])
        .unwrap_or_else(|| cloud_mcp_outbox_payload_hash(&hash_seed));
    let payload_hash =
        cloud_mcp_payload_text(payload, &["payload_hash"]).unwrap_or_else(|| content_hash.clone());
    let idempotency_key =
        cloud_mcp_payload_text(payload, &["idempotency_key"]).unwrap_or_else(|| {
            format!("device-live-state:{scope_key}:{device_id}:{sync_unit}:{content_hash}")
        });
    Some((
        scope_key,
        device_id,
        sync_unit,
        content_hash,
        payload_hash,
        idempotency_key,
    ))
}

fn cloud_mcp_device_live_payload_with_sync_identity(mut payload: Value) -> Value {
    let Some((scope_key, device_id, sync_unit, content_hash, payload_hash, idempotency_key)) =
        cloud_mcp_device_live_sync_identity_from_payload(&payload)
    else {
        return payload;
    };
    if let Some(object) = payload.as_object_mut() {
        object
            .entry("device_id".to_string())
            .or_insert_with(|| json!(device_id.clone()));
        object
            .entry("scope_key".to_string())
            .or_insert_with(|| json!(scope_key.clone()));
        object
            .entry("sync_unit".to_string())
            .or_insert_with(|| json!(sync_unit.clone()));
        object
            .entry("sync_content_hash".to_string())
            .or_insert_with(|| json!(content_hash.clone()));
        object
            .entry("payload_hash".to_string())
            .or_insert_with(|| json!(payload_hash.clone()));
        object
            .entry("idempotency_key".to_string())
            .or_insert_with(|| json!(idempotency_key.clone()));
    }
    payload
}

fn cloud_mcp_device_live_mark_sync_pending(payload: &Value) -> Result<(), String> {
    let _guard = CLOUD_MCP_DEVICE_LIVE_SYNC_LOCK
        .get_or_init(|| StdMutex::new(()))
        .lock()
        .map_err(|_| "Device live-state sync lock is poisoned.".to_string())?;
    let Some((scope_key, device_id, sync_unit, content_hash, payload_hash, idempotency_key)) =
        cloud_mcp_device_live_sync_identity_from_payload(payload)
    else {
        return Ok(());
    };
    let conn = cloud_mcp_open_outbox_conn()?;
    let now = cloud_mcp_now_ms() as i64;
    conn.execute(
        &format!(
            "INSERT INTO {CLOUD_MCP_DEVICE_LIVE_SYNC_STATE_TABLE}(
                scope_key, device_id, sync_unit, content_hash, payload_hash,
                idempotency_key, server_cursor, acked_at_ms, updated_at_ms
             )
             VALUES(?1, ?2, ?3, ?4, ?5, ?6, '', 0, ?7)
             ON CONFLICT(scope_key, device_id, sync_unit) DO UPDATE SET
                content_hash=excluded.content_hash,
                payload_hash=excluded.payload_hash,
                idempotency_key=excluded.idempotency_key,
                acked_at_ms=0,
                updated_at_ms=excluded.updated_at_ms"
        ),
        rusqlite::params![
            scope_key,
            device_id,
            sync_unit,
            content_hash,
            payload_hash,
            idempotency_key,
            now,
        ],
    )
    .map_err(|error| format!("Unable to mark device live-state sync pending: {error}"))?;
    if sync_unit == "device_live_state_snapshot" {
        if let Some(coalesce_key) =
            cloud_mcp_outbox_snapshot_coalesce_key("device_live_state_snapshot", payload)
        {
            conn.execute(
                &format!(
                    "UPDATE {CLOUD_MCP_OUTBOX_TABLE}
                     SET status='superseded', updated_at_ms=?1
                     WHERE coalesce_key=?2
                       AND idempotency_key<>?3
                       AND status IN ('queued', 'retrying', 'in_flight')"
                ),
                rusqlite::params![now, coalesce_key, idempotency_key],
            )
            .map_err(|error| {
                format!("Unable to supersede stale device live-state outbox rows: {error}")
            })?;
        }
    }
    Ok(())
}

fn cloud_mcp_device_live_sync_state_matches_from_conn(
    conn: &rusqlite::Connection,
    payload: &Value,
) -> Result<CloudMcpDeviceLiveSyncStateMatch, String> {
    let Some((scope_key, device_id, sync_unit, content_hash, _payload_hash, idempotency_key)) =
        cloud_mcp_device_live_sync_identity_from_payload(payload)
    else {
        return Ok(CloudMcpDeviceLiveSyncStateMatch::Missing);
    };
    let current = conn
        .query_row(
            &format!(
                "SELECT content_hash, idempotency_key
                 FROM {CLOUD_MCP_DEVICE_LIVE_SYNC_STATE_TABLE}
                 WHERE scope_key=?1 AND device_id=?2 AND sync_unit=?3"
            ),
            rusqlite::params![scope_key, device_id, sync_unit],
            |row| Ok((row.get::<_, String>(0)?, row.get::<_, String>(1)?)),
        )
        .optional()
        .map_err(|error| format!("Unable to read current device live-state sync: {error}"))?;
    Ok(match current {
        Some((current_hash, current_idempotency_key))
            if current_hash == content_hash && current_idempotency_key == idempotency_key =>
        {
            CloudMcpDeviceLiveSyncStateMatch::Current
        }
        Some(_) => CloudMcpDeviceLiveSyncStateMatch::Superseded,
        None => CloudMcpDeviceLiveSyncStateMatch::Missing,
    })
}

fn cloud_mcp_device_live_mark_sync_acked_from_payload(
    source_payload: Option<&Value>,
    response: &Value,
) -> Result<bool, String> {
    let _guard = CLOUD_MCP_DEVICE_LIVE_SYNC_LOCK
        .get_or_init(|| StdMutex::new(()))
        .lock()
        .map_err(|_| "Device live-state sync lock is poisoned.".to_string())?;
    let identity_source = source_payload.unwrap_or(response);
    let Some((scope_key, device_id, sync_unit, content_hash, payload_hash, idempotency_key)) =
        cloud_mcp_device_live_sync_identity_from_payload(identity_source)
            .or_else(|| cloud_mcp_device_live_sync_identity_from_payload(response))
    else {
        return Ok(false);
    };
    let response_data = response.get("data").filter(|value| value.is_object());
    let server_cursor =
        cloud_mcp_payload_text(response, &["server_cursor", "sync_cursor", "revision"])
            .or_else(|| {
                response_data.and_then(|data| {
                    cloud_mcp_payload_text(data, &["server_cursor", "sync_cursor", "revision"])
                })
            })
            .unwrap_or_default();
    let conn = cloud_mcp_open_outbox_conn()?;
    if source_payload.is_some()
        && cloud_mcp_device_live_sync_state_matches_from_conn(&conn, identity_source)?
            != CloudMcpDeviceLiveSyncStateMatch::Current
    {
        return Ok(false);
    }
    let now = cloud_mcp_now_ms() as i64;
    conn.execute(
        &format!(
            "INSERT INTO {CLOUD_MCP_DEVICE_LIVE_SYNC_STATE_TABLE}(
                scope_key, device_id, sync_unit, content_hash, payload_hash,
                idempotency_key, server_cursor, acked_at_ms, updated_at_ms
             )
             VALUES(?1, ?2, ?3, ?4, ?5, ?6, ?7, ?8, ?8)
             ON CONFLICT(scope_key, device_id, sync_unit) DO UPDATE SET
                content_hash=excluded.content_hash,
                payload_hash=excluded.payload_hash,
                idempotency_key=excluded.idempotency_key,
                server_cursor=excluded.server_cursor,
                acked_at_ms=excluded.acked_at_ms,
                updated_at_ms=excluded.updated_at_ms"
        ),
        rusqlite::params![
            scope_key,
            device_id,
            sync_unit,
            content_hash,
            payload_hash,
            idempotency_key,
            server_cursor,
            now,
        ],
    )
    .map_err(|error| format!("Unable to mark device live-state sync acked: {error}"))?;
    Ok(true)
}

fn cloud_mcp_device_live_enqueue_fallback_if_current(
    payload: &Value,
    reason: &str,
) -> Result<Option<CloudMcpOutboxRow>, String> {
    let _guard = CLOUD_MCP_DEVICE_LIVE_SYNC_LOCK
        .get_or_init(|| StdMutex::new(()))
        .lock()
        .map_err(|_| "Device live-state sync lock is poisoned.".to_string())?;
    let conn = cloud_mcp_open_outbox_conn()?;
    match cloud_mcp_device_live_sync_state_matches_from_conn(&conn, payload)? {
        CloudMcpDeviceLiveSyncStateMatch::Current => {}
        CloudMcpDeviceLiveSyncStateMatch::Superseded => return Ok(None),
        CloudMcpDeviceLiveSyncStateMatch::Missing => {
            return Err(
                "Current device live-state sync marker is missing; rebuild the snapshot."
                    .to_string(),
            );
        }
    }
    drop(conn);
    cloud_mcp_outbox_enqueue_event(
        "device_live_state_snapshot",
        payload,
        CLOUD_MCP_BACKGROUND_SYNC_PRIORITY_HIGH,
        reason,
    )
    .map(Some)
}

fn cloud_mcp_device_live_sync_decision(
    payload: &Value,
) -> Result<CloudMcpDeviceLiveSyncDecision, String> {
    let Some((scope_key, device_id, sync_unit, content_hash, _payload_hash, idempotency_key)) =
        cloud_mcp_device_live_sync_identity_from_payload(payload)
    else {
        return Ok(CloudMcpDeviceLiveSyncDecision::Enqueue);
    };
    let conn = cloud_mcp_open_outbox_conn()?;
    let state = conn
        .query_row(
            &format!(
                "SELECT content_hash, idempotency_key, acked_at_ms
                 FROM {CLOUD_MCP_DEVICE_LIVE_SYNC_STATE_TABLE}
                 WHERE scope_key=?1 AND device_id=?2 AND sync_unit=?3"
            ),
            rusqlite::params![scope_key, device_id, sync_unit],
            |row| {
                Ok((
                    row.get::<_, String>(0).unwrap_or_default(),
                    row.get::<_, String>(1).unwrap_or_default(),
                    row.get::<_, i64>(2).unwrap_or(0).max(0),
                ))
            },
        )
        .ok();
    if let Some((state_content_hash, state_idempotency_key, acked_at_ms)) = state {
        if state_content_hash == content_hash {
            if acked_at_ms > 0 {
                return Ok(CloudMcpDeviceLiveSyncDecision::CurrentAcked);
            }
            if !state_idempotency_key.trim().is_empty() {
                match cloud_mcp_outbox_status_for_idempotency(&state_idempotency_key).as_deref() {
                    Some("queued" | "retrying" | "in_flight") => {
                        return Ok(CloudMcpDeviceLiveSyncDecision::CurrentPending);
                    }
                    Some("acked") => {
                        let _ = cloud_mcp_device_live_mark_sync_acked_from_payload(
                            Some(payload),
                            payload,
                        );
                        return Ok(CloudMcpDeviceLiveSyncDecision::CurrentAcked);
                    }
                    _ => {}
                }
            }
        }
    }
    if let Some(acked_at_ms) = cloud_mcp_outbox_acked_at_for_idempotency(&idempotency_key) {
        let _ = cloud_mcp_device_live_mark_sync_acked_from_payload(
            Some(payload),
            &json!({
                "acked_at_ms": acked_at_ms,
            }),
        );
        return Ok(CloudMcpDeviceLiveSyncDecision::CurrentAcked);
    }
    Ok(CloudMcpDeviceLiveSyncDecision::Enqueue)
}

async fn cloud_mcp_sync_device_live_unit_event(
    state: &CloudMcpState,
    event_kind: &str,
    payload: Value,
) -> Result<Value, String> {
    let payload = cloud_mcp_device_live_payload_with_sync_identity(payload);
    let sync_unit =
        cloud_mcp_payload_text(&payload, &["sync_unit"]).unwrap_or_else(|| event_kind.to_string());
    match cloud_mcp_device_live_sync_decision(&payload)? {
        CloudMcpDeviceLiveSyncDecision::CurrentAcked => {
            return Ok(json!({
                "ok": true,
                "skipped": true,
                "reason": "sync_unit_current",
                "event_kind": event_kind,
                "sync_unit": sync_unit,
            }));
        }
        CloudMcpDeviceLiveSyncDecision::CurrentPending => {
            return Ok(json!({
                "ok": true,
                "queued": true,
                "skipped": true,
                "reason": "sync_unit_pending",
                "event_kind": event_kind,
                "sync_unit": sync_unit,
            }));
        }
        CloudMcpDeviceLiveSyncDecision::Enqueue => {}
    }
    cloud_mcp_device_live_mark_sync_pending(&payload)?;
    cloud_mcp_post_event_endpoint(state, event_kind, &payload).await
}

async fn cloud_mcp_provider_accounts_live_state() -> Value {
    if let Some(app) = CLOUD_MCP_SYNC_STATUS_APP.get() {
        let terminal_state = app.state::<TerminalState>();
        agent_accounts_device_live_state_for_terminal_state(terminal_state.inner()).await
    } else {
        agent_accounts_device_live_state()
    }
}

async fn cloud_mcp_device_live_state_snapshot_payload(
    state: &CloudMcpState,
    reason: &str,
) -> Value {
    let device_profile = cloud_mcp_desktop_device_profile();
    let device_id = cloud_mcp_payload_text(&device_profile, &["device_id"])
        .unwrap_or_else(|| "desktop".to_string());
    let device_id = cloud_mcp_device_id_match_key(&device_id);
    let device_aliases = vec![device_id.clone()];
    let (connection_id, session_started_at_ms) = {
        let runtime = state.inner.lock().await;
        (
            runtime.global_ws_connection_id.clone(),
            runtime
                .global_ws_last_connected_ms
                .or(runtime.last_connected_ms),
        )
    };
    let session_started_at_ms = session_started_at_ms.unwrap_or_else(cloud_mcp_now_ms);
    let session_id = connection_id
        .clone()
        .unwrap_or_else(|| format!("desktop-session-{}-{session_started_at_ms}", device_id));
    let mut workspaces = serde_json::Map::new();
    let mut app_context = Value::Null;
    let mut has_app_context = false;
    let mut audio_preferences = Value::Null;
    let mut has_audio_preferences = false;
    let mut notification_preferences = Value::Null;
    let mut has_notification_preferences = false;
    let mut has_workspace_state = false;
    let mut cli_states = Value::Null;
    let mut has_cli_state = false;
    let mut coding_agents = Vec::new();
    let mut has_agent_installations = false;
    let mut terminal_orchestrators = Vec::new();
    let mut has_terminal_orchestrator_state = false;
    let provider_accounts = cloud_mcp_provider_accounts_live_state().await;

    let (lifecycle_workspaces, workspace_catalog_ready) =
        cloud_mcp_lifecycle_workspaces(state).await;
    if workspace_catalog_ready {
        has_workspace_state = true;
    }
    for (index, workspace) in lifecycle_workspaces.iter().enumerate() {
        let (workspace_key, workspace_value) =
            cloud_mcp_live_state_workspace_from_snapshot(workspace, index);
        let existing = workspaces.entry(workspace_key).or_insert_with(|| json!({}));
        cloud_mcp_live_state_merge_object(existing, workspace_value);
    }

    {
        let snapshots = state.runtime_snapshots.lock().await;
        if let Some(snapshot) = snapshots.app_context.as_ref() {
            has_app_context = true;
            app_context = snapshot.clone();
        }
        if let Some(snapshot) = snapshots.audio_preferences.as_ref() {
            has_audio_preferences = true;
            audio_preferences = snapshot.clone();
        }
        if let Some(snapshot) = snapshots.notification_preferences.as_ref() {
            has_notification_preferences = true;
            notification_preferences = snapshot.clone();
        }
        if let Some(snapshot) = snapshots.cli_states.as_ref() {
            if let Some(clis) = snapshot.get("cli_states").or_else(|| snapshot.get("clis")) {
                cli_states = clis.clone();
                has_cli_state = true;
            }
        }
        if let Some(snapshot) = snapshots.agent_installations.as_ref() {
            if let Some(agents) = snapshot.get("coding_agents").and_then(Value::as_array) {
                coding_agents = agents.clone();
                has_agent_installations = true;
            }
        }
        if let Some(orchestrator_source) = snapshots
            .workspace_terminals
            .as_ref()
            .and_then(|snapshot| snapshot.get("terminal_orchestrators"))
        {
            has_terminal_orchestrator_state = true;
            let observed_at_ms = cloud_mcp_now_ms();
            terminal_orchestrators = cloud_mcp_live_state_values(Some(orchestrator_source))
                .into_iter()
                .enumerate()
                .filter_map(|(index, terminal)| {
                    cloud_mcp_normalize_device_terminal_orchestrator(
                        &terminal,
                        index,
                        observed_at_ms,
                    )
                    .map(|normalized| cloud_mcp_compact_terminal_live_state(&normalized, index))
                })
                .collect();
        }
    }

    let mut payload = json!({
        "source": "rust-diffforge-device-live-state",
        "reason": reason,
        "device_id": device_id.clone(),
        "machine_id": device_id.clone(),
        "device_aliases": device_aliases.clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "platform": device_profile["platform"].clone(),
        "app_update": app_update_device_payload(),
        "form_factor": device_profile["form_factor"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "client_type": device_profile["client_type"].clone(),
        "connection_source": device_profile["connection_source"].clone(),
        "connection_id": connection_id.clone(),
        "session_id": session_id,
        "session_started_at": session_started_at_ms,
        "last_connected_at": session_started_at_ms,
        "updated_at_ms": cloud_mcp_now_ms(),
        "ts_ms": cloud_mcp_now_ms(),
        "status": "connected",
        "connected": true,
        "native_connected": true,
        "workspace_catalog_ready": workspace_catalog_ready,
        "workspace_snapshot_complete": workspace_catalog_ready,
        "workspace_snapshot_authoritative": workspace_catalog_ready,
        "device": {
            "id": device_id.clone(),
            "device_id": device_id.clone(),
            "machine_id": device_id.clone(),
            "device_aliases": device_aliases.clone(),
            "name": device_profile["device_name"].clone(),
            "host": device_profile["machine_name"].clone(),
            "os": device_profile["platform"].clone(),
            "platform": device_profile["platform"].clone(),
            "kind": device_profile["form_factor"].clone(),
            "native": true,
            "web": false,
            "connected": true,
        },
        "web": {
            "connected": false,
            "active": false,
            "target_device_id": device_id,
        },
        "provider_accounts": provider_accounts,
    });
    if let Some(object) = payload.as_object_mut() {
        if has_app_context {
            object.insert(
                "app".to_string(),
                cloud_mcp_compact_app_live_state(&app_context),
            );
        }
        if has_audio_preferences {
            object.insert("audio_preferences".to_string(), audio_preferences);
        }
        if has_notification_preferences {
            object.insert(
                "notification_preferences".to_string(),
                notification_preferences,
            );
        }
        if has_workspace_state {
            let workspace_values = workspaces
                .values()
                .cloned()
                .map(|mut workspace| {
                    cloud_mcp_stamp_workspace_device_identity(
                        &mut workspace,
                        &device_id,
                        &device_aliases,
                        cloud_mcp_desktop_platform(),
                    );
                    workspace
                })
                .collect::<Vec<_>>();
            let workspace_set_empty_authoritative = workspace_values.is_empty();
            object.insert("workspaces".to_string(), Value::Array(workspace_values));
            if workspace_set_empty_authoritative {
                object.insert("workspace_set_empty_authoritative".to_string(), json!(true));
                object.insert(
                    "workspace_clear_reason".to_string(),
                    json!("workspace_catalog_cleared"),
                );
            }
        }
        if has_cli_state {
            object.insert("cli_states".to_string(), cli_states);
        }
        if has_agent_installations {
            object.insert("agent_count".to_string(), json!(coding_agents.len()));
            object.insert("coding_agents".to_string(), Value::Array(coding_agents));
        }
        if has_terminal_orchestrator_state {
            object.insert(
                "terminal_orchestrator_count".to_string(),
                json!(terminal_orchestrators.len()),
            );
            object.insert(
                "terminal_orchestrators".to_string(),
                Value::Array(terminal_orchestrators),
            );
        }
    }
    payload
}

fn cloud_mcp_device_live_snapshot_force_replay(reason: &str) -> bool {
    reason.trim().split(':').any(|part| {
        part.eq_ignore_ascii_case("websocket_ready_replay")
            || part.eq_ignore_ascii_case("workspace_catalog_ready_deferred_republish")
    })
}

fn cloud_mcp_device_live_snapshot_lifecycle_fast_lane(reason: &str) -> bool {
    reason.trim().split(':').any(|part| {
        let part = part.trim().to_ascii_lowercase();
        matches!(
            part.as_str(),
            "local_workspace_deleted"
                | "workspace_archive"
                | "workspace_close"
                | "workspace_delete"
                | "workspace_open"
                | "workspace_registered"
                | "workspace_registration"
                | "terminal_close"
                | "terminal_prompt_resolved"
        ) || part.starts_with("workspace_activate")
            || part.starts_with("workspace_deactivate")
    })
}

fn cloud_mcp_device_live_force_replay_identity(mut payload: Value) -> Value {
    let replay_token = cloud_mcp_payload_text(&payload, &["connection_id", "session_id"])
        .unwrap_or_else(|| cloud_mcp_now_ms().to_string());
    let base_idempotency_key = cloud_mcp_payload_text(&payload, &["idempotency_key"])
        .unwrap_or_else(|| "device-live-state".to_string());
    if let Some(object) = payload.as_object_mut() {
        object.insert(
            "idempotency_key".to_string(),
            json!(format!("{base_idempotency_key}:replay:{replay_token}")),
        );
        object.insert("force_connection_replay".to_string(), json!(true));
    }
    payload
}

fn cloud_mcp_schedule_device_live_catalog_ready_retry(state: &CloudMcpState, reason: &str) {
    if state
        .device_live_catalog_retry_scheduled
        .swap(true, Ordering::SeqCst)
    {
        return;
    }
    let state = state.clone();
    let reason = reason.to_string();
    tauri::async_runtime::spawn(async move {
        for attempt in 0..CLOUD_MCP_DEVICE_LIVE_CATALOG_RETRY_MAX_ATTEMPTS {
            sleep(cloud_mcp_device_live_catalog_retry_delay(attempt)).await;
            if crate::app_shutdown_requested() {
                state
                    .device_live_catalog_retry_scheduled
                    .store(false, Ordering::SeqCst);
                return;
            }
            let payload = cloud_mcp_device_live_payload_with_sync_identity(
                cloud_mcp_device_live_state_snapshot_payload(
                    &state,
                    "workspace_catalog_ready_deferred_republish",
                )
                .await,
            );
            if !cloud_mcp_payload_bool(&payload, &["workspace_catalog_ready"], false) {
                continue;
            }
            state
                .device_live_catalog_retry_scheduled
                .store(false, Ordering::SeqCst);
            cloud_mcp_publish_device_live_state_ready_payload(
                &state,
                payload,
                &format!("{reason}:workspace_catalog_ready_deferred_republish"),
            )
            .await;
            return;
        }
        log_terminal_status_event(
            "backend.cloud_mcp.device_live_state.ws.retry_exhausted",
            json!({
                "reason": reason,
                "attempts": CLOUD_MCP_DEVICE_LIVE_CATALOG_RETRY_MAX_ATTEMPTS,
                "max_wait_ms": (0..CLOUD_MCP_DEVICE_LIVE_CATALOG_RETRY_MAX_ATTEMPTS)
                    .map(cloud_mcp_device_live_catalog_retry_delay)
                    .map(|delay| delay.as_millis() as u64)
                    .sum::<u64>(),
                "status": "waiting_for_workspace_catalog_ready_event",
            }),
        );

        // Stop polling after the bounded retry window. The durable catalog
        // writer wakes this task once hydration completes, so a slow startup
        // still republishes without rebuilding the snapshot forever.
        tokio::select! {
            _ = state.device_live_catalog_ready_notify.notified() => {}
            _ = cloud_mcp_shutdown_goodbye_notify().notified() => {
                state
                    .device_live_catalog_retry_scheduled
                    .store(false, Ordering::SeqCst);
                return;
            }
        }
        if crate::app_shutdown_requested() {
            state
                .device_live_catalog_retry_scheduled
                .store(false, Ordering::SeqCst);
            return;
        }
        let payload = cloud_mcp_device_live_payload_with_sync_identity(
            cloud_mcp_device_live_state_snapshot_payload(
                &state,
                "workspace_catalog_ready_deferred_republish",
            )
            .await,
        );
        state
            .device_live_catalog_retry_scheduled
            .store(false, Ordering::SeqCst);
        if cloud_mcp_payload_bool(&payload, &["workspace_catalog_ready"], false) {
            cloud_mcp_publish_device_live_state_ready_payload(
                &state,
                payload,
                &format!("{reason}:workspace_catalog_ready_deferred_republish"),
            )
            .await;
        } else {
            cloud_mcp_schedule_device_live_catalog_ready_retry(&state, &reason);
        }
    });
}

fn cloud_mcp_notify_workspace_catalog_ready(state: &CloudMcpState) {
    if state
        .device_live_catalog_retry_scheduled
        .load(Ordering::SeqCst)
    {
        state.device_live_catalog_ready_notify.notify_one();
    }
}

fn cloud_mcp_device_live_catalog_retry_delay(attempt: usize) -> Duration {
    let shift = attempt.min(20) as u32;
    let delay_ms = CLOUD_MCP_DEVICE_LIVE_CATALOG_RETRY_INITIAL_MS
        .saturating_mul(1_u64 << shift)
        .min(CLOUD_MCP_DEVICE_LIVE_CATALOG_RETRY_MAX_MS);
    Duration::from_millis(delay_ms)
}

async fn cloud_mcp_publish_device_live_state_snapshot(state: &CloudMcpState, reason: &str) {
    let payload = cloud_mcp_device_live_payload_with_sync_identity(
        cloud_mcp_device_live_state_snapshot_payload(state, reason).await,
    );
    if !cloud_mcp_payload_bool(&payload, &["workspace_catalog_ready"], false) {
        log_terminal_status_event(
            "backend.cloud_mcp.device_live_state.ws.skip",
            json!({
                "reason": reason,
                "status": "workspace_catalog_not_ready",
            }),
        );
        cloud_mcp_schedule_device_live_catalog_ready_retry(state, reason);
        return;
    }
    cloud_mcp_publish_device_live_state_ready_payload(state, payload, reason).await;
}

async fn cloud_mcp_publish_device_live_state_ready_payload(
    state: &CloudMcpState,
    mut payload: Value,
    reason: &str,
) {
    let force_replay = cloud_mcp_device_live_snapshot_force_replay(reason);
    let lifecycle_fast_lane = cloud_mcp_device_live_snapshot_lifecycle_fast_lane(reason);
    if force_replay {
        payload = cloud_mcp_device_live_force_replay_identity(payload);
    }
    match if force_replay || lifecycle_fast_lane {
        Ok(CloudMcpDeviceLiveSyncDecision::Enqueue)
    } else {
        cloud_mcp_device_live_sync_decision(&payload)
    } {
        Ok(CloudMcpDeviceLiveSyncDecision::CurrentAcked) => {
            log_terminal_status_event(
                "backend.cloud_mcp.device_live_state.ws.skip",
                json!({
                    "reason": reason,
                    "status": "current_acked",
                }),
            );
            return;
        }
        Ok(CloudMcpDeviceLiveSyncDecision::CurrentPending) => {
            log_terminal_status_event(
                "backend.cloud_mcp.device_live_state.ws.skip",
                json!({
                    "reason": reason,
                    "status": "current_pending",
                }),
            );
            return;
        }
        Ok(CloudMcpDeviceLiveSyncDecision::Enqueue) => {}
        Err(error) => {
            log_terminal_status_event(
                "backend.cloud_mcp.device_live_state.sync_decision_failed",
                json!({
                    "reason": reason,
                    "error": clean_terminal_telemetry_text(&error),
                }),
            );
        }
    }
    let pending_recorded = match cloud_mcp_device_live_mark_sync_pending(&payload) {
        Ok(()) => true,
        Err(error) => {
            log_terminal_status_event(
                "backend.cloud_mcp.device_live_state.mark_pending_failed",
                json!({
                    "reason": reason,
                    "error": clean_terminal_telemetry_text(&error),
                }),
            );
            false
        }
    };
    let state = state.clone();
    let reason = reason.to_string();
    tauri::async_runtime::spawn(async move {
        match cloud_mcp_send_event_over_app_ws_once(
            &state,
            "device_live_state_snapshot",
            &payload,
            "device-live-state",
        )
        .await
        {
            Ok(response) => {
                let _ =
                    cloud_mcp_device_live_mark_sync_acked_from_payload(Some(&payload), &response);
                log_terminal_status_event(
                    "backend.cloud_mcp.device_live_state.ws.sent",
                    json!({
                        "reason": reason,
                        "cloud_event_id": cloud_mcp_outbox_cloud_event_id(&response),
                    }),
                );
            }
            Err(error) => {
                if let Some(rebuild_reason) =
                    cloud_mcp_authoritative_workspace_snapshot_rebuild_reason(&error)
                {
                    log_terminal_status_event(
                        "backend.cloud_mcp.device_live_state.ws.rebuild",
                        json!({
                            "reason": reason,
                            "status": rebuild_reason,
                        }),
                    );
                    let current_payload = cloud_mcp_device_live_payload_with_sync_identity(
                        cloud_mcp_device_live_state_snapshot_payload(
                            &state,
                            "workspace_catalog_changed_during_live_send",
                        )
                        .await,
                    );
                    if cloud_mcp_payload_bool(&current_payload, &["workspace_catalog_ready"], false)
                    {
                        cloud_mcp_enqueue_background_sync(
                            &state,
                            "device_live_state_snapshot".to_string(),
                            "device_live_state_snapshot",
                            current_payload,
                            CLOUD_MCP_BACKGROUND_SYNC_PRIORITY_HIGH,
                            "workspace_catalog_changed_during_live_send",
                        )
                        .await;
                    }
                    return;
                }
                cloud_mcp_background_sync_ensure_started(&state);
                let fallback = if pending_recorded {
                    cloud_mcp_device_live_enqueue_fallback_if_current(&payload, reason.as_str())
                } else {
                    Err(
                        "Device live-state pending marker was not recorded; rebuild the snapshot."
                            .to_string(),
                    )
                };
                let fallback_status = match fallback {
                    Ok(Some(_)) => {
                        state.background_sync.notify.notify_one();
                        "durable_outbox"
                    }
                    Ok(None) => "stale_snapshot_dropped",
                    Err(fallback_error) => {
                        // If SQLite itself is unavailable, rebuild from current local state
                        // before falling back to the in-memory queue. Never enqueue the
                        // captured (possibly stale) snapshot after a newer activation.
                        let mut current_payload = cloud_mcp_device_live_payload_with_sync_identity(
                            cloud_mcp_device_live_state_snapshot_payload(
                                &state,
                                "direct_send_fallback_refresh",
                            )
                            .await,
                        );
                        if !cloud_mcp_payload_bool(
                            &current_payload,
                            &["workspace_catalog_ready"],
                            false,
                        ) {
                            log_terminal_status_event(
                                "backend.cloud_mcp.device_live_state.ws.skip",
                                json!({
                                    "reason": reason,
                                    "status": "workspace_catalog_not_ready_during_fallback",
                                }),
                            );
                            return;
                        }
                        if force_replay {
                            current_payload =
                                cloud_mcp_device_live_force_replay_identity(current_payload);
                        }
                        cloud_mcp_enqueue_background_sync(
                            &state,
                            "device_live_state_snapshot".to_string(),
                            "device_live_state_snapshot",
                            current_payload,
                            CLOUD_MCP_BACKGROUND_SYNC_PRIORITY_HIGH,
                            format!("{reason}: {fallback_error}"),
                        )
                        .await;
                        "current_snapshot_memory_fallback"
                    }
                };
                log_terminal_status_event(
                    "backend.cloud_mcp.device_live_state.ws.queued",
                    json!({
                        "reason": reason,
                        "error": clean_terminal_telemetry_text(&error),
                        "fallback": fallback_status,
                    }),
                );
            }
        }
    });
}

/// Host and transport of the most recently resolved app websocket target.
/// While live sync is connected this is the proven-reachable cloud host, so
/// dedicated websocket routes (voice, dictation, terminal proxy) derive from
/// it instead of depending on a balancer round trip.
static CLOUD_MCP_LIVE_APP_WS_HOST: OnceLock<StdMutex<Option<(String, String)>>> = OnceLock::new();

/// Last direct route observed from any successful resolve. Blocking resolvers
/// cannot reach the app websocket request path, so they reuse this while the
/// token is still valid when the balancer is unreachable.
#[derive(Clone)]
struct CloudMcpLastDirectRoute {
    ws_url: String,
    transport: String,
    route_token: String,
    expires_at_s: u64,
}

static CLOUD_MCP_LAST_DIRECT_ROUTE: OnceLock<StdMutex<Option<CloudMcpLastDirectRoute>>> =
    OnceLock::new();

const CLOUD_MCP_ROUTE_TOKEN_REUSE_MARGIN_SECS: u64 = 30;

fn cloud_mcp_live_app_ws_host_store(ws_url: &str, transport: &str) {
    if let Ok(mut slot) = CLOUD_MCP_LIVE_APP_WS_HOST
        .get_or_init(|| StdMutex::new(None))
        .lock()
    {
        *slot = Some((ws_url.to_string(), transport.to_string()));
    }
}

fn cloud_mcp_live_app_ws_host() -> Option<(String, String)> {
    CLOUD_MCP_LIVE_APP_WS_HOST
        .get_or_init(|| StdMutex::new(None))
        .lock()
        .ok()?
        .clone()
}

fn cloud_mcp_clear_live_app_ws_route_cache() {
    if let Ok(mut slot) = CLOUD_MCP_LIVE_APP_WS_HOST
        .get_or_init(|| StdMutex::new(None))
        .lock()
    {
        *slot = None;
    }
    if let Ok(mut slot) = CLOUD_MCP_LAST_DIRECT_ROUTE
        .get_or_init(|| StdMutex::new(None))
        .lock()
    {
        *slot = None;
    }
}

fn cloud_mcp_route_token_expiry_seconds(route_token: &str) -> Option<u64> {
    cloud_mcp_route_token_payload(route_token)?
        .get("exp")?
        .as_u64()
}

fn cloud_mcp_route_token_payload(route_token: &str) -> Option<Value> {
    let (payload_b64, _) = route_token.split_once('.')?;
    let payload = general_purpose::URL_SAFE_NO_PAD.decode(payload_b64).ok()?;
    serde_json::from_slice::<Value>(&payload).ok()
}

fn cloud_mcp_route_token_scope_allows_endpoint(route_token: &str, endpoint_path: &str) -> bool {
    let Some(payload) = cloud_mcp_route_token_payload(route_token) else {
        return false;
    };
    let Some(paths) = payload.get("allowed_paths") else {
        return true;
    };
    let Some(paths) = paths.as_array() else {
        return false;
    };
    if paths.is_empty() {
        return false;
    }
    let endpoint_path = if endpoint_path.starts_with('/') {
        endpoint_path.to_string()
    } else {
        format!("/{endpoint_path}")
    };
    paths.iter().any(|path| {
        let path = path.as_str().unwrap_or_default().trim();
        if path == "/" {
            return true;
        }
        if let Some(prefix) = path.strip_suffix("/*") {
            let prefix = prefix.trim_end_matches('/');
            return endpoint_path == prefix || endpoint_path.starts_with(&format!("{prefix}/"));
        }
        endpoint_path == path
    })
}

fn cloud_mcp_clean_endpoint_path(value: &str) -> String {
    let trimmed = value.trim();
    if trimmed.starts_with('/') {
        trimmed.to_string()
    } else {
        format!("/{trimmed}")
    }
}

fn cloud_mcp_clean_host(value: &str) -> String {
    let raw = value
        .split(',')
        .next()
        .unwrap_or_default()
        .trim()
        .to_ascii_lowercase();
    if let Some(rest) = raw.strip_prefix('[') {
        if let Some(end) = rest.find(']') {
            return rest[..end].to_string();
        }
    }
    raw.split(':')
        .next()
        .unwrap_or_default()
        .trim_end_matches('.')
        .to_string()
}

fn cloud_mcp_direct_gateway_parts(pathname: &str) -> Option<(String, String)> {
    const PREFIX: &str = "/_diffforge/instances/";
    let rest = pathname.strip_prefix(PREFIX)?;
    let (instance_id, upstream) = rest.split_once('/').unwrap_or((rest, ""));
    let upstream_path = if upstream.is_empty() {
        "/".to_string()
    } else {
        format!("/{upstream}")
    };
    Some((instance_id.to_string(), upstream_path))
}

fn cloud_mcp_route_token_compatible_with_url(
    route_token: &str,
    ws_url: &str,
    endpoint_path: &str,
) -> bool {
    let Some(payload) = cloud_mcp_route_token_payload(route_token) else {
        return false;
    };
    if payload.get("scope").and_then(Value::as_str) != Some("cloud_ws") {
        return false;
    }
    let Ok(url) = reqwest::Url::parse(ws_url) else {
        return false;
    };
    let requested_path = cloud_mcp_clean_endpoint_path(endpoint_path);
    let gateway = cloud_mcp_direct_gateway_parts(url.path());
    let upstream_path = gateway
        .as_ref()
        .map(|(_, path)| path.as_str())
        .unwrap_or_else(|| url.path());
    if cloud_mcp_clean_endpoint_path(upstream_path) != requested_path {
        return false;
    }
    if !cloud_mcp_route_token_scope_allows_endpoint(route_token, upstream_path) {
        return false;
    }
    let route_mode = payload
        .get("route_mode")
        .and_then(Value::as_str)
        .unwrap_or_default();
    let Some((instance_id, _)) = gateway else {
        return route_mode.is_empty() || route_mode == "direct_cloud_container";
    };
    let node_dns = payload
        .get("node_dns")
        .and_then(Value::as_str)
        .unwrap_or_default();
    route_mode == "node_dns_gateway"
        && payload.get("backend_id").and_then(Value::as_str) == Some(instance_id.as_str())
        && cloud_mcp_clean_host(node_dns)
            == cloud_mcp_clean_host(url.host_str().unwrap_or_default())
        && !payload
            .get("container_port")
            .unwrap_or(&Value::Null)
            .is_null()
}

fn cloud_mcp_note_direct_route(target: &CloudMcpWsTarget) {
    let Some(route_token) = target.route_token.clone() else {
        return;
    };
    let Some(expires_at_s) = cloud_mcp_route_token_expiry_seconds(&route_token) else {
        return;
    };
    if let Ok(mut slot) = CLOUD_MCP_LAST_DIRECT_ROUTE
        .get_or_init(|| StdMutex::new(None))
        .lock()
    {
        *slot = Some(CloudMcpLastDirectRoute {
            ws_url: target.ws_url.clone(),
            transport: target.transport.clone(),
            route_token,
            expires_at_s,
        });
    }
}

fn cloud_mcp_last_direct_route_fresh(endpoint_path: &str) -> Option<CloudMcpWsTarget> {
    let cached = CLOUD_MCP_LAST_DIRECT_ROUTE
        .get_or_init(|| StdMutex::new(None))
        .lock()
        .ok()?
        .clone()?;
    let now_s = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs();
    if cached.expires_at_s <= now_s.saturating_add(CLOUD_MCP_ROUTE_TOKEN_REUSE_MARGIN_SECS) {
        return None;
    }
    if !cloud_mcp_route_token_scope_allows_endpoint(&cached.route_token, endpoint_path) {
        return None;
    }
    let ws_url = cloud_mcp_rewrite_ws_endpoint(&cached.ws_url, endpoint_path);
    if !cloud_mcp_route_token_compatible_with_url(&cached.route_token, &ws_url, endpoint_path) {
        return None;
    }
    Some(CloudMcpWsTarget {
        ws_url,
        route_token: Some(cached.route_token),
        transport: cached.transport,
    })
}

/// Mints a fresh direct route token over the always-open app websocket and
/// derives the endpoint target from the connected host. This shortcut is only
/// valid for direct container routes; node-gateway routes need balancer-issued
/// tokens because the gateway validates node DNS, container port, and path
/// claims that the backend cannot mint for itself.
async fn cloud_mcp_resolve_ws_target_via_app_ws(
    state: &CloudMcpState,
    endpoint_path: &str,
) -> Result<CloudMcpWsTarget, String> {
    let (app_ws_url, transport) = cloud_mcp_live_app_ws_host()
        .ok_or_else(|| "Cloud app websocket host is not known yet.".to_string())?;
    // Minimal inline request path on purpose: cloud_mcp_ws_request_* starts
    // the global ws loop, and that loop awaits this resolver — calling it
    // here would make the resolver futures cyclic. The caller already gates
    // on a connected app websocket, so only an existing sender is used.
    let tx = state
        .global_ws_tx
        .lock()
        .await
        .as_ref()
        .cloned()
        .filter(|tx| !tx.is_closed())
        .ok_or_else(|| "Cloud app websocket is not accepting messages.".to_string())?;
    let auth = cloud_mcp_ws_auth_object(state).await?;
    let request_id = format!("ws-{}-{}", cloud_mcp_now_ms(), uuid::Uuid::new_v4());
    let (response_tx, response_rx) = oneshot::channel::<Value>();
    state
        .global_ws_pending
        .lock()
        .await
        .insert(request_id.clone(), response_tx);
    let envelope = json!({
        "kind": "direct_route_token_refresh",
        "id": request_id,
        "contract": "diffforge.app_ws.v1",
        "auth": auth,
        "client_id": CLOUD_MCP_RUST_CLIENT_ID,
        "request": json!({
            "endpoint_path": endpoint_path,
        }),
    });
    if tx.send(envelope).is_err() {
        state.global_ws_pending.lock().await.remove(&request_id);
        return Err("Cloud app websocket is not accepting messages.".to_string());
    }
    let response = match timeout(
        Duration::from_secs(CLOUD_MCP_WS_READY_TIMEOUT_SECS),
        response_rx,
    )
    .await
    {
        Ok(Ok(response)) => response,
        Ok(Err(_)) => {
            state.global_ws_pending.lock().await.remove(&request_id);
            return Err("Cloud app websocket route token response was cancelled.".to_string());
        }
        Err(_) => {
            state.global_ws_pending.lock().await.remove(&request_id);
            return Err("Cloud app websocket route token request timed out.".to_string());
        }
    };
    if response.get("ok").and_then(Value::as_bool) == Some(false)
        || response.get("kind").and_then(Value::as_str) == Some("error")
    {
        let message = response["error"]["message"]
            .as_str()
            .unwrap_or("Cloud app websocket route token refresh failed.");
        return Err(message.to_string());
    }
    let route_token = response["route_token"]
        .as_str()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| "Cloud app websocket returned no route token.".to_string())?
        .to_string();
    let response_ws_url = response["websocket_url"]
        .as_str()
        .or_else(|| response["route"]["websocket_url"].as_str())
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or(app_ws_url.as_str());
    let ws_url = cloud_mcp_rewrite_ws_endpoint(response_ws_url, endpoint_path);
    if !cloud_mcp_route_token_scope_allows_endpoint(&route_token, endpoint_path)
        || !cloud_mcp_route_token_compatible_with_url(&route_token, &ws_url, endpoint_path)
    {
        return Err(format!(
            "Cloud app websocket route token is not compatible with {endpoint_path}; resolving through the balancer."
        ));
    }
    let target = CloudMcpWsTarget {
        ws_url,
        route_token: Some(route_token),
        transport,
    };
    cloud_mcp_note_direct_route(&target);
    Ok(target)
}

async fn cloud_mcp_resolve_ws_target(
    state: &CloudMcpState,
    base_url: &str,
    endpoint_path: &str,
) -> Result<CloudMcpWsTarget, String> {
    let local_docker_target = cloud_mcp_local_docker_ws_target(endpoint_path);

    // The always-open live sync websocket can derive dedicated websocket routes
    // for direct container/local connections. Node-gateway routes fall back to
    // the balancer so the route token includes the gateway-required node and
    // path binding.
    if endpoint_path != "/v1/app/ws" {
        let app_ws_connected = { state.inner.lock().await.global_ws_connected };
        if app_ws_connected {
            match cloud_mcp_resolve_ws_target_via_app_ws(state, endpoint_path).await {
                Ok(target) => {
                    cloud_mcp_record_signin_diagnostic(
                        state,
                        "route.resolve",
                        "ok",
                        "Cloud MCP route derived from the live app websocket",
                        json!({
                            "transport": target.transport,
                            "ws_url": target.ws_url,
                            "source": "app_ws",
                        }),
                    )
                    .await;
                    return Ok(target);
                }
                Err(error) => {
                    cloud_mcp_record_signin_diagnostic(
                        state,
                        "route.resolve",
                        "warn",
                        &format!(
                            "Live app websocket route derivation failed; falling back to the balancer: {error}"
                        ),
                        json!({"transport": "app_ws_derive"}),
                    )
                    .await;
                }
            }
        }
    }

    cloud_mcp_set_global_ws_phase(state, "authenticating", "authenticating").await;
    let bearer = match cloud_mcp_authorization_bearer(state).await {
        Ok(token) => token,
        Err(error) => {
            if cloud_mcp_error_text_is_device_limit(&error) {
                cloud_mcp_mark_registration_blocked(
                    state,
                    error.clone(),
                    json!({"source": "route.resolve"}),
                )
                .await;
                return Err(error);
            }
            let message = format!("Unable to prepare Cloud MCP route auth: {error}");
            cloud_mcp_record_signin_diagnostic(
                state,
                "route.resolve",
                "error",
                &message,
                json!({"transport": "direct_route_unavailable"}),
            )
            .await;
            return Err(message);
        }
    };
    let Some(bearer) = bearer else {
        if let Some(target) = local_docker_target {
            cloud_mcp_record_signin_diagnostic(
                state,
                "route.resolve",
                "ok",
                "Cloud MCP local Docker websocket route selected without account auth",
                json!({"transport": target.transport, "ws_url": target.ws_url}),
            )
            .await;
            return Ok(target);
        }
        return Err(
            "Cloud MCP auth token is unavailable; waiting for sign-in before resolving a route."
                .to_string(),
        );
    };

    let (billing_scope_type, team_id) = cloud_mcp_account_scope(state).await;
    let (plan_name, device_limit) = cloud_mcp_account_plan(state).await;
    let device_profile = cloud_mcp_desktop_device_profile();
    let device_id = cloud_mcp_payload_text(&device_profile, &["device_id"]);
    let _ = cloud_mcp_send_device_heartbeat_if_due(
        state,
        base_url,
        &bearer,
        &billing_scope_type,
        team_id.as_deref(),
        &plan_name,
        device_limit,
        &device_profile,
        "connected",
    )
    .await;
    cloud_mcp_set_global_ws_phase(state, "resolving_route", "resolving_route").await;
    let route_started = Instant::now();
    let mut route_attempt: u64 = 0;
    loop {
        route_attempt = route_attempt.saturating_add(1);
        match cloud_mcp_fetch_direct_route_async(
            base_url,
            endpoint_path,
            &bearer,
            &billing_scope_type,
            team_id.as_deref(),
            &plan_name,
            device_limit,
            device_id.as_deref(),
        )
        .await
        {
            Ok(Some(target)) => {
                cloud_mcp_note_direct_route(&target);
                cloud_mcp_record_signin_diagnostic(
                    state,
                    "route.resolve",
                    "ok",
                    "Cloud MCP direct route resolved",
                    json!({
                        "attempt": route_attempt,
                        "elapsed_ms": route_started.elapsed().as_millis() as u64,
                        "transport": target.transport,
                        "ws_url": target.ws_url
                    }),
                )
                .await;
                return Ok(target);
            }
            Ok(None) => {
                let message = "Balancer did not offer a direct route (direct routing disabled or backend unsupported).".to_string();
                if let Some(target) = cloud_mcp_last_direct_route_fresh(endpoint_path) {
                    cloud_mcp_record_signin_diagnostic(
                        state,
                        "route.resolve",
                        "warn",
                        "Balancer offered no direct route; reusing the last known direct route",
                        json!({"transport": target.transport, "ws_url": target.ws_url}),
                    )
                    .await;
                    return Ok(target);
                }
                if cloud_mcp_should_retry_no_direct_route_offer(route_attempt) {
                    cloud_mcp_set_global_ws_phase(
                        state,
                        "route_initializing",
                        "route_initializing",
                    )
                    .await;
                    let sleep_for = cloud_mcp_no_direct_route_offer_retry_delay();
                    cloud_mcp_record_signin_diagnostic(
                        state,
                        "route.resolve",
                        "info",
                        "Balancer offered no direct route; retrying briefly for transient route state",
                        json!({
                            "attempt": route_attempt,
                            "elapsed_ms": route_started.elapsed().as_millis() as u64,
                            "poll_ms": sleep_for.as_millis() as u64,
                            "transport": "direct_route_unavailable",
                        }),
                    )
                    .await;
                    tokio::select! {
                        _ = sleep(sleep_for) => {}
                        _ = state.global_ws_reconnect.notified() => {
                            return Err("Cloud MCP route retry was interrupted by a reconnect request.".to_string());
                        }
                    }
                    continue;
                }
                cloud_mcp_record_signin_diagnostic(
                    state,
                    "route.resolve",
                    "error",
                    &message,
                    json!({"transport": "direct_route_unavailable"}),
                )
                .await;
                return Err(message);
            }
            Err(error) => {
                if cloud_mcp_route_error_runtime_status(&error) == Some("route_initializing") {
                    cloud_mcp_set_global_ws_phase(
                        state,
                        "route_initializing",
                        "route_initializing",
                    )
                    .await;
                    cloud_mcp_reconnect_window_reset(state);
                    let elapsed = route_started.elapsed();
                    if elapsed >= Duration::from_secs(CLOUD_MCP_ROUTE_INITIALIZING_TIMEOUT_SECS) {
                        let message = format!(
                            "Cloud MCP route initialization timed out after {CLOUD_MCP_ROUTE_INITIALIZING_TIMEOUT_SECS}s."
                        );
                        cloud_mcp_record_signin_diagnostic(
                            state,
                            "route.resolve",
                            "error",
                            &message,
                            json!({
                                "attempt": route_attempt,
                                "elapsed_ms": elapsed.as_millis() as u64,
                                "last_error": clean_terminal_telemetry_text(&error),
                                "transport": "direct_route_unavailable"
                            }),
                        )
                        .await;
                        return Err(message);
                    }

                    let poll_delay = cloud_mcp_route_initializing_poll_delay(&error);
                    let remaining = Duration::from_secs(CLOUD_MCP_ROUTE_INITIALIZING_TIMEOUT_SECS)
                        .saturating_sub(elapsed);
                    let sleep_for = poll_delay.min(remaining);
                    cloud_mcp_record_signin_diagnostic(
                        state,
                        "route.resolve",
                        "info",
                        "Cloud MCP route is initializing; polling for readiness",
                        json!({
                            "attempt": route_attempt,
                            "elapsed_ms": elapsed.as_millis() as u64,
                            "poll_ms": sleep_for.as_millis() as u64,
                            "retry_after_ms": cloud_mcp_route_error_retry_after_ms(&error),
                        }),
                    )
                    .await;
                    tokio::select! {
                        _ = sleep(sleep_for) => {}
                        _ = state.global_ws_reconnect.notified() => {
                            return Err("Cloud MCP route initialization was interrupted by a reconnect request.".to_string());
                        }
                    }
                    continue;
                }

                let message = format!("Cloud MCP direct route unavailable: {error}");
                if let Some(target) = cloud_mcp_last_direct_route_fresh(endpoint_path) {
                    cloud_mcp_record_signin_diagnostic(
                        state,
                        "route.resolve",
                        "warn",
                        &format!("Balancer route request failed; reusing the last known direct route: {error}"),
                        json!({"transport": target.transport, "ws_url": target.ws_url}),
                    )
                    .await;
                    return Ok(target);
                }
                cloud_mcp_record_signin_diagnostic(
                    state,
                    "route.resolve",
                    "error",
                    &message,
                    json!({"transport": "direct_route_unavailable"}),
                )
                .await;
                return Err(message);
            }
        }
    }
}

fn cloud_mcp_rewrite_ws_endpoint(ws_url: &str, endpoint_path: &str) -> String {
    let ws_url = ws_url.trim();
    let endpoint_path = if endpoint_path.starts_with('/') {
        endpoint_path.to_string()
    } else {
        format!("/{endpoint_path}")
    };

    for suffix in ["/v1/app/ws", "/v1/voice/ws"] {
        if let Some(base) = ws_url.strip_suffix(suffix) {
            return format!("{base}{endpoint_path}");
        }
    }

    if let Some(index) = ws_url.find("/v1/") {
        return format!("{}{}", &ws_url[..index], endpoint_path);
    }

    format!("{}{}", ws_url.trim_end_matches('/'), endpoint_path)
}

fn cloud_mcp_http_url_from_ws_url(ws_url: &str) -> Option<String> {
    let trimmed = ws_url.trim();
    if let Some(rest) = trimmed.strip_prefix("wss://") {
        return Some(format!("https://{rest}"));
    }
    if let Some(rest) = trimmed.strip_prefix("ws://") {
        return Some(format!("http://{rest}"));
    }
    if trimmed.starts_with("https://") || trimmed.starts_with("http://") {
        return Some(trimmed.to_string());
    }
    None
}

fn cloud_mcp_ws_url_from_http_base_url(base_url: &str, endpoint_path: &str) -> Option<String> {
    let trimmed = base_url.trim().trim_end_matches('/');
    let ws_base = if let Some(rest) = trimmed.strip_prefix("https://") {
        format!("wss://{rest}")
    } else if let Some(rest) = trimmed.strip_prefix("http://") {
        format!("ws://{rest}")
    } else if trimmed.starts_with("ws://") || trimmed.starts_with("wss://") {
        trimmed.to_string()
    } else {
        return None;
    };
    Some(cloud_mcp_rewrite_ws_endpoint(&ws_base, endpoint_path))
}

fn cloud_mcp_http_url_with_route_token(url: String, route_token: Option<&str>) -> String {
    let Some(route_token) = route_token
        .map(str::trim)
        .filter(|route_token| !route_token.is_empty())
    else {
        return url;
    };
    let separator = if url.contains('?') { '&' } else { '?' };
    format!("{url}{separator}route_token={route_token}")
}

async fn cloud_mcp_asset_resolve_direct_target_async(
    state: &CloudMcpState,
    base_url: &str,
    endpoint_path: &str,
) -> Result<CloudMcpWsTarget, String> {
    let bearer = cloud_mcp_authorization_bearer(state).await?;
    let Some(bearer) = bearer else {
        if let Some(target) = cloud_mcp_local_docker_ws_target(endpoint_path) {
            return Ok(target);
        }
        return Err(
            "Cloud MCP auth token is unavailable; waiting for sign-in before resolving an asset route."
                .to_string(),
        );
    };
    let app_ws_connected = { state.inner.lock().await.global_ws_connected };
    if app_ws_connected {
        if let Ok(target) = cloud_mcp_resolve_ws_target_via_app_ws(state, endpoint_path).await {
            return Ok(target);
        }
    }
    let (billing_scope_type, team_id) = cloud_mcp_account_scope(state).await;
    let (plan_name, device_limit) = cloud_mcp_account_plan(state).await;
    let device_profile = cloud_mcp_desktop_device_profile();
    let device_id = cloud_mcp_payload_text(&device_profile, &["device_id"]);
    match cloud_mcp_fetch_direct_route_async(
        base_url,
        endpoint_path,
        &bearer,
        &billing_scope_type,
        team_id.as_deref(),
        &plan_name,
        device_limit,
        device_id.as_deref(),
    )
    .await
    {
        Ok(Some(target)) => {
            cloud_mcp_note_direct_route(&target);
            Ok(target)
        }
        Ok(None) => cloud_mcp_last_direct_route_fresh(endpoint_path).ok_or_else(|| {
            "Balancer did not offer a direct asset route (direct routing disabled or backend unsupported)."
                .to_string()
        }),
        Err(error) => cloud_mcp_last_direct_route_fresh(endpoint_path)
            .ok_or_else(|| format!("Cloud MCP direct route unavailable: {error}")),
    }
}

fn cloud_mcp_asset_resolve_direct_target_blocking(
    base_url: &str,
    endpoint_path: &str,
) -> Result<CloudMcpWsTarget, String> {
    let Some(bearer) = cloud_mcp_process_authorization_bearer() else {
        if let Some(target) = cloud_mcp_local_docker_ws_target(endpoint_path) {
            return Ok(target);
        }
        return Err(
            "Cloud MCP auth token is unavailable; waiting for sign-in before resolving an asset route."
                .to_string(),
        );
    };
    if let Some(target) = cloud_mcp_last_direct_route_fresh(endpoint_path) {
        return Ok(target);
    }
    let (billing_scope_type, team_id) = cloud_mcp_process_account_scope();
    let (plan_name, device_limit) = cloud_mcp_process_account_plan();
    let device_profile = cloud_mcp_desktop_device_profile();
    let device_id = cloud_mcp_payload_text(&device_profile, &["device_id"]);
    match cloud_mcp_fetch_direct_route_blocking(
        base_url,
        endpoint_path,
        &bearer,
        &billing_scope_type,
        team_id.as_deref(),
        &plan_name,
        device_limit,
        device_id.as_deref(),
    )
    {
        Ok(Some(target)) => {
            cloud_mcp_note_direct_route(&target);
            Ok(target)
        }
        Ok(None) => cloud_mcp_last_direct_route_fresh(endpoint_path).ok_or_else(|| {
            "Balancer did not offer a direct asset route (direct routing disabled or backend unsupported)."
                .to_string()
        }),
        Err(error) => cloud_mcp_last_direct_route_fresh(endpoint_path)
            .ok_or_else(|| format!("Cloud MCP direct route unavailable: {error}")),
    }
}

async fn cloud_mcp_asset_http_target_async(
    state: &CloudMcpState,
    endpoint_path: &str,
) -> Result<CloudMcpAssetHttpTarget, String> {
    let base_url = cloud_mcp_base_url();
    let target = cloud_mcp_asset_resolve_direct_target_async(state, &base_url, endpoint_path)
        .await
        .map_err(|error| format!("Cloud asset direct route unavailable: {error}"))?;
    let url = cloud_mcp_http_url_from_ws_url(&target.ws_url)
        .ok_or_else(|| "Cloud asset direct route URL is invalid.".to_string())?;
    Ok(CloudMcpAssetHttpTarget {
        url,
        route_token: target.route_token,
    })
}

fn cloud_mcp_asset_http_target_blocking(
    base_url: &str,
    endpoint_path: &str,
) -> Result<CloudMcpAssetHttpTarget, String> {
    let target = cloud_mcp_asset_resolve_direct_target_blocking(base_url, endpoint_path)
        .map_err(|error| format!("Cloud asset direct route unavailable: {error}"))?;
    let url = cloud_mcp_http_url_from_ws_url(&target.ws_url)
        .ok_or_else(|| "Cloud asset direct route URL is invalid.".to_string())?;
    Ok(CloudMcpAssetHttpTarget {
        url,
        route_token: target.route_token,
    })
}

fn cloud_mcp_internal_api_http_target_blocking(
    base_url: &str,
    endpoint_path: &str,
) -> Result<CloudMcpAssetHttpTarget, String> {
    if let Some(target) = cloud_mcp_local_docker_ws_target(endpoint_path) {
        let url = cloud_mcp_http_url_from_ws_url(&target.ws_url)
            .ok_or_else(|| "Cloud internal API local Docker URL is invalid.".to_string())?;
        return Ok(CloudMcpAssetHttpTarget {
            url,
            route_token: None,
        });
    }

    cloud_mcp_asset_http_target_blocking(base_url, endpoint_path)
}

fn cloud_mcp_asset_direct_presigned(_payload: &Value) -> bool {
    // B2 credentials and object URLs stay server-side; desktop transfers only
    // talk to cloud-diffforge.
    false
}

fn cloud_mcp_asset_prepare_transfer_id(payload: &Value, direction: &str) -> Result<String, String> {
    cloud_mcp_payload_text(payload, &["transfer_id", "id"])
        .or_else(|| cloud_mcp_payload_text(payload, &["transfer", "transfer_id"]))
        .or_else(|| cloud_mcp_payload_text(payload, &["transfer", "id"]))
        .ok_or_else(|| format!("Cloud did not return an asset {direction} transfer id."))
}

fn cloud_mcp_local_docker_ws_target(endpoint_path: &str) -> Option<CloudMcpWsTarget> {
    if !cloud_mcp_local_cloud_probe_enabled() {
        return None;
    }

    let explicit_voice_url = if endpoint_path == "/v1/voice/ws" {
        env::var(CLOUD_MCP_LOCAL_DOCKER_VOICE_WS_URL_ENV)
            .ok()
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
    } else {
        None
    };
    let configured_url = explicit_voice_url.or_else(|| {
        env::var(CLOUD_MCP_LOCAL_DOCKER_APP_WS_URL_ENV)
            .ok()
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
    });
    let configured_base_url =
        cloud_mcp_configured_base_url().filter(|value| cloud_mcp_local_http_url_allowed(value));
    let ws_url = configured_url
        .map(|value| cloud_mcp_rewrite_ws_endpoint(&value, endpoint_path))
        .or_else(|| {
            configured_base_url
                .as_deref()
                .and_then(|value| cloud_mcp_ws_url_from_http_base_url(value, endpoint_path))
        })
        .unwrap_or_else(|| {
            cloud_mcp_rewrite_ws_endpoint(CLOUD_MCP_LOCAL_DOCKER_APP_WS_URL, endpoint_path)
        });
    if !(ws_url.starts_with("ws://") || ws_url.starts_with("wss://")) {
        return None;
    }
    if !cloud_mcp_local_cloud_available_blocking(&ws_url) {
        return None;
    }

    Some(CloudMcpWsTarget {
        ws_url,
        route_token: None,
        transport: "local_docker_cloud".to_string(),
    })
}

fn cloud_mcp_local_cloud_probe_enabled() -> bool {
    cloud_mcp_env_flag("RUST_DIFFFORGE_USE_LOCAL_DOCKER_CLOUD")
        .or_else(|| cloud_mcp_env_flag(CLOUD_MCP_ALLOW_LOCAL_CLOUD_ENV))
        .or_else(|| {
            cloud_mcp_configured_base_url()
                .as_deref()
                .filter(|value| cloud_mcp_local_http_url_allowed(value))
                .map(|_| true)
        })
        .unwrap_or(CLOUD_MCP_LOCAL_DOCKER_APP_WS_OVERRIDE_ENABLED)
}

fn cloud_mcp_local_cloud_available_blocking(ws_url: &str) -> bool {
    let Some(ready_url) = cloud_mcp_local_cloud_ready_url_from_ws_url(ws_url) else {
        return false;
    };
    if !cloud_mcp_local_http_url_allowed(&ready_url) {
        return false;
    }

    static LOCAL_CLOUD_HEALTH_CACHE: OnceLock<StdMutex<HashMap<String, (bool, u64)>>> =
        OnceLock::new();
    let now = cloud_mcp_now_ms();
    let cache = LOCAL_CLOUD_HEALTH_CACHE.get_or_init(|| StdMutex::new(HashMap::new()));
    if let Ok(cache_guard) = cache.lock() {
        if let Some((available, checked_ms)) = cache_guard.get(&ready_url) {
            if now.saturating_sub(*checked_ms) < CLOUD_MCP_LOCAL_CLOUD_HEALTH_CACHE_MS {
                return *available;
            }
        }
    }

    let available = cloud_mcp_probe_local_http_health(&ready_url, Duration::from_millis(750));
    if let Ok(mut cache_guard) = cache.lock() {
        cache_guard.insert(ready_url, (available, now));
    }
    available
}

fn cloud_mcp_parse_local_http_health_url(url: &str) -> Option<(String, u16, String)> {
    let rest = url.trim().strip_prefix("http://")?;
    let (host, port_and_path) = if let Some(rest) = rest.strip_prefix('[') {
        let end = rest.find(']')?;
        let host = rest[..end].to_string();
        let port_and_path = rest[end + 1..].strip_prefix(':')?;
        (host, port_and_path)
    } else {
        let (authority, path) = rest.split_once('/').unwrap_or((rest, ""));
        let (host, port) = authority.rsplit_once(':')?;
        return Some((
            host.to_string(),
            port.parse::<u16>().ok()?,
            format!("/{}", path.trim_start_matches('/')),
        ));
    };
    let (port, path) = port_and_path.split_once('/').unwrap_or((port_and_path, ""));
    Some((
        host,
        port.parse::<u16>().ok()?,
        format!("/{}", path.trim_start_matches('/')),
    ))
}

fn cloud_mcp_local_health_socket_addrs(host: &str, port: u16) -> Vec<std::net::SocketAddr> {
    match host {
        "127.0.0.1" => vec![std::net::SocketAddr::from(([127, 0, 0, 1], port))],
        "localhost" => vec![
            std::net::SocketAddr::from(([127, 0, 0, 1], port)),
            std::net::SocketAddr::from((std::net::Ipv6Addr::LOCALHOST, port)),
        ],
        "::1" => vec![std::net::SocketAddr::from((
            std::net::Ipv6Addr::LOCALHOST,
            port,
        ))],
        _ => Vec::new(),
    }
}

fn cloud_mcp_probe_local_http_health(url: &str, timeout_duration: Duration) -> bool {
    let Some((host, port, path)) = cloud_mcp_parse_local_http_health_url(url) else {
        return false;
    };
    for address in cloud_mcp_local_health_socket_addrs(&host, port) {
        let Ok(mut stream) = std::net::TcpStream::connect_timeout(&address, timeout_duration)
        else {
            continue;
        };
        let _ = stream.set_read_timeout(Some(timeout_duration));
        let _ = stream.set_write_timeout(Some(timeout_duration));
        let request =
            format!("GET {path} HTTP/1.1\r\nHost: {host}:{port}\r\nConnection: close\r\n\r\n");
        if stream.write_all(request.as_bytes()).is_err() {
            continue;
        }
        let mut response = [0_u8; 64];
        let Ok(read) = stream.read(&mut response) else {
            continue;
        };
        if read == 0 {
            continue;
        }
        let status_line = String::from_utf8_lossy(&response[..read]);
        if status_line.starts_with("HTTP/1.1 2") || status_line.starts_with("HTTP/1.0 2") {
            return true;
        }
    }
    false
}

fn cloud_mcp_local_http_url_allowed(url: &str) -> bool {
    let lower = url.trim().to_ascii_lowercase();
    lower.starts_with("http://127.0.0.1:")
        || lower.starts_with("http://localhost:")
        || lower.starts_with("http://[::1]:")
}

fn cloud_mcp_local_cloud_ready_url_from_ws_url(ws_url: &str) -> Option<String> {
    cloud_mcp_http_url_from_ws_url(&cloud_mcp_rewrite_ws_endpoint(ws_url, "/v1/ready"))
}

fn cloud_mcp_local_cloud_base_url_from_ws_url(ws_url: &str) -> Option<String> {
    let health_url = cloud_mcp_local_cloud_ready_url_from_ws_url(ws_url)?;
    Some(
        health_url
            .trim_end_matches("/v1/ready")
            .trim_end_matches('/')
            .to_string(),
    )
}

fn cloud_mcp_local_cloud_base_url_if_available_blocking() -> Option<String> {
    let target = cloud_mcp_local_docker_ws_target("/v1/app/ws")?;
    cloud_mcp_local_cloud_base_url_from_ws_url(&target.ws_url)
        .or_else(|| Some(CLOUD_MCP_LOCAL_CLOUD_BASE_URL.to_string()))
}

async fn cloud_mcp_send_device_heartbeat_if_due(
    state: &CloudMcpState,
    base_url: &str,
    bearer: &str,
    billing_scope_type: &str,
    team_id: Option<&str>,
    plan_name: &str,
    device_limit: Option<u64>,
    device_profile: &Value,
    status: &str,
) -> Result<(), String> {
    let now = cloud_mcp_now_ms();
    {
        let mut runtime = state.inner.lock().await;
        if runtime
            .last_device_heartbeat_ms
            .is_some_and(|last| now.saturating_sub(last) < CLOUD_MCP_DEVICE_HEARTBEAT_INTERVAL_MS)
        {
            return Ok(());
        }
        runtime.last_device_heartbeat_ms = Some(now);
    }

    cloud_mcp_send_device_heartbeat_async(
        base_url,
        bearer,
        billing_scope_type,
        team_id,
        plan_name,
        device_limit,
        device_profile,
        status,
    )
    .await
}

async fn cloud_mcp_send_device_heartbeat_async(
    base_url: &str,
    bearer: &str,
    billing_scope_type: &str,
    team_id: Option<&str>,
    plan_name: &str,
    device_limit: Option<u64>,
    device_profile: &Value,
    status: &str,
) -> Result<(), String> {
    let url = format!("{}/v1/devices/heartbeat", base_url.trim_end_matches('/'));
    let device_id = cloud_mcp_payload_text(device_profile, &["device_id"])
        .ok_or_else(|| "Device heartbeat requires a stable device id.".to_string())?;
    let body = json!({
        "billing_scope_type": billing_scope_type,
        "scope_type": billing_scope_type,
        "team_id": team_id,
        "plan_name": plan_name,
        "device_limit": device_limit,
        "device_id": device_id,
        "device_name": cloud_mcp_payload_text(device_profile, &["device_name"]),
        "machine_name": cloud_mcp_payload_text(device_profile, &["machine_name"]),
        "hostname": cloud_mcp_payload_text(device_profile, &["hostname"]),
        "device_key_id": cloud_mcp_payload_text(device_profile, &["device_key_id"]),
        "device_public_key": cloud_mcp_payload_text(device_profile, &["device_public_key"]),
        "device_key_algorithm": cloud_mcp_payload_text(device_profile, &["device_key_algorithm"]),
        "platform": cloud_mcp_payload_text(device_profile, &["platform"]),
        "os": cloud_mcp_payload_text(device_profile, &["os"]),
        "form_factor": cloud_mcp_payload_text(device_profile, &["form_factor"]),
        "device_type": cloud_mcp_payload_text(device_profile, &["device_type"]),
        "status": status,
    });
    let response = shared_async_http_client()
        .post(url)
        .timeout(Duration::from_secs(CLOUD_MCP_AUTH_TIMEOUT_SECS))
        .header("Authorization", format!("Bearer {bearer}"))
        .header("x-diffforge-actor", CLOUD_MCP_RUST_CLIENT_ID)
        .header("x-diffforge-billing-scope-type", billing_scope_type)
        .header("x-diffforge-scope-type", billing_scope_type)
        .header("x-diffforge-plan-name", plan_name)
        .headers({
            let mut headers = reqwest::header::HeaderMap::new();
            if let Some(device_limit) = device_limit {
                if let Ok(value) = reqwest::header::HeaderValue::from_str(&device_limit.to_string())
                {
                    headers.insert("x-diffforge-device-limit", value);
                }
            }
            if let Ok(value) = reqwest::header::HeaderValue::from_str(&device_id) {
                headers.insert("x-diffforge-device-id", value);
            }
            headers
        })
        .json(&body)
        .send()
        .await
        .map_err(|error| format!("Device heartbeat request failed: {error}"))?;
    if !response.status().is_success() {
        let status = response.status();
        let text = response.text().await.unwrap_or_default();
        return Err(format!("Device heartbeat returned {status}: {text}"));
    }
    Ok(())
}

/// Coarse latency hint for region-aware balancer placement, derived from the
/// system timezone (the /etc/localtime symlink on macOS/Linux). Values match
/// the balancer's location categories: "us-east", "us-west", "eu", "asia".
/// None on platforms where the zone cannot be read; the balancer then uses
/// its default region.
fn cloud_mcp_region_hint() -> Option<&'static str> {
    static REGION_HINT: OnceLock<Option<&'static str>> = OnceLock::new();
    *REGION_HINT.get_or_init(|| {
        let zone = fs::read_link("/etc/localtime")
            .ok()
            .map(|target| target.to_string_lossy().to_string())?;
        let zone = zone
            .split("zoneinfo/")
            .nth(1)
            .map(str::to_string)
            .unwrap_or(zone);
        let zone_lower = zone.to_ascii_lowercase();
        if zone_lower.starts_with("europe/") || zone_lower.starts_with("africa/") {
            return Some("eu");
        }
        if zone_lower.starts_with("asia/")
            || zone_lower.starts_with("australia/")
            || zone_lower.starts_with("pacific/")
            || zone_lower.starts_with("indian/")
        {
            return Some("asia");
        }
        if zone_lower.starts_with("america/")
            || zone_lower.starts_with("us/")
            || zone_lower.starts_with("canada/")
            || zone_lower.starts_with("mexico/")
        {
            let western = [
                "los_angeles",
                "vancouver",
                "tijuana",
                "phoenix",
                "denver",
                "edmonton",
                "boise",
                "whitehorse",
                "anchorage",
                "pacific",
                "mountain",
            ];
            if western.iter().any(|needle| zone_lower.contains(needle)) {
                return Some("us-west");
            }
            return Some("us-east");
        }
        None
    })
}

fn cloud_mcp_route_request_url(base_url: &str) -> String {
    let normalized = base_url.trim_end_matches('/');
    if cloud_mcp_local_http_url_allowed(normalized) {
        format!("{normalized}/v1/route")
    } else {
        api_endpoint("agents/route")
    }
}

fn cloud_mcp_route_response_content_type(headers: &reqwest::header::HeaderMap) -> String {
    headers
        .get(reqwest::header::CONTENT_TYPE)
        .and_then(|value| value.to_str().ok())
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("unknown")
        .to_string()
}

fn cloud_mcp_route_response_preview(body: &str) -> String {
    let compact = body.split_whitespace().collect::<Vec<_>>().join(" ");
    clean_terminal_telemetry_text(&compact)
        .chars()
        .take(240)
        .collect()
}

fn cloud_mcp_route_invalid_json_message(
    status: reqwest::StatusCode,
    content_type: &str,
    body: &str,
    parse_error: serde_json::Error,
) -> String {
    let preview = cloud_mcp_route_response_preview(body);
    let suffix = if preview.is_empty() {
        String::new()
    } else {
        format!("; body_preview={preview:?}")
    };
    if status.is_success() {
        return format!(
            "Cloud MCP route response was invalid JSON: HTTP {}; content-type={content_type}; parse_error={parse_error}{suffix}",
            status.as_u16()
        );
    }

    format!(
        "Cloud MCP route request returned HTTP {} with a non-JSON response; content-type={content_type}; parse_error={parse_error}{suffix}",
        status.as_u16()
    )
}

fn cloud_mcp_parse_route_response_body(
    status: reqwest::StatusCode,
    content_type: &str,
    response_text: &str,
) -> Result<Value, String> {
    if response_text.trim().is_empty() {
        return Ok(json!({}));
    }

    serde_json::from_str::<Value>(response_text).map_err(|error| {
        cloud_mcp_route_invalid_json_message(status, content_type, response_text, error)
    })
}

async fn cloud_mcp_read_route_response(
    response: reqwest::Response,
) -> Result<(reqwest::StatusCode, Value), String> {
    let status = response.status();
    let content_type = cloud_mcp_route_response_content_type(response.headers());
    let response_text = response
        .text()
        .await
        .map_err(|error| format!("Unable to read Cloud MCP route response: {error}"))?;
    let parsed = cloud_mcp_parse_route_response_body(status, &content_type, &response_text)?;
    Ok((status, parsed))
}

fn cloud_mcp_read_route_response_blocking(
    response: reqwest::blocking::Response,
) -> Result<(reqwest::StatusCode, Value), String> {
    let status = response.status();
    let content_type = cloud_mcp_route_response_content_type(response.headers());
    let response_text = response
        .text()
        .map_err(|error| format!("Unable to read Cloud MCP route response: {error}"))?;
    let parsed = cloud_mcp_parse_route_response_body(status, &content_type, &response_text)?;
    Ok((status, parsed))
}

fn cloud_mcp_route_response_message(route: &Value, fallback: &str) -> String {
    route
        .pointer("/error/message")
        .and_then(Value::as_str)
        .or_else(|| route.get("error").and_then(Value::as_str))
        .or_else(|| route.get("message").and_then(Value::as_str))
        .unwrap_or(fallback)
        .to_string()
}

fn cloud_mcp_direct_route_pending_error(route: &Value) -> Option<String> {
    let route_state = route
        .get("route_state")
        .and_then(Value::as_str)
        .unwrap_or("route_not_ready");
    let backend_status = route
        .get("backend_status")
        .and_then(Value::as_str)
        .unwrap_or("");
    let retry_after_ms = route
        .get("retry_after_ms")
        .and_then(Value::as_u64)
        .unwrap_or(0);
    let waiting = route
        .get("waiting")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let initializing = route
        .get("initializing")
        .or_else(|| route.get("initializing_workspace"))
        .and_then(Value::as_bool)
        .unwrap_or(false);

    let route_state_waiting = route_state.trim().eq_ignore_ascii_case("waiting");
    if initializing
        || waiting
        || route_state_waiting
        || cloud_mcp_route_state_is_provisioning(route_state, backend_status)
    {
        return Some(format!(
            "Cloud MCP route pending: route_state={route_state}; backend_status={backend_status}; retry_after_ms={retry_after_ms}"
        ));
    }

    None
}

fn cloud_mcp_direct_route_rejected_error(route: &Value) -> Option<String> {
    if route.get("ok").and_then(Value::as_bool) != Some(false) {
        return None;
    }
    let route_state = route
        .get("route_state")
        .and_then(Value::as_str)
        .unwrap_or("blocked");
    let message = cloud_mcp_route_response_message(route, "route rejected");
    Some(format!(
        "Cloud MCP route rejected: route_state={route_state}; {message}"
    ))
}

fn cloud_mcp_direct_route_unusable_error(route: &Value, endpoint_path: &str) -> Option<String> {
    let direct = route.get("direct").filter(|value| value.is_object())?;
    if direct.get("enabled").and_then(Value::as_bool) == Some(false) {
        return Some("Cloud MCP direct route disabled by balancer.".to_string());
    }
    let transport = direct
        .get("transport")
        .and_then(Value::as_str)
        .unwrap_or("unknown");
    let route_token_present = direct
        .get("route_token")
        .and_then(Value::as_str)
        .map(str::trim)
        .is_some_and(|value| !value.is_empty());
    Some(format!(
        "Cloud MCP direct route payload was unusable for {endpoint_path}; transport={transport}; route_token_present={route_token_present}"
    ))
}

async fn cloud_mcp_fetch_direct_route_async(
    base_url: &str,
    endpoint_path: &str,
    bearer: &str,
    billing_scope_type: &str,
    team_id: Option<&str>,
    plan_name: &str,
    device_limit: Option<u64>,
    device_id: Option<&str>,
) -> Result<Option<CloudMcpWsTarget>, String> {
    let url = cloud_mcp_route_request_url(base_url);
    let region_hint = cloud_mcp_region_hint();
    let appwrite_user_id = cloud_mcp_appwrite_user_id_for_bearer(bearer);
    let mut body = json!({
        "requested_path": endpoint_path,
        "client_id": CLOUD_MCP_RUST_CLIENT_ID,
        "billing_scope_type": billing_scope_type,
        "scope_type": billing_scope_type,
        "team_id": team_id,
        "plan_name": plan_name,
        "device_limit": device_limit,
        "device_id": device_id,
        "region_hint": region_hint,
        "wait_for_ready": false,
        "wait_ms": 0,
    });
    if let Some(user_id) = appwrite_user_id.as_deref() {
        body["appwrite_user_id"] = json!(user_id);
    }
    let response = shared_async_http_client()
        .post(url)
        .timeout(Duration::from_secs(CLOUD_MCP_AUTH_TIMEOUT_SECS))
        .header("Authorization", format!("Bearer {bearer}"))
        .header("Accept", "application/json")
        .header("x-diffforge-client-id", CLOUD_MCP_RUST_CLIENT_ID)
        .header("x-diffforge-actor", CLOUD_MCP_RUST_CLIENT_ID)
        .header("x-diffforge-billing-scope-type", billing_scope_type)
        .header("x-diffforge-scope-type", billing_scope_type)
        .header("x-diffforge-plan-name", plan_name)
        .headers({
            let mut headers = reqwest::header::HeaderMap::new();
            if let Some(device_limit) = device_limit {
                if let Ok(value) = reqwest::header::HeaderValue::from_str(&device_limit.to_string())
                {
                    headers.insert("x-diffforge-device-limit", value);
                }
            }
            if let Some(device_id) = device_id {
                if let Ok(value) = reqwest::header::HeaderValue::from_str(device_id) {
                    headers.insert("x-diffforge-device-id", value);
                }
            }
            if let Some(user_id) = appwrite_user_id.as_deref() {
                if let Ok(value) = reqwest::header::HeaderValue::from_str(user_id) {
                    headers.insert("x-diffforge-appwrite-user-id", value);
                }
            }
            if let Some(region_hint) = region_hint {
                headers.insert(
                    "x-diffforge-region-hint",
                    reqwest::header::HeaderValue::from_static(region_hint),
                );
            }
            headers
        })
        .json(&body)
        .send()
        .await
        .map_err(|error| format!("Cloud MCP route request failed: {error}"))?;
    let (status, parsed) = cloud_mcp_read_route_response(response).await?;
    if !status.is_success() {
        return Err(format!(
            "Cloud MCP route request returned {}: {}",
            status.as_u16(),
            cloud_mcp_route_response_message(&parsed, "route rejected")
        ));
    }
    let target = cloud_mcp_direct_target_from_route(&parsed, endpoint_path);
    if target.is_none() {
        if let Some(error) = cloud_mcp_direct_route_pending_error(&parsed) {
            return Err(error);
        }
        if let Some(error) = cloud_mcp_direct_route_rejected_error(&parsed) {
            return Err(error);
        }
        if let Some(error) = cloud_mcp_direct_route_unusable_error(&parsed, endpoint_path) {
            return Err(error);
        }
    }
    Ok(target)
}

fn cloud_mcp_route_state_is_provisioning(route_state: &str, backend_status: &str) -> bool {
    let route_state = route_state.trim().to_ascii_lowercase();
    let backend_status = backend_status.trim().to_ascii_lowercase();
    matches!(
        route_state.as_str(),
        "waiting"
            | "assignment_booting"
            | "dns_propagating"
            | "route_not_configured"
            | "route_not_browser_ready"
    ) || matches!(
        backend_status.as_str(),
        "booting" | "pending" | "starting" | "provisioning" | "deactivated"
    )
}

fn cloud_mcp_route_error_runtime_status(error: &str) -> Option<&'static str> {
    let error = error.to_ascii_lowercase();
    if error.contains("route pending")
        || error.contains("route_initializing")
        || error.contains("route_state=waiting")
        || error.contains("assignment_booting")
        || error.contains("dns_propagating")
        || error.contains("route_not_configured")
        || error.contains("route_not_browser_ready")
        || error.contains("backend_status=booting")
        || error.contains("backend_status=pending")
        || error.contains("backend_status=starting")
        || error.contains("backend_status=provisioning")
        || error.contains("backend_status=deactivated")
    {
        return Some("route_initializing");
    }
    None
}

fn cloud_mcp_route_error_retry_after_ms(error: &str) -> Option<u64> {
    let marker = "retry_after_ms=";
    let start = error.find(marker)? + marker.len();
    let digits = error[start..]
        .chars()
        .take_while(|ch| ch.is_ascii_digit())
        .collect::<String>();
    digits.parse::<u64>().ok()
}

fn cloud_mcp_route_initializing_poll_delay(error: &str) -> Duration {
    let delay_ms = cloud_mcp_route_error_retry_after_ms(error)
        .filter(|value| *value > 0)
        .unwrap_or(CLOUD_MCP_ROUTE_INITIALIZING_DEFAULT_POLL_MS)
        .clamp(
            CLOUD_MCP_ROUTE_INITIALIZING_MIN_POLL_MS,
            CLOUD_MCP_ROUTE_INITIALIZING_MAX_POLL_MS,
        );
    Duration::from_millis(delay_ms)
}

fn cloud_mcp_should_retry_no_direct_route_offer(route_attempt: u64) -> bool {
    route_attempt <= CLOUD_MCP_DIRECT_ROUTE_NO_OFFER_RETRY_ATTEMPTS
}

fn cloud_mcp_no_direct_route_offer_retry_delay() -> Duration {
    Duration::from_millis(CLOUD_MCP_DIRECT_ROUTE_NO_OFFER_RETRY_DELAY_MS)
}

fn cloud_mcp_direct_target_from_route(
    route: &Value,
    endpoint_path: &str,
) -> Option<CloudMcpWsTarget> {
    if let Some(target) = route
        .get("direct")
        .filter(|value| value.is_object())
        .and_then(|direct| cloud_mcp_direct_target_from_balancer_route(direct, endpoint_path))
    {
        return Some(target);
    }

    cloud_mcp_direct_target_from_broker_route(route, endpoint_path)
}

fn cloud_mcp_direct_target_from_balancer_route(
    direct: &Value,
    endpoint_path: &str,
) -> Option<CloudMcpWsTarget> {
    if direct.get("enabled").and_then(Value::as_bool) == Some(false) {
        return None;
    }
    let route_token = direct
        .get("route_token")
        .and_then(Value::as_str)
        .map(str::to_string)?;
    if !cloud_mcp_route_token_scope_allows_endpoint(&route_token, endpoint_path) {
        return None;
    }
    let preferred = if endpoint_path == "/v1/voice/ws" {
        direct.get("voice_websocket_url")
    } else if endpoint_path == "/v1/media/convert/ws" {
        direct
            .get("media_convert_websocket_url")
            .or_else(|| direct.get("browser_media_convert_websocket_url"))
    } else {
        None
    };
    let ws_url = preferred
        .or_else(|| direct.get("websocket_url"))
        .or_else(|| direct.get("browser_websocket_url"))
        .or_else(|| direct.get("app_websocket_url"))
        .and_then(Value::as_str)?
        .trim()
        .to_string();
    if !(ws_url.starts_with("ws://") || ws_url.starts_with("wss://")) {
        return None;
    }
    let ws_url = cloud_mcp_rewrite_ws_endpoint(&ws_url, endpoint_path);
    Some(CloudMcpWsTarget {
        ws_url,
        route_token: Some(route_token),
        transport: direct
            .get("transport")
            .and_then(Value::as_str)
            .unwrap_or("direct_cloud_container")
            .to_string(),
    })
}

fn cloud_mcp_direct_target_from_broker_route(
    route: &Value,
    endpoint_path: &str,
) -> Option<CloudMcpWsTarget> {
    let route_token = route
        .get("route_token")
        .and_then(Value::as_str)
        .map(str::to_string)?;
    if !cloud_mcp_route_token_scope_allows_endpoint(&route_token, endpoint_path) {
        return None;
    }
    let preferred = if endpoint_path == "/v1/voice/ws" {
        route
            .get("voice_websocket_url")
            .or_else(|| route.get("websocket_url"))
    } else {
        route
            .get("websocket_url")
            .or_else(|| route.get("app_websocket_url"))
    };
    let ws_url = preferred.and_then(Value::as_str)?.trim().to_string();
    if !(ws_url.starts_with("ws://") || ws_url.starts_with("wss://")) {
        return None;
    }
    let ws_url = cloud_mcp_rewrite_ws_endpoint(&ws_url, endpoint_path);
    Some(CloudMcpWsTarget {
        ws_url,
        route_token: Some(route_token),
        transport: route
            .get("transport")
            .and_then(Value::as_str)
            .unwrap_or("direct_cloud_container")
            .to_string(),
    })
}

async fn cloud_mcp_replay_runtime_snapshots(
    state: &CloudMcpState,
    _connection_id: &str,
    _message_token: &str,
) {
    cloud_mcp_publish_device_live_state_snapshot(state, "websocket_ready_replay").await;
    cloud_mcp_record_connection_diagnostic(
        state,
        "rust.cloud_mcp.device_live_state.replay",
        "ok",
        "Rust client replayed the unified device live-state snapshot after websocket reconnect.",
        json!({
            "reason": "websocket_ready_replay",
        }),
    )
    .await;
}

async fn cloud_mcp_fail_pending_ws_requests(state: &CloudMcpState, error: &str) {
    let mut pending = state.global_ws_pending.lock().await;
    let drained = std::mem::take(&mut *pending);
    drop(pending);
    for (_, sender) in drained {
        let _ = sender.send(json!({
            "kind": "error",
            "ok": false,
            "error": {
                "code": "cloud_ws_disconnected",
                "message": clean_terminal_telemetry_text(error),
            }
        }));
    }
}

async fn cloud_mcp_ws_request(
    state: &CloudMcpState,
    request_kind: &str,
    payload: &Value,
) -> Result<Value, String> {
    cloud_mcp_ws_request_with_timeout(
        state,
        request_kind,
        payload,
        Duration::from_secs(CLOUD_MCP_SYNC_TIMEOUT_SECS),
    )
    .await
}

async fn cloud_mcp_ws_request_with_timeout(
    state: &CloudMcpState,
    request_kind: &str,
    payload: &Value,
    response_timeout: Duration,
) -> Result<Value, String> {
    let mut last_error = String::new();
    // Destructive resets must never be re-sent on timeout: the server may still
    // be processing the first request, and a retry doubles the heavy work.
    let retry_transient_errors = !matches!(request_kind, "server_reset_cloud_state");
    for attempt in 0..2 {
        match cloud_mcp_ws_request_once_with_timeout(state, request_kind, payload, response_timeout)
            .await
        {
            Ok(response) => {
                cloud_mcp_ws_note_request_outcome(false);
                return Ok(response);
            }
            Err(error) => {
                let timed_out = error.contains("request timed out");
                cloud_mcp_ws_note_request_outcome(timed_out);
                if !retry_transient_errors
                    || !cloud_mcp_ws_request_error_is_transient(&error)
                    || attempt > 0
                {
                    if cloud_mcp_ws_request_error_indicates_dead_connection(&error) {
                        cloud_mcp_mark_global_ws_disconnected(state, &error).await;
                        state.global_ws_reconnect.notify_waiters();
                    }
                    return Err(error);
                }
                last_error = error.clone();
                // Tear the shared websocket down only when the error proves
                // the connection itself is gone. Request timeouts are scoped
                // to the individual sync unit: the server may still process
                // that request, and killing the app socket here creates a
                // reconnect storm under backlog pressure.
                if cloud_mcp_ws_request_error_indicates_dead_connection(&error) {
                    cloud_mcp_mark_global_ws_disconnected(state, &error).await;
                    state.global_ws_reconnect.notify_waiters();
                }
            }
        }
    }

    Err(last_error)
}

async fn cloud_mcp_ws_request_once_with_timeout(
    state: &CloudMcpState,
    request_kind: &str,
    payload: &Value,
    response_timeout: Duration,
) -> Result<Value, String> {
    cloud_mcp_start_global_ws(state).await;
    let tx = cloud_mcp_wait_for_ws_sender(state).await?;
    let request_id = format!("ws-{}-{}", cloud_mcp_now_ms(), uuid::Uuid::new_v4());
    let auth = cloud_mcp_ws_auth_object(state).await?;
    if cloud_mcp_voice_ws_kind(request_kind) {
        cloud_mcp_log_voice_shared_ws(
            "voice_agent.shared_ws.request_prepared",
            request_kind,
            "start",
            "Rust prepared an authenticated voice request for the shared app websocket.",
            json!({
                "id": request_id,
                "repo_id": cloud_mcp_payload_text(payload, &["repo_id"]),
                "workspace_id": cloud_mcp_payload_text(payload, &["workspace_id"]),
                "voice_session_id": cloud_mcp_payload_text(payload, &["voice_session_id"]),
                "request_kind": cloud_mcp_payload_text(payload, &["kind"]),
                "timeout_ms": response_timeout.as_millis(),
            }),
        );
    }
    let (response_tx, response_rx) = oneshot::channel::<Value>();
    state
        .global_ws_pending
        .lock()
        .await
        .insert(request_id.clone(), response_tx);
    let (scope_type, team_id) = cloud_mcp_account_scope(state).await;
    let scope_payload = cloud_mcp_account_scope_payload_from_parts(&scope_type, team_id.as_deref());
    let mut envelope = json!({
        "kind": request_kind,
        "id": request_id,
        "contract": "diffforge.app_ws.v1",
        "auth": auth,
        "client_id": CLOUD_MCP_RUST_CLIENT_ID,
        "repo_id": cloud_mcp_payload_text(payload, &["repo_id"])
            .or_else(|| cloud_mcp_payload_text(payload, &["payload", "repo_id"])),
        "workspace_id": cloud_mcp_payload_text(payload, &["workspace_id"])
            .or_else(|| cloud_mcp_payload_text(payload, &["payload", "workspace_id"])),
        "request": payload,
    });
    if let Some(object) = envelope.as_object_mut() {
        if let Some(scope_object) = scope_payload.as_object() {
            for (key, value) in scope_object {
                object.insert(key.clone(), value.clone());
            }
        }
        object.retain(|_, value| !value.is_null());
    }
    if tx.send(envelope).is_err() {
        state.global_ws_pending.lock().await.remove(&request_id);
        if cloud_mcp_voice_ws_kind(request_kind) {
            cloud_mcp_log_voice_shared_ws(
                "voice_agent.shared_ws.request_queue_failed",
                request_kind,
                "error",
                "Rust could not queue a voice request on the shared app websocket.",
                json!({
                    "id": request_id,
                }),
            );
        }
        return Err("Cloud MCP app websocket is not accepting messages.".to_string());
    }
    if cloud_mcp_voice_ws_kind(request_kind) {
        cloud_mcp_log_voice_shared_ws(
            "voice_agent.shared_ws.request_queued",
            request_kind,
            "ok",
            "Rust queued a voice request on the shared app websocket and is waiting for the cloud ack.",
            json!({
                "id": request_id,
            }),
        );
    }
    let response = match timeout(response_timeout, response_rx).await {
        Ok(Ok(response)) => response,
        Ok(Err(_)) => {
            state.global_ws_pending.lock().await.remove(&request_id);
            if cloud_mcp_voice_ws_kind(request_kind) {
                cloud_mcp_log_voice_shared_ws(
                    "voice_agent.shared_ws.response_cancelled",
                    request_kind,
                    "error",
                    "Rust voice request response channel was cancelled before cloud ack.",
                    json!({
                        "id": request_id,
                    }),
                );
            }
            return Err("Cloud MCP app websocket response was cancelled.".to_string());
        }
        Err(_) => {
            state.global_ws_pending.lock().await.remove(&request_id);
            if cloud_mcp_voice_ws_kind(request_kind) {
                cloud_mcp_log_voice_shared_ws(
                    "voice_agent.shared_ws.response_timeout",
                    request_kind,
                    "error",
                    "Rust timed out waiting for the cloud ack for a voice request.",
                    json!({
                        "id": request_id,
                        "timeout_ms": response_timeout.as_millis(),
                    }),
                );
            }
            return Err("Cloud MCP app websocket request timed out.".to_string());
        }
    };
    if cloud_mcp_voice_ws_kind(request_kind) {
        cloud_mcp_log_voice_shared_ws(
            "voice_agent.shared_ws.response_received",
            request_kind,
            "ok",
            "Rust received the cloud ack for a voice request.",
            json!({
                "id": request_id,
                "response_kind": response.get("kind").and_then(Value::as_str),
                "ok": response.get("ok").and_then(Value::as_bool),
                "request_kind": response.get("request_kind").cloned().unwrap_or(Value::Null),
            }),
        );
    }
    if response.get("ok").and_then(Value::as_bool) == Some(false)
        || response.get("kind").and_then(Value::as_str) == Some("error")
    {
        let message = response["error"]["message"]
            .as_str()
            .unwrap_or("Cloud MCP app websocket request failed.");
        return Err(message.to_string());
    }
    let data = response
        .get("data")
        .cloned()
        .unwrap_or_else(|| response.clone());
    Ok(json!({
        "ok": true,
        "data": data,
        "warnings": [],
    }))
}

fn cloud_mcp_ws_request_error_is_transient(error: &str) -> bool {
    let error = error.to_ascii_lowercase();
    if !error.contains("cloud mcp app websocket") && !error.contains("cloud mcp websocket") {
        return false;
    }
    [
        "not accepting",
        "not connected",
        "sender",
        "timed out",
        "cancelled",
        "closed",
        "disconnected",
        "write failed",
        "read failed",
    ]
    .iter()
    .any(|needle| error.contains(needle))
}

static CLOUD_MCP_WS_TIMEOUT_STRIKES: AtomicUsize = AtomicUsize::new(0);

/// Request timeouts are telemetry for sync-unit retry/backoff only. The socket
/// health decision belongs to explicit close/read/write failures and the silence
/// watchdog, because a slow server response can coexist with a healthy app ws.
fn cloud_mcp_ws_note_request_outcome(timed_out: bool) {
    if !timed_out {
        CLOUD_MCP_WS_TIMEOUT_STRIKES.store(0, Ordering::Release);
        return;
    }
    CLOUD_MCP_WS_TIMEOUT_STRIKES.fetch_add(1, Ordering::AcqRel);
}

/// Subset of transient errors that prove the shared websocket itself is dead
/// (versus a single request that timed out on a healthy connection).
fn cloud_mcp_ws_request_error_indicates_dead_connection(error: &str) -> bool {
    let error = error.to_ascii_lowercase();
    if !error.contains("cloud mcp app websocket") && !error.contains("cloud mcp websocket") {
        return false;
    }
    [
        "not accepting",
        "not connected",
        "sender",
        "closed",
        "disconnected",
        "write failed",
        "read failed",
    ]
    .iter()
    .any(|needle| error.contains(needle))
}

async fn cloud_mcp_ws_auth_object(state: &CloudMcpState) -> Result<Value, String> {
    let runtime = state.inner.lock().await;
    let connection_id = runtime
        .global_ws_connection_id
        .as_deref()
        .filter(|value| !value.trim().is_empty())
        .ok_or_else(|| "Cloud MCP app websocket connection auth is not established.".to_string())?;
    let message_token = runtime
        .global_ws_message_token
        .as_deref()
        .filter(|value| !value.trim().is_empty())
        .ok_or_else(|| "Cloud MCP app websocket message auth is not established.".to_string())?;
    Ok(json!({
        "connection_id": connection_id,
        "message_token": message_token,
    }))
}

async fn cloud_mcp_wait_for_app_ws_auth(state: &CloudMcpState) -> Result<Value, String> {
    cloud_mcp_start_global_ws(state).await;
    let _ = cloud_mcp_wait_for_ws_sender(state).await?;
    cloud_mcp_ws_auth_object(state).await
}

async fn cloud_mcp_wait_for_ws_sender(
    state: &CloudMcpState,
) -> Result<mpsc::UnboundedSender<Value>, String> {
    let started = Instant::now();
    loop {
        if state.global_ws_perma_offline.load(Ordering::SeqCst) {
            return Err(cloud_mcp_offline_mode_message().to_string());
        }
        if state.global_ws_registration_blocked.load(Ordering::SeqCst) {
            let runtime = state.inner.lock().await;
            let primary = runtime.global_ws_last_error.trim();
            let fallback = runtime.last_error.trim();
            let detail = if !primary.is_empty() {
                primary.to_string()
            } else if !fallback.is_empty() {
                fallback.to_string()
            } else {
                "Device limit reached. Open the Diff Forge dashboard and remove a registered device, then reconnect the Rust client.".to_string()
            };
            return Err(detail.to_string());
        }
        let ready = {
            let runtime = state.inner.lock().await;
            runtime.connected
                && runtime.global_ws_connected
                && runtime.global_ws_connection_id.is_some()
                && runtime.global_ws_message_token.is_some()
        };
        if ready {
            let tx = state.global_ws_tx.lock().await.as_ref().cloned();
            if let Some(tx) = tx {
                if !tx.is_closed() {
                    return Ok(tx);
                }
                cloud_mcp_mark_global_ws_disconnected(
                    state,
                    "Cloud MCP app websocket sender closed.",
                )
                .await;
                state.global_ws_reconnect.notify_waiters();
            }
        }
        if started.elapsed() >= Duration::from_secs(CLOUD_MCP_CONNECT_TIMEOUT_SECS) {
            let runtime = state.inner.lock().await;
            let detail = [
                runtime.global_ws_last_error.as_str(),
                runtime.last_error.as_str(),
            ]
            .into_iter()
            .map(str::trim)
            .find(|value| !value.is_empty())
            .unwrap_or("Cloud MCP app websocket is not connected yet.");
            return Err(detail.to_string());
        }
        sleep(Duration::from_millis(80)).await;
    }
}

fn cloud_mcp_workspace_control_dir(root: &Path) -> PathBuf {
    coordination::db::coordination_workspace_state_root(root).join("cloud-mcp")
}

fn cloud_mcp_visible_workspace_log_root(root: &Path) -> PathBuf {
    for ancestor in root.ancestors() {
        if ancestor.file_name().and_then(|value| value.to_str()) != Some("worktrees") {
            continue;
        }
        let Some(agents_dir) = ancestor.parent() else {
            continue;
        };
        if agents_dir.file_name().and_then(|value| value.to_str()) != Some(".agents") {
            continue;
        }
        if let Some(workspace_root) = agents_dir.parent() {
            return workspace_root.to_path_buf();
        }
    }
    root.to_path_buf()
}

fn cloud_mcp_workspace_log_path(root: &Path) -> PathBuf {
    cloud_mcp_workspace_control_dir(root).join("cloud-mcp.jsonl")
}

fn cloud_mcp_workspace_logging_enabled() -> bool {
    cloud_mcp_env_flag(CLOUD_MCP_WORKSPACE_LOG_ENV).unwrap_or(false)
}

fn cloud_mcp_workspace_log(
    root: &Path,
    phase: &str,
    workspace_id: &str,
    workspace_name: &str,
    fields: Value,
) -> Result<PathBuf, String> {
    let root = cloud_mcp_visible_workspace_log_root(root);
    let root = root.as_path();
    let path = cloud_mcp_workspace_log_path(root);
    if !cloud_mcp_workspace_logging_enabled() {
        return Ok(path);
    }

    let dir = cloud_mcp_workspace_control_dir(root);
    fs::create_dir_all(&dir).map_err(|error| {
        format!(
            "Unable to create Cloud MCP workspace log directory {}: {error}",
            workspace_path_display(&dir)
        )
    })?;
    if let Some(state_root) = dir.parent() {
        if coordination::db::coordination_state_root_is_visible(root, state_root) {
            let _ = ensure_workspace_agents_gitignore(root);
        }
    }

    static CLOUD_MCP_WORKSPACE_LOG_LOCK: std::sync::OnceLock<std::sync::Mutex<()>> =
        std::sync::OnceLock::new();
    let _guard = CLOUD_MCP_WORKSPACE_LOG_LOCK
        .get_or_init(|| std::sync::Mutex::new(()))
        .lock()
        .map_err(|_| "Cloud MCP workspace log lock is poisoned.".to_string())?;
    let mut file = fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open(&path)
        .map_err(|error| {
            format!(
                "Unable to open Cloud MCP workspace log {}: {error}",
                workspace_path_display(&path)
            )
        })?;

    let entry = json!({
        "ts_ms": cloud_mcp_now_ms(),
        "phase": phase,
        "workspace_id": workspace_id,
        "workspace_name": workspace_name,
        "root": workspace_path_display(root),
        "fields": fields,
    });

    writeln!(file, "{entry}").map_err(|error| {
        format!(
            "Unable to write Cloud MCP workspace log {}: {error}",
            workspace_path_display(&path)
        )
    })?;

    Ok(path)
}

fn cloud_mcp_policy_candidate(path: &Path) -> bool {
    let file_name = path
        .file_name()
        .map(|value| value.to_string_lossy().to_ascii_lowercase())
        .unwrap_or_default();
    let parent_name = path
        .parent()
        .and_then(Path::file_name)
        .map(|value| value.to_string_lossy().to_ascii_lowercase())
        .unwrap_or_default();

    matches!(
        file_name.as_str(),
        "policygraph.json" | "policy-graph.json" | "policy_graph.json"
    ) || (file_name == "graph.json" && (parent_name.contains("policy") || parent_name == "sql"))
}

fn cloud_mcp_find_policy_graph(root: &Path) -> Option<(String, Value)> {
    let mut candidates = Vec::new();

    for ancestor in root.ancestors().take(5) {
        candidates.push(ancestor.join("PolicyGraph.json"));
        candidates.push(ancestor.join("policygraph.json"));
        candidates.push(ancestor.join("policy-graph.json"));
        candidates.push(ancestor.join("policy_graph.json"));
        candidates.push(ancestor.join(".diffforge").join("policygraph.json"));
        candidates.push(ancestor.join(".agents").join("policygraph.json"));
        candidates.push(ancestor.join("sql").join("graph.json"));

        if let Ok(read_dir) = fs::read_dir(ancestor) {
            for entry in read_dir.flatten().take(96) {
                let path = entry.path();
                if path.is_file() {
                    candidates.push(path);
                    continue;
                }

                if path.is_dir() {
                    if let Ok(child_dir) = fs::read_dir(&path) {
                        for child in child_dir.flatten().take(96) {
                            candidates.push(child.path());
                        }
                    }
                }
            }
        }
    }

    let mut seen = HashSet::new();
    for candidate in candidates {
        if !cloud_mcp_policy_candidate(&candidate) {
            continue;
        }

        let key = workspace_path_display(&candidate);
        if !seen.insert(key.clone()) {
            continue;
        }

        let Ok(metadata) = fs::metadata(&candidate) else {
            continue;
        };
        if !metadata.is_file() || metadata.len() > 256 * 1024 {
            continue;
        }

        let Ok(contents) = fs::read_to_string(&candidate) else {
            continue;
        };
        if let Ok(value) = serde_json::from_str::<Value>(&contents) {
            return Some((key, value));
        }
    }

    None
}

fn cloud_mcp_workspace_identity(
    root: &Path,
    workspace_id: Option<&str>,
    workspace_name: Option<&str>,
) -> (String, String) {
    let root_display = workspace_path_display(root);
    let workspace_id = workspace_id
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToOwned::to_owned)
        .unwrap_or_else(|| format!("local-{}", cloud_mcp_short_hash(&root_display)));
    let workspace_name = workspace_name
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToOwned::to_owned)
        .unwrap_or_else(|| {
            root.file_name()
                .map(|value| value.to_string_lossy().to_string())
                .filter(|value| !value.trim().is_empty())
                .unwrap_or_else(|| "Local workspace".to_string())
        });
    (workspace_id, workspace_name)
}

fn cloud_mcp_child_project_mounts(
    root: &Path,
    mounts: &[WorkspaceProjectMount],
) -> Vec<WorkspaceProjectMount> {
    let root = root.canonicalize().unwrap_or_else(|_| root.to_path_buf());
    let root_key = normalized_path_key(&root);
    mounts
        .iter()
        .filter(|mount| mount.mount_kind == "project")
        .filter(|mount| normalized_path_key(&mount.root_path) != root_key)
        .cloned()
        .collect()
}

fn cloud_mcp_project_mounts_for_workspace_sync(
    root: &Path,
    workspace_kind: &str,
    mounts: &[WorkspaceProjectMount],
) -> Vec<WorkspaceProjectMount> {
    if cloud_mcp_workspace_kind_is_container(workspace_kind) {
        mounts
            .iter()
            .filter(|mount| mount.mount_kind == "project")
            .cloned()
            .collect()
    } else {
        cloud_mcp_child_project_mounts(root, mounts)
    }
}

fn cloud_mcp_workspace_kind_is_container(workspace_kind: &str) -> bool {
    workspace_kind == "container"
}

fn cloud_mcp_prepare_workspace_bundle(
    repo_path: String,
    workspace_id: Option<String>,
    workspace_name: Option<String>,
) -> Result<CloudMcpPreparedWorkspaceBundle, String> {
    let root = resolve_workspace_root_directory(Some(&repo_path))?;
    let primary =
        cloud_mcp_prepare_workspace_from_root(root.clone(), workspace_id.clone(), workspace_name)?;
    let mut children = Vec::new();
    let mut seen = HashSet::new();
    seen.insert(normalized_path_key(&primary.root));
    let mut pending_mounts = VecDeque::from(primary.project_mounts.clone());
    while let Some(mount) = pending_mounts.pop_front() {
        let key = normalized_path_key(&mount.root_path);
        if !seen.insert(key) {
            continue;
        }
        let child = cloud_mcp_prepare_workspace_from_root(
            mount.root_path.clone(),
            workspace_id.clone(),
            Some(mount.project_name.clone()),
        )?;
        pending_mounts.extend(child.project_mounts.clone());
        children.push(child);
    }

    Ok(CloudMcpPreparedWorkspaceBundle { primary, children })
}

fn cloud_mcp_prepare_workspace_from_root(
    root: PathBuf,
    workspace_id: Option<String>,
    workspace_name: Option<String>,
) -> Result<CloudMcpPreparedWorkspace, String> {
    let root_display = workspace_path_display(&root);
    let detected_mounts = workspace_project_mounts(&root);
    let workspace_kind = workspace_kind_for_mounts(&root, &detected_mounts);
    let project_mounts =
        cloud_mcp_project_mounts_for_workspace_sync(&root, &workspace_kind, &detected_mounts);
    let (workspace_id, workspace_name) =
        cloud_mcp_workspace_identity(&root, workspace_id.as_deref(), workspace_name.as_deref());
    let (policy_graph_path, policy_graph) = cloud_mcp_find_policy_graph(&root)
        .map(|(path, value)| (path, Some(value)))
        .unwrap_or_else(|| (String::new(), None));

    Ok(CloudMcpPreparedWorkspace {
        root,
        root_display,
        workspace_kind,
        project_mounts,
        workspace_id,
        workspace_name,
        policy_graph_path,
        policy_graph,
    })
}

async fn cloud_mcp_post_json_endpoint(
    state: &CloudMcpState,
    endpoint: &str,
    payload: &Value,
) -> Result<Value, String> {
    let log_context = cloud_mcp_post_log_context(endpoint, payload);
    if let Some((root, workspace_id, workspace_name, fields)) = &log_context {
        let mut fields = fields.clone();
        fields["transport"] = json!("app_websocket");
        let _ = cloud_mcp_workspace_log(
            root,
            "cloud_mcp.ws.start",
            &workspace_id,
            workspace_name,
            fields,
        );
    }

    let Some(ws_kind) = cloud_mcp_ws_kind_for_endpoint(endpoint) else {
        let error = format!(
            "Cloud MCP endpoint {endpoint} is not routed through the required app websocket"
        );
        if let Some((root, workspace_id, workspace_name, fields)) = &log_context {
            let mut fields = fields.clone();
            fields["transport"] = json!("app_websocket");
            fields["error"] = json!(error.clone());
            let _ = cloud_mcp_workspace_log(
                root,
                "cloud_mcp.ws.error",
                workspace_id,
                workspace_name,
                fields,
            );
        }
        return Err(error);
    };

    let sync_activity_key = cloud_mcp_sync_activity_for_endpoint(endpoint, payload).map(
        |(domain, direction, state, count, bytes, size_class)| {
            cloud_mcp_record_sync_activity(
                domain,
                direction,
                state,
                count,
                bytes,
                false,
                size_class,
                &format!("endpoint:{endpoint}:{}", uuid::Uuid::new_v4()),
            )
        },
    );

    match cloud_mcp_ws_request(state, ws_kind, payload).await {
        Ok(value) => {
            if let Some(key) = sync_activity_key.as_deref() {
                cloud_mcp_clear_sync_activity_key(key);
            }
            cloud_mcp_update_todo_mirror_from_response(
                state,
                "app_websocket_response",
                endpoint,
                payload,
                &value,
            )
            .await;
            cloud_mcp_update_asset_library_from_response(
                if endpoint == "/v1/assets/list" {
                    "asset_library_list_snapshot"
                } else {
                    "app_websocket_response"
                },
                Some(endpoint),
                payload,
                &value,
            );
            if let Some((root, workspace_id, workspace_name, fields)) = &log_context {
                let mut fields = fields.clone();
                fields["transport"] = json!("app_websocket");
                let _ = cloud_mcp_workspace_log(
                    root,
                    "cloud_mcp.ws.done",
                    workspace_id,
                    workspace_name,
                    fields,
                );
            }
            Ok(value)
        }
        Err(error) => {
            if let Some(key) = sync_activity_key.as_deref() {
                cloud_mcp_fail_sync_activity_key(key);
            }
            if let Some((root, workspace_id, workspace_name, fields)) = &log_context {
                let mut fields = fields.clone();
                fields["transport"] = json!("app_websocket");
                fields["error"] = json!(clean_terminal_telemetry_text(&error));
                let _ = cloud_mcp_workspace_log(
                    root,
                    "cloud_mcp.ws.error",
                    workspace_id,
                    workspace_name,
                    fields,
                );
            }
            Err(error)
        }
    }
}

fn cloud_mcp_ws_kind_for_endpoint(endpoint: &str) -> Option<&'static str> {
    match endpoint {
        "/v1/status" => Some("status"),
        "/v1/events" => Some("event"),
        "/v1/assets/list" => Some("account_assets_hello"),
        "/v1/assets/clouds/list" => Some("account_assets_clouds_list"),
        "/v1/assets/clouds/save" => Some("account_assets_cloud_save"),
        "/v1/assets/clouds/validate" => Some("account_assets_cloud_validate"),
        "/v1/assets/clouds/default" => Some("account_assets_cloud_set_default"),
        "/v1/assets/clouds/delete" => Some("account_assets_cloud_delete"),
        "/v1/assets/register" => Some("account_assets_register"),
        "/v1/assets/prepare-upload" => Some("account_assets_prepare_upload"),
        "/v1/assets/complete-upload" => Some("account_assets_complete_upload"),
        "/v1/assets/prepare-download" => Some("account_assets_prepare_download"),
        "/v1/assets/delete-cloud" => Some("account_assets_delete"),
        "/v1/assets/publish-public" => Some("account_assets_publish_public"),
        "/v1/assets/unpublish-public" => Some("account_assets_unpublish_public"),
        "/v1/assets/status" => Some("account_assets_hello"),
        "/v1/assets/report-transfer-progress" => Some("account_assets_report_transfer_progress"),
        "/v1/tokenomics/reset-device" => Some("tokenomics_reset_device_cloud"),
        "/v1/cloud/server-reset" => Some("server_reset_cloud_state"),
        "/v1/cloud/repo-catalog" => Some("account_repo_catalog"),
        "/v1/tools/cli-snapshot" => Some("account_clis_snapshot"),
        _ => None,
    }
}

fn cloud_mcp_account_asset_request_endpoint(request_kind: &str) -> Option<&'static str> {
    match request_kind {
        "account_assets_register" => Some("/v1/assets/register"),
        "account_assets_report_transfer_progress" => Some("/v1/assets/report-transfer-progress"),
        _ => None,
    }
}

fn cloud_mcp_is_account_asset_request_kind(request_kind: &str) -> bool {
    cloud_mcp_account_asset_request_endpoint(request_kind).is_some()
}

async fn cloud_mcp_post_event_endpoint(
    state: &CloudMcpState,
    event_kind: &str,
    payload: &Value,
) -> Result<Value, String> {
    if cloud_mcp_task_event_kind_removed(event_kind) {
        return Ok(cloud_mcp_task_event_removed_outbox_response(event_kind));
    }
    let (payload, idempotency_key, _payload_hash, _coalesce_key) =
        cloud_mcp_outbox_payload_with_idempotency(event_kind, payload);
    if cloud_mcp_is_workspace_todo_wake_event(event_kind, &payload) {
        cloud_mcp_update_todo_mirror_from_response(
            state,
            "local_workspace_todo_event",
            "/v1/events",
            &payload,
            &payload,
        )
        .await;
        let _ = state
            .global_ws_events
            .send(cloud_mcp_event_envelope(event_kind, &payload));
    }
    cloud_mcp_background_sync_ensure_started(state);
    let row = cloud_mcp_outbox_enqueue_event(
        event_kind,
        &payload,
        cloud_mcp_outbox_priority_for_event(event_kind),
        "direct_event",
    )?;
    let _ = cloud_mcp_outbox_mark_in_flight(&row);
    match cloud_mcp_send_outbox_row_now(state, &row).await {
        Ok(response) => {
            let _ = cloud_mcp_outbox_mark_acked(&row, &response);
            Ok(response)
        }
        Err(error) => {
            let _ = cloud_mcp_outbox_mark_retry(&row, &error);
            state.background_sync.notify.notify_one();
            Ok(cloud_mcp_outbox_queued_response(
                &CloudMcpOutboxRow {
                    idempotency_key,
                    ..row
                },
                Some(&error),
            ))
        }
    }
}

async fn cloud_mcp_apply_local_workspace_todo_event(
    state: &CloudMcpState,
    event_kind: &str,
    payload: &Value,
    source: &str,
) -> Result<Value, String> {
    cloud_mcp_update_todo_mirror_from_response(state, source, "/v1/events", payload, payload).await;
    let _ = state
        .global_ws_events
        .send(cloud_mcp_event_envelope(event_kind, payload));
    Ok(json!({
        "ok": true,
        "event_kind": event_kind,
        "local_only": true,
        "source": source,
    }))
}

async fn cloud_mcp_send_outbox_row_now(
    state: &CloudMcpState,
    row: &CloudMcpOutboxRow,
) -> Result<Value, String> {
    if cloud_mcp_task_event_kind_removed(&row.event_kind) {
        return Ok(cloud_mcp_task_event_removed_outbox_response(
            &row.event_kind,
        ));
    }
    let payload = serde_json::from_str::<Value>(&row.payload_json)
        .map_err(|error| format!("Unable to decode Cloud sync outbox payload: {error}"))?;
    if let Err(reason) =
        cloud_mcp_validate_authoritative_workspace_snapshot_payload(&row.event_kind, &payload)
    {
        return Ok(json!({
            "ok": true,
            "skipped": true,
            "reason": reason,
            "event_kind": row.event_kind,
            "outbox_id": row.outbox_id,
        }));
    }
    let response = cloud_mcp_send_event_now(state, &row.event_kind, &payload).await?;
    if row.event_kind == CLOUD_MCP_AGENT_CHAT_SESSION_SYNC_EVENT
        && !cloud_mcp_agent_chat_sync_response_accepted(&response)
    {
        return Err("Agent chat session sync was not accepted by cloud server.".to_string());
    }
    Ok(response)
}

async fn cloud_mcp_send_event_now(
    state: &CloudMcpState,
    event_kind: &str,
    payload: &Value,
) -> Result<Value, String> {
    if cloud_mcp_task_event_kind_removed(event_kind) {
        return Ok(cloud_mcp_task_event_removed_outbox_response(event_kind));
    }
    if let Err(reason) =
        cloud_mcp_validate_authoritative_workspace_snapshot_payload(event_kind, payload)
    {
        return Ok(json!({
            "ok": true,
            "skipped": true,
            "reason": reason,
            "event_kind": event_kind,
        }));
    }
    if cloud_mcp_is_account_asset_request_kind(event_kind) {
        let response = cloud_mcp_ws_request(state, event_kind, payload).await?;
        let data = response
            .get("data")
            .cloned()
            .unwrap_or_else(|| response.clone());
        cloud_mcp_update_asset_library_from_response(
            "asset_library_outbox_response",
            cloud_mcp_account_asset_request_endpoint(event_kind),
            payload,
            &data,
        );
        return Ok(response);
    }
    if event_kind.trim().eq_ignore_ascii_case("todo.live_state") {
        if cloud_mcp_todo_sync_payload_is_app_control(payload) {
            log_terminal_status_event(
                "backend.cloud_mcp.todo_sync_app_control_outbox_skip",
                json!({
                    "workspace_id": cloud_mcp_payload_text(payload, &["workspace_id"]).unwrap_or_default(),
                }),
            );
            return Ok(json!({
                "ok": true,
                "skipped": true,
                "reason": "app_control_terminal",
            }));
        }
        let response = cloud_mcp_ws_request(state, "todo.live_state", payload).await?;
        cloud_mcp_update_todo_mirror_from_response(
            state,
            "todo_sync_outbox_response",
            "todo.live_state",
            payload,
            &response,
        )
        .await;
        return Ok(response);
    }
    if event_kind.trim().eq_ignore_ascii_case("script.inventory")
        || event_kind
            .trim()
            .eq_ignore_ascii_case("account_script_run_state")
    {
        return cloud_mcp_ws_request(state, event_kind.trim(), payload).await;
    }
    if event_kind.trim().eq_ignore_ascii_case("loopspaces.sync") {
        let response = cloud_mcp_ws_request(state, "loopspaces.sync", payload).await?;
        let data = response
            .get("data")
            .cloned()
            .unwrap_or_else(|| response.clone());
        if let Ok(snapshot) =
            cloud_mcp_apply_loopspaces_sync_data(state, &data, "loopspaces_outbox_response").await
        {
            let _ = state.global_ws_events.send(json!({
                "kind": "loopspaces.sync",
                "event_kind": "loopspaces.sync",
                "contract": CLOUD_MCP_LOOPSPACES_CONTRACT,
                "payload": snapshot,
            }));
        }
        return Ok(response);
    }
    if event_kind
        .trim()
        .eq_ignore_ascii_case("loopspace_triggers.sync")
    {
        let response = cloud_mcp_ws_request(state, "loopspace_triggers.sync", payload).await?;
        let data = response
            .get("data")
            .cloned()
            .unwrap_or_else(|| response.clone());
        if let Ok(snapshot) = cloud_mcp_apply_loopspace_triggers_sync_data(
            state,
            &data,
            "loopspace_triggers_outbox_response",
        )
        .await
        {
            let _ = state.global_ws_events.send(json!({
                "kind": "loopspace_triggers.sync",
                "event_kind": "loopspace_triggers.sync",
                "contract": CLOUD_MCP_LOOPSPACE_TRIGGERS_CONTRACT,
                "payload": snapshot,
            }));
        }
        return Ok(response);
    }
    if matches!(
        event_kind.trim().to_ascii_lowercase().as_str(),
        "doc.sync" | "doc.content"
    ) {
        let request_kind = if event_kind.trim().eq_ignore_ascii_case("doc.content") {
            "doc.content"
        } else {
            "doc.sync"
        };
        let response = cloud_mcp_ws_request(state, request_kind, payload).await?;
        if cloud_mcp_is_account_documents_sync_wake_event(event_kind, payload) {
            let data = response
                .get("data")
                .cloned()
                .unwrap_or_else(|| response.clone());
            if let Ok(applied) = cloud_mcp_apply_account_documents_sync_data_with_hydration(
                state,
                &data,
                "documents_outbox_response",
            )
            .await
            {
                let _ = state.global_ws_events.send(json!({
                    "kind": "doc.sync",
                    "event_kind": "doc.sync",
                    "contract": CLOUD_MCP_ACCOUNT_DOCUMENTS_CONTRACT,
                    "c": "doc.sync",
                    "d": "documents",
                    "payload": applied,
                }));
            }
        }
        return Ok(response);
    }
    let envelope = cloud_mcp_event_envelope(event_kind, payload);
    cloud_mcp_post_json_endpoint(state, "/v1/events", &envelope).await
}

fn cloud_mcp_event_envelope(event_kind: &str, payload: &Value) -> Value {
    let mut workspace_ids = Vec::new();
    let mut repo_ids = Vec::new();
    if let Some(workspace_id) = cloud_mcp_payload_text(payload, &["workspace_id"]) {
        if !workspace_ids
            .iter()
            .any(|value: &String| value == &workspace_id)
        {
            workspace_ids.push(workspace_id);
        }
    }
    if let Some(repo_id) = cloud_mcp_payload_text(payload, &["repo_id"]) {
        if !repo_ids.iter().any(|value: &String| value == &repo_id) {
            repo_ids.push(repo_id);
        }
    }
    if let Some(items) = payload.get("workspace_ids").and_then(Value::as_array) {
        for item in items.iter().filter_map(Value::as_str) {
            let item = item.trim().to_string();
            if !item.is_empty() && !workspace_ids.iter().any(|value| value == &item) {
                workspace_ids.push(item);
            }
        }
    }
    if let Some(items) = payload.get("repo_ids").and_then(Value::as_array) {
        for item in items.iter().filter_map(Value::as_str) {
            let item = item.trim().to_string();
            if !item.is_empty() && !repo_ids.iter().any(|value| value == &item) {
                repo_ids.push(item);
            }
        }
    }
    if let Some(workspaces) = payload.get("workspaces").and_then(Value::as_array) {
        for workspace in workspaces {
            if let Some(workspace_id) = cloud_mcp_payload_text(workspace, &["workspace_id", "id"]) {
                if !workspace_ids
                    .iter()
                    .any(|value: &String| value == &workspace_id)
                {
                    workspace_ids.push(workspace_id);
                }
            }
            if let Some(repo_id) = cloud_mcp_payload_text(workspace, &["repo_id"]) {
                if !repo_ids.iter().any(|value: &String| value == &repo_id) {
                    repo_ids.push(repo_id);
                }
            }
        }
    }
    let primary_workspace_id = (workspace_ids.len() == 1).then(|| workspace_ids[0].clone());
    let primary_repo_id = (repo_ids.len() == 1).then(|| repo_ids[0].clone());
    let idempotency_key = cloud_mcp_payload_text(payload, &["idempotency_key"]);
    let payload_hash = cloud_mcp_payload_text(payload, &["payload_hash"])
        .unwrap_or_else(|| cloud_mcp_outbox_payload_hash(payload));
    let scope_payload = cloud_mcp_payload_account_scope_payload(payload)
        .unwrap_or_else(cloud_mcp_process_account_scope_payload);
    let mut envelope = json!({
        "event_kind": event_kind,
        "payload": payload,
        "idempotency_key": idempotency_key,
        "payload_hash": payload_hash,
        "repo_id": primary_repo_id,
        "repo_ids": repo_ids,
        "ts_ms": cloud_mcp_now_ms(),
        "workspace_id": primary_workspace_id,
        "workspace_ids": workspace_ids,
    });
    if let Some(object) = envelope.as_object_mut() {
        if let Some(scope_object) = scope_payload.as_object() {
            for (key, value) in scope_object {
                object.insert(key.clone(), value.clone());
            }
        }
        object.retain(|_, value| !value.is_null());
    }
    envelope
}

fn cloud_mcp_terminal_output_message_kind(message: &Value) -> String {
    cloud_mcp_payload_text(message, &["k", "kind", "type", "event_kind"])
        .unwrap_or_default()
        .trim()
        .to_ascii_lowercase()
}

fn cloud_mcp_terminal_output_key_component(value: &str) -> String {
    value.trim().replace('%', "%25").replace(':', "%3A")
}

fn cloud_mcp_terminal_output_decode_key_component(value: &str) -> String {
    value
        .trim()
        .replace("%3A", ":")
        .replace("%3a", ":")
        .replace("%25", "%")
}

fn cloud_mcp_terminal_output_message_stream_key(message: &Value) -> Option<String> {
    if let Some(stream_key) = cloud_mcp_payload_text(message, &["sk", "stream_key"])
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
    {
        return Some(stream_key);
    }
    let device_id = cloud_mcp_payload_text(message, &["d", "device_id"])?;
    let workspace_id = cloud_mcp_payload_text(message, &["w", "workspace_id"])?;
    let workspace_id = cloud_mcp_canonical_workspace_id_from_value(
        &workspace_id,
        message,
        cloud_mcp_desktop_platform(),
    );
    let pane_id = cloud_mcp_payload_text(
        message,
        &["p", "pane_id", "terminal_id", "target_terminal_id"],
    )?;
    let instance_id =
        cloud_mcp_payload_text(message, &["i", "terminal_instance_id", "instance_id"])
            .unwrap_or_default();
    if instance_id.trim().is_empty() {
        Some(format!(
            "{}:{}:{}",
            cloud_mcp_terminal_output_key_component(&device_id),
            cloud_mcp_terminal_output_key_component(&workspace_id),
            cloud_mcp_terminal_output_key_component(&pane_id),
        ))
    } else {
        Some(format!(
            "{}:{}:{}:{}",
            cloud_mcp_terminal_output_key_component(&device_id),
            cloud_mcp_terminal_output_key_component(&workspace_id),
            cloud_mcp_terminal_output_key_component(&pane_id),
            cloud_mcp_terminal_output_key_component(&instance_id),
        ))
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct CloudMcpTerminalIoTarget {
    stream_key: String,
    device_id: String,
    workspace_id: String,
    pane_id: String,
    instance_id: u64,
}

fn cloud_mcp_terminal_io_target(stream_key: &str) -> Result<CloudMcpTerminalIoTarget, String> {
    let parts = stream_key.split(':').collect::<Vec<_>>();
    if parts.len() != 4 || parts.iter().any(|part| part.trim().is_empty()) {
        return Err(
            "Terminal stream key must contain device, workspace, pane, and instance.".to_string(),
        );
    }
    let instance_id = cloud_mcp_terminal_output_decode_key_component(parts[3])
        .parse::<u64>()
        .ok()
        .filter(|value| *value > 0)
        .ok_or_else(|| "Terminal stream key has an invalid instance generation.".to_string())?;
    Ok(CloudMcpTerminalIoTarget {
        stream_key: stream_key.to_string(),
        device_id: cloud_mcp_terminal_output_decode_key_component(parts[0]),
        workspace_id: cloud_mcp_terminal_output_decode_key_component(parts[1]),
        pane_id: cloud_mcp_terminal_output_decode_key_component(parts[2]),
        instance_id,
    })
}

fn cloud_mcp_terminal_io_origin(message: &Value) -> String {
    cloud_mcp_payload_text(message, &["origin_connection_id"])
        .unwrap_or_else(|| "unknown".to_string())
}

#[derive(Clone, Default)]
struct CloudMcpTerminalRemotePresenceEntry {
    workspace_id: String,
    pane_id: String,
    instance_id: Option<u64>,
    stream_key: String,
    shell_viewers: usize,
    shell_controller: bool,
    chat_watchers: usize,
}

fn cloud_mcp_terminal_remote_presence_identity_key(
    workspace_id: &str,
    pane_id: &str,
    instance_id: Option<u64>,
) -> String {
    format!(
        "{}|{}|{}",
        cloud_mcp_workspace_id_match_key(workspace_id),
        pane_id.trim(),
        instance_id
            .map(|value| value.to_string())
            .unwrap_or_else(|| "unknown".to_string()),
    )
}

fn cloud_mcp_remote_presence_origin_is_remote(
    origin: &str,
    local_connection_id: Option<&str>,
) -> bool {
    let origin = origin.trim();
    if origin.is_empty() {
        return false;
    }
    if local_connection_id.is_some_and(|local| !local.is_empty() && local == origin) {
        return false;
    }
    let normalized = origin.to_ascii_lowercase();
    !matches!(
        normalized.as_str(),
        "local"
            | "loopback"
            | "localhost"
            | "native"
            | "desktop"
            | "unknown"
            | "rust"
            | "rust-diffforge"
            | CLOUD_MCP_RUST_CLIENT_ID
    ) && !normalized.starts_with("local:")
        && !normalized.starts_with("loopback:")
        && !normalized.starts_with("localhost:")
}

fn cloud_mcp_terminal_remote_presence_origin_is_fresh(last_seen_ms: u64, now_ms: u64) -> bool {
    now_ms.saturating_sub(last_seen_ms) < TERMINAL_REMOTE_PRESENCE_STALE_ORIGIN_TTL_MS
}

fn cloud_mcp_prune_terminal_remote_presence_stale_origins_at(
    state: &CloudMcpState,
    now_ms: u64,
) -> bool {
    let mut changed = false;
    if let Ok(mut subscriptions) = state.terminal_io_stream_subscriptions.lock() {
        subscriptions.retain(|_, origins| {
            let before = origins.len();
            origins.retain(|_, subscription| {
                cloud_mcp_terminal_remote_presence_origin_is_fresh(
                    subscription.last_seen_ms,
                    now_ms,
                )
            });
            changed |= origins.len() != before;
            let keep = !origins.is_empty();
            changed |= !keep;
            keep
        });
    }
    if let Ok(mut owners) = state.terminal_io_control_owners.lock() {
        let before = owners.len();
        owners.retain(|_, owner| {
            cloud_mcp_terminal_remote_presence_origin_is_fresh(owner.last_seen_ms, now_ms)
        });
        changed |= owners.len() != before;
    }
    changed |= agent_chat_session_prune_stale_observed_terminals(
        now_ms,
        TERMINAL_REMOTE_PRESENCE_STALE_ORIGIN_TTL_MS,
    );
    changed
}

fn cloud_mcp_prune_terminal_remote_presence_stale_origins(state: &CloudMcpState) -> bool {
    cloud_mcp_prune_terminal_remote_presence_stale_origins_at(state, cloud_mcp_now_ms())
}

fn cloud_mcp_terminal_remote_presence_has_tracked_origins(state: &CloudMcpState) -> bool {
    let has_shell_viewers = state
        .terminal_io_stream_subscriptions
        .lock()
        .map(|subscriptions| subscriptions.values().any(|origins| !origins.is_empty()))
        .unwrap_or(false);
    let has_shell_controllers = state
        .terminal_io_control_owners
        .lock()
        .map(|owners| !owners.is_empty())
        .unwrap_or(false);
    has_shell_viewers || has_shell_controllers || agent_chat_session_has_observed_terminal_origins()
}

fn cloud_mcp_schedule_terminal_remote_presence_reaper(state: &CloudMcpState) {
    if state
        .terminal_remote_presence_reaper_scheduled
        .swap(true, Ordering::SeqCst)
    {
        return;
    }
    let state = state.clone();
    tauri::async_runtime::spawn(async move {
        sleep(Duration::from_millis(
            TERMINAL_REMOTE_PRESENCE_STALE_ORIGIN_TTL_MS
                .saturating_add(TERMINAL_REMOTE_PRESENCE_REAPER_GRACE_MS),
        ))
        .await;
        state
            .terminal_remote_presence_reaper_scheduled
            .store(false, Ordering::SeqCst);
        if cloud_mcp_prune_terminal_remote_presence_stale_origins(&state) {
            cloud_mcp_schedule_terminal_remote_presence_emit(
                &state,
                "terminal_remote_presence_stale_reaper",
            );
        }
        if cloud_mcp_terminal_remote_presence_has_tracked_origins(&state) {
            cloud_mcp_schedule_terminal_remote_presence_reaper(&state);
        }
    });
}

fn cloud_mcp_touch_terminal_io_presence_origin(
    state: &CloudMcpState,
    stream_key: &str,
    origin: &str,
) {
    let origin = origin.trim();
    if origin.is_empty() {
        return;
    }
    let now_ms = cloud_mcp_now_ms();
    let mut touched = false;
    if let Ok(mut subscriptions) = state.terminal_io_stream_subscriptions.lock() {
        if let Some(origins) = subscriptions.get_mut(stream_key) {
            if let Some(subscription) = origins.get_mut(origin) {
                subscription.last_seen_ms = now_ms;
                touched = true;
            }
        }
    }
    if let Ok(mut owners) = state.terminal_io_control_owners.lock() {
        if let Some(owner) = owners.get_mut(stream_key) {
            if owner.origin.as_str() == origin {
                owner.last_seen_ms = now_ms;
                touched = true;
            }
        }
    }
    if touched {
        cloud_mcp_schedule_terminal_remote_presence_reaper(state);
    }
}

fn cloud_mcp_terminal_remote_presence_entry_value(
    entry: &CloudMcpTerminalRemotePresenceEntry,
) -> Value {
    json!({
        "workspace_id": entry.workspace_id,
        "pane_id": entry.pane_id,
        "instance_id": entry.instance_id,
        "stream_key": entry.stream_key,
        "shell_viewers": entry.shell_viewers,
        "shell_controller": entry.shell_controller,
        "chat_watchers": entry.chat_watchers,
    })
}

async fn cloud_mcp_terminal_remote_presence_snapshot_payload(state: &CloudMcpState) -> Value {
    let _ = cloud_mcp_prune_terminal_remote_presence_stale_origins(state);
    let local_device = cloud_mcp_payload_text(&cloud_mcp_desktop_device_profile(), &["device_id"])
        .unwrap_or_else(|| "desktop-primary".to_string());
    let local_connection_id = {
        let runtime = state.inner.lock().await;
        runtime.global_ws_connection_id.clone()
    };
    let local_connection_id = local_connection_id.as_deref();
    let mut entries: HashMap<String, CloudMcpTerminalRemotePresenceEntry> = HashMap::new();

    if let Ok(subscriptions) = state.terminal_io_stream_subscriptions.lock() {
        for (stream_key, origins) in subscriptions.iter() {
            let Ok(target) = cloud_mcp_terminal_io_target(stream_key) else {
                continue;
            };
            if target.device_id != local_device {
                continue;
            }
            let shell_viewers = origins
                .keys()
                .filter(|origin| {
                    cloud_mcp_remote_presence_origin_is_remote(origin, local_connection_id)
                })
                .count();
            if shell_viewers == 0 {
                continue;
            }
            let key = cloud_mcp_terminal_remote_presence_identity_key(
                &target.workspace_id,
                &target.pane_id,
                Some(target.instance_id),
            );
            let entry = entries
                .entry(key)
                .or_insert_with(|| CloudMcpTerminalRemotePresenceEntry {
                    workspace_id: cloud_mcp_workspace_id_match_key(&target.workspace_id),
                    pane_id: target.pane_id.trim().to_string(),
                    instance_id: Some(target.instance_id),
                    stream_key: target.stream_key.clone(),
                    ..CloudMcpTerminalRemotePresenceEntry::default()
                });
            entry.shell_viewers = shell_viewers;
            if entry.stream_key.is_empty() {
                entry.stream_key = target.stream_key.clone();
            }
        }
    }

    if let Ok(owners) = state.terminal_io_control_owners.lock() {
        for (stream_key, owner) in owners.iter() {
            if !cloud_mcp_remote_presence_origin_is_remote(&owner.origin, local_connection_id) {
                continue;
            }
            let Ok(target) = cloud_mcp_terminal_io_target(stream_key) else {
                continue;
            };
            if target.device_id != local_device {
                continue;
            }
            let key = cloud_mcp_terminal_remote_presence_identity_key(
                &target.workspace_id,
                &target.pane_id,
                Some(target.instance_id),
            );
            let entry = entries
                .entry(key)
                .or_insert_with(|| CloudMcpTerminalRemotePresenceEntry {
                    workspace_id: cloud_mcp_workspace_id_match_key(&target.workspace_id),
                    pane_id: target.pane_id.trim().to_string(),
                    instance_id: Some(target.instance_id),
                    stream_key: target.stream_key.clone(),
                    ..CloudMcpTerminalRemotePresenceEntry::default()
                });
            entry.shell_controller = true;
            if entry.stream_key.is_empty() {
                entry.stream_key = target.stream_key.clone();
            }
        }
    }

    for observed in agent_chat_session_observed_terminal_presence_entries() {
        let chat_watchers = observed
            .origins
            .iter()
            .filter(|origin| {
                cloud_mcp_remote_presence_origin_is_remote(origin, local_connection_id)
            })
            .count();
        if chat_watchers == 0 {
            continue;
        }
        let workspace_id = cloud_mcp_workspace_id_match_key(&observed.workspace_id);
        let key = cloud_mcp_terminal_remote_presence_identity_key(
            &workspace_id,
            &observed.pane_id,
            observed.instance_id,
        );
        let stream_key = observed.instance_id.map(|instance_id| {
            cloud_mcp_terminal_output_stream_key(
                &local_device,
                &workspace_id,
                observed.pane_id.trim(),
                instance_id,
            )
        });
        let entry = entries
            .entry(key)
            .or_insert_with(|| CloudMcpTerminalRemotePresenceEntry {
                workspace_id,
                pane_id: observed.pane_id.trim().to_string(),
                instance_id: observed.instance_id,
                stream_key: stream_key.clone().unwrap_or_default(),
                ..CloudMcpTerminalRemotePresenceEntry::default()
            });
        entry.chat_watchers = chat_watchers;
        if entry.stream_key.is_empty() {
            if let Some(stream_key) = stream_key {
                entry.stream_key = stream_key;
            }
        }
    }

    let mut items = entries.into_values().collect::<Vec<_>>();
    items.sort_by(|left, right| {
        (
            &left.workspace_id,
            &left.pane_id,
            left.instance_id.unwrap_or(0),
            &left.stream_key,
        )
            .cmp(&(
                &right.workspace_id,
                &right.pane_id,
                right.instance_id.unwrap_or(0),
                &right.stream_key,
            ))
    });

    let mut by_stream_key = serde_json::Map::new();
    let mut by_terminal_key = serde_json::Map::new();
    let item_values = items
        .iter()
        .map(|entry| {
            let value = cloud_mcp_terminal_remote_presence_entry_value(entry);
            if !entry.stream_key.is_empty() {
                by_stream_key.insert(entry.stream_key.clone(), value.clone());
            }
            by_terminal_key.insert(
                cloud_mcp_terminal_remote_presence_identity_key(
                    &entry.workspace_id,
                    &entry.pane_id,
                    entry.instance_id,
                ),
                value.clone(),
            );
            value
        })
        .collect::<Vec<_>>();

    json!({
        "items": item_values,
        "by_stream_key": Value::Object(by_stream_key),
        "by_terminal_key": Value::Object(by_terminal_key),
        "updated_at_ms": cloud_mcp_now_ms(),
    })
}

async fn cloud_mcp_emit_terminal_remote_presence_snapshot(state: &CloudMcpState, reason: &str) {
    let Some(app) = CLOUD_MCP_SYNC_STATUS_APP.get() else {
        return;
    };
    let mut payload = cloud_mcp_terminal_remote_presence_snapshot_payload(state).await;
    if let Some(object) = payload.as_object_mut() {
        object.insert("reason".to_string(), json!(reason));
    }
    let _ = app.emit(TERMINAL_REMOTE_PRESENCE_CHANGED_EVENT, payload);
}

fn cloud_mcp_schedule_terminal_remote_presence_emit(state: &CloudMcpState, reason: &'static str) {
    if state
        .terminal_remote_presence_emit_scheduled
        .swap(true, Ordering::SeqCst)
    {
        return;
    }
    let state = state.clone();
    tauri::async_runtime::spawn(async move {
        sleep(Duration::from_millis(TERMINAL_REMOTE_PRESENCE_DEBOUNCE_MS)).await;
        state
            .terminal_remote_presence_emit_scheduled
            .store(false, Ordering::SeqCst);
        cloud_mcp_emit_terminal_remote_presence_snapshot(&state, reason).await;
    });
}

fn cloud_mcp_clear_terminal_remote_presence_state(state: &CloudMcpState, reason: &'static str) {
    if let Ok(mut subscriptions) = state.terminal_io_stream_subscriptions.lock() {
        subscriptions.clear();
    }
    if let Ok(mut owners) = state.terminal_io_control_owners.lock() {
        owners.clear();
    }
    let _ = agent_chat_session_clear_observed_terminals();
    cloud_mcp_schedule_terminal_remote_presence_emit(state, reason);
}

fn cloud_mcp_terminal_remote_presence_stream_matches_terminal(
    stream_key: &str,
    local_device_id: &str,
    workspace_match_key: Option<&str>,
    pane_id: &str,
    instance_id: u64,
) -> bool {
    let Ok(target) = cloud_mcp_terminal_io_target(stream_key) else {
        return false;
    };
    if target.device_id != local_device_id
        || target.pane_id.trim() != pane_id.trim()
        || target.instance_id != instance_id
    {
        return false;
    }
    workspace_match_key.is_none_or(|workspace_match_key| {
        cloud_mcp_workspace_id_match_key(&target.workspace_id) == workspace_match_key
    })
}

fn cloud_mcp_clear_terminal_remote_presence_for_terminal(
    state: &CloudMcpState,
    workspace_id: &str,
    pane_id: &str,
    instance_id: u64,
    reason: &'static str,
) -> bool {
    if pane_id.trim().is_empty() {
        return false;
    }
    let device_id = cloud_mcp_payload_text(&cloud_mcp_desktop_device_profile(), &["device_id"])
        .unwrap_or_else(|| "desktop-primary".to_string());
    let workspace_match_key = cloud_mcp_workspace_id_match_key(workspace_id);
    let workspace_match_key = (!workspace_match_key.is_empty()).then_some(workspace_match_key);
    let mut changed = false;
    if let Ok(mut subscriptions) = state.terminal_io_stream_subscriptions.lock() {
        subscriptions.retain(|stream_key, _| {
            let remove = cloud_mcp_terminal_remote_presence_stream_matches_terminal(
                stream_key,
                &device_id,
                workspace_match_key.as_deref(),
                pane_id,
                instance_id,
            );
            changed |= remove;
            !remove
        });
    }
    if let Ok(mut owners) = state.terminal_io_control_owners.lock() {
        owners.retain(|stream_key, _| {
            let remove = cloud_mcp_terminal_remote_presence_stream_matches_terminal(
                stream_key,
                &device_id,
                workspace_match_key.as_deref(),
                pane_id,
                instance_id,
            );
            changed |= remove;
            !remove
        });
    }
    if let Ok(mut tails) = state.terminal_io_tail_by_stream.lock() {
        tails.retain(|stream_key, _| {
            !cloud_mcp_terminal_remote_presence_stream_matches_terminal(
                stream_key,
                &device_id,
                workspace_match_key.as_deref(),
                pane_id,
                instance_id,
            )
        });
    }
    changed |= agent_chat_session_clear_observed_terminal_matching(
        workspace_match_key.as_deref(),
        pane_id,
        Some(instance_id),
    );
    changed |= agent_chat_session_clear_observed_terminal_matching(
        workspace_match_key.as_deref(),
        pane_id,
        None,
    );
    if changed {
        cloud_mcp_schedule_terminal_remote_presence_emit(state, reason);
    }
    changed
}

async fn cloud_mcp_send_terminal_io_message(
    state: &CloudMcpState,
    request: Option<&Value>,
    target: &CloudMcpTerminalIoTarget,
    kind: &str,
    id: String,
    payload: Value,
) -> Result<(), String> {
    let tx = if let Some(tx) = state.global_ws_termio_tx.lock().await.as_ref().cloned() {
        tx
    } else {
        state
            .global_ws_tx
            .lock()
            .await
            .as_ref()
            .cloned()
            .ok_or_else(|| "Cloud MCP websocket is unavailable.".to_string())?
    };
    let auth = cloud_mcp_ws_auth_object(state).await?;
    let mut envelope = json!({
        "v": 1,
        "contract": CLOUD_MCP_TERMINAL_IO_CONTRACT,
        "kind": kind,
        "id": id,
        "sk": target.stream_key,
        "d": target.device_id,
        "w": target.workspace_id,
        "p": target.pane_id,
        "i": target.instance_id,
        "auth": auth,
        "client_id": CLOUD_MCP_RUST_CLIENT_ID,
    });
    if let (Some(object), Some(payload)) = (envelope.as_object_mut(), payload.as_object()) {
        for (key, value) in payload {
            object.insert(key.clone(), value.clone());
        }
    }
    if let Some(origin) = request
        .and_then(|value| cloud_mcp_payload_text(value, &["origin_connection_id"]))
        .filter(|value| !value.trim().is_empty())
    {
        envelope["origin_connection_id"] = json!(origin);
    }
    tx.send(envelope)
        .map_err(|_| "Cloud MCP websocket terminal sender is closed.".to_string())
}

async fn cloud_mcp_send_terminal_io_error(
    state: &CloudMcpState,
    request: &Value,
    target: &CloudMcpTerminalIoTarget,
    code: &str,
    message: &str,
) {
    let id = cloud_mcp_payload_text(request, &["id"])
        .unwrap_or_else(|| format!("termio-error-{}", cloud_mcp_now_ms()));
    let request_kind = cloud_mcp_terminal_output_message_kind(request);
    let _ = cloud_mcp_send_terminal_io_message(
        state,
        Some(request),
        target,
        "termio.error",
        id,
        json!({"code": code, "message": message, "request_kind": request_kind}),
    )
    .await;
}

fn cloud_mcp_terminal_io_has_control(
    state: &CloudMcpState,
    stream_key: &str,
    origin: &str,
) -> bool {
    state
        .terminal_io_control_owners
        .lock()
        .ok()
        .and_then(|owners| owners.get(stream_key).cloned())
        .is_some_and(|owner| owner.origin.as_str() == origin)
}

fn cloud_mcp_terminal_io_attachment_refs(
    message: &Value,
) -> Result<Vec<ChatAttachmentRef>, String> {
    let Some(attachments) = message.get("attachments") else {
        return Ok(Vec::new());
    };
    serde_json::from_value::<Vec<ChatAttachmentRef>>(attachments.clone())
        .map_err(|_| "Terminal attachment refs are invalid.".to_string())
}

#[cfg(not(windows))]
fn cloud_mcp_terminal_io_shell_quote_path(path: &str) -> String {
    format!("'{}'", path.replace('\'', "'\\''"))
}

#[cfg(windows)]
fn cloud_mcp_terminal_io_shell_quote_path(path: &str) -> String {
    // Diff Forge's default Windows shell is PowerShell. Single-quoted
    // PowerShell strings escape a literal quote by doubling it.
    format!("'{}'", path.replace('\'', "''"))
}

fn cloud_mcp_terminal_io_shell_attachment_paste(
    attachments: &[SavedTodoImageAttachment],
) -> Result<Vec<u8>, String> {
    let quoted = attachments
        .iter()
        .map(|attachment| attachment.path.trim())
        .filter(|path| !path.is_empty())
        .map(|path| {
            if path.chars().any(char::is_control) {
                Err("Staged attachment path contains invalid control characters.".to_string())
            } else {
                Ok(cloud_mcp_terminal_io_shell_quote_path(path))
            }
        })
        .collect::<Result<Vec<_>, _>>()?;
    if quoted.is_empty() {
        return Err("No verified terminal attachment paths were staged.".to_string());
    }
    let mut bytes = Vec::new();
    bytes.extend_from_slice(b"\x1b[200~");
    bytes.extend_from_slice(quoted.join(" ").as_bytes());
    bytes.extend_from_slice(b"\x1b[201~");
    Ok(bytes)
}

async fn cloud_mcp_handle_terminal_io_message(
    state: &CloudMcpState,
    message: &Value,
    fallback_kind: &str,
) -> bool {
    let direct = cloud_mcp_terminal_output_message_kind(message);
    let kind = if direct.is_empty() {
        fallback_kind.trim().to_ascii_lowercase()
    } else {
        direct
    };
    if cloud_mcp_payload_text(message, &["contract", "c"]).as_deref()
        != Some(CLOUD_MCP_TERMINAL_IO_CONTRACT)
    {
        return false;
    }
    if !kind.starts_with("termio.") {
        return true;
    }
    let Some(stream_key) = cloud_mcp_payload_text(message, &["sk", "stream_key"])
        .filter(|value| !value.trim().is_empty())
    else {
        return true;
    };
    let Ok(target) = cloud_mcp_terminal_io_target(&stream_key) else {
        return true;
    };
    let local_device = cloud_mcp_payload_text(&cloud_mcp_desktop_device_profile(), &["device_id"])
        .unwrap_or_else(|| "desktop-primary".to_string());
    if target.device_id != local_device {
        return true;
    }
    let Some(app) = CLOUD_MCP_SYNC_STATUS_APP.get().cloned() else {
        cloud_mcp_send_terminal_io_error(
            state,
            message,
            &target,
            "desktop_not_ready",
            "Desktop terminal runtime is not ready.",
        )
        .await;
        return true;
    };
    let terminal_state = app.state::<TerminalState>();
    let instance = match get_terminal_instance_if_current(
        terminal_state.inner(),
        &target.pane_id,
        Some(target.instance_id),
    )
    .await
    {
        Ok(Some(instance))
            if cloud_mcp_workspace_id_match_key(&instance.metadata.workspace_id)
                == cloud_mcp_workspace_id_match_key(&target.workspace_id) =>
        {
            instance
        }
        _ => {
            let id = cloud_mcp_payload_text(message, &["id"])
                .unwrap_or_else(|| format!("termio-ended-{}", cloud_mcp_now_ms()));
            let _ = cloud_mcp_send_terminal_io_message(
                state,
                Some(message),
                &target,
                "termio.ended",
                id,
                json!({
                    "reason": "stale_or_missing_instance",
                    "request_kind": kind,
                }),
            )
            .await;
            return true;
        }
    };
    let origin = cloud_mcp_terminal_io_origin(message);
    let request_id = cloud_mcp_payload_text(message, &["id"])
        .unwrap_or_else(|| format!("termio-{}", cloud_mcp_now_ms()));
    cloud_mcp_touch_terminal_io_presence_origin(state, &target.stream_key, &origin);

    match kind.as_str() {
        "termio.attach" => {
            // Serialize hydration against live output so attached + snapshot
            // establishes the byte offset before any later delta can pass it.
            let _send_guard = state.terminal_io_output_send_lock.lock().await;
            if let Ok(mut subscriptions) = state.terminal_io_stream_subscriptions.lock() {
                subscriptions
                    .entry(target.stream_key.clone())
                    .or_default()
                    .insert(
                        origin.clone(),
                        CloudMcpTerminalIoSubscription {
                            attachment_id: request_id.clone(),
                            last_seen_ms: cloud_mcp_now_ms(),
                        },
                    );
            }
            cloud_mcp_schedule_terminal_remote_presence_reaper(state);
            cloud_mcp_schedule_terminal_remote_presence_emit(state, "termio_attach");
            let size = *instance.size.lock().await;
            let (total, bytes, retained_tail_bytes) = {
                let output = instance.headless_output.lock().ok();
                let total = output.as_ref().map(|value| value.total_bytes).unwrap_or(0);
                let bytes = output
                    .as_ref()
                    .map(|value| value.vt_state())
                    .unwrap_or_default();
                let retained_tail_bytes =
                    output.as_ref().map(|value| value.tail.len()).unwrap_or(0);
                (total, bytes, retained_tail_bytes)
            };
            let seq = state
                .terminal_io_tail_by_stream
                .lock()
                .ok()
                .and_then(|tails| tails.get(&target.stream_key).map(|tail| tail.seq))
                .unwrap_or(0);
            let _ = cloud_mcp_send_terminal_io_message(
                state,
                Some(message),
                &target,
                "termio.attached",
                request_id.clone(),
                json!({"attachment_id": request_id, "cols": size.cols, "rows": size.rows, "seq": seq, "q": seq, "f": total, "n": total, "from_total_bytes": total, "total_bytes": total, "mode": "vt", "retained_tail_bytes": retained_tail_bytes}),
            )
            .await;
            let _ = cloud_mcp_send_terminal_io_message(
                state,
                Some(message),
                &target,
                "termio.snapshot",
                format!("{}-snapshot", request_id),
                json!({
                    "attachment_id": request_id,
                    "q": seq,
                    "seq": seq,
                    "f": total,
                    "n": total,
                    "from_total_bytes": total,
                    "total_bytes": total,
                    "b": general_purpose::STANDARD.encode(bytes),
                    "mode": "vt",
                    "reset": true,
                    "truncated": false,
                    "retained_tail_bytes": retained_tail_bytes,
                }),
            )
            .await;
        }
        "termio.detach" => {
            let attachment_id = cloud_mcp_payload_text(message, &["attachment_id", "attach_id"]);
            if let Ok(mut subscriptions) = state.terminal_io_stream_subscriptions.lock() {
                if let Some(origins) = subscriptions.get_mut(&target.stream_key) {
                    let current_attachment = origins
                        .get(&origin)
                        .map(|subscription| subscription.attachment_id.clone());
                    if attachment_id
                        .as_deref()
                        .is_none_or(|requested| current_attachment.as_deref() == Some(requested))
                    {
                        origins.remove(&origin);
                    }
                    if origins.is_empty() {
                        subscriptions.remove(&target.stream_key);
                    }
                }
            }
            if let Ok(mut owners) = state.terminal_io_control_owners.lock() {
                if owners
                    .get(&target.stream_key)
                    .is_some_and(|owner| owner.origin.as_str() == origin)
                {
                    owners.remove(&target.stream_key);
                }
            }
            cloud_mcp_schedule_terminal_remote_presence_emit(state, "termio_detach");
        }
        "termio.control.request" => {
            let granted = if let Ok(mut owners) = state.terminal_io_control_owners.lock() {
                match owners.get(&target.stream_key) {
                    Some(owner) => owner.origin.as_str() == origin,
                    None => {
                        owners.insert(
                            target.stream_key.clone(),
                            CloudMcpTerminalIoControlOwner {
                                origin: origin.clone(),
                                last_seen_ms: cloud_mcp_now_ms(),
                            },
                        );
                        true
                    }
                }
            } else {
                false
            };
            if granted {
                cloud_mcp_schedule_terminal_remote_presence_reaper(state);
                cloud_mcp_schedule_terminal_remote_presence_emit(state, "termio_control_request");
            }
            let response_kind = if granted {
                "termio.control.granted"
            } else {
                "termio.control.denied"
            };
            let _ = cloud_mcp_send_terminal_io_message(
                state,
                Some(message),
                &target,
                response_kind,
                request_id,
                json!({"granted": granted}),
            )
            .await;
        }
        "termio.control.release" => {
            let released = if let Ok(mut owners) = state.terminal_io_control_owners.lock() {
                if owners
                    .get(&target.stream_key)
                    .is_some_and(|owner| owner.origin.as_str() == origin)
                {
                    owners.remove(&target.stream_key);
                    true
                } else {
                    false
                }
            } else {
                false
            };
            if released {
                cloud_mcp_schedule_terminal_remote_presence_emit(state, "termio_control_release");
            }
            let response_kind = if released {
                "termio.control.released"
            } else {
                "termio.control.denied"
            };
            let _ = cloud_mcp_send_terminal_io_message(
                state,
                Some(message),
                &target,
                response_kind,
                request_id,
                json!({"released": released}),
            )
            .await;
        }
        "termio.heartbeat" => {
            let heartbeat_seq = cloud_mcp_payload_u64(message, &["seq", "q"]).unwrap_or(0);
            let _ = cloud_mcp_send_terminal_io_message(
                state,
                Some(message),
                &target,
                "termio.heartbeat.ack",
                request_id,
                json!({"seq": heartbeat_seq, "q": heartbeat_seq}),
            )
            .await;
        }
        "termio.output.ack" | "termio.output_ack" => {}
        "termio.input" => {
            let input_seq = cloud_mcp_payload_u64(message, &["seq", "q"]).unwrap_or(0);
            if !cloud_mcp_terminal_io_has_control(state, &target.stream_key, &origin) {
                let _ = cloud_mcp_send_terminal_io_message(state, Some(message), &target, "termio.input.ack", request_id, json!({"seq": input_seq, "q": input_seq, "ok": false, "code": "control_required"})).await;
                return true;
            }
            let attachment_refs = match cloud_mcp_terminal_io_attachment_refs(message) {
                Ok(attachments) => attachments,
                Err(error) => {
                    let _ = cloud_mcp_send_terminal_io_message(state, Some(message), &target, "termio.input.ack", request_id, json!({"seq": input_seq, "q": input_seq, "ok": false, "code": "invalid_attachments", "error": error})).await;
                    return true;
                }
            };
            let mut decoded = match cloud_mcp_payload_text(message, &["b", "bytes_base64"]) {
                Some(value) if !value.is_empty() => match general_purpose::STANDARD.decode(value) {
                    Ok(bytes) => bytes,
                    Err(_) => {
                        let _ = cloud_mcp_send_terminal_io_message(state, Some(message), &target, "termio.input.ack", request_id, json!({"seq": input_seq, "q": input_seq, "ok": false, "code": "invalid_base64", "error": "Terminal input is not valid base64."})).await;
                        return true;
                    }
                },
                _ => Vec::new(),
            };
            let attachment_count = attachment_refs.len();
            if !attachment_refs.is_empty() {
                if terminal_metadata_is_codex(&instance.metadata)
                    || terminal_metadata_is_claude(&instance.metadata)
                    || terminal_metadata_is_opencode(&instance.metadata)
                {
                    let _ = cloud_mcp_send_terminal_io_message(state, Some(message), &target, "termio.input.ack", request_id, json!({"seq": input_seq, "q": input_seq, "ok": false, "code": "native_attachment_path_required", "error": "Coding-agent images must use the existing native attachment composer path."})).await;
                    return true;
                }
                let request = ChatAttachmentStageRequest {
                    workspace_id: target.workspace_id.clone(),
                    attachments: attachment_refs,
                    ack_cloud: true,
                    marker_start_index: 0,
                };
                let staged = match timeout(
                    Duration::from_secs(30),
                    tauri::async_runtime::spawn_blocking(move || {
                        stage_chat_attachment_refs_for_dispatch(request)
                    }),
                )
                .await
                {
                    Ok(Ok(result)) if result.failed.is_empty() => result,
                    Ok(Ok(result)) => {
                        let error = result
                            .failed
                            .iter()
                            .map(|failure| format!("{}: {}", failure.name, failure.reason))
                            .collect::<Vec<_>>()
                            .join("; ");
                        let _ = cloud_mcp_send_terminal_io_message(state, Some(message), &target, "termio.input.ack", request_id, json!({"seq": input_seq, "q": input_seq, "ok": false, "code": "attachment_stage_failed", "error": error})).await;
                        return true;
                    }
                    Ok(Err(error)) => {
                        let _ = cloud_mcp_send_terminal_io_message(state, Some(message), &target, "termio.input.ack", request_id, json!({"seq": input_seq, "q": input_seq, "ok": false, "code": "attachment_stage_failed", "error": error.to_string()})).await;
                        return true;
                    }
                    Err(_) => {
                        let _ = cloud_mcp_send_terminal_io_message(state, Some(message), &target, "termio.input.ack", request_id, json!({"seq": input_seq, "q": input_seq, "ok": false, "code": "attachment_stage_timeout", "error": "Terminal attachment staging timed out."})).await;
                        return true;
                    }
                };
                let mut attachment_paste = match cloud_mcp_terminal_io_shell_attachment_paste(
                    &staged.attachments,
                ) {
                    Ok(bytes) => bytes,
                    Err(error) => {
                        let _ = cloud_mcp_send_terminal_io_message(state, Some(message), &target, "termio.input.ack", request_id, json!({"seq": input_seq, "q": input_seq, "ok": false, "code": "attachment_path_invalid", "error": error})).await;
                        return true;
                    }
                };
                attachment_paste.append(&mut decoded);
                decoded = attachment_paste;
            }
            let result = if decoded.is_empty() {
                Err("Terminal input and attachments are empty.".to_string())
            } else {
                write_terminal_input_bytes(
                    terminal_state.inner(),
                    &target.pane_id,
                    target.instance_id,
                    &decoded,
                )
                .await
            };
            let ok = matches!(result, Ok(true));
            let error = result.err().unwrap_or_default();
            let _ = cloud_mcp_send_terminal_io_message(state, Some(message), &target, "termio.input.ack", request_id, json!({"seq": input_seq, "q": input_seq, "ok": ok, "error": error, "attachment_count": attachment_count, "attachment_delivery": if attachment_count > 0 { "shell_quoted_bracketed_paste" } else { "none" }})).await;
        }
        "termio.resize" => {
            let resize_seq = cloud_mcp_payload_u64(message, &["seq", "q"]).unwrap_or(0);
            if !cloud_mcp_terminal_io_has_control(state, &target.stream_key, &origin) {
                cloud_mcp_send_terminal_io_error(
                    state,
                    message,
                    &target,
                    "control_required",
                    "Terminal control is required before resize.",
                )
                .await;
                return true;
            }
            let cols = cloud_mcp_payload_u64(message, &["cols"])
                .and_then(|value| u16::try_from(value).ok());
            let rows = cloud_mcp_payload_u64(message, &["rows"])
                .and_then(|value| u16::try_from(value).ok());
            let result = match (cols, rows) {
                (Some(cols), Some(rows)) => {
                    resize_terminal_instance_exact(
                        &app,
                        terminal_state.inner(),
                        &target.pane_id,
                        target.instance_id,
                        cols,
                        rows,
                    )
                    .await
                }
                _ => Err("Terminal resize dimensions are invalid.".to_string()),
            };
            match result {
                Ok(true) => {
                    let _ = cloud_mcp_send_terminal_io_message(
                        state,
                        Some(message),
                        &target,
                        "termio.resized",
                        request_id,
                        json!({"seq": resize_seq, "q": resize_seq, "cols": cols, "rows": rows}),
                    )
                    .await;
                }
                Ok(false) => {
                    cloud_mcp_send_terminal_io_error(
                        state,
                        message,
                        &target,
                        "stale_instance",
                        "Terminal instance is no longer current.",
                    )
                    .await
                }
                Err(error) => {
                    cloud_mcp_send_terminal_io_error(
                        state,
                        message,
                        &target,
                        "resize_failed",
                        &error,
                    )
                    .await
                }
            }
        }
        "termio.signal" => {
            let signal = cloud_mcp_payload_text(message, &["signal"])
                .unwrap_or_default()
                .to_ascii_lowercase();
            if !cloud_mcp_terminal_io_has_control(state, &target.stream_key, &origin) {
                cloud_mcp_send_terminal_io_error(
                    state,
                    message,
                    &target,
                    "control_required",
                    "Terminal control is required before sending a signal.",
                )
                .await;
                return true;
            }
            let result = match signal.as_str() {
                "interrupt" | "escape" => terminal_interrupt_agent_remote(
                    app.clone(),
                    target.pane_id.clone(),
                    Some(target.instance_id),
                    "termio_signal".to_string(),
                )
                .await
                .map(|_| true),
                "sigint"
                    if terminal_metadata_is_codex(&instance.metadata)
                        || terminal_metadata_is_claude(&instance.metadata)
                        || terminal_metadata_is_opencode(&instance.metadata) =>
                {
                    terminal_interrupt_agent_remote(
                        app.clone(),
                        target.pane_id.clone(),
                        Some(target.instance_id),
                        "termio_sigint".to_string(),
                    )
                    .await
                    .map(|_| true)
                }
                "sigint" => {
                    write_terminal_input_bytes(
                        terminal_state.inner(),
                        &target.pane_id,
                        target.instance_id,
                        &[0x03],
                    )
                    .await
                }
                "sigquit" => {
                    write_terminal_input_bytes(
                        terminal_state.inner(),
                        &target.pane_id,
                        target.instance_id,
                        &[0x1c],
                    )
                    .await
                }
                "break" => {
                    write_terminal_input_bytes(
                        terminal_state.inner(),
                        &target.pane_id,
                        target.instance_id,
                        &[0x03],
                    )
                    .await
                }
                "eof" => {
                    write_terminal_input_bytes(
                        terminal_state.inner(),
                        &target.pane_id,
                        target.instance_id,
                        &[0x04],
                    )
                    .await
                }
                "sigterm" | "sighup" | "terminate" | "close" => {
                    close_terminal_session(
                        Some(app.clone()),
                        terminal_state.inner(),
                        Some(state),
                        &target.pane_id,
                        Some(target.instance_id),
                        false,
                        false,
                        None,
                    )
                    .await
                }
                _ => Err("Unsupported terminal signal.".to_string()),
            };
            match result {
                Ok(true) => {
                    let _ = cloud_mcp_send_terminal_io_message(state, Some(message), &target, "termio.signal.ack", request_id, json!({"seq": cloud_mcp_payload_u64(message, &["seq", "q"]).unwrap_or(0), "ok": true, "signal": signal})).await;
                }
                Ok(false) => {
                    cloud_mcp_send_terminal_io_error(
                        state,
                        message,
                        &target,
                        "stale_instance",
                        "Terminal instance is no longer current.",
                    )
                    .await
                }
                Err(error) => {
                    cloud_mcp_send_terminal_io_error(
                        state,
                        message,
                        &target,
                        "signal_failed",
                        &error,
                    )
                    .await
                }
            }
        }
        _ => {
            cloud_mcp_send_terminal_io_error(
                state,
                message,
                &target,
                "unsupported_kind",
                "Unsupported terminal I/O message kind.",
            )
            .await
        }
    }
    true
}

fn cloud_mcp_handle_agent_session_observer_subscription(
    state: &CloudMcpState,
    message: &Value,
    fallback_kind: &str,
) -> bool {
    let direct_kind = cloud_mcp_terminal_output_message_kind(message);
    let kind = if direct_kind.is_empty() {
        fallback_kind.trim().to_ascii_lowercase()
    } else {
        direct_kind
    };
    if !matches!(
        kind.as_str(),
        "session.watch" | "session.unwatch" | "session.heartbeat"
    ) {
        return false;
    }
    let heartbeat = kind == "session.heartbeat";
    let active =
        kind == "session.watch" && message.get("active").and_then(Value::as_bool) != Some(false);
    let stream_key = cloud_mcp_terminal_output_message_stream_key(message).unwrap_or_default();
    let stream_target = cloud_mcp_terminal_io_target(&stream_key).ok();
    let parts = stream_key.split(':').collect::<Vec<_>>();
    let workspace_id = cloud_mcp_payload_text(message, &["w", "workspace_id"])
        .or_else(|| {
            stream_target
                .as_ref()
                .map(|target| target.workspace_id.clone())
        })
        .or_else(|| {
            parts
                .get(1)
                .map(|value| cloud_mcp_terminal_output_decode_key_component(value))
        })
        .map(|value| cloud_mcp_workspace_id_match_key(&value))
        .unwrap_or_default();
    let pane_id = cloud_mcp_payload_text(message, &["p", "pane_id", "terminal_id"])
        .or_else(|| stream_target.as_ref().map(|target| target.pane_id.clone()))
        .or_else(|| {
            parts
                .get(2)
                .map(|value| cloud_mcp_terminal_output_decode_key_component(value))
        })
        .unwrap_or_default();
    let instance_id = cloud_mcp_payload_u64(message, &["i", "terminal_instance_id", "instance_id"])
        .or_else(|| stream_target.as_ref().map(|target| target.instance_id))
        .or_else(|| {
            parts.get(3).and_then(|value| {
                cloud_mcp_terminal_output_decode_key_component(value)
                    .parse::<u64>()
                    .ok()
            })
        });
    if workspace_id.trim().is_empty() || pane_id.trim().is_empty() {
        return true;
    }
    let origin = cloud_mcp_payload_text(message, &["origin_connection_id"]);
    let subscription_count = if heartbeat {
        agent_chat_session_touch_terminal_observed(
            &workspace_id,
            &pane_id,
            instance_id,
            origin.as_deref(),
        )
    } else {
        agent_chat_session_set_terminal_observed(
            &workspace_id,
            &pane_id,
            instance_id,
            origin.as_deref(),
            active,
        )
    };
    if active || (heartbeat && subscription_count > 0) {
        cloud_mcp_schedule_terminal_remote_presence_reaper(state);
    }
    if !heartbeat {
        cloud_mcp_schedule_terminal_remote_presence_emit(
            state,
            if active {
                "session_watch"
            } else {
                "session_unwatch"
            },
        );
    }
    let triggered = if active {
        CLOUD_MCP_SYNC_STATUS_APP
            .get()
            .map(|app| {
                trigger_agent_thread_transcript_native_watch(
                    app,
                    &pane_id,
                    instance_id,
                    "session-observer-opened",
                )
            })
            .unwrap_or_default()
    } else {
        0
    };
    log_cloud_sync_event(
        "agent_chat_session.observer_subscription",
        json!({
            "active": active,
            "heartbeat": heartbeat,
            "instance_id": instance_id,
            "origin_connection_id": origin,
            "pane_id": pane_id,
            "stream_key": stream_key,
            "subscription_count": subscription_count,
            "triggered_watch_count": triggered,
            "workspace_id": workspace_id,
        }),
    );
    true
}

fn cloud_mcp_terminal_output_stream_is_subscribed(state: &CloudMcpState, stream_key: &str) -> bool {
    state
        .terminal_io_stream_subscriptions
        .lock()
        .map(|subscriptions| {
            subscriptions
                .get(stream_key)
                .is_some_and(|origins| !origins.is_empty())
        })
        .unwrap_or(false)
}

fn cloud_mcp_terminal_output_stream_key(
    device_id: &str,
    workspace_id: &str,
    pane_id: &str,
    instance_id: u64,
) -> String {
    let workspace_id = cloud_mcp_workspace_id_match_key(workspace_id);
    format!(
        "{}:{}:{}:{}",
        cloud_mcp_terminal_output_key_component(device_id),
        cloud_mcp_terminal_output_key_component(&workspace_id),
        cloud_mcp_terminal_output_key_component(pane_id),
        cloud_mcp_terminal_output_key_component(&instance_id.to_string()),
    )
}

const CLOUD_MCP_TERMINAL_OUTPUT_REPLAY_TAIL_BYTES: usize = TERMINAL_HEADLESS_OUTPUT_TAIL_BYTES;

fn cloud_mcp_remember_terminal_output_tail(
    state: &CloudMcpState,
    stream_key: &str,
    seq: u64,
    total_bytes: u64,
    chunk: &[u8],
) -> bool {
    if chunk.is_empty() {
        return false;
    }
    let Ok(mut tails) = state.terminal_io_tail_by_stream.lock() else {
        return false;
    };
    let entry = tails.entry(stream_key.to_string()).or_default();
    if seq <= entry.seq {
        return false;
    }
    if total_bytes < entry.total_bytes {
        entry.tail.clear();
    }
    entry.seq = seq;
    entry.total_bytes = total_bytes;
    entry.tail.extend_from_slice(chunk);
    let overflow = entry
        .tail
        .len()
        .saturating_sub(CLOUD_MCP_TERMINAL_OUTPUT_REPLAY_TAIL_BYTES);
    if overflow > 0 {
        entry.tail.drain(..overflow);
    }
    if tails.len() > 256 {
        let stale_keys = tails
            .keys()
            .take(tails.len().saturating_sub(256))
            .cloned()
            .collect::<Vec<_>>();
        for key in stale_keys {
            tails.remove(&key);
        }
    }
    true
}

#[cfg(test)]
fn cloud_mcp_terminal_output_replay_frame(
    state: &CloudMcpState,
    stream_key: &str,
    requested_from: u64,
) -> Option<(u64, u64, u64, Vec<u8>, bool)> {
    let tails = state.terminal_io_tail_by_stream.lock().ok()?;
    let tail = tails.get(stream_key)?;
    if tail.tail.is_empty() {
        return None;
    }
    let tail_start = tail.total_bytes.saturating_sub(tail.tail.len() as u64);
    let truncated = requested_from < tail_start;
    let from_total_bytes = if truncated {
        tail_start
    } else {
        requested_from.min(tail.total_bytes)
    };
    if from_total_bytes >= tail.total_bytes && !truncated {
        return None;
    }
    let start_index = from_total_bytes
        .saturating_sub(tail_start)
        .min(tail.tail.len() as u64) as usize;
    Some((
        tail.seq,
        from_total_bytes,
        tail.total_bytes,
        tail.tail[start_index..].to_vec(),
        truncated,
    ))
}

pub(crate) fn cloud_mcp_publish_terminal_output_delta(
    state: &CloudMcpState,
    headless_output: &Arc<StdMutex<TerminalHeadlessOutputBuffer>>,
    workspace_id: &str,
    pane_id: &str,
    instance_id: u64,
    seq: u64,
    chunk: &[u8],
) {
    if chunk.is_empty() {
        return;
    }
    let device_id = cloud_mcp_payload_text(&cloud_mcp_desktop_device_profile(), &["device_id"])
        .unwrap_or_else(|| "desktop-primary".to_string());
    let stream_key =
        cloud_mcp_terminal_output_stream_key(&device_id, workspace_id, pane_id, instance_id);
    let state = state.clone();
    let headless_output = Arc::clone(headless_output);
    let chunk = chunk.to_vec();
    tauri::async_runtime::block_on(async move {
        // This lock is the terminal journal barrier. A checkpoint and a delta
        // can no longer observe two different byte clocks: parser append,
        // replay-tail advance, and websocket enqueue happen as one ordered cut.
        let _send_guard = state.terminal_io_output_send_lock.lock().await;
        let (from_total_bytes, total_bytes) = {
            let Ok(mut output) = headless_output.lock() else {
                return;
            };
            let from = output.total_bytes;
            output.append(&chunk);
            (from, output.total_bytes)
        };
        let gap = state
            .terminal_io_tail_by_stream
            .lock()
            .ok()
            .and_then(|tails| tails.get(&stream_key).cloned())
            .filter(|previous| {
                previous.seq.saturating_add(1) != seq || previous.total_bytes != from_total_bytes
            })
            .map(|previous| (previous.seq, previous.total_bytes));
        if !cloud_mcp_remember_terminal_output_tail(&state, &stream_key, seq, total_bytes, &chunk) {
            return;
        }
        if !cloud_mcp_terminal_output_stream_is_subscribed(&state, &stream_key) {
            return;
        }
        let tx = if let Some(tx) = state.global_ws_termio_tx.lock().await.as_ref().cloned() {
            tx
        } else if let Some(tx) = state.global_ws_tx.lock().await.as_ref().cloned() {
            tx
        } else {
            return;
        };
        let Ok(auth) = cloud_mcp_ws_auth_object(&state).await else {
            return;
        };
        if let Some((previous_seq, previous_total_bytes)) = gap {
            let gap_envelope = json!({
                "v": 1,
                "kind": "termio.gap",
                "contract": CLOUD_MCP_TERMINAL_IO_CONTRACT,
                "auth": auth.clone(),
                "client_id": CLOUD_MCP_RUST_CLIENT_ID,
                "id": format!("termio-gap-{instance_id}-{seq}"),
                "sk": stream_key.as_str(),
                "seq": seq,
                "q": seq,
                "from": previous_total_bytes,
                "to": from_total_bytes,
                "previous_seq": previous_seq,
                "reason": "desktop_output_sequence_gap",
            });
            if tx.send(gap_envelope).is_err() {
                cloud_mcp_mark_global_ws_disconnected(
                    &state,
                    "Cloud MCP app websocket terminal-output sender is closed.",
                )
                .await;
                return;
            }
        }
        let envelope = json!({
            "v": 1,
            "kind": "termio.output",
            "contract": CLOUD_MCP_TERMINAL_IO_CONTRACT,
            "auth": auth,
            "client_id": CLOUD_MCP_RUST_CLIENT_ID,
            "id": format!("termio-output-{instance_id}-{seq}"),
            "sk": stream_key.as_str(),
            "q": seq,
            "seq": seq,
            "f": from_total_bytes,
            "n": total_bytes,
            "from_total_bytes": from_total_bytes,
            "total_bytes": total_bytes,
            "b": general_purpose::STANDARD.encode(chunk),
        });
        if tx.send(envelope).is_err() {
            cloud_mcp_mark_global_ws_disconnected(
                &state,
                "Cloud MCP app websocket terminal-output sender is closed.",
            )
            .await;
        }
    });
}

async fn cloud_mcp_publish_terminal_io_ended(
    state: &CloudMcpState,
    workspace_id: &str,
    pane_id: &str,
    instance_id: u64,
    reason: &str,
) {
    let device_id = cloud_mcp_payload_text(&cloud_mcp_desktop_device_profile(), &["device_id"])
        .unwrap_or_else(|| "desktop-primary".to_string());
    let stream_key =
        cloud_mcp_terminal_output_stream_key(&device_id, workspace_id, pane_id, instance_id);
    let _send_guard = state.terminal_io_output_send_lock.lock().await;
    if cloud_mcp_terminal_output_stream_is_subscribed(state, &stream_key) {
        let target = CloudMcpTerminalIoTarget {
            stream_key: stream_key.clone(),
            device_id,
            workspace_id: cloud_mcp_workspace_id_match_key(workspace_id),
            pane_id: pane_id.to_string(),
            instance_id,
        };
        let _ = cloud_mcp_send_terminal_io_message(
            state,
            None,
            &target,
            "termio.ended",
            format!("termio-ended-{instance_id}-{}", cloud_mcp_now_ms()),
            json!({"reason": reason}),
        )
        .await;
    }
    let _ = cloud_mcp_clear_terminal_remote_presence_for_terminal(
        state,
        workspace_id,
        pane_id,
        instance_id,
        "termio_ended",
    );
}

pub(crate) async fn cloud_mcp_revoke_terminal_io_control_for_local_action(
    state: &CloudMcpState,
    workspace_id: &str,
    pane_id: &str,
    instance_id: u64,
    reason: &str,
) {
    let device_id = cloud_mcp_payload_text(&cloud_mcp_desktop_device_profile(), &["device_id"])
        .unwrap_or_else(|| "desktop-primary".to_string());
    let stream_key =
        cloud_mcp_terminal_output_stream_key(&device_id, workspace_id, pane_id, instance_id);
    let previous_owner = state
        .terminal_io_control_owners
        .lock()
        .ok()
        .and_then(|mut owners| owners.remove(&stream_key));
    let Some(previous_owner) = previous_owner else {
        return;
    };
    cloud_mcp_schedule_terminal_remote_presence_emit(state, "termio_control_local_revoke");
    let target = CloudMcpTerminalIoTarget {
        stream_key,
        device_id,
        workspace_id: cloud_mcp_workspace_id_match_key(workspace_id),
        pane_id: pane_id.to_string(),
        instance_id,
    };
    let request = json!({"origin_connection_id": previous_owner.origin});
    let _ = cloud_mcp_send_terminal_io_message(
        state,
        Some(&request),
        &target,
        "termio.control.released",
        format!("termio-local-revoke-{instance_id}-{}", cloud_mcp_now_ms()),
        json!({"released": true, "reason": reason, "source": "native"}),
    )
    .await;
}

pub(crate) fn cloud_mcp_terminal_io_has_remote_control(
    state: &CloudMcpState,
    workspace_id: &str,
    pane_id: &str,
    instance_id: u64,
) -> bool {
    let device_id = cloud_mcp_payload_text(&cloud_mcp_desktop_device_profile(), &["device_id"])
        .unwrap_or_else(|| "desktop-primary".to_string());
    let stream_key =
        cloud_mcp_terminal_output_stream_key(&device_id, workspace_id, pane_id, instance_id);
    state
        .terminal_io_control_owners
        .lock()
        .map(|owners| owners.contains_key(&stream_key))
        .unwrap_or(false)
}

async fn cloud_mcp_flush_pending_device_live_snapshot(state: &CloudMcpState) {
    let reason = state
        .device_live_snapshot_debounce
        .lock()
        .ok()
        .and_then(|mut pending| pending.take());
    if let Some(reason) = reason {
        cloud_mcp_publish_device_live_state_snapshot(state, &reason).await;
    }
}

fn cloud_mcp_post_log_context(
    endpoint: &str,
    payload: &Value,
) -> Option<(PathBuf, String, String, Value)> {
    let repo_path = cloud_mcp_payload_text(payload, &["repo_path"])
        .or_else(|| cloud_mcp_payload_text(payload, &["workspace_root"]))
        .or_else(|| cloud_mcp_payload_text(payload, &["payload", "repo_path"]))
        .or_else(|| cloud_mcp_payload_text(payload, &["payload", "workspace_root"]))?;
    let root = resolve_workspace_root_directory(Some(&repo_path))
        .unwrap_or_else(|_| PathBuf::from(&repo_path));
    let workspace_id = cloud_mcp_payload_text(payload, &["workspace_id"])
        .or_else(|| cloud_mcp_payload_text(payload, &["payload", "workspace_id"]))
        .unwrap_or_default();
    let workspace_name = cloud_mcp_payload_text(payload, &["workspace_name"])
        .or_else(|| cloud_mcp_payload_text(payload, &["payload", "workspace_name"]))
        .unwrap_or_default();
    let agent_id = cloud_mcp_payload_text(payload, &["agent_id"])
        .or_else(|| cloud_mcp_payload_text(payload, &["payload", "agent_id"]))
        .unwrap_or_else(|| "rust-diffforge".to_string());
    let pane_id = cloud_mcp_payload_text(payload, &["terminal_id"])
        .or_else(|| cloud_mcp_payload_text(payload, &["pane_id"]))
        .or_else(|| cloud_mcp_payload_text(payload, &["payload", "terminal_id"]))
        .or_else(|| cloud_mcp_payload_text(payload, &["payload", "pane_id"]));
    let terminal_instance_id = payload
        .get("terminal_instance_id")
        .or_else(|| payload.get("instance_id"))
        .or_else(|| {
            payload
                .get("payload")
                .and_then(|payload| payload.get("terminal_instance_id"))
        })
        .or_else(|| {
            payload
                .get("payload")
                .and_then(|payload| payload.get("instance_id"))
        })
        .cloned();
    let tool = match endpoint {
        "/v1/status" => "cloud_status",
        "/v1/assets/list" => "cloud_list_account_assets",
        "/v1/assets/clouds/list" => "cloud_list_asset_clouds",
        "/v1/assets/clouds/save" => "cloud_save_asset_cloud",
        "/v1/assets/clouds/validate" => "cloud_validate_asset_cloud",
        "/v1/assets/clouds/default" => "cloud_set_default_asset_cloud",
        "/v1/assets/clouds/delete" => "cloud_delete_asset_cloud",
        "/v1/assets/register" => "cloud_register_account_asset",
        "/v1/assets/prepare-upload" => "cloud_prepare_asset_upload",
        "/v1/assets/complete-upload" => "cloud_complete_asset_upload",
        "/v1/assets/prepare-download" => "cloud_prepare_asset_download",
        "/v1/assets/delete-cloud" => "cloud_delete_cloud_asset",
        "/v1/assets/publish-public" => "cloud_publish_public_asset",
        "/v1/assets/unpublish-public" => "cloud_unpublish_public_asset",
        "/v1/assets/status" => "cloud_get_asset_status",
        "/v1/assets/report-transfer-progress" => "cloud_report_asset_transfer_progress",
        "/v1/events" => payload
            .get("event_kind")
            .and_then(Value::as_str)
            .unwrap_or("cloud_event"),
        _ => "cloud_mcp_http",
    };
    let mut fields = json!({
        "endpoint": endpoint,
        "tool": tool,
        "agent_id": agent_id,
        "repo_path": repo_path,
    });
    if let Some(pane_id) = pane_id {
        fields["pane_id"] = json!(pane_id);
    }
    if let Some(terminal_instance_id) = terminal_instance_id {
        fields["terminal_instance_id"] = terminal_instance_id;
    }

    Some((root, workspace_id, workspace_name, fields))
}

fn cloud_mcp_payload_text(payload: &Value, path: &[&str]) -> Option<String> {
    for key in path {
        if let Some(value) = payload
            .get(*key)
            .and_then(Value::as_str)
            .map(str::to_string)
            .filter(|value| !value.trim().is_empty())
        {
            return Some(value);
        }
    }

    let mut current = payload;
    for key in path {
        current = current.get(*key)?;
    }
    current
        .as_str()
        .map(str::to_string)
        .filter(|value| !value.trim().is_empty())
}

fn cloud_mcp_payload_i64(payload: &Value, path: &[&str]) -> Option<i64> {
    for key in path {
        if let Some(value) = payload.get(*key).and_then(|value| {
            value
                .as_i64()
                .or_else(|| value.as_str()?.trim().parse::<i64>().ok())
        }) {
            return Some(value);
        }
    }

    let mut current = payload;
    for key in path {
        current = current.get(*key)?;
    }
    current
        .as_i64()
        .or_else(|| current.as_str()?.trim().parse::<i64>().ok())
}

fn cloud_mcp_terminal_nickname_key(value: &str) -> String {
    value
        .chars()
        .filter(|ch| ch.is_ascii_alphabetic())
        .flat_map(char::to_lowercase)
        .collect()
}

fn cloud_mcp_normalize_terminal_nickname(value: &str) -> Option<String> {
    let key = cloud_mcp_terminal_nickname_key(value);
    if key.is_empty() {
        return None;
    }

    CLOUD_MCP_TERMINAL_NICKNAMES
        .iter()
        .find(|name| name.to_ascii_lowercase() == key)
        .map(|name| (*name).to_string())
}

fn cloud_mcp_terminal_name_placeholder(value: &str) -> bool {
    let mut key = value
        .trim()
        .chars()
        .filter(|ch| ch.is_ascii_alphanumeric())
        .flat_map(char::to_lowercase)
        .collect::<String>();
    while key
        .chars()
        .last()
        .map(|ch| ch.is_ascii_digit())
        .unwrap_or(false)
    {
        key.pop();
    }
    matches!(
        key.as_str(),
        "" | "agent"
            | "terminal"
            | "prewarm"
            | "prewarmpty"
            | "codingagent"
            | "codex"
            | "claude"
            | "claudecode"
            | "openai"
            | "opencode"
    )
}

fn cloud_mcp_clean_terminal_nickname(value: &str) -> Option<String> {
    let value = value.trim();
    if cloud_mcp_terminal_name_placeholder(value) {
        return None;
    }
    cloud_mcp_normalize_terminal_nickname(value).or_else(|| Some(value.to_string()))
}

fn cloud_mcp_terminal_nickname_text(payload: &Value, path: &[&str]) -> Option<String> {
    for key in path {
        if let Some(value) = payload
            .get(*key)
            .and_then(Value::as_str)
            .and_then(cloud_mcp_clean_terminal_nickname)
        {
            return Some(value);
        }
    }

    let mut current = payload;
    for key in path {
        current = current.get(*key)?;
    }
    current.as_str().and_then(cloud_mcp_clean_terminal_nickname)
}

fn cloud_mcp_payload_object(payload: &Value, path: &[&str]) -> Option<Value> {
    for key in path {
        if let Some(value) = payload.get(*key).filter(|value| value.is_object()) {
            return Some(value.clone());
        }
    }

    let mut current = payload;
    for key in path {
        current = current.get(*key)?;
    }
    current.is_object().then(|| current.clone())
}

fn cloud_mcp_payload_u64(payload: &Value, path: &[&str]) -> Option<u64> {
    for key in path {
        if let Some(value) = payload.get(*key) {
            if let Some(number) = value.as_u64() {
                return Some(number);
            }
            if let Some(number) = value.as_i64().and_then(|number| u64::try_from(number).ok()) {
                return Some(number);
            }
            if let Some(number) = value
                .as_str()
                .and_then(|text| text.trim().parse::<u64>().ok())
            {
                return Some(number);
            }
        }
    }

    let mut current = payload;
    for key in path {
        current = current.get(*key)?;
    }
    current
        .as_u64()
        .or_else(|| {
            current
                .as_i64()
                .and_then(|number| u64::try_from(number).ok())
        })
        .or_else(|| {
            current
                .as_str()
                .and_then(|text| text.trim().parse::<u64>().ok())
        })
}

fn cloud_mcp_payload_bool(payload: &Value, path: &[&str], fallback: bool) -> bool {
    let mut current = payload;
    for key in path {
        current = match current.get(*key) {
            Some(value) => value,
            None => return fallback,
        };
    }
    if let Some(value) = current.as_bool() {
        return value;
    }
    if let Some(text) = current.as_str() {
        return match text.trim().to_ascii_lowercase().as_str() {
            "1" | "true" | "yes" | "on" => true,
            "0" | "false" | "no" | "off" => false,
            _ => fallback,
        };
    }
    fallback
}

fn cloud_mcp_payload_items(payload: &Value, keys: &[&str], limit: usize) -> Vec<Value> {
    for key in keys {
        let Some(value) = payload.get(*key) else {
            continue;
        };
        if let Some(items) = value.as_array() {
            return items.iter().take(limit).cloned().collect();
        }
        if let Some(object) = value.as_object() {
            let items = object.values().take(limit).cloned().collect::<Vec<_>>();
            if !items.is_empty() {
                return items;
            }
        }
    }
    Vec::new()
}

fn cloud_mcp_workspace_terminal_items(workspace: &Value) -> Vec<Value> {
    cloud_mcp_payload_items(workspace, &["terminals"], 64)
}

fn cloud_mcp_terminal_empty_clear_reason_is_explicit(value: &str) -> bool {
    let token = value
        .trim()
        .to_ascii_lowercase()
        .replace(['-', ' ', '.'], "_");
    if token.is_empty() {
        return false;
    }
    matches!(
        token.as_str(),
        "all_terminals_closed"
            | "all_terminal_sessions_closed"
            | "close_all_terminals"
            | "terminal_closed"
            | "terminals_closed"
            | "terminal_deleted"
            | "terminals_deleted"
            | "terminal_removed"
            | "terminals_removed"
            | "workspace_deleted"
            | "workspace_delete"
            | "workspace_removed"
            | "workspace_catalog_deleted"
    ) || token.contains("all_terminals_closed")
        || token.contains("all_terminal_sessions_closed")
        || token.contains("close_all_terminals")
}

fn cloud_mcp_workspace_terminal_empty_clear_is_explicit(
    workspace: &Value,
    snapshot_reason: &str,
    requested_terminal_clear_reason: &str,
) -> bool {
    if cloud_mcp_terminal_empty_clear_reason_is_explicit(requested_terminal_clear_reason)
        || cloud_mcp_terminal_empty_clear_reason_is_explicit(snapshot_reason)
    {
        return true;
    }
    [
        "terminal_clear_reason",
        "reason",
        "event_kind",
        "event_type",
        "status",
        "state",
    ]
    .iter()
    .filter_map(|key| workspace.get(*key).and_then(Value::as_str))
    .any(cloud_mcp_terminal_empty_clear_reason_is_explicit)
}

fn cloud_mcp_workspace_empty_clear_reason_removes_workspace(value: &str) -> bool {
    let token = value
        .trim()
        .to_ascii_lowercase()
        .replace(['-', ' ', '.'], "_");
    matches!(
        token.as_str(),
        "workspace_deleted"
            | "workspace_delete"
            | "workspace_removed"
            | "workspace_remove"
            | "workspace_catalog_deleted"
            | "workspace_catalog_removed"
    )
}

fn cloud_mcp_workspace_explicit_active_state(workspace: &Value) -> Option<bool> {
    for key in [
        "workspace_effective_active",
        "workspace_reported_active",
        "workspace_active",
        "active",
    ] {
        let Some(value) = workspace.get(key) else {
            continue;
        };
        if let Some(value) = value.as_bool() {
            return Some(value);
        }
        if let Some(value) = value.as_i64() {
            return Some(value != 0);
        }
        if let Some(value) = value.as_u64() {
            return Some(value != 0);
        }
        if let Some(text) = value.as_str() {
            let token = text.trim().to_ascii_lowercase().replace(['_', ' '], "-");
            if token.is_empty() {
                continue;
            }
            if ["0", "false", "no", "off"].contains(&token.as_str())
                || ["deactivated", "disabled", "inactive", "offline", "closed"]
                    .iter()
                    .any(|needle| token.contains(needle))
            {
                return Some(false);
            }
            if ["1", "true", "yes", "on"].contains(&token.as_str())
                || [
                    "active",
                    "connected",
                    "online",
                    "ready",
                    "running",
                    "starting",
                ]
                .iter()
                .any(|needle| token.contains(needle))
            {
                return Some(true);
            }
        }
    }

    let status = cloud_mcp_payload_text(
        workspace,
        &[
            "workspace_status",
            "workspace_reported_status",
            "display_status",
            "status",
            "state",
        ],
    )
    .unwrap_or_default()
    .trim()
    .to_ascii_lowercase()
    .replace(['_', ' '], "-");
    if status.is_empty() {
        return None;
    }
    if ["deactivated", "disabled", "inactive", "offline", "closed"]
        .iter()
        .any(|needle| status.contains(needle))
    {
        return Some(false);
    }
    if [
        "active",
        "connected",
        "online",
        "ready",
        "running",
        "starting",
    ]
    .iter()
    .any(|needle| status.contains(needle))
    {
        return Some(true);
    }
    None
}

fn cloud_mcp_workspace_inactive_terminal_empty_clear_is_explicit(
    workspace: &Value,
    snapshot_reason: &str,
    requested_terminal_clear_reason: &str,
    workspace_active: bool,
) -> bool {
    let requested = requested_terminal_clear_reason.trim();
    if workspace_active {
        return cloud_mcp_workspace_terminal_empty_clear_is_explicit(
            workspace,
            snapshot_reason,
            requested,
        );
    }
    let workspace_clear_reason =
        cloud_mcp_payload_text(workspace, &["workspace_clear_reason"]).unwrap_or_default();
    let workspace_event_reason =
        cloud_mcp_payload_text(workspace, &["reason", "event_kind", "event_type"])
            .unwrap_or_default();
    [
        requested,
        snapshot_reason,
        workspace_clear_reason.as_str(),
        workspace_event_reason.as_str(),
    ]
    .iter()
    .any(|value| cloud_mcp_workspace_empty_clear_reason_removes_workspace(value))
}

fn cloud_mcp_panel_empty_clear_reason_is_explicit(value: &str) -> bool {
    let token = value
        .trim()
        .to_ascii_lowercase()
        .replace(['-', ' ', '.'], "_");
    if token.is_empty() {
        return false;
    }
    matches!(
        token.as_str(),
        "all_panels_closed"
            | "all_panels_deleted"
            | "all_panels_removed"
            | "no_workspace_panels"
            | "panel_closed"
            | "panels_closed"
            | "panel_deleted"
            | "panels_deleted"
            | "panel_removed"
            | "panels_removed"
            | "workspace_deleted"
            | "workspace_delete"
            | "workspace_removed"
            | "workspace_catalog_deleted"
    ) || token.contains("all_panels_closed")
        || token.contains("all_panels_deleted")
        || token.contains("all_panels_removed")
}

fn cloud_mcp_workspace_panel_empty_clear_is_explicit(
    workspace: &Value,
    snapshot_reason: &str,
    requested_panel_clear_reason: &str,
    workspace_active: bool,
) -> bool {
    if !workspace_active {
        let workspace_clear_reason =
            cloud_mcp_payload_text(workspace, &["workspace_clear_reason"]).unwrap_or_default();
        let workspace_event_reason =
            cloud_mcp_payload_text(workspace, &["reason", "event_kind", "event_type"])
                .unwrap_or_default();
        return [
            requested_panel_clear_reason,
            snapshot_reason,
            workspace_clear_reason.as_str(),
            workspace_event_reason.as_str(),
        ]
        .iter()
        .any(|value| cloud_mcp_workspace_empty_clear_reason_removes_workspace(value));
    }
    if cloud_mcp_panel_empty_clear_reason_is_explicit(requested_panel_clear_reason)
        || cloud_mcp_panel_empty_clear_reason_is_explicit(snapshot_reason)
    {
        return true;
    }
    [
        "panel_clear_reason",
        "reason",
        "event_kind",
        "event_type",
        "status",
        "state",
    ]
    .iter()
    .filter_map(|key| workspace.get(*key).and_then(Value::as_str))
    .any(cloud_mcp_panel_empty_clear_reason_is_explicit)
}

fn cloud_mcp_workspace_panel_items(workspace: &Value) -> Vec<Value> {
    for key in ["panels", "workspace_panels"] {
        let Some(value) = workspace.get(key) else {
            continue;
        };
        if value.is_array() || value.is_object() {
            return cloud_mcp_payload_items(workspace, &[key], 64);
        }
    }
    cloud_mcp_workspace_terminal_items(workspace)
        .into_iter()
        .filter(|item| cloud_mcp_workspace_panel_kind(item).is_some())
        .collect()
}

fn cloud_mcp_workspace_panel_kind(panel: &Value) -> Option<String> {
    let kind = cloud_mcp_payload_text(
        panel,
        &[
            "panel_type",
            "pane_kind",
            "panel_kind",
            "surface_kind",
            "kind",
            "role",
        ],
    )?
    .trim()
    .to_ascii_lowercase()
    .replace('_', "-");
    match kind.as_str() {
        "docs" | "doc" | "document" | "documents" | "workspace-docs" | "workspace-document"
        | "docs-panel" | "document-panel" | "documents-panel" => Some("docs".to_string()),
        "web" | "browser" | "chrome" | "workspace-web" | "workspace-browser" | "web-panel" => {
            Some("web".to_string())
        }
        "pcb" | "pcb-panel" | "pcb-design" | "workspace-pcb" => Some("pcb".to_string()),
        "vm" | "vm-sandbox" | "vmsandbox" | "workspace-vm" | "vm-panel" | "sandbox-vm"
        | "virtual-machine" | "virtualmachine" => Some("vm".to_string()),
        "video" | "video-editor" | "videoeditor" | "video-panel" | "workspace-video" => {
            Some("video".to_string())
        }
        "swarm" | "agent-swarm" | "agents-swarm" | "swarm-agents" | "workspace-swarm"
        | "swarm-panel" => Some("swarm".to_string()),
        _ => None,
    }
}

// Level 1 remote PCB/Video project management: the frontend catalog snapshot
// carries per-workspace `pcb_projects` / `video_projects` rows. The workspace
// snapshot normalization below is an explicit whitelist, so pass these arrays
// through with their pinned snake_case shape ({ id, name, path,
// updated_at_ms? }), dedupe by path, and cap the list so the cloud payload
// stays small.
const CLOUD_MCP_WORKSPACE_PROJECT_LIMIT: usize = 50;
const CLOUD_MCP_WORKSPACE_PROJECT_TEXT_LIMIT: usize = 256;
const CLOUD_MCP_WORKSPACE_PROJECT_PATH_LIMIT: usize = 1024;

fn cloud_mcp_workspace_project_rows(workspace: &Value, keys: &[&str]) -> Vec<Value> {
    let clean_text = |value: String, limit: usize| -> String {
        value.trim().chars().take(limit).collect::<String>()
    };
    let mut rows = Vec::new();
    let mut seen_paths = std::collections::BTreeSet::new();
    for item in cloud_mcp_payload_items(workspace, keys, CLOUD_MCP_WORKSPACE_PROJECT_LIMIT) {
        if !item.is_object() {
            continue;
        }
        let Some(path) = cloud_mcp_payload_text(&item, &["path", "project_path", "board_path"])
            .map(|value| clean_text(value, CLOUD_MCP_WORKSPACE_PROJECT_PATH_LIMIT))
            .filter(|value| !value.is_empty())
        else {
            continue;
        };
        if !seen_paths.insert(path.clone()) {
            continue;
        }
        let id = cloud_mcp_payload_text(&item, &["id", "project_id", "board_id"])
            .map(|value| clean_text(value, CLOUD_MCP_WORKSPACE_PROJECT_TEXT_LIMIT))
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| path.clone());
        let name = cloud_mcp_payload_text(&item, &["name", "project_name", "title"])
            .map(|value| clean_text(value, CLOUD_MCP_WORKSPACE_PROJECT_TEXT_LIMIT))
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| id.clone());
        let mut row = json!({
            "id": id,
            "name": name,
            "path": path,
        });
        if let Some(updated_at_ms) = cloud_mcp_payload_u64(&item, &["updated_at_ms"]) {
            if let Some(object) = row.as_object_mut() {
                object.insert("updated_at_ms".to_string(), json!(updated_at_ms));
            }
        }
        rows.push(row);
    }
    rows
}

fn cloud_mcp_workspace_project_active_id(workspace: &Value, keys: &[&str]) -> Value {
    cloud_mcp_payload_text(workspace, keys)
        .map(|value| {
            value
                .trim()
                .chars()
                .take(CLOUD_MCP_WORKSPACE_PROJECT_TEXT_LIMIT)
                .collect::<String>()
        })
        .filter(|value| !value.is_empty())
        .map(Value::String)
        .unwrap_or(Value::Null)
}

fn cloud_mcp_workspace_panel_is_last_known(panel: &Value) -> bool {
    cloud_mcp_payload_bool(panel, &["last_known_runtime"], false)
        || cloud_mcp_payload_bool(panel, &["runtime_read_only"], false)
}

fn cloud_mcp_workspace_panel_is_deleted(panel: &Value) -> bool {
    cloud_mcp_payload_bool(panel, &["deleted"], false)
        || cloud_mcp_payload_bool(panel, &["tombstoned"], false)
        || cloud_mcp_payload_bool(panel, &["removed"], false)
        || cloud_mcp_payload_bool(panel, &["hidden"], false)
        || cloud_mcp_payload_text(panel, &["deleted_at"]).is_some()
        || cloud_mcp_payload_text(panel, &["removed_at"]).is_some()
        || cloud_mcp_payload_text(panel, &["tombstoned_at"]).is_some()
}

fn cloud_mcp_workspace_panel_is_current(
    panel: &Value,
    _workspace: &Value,
    workspace_active: bool,
) -> bool {
    if cloud_mcp_workspace_panel_is_deleted(panel) {
        return false;
    }

    let status = ["display_status", "status", "state", "lifecycle"]
        .iter()
        .filter_map(|key| panel.get(*key).and_then(Value::as_str))
        .map(|text| text.trim().to_ascii_lowercase())
        .filter(|text| !text.is_empty())
        .collect::<Vec<_>>()
        .join(" ");

    if ["deleted", "hidden", "removed", "tombstone", "tombstoned"]
        .iter()
        .any(|token| status.contains(token))
    {
        return false;
    }

    if cloud_mcp_workspace_panel_is_last_known(panel) {
        return true;
    }

    if !workspace_active {
        return false;
    }

    if [
        "closed",
        "closing",
        "deactivated",
        "disabled",
        "disconnected",
        "exited",
        "inactive",
        "offline",
        "terminated",
    ]
    .iter()
    .any(|token| status.contains(token))
    {
        return false;
    }

    if cloud_mcp_payload_bool(panel, &["active"], false)
        || cloud_mcp_payload_bool(panel, &["connected"], false)
        || cloud_mcp_payload_bool(panel, &["native_connected"], false)
    {
        return true;
    }

    if !status.is_empty() {
        return [
            "active",
            "busy",
            "connected",
            "idle",
            "loading",
            "open",
            "opening",
            "ready",
            "running",
            "starting",
        ]
        .iter()
        .any(|token| status.contains(token));
    }

    workspace_active
}

fn cloud_mcp_workspace_server_items(workspace: &Value) -> Vec<Value> {
    let direct = cloud_mcp_payload_items(workspace, &["mcps", "servers"], 128);
    if !direct.is_empty() {
        return direct;
    }
    for key in ["registry", "data", "payload"] {
        if let Some(nested) = workspace.get(key) {
            let nested_items = cloud_mcp_workspace_server_items(nested);
            if !nested_items.is_empty() {
                return nested_items;
            }
        }
    }
    Vec::new()
}

fn cloud_mcp_normalize_workspace_mcp_servers_for_snapshot(workspace: &Value) -> Vec<Value> {
    cloud_mcp_workspace_server_items(workspace)
        .iter()
        .enumerate()
        .filter_map(|(index, server)| {
            if !server.is_object() {
                return None;
            }
            let server_key = cloud_mcp_payload_text(
                server,
                &[
                    "server_key",
                    "key",
                    "id",
                    "name",
                    "label",
                    "slug",
                    "package_ref",
                ],
            )
            .unwrap_or_else(|| format!("server-{}", index + 1));
            if server_key == "secrets" {
                return None;
            }
            let name = cloud_mcp_payload_text(server, &["name", "label", "display_name"])
                .unwrap_or_else(|| server_key.clone());
            let name = name
                .chars()
                .take(CLOUD_MCP_WORKSPACE_MCP_TEXT_LIMIT)
                .collect::<String>();
            let tools = cloud_mcp_workspace_mcp_tool_names(server);
            let tool_count = tools.len();
            Some(json!({
                "server_key": server_key,
                "name": name,
                "workspace_enabled": cloud_mcp_payload_bool(server, &["workspace_enabled"], true)
                    && cloud_mcp_payload_bool(server, &["workspace_enabled"], true),
                "tools": tools,
                "tool_count": tool_count}))
        })
        .collect()
}

fn cloud_mcp_workspace_mcp_tool_names(server: &Value) -> Vec<Value> {
    let mut names = server
        .get("tools")
        .or_else(|| server.get("tools_json"))
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default()
        .into_iter()
        .filter_map(|tool| {
            let name = if let Some(text) = tool.as_str() {
                text.trim().to_string()
            } else {
                cloud_mcp_payload_text(&tool, &["name", "id"]).unwrap_or_default()
            };
            let name = name.trim();
            if name.is_empty() {
                None
            } else {
                Some(json!(name
                    .chars()
                    .take(CLOUD_MCP_WORKSPACE_MCP_TEXT_LIMIT)
                    .collect::<String>()))
            }
        })
        .collect::<Vec<_>>();
    names.sort_by(|left, right| {
        left.as_str()
            .unwrap_or_default()
            .cmp(right.as_str().unwrap_or_default())
    });
    names.dedup();
    names
        .into_iter()
        .take(CLOUD_MCP_WORKSPACE_MCP_TOOL_NAME_LIMIT)
        .collect()
}

#[cfg(test)]
fn cloud_mcp_workspace_mcp_server_content_hash(
    workspace_id: &str,
    workspace: &Value,
    server: &Value,
) -> String {
    let workspace_active = workspace
        .get("workspace_active")
        .or_else(|| workspace.get("active"))
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let workspace_status = cloud_mcp_payload_text(workspace, &["workspace_status", "status"])
        .unwrap_or_else(|| {
            if workspace_active {
                "active".to_string()
            } else {
                "deactivated".to_string()
            }
        });
    let workspace_name = cloud_mcp_payload_text(workspace, &["workspace_name", "name"])
        .unwrap_or_else(|| workspace_id.to_string());
    cloud_mcp_outbox_payload_hash(&json!({
        "workspace_id": workspace_id,
        "workspace_active": workspace_active,
        "workspace_name": workspace_name,
        "workspace_status": workspace_status,
        "server": server,
        "current": true,
    }))
}

async fn cloud_mcp_register_prepared_workspace(
    state: &CloudMcpState,
    prepared: CloudMcpPreparedWorkspace,
    reason: &str,
) -> Result<CloudMcpWorkspaceRegistrationResult, String> {
    let now_ms = cloud_mcp_now_ms();
    let policy_graph_detected = prepared.policy_graph.is_some();
    let workspace_status = CloudMcpWorkspaceStatus {
        root: prepared.root_display.clone(),
        workspace_id: prepared.workspace_id.clone(),
        workspace_name: prepared.workspace_name.clone(),
        dashboard_workspace: true,
        workspace_role: "desktop_workspace".to_string(),
        display_surface: "dashboard_workspace".to_string(),
        last_registered_ms: if reason == "workspace_registration" {
            Some(now_ms)
        } else {
            None
        },
        last_synced_ms: Some(now_ms),
        last_error: String::new(),
        policy_graph_detected,
        policy_graph_path: prepared.policy_graph_path.clone(),
    };
    let payload = json!({
        "source": "rust-diffforge",
        "agent_id": "rust-diffforge",
        "event_kind": reason,
        "summary": format!("Workspace {} synced into the Cloud MCP context ledger.", prepared.workspace_name),
        "payload": {
            "reason": reason,
            "workspace_id": prepared.workspace_id.clone(),
            "workspace_name": prepared.workspace_name.clone(),
            "workspace_kind": prepared.workspace_kind.clone(),
            "dashboard_workspace": true,
            "workspace_role": "desktop_workspace",
            "display_surface": "dashboard_workspace",
            "policy_graph_detected": policy_graph_detected,
            "policy_graph_path": workspace_status.policy_graph_path,
            "context_pack_model": true,
        }
    });
    let event_response = cloud_mcp_post_event_endpoint(state, reason, &payload).await?;
    if reason == "workspace_registration" {
        cloud_mcp_publish_device_live_state_snapshot(state, "workspace_registration").await;
    }
    let log_path = cloud_mcp_workspace_log(
        &prepared.root,
        reason,
        &workspace_status.workspace_id,
        &workspace_status.workspace_name,
        json!({
            "workspace_kind": prepared.workspace_kind.clone(),
            "policy_graph_detected": policy_graph_detected,
            "synced": true,
        }),
    )?;
    {
        let mut runtime = state.inner.lock().await;
        runtime
            .registered_workspaces
            .insert(workspace_status.root.clone(), workspace_status.clone());
        runtime.connected = runtime.global_ws_connected;
        runtime.status = if runtime.global_ws_connected {
            "connected".to_string()
        } else {
            "websocket_required".to_string()
        };
        if runtime.global_ws_connected {
            runtime.last_error.clear();
        }
        runtime.last_connected_ms = Some(now_ms);
    }
    let registration_response =
        cloud_mcp_ws_send_workspace_registration(state, &workspace_status).await?;
    cloud_mcp_publish_device_live_state_snapshot(state, "workspace_registered").await;
    let status = cloud_mcp_status_snapshot(state).await;
    Ok(CloudMcpWorkspaceRegistrationResult {
        status,
        workspace: workspace_status,
        child_workspaces: Vec::new(),
        server_response: json!({
            "event": event_response,
            "workspace_registration": registration_response,
        }),
        synced: true,
        log_path: workspace_path_display(&log_path),
        message: "Workspace synced to Cloud MCP context ledger.".to_string(),
    })
}

async fn cloud_mcp_register_prepared_workspace_bundle(
    state: &CloudMcpState,
    bundle: CloudMcpPreparedWorkspaceBundle,
    reason: &str,
) -> Result<CloudMcpWorkspaceRegistrationResult, String> {
    let mut result = cloud_mcp_register_prepared_workspace(state, bundle.primary, reason).await?;
    let project_mount_count = bundle.children.len();

    if project_mount_count > 0 {
        if let Some(object) = result.server_response.as_object_mut() {
            object.insert(
                "project_mount_count".to_string(),
                json!(project_mount_count),
            );
        }
        result.message = format!(
            "Workspace synced with {} project mount{}.",
            project_mount_count,
            if project_mount_count == 1 { "" } else { "s" }
        );
    }

    Ok(result)
}

async fn cloud_mcp_ws_send_workspace_registration(
    state: &CloudMcpState,
    workspace: &CloudMcpWorkspaceStatus,
) -> Result<Value, String> {
    let (mut catalog_workspaces, workspace_catalog_ready) =
        cloud_mcp_lifecycle_workspaces(state).await;
    if !workspace_catalog_ready {
        return Ok(json!({
            "ok": true,
            "skipped": true,
            "reason": "workspace_catalog_not_ready",
            "event_kind": "workspace_register",
        }));
    }
    let device_profile = cloud_mcp_desktop_device_profile();
    let device_id = cloud_mcp_payload_text(&device_profile, &["device_id"])
        .unwrap_or_else(|| "desktop".to_string());
    let device_aliases = vec![device_id.clone()];
    for catalog_workspace in &mut catalog_workspaces {
        cloud_mcp_stamp_workspace_device_identity(
            catalog_workspace,
            &device_id,
            &device_aliases,
            cloud_mcp_desktop_platform(),
        );
    }
    let mut payload = json!({
        "workspace_id": workspace.workspace_id,
        "workspace_name": workspace.workspace_name,
        "dashboard_workspace": workspace.dashboard_workspace,
        "workspace_role": workspace.workspace_role,
        "display_surface": workspace.display_surface,
        "workspace_status": "registered",
        "device_id": device_id,
        "device_aliases": device_aliases,
        "workspace_catalog_ready": true,
        "workspace_snapshot_complete": true,
        "workspace_snapshot_authoritative": true,
        "workspaces": catalog_workspaces,
        "schema_version": 1,
    });
    if !workspace.root.trim().is_empty() {
        if let Some(object) = payload.as_object_mut() {
            object.insert("workspace_root".to_string(), json!(workspace.root.trim()));
        }
    }
    cloud_mcp_ws_request(state, "workspace_register", &payload).await
}

fn cloud_mcp_response_data(value: &Value) -> Value {
    value.get("data").cloned().unwrap_or_else(|| value.clone())
}

fn cloud_mcp_terminal_key(pane_id: &str, instance_id: u64) -> String {
    format!("{pane_id}::{instance_id}")
}

fn cloud_mcp_terminal_context_missing_backed_off(
    state: &CloudMcpState,
    terminal_key: &str,
    now_ms: u64,
) -> bool {
    let Ok(mut cache) = state.terminal_context_missing_until_ms.lock() else {
        return false;
    };
    match cache.get(terminal_key).copied() {
        Some(deadline_ms) if deadline_ms > now_ms => true,
        Some(_) => {
            cache.remove(terminal_key);
            false
        }
        None => false,
    }
}

fn cloud_mcp_mark_terminal_context_missing(state: &CloudMcpState, terminal_key: &str, now_ms: u64) {
    let Ok(mut cache) = state.terminal_context_missing_until_ms.lock() else {
        return;
    };
    if cache.len() > CLOUD_MCP_TERMINAL_CONTEXT_MISSING_CACHE_MAX {
        cache.retain(|_, deadline_ms| *deadline_ms > now_ms);
    }
    cache.insert(
        terminal_key.to_string(),
        now_ms.saturating_add(CLOUD_MCP_TERMINAL_CONTEXT_MISSING_BACKOFF_MS),
    );
}

fn cloud_mcp_clear_terminal_context_missing(state: &CloudMcpState, terminal_key: &str) {
    let Ok(mut cache) = state.terminal_context_missing_until_ms.lock() else {
        return;
    };
    cache.remove(terminal_key);
}

fn cloud_mcp_terminal_agent_id(
    pane_id: &str,
    instance_id: u64,
    coordination: Option<&TerminalCoordinationSession>,
) -> String {
    coordination
        .and_then(|coordination| cloud_mcp_stable_agent_id(Some(coordination.agent_id.as_str())))
        .unwrap_or_else(|| format!("{pane_id}-{instance_id}"))
}

fn cloud_mcp_stable_agent_id(agent_id: Option<&str>) -> Option<String> {
    let agent_id = agent_id?.trim();
    if agent_id.is_empty() {
        return None;
    }
    Some(agent_id.to_string())
}

fn cloud_mcp_short_agent_label(agent_id: &str) -> Option<String> {
    let agent_id = agent_id.trim();
    if agent_id.is_empty() || agent_id.starts_with("workspace-terminal-") {
        return None;
    }
    let label = agent_id
        .chars()
        .filter(|character| character.is_ascii_alphanumeric())
        .take(3)
        .collect::<String>();
    if label.is_empty() {
        None
    } else {
        Some(label)
    }
}

fn cloud_mcp_terminal_worktree_id(
    coordination: Option<&TerminalCoordinationSession>,
) -> Option<String> {
    let coordination = coordination?;
    let conn = rusqlite::Connection::open(&coordination.db_path).ok()?;
    let worktree_id = conn
        .query_row(
            "SELECT worktree_id
             FROM agent_sessions
             WHERE id=?1
             LIMIT 1",
            [coordination.session_id.as_str()],
            |row| row.get::<_, Option<String>>(0),
        )
        .ok()
        .flatten()?;
    let worktree_id = worktree_id.trim();
    if worktree_id.is_empty() {
        None
    } else {
        Some(worktree_id.to_string())
    }
}

fn cloud_mcp_patch_changed_files_for_task(
    conn: &rusqlite::Connection,
    local_task_id: &str,
) -> Vec<Value> {
    let patch_id = conn
        .query_row(
            "SELECT id FROM patches
             WHERE task_id=?1 AND status='merged'
             ORDER BY created_at DESC LIMIT 1",
            [local_task_id],
            |row| row.get::<_, String>(0),
        )
        .ok();
    let Some(patch_id) = patch_id else {
        return Vec::new();
    };
    let mut statement = match conn.prepare(
        "SELECT path, change_kind
         FROM patch_files
         WHERE patch_id=?1
         ORDER BY path ASC
         LIMIT 200",
    ) {
        Ok(statement) => statement,
        Err(_) => return Vec::new(),
    };
    let rows = match statement.query_map([patch_id.as_str()], |row| {
        let path: String = row.get(0)?;
        let change_kind: Option<String> = row.get(1)?;
        Ok(json!({
            "path": path,
            "change_kind": change_kind,
            "patch_id": patch_id,
        }))
    }) {
        Ok(rows) => rows,
        Err(_) => return Vec::new(),
    };
    rows.filter_map(Result::ok).collect()
}

fn cloud_mcp_terminal_repo_id(
    working_directory: &Path,
    coordination: Option<&TerminalCoordinationSession>,
) -> String {
    coordination
        .map(|coordination| coordination.repo_path.clone())
        .filter(|value| !value.trim().is_empty())
        .map(|value| format!("repo-{}", cloud_mcp_short_hash(&value)))
        .unwrap_or_else(|| {
            format!(
                "repo-{}",
                cloud_mcp_short_hash(&workspace_path_display(working_directory))
            )
        })
}

fn cloud_mcp_terminal_repo_root_path(
    working_directory: &Path,
    coordination: Option<&TerminalCoordinationSession>,
) -> PathBuf {
    coordination
        .map(|coordination| coordination.repo_path.trim())
        .filter(|value| !value.is_empty())
        .map(PathBuf::from)
        .unwrap_or_else(|| working_directory.to_path_buf())
}

fn cloud_mcp_strip_terminal_sequences(value: &str) -> String {
    enum State {
        Ground,
        Escape,
        Csi,
        Osc,
        OscEscape,
        Ss3,
    }

    let mut state = State::Ground;
    let mut output = String::with_capacity(value.len());
    for character in value.chars() {
        match state {
            State::Ground => {
                if character == '\u{1b}' {
                    state = State::Escape;
                } else {
                    output.push(character);
                }
            }
            State::Escape => {
                state = match character {
                    '[' => State::Csi,
                    ']' | 'P' | '^' | '_' | 'X' => State::Osc,
                    'O' => State::Ss3,
                    _ => State::Ground,
                };
            }
            State::Csi => {
                let code = character as u32;
                if (0x40..=0x7e).contains(&code) {
                    state = State::Ground;
                }
            }
            State::Osc => {
                if character == '\u{1b}' {
                    state = State::OscEscape;
                } else if character == '\u{7}' {
                    state = State::Ground;
                }
            }
            State::OscEscape => {
                state = State::Ground;
            }
            State::Ss3 => {
                state = State::Ground;
            }
        }
    }
    output
}

fn cloud_mcp_strip_terminal_residue(value: &str) -> String {
    let chars = value.chars().collect::<Vec<_>>();
    let mut output = String::with_capacity(value.len());
    let mut index = 0;
    while index < chars.len() {
        let character = chars[index];
        if character == '[' && index + 1 < chars.len() {
            let next = chars[index + 1];
            if next == '?' || next.is_ascii_digit() {
                let mut end = index + 1;
                while end < chars.len() && end.saturating_sub(index) <= 48 {
                    let code = chars[end] as u32;
                    if (0x40..=0x7e).contains(&code) {
                        end += 1;
                        break;
                    }
                    end += 1;
                }
                if end > index + 1 && end <= chars.len() {
                    output.push(' ');
                    index = end;
                    continue;
                }
            }
            if matches!(next, 'O' | 'I') {
                output.push(' ');
                index += 2;
                continue;
            }
        }
        if character == ']' && index + 2 < chars.len() && chars[index + 1].is_ascii_digit() {
            let mut end = index + 1;
            while end < chars.len() && chars[end].is_ascii_digit() {
                end += 1;
            }
            if end < chars.len() && chars[end] == ';' {
                end += 1;
                while end < chars.len() && !chars[end].is_whitespace() {
                    if chars[end] == '\\' {
                        end += 1;
                        break;
                    }
                    end += 1;
                }
                output.push(' ');
                index = end;
                continue;
            }
        }
        output.push(character);
        index += 1;
    }
    output
}

fn cloud_mcp_clean_prompt_text(prompt: &str) -> String {
    cloud_mcp_strip_terminal_residue(&cloud_mcp_strip_terminal_sequences(prompt))
        .replace(|character: char| character.is_control(), " ")
        .split_whitespace()
        .collect::<Vec<_>>()
        .join(" ")
}

fn cloud_mcp_prompt_summary(prompt: &str) -> String {
    let cleaned = cloud_mcp_clean_prompt_text(prompt);
    cleaned
        .split_whitespace()
        .collect::<Vec<_>>()
        .join(" ")
        .chars()
        .take(220)
        .collect()
}

fn cloud_mcp_extract_agent_work_brief(text: &str) -> Option<String> {
    let cleaned = cloud_mcp_clean_prompt_text(text);
    let lower = cleaned.to_ascii_lowercase();
    let markers = ["i'll ", "i’ll ", "i will ", "i'm ", "i’m ", "i am "];
    let (start, _) = markers
        .iter()
        .filter_map(|marker| lower.find(marker).map(|index| (index, *marker)))
        .min_by_key(|(index, _)| *index)?;
    let mut brief = cleaned[start..].trim().to_string();
    if let Some(index) = brief.find(". ") {
        brief.truncate(index + 1);
    }
    let brief = brief
        .trim_matches(|character: char| {
            character == '•' || character == '-' || character.is_whitespace()
        })
        .split_whitespace()
        .collect::<Vec<_>>()
        .join(" ");
    if brief.len() < 18 {
        None
    } else {
        Some(brief.chars().take(280).collect())
    }
}

fn cloud_mcp_work_title_from_brief(brief: &str) -> String {
    let mut title = brief.trim().to_string();
    for prefix in ["I'll ", "I’ll ", "I will ", "I'm ", "I’m ", "I am "] {
        if title.starts_with(prefix) {
            title = title[prefix.len()..].trim().to_string();
            break;
        }
    }
    let lower = title.to_ascii_lowercase();
    for delimiter in [" now by ", " by ", " so ", " until ", " and then "] {
        if let Some(index) = lower.find(delimiter) {
            title.truncate(index);
            break;
        }
    }
    let title = title
        .trim_matches(|character: char| {
            character == '.' || character == ':' || character.is_whitespace()
        })
        .split_whitespace()
        .collect::<Vec<_>>()
        .join(" ");
    if title.is_empty() {
        "Agent working on requested task".to_string()
    } else {
        let mut characters = title.chars();
        let first = characters
            .next()
            .map(|character| character.to_uppercase().collect::<String>())
            .unwrap_or_default();
        format!("{}{}", first, characters.collect::<String>())
            .chars()
            .take(160)
            .collect()
    }
}

fn cloud_mcp_work_subject(work_brief: &str) -> String {
    if work_brief.trim().is_empty() {
        "requested work".to_string()
    } else {
        cloud_mcp_work_title_from_brief(work_brief)
    }
}

fn cloud_mcp_git_output(root: &Path, args: &[&str]) -> Option<Vec<u8>> {
    if app_shutdown_requested() {
        return None;
    }

    let mut command = Command::new("git");
    command
        .arg("-C")
        .arg(root)
        .args(args)
        .stdin(Stdio::null())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped());

    #[cfg(windows)]
    {
        use std::os::windows::process::CommandExt;

        const CREATE_NO_WINDOW: u32 = 0x0800_0000;
        command.creation_flags(CREATE_NO_WINDOW);
    }

    let mut child = command.spawn().ok()?;
    loop {
        if app_shutdown_requested() {
            let _ = child.kill();
            let _ = child.wait();
            return None;
        }

        match child.try_wait() {
            Ok(Some(_)) => break,
            Ok(None) => thread::sleep(Duration::from_millis(25)),
            Err(_) => {
                let _ = child.kill();
                return None;
            }
        }
    }

    let output = child.wait_with_output().ok()?;
    output.status.success().then_some(output.stdout)
}

fn cloud_mcp_git_changed_files(root: &Path) -> Vec<Value> {
    let Some(output) = cloud_mcp_git_output(
        root,
        &["status", "--porcelain", "-z", "--untracked-files=all"],
    ) else {
        return Vec::new();
    };

    let mut files = Vec::new();
    let mut parts = output
        .split(|byte| *byte == 0)
        .filter(|part| !part.is_empty());
    while let Some(entry) = parts.next() {
        if entry.len() < 4 {
            continue;
        }
        let status = String::from_utf8_lossy(&entry[0..2]).to_string();
        let mut path = String::from_utf8_lossy(&entry[3..]).replace('\\', "/");
        let change_kind = if status.starts_with('R') || status.starts_with('C') {
            if let Some(next_path) = parts.next() {
                path = String::from_utf8_lossy(next_path).replace('\\', "/");
            }
            if status.starts_with('R') {
                "renamed"
            } else {
                "copied"
            }
        } else if status == "??" || status.contains('A') {
            "added"
        } else if status.contains('D') {
            "deleted"
        } else {
            "modified"
        };
        if path.starts_with(".agents/") || path.starts_with(".git/") {
            continue;
        }
        if path == ".DS_Store" || path.ends_with("/.DS_Store") {
            continue;
        }
        files.push(json!({
            "path": path,
            "change_kind": change_kind,
            "untracked": status == "??",
        }));
        if files.len() >= 100 {
            break;
        }
    }
    files
}

fn cloud_mcp_path_from_file_scope(scope: &Value) -> Option<String> {
    let value = scope["path"]
        .as_str()
        .or_else(|| scope["file"].as_str())
        .or_else(|| scope["file_path"].as_str())
        .or_else(|| scope["resource_key"].as_str())?;
    let path = value
        .trim()
        .trim_start_matches("file:")
        .trim_start_matches("./")
        .replace('\\', "/");
    if path.trim().is_empty() {
        None
    } else {
        Some(path)
    }
}

fn cloud_mcp_filter_git_changed_files_by_scope(
    changed_files: Vec<Value>,
    scopes: &[Value],
) -> Vec<Value> {
    let scope_paths = scopes
        .iter()
        .filter_map(cloud_mcp_path_from_file_scope)
        .collect::<std::collections::HashSet<_>>();
    if scope_paths.is_empty() {
        return changed_files;
    }
    changed_files
        .into_iter()
        .filter(|file| {
            let path = file["path"].as_str().unwrap_or_default();
            scope_paths.iter().any(|scope| {
                path == scope
                    || path.strip_prefix("./") == Some(scope.as_str())
                    || scope.strip_prefix("./") == Some(path)
            })
        })
        .collect()
}

fn cloud_mcp_git_changed_files_for_scope(root: &Path, scopes: &[Value]) -> Vec<Value> {
    cloud_mcp_filter_git_changed_files_by_scope(cloud_mcp_git_changed_files(root), scopes)
}

async fn cloud_mcp_sync_terminal_agent_status(
    _state: &CloudMcpState,
    repo_id: &str,
    agent_id: &str,
    status: &str,
    current_prompt: Option<&str>,
    progress_summary: &str,
    working_directory: &Path,
    pane_id: &str,
    instance_id: u64,
    coordination: Option<&TerminalCoordinationSession>,
    local_task_id: Option<&str>,
    session_mode: Option<&str>,
    reason: &str,
) {
    let status_working_directory =
        cloud_mcp_terminal_repo_root_path(working_directory, coordination);
    let agent_label = cloud_mcp_short_agent_label(agent_id);
    let agent_label = agent_label.as_deref();
    log_terminal_status_event(
        "backend.cloud_mcp.agent_status.local_only",
        json!({
            "skipped": true,
            "skip_reason": "agent_status_is_event_based",
            "sync_kind": "terminal_agent_status",
            "repo_id": repo_id,
            "agent_id": agent_id,
            "agent_label": agent_label,
            "reason": reason,
            "server_status": status,
            "has_current_prompt": current_prompt.is_some(),
            "terminal_ground_truth_hint": progress_summary,
            "task_id": local_task_id,
            "session_mode": session_mode.unwrap_or(if coordination.is_some() { "managed_patch" } else { "free" }),
            "workspace_root": workspace_path_display(&status_working_directory),
            "terminal_id": pane_id,
            "terminal_instance_id": instance_id,
        }),
    );
}

fn cloud_mcp_agent_status_for_lifecycle_status(status: &str) -> &'static str {
    match status {
        "starting" => "starting",
        "active" => "active",
        "busy" => "busy",
        "running" => "running",
        "dispatched" => "dispatched",
        "resume_requested" => "resume_requested",
        "merged" | "completed" => "done",
        "blocked" => "blocked",
        "parked" => "parked",
        "resume_ready" => "resume_ready",
        "waiting" => "waiting",
        "review" => "review",
        "done" => "done",
        "cancelled" => "cancelled",
        "interrupted" => "interrupted",
        "closed" => "closed",
        "stopped" => "stopped",
        "idle" => "idle",
        _ => "inactive",
    }
}

fn cloud_mcp_parse_voice_plan_prompt_event_id(value: &str) -> Option<CloudMcpVoicePlanPromptParts> {
    let task_id = value.trim();
    if !task_id.starts_with("voice-plan-") {
        return None;
    }

    let (before_task, _) = task_id.rsplit_once("-t")?;
    let (before_stage, stage) = before_task.rsplit_once('-')?;
    if !matches!(stage, "execution" | "revision") {
        return None;
    }
    let (run_id, step_text) = before_stage.rsplit_once("-s")?;
    let step_ordinal = step_text.parse::<i64>().ok()?;
    if run_id.trim().is_empty() {
        return None;
    }

    Some(CloudMcpVoicePlanPromptParts {
        run_id: run_id.to_string(),
        stage: stage.to_string(),
        step_ordinal,
        task_id: task_id.to_string(),
    })
}

async fn cloud_mcp_voice_plan_prompt_metadata_for_terminal_task(
    state: &CloudMcpState,
    pane_id: &str,
    instance_id: u64,
    _local_task_id: &str,
) -> Option<CloudMcpVoicePlanPromptMetadata> {
    let terminal_key = cloud_mcp_terminal_key(pane_id, instance_id);
    let runtime = state.inner.lock().await;
    let entry = runtime.terminal_contexts.get(&terminal_key)?;
    let prompt_event_id = entry
        .prompt_event_id
        .as_deref()
        .map(str::trim)
        .filter(|value| cloud_mcp_parse_voice_plan_prompt_event_id(value).is_some())?
        .to_string();

    Some(CloudMcpVoicePlanPromptMetadata {
        prompt_event_id,
        prompt_event_source: entry.prompt_event_source.clone(),
        prompt_event_submitted_at: entry.prompt_event_submitted_at.clone(),
        terminal_index: entry.terminal_index,
        thread_id: entry.thread_id.clone(),
        workspace_id: entry.workspace_id.clone(),
        workspace_name: entry.workspace_name.clone(),
    })
}

fn cloud_mcp_voice_plan_status_for_terminal_lifecycle(status: &str) -> Option<&'static str> {
    match status
        .trim()
        .to_ascii_lowercase()
        .replace([' ', '-'], "_")
        .as_str()
    {
        "parked" | "blocked" | "waiting_on_dependency" => Some("parked"),
        "resume_ready" | "ready_to_resume" => Some("resume_ready"),
        "resume_requested" | "resuming" => Some("resume_requested"),
        "active" | "busy" | "running" | "starting" => Some("running"),
        "dispatched" | "redispatched" => Some("dispatched"),
        "cancelled" | "canceled" => Some("cancelled"),
        "interrupted" | "interrupt" | "stopped" => Some("interrupted"),
        _ => None,
    }
}

async fn cloud_mcp_record_voice_plan_terminal_lifecycle(
    app: &AppHandle,
    state: &CloudMcpState,
    parked: &TerminalParkedPrompt,
    status: &str,
    body: &str,
) {
    let Some(metadata) = parked.voice_plan_prompt.as_ref() else {
        log_terminal_status_event(
            "backend.voice_plan_task_status.terminal_lifecycle_skip",
            json!({
                "reason": "missing_voice_plan_prompt_metadata",
                "status": status,
                "task_id": parked.task_id.as_str(),
                "terminal_id": parked.pane_id.as_str(),
                "terminal_instance_id": parked.instance_id,
            }),
        );
        return;
    };
    let Some(parts) = cloud_mcp_parse_voice_plan_prompt_event_id(&metadata.prompt_event_id) else {
        return;
    };
    let Some(plan_status) = cloud_mcp_voice_plan_status_for_terminal_lifecycle(status) else {
        log_terminal_status_event(
            "backend.voice_plan_task_status.terminal_lifecycle_skip",
            json!({
                "prompt_event_id": metadata.prompt_event_id.as_str(),
                "reason": "unsupported_terminal_lifecycle_status",
                "status": status,
                "task_id": parked.task_id.as_str(),
            }),
        );
        return;
    };

    let req = cloud_mcp_repo_request(
        parked.working_directory.display().to_string(),
        if metadata.workspace_id.trim().is_empty() {
            None
        } else {
            Some(metadata.workspace_id.clone())
        },
        if metadata.workspace_name.trim().is_empty() {
            None
        } else {
            Some(metadata.workspace_name.clone())
        },
    );
    let agent_id = cloud_mcp_terminal_agent_id(
        &parked.pane_id,
        parked.instance_id,
        Some(&parked.coordination),
    );
    let payload = json!({
        "agent_id": agent_id,
        "event_kind": "voice_plan_task_status",
        "lifecycle_source": "terminal_parked_lifecycle",
        "run_id": parts.run_id.clone(),
        "plan_run_id": parts.run_id.clone(),
        "plan_stage": parts.stage.clone(),
        "plan_step_ordinal": parts.step_ordinal,
        "stage": parts.stage.clone(),
        "step_ordinal": parts.step_ordinal,
        "task_id": parts.task_id.clone(),
        "plan_task_id": parts.task_id.clone(),
        "prompt_event_id": metadata.prompt_event_id.as_str(),
        "prompt_event_source": metadata.prompt_event_source.as_deref().unwrap_or_default(),
        "prompt_event_submitted_at": metadata.prompt_event_submitted_at.as_deref().unwrap_or_default(),
        "repo_id": req.repo_id,
        "repo_path": req.root_display.clone(),
        "status": plan_status,
        "summary": body,
        "terminal_id": parked.pane_id.as_str(),
        "terminal_index": metadata.terminal_index,
        "terminal_instance_id": parked.instance_id,
        "thread_id": metadata.thread_id.as_deref().unwrap_or_default(),
            "workspace_id": req.workspace_id.as_deref().unwrap_or_default(),
        "workspace_name": metadata.workspace_name.as_str(),
        "workspace_root": req.root_display.clone(),
    });

    log_terminal_status_event(
        "backend.voice_plan_task_status.terminal_lifecycle_send",
        json!({
            "payload": payload.clone(),
            "reason": "terminal_parked_or_resume_lifecycle",
            "terminal_lifecycle_status": status,
            "voice_plan_status": plan_status,
        }),
    );
    let result = cloud_mcp_post_event_endpoint(state, "voice_plan_task_status", &payload).await;
    match &result {
        Ok(value) => {
            log_terminal_status_event(
                "backend.voice_plan_task_status.terminal_lifecycle_result",
                json!({
                    "ok": true,
                    "prompt_event_id": metadata.prompt_event_id.as_str(),
                    "result": value,
                    "voice_plan_status": plan_status,
                }),
            );
            let _ = app.emit(
                VOICE_PLAN_SERVER_RESULT_EVENT,
                json!({
                    "result": value,
                    "source": "backend_terminal_parked_lifecycle",
                    "status_payload": payload,
                    "workspace_id": req.workspace_id.as_deref().unwrap_or_default(),
                }),
            );
        }
        Err(error) => log_terminal_status_event(
            "backend.voice_plan_task_status.terminal_lifecycle_error",
            json!({
                "error": clean_terminal_telemetry_text(error),
                "payload": payload,
                "prompt_event_id": metadata.prompt_event_id.as_str(),
                "voice_plan_status": plan_status,
            }),
        ),
    }
}

fn cloud_mcp_lifecycle_status_clears_terminal_context(status: &str) -> bool {
    !matches!(
        status,
        "starting"
            | "active"
            | "busy"
            | "running"
            | "dispatched"
            | "parked"
            | "resume_ready"
            | "resume_requested"
    )
}

pub(crate) async fn cloud_mcp_mark_terminal_task_lifecycle(
    state: &CloudMcpState,
    pane_id: &str,
    instance_id: u64,
    working_directory: &Path,
    coordination: Option<&TerminalCoordinationSession>,
    local_task_id: Option<&str>,
    _title: Option<&str>,
    status: &str,
    brief: &str,
) -> Option<String> {
    if cloud_mcp_connected_or_connect(state).await.is_err() {
        return None;
    }

    let agent_id = cloud_mcp_terminal_agent_id(pane_id, instance_id, coordination);
    let repo_id = cloud_mcp_terminal_repo_id(working_directory, coordination);
    let repo_root = cloud_mcp_terminal_repo_root_path(working_directory, coordination);
    let terminal_key = cloud_mcp_terminal_key(pane_id, instance_id);

    let agent_status = cloud_mcp_agent_status_for_lifecycle_status(status);
    cloud_mcp_sync_terminal_agent_status(
        state,
        &repo_id,
        &agent_id,
        agent_status,
        None,
        brief,
        working_directory,
        pane_id,
        instance_id,
        coordination,
        local_task_id,
        Some(if coordination.is_some() {
            "managed_patch"
        } else {
            "free"
        }),
        "terminal_task_lifecycle",
    )
    .await;
    if matches!(status, "cancelled" | "interrupted") {
        if let Some(local_task_id) = local_task_id
            .map(str::trim)
            .filter(|value| !value.is_empty())
        {
            let worktree_id = cloud_mcp_terminal_worktree_id(coordination);
            let prune_payload = json!({
                "source": "rust-diffforge-terminal-lifecycle",
                "repo_id": repo_id,
                "agent_id": agent_id,
                "self_agent_id": agent_id,
                "current_agent_id": agent_id,
                "status": cloud_mcp_agent_status_for_lifecycle_status(status),
                "task_status": status,
                "task_id": local_task_id,
                "run_id": local_task_id,
                "workspace_root": workspace_path_display(&repo_root),
                "terminal_id": pane_id,
                "terminal_instance_id": instance_id,
                "worktree_id": worktree_id.clone(),
                "record_spec_activity": false,
                "prune_spec_activity": true,
                "remove_isolated_work": true,
                "claimed_paths": [],
                "summary": brief,
                "metadata": {
                    "reason": "terminal_task_stopped",
                    "terminal_lifecycle_status": status,
                    "coordination_task_id": local_task_id,
                    "local_coordination_task_id": local_task_id,
                    "worktree_id": worktree_id.clone(),
                },
                "ts_ms": cloud_mcp_now_ms(),
            });
            let _ = cloud_mcp_workspace_log(
                &repo_root,
                "cloud_mcp.task_lifecycle_sync.skipped",
                "",
                "",
                json!({
                    "event_kind": "isolated_work_pruned",
                    "reason": "cloud_task_sync_removed",
                    "payload": prune_payload,
                }),
            );
        }
    }
    if cloud_mcp_lifecycle_status_clears_terminal_context(status) {
        let mut runtime = state.inner.lock().await;
        runtime.terminal_contexts.remove(&terminal_key);
    }

    None
}

pub(crate) async fn cloud_mcp_mark_terminal_opened(
    state: &CloudMcpState,
    pane_id: &str,
    instance_id: u64,
    working_directory: &Path,
    coordination: Option<&TerminalCoordinationSession>,
    session_mode: TerminalSessionMode,
    metadata: &TerminalInstanceMetadata,
    provider_session_id: Option<&str>,
    fork_from_provider_session_id: Option<&str>,
    shared_history_id: Option<&str>,
    reason: &str,
) {
    let repo_root = cloud_mcp_terminal_repo_root_path(working_directory, coordination);
    let workspace_id = metadata.workspace_id.trim();
    let workspace_id = (!workspace_id.is_empty()).then(|| workspace_id.to_string());
    let workspace_name = metadata.workspace_name.trim();
    let workspace_name = (!workspace_name.is_empty()).then(|| workspace_name.to_string());
    let req = cloud_mcp_repo_request(
        workspace_path_display(&repo_root),
        workspace_id,
        workspace_name,
    );
    let device_profile = cloud_mcp_desktop_device_profile();
    let now_ms = cloud_mcp_now_ms();
    let status_seq = cloud_mcp_next_terminal_lifecycle_seq(state, Some(now_ms));
    let workspace_runtime_seq = cloud_mcp_next_workspace_runtime_seq(state, Some(now_ms));
    let workspace_runtime_epoch = cloud_mcp_workspace_runtime_epoch(state);
    let agent_id = cloud_mcp_terminal_agent_id(pane_id, instance_id, coordination);
    let agent_kind = coordination
        .map(|coordination| coordination.agent_kind.as_str())
        .filter(|value| !value.trim().is_empty())
        .or_else(|| {
            (!metadata.agent_kind.trim().is_empty()).then_some(metadata.agent_kind.as_str())
        })
        .or_else(|| (!metadata.agent_id.trim().is_empty()).then_some(metadata.agent_id.as_str()))
        .unwrap_or("terminal");
    let provider_session_id = provider_session_id
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let fork_from_provider_session_id = fork_from_provider_session_id
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let shared_history_id = shared_history_id
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let terminal_nickname = cloud_mcp_clean_terminal_nickname(metadata.terminal_nickname.trim())
        .or_else(|| cloud_mcp_clean_terminal_nickname(metadata.terminal_name.trim()));
    let terminal_display_name = terminal_nickname
        .as_deref()
        .filter(|value| !value.trim().is_empty())
        .or_else(|| {
            let value = metadata.terminal_name.trim();
            (!value.is_empty()).then_some(value)
        })
        .unwrap_or(metadata.agent_id.as_str())
        .to_string();
    let terminal_nickname_text = terminal_nickname.unwrap_or_default();
    let payload = json!({
        "source": "rust-diffforge-terminal-open",
        "event_kind": "terminal_state_update",
        "v": 1,
        "device": device_profile.clone(),
        "device_id": device_profile["device_id"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "repo_id": req.repo_id,
        "workspace_root": req.root_display,
        "workspace_active": true,
        "workspace_id": req.workspace_id,
        "workspace_name": req.workspace_name,
        "workspace_status": "active",
        "workspace_runtime_seq": workspace_runtime_seq,
        "workspace_runtime_epoch": workspace_runtime_epoch,
        "display_name": terminal_display_name.clone(),
        "terminal_id": pane_id,
        "target_terminal_id": pane_id,
        "pane_id": pane_id,
        "terminal_instance_id": instance_id,
        "terminal_index": metadata.terminal_index,
        "terminal_epoch": format!("{pane_id}:{instance_id}"),
        "terminal_name": terminal_display_name.clone(),
        "terminal_nickname": terminal_nickname_text,
        "thread_id": metadata.thread_id.as_str(),
        "target_thread_id": metadata.thread_id.as_str(),
        "terminal_lifecycle": "open",
        "agent_id": agent_id,
        "agent_kind": agent_kind,
        "agent_type": agent_kind,
        "provider": agent_kind,
        "event_type": "terminal.opened",
        "state": "starting",
        "status": "starting",
        "activity_status": "starting",
        "readiness": "busy",
        "turn_status": "running",
        "command_phase": "starting",
        "execution_phase": "starting",
        "input_ready": false,
        "session_mode": session_mode.as_str(),
        "session_state": "session_attached",
        "provider_session_id": provider_session_id,
        "native_session_id": provider_session_id,
        "session_id": provider_session_id,
        "fork_from_provider_session_id": fork_from_provider_session_id,
        "shared_history_id": shared_history_id,
        "status_seq": status_seq,
        "observed_at_ms": now_ms,
        "reason": reason,
        "summary": "Terminal opened.",
        "ts_ms": now_ms});
    cloud_mcp_publish_terminal_state_live_update(state, &payload, reason).await;
}

fn cloud_mcp_presence_terminal_matches_instance(
    terminal: &Value,
    pane_id: &str,
    instance_id: u64,
) -> bool {
    let terminal_id =
        cloud_mcp_payload_text(terminal, &["pane_id", "terminal_id", "target_terminal_id"])
            .unwrap_or_default();
    if terminal_id != pane_id {
        return false;
    }
    match cloud_mcp_payload_u64(terminal, &["terminal_instance_id", "instance_id"]) {
        Some(value) if value > 0 => value == instance_id,
        _ => true,
    }
}

/// Close settlement runs detached from workspace close and can arrive after
/// the workspace reopened. A candidate without an instance id (legacy or
/// cloud-hydrated rows) matches the lenient matcher above, which would let a
/// LATE close for an old instance mark a reopened pane closed — so closes
/// require an explicit instance match when we know the instance we closed.
fn cloud_mcp_presence_terminal_matches_instance_for_close(
    terminal: &Value,
    pane_id: &str,
    instance_id: u64,
) -> bool {
    if instance_id == 0 {
        return cloud_mcp_presence_terminal_matches_instance(terminal, pane_id, instance_id);
    }
    let terminal_id =
        cloud_mcp_payload_text(terminal, &["pane_id", "terminal_id", "target_terminal_id"])
            .unwrap_or_default();
    if terminal_id != pane_id {
        return false;
    }
    matches!(
        cloud_mcp_payload_u64(
            terminal,
            &["terminal_instance_id", "instance_id"],
        ),
        Some(value) if value == instance_id
    )
}

fn cloud_mcp_terminal_state_removes_from_live_snapshot(terminal: &Value) -> bool {
    [
        "status",
        "state",
        "activity_status",
        "terminal_lifecycle",
        "event_type",
    ]
    .iter()
    .filter_map(|key| terminal.get(*key).and_then(Value::as_str))
    .map(|value| value.trim().to_ascii_lowercase())
    .any(|value| {
        matches!(value.as_str(), "deleted" | "removed" | "tombstoned")
            || value.ends_with(".removed")
            || value.ends_with("_removed")
            || value.ends_with("-removed")
            || value.ends_with(".deleted")
            || value.ends_with("_deleted")
            || value.ends_with("-deleted")
            || value.ends_with(".tombstoned")
            || value.ends_with("_tombstoned")
            || value.ends_with("-tombstoned")
    })
}

fn cloud_mcp_terminal_state_is_workspace_runtime_shutdown(terminal: &Value) -> bool {
    let explicit_closed_lifecycle = [
        "status",
        "state",
        "activity_status",
        "terminal_lifecycle",
        "command_phase",
        "execution_phase",
    ]
    .iter()
    .filter_map(|key| terminal.get(*key).and_then(Value::as_str))
    .map(|value| value.trim().to_ascii_lowercase())
    .any(|value| {
        matches!(
            value.as_str(),
            "closed" | "exited" | "terminated" | "disconnected"
        )
    });
    explicit_closed_lifecycle
        || [
            "reason",
            "close_reason",
            "event_kind",
            "event_type",
            "summary",
        ]
        .iter()
        .filter_map(|key| terminal.get(*key).and_then(Value::as_str))
        .map(|value| value.trim().to_ascii_lowercase())
        .any(|value| {
            value.contains("workspace_close")
                || value.contains("workspace-close")
                || value.contains("workspace_close_all")
                || value.contains("workspace-close-all")
                || value.contains("workspace_deactivate")
                || value.contains("workspace-deactivate")
                || value.contains("workspace_runtime")
                || value.contains("workspace-runtime")
                || value.contains("close_workspace")
                || value.contains("close-workspace")
                || value.contains("terminal_close")
                || value.contains("terminal-close")
                || value.contains("terminal.closed")
        })
}

fn cloud_mcp_mark_terminal_last_known_read_only(value: &mut Value) {
    let Some(object) = value.as_object_mut() else {
        return;
    };
    object.insert("last_known_runtime".to_string(), json!(true));
    object.insert("runtime_read_only".to_string(), json!(true));
    object.insert("commandable".to_string(), json!(false));
    object.insert("native_connected".to_string(), json!(false));
    object.insert("connected".to_string(), json!(false));
}

/// An interaction is actionable only while its exact native terminal
/// generation is alive.  Closed terminals and deactivated workspaces must
/// carry an explicit prompt clear so Cloud can retire the matching push
/// generation; merely omitting these fields would preserve the older prompt
/// during lossless live-state merges.
fn cloud_mcp_clear_terminal_prompt_state(
    value: &mut Value,
    resolved_provider_request_id: Option<&str>,
    reason: &str,
    observed_at_ms: u64,
) {
    let Some(object) = value.as_object_mut() else {
        return;
    };
    object.insert("prompt_id".to_string(), json!(""));
    object.insert("prompt_kind".to_string(), Value::Null);
    object.insert("prompt_default_option".to_string(), Value::Null);
    object.insert("prompt_ttl_ms".to_string(), Value::Null);
    object.insert("prompt_options".to_string(), json!([]));
    object.insert("prompt_questions".to_string(), Value::Null);
    object.insert("prompt_schema".to_string(), Value::Null);
    object.insert("prompt_url".to_string(), Value::Null);
    object.insert("allows_free_text".to_string(), json!(false));
    object.insert("manual_approval_required".to_string(), json!(false));
    object.insert("provider_blocked_for_user".to_string(), json!(false));
    object.insert("terminal_is_prompting_user".to_string(), json!(false));
    object.insert("prompting_user_kind".to_string(), Value::Null);
    object.insert("prompting_user_source".to_string(), Value::Null);
    object.insert("prompting_user_confidence".to_string(), Value::Null);
    object.insert("prompting_user_text".to_string(), Value::Null);
    object.insert("interaction_id".to_string(), Value::Null);
    object.insert("interaction_revision".to_string(), Value::Null);
    object.insert("interaction_source".to_string(), Value::Null);
    object.insert("interaction_response_mode".to_string(), Value::Null);
    object.insert("provider_request_id".to_string(), Value::Null);
    object.insert("approval_id".to_string(), Value::Null);
    object.insert("permission_prompt_id".to_string(), Value::Null);
    object.insert("permission_request_id".to_string(), Value::Null);
    object.insert("interaction_resolution_reason".to_string(), json!(reason));
    object.insert(
        "interaction_resolved_at_ms".to_string(),
        json!(observed_at_ms),
    );
    if let Some(request_id) = resolved_provider_request_id
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        object.insert(
            "resolved_provider_request_id".to_string(),
            json!(request_id),
        );
    }
}

fn cloud_mcp_mark_terminal_value_closed(
    value: &mut Value,
    status_seq: u64,
    observed_at_ms: u64,
    reason: &str,
) {
    let Some(object) = value.as_object_mut() else {
        return;
    };
    object.insert("status".to_string(), json!("closed"));
    object.insert("state".to_string(), json!("closed"));
    object.insert("activity_status".to_string(), json!("closed"));
    object.insert("native_rail_state".to_string(), json!("closed"));
    object.insert("terminal_lifecycle".to_string(), json!("closed"));
    object.insert("readiness".to_string(), json!("closed"));
    object.insert("command_phase".to_string(), json!("closed"));
    object.insert("execution_phase".to_string(), json!("closed"));
    object.insert("turn_status".to_string(), json!("interrupted"));
    object.insert("input_ready".to_string(), json!(false));
    object.insert("session_state".to_string(), json!("no_session"));
    object.insert("active".to_string(), json!(false));
    object.insert("commandable".to_string(), json!(false));
    object.insert("native_connected".to_string(), json!(false));
    object.insert("connected".to_string(), json!(false));
    object.insert("status_seq".to_string(), json!(status_seq));
    object.insert("observed_at_ms".to_string(), json!(observed_at_ms));
    object.insert("close_reason".to_string(), json!(reason));
}

fn cloud_mcp_mark_panel_last_known_read_only(value: &mut Value) {
    let Some(object) = value.as_object_mut() else {
        return;
    };
    object.insert("last_known_runtime".to_string(), json!(true));
    object.insert("runtime_read_only".to_string(), json!(true));
    object.insert("active".to_string(), json!(false));
    object.insert("commandable".to_string(), json!(false));
    object.insert("connected".to_string(), json!(false));
    object.insert("native_connected".to_string(), json!(false));
}

fn cloud_mcp_mark_workspace_terminals_last_known_read_only(workspace: &mut Value) {
    let observed_at_ms = cloud_mcp_now_ms();
    let Some(terminals) = workspace.get_mut("terminals") else {
        return;
    };
    if let Some(terminals) = terminals.as_array_mut() {
        for terminal in terminals {
            cloud_mcp_mark_terminal_last_known_read_only(terminal);
            cloud_mcp_clear_terminal_prompt_state(
                terminal,
                None,
                "workspace_deactivated",
                observed_at_ms,
            );
        }
        return;
    }
    if let Some(terminals) = terminals.as_object_mut() {
        for terminal in terminals.values_mut() {
            cloud_mcp_mark_terminal_last_known_read_only(terminal);
            cloud_mcp_clear_terminal_prompt_state(
                terminal,
                None,
                "workspace_deactivated",
                observed_at_ms,
            );
        }
    }
}

fn cloud_mcp_recount_workspace_terminal_activity(workspace: &mut Value) {
    let Some(terminals) = workspace.get("terminals").and_then(Value::as_array) else {
        return;
    };
    let terminal_count = terminals.len();
    let active_count = terminals
        .iter()
        .filter(|terminal| {
            let status = cloud_mcp_payload_text(
                terminal,
                &[
                    "status",
                    "state",
                    "activity_status",
                    "terminal_lifecycle",
                    "session_state",
                ],
            )
            .unwrap_or_default()
            .trim()
            .to_ascii_lowercase();
            !matches!(
                status.as_str(),
                "closed"
                    | "deleted"
                    | "removed"
                    | "exited"
                    | "terminated"
                    | "no_session"
                    | "offline"
                    | "deactivated"
                    | "disabled"
            )
        })
        .count();
    if let Some(object) = workspace.as_object_mut() {
        object.insert("terminal_count".to_string(), json!(terminal_count));
        object.insert("active_count".to_string(), json!(active_count));
    }
}

async fn cloud_mcp_mark_device_live_terminal_closed(
    state: &CloudMcpState,
    pane_id: &str,
    instance_id: u64,
    status_seq: u64,
    workspace_runtime_seq: u64,
    workspace_runtime_epoch: &str,
    observed_at_ms: u64,
    reason: &str,
) {
    let mut snapshots = state.runtime_snapshots.lock().await;
    let Some(snapshot) = snapshots.workspace_terminals.as_mut() else {
        return;
    };
    let Some(workspaces) = snapshot.get_mut("workspaces").and_then(Value::as_array_mut) else {
        return;
    };
    let mut matched = 0usize;
    for workspace in workspaces {
        let mut workspace_matched = false;
        let Some(terminals) = workspace.get_mut("terminals").and_then(Value::as_array_mut) else {
            continue;
        };
        for terminal in terminals {
            if !cloud_mcp_presence_terminal_matches_instance_for_close(
                terminal,
                pane_id,
                instance_id,
            ) {
                continue;
            }
            matched = matched.saturating_add(1);
            workspace_matched = true;
            cloud_mcp_clear_terminal_prompt_state(terminal, None, reason, observed_at_ms);
            cloud_mcp_mark_terminal_value_closed(terminal, status_seq, observed_at_ms, reason);
        }
        if workspace_matched {
            cloud_mcp_recount_workspace_terminal_activity(workspace);
            if let Some(object) = workspace.as_object_mut() {
                object.insert(
                    "workspace_runtime_seq".to_string(),
                    json!(workspace_runtime_seq),
                );
                object.insert(
                    "workspace_runtime_epoch".to_string(),
                    json!(workspace_runtime_epoch),
                );
            }
        }
    }
    if matched > 0 {
        if let Some(object) = snapshot.as_object_mut() {
            object.insert("reason".to_string(), json!(reason));
            object.insert("ts_ms".to_string(), json!(observed_at_ms));
        }
    }
}

/// Withdraw a prompt that finished publishing after its discovery generation
/// or terminal instance had already been invalidated.  This mutates only an
/// existing exact terminal row and never routes the stale instance through the
/// normal activity pipeline, so it cannot create a phantom terminal or
/// resurrect a closed one as `thinking`.
fn cloud_mcp_withdraw_stale_terminal_prompt_in_snapshot(
    snapshot: &mut Value,
    pane_id: &str,
    instance_id: u64,
    provider_request_id: &str,
    terminal_closed: bool,
    status_seq: u64,
    observed_at_ms: u64,
    reason: &str,
) -> bool {
    let Some(workspaces) = snapshot.get_mut("workspaces").and_then(Value::as_array_mut) else {
        return false;
    };
    let mut changed = false;
    for workspace in workspaces {
        let mut workspace_changed = false;
        let Some(terminals) = workspace.get_mut("terminals").and_then(Value::as_array_mut) else {
            continue;
        };
        for terminal in terminals {
            if !cloud_mcp_presence_terminal_matches_instance_for_close(
                terminal,
                pane_id,
                instance_id,
            ) {
                continue;
            }
            if !terminal_closed {
                let published_request_id = cloud_mcp_payload_text(
                    terminal,
                    &["provider_request_id", "permission_request_id", "prompt_id"],
                )
                .unwrap_or_default();
                if published_request_id.trim() != provider_request_id.trim() {
                    // A newer prompt generation already owns this live row.
                    // The stale generation is resolved locally, but must not
                    // clear the replacement interaction.
                    continue;
                }
            }
            cloud_mcp_clear_terminal_prompt_state(
                terminal,
                Some(provider_request_id),
                reason,
                observed_at_ms,
            );
            if terminal_closed {
                cloud_mcp_mark_terminal_value_closed(terminal, status_seq, observed_at_ms, reason);
            } else if let Some(object) = terminal.as_object_mut() {
                // The terminal is still current but a newer deterministic
                // discovery generation replaced this prompt. Keep it alive in
                // a non-actionable startup state until that generation settles.
                object.insert("status".to_string(), json!("starting"));
                object.insert("state".to_string(), json!("starting"));
                object.insert("activity_status".to_string(), json!("starting"));
                object.insert("native_rail_state".to_string(), json!("starting"));
                object.insert("terminal_lifecycle".to_string(), json!("starting"));
                object.insert("readiness".to_string(), json!("starting"));
                object.insert("command_phase".to_string(), json!("starting"));
                object.insert("execution_phase".to_string(), json!("starting"));
                object.insert("turn_status".to_string(), json!("idle"));
                object.insert("input_ready".to_string(), json!(false));
                object.insert("status_seq".to_string(), json!(status_seq));
                object.insert("observed_at_ms".to_string(), json!(observed_at_ms));
            }
            workspace_changed = true;
            changed = true;
        }
        if workspace_changed {
            cloud_mcp_recount_workspace_terminal_activity(workspace);
        }
    }
    if changed {
        if let Some(object) = snapshot.as_object_mut() {
            object.insert("reason".to_string(), json!(reason));
            object.insert("ts_ms".to_string(), json!(observed_at_ms));
        }
    }
    changed
}

pub(crate) async fn cloud_mcp_withdraw_stale_terminal_prompt(
    state: &CloudMcpState,
    pane_id: &str,
    instance_id: u64,
    provider_request_id: &str,
    terminal_closed: bool,
    reason: &str,
) -> bool {
    let observed_at_ms = cloud_mcp_now_ms();
    let status_seq = cloud_mcp_next_terminal_lifecycle_seq(state, Some(observed_at_ms));
    let changed = {
        let mut snapshots = state.runtime_snapshots.lock().await;
        snapshots
            .workspace_terminals
            .as_mut()
            .is_some_and(|snapshot| {
                cloud_mcp_withdraw_stale_terminal_prompt_in_snapshot(
                    snapshot,
                    pane_id,
                    instance_id,
                    provider_request_id,
                    terminal_closed,
                    status_seq,
                    observed_at_ms,
                    reason,
                )
            })
    };
    if changed {
        let publish_reason = if terminal_closed {
            format!("terminal_close:{reason}")
        } else {
            format!("terminal_prompt_resolved:{reason}")
        };
        cloud_mcp_publish_device_live_state_snapshot_debounced(state, &publish_reason).await;
    }
    changed
}

async fn cloud_mcp_enqueue_terminal_closed_delta(
    state: &CloudMcpState,
    pane_id: &str,
    instance_id: u64,
    close_context: &TerminalCloudMcpCloseContext,
    context_entry: Option<&CloudMcpTerminalContextState>,
    agent_id: &str,
    local_task_id: Option<&str>,
    reason: &str,
    summary: &str,
) {
    let coordination = close_context.coordination.as_ref();
    let working_directory = close_context.working_directory.as_ref();
    let repo_root = cloud_mcp_terminal_repo_root_path(working_directory, coordination);
    let workspace_id = context_entry
        .map(|entry| entry.workspace_id.as_str())
        .filter(|value| !value.trim().is_empty())
        .or_else(|| {
            (!close_context.metadata.workspace_id.trim().is_empty())
                .then_some(close_context.metadata.workspace_id.as_str())
        })
        .map(str::to_string);
    let workspace_name = context_entry
        .map(|entry| entry.workspace_name.as_str())
        .filter(|value| !value.trim().is_empty())
        .or_else(|| {
            (!close_context.metadata.workspace_name.trim().is_empty())
                .then_some(close_context.metadata.workspace_name.as_str())
        })
        .map(str::to_string);
    let req = cloud_mcp_repo_request(
        workspace_path_display(&repo_root),
        workspace_id,
        workspace_name,
    );
    let device_profile = cloud_mcp_desktop_device_profile();
    let now_ms = cloud_mcp_now_ms();
    let status_seq = cloud_mcp_next_terminal_lifecycle_seq(state, Some(now_ms));
    let workspace_runtime_seq = cloud_mcp_next_workspace_runtime_seq(state, Some(now_ms));
    let workspace_runtime_epoch = cloud_mcp_workspace_runtime_epoch(state);
    let agent_kind = coordination
        .map(|coordination| coordination.agent_kind.as_str())
        .filter(|value| !value.trim().is_empty())
        .or_else(|| context_entry.map(|entry| entry.agent_id.as_str()))
        .filter(|value| !value.trim().is_empty())
        .or_else(|| {
            (!close_context.metadata.agent_kind.trim().is_empty())
                .then_some(close_context.metadata.agent_kind.as_str())
        })
        .or_else(|| {
            (!close_context.metadata.agent_id.trim().is_empty())
                .then_some(close_context.metadata.agent_id.as_str())
        })
        .unwrap_or("terminal");
    let terminal_index = context_entry
        .and_then(|entry| entry.terminal_index)
        .or(close_context.metadata.terminal_index);
    let last_prompt = context_entry
        .map(|entry| entry.last_prompt.as_str())
        .filter(|value| !value.trim().is_empty());
    let terminal_nickname = cloud_mcp_clean_terminal_nickname(
        close_context.metadata.terminal_nickname.trim(),
    )
    .or_else(|| cloud_mcp_clean_terminal_nickname(close_context.metadata.terminal_name.trim()));
    let terminal_display_name = terminal_nickname
        .as_deref()
        .filter(|value| !value.trim().is_empty())
        .or_else(|| {
            let value = close_context.metadata.terminal_name.trim();
            (!value.is_empty()).then_some(value)
        })
        .or_else(|| {
            let value = close_context.metadata.agent_id.trim();
            (!value.is_empty()).then_some(value)
        })
        .unwrap_or(agent_kind)
        .to_string();
    let terminal_nickname_text = terminal_nickname.unwrap_or_default();
    let payload = json!({
        "source": "rust-diffforge-terminal-close",
        "event_kind": "terminal_state_update",
        "v": 1,
        "device": device_profile.clone(),
        "device_id": device_profile["device_id"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "repo_id": req.repo_id,
        "workspace_root": req.root_display,
        "workspace_active": true,
        "workspace_id": req.workspace_id,
        "workspace_name": req.workspace_name,
        "workspace_status": "active",
        "workspace_runtime_seq": workspace_runtime_seq,
        "workspace_runtime_epoch": workspace_runtime_epoch,
        "display_name": terminal_display_name.clone(),
        "terminal_id": pane_id,
        "target_terminal_id": pane_id,
        "pane_id": pane_id,
        "terminal_instance_id": instance_id,
        "terminal_index": terminal_index,
        "terminal_epoch": format!("{pane_id}:{instance_id}"),
        "terminal_name": terminal_display_name.clone(),
        "terminal_nickname": terminal_nickname_text,
        "terminal_lifecycle": "closed",
        "agent_id": agent_id,
        "agent_kind": agent_kind,
        "agent_type": agent_kind,
        "provider": agent_kind,
        "event_type": "terminal.closed",
        "state": "closed",
        "status": "closed",
        "activity_status": "closed",
        "readiness": "closed",
        "turn_status": "interrupted",
        "command_phase": "closed",
        "execution_phase": "closed",
        "input_ready": false,
        "session_mode": close_context.session_mode.as_str(),
        "session_state": "no_session",
        "prompt_id": "",
        "prompt_kind": null,
        "prompt_default_option": null,
        "prompt_ttl_ms": null,
        "prompt_options": [],
        "prompt_questions": null,
        "prompt_schema": null,
        "prompt_url": null,
        "allows_free_text": false,
        "manual_approval_required": false,
        "provider_blocked_for_user": false,
        "terminal_is_prompting_user": false,
        "prompting_user_kind": null,
        "prompting_user_source": null,
        "prompting_user_confidence": null,
        "prompting_user_text": null,
        "interaction_id": null,
        "interaction_revision": null,
        "interaction_source": null,
        "interaction_response_mode": null,
        "provider_request_id": null,
        "task_id": local_task_id,
        "run_id": local_task_id,
        "last_prompt": last_prompt,
        "status_seq": status_seq,
        "observed_at_ms": now_ms,
        "reason": reason,
        "summary": summary,
        "ts_ms": now_ms});
    cloud_mcp_mark_device_live_terminal_closed(
        state,
        pane_id,
        instance_id,
        status_seq,
        workspace_runtime_seq,
        &workspace_runtime_epoch,
        now_ms,
        reason,
    )
    .await;
    cloud_mcp_publish_terminal_state_live_update(state, &payload, reason).await;
}

pub(crate) async fn cloud_mcp_mark_terminal_closed(
    state: &CloudMcpState,
    pane_id: &str,
    instance_id: u64,
    close_context: &TerminalCloudMcpCloseContext,
    reason: &str,
) {
    let coordination = close_context.coordination.as_ref();
    let working_directory = close_context.working_directory.as_ref();
    let agent_id = cloud_mcp_terminal_agent_id(pane_id, instance_id, coordination);
    let repo_id = cloud_mcp_terminal_repo_id(working_directory, coordination);
    let terminal_key = cloud_mcp_terminal_key(pane_id, instance_id);
    let active_task = close_context.active_task.lock().await.clone();
    let context_entry = {
        let runtime = state.inner.lock().await;
        runtime.terminal_contexts.get(&terminal_key).cloned()
    };
    let context_workspace_id = context_entry
        .as_ref()
        .map(|context| context.workspace_id.trim())
        .filter(|workspace_id| !workspace_id.is_empty())
        .map(str::to_string);
    if let Some(workspace_id) = context_workspace_id.as_deref() {
        cloud_mcp_publish_terminal_io_ended(state, workspace_id, pane_id, instance_id, reason)
            .await;
    }
    let cleanup_workspace_id = context_workspace_id
        .as_deref()
        .or_else(|| {
            let workspace_id = close_context.metadata.workspace_id.trim();
            (!workspace_id.is_empty()).then_some(workspace_id)
        })
        .unwrap_or_default();
    let _ = cloud_mcp_clear_terminal_remote_presence_for_terminal(
        state,
        cleanup_workspace_id,
        pane_id,
        instance_id,
        "terminal_closed",
    );
    let local_task_id = active_task
        .as_ref()
        .map(|task| task.task_id.clone())
        .or_else(|| {
            context_entry
                .as_ref()
                .and_then(|entry| entry.local_task_id.clone())
        });
    let title = active_task.as_ref().map(|task| task.title.as_str());
    let last_prompt = context_entry
        .as_ref()
        .map(|entry| entry.last_prompt.as_str())
        .filter(|prompt| !prompt.trim().is_empty());
    let work_subject = context_entry
        .as_ref()
        .map(|entry| cloud_mcp_work_subject(&entry.work_brief))
        .unwrap_or_else(|| {
            title
                .map(str::to_string)
                .unwrap_or_else(|| "terminal task".to_string())
        });
    let brief = format!(
        "Terminal closed via {reason}; marking {} inactive.",
        cloud_mcp_work_subject(&work_subject)
    );
    cloud_mcp_enqueue_terminal_closed_delta(
        state,
        pane_id,
        instance_id,
        close_context,
        context_entry.as_ref(),
        &agent_id,
        local_task_id.as_deref(),
        reason,
        &brief,
    )
    .await;
    let close_preserves_parked_task =
        matches!(reason, "terminal_close" | "close_all" | "drop_fallback");
    let active_task_is_parked = close_preserves_parked_task
        && active_task.as_ref().is_some_and(|task| {
            coordination
                .and_then(|coordination| {
                    crate::coordination::CoordinationKernel::open(
                        &coordination.repo_path,
                        Some(PathBuf::from(&coordination.db_path)),
                    )
                    .ok()
                })
                .and_then(|kernel| kernel.task_has_parked_resource_intents(&task.task_id).ok())
                .unwrap_or(false)
        });

    if let Some(active_task) = active_task.as_ref() {
        let lifecycle_status = if active_task_is_parked {
            "parked"
        } else {
            "interrupted"
        };
        let lifecycle_brief = if active_task_is_parked {
            format!(
                "Terminal closed via {reason}; parked task {} remains waiting for dependency release or session recovery.",
                cloud_mcp_work_subject(&work_subject)
            )
        } else {
            brief.clone()
        };
        cloud_mcp_mark_terminal_task_lifecycle(
            state,
            pane_id,
            instance_id,
            working_directory,
            coordination,
            Some(&active_task.task_id),
            Some(&active_task.title),
            lifecycle_status,
            &lifecycle_brief,
        )
        .await;
    }

    cloud_mcp_sync_terminal_agent_status(
        state,
        &repo_id,
        &agent_id,
        "closed",
        last_prompt,
        &brief,
        working_directory,
        pane_id,
        instance_id,
        coordination,
        local_task_id.as_deref(),
        Some(close_context.session_mode.as_str()),
        reason,
    )
    .await;

    let mut runtime = state.inner.lock().await;
    runtime.terminal_contexts.remove(&terminal_key);
}

pub(crate) fn cloud_mcp_clean_terminal_state_text(text: &str) -> String {
    let mut cleaned = String::with_capacity(text.len().min(2400));
    let mut chars = text.chars().peekable();
    while let Some(ch) = chars.next() {
        if ch == '\u{1b}' {
            match chars.peek().copied() {
                Some('[') => {
                    chars.next();
                    while let Some(next) = chars.next() {
                        if ('@'..='~').contains(&next) {
                            break;
                        }
                    }
                }
                Some(']') => {
                    chars.next();
                    let mut escaped = false;
                    while let Some(next) = chars.next() {
                        if next == '\u{7}' {
                            break;
                        }
                        if escaped && next == '\\' {
                            break;
                        }
                        escaped = next == '\u{1b}';
                    }
                }
                _ => {
                    let _ = chars.next();
                }
            }
            cleaned.push(' ');
        } else if ch.is_control() {
            cleaned.push(' ');
        } else {
            cleaned.push(ch);
        }
    }

    cleaned.split_whitespace().collect::<Vec<_>>().join(" ")
}

pub(crate) fn cloud_mcp_terminal_output_has_working_indicator(cleaned_text: &str) -> bool {
    let lower = cleaned_text.to_ascii_lowercase();
    let latest_mcp_startup = ["booting mcp server", "starting mcp server"]
        .into_iter()
        .filter_map(|needle| lower.rfind(needle))
        .max()
        .max(
            (lower.contains("mcp client for") && lower.contains("failed to start"))
                .then(|| lower.rfind("mcp client for"))
                .flatten(),
        );
    ["Working (", "Working("]
        .into_iter()
        .flat_map(|needle| {
            cleaned_text
                .match_indices(needle)
                .map(|(index, _)| index)
        })
        .filter(|index| {
            *index == 0
                || cleaned_text[..*index]
                    .chars()
                    .next_back()
                    .is_none_or(|character| {
                        !character.is_ascii_alphanumeric() && character != '_'
                    })
        })
        .filter_map(|index| {
            lower[index..]
                .find("esc to interrupt")
                .filter(|suffix_index| *suffix_index <= 160)
                .map(|_| index)
        })
        .max()
        .is_some_and(|working_index| {
            latest_mcp_startup.is_none_or(|startup_index| working_index > startup_index)
        })
}

pub(crate) fn cloud_mcp_terminal_output_has_mcp_startup_indicator(text: &str) -> bool {
    let lower = text.to_ascii_lowercase();
    lower.contains("booting mcp server")
        || lower.contains("starting mcp server")
        || (lower.contains("mcp client for") && lower.contains("failed to start"))
}

fn cloud_mcp_terminal_output_mcp_startup_blocks_prompt(text: &str) -> bool {
    let lower = text.to_ascii_lowercase();
    let latest_startup = ["booting mcp server", "starting mcp server"]
        .into_iter()
        .filter_map(|needle| lower.rfind(needle))
        .max()
        .max(
            (lower.contains("mcp client for") && lower.contains("failed to start"))
                .then(|| lower.rfind("mcp client for"))
                .flatten(),
        );
    let latest_prompt = ["›", "❯", "❱"]
        .into_iter()
        .filter_map(|needle| text.rfind(needle))
        .max();
    latest_startup.is_some_and(|startup_index| {
        latest_prompt.is_none_or(|prompt_index| startup_index > prompt_index)
    })
}

pub(crate) fn cloud_mcp_terminal_output_has_prompt_marker(cleaned_text: &str) -> bool {
    let lower = cleaned_text.trim().to_ascii_lowercase();
    let has_ascii_prompt_line = cleaned_text
        .lines()
        .rev()
        .filter_map(|line| {
            let trimmed = line.trim();
            (!trimmed.is_empty()).then_some(trimmed)
        })
        .take(4)
        .any(|line| line == ">" || line.starts_with("> "));
    cleaned_text.contains('›')
        || cleaned_text.contains('❯')
        || cleaned_text.contains('❱')
        || has_ascii_prompt_line
        || (lower.contains("ctrl+p commands")
            && (lower.contains("opencode") || lower.contains("build ")))
}

fn cloud_mcp_terminal_output_looks_active(text: &str) -> bool {
    let cleaned = cloud_mcp_clean_terminal_state_text(text);
    if cleaned.is_empty() {
        return false;
    }
    if cloud_mcp_terminal_output_has_working_indicator(&cleaned) {
        return true;
    }
    if cloud_mcp_terminal_output_mcp_startup_blocks_prompt(&cleaned) {
        return false;
    }
    if cloud_mcp_terminal_output_has_prompt_marker(&cleaned) {
        return false;
    }

    let lower = cleaned.to_lowercase();
    let tool_action = [
        "• called",
        "• ran",
        "• edited",
        "• created",
        "• updated",
        "• modified",
        "• explored",
        "• exploring",
        "• read",
        "• listed",
        "• searched",
        "• checked",
        "• checking",
        "• wrote",
        "• applied",
        "• started",
        "• starting",
    ]
    .iter()
    .any(|needle| lower.contains(needle));

    tool_action
        || lower.contains("called ")
        || lower.contains("ran ")
        || lower.contains("edited ")
        || lower.contains("created ")
        || lower.contains("updated ")
        || lower.contains("modified ")
        || lower.contains("i'll ")
        || lower.contains("i’ll ")
        || lower.contains("i will ")
        || lower.contains("i'm ")
        || lower.contains("i’m ")
        || lower.contains("i am ")
}

fn cloud_mcp_terminal_output_looks_ready(text: &str) -> bool {
    let cleaned = cloud_mcp_clean_terminal_state_text(text);
    if cloud_mcp_terminal_output_has_working_indicator(&cleaned) {
        return false;
    }
    if cloud_mcp_terminal_output_mcp_startup_blocks_prompt(&cleaned) {
        return false;
    }

    text.contains("\n›")
        || text.contains("\r›")
        || text.contains("› ")
        || text.contains("\n> ")
        || text.contains("\r> ")
        || cloud_mcp_terminal_output_has_prompt_marker(&cleaned)
}

pub(crate) fn cloud_mcp_agent_uses_activity_hooks(agent_id: &str) -> bool {
    // Keep in sync with the frontend `TERMINAL_ACTIVITY_HOOK_AGENT_KINDS`
    // (terminalActivityState.js). OpenCode owns its turn state through the
    // injected activity plugin, so it must emit the synthetic
    // `provider-turn-started` on app/queue-dispatched prompts (immediate
    // "thinking" highlight) and skip the text-scraping output observer that
    // would otherwise fire premature/duplicate turn-complete cues.
    matches!(
        agent_id.trim().to_ascii_lowercase().as_str(),
        "claude" | "codex" | "opencode"
    )
}

async fn cloud_mcp_observe_terminal_output(
    app: AppHandle,
    state: CloudMcpState,
    pane_id: &str,
    instance_id: u64,
    chunk: &[u8],
) {
    let observe_started_at = Instant::now();
    let terminal_key = cloud_mcp_terminal_key(pane_id, instance_id);
    let hooks_own_turn_state = {
        let runtime = state.inner.lock().await;
        runtime
            .terminal_contexts
            .get(&terminal_key)
            .is_some_and(|entry| cloud_mcp_agent_uses_activity_hooks(&entry.agent_id))
    };
    if hooks_own_turn_state {
        return;
    }
    let decode_started_at = Instant::now();
    let text = String::from_utf8_lossy(chunk);
    let decode_ms = terminal_diagnostic_elapsed_ms(decode_started_at);
    let scan_started_at = Instant::now();
    let looks_active = cloud_mcp_terminal_output_looks_active(&text);
    let looks_ready = cloud_mcp_terminal_output_looks_ready(&text);
    let scan_ms = terminal_diagnostic_elapsed_ms(scan_started_at);
    if !looks_active && !looks_ready {
        let elapsed_ms = terminal_diagnostic_elapsed_ms(observe_started_at);
        if elapsed_ms >= TERMINAL_DIAGNOSTIC_SLOW_MS {
            log_terminal_diagnostic_event(
                &app,
                "backend.output_observer.inactive_slow",
                json!({
                    "bytes": chunk.len(),
                    "decode_ms": decode_ms,
                    "elapsed_ms": elapsed_ms,
                    "instance_id": instance_id,
                    "pane_id": clean_terminal_diagnostic_log_text(pane_id),
                    "scan_ms": scan_ms,
                }),
            );
        }
        return;
    }

    let now_ms = cloud_mcp_now_ms();
    let context_missing_backed_off =
        cloud_mcp_terminal_context_missing_backed_off(&state, &terminal_key, now_ms);
    if !context_missing_backed_off {
        log_terminal_status_event(
            "backend.terminal.ground_truth.output_observed",
            json!({
                "bytes": chunk.len(),
                "decoded_preview": clean_terminal_diagnostic_log_text(&text),
                "instance_id": instance_id,
                "looks_active": looks_active,
                "looks_ready": looks_ready,
                "pane_id": clean_terminal_diagnostic_log_text(pane_id),
                "status_truth": if looks_active { "processing_or_active" } else { "idle_or_prompt_ready" },
            }),
        );
    }
    let _ = app.emit(
        TERMINAL_OUTPUT_STATE_EVENT,
        TerminalOutputStatePayload {
            pane_id: pane_id.to_string(),
            instance_id,
            looks_active,
            looks_ready,
            status_truth: if looks_active {
                "processing_or_active".to_string()
            } else {
                "idle_or_prompt_ready".to_string()
            },
            output_preview: clean_terminal_diagnostic_log_text(&text),
        },
    );
    if context_missing_backed_off {
        return;
    }
    let work_brief = cloud_mcp_extract_agent_work_brief(&text);
    let (work_update, completion, missing_context_lock_ms) = {
        let lock_started_at = Instant::now();
        let mut runtime = state.inner.lock().await;
        let lock_ms = terminal_diagnostic_elapsed_ms(lock_started_at);
        match runtime.terminal_contexts.get_mut(&terminal_key) {
            Some(entry) => {
                let hooks_own_turn_state = cloud_mcp_agent_uses_activity_hooks(&entry.agent_id);
                if looks_active && !hooks_own_turn_state {
                    entry.saw_agent_activity = true;
                }
                let work_update = if hooks_own_turn_state {
                    None
                } else if let Some(brief) = work_brief.clone() {
                    if !entry.work_brief_reported && entry.work_brief.trim().is_empty() {
                        entry.work_brief = brief.clone();
                    }
                    if entry.work_brief_reported {
                        None
                    } else {
                        entry.work_brief_reported = true;
                        Some((
                            entry.repo_id.clone(),
                            entry.agent_id.clone(),
                            entry.local_task_id.clone(),
                            entry.session_mode.clone(),
                            brief,
                            entry.working_directory.clone(),
                            entry.repo_root.clone(),
                        ))
                    }
                } else {
                    None
                };
                let old_enough = cloud_mcp_now_ms().saturating_sub(entry.created_ms) >= 5_000;
                let completion = if !hooks_own_turn_state
                    && entry.saw_agent_activity
                    && !entry.done_reported
                    && old_enough
                    && looks_ready
                {
                    entry.done_reported = true;
                    Some((
                        entry.local_task_id.clone(),
                        entry.repo_id.clone(),
                        entry.agent_id.clone(),
                        entry.last_prompt.clone(),
                        entry.work_brief.clone(),
                        entry.working_directory.clone(),
                        entry.repo_root.clone(),
                        entry.prompt_event_id.clone(),
                        entry.prompt_event_source.clone(),
                        entry.prompt_event_submitted_at.clone(),
                        entry.terminal_index,
                        entry.thread_id.clone(),
                        entry.workspace_id.clone(),
                        entry.workspace_name.clone(),
                        entry.session_mode.clone(),
                        entry.todo_id.clone(),
                        entry.todo_dispatch_id.clone(),
                        entry.todo_command_id.clone(),
                    ))
                } else {
                    None
                };
                if hooks_own_turn_state && (looks_active || looks_ready) {
                    log_terminal_status_event(
                        "backend.terminal.ground_truth.output_hook_managed_ignored",
                        json!({
                            "agent_id": entry.agent_id.clone(),
                            "bytes": chunk.len(),
                            "instance_id": instance_id,
                            "looks_active": looks_active,
                            "looks_ready": looks_ready,
                            "pane_id": clean_terminal_diagnostic_log_text(pane_id),
                            "status_truth": if looks_active { "processing_or_active" } else { "idle_or_prompt_ready" },
                        }),
                    );
                }
                let elapsed_ms = terminal_diagnostic_elapsed_ms(observe_started_at);
                if elapsed_ms >= TERMINAL_DIAGNOSTIC_SLOW_MS {
                    log_terminal_diagnostic_event(
                        &app,
                        "backend.output_observer.match_slow",
                        json!({
                            "bytes": chunk.len(),
                            "decode_ms": decode_ms,
                            "elapsed_ms": elapsed_ms,
                            "instance_id": instance_id,
                            "lock_ms": lock_ms,
                            "looks_active": looks_active,
                            "looks_ready": looks_ready,
                            "pane_id": clean_terminal_diagnostic_log_text(pane_id),
                            "scan_ms": scan_ms,
                            "will_complete": completion.is_some(),
                            "will_update": work_update.is_some(),
                        }),
                    );
                }
                (work_update, completion, None)
            }
            None => (None, None, Some(lock_ms)),
        }
    };
    if let Some(lock_ms) = missing_context_lock_ms {
        cloud_mcp_mark_terminal_context_missing(&state, &terminal_key, now_ms);
        log_terminal_status_event(
            "backend.terminal.ground_truth.missing_context",
            json!({
                "bytes": chunk.len(),
                "instance_id": instance_id,
                "looks_active": looks_active,
                "looks_ready": looks_ready,
                "pane_id": clean_terminal_diagnostic_log_text(pane_id),
                "status_truth": if looks_active { "processing_or_active" } else { "idle_or_prompt_ready" },
            }),
        );
        let elapsed_ms = terminal_diagnostic_elapsed_ms(observe_started_at);
        if elapsed_ms >= TERMINAL_DIAGNOSTIC_SLOW_MS {
            log_terminal_diagnostic_event(
                &app,
                "backend.output_observer.missing_context_slow",
                json!({
                    "bytes": chunk.len(),
                    "decode_ms": decode_ms,
                    "elapsed_ms": elapsed_ms,
                    "instance_id": instance_id,
                    "lock_ms": lock_ms,
                    "looks_active": looks_active,
                    "looks_ready": looks_ready,
                    "pane_id": clean_terminal_diagnostic_log_text(pane_id),
                    "scan_ms": scan_ms,
                }),
            );
        }
        return;
    }

    log_terminal_status_event(
        "backend.terminal.ground_truth.output_decision",
        json!({
            "bytes": chunk.len(),
            "instance_id": instance_id,
            "looks_active": looks_active,
            "looks_ready": looks_ready,
            "pane_id": clean_terminal_diagnostic_log_text(pane_id),
            "status_truth": if looks_active { "processing_or_active" } else { "idle_or_prompt_ready" },
            "will_mark_done": completion.is_some(),
            "will_send_active_update": work_update.is_some(),
        }),
    );

    if let Some((
        repo_id,
        agent_id,
        local_task_id,
        session_mode,
        brief,
        _working_directory,
        repo_root,
    )) = work_update
    {
        cloud_mcp_sync_terminal_agent_status(
            &state,
            &repo_id,
            &agent_id,
            "active",
            None,
            &brief,
            &repo_root,
            pane_id,
            instance_id,
            None,
            local_task_id.as_deref(),
            Some(session_mode.as_str()),
            "terminal_status",
        )
        .await;
    }

    let Some((
        local_task_id,
        repo_id,
        agent_id,
        _prompt,
        work_brief,
        _working_directory,
        repo_root,
        prompt_event_id,
        prompt_event_source,
        prompt_event_submitted_at,
        terminal_index,
        thread_id,
        workspace_id,
        _workspace_name,
        session_mode,
        todo_id,
        todo_dispatch_id,
        todo_command_id,
    )) = completion
    else {
        return;
    };
    log_terminal_status_event(
        "backend.terminal.ground_truth.done_detected",
        json!({
            "agent_id": agent_id.clone(),
            "instance_id": instance_id,
            "local_task_id": local_task_id.clone(),
            "pane_id": clean_terminal_diagnostic_log_text(pane_id),
            "prompt_event_id": prompt_event_id.clone(),
            "prompt_event_submitted_at": prompt_event_submitted_at.clone(),
            "repo_id": repo_id.clone(),
            "session_mode": session_mode.clone(),
            "status_truth": "idle_or_prompt_ready",
            "thread_id": thread_id.clone(),
            "workspace_id": workspace_id.clone(),
            "work_brief": clean_terminal_diagnostic_log_text(&work_brief),
        }),
    );
    if let Some(prompt_event_id) = prompt_event_id
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        log_terminal_status_event(
            "backend.voice_plan_task_status.prompt_ready_not_final",
            json!({
                "agent_id": agent_id.clone(),
                "instance_id": instance_id,
                "pane_id": clean_terminal_diagnostic_log_text(pane_id),
                "prompt_event_id": prompt_event_id,
                "prompt_event_source": prompt_event_source.clone(),
                "reason": "terminal_prompt_ready_is_not_provider_turn_complete",
                "terminal_index": terminal_index,
                "thread_id": thread_id.clone(),
                "workspace_id": workspace_id.clone(),
            }),
        );
    }
    if let (Some(todo_id), Some(dispatch_id), Some(command_id)) =
        (todo_id, todo_dispatch_id, todo_command_id)
    {
        cloud_mcp_record_direct_prompt_todo_dispatch_status(
            &state,
            &CloudMcpDirectPromptTodoRefs {
                todo_id,
                dispatch_id,
                command_id,
            },
            &workspace_id,
            "completed",
            json!({
                "reason": "terminal_prompt_ready",
                "agent_id": agent_id,
                "pane_id": pane_id,
                "prompt_event_id": prompt_event_id,
                "thread_id": thread_id,
            }),
        )
        .await;
    }
    if session_mode != TerminalSessionMode::ManagedPatch.as_str() {
        let brief = if work_brief.trim().is_empty() {
            "Terminal activity is idle.".to_string()
        } else {
            format!(
                "Terminal activity ready: {}",
                cloud_mcp_work_subject(&work_brief)
            )
        };
        cloud_mcp_sync_terminal_agent_status(
            &state,
            &repo_id,
            &agent_id,
            "inactive",
            None,
            &brief,
            &repo_root,
            pane_id,
            instance_id,
            None,
            local_task_id.as_deref(),
            Some(session_mode.as_str()),
            "terminal_unmanaged_prompt_ready",
        )
        .await;

        let mut runtime = state.inner.lock().await;
        runtime.terminal_contexts.remove(&terminal_key);
        return;
    }
    let brief = format!(
        "Ready for patch submission: {}",
        cloud_mcp_work_subject(&work_brief)
    );
    let _ = cloud_mcp_workspace_log(
        &repo_root,
        "cloud_mcp.context_pack.work_review",
        "",
        "",
        json!({
            "agent_id": clean_terminal_telemetry_text(&agent_id),
            "pane_id": clean_terminal_telemetry_text(pane_id),
            "instance_id": instance_id,
            "repo_id": clean_terminal_telemetry_text(&repo_id),
            "local_task_id": local_task_id.as_deref().map(clean_terminal_telemetry_text),
            "source": "terminal_prompt_ready",
            "status": "review",
            "completion_gate": "submit_patch_required",
        }),
    );
    cloud_mcp_sync_terminal_agent_status(
        &state,
        &repo_id,
        &agent_id,
        "inactive",
        None,
        &brief,
        &repo_root,
        pane_id,
        instance_id,
        None,
        local_task_id.as_deref(),
        Some(session_mode.as_str()),
        "terminal_prompt_ready",
    )
    .await;

    let mut runtime = state.inner.lock().await;
    runtime.terminal_contexts.remove(&terminal_key);
}

async fn cloud_mcp_record_direct_prompt_todo_dispatch_status(
    state: &CloudMcpState,
    refs: &CloudMcpDirectPromptTodoRefs,
    workspace_id: &str,
    status: &str,
    details: Value,
) {
    if refs.dispatch_id.trim().is_empty() {
        return;
    }
    // Deleted todos are terminal: turn-status echoes (hook events, prompt
    // ready) for a tombstoned id must never resurrect the row server-side.
    if todo_store_tombstone_ids(workspace_id).contains(refs.todo_id.as_str()) {
        return;
    }
    let device_profile = cloud_mcp_desktop_device_profile();
    let todo_id = refs.todo_id.as_str();
    let dispatch_id = refs.dispatch_id.as_str();
    let command_id = refs.command_id.as_str();
    let mut payload = json!({
        "event_kind": "workspace_todo_dispatch_status",
        "source": "rust-diffforge-direct-prompt",
        "todo_dispatch_id": dispatch_id,
        "dispatch_id": dispatch_id,
        "command_id": command_id,
        "todo_id": todo_id,
        "workspace_id": workspace_id,
        "device": device_profile.clone(),
        "device_id": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "status": status,
        "dispatch_status": status,
        "details": details,
        "ts_ms": cloud_mcp_now_ms(),
    });
    if let Some(dispatch_source) = cloud_mcp_payload_object(
        &details,
        &["dispatch_source", "source_context", "source_endpoint"],
    ) {
        payload["dispatch_source"] = dispatch_source;
    }
    if let Some(dispatch_target) = cloud_mcp_payload_object(
        &details,
        &["dispatch_target", "target_context", "target_endpoint"],
    ) {
        payload["dispatch_target"] = dispatch_target;
    }
    for (target_key, source_keys) in [
        ("target_agent_id", &["target_agent_id", "agent_id"][..]),
        (
            "target_terminal_id",
            &["target_terminal_id", "terminal_id", "pane_id"][..],
        ),
        (
            "target_terminal_index",
            &["target_terminal_index", "terminal_index"][..],
        ),
        ("target_thread_id", &["target_thread_id", "thread_id"][..]),
        (
            "target_color_slot",
            &["target_color_slot", "color_slot"][..],
        ),
        (
            "target_terminal_color",
            &["target_terminal_color", "terminal_color", "color"][..],
        ),
        (
            "provider_session_id",
            &["provider_session_id", "session_id"][..],
        ),
    ] {
        if let Some(value) = cloud_mcp_payload_text(&details, source_keys) {
            payload[target_key] = json!(value);
        }
    }
    cloud_mcp_limit_workspace_todo_sync_payload(&mut payload);
    if let Err(error) = cloud_mcp_apply_local_workspace_todo_event(
        state,
        "workspace_todo_dispatch_status",
        &payload,
        "direct_prompt_todo_status_local",
    )
    .await
    {
        log_terminal_status_event(
            "backend.direct_prompt_todo.status_error",
            json!({
                "dispatch_id": dispatch_id,
                "error": clean_terminal_telemetry_text(&error),
                "status": status,
                "todo_id": todo_id,
                "workspace_id": workspace_id,
            }),
        );
    }
}

async fn cloud_mcp_terminal_context_pack_for_prompt(
    state: CloudMcpState,
    pane_id: String,
    instance_id: u64,
    working_directory: PathBuf,
    coordination: Option<TerminalCoordinationSession>,
    session_mode: TerminalSessionMode,
    local_task_id: Option<String>,
    local_task_title: Option<String>,
    prompt: String,
    prompt_metadata: Option<CloudMcpTerminalPromptMetadata>,
) {
    let prompt = cloud_mcp_clean_prompt_text(&prompt);
    if prompt.trim().is_empty() {
        return;
    }
    let agent_id = cloud_mcp_terminal_agent_id(&pane_id, instance_id, coordination.as_ref());
    let repo_id = cloud_mcp_terminal_repo_id(&working_directory, coordination.as_ref());
    let status_working_directory =
        cloud_mcp_terminal_repo_root_path(&working_directory, coordination.as_ref());
    let terminal_key = cloud_mcp_terminal_key(&pane_id, instance_id);
    let prompt_metadata = prompt_metadata.unwrap_or_else(|| CloudMcpTerminalPromptMetadata {
        prompt_event_id: None,
        prompt_event_source: None,
        prompt_event_submitted_at: None,
        terminal_index: None,
        thread_id: None,
        workspace_id: String::new(),
        workspace_name: String::new(),
        todo_id: None,
        todo_dispatch_id: None,
        todo_command_id: None,
        todo_action: None,
        todo_resume_requested: false,
    });
    // Direct prompts are registered exclusively by the todo_dispatch capture
    // (one unique todo per prompt, with tombstones and settlement). This
    // pipeline used to fabricate parallel hash-derived `direct-prompt-*` refs
    // here — a second writer whose context-cached ids were re-pushed on every
    // hook event, mutating one cloud row across prompts and resurrecting
    // deleted todos. The context now carries todo ids only when a REAL todo
    // drove the prompt.
    let effective_todo_id = cloud_mcp_clean_optional_text(&prompt_metadata.todo_id);
    let effective_todo_dispatch_id =
        cloud_mcp_clean_optional_text(&prompt_metadata.todo_dispatch_id);
    let effective_todo_command_id = cloud_mcp_clean_optional_text(&prompt_metadata.todo_command_id);
    let effective_todo_action = cloud_mcp_clean_optional_text(&prompt_metadata.todo_action);
    let effective_todo_resume_requested = prompt_metadata.todo_resume_requested;
    let prompt_workspace_id = cloud_mcp_workspace_id_match_key(&prompt_metadata.workspace_id);
    {
        let mut runtime = state.inner.lock().await;
        runtime.terminal_contexts.insert(
            terminal_key.clone(),
            CloudMcpTerminalContextState {
                last_prompt: prompt.clone(),
                repo_id: repo_id.clone(),
                agent_id: agent_id.clone(),
                working_directory: working_directory.clone(),
                repo_root: status_working_directory.clone(),
                prompt_event_id: prompt_metadata.prompt_event_id.clone(),
                prompt_event_source: prompt_metadata.prompt_event_source.clone(),
                prompt_event_submitted_at: prompt_metadata.prompt_event_submitted_at.clone(),
                terminal_index: prompt_metadata.terminal_index,
                thread_id: prompt_metadata.thread_id.clone(),
                workspace_id: prompt_workspace_id,
                workspace_name: prompt_metadata.workspace_name.clone(),
                session_mode: session_mode.as_str().to_string(),
                todo_id: effective_todo_id.clone(),
                todo_dispatch_id: effective_todo_dispatch_id.clone(),
                todo_command_id: effective_todo_command_id.clone(),
                created_ms: cloud_mcp_now_ms(),
                local_task_id: local_task_id.clone(),
                saw_agent_activity: false,
                work_brief: String::new(),
                work_brief_reported: false,
                done_reported: false,
            },
        );
    }
    cloud_mcp_clear_terminal_context_missing(&state, &terminal_key);

    if let Err(error) = cloud_mcp_connected_or_connect(&state).await {
        let _ = cloud_mcp_workspace_log(
            &status_working_directory,
            "cloud_mcp.context_pack.error",
            "",
            "",
            json!({
                "agent_id": agent_id,
                "pane_id": pane_id,
                "instance_id": instance_id,
                "error": clean_terminal_telemetry_text(&error),
            }),
        );
        return;
    }

    let payload = json!({
        "source": "rust-diffforge-terminal",
        "repo_id": repo_id,
        "agent_id": agent_id,
        "agent_kind": coordination.as_ref().map(|coordination| coordination.agent_kind.clone()),
        "coding_agent": coordination.as_ref().map(|coordination| coordination.agent_kind.clone()),
        "self_agent_id": agent_id,
        "current_agent_id": agent_id,
        "terminal_id": pane_id,
        "terminal_instance_id": instance_id,
        "terminal_index": prompt_metadata.terminal_index,
        "thread_id": prompt_metadata.thread_id,
        "workspace_id": prompt_metadata.workspace_id,
        "workspace_name": prompt_metadata.workspace_name,
        "prompt_event_id": prompt_metadata.prompt_event_id,
        "prompt_event_source": prompt_metadata.prompt_event_source,
        "prompt_event_submitted_at": prompt_metadata.prompt_event_submitted_at,
        "todo_id": effective_todo_id.as_deref(),
        "todo_dispatch_id": effective_todo_dispatch_id.as_deref(),
        "command_id": effective_todo_command_id.as_deref(),
        "todo_action": effective_todo_action.as_deref(),
        "todo_resume_requested": effective_todo_resume_requested,
        "resume_requested": effective_todo_resume_requested,
        "task_id": local_task_id.clone(),
        "run_id": local_task_id.clone(),
        "prompt": prompt,
        "session_mode": session_mode.as_str(),
        "file_authority": session_mode.file_authority(),
        "workspace_root": workspace_path_display(&status_working_directory),
        "coordination": coordination.as_ref().map(|coordination| json!({
            "agent_id": coordination.agent_id.clone(),
            "agent_kind": coordination.agent_kind.clone(),
            "session_id": coordination.session_id.clone(),
            "repo_path": coordination.repo_path.clone(),
            "local_task_id": local_task_id.clone(),
            "local_task_title": local_task_title.clone(),
        })),
        "ts_ms": cloud_mcp_now_ms(),
    });

    cloud_mcp_sync_terminal_agent_status(
        &state,
        &repo_id,
        &agent_id,
        "starting",
        Some(payload["prompt"].as_str().unwrap_or_default()),
        "Terminal prompt submitted; cloud task/context sync is disabled.",
        &status_working_directory,
        &pane_id,
        instance_id,
        coordination.as_ref(),
        local_task_id.as_deref(),
        Some(session_mode.as_str()),
        "terminal_prompt_submitted",
    )
    .await;

    cloud_mcp_sync_terminal_agent_status(
        &state,
        &repo_id,
        &agent_id,
        "active",
        payload["prompt"].as_str(),
        "Terminal activity is running with local-only task coordination.",
        &status_working_directory,
        &pane_id,
        instance_id,
        coordination.as_ref(),
        local_task_id.as_deref(),
        Some(session_mode.as_str()),
        "terminal_task_context_disabled",
    )
    .await;
}

async fn require_cloud_mcp_terminal_gate(
    state: &CloudMcpState,
    working_directory: Option<&str>,
    workspace_id: Option<&str>,
    workspace_name: Option<&str>,
) -> Result<CloudMcpStatus, String> {
    let _ = working_directory;
    let _ = workspace_id;
    let _ = workspace_name;
    Ok(cloud_mcp_status_snapshot(state).await)
}

async fn require_cloud_mcp_terminal_gate_for_path(
    state: &CloudMcpState,
    working_directory: &Path,
    workspace_id: Option<&str>,
    workspace_name: Option<&str>,
) -> Result<CloudMcpStatus, String> {
    require_cloud_mcp_terminal_gate(
        state,
        Some(&workspace_path_display(working_directory)),
        workspace_id,
        workspace_name,
    )
    .await
}

#[tauri::command(rename_all = "snake_case")]
async fn cloud_mcp_connect(
    state: State<'_, CloudMcpState>,
    expected_account_key: Option<String>,
) -> Result<CloudMcpStatus, String> {
    let expected_account_key = expected_account_key
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty());
    if let Some(expected) = expected_account_key {
        if state.auth.lock().await.account_key != expected {
            return Err("Cloud MCP connect belongs to a previous account.".to_string());
        }
    }
    let status = cloud_mcp_connect_state(state.inner()).await?;
    if let Some(expected) = expected_account_key {
        if state.auth.lock().await.account_key != expected {
            cloud_mcp_mark_global_ws_disconnected(
                state.inner(),
                "Cloud MCP account changed while connecting; reconnecting with fresh auth.",
            )
            .await;
            return Err("Cloud MCP connect belongs to a previous account.".to_string());
        }
    }
    Ok(status)
}

/// Manual retry. Clears offline/permanent-offline mode, resets the reconnect
/// window so the 10s/30s/3min retry cycle starts fresh, wakes the loop, and
/// ensures the loop is running.
#[tauri::command(rename_all = "snake_case")]
async fn cloud_mcp_reconnect_now(
    state: State<'_, CloudMcpState>,
) -> Result<CloudMcpStatus, String> {
    let state = state.inner();
    state.global_ws_perma_offline.store(false, Ordering::SeqCst);
    cloud_mcp_reconnect_window_reset(state);
    state.global_ws_reconnect.notify_waiters();
    // Wake the parked background-sync worker so the offline backlog drains
    // as soon as the user reconnects.
    state.background_sync.notify.notify_one();
    cloud_mcp_connect_state(state).await
}

/// Enter permanent offline mode immediately (e.g. the "Continue Offline" button
/// or a user choosing to stop retrying). The loop parks at the top until a
/// manual retry.
#[tauri::command(rename_all = "snake_case")]
async fn cloud_mcp_enter_offline_mode(
    state: State<'_, CloudMcpState>,
) -> Result<CloudMcpStatus, String> {
    let state = state.inner();
    state.global_ws_perma_offline.store(true, Ordering::SeqCst);
    let close_result = cloud_mcp_send_app_ws_close_request(state, "user_offline_mode").await;
    state.global_ws_epoch.fetch_add(1, Ordering::SeqCst);
    let _ = state.global_ws_tx.lock().await.take();
    let _ = state.global_ws_termio_tx.lock().await.take();
    cloud_mcp_mark_global_ws_offline_permanent(state).await;
    state.global_ws_reconnect.notify_waiters();
    if let Err(error) = close_result {
        log_cloud_sync_event(
            "ws.offline_close_skipped",
            json!({ "error": clean_terminal_telemetry_text(&error) }),
        );
    }
    Ok(cloud_mcp_status_snapshot(state).await)
}

async fn cloud_mcp_signal_desktop_closing(app: &AppHandle, reason: &str) -> Result<Value, String> {
    let state = app.state::<CloudMcpState>().inner().clone();
    if !cloud_mcp_status_snapshot(&state).await.global_ws_connected {
        return Ok(json!({
            "ok": true,
            "sent": false,
            "reason": "websocket_not_connected",
        }));
    }

    let reason = reason.trim();
    let lifecycle_result = timeout(
        Duration::from_millis(900),
        cloud_mcp_send_lifecycle_event(
            &state,
            "desktop_client_closing",
            "closing",
            Some(if reason.is_empty() {
                "app_shutdown"
            } else {
                reason
            }),
        ),
    )
    .await;
    let result = lifecycle_result
        .map_err(|_| "Timed out sending desktop close signal to Cloud MCP.".to_string())??;
    Ok(result)
}

async fn cloud_mcp_request_desktop_close(app: &AppHandle, reason: &str) -> Result<(), String> {
    let state = app.state::<CloudMcpState>().inner().clone();
    if !cloud_mcp_status_snapshot(&state).await.global_ws_connected {
        return Ok(());
    }

    timeout(
        Duration::from_millis(900),
        cloud_mcp_send_app_ws_close_request(&state, reason),
    )
    .await
    .map_err(|_| "Timed out sending desktop close request to Cloud MCP.".to_string())??;
    sleep(Duration::from_millis(250)).await;
    Ok(())
}

const CLOUD_MCP_LEGACY_SESSION_STATE_KEY: &str = "desktop-session";

fn cloud_mcp_remove_legacy_desktop_session(app: &AppHandle) {
    if let Ok(path) = app_local_state_path(app, CLOUD_MCP_LEGACY_SESSION_STATE_KEY) {
        let _ = fs::remove_file(&path);
        let _ = fs::remove_file(path.with_extension("json.tmp"));
    }
}

fn cloud_mcp_auth_context_changed(
    previous_account_key: &str,
    previous_has_session: bool,
    previous_scope_type: &str,
    previous_team_id: Option<&str>,
    account_key: &str,
    has_session: bool,
    scope_type: &str,
    team_id: Option<&str>,
) -> bool {
    previous_account_key != account_key
        || previous_has_session != has_session
        || previous_scope_type != scope_type
        || previous_team_id != team_id
}

fn cloud_mcp_account_scope_change_requires_disconnect(
    account_context_changed: bool,
    global_ws_connected: bool,
    connection_id_present: bool,
) -> bool {
    account_context_changed && (global_ws_connected || connection_id_present)
}

async fn cloud_mcp_apply_desktop_auth_session(
    app: AppHandle,
    state: &CloudMcpState,
    account_key: Option<String>,
    token: Option<String>,
    scope_type: Option<String>,
    team_id: Option<String>,
    plan_name: Option<String>,
    device_limit: Option<u64>,
) -> Result<CloudMcpStatus, String> {
    let account_key = account_key.unwrap_or_default().trim().to_string();
    let token = token
        .unwrap_or_default()
        .replace(|character: char| character.is_control(), "")
        .trim()
        .to_string();
    let desktop_session_token = if token.is_empty() {
        None
    } else {
        validate_auth_value("Desktop session", &token)?;
        Some(token)
    };
    let (billing_scope_type, team_id) = cloud_mcp_account_scope_from_values(scope_type, team_id);
    let plan_name = cloud_mcp_plan_name_from_value(plan_name);
    let device_limit = cloud_mcp_device_limit_from_value(device_limit, &plan_name);
    let previous_auth = {
        let auth = state.auth.lock().await;
        (
            auth.account_key.clone(),
            auth.desktop_session_token.is_some(),
            auth.billing_scope_type.clone(),
            auth.team_id.clone(),
        )
    };
    let account_context_changed = cloud_mcp_auth_context_changed(
        &previous_auth.0,
        previous_auth.1,
        &previous_auth.2,
        previous_auth.3.as_deref(),
        &account_key,
        desktop_session_token.is_some(),
        &billing_scope_type,
        team_id.as_deref(),
    );
    cloud_mcp_remove_legacy_desktop_session(&app);

    {
        let mut auth = state.auth.lock().await;
        auth.account_key = account_key.clone();
        auth.desktop_session_token = desktop_session_token.clone();
        auth.appwrite_jwt = None;
        auth.appwrite_jwt_expires_ms = None;
        auth.billing_scope_type = billing_scope_type.clone();
        auth.team_id = team_id.clone();
        auth.plan_name = plan_name.clone();
        auth.device_limit = device_limit;
    }
    cloud_mcp_update_process_auth_cache(
        desktop_session_token,
        None,
        None,
        Some(billing_scope_type),
        team_id,
        Some(plan_name),
        device_limit,
    );
    let registration_was_blocked = state
        .global_ws_registration_blocked
        .swap(false, Ordering::SeqCst);
    if account_context_changed {
        {
            let mut snapshots = state.runtime_snapshots.lock().await;
            *snapshots = CloudMcpRuntimeSnapshots::default();
        }
        let websocket_was_established = {
            let mut runtime = state.inner.lock().await;
            runtime.account_key = account_key.clone();
            runtime.account_usage_snapshot = None;
            runtime.account_device_live_state_snapshot = None;
            runtime.registered_workspaces.clear();
            cloud_mcp_account_scope_change_requires_disconnect(
                true,
                runtime.global_ws_connected,
                runtime.global_ws_connection_id.is_some(),
            )
        };
        if websocket_was_established {
            cloud_mcp_mark_global_ws_disconnected(
                state,
                "Cloud MCP account scope changed; reconnecting websocket with fresh scope.",
            )
            .await;
        } else {
            // Initial auth hydration commonly changes the empty bootstrap
            // scope before any socket exists. Wake connection startup without
            // recording a false ws.disconnected error.
            state.global_ws_reconnect.notify_waiters();
        }
    } else {
        state.inner.lock().await.account_key = account_key;
    }
    if registration_was_blocked {
        let mut runtime = state.inner.lock().await;
        if runtime.global_ws_status == "device_limit_reached" {
            runtime.connected = false;
            runtime.status = "starting".to_string();
            runtime.last_error.clear();
            runtime.global_ws_connected = false;
            runtime.global_ws_status = "starting".to_string();
            runtime.global_ws_last_error.clear();
            runtime.global_ws_connection_id = None;
            runtime.global_ws_message_token = None;
        }
        drop(runtime);
        state.global_ws_reconnect.notify_waiters();
    }

    Ok(cloud_mcp_status_snapshot(state).await)
}

