/// Internal agent-inventory push so the headless watcher and remote levers
/// can converge the cloud without a tauri command context.
pub(crate) async fn cloud_mcp_sync_agent_installations_internal(
    state: &CloudMcpState,
    _repo_path: String,
    workspace_id: Option<String>,
    workspace_name: Option<String>,
    mut agent_statuses: Value,
    reason: Option<String>,
) -> Result<Value, String> {
    let clean_option = |value: Option<String>| {
        value
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
    };
    let workspace_id = clean_option(workspace_id);
    let workspace_name = clean_option(workspace_name);
    let reason = clean_option(reason).unwrap_or_else(|| "agent_status_refresh".to_string());
    if !cloud_mcp_agent_status_payload_has_model_catalogs(&agent_statuses) {
        cloud_mcp_refresh_agent_model_catalogs_from_status_payload(&agent_statuses, &reason).await;
    }
    cloud_mcp_enrich_agent_status_payload_with_cached_catalogs(&mut agent_statuses);
    let snapshot_id = format!(
        "agent-installations-{}-{}",
        cloud_mcp_now_ms(),
        uuid::Uuid::new_v4()
    );
    let device_profile = cloud_mcp_desktop_device_profile();
    let agent_items = agent_statuses
        .as_array()
        .ok_or_else(|| "Agent installation sync requires an agentStatuses array.".to_string())?;
    let coding_agents = agent_items
        .iter()
        .take(64)
        .filter_map(cloud_mcp_sanitize_coding_agent_status)
        .collect::<Vec<_>>();
    let agent_count = coding_agents.len();
    let payload = json!({
        "source": "rust-diffforge-device-live-agent-inventory",
        "event_kind": "device_live_state_snapshot",
        "device_id": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "platform": device_profile["platform"].clone(),
        "form_factor": device_profile["form_factor"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "workspace_id": workspace_id,
        "workspace_name": workspace_name,
        "agent_id": "rust-diffforge",
        "agent_label": "Diff Forge Desktop",
        "reason": reason,
        "snapshot_id": snapshot_id,
        "agent_count": agent_count,
        "coding_agents": coding_agents,
        "summary": "Desktop coding agent capabilities synced.",
        "ts_ms": cloud_mcp_now_ms(),
    });

    {
        let mut snapshots = state.runtime_snapshots.lock().await;
        snapshots.agent_installations = Some(payload.clone());
    }
    let mut sent_count = 0usize;
    let mut skipped_count = 0usize;
    for agent in &coding_agents {
        let Some(agent_id) = cloud_mcp_payload_text(agent, &["id", "agent_id"]) else {
            continue;
        };
        let sync_unit = format!("agent_installation:{agent_id}");
        let content_hash = cloud_mcp_outbox_payload_hash(&json!({
            "workspace_id": workspace_id,
            "workspace_name": workspace_name,
            "agent": agent,
        }));
        let unit_payload = json!({
            "source": "rust-diffforge-agent-installation-unit",
            "event_kind": "device_agent_installation_status",
            "device_id": device_profile["device_id"].clone(),
            "device_name": device_profile["device_name"].clone(),
            "machine_id": device_profile["device_id"].clone(),
            "machine_name": device_profile["machine_name"].clone(),
            "platform": device_profile["platform"].clone(),
            "form_factor": device_profile["form_factor"].clone(),
            "client_kind": device_profile["client_kind"].clone(),
            "workspace_id": workspace_id,
            "workspace_name": workspace_name,
            "agent_id": agent_id,
            "agent": agent,
            "coding_agents": [agent],
            "sync_unit": sync_unit,
            "sync_content_hash": content_hash,
            "reason": reason,
            "ts_ms": cloud_mcp_now_ms(),
        });
        let response = cloud_mcp_sync_device_live_unit_event(
            state,
            "device_agent_installation_status",
            unit_payload,
        )
        .await?;
        if response
            .get("skipped")
            .and_then(Value::as_bool)
            .unwrap_or(false)
        {
            skipped_count = skipped_count.saturating_add(1);
        } else {
            sent_count = sent_count.saturating_add(1);
        }
    }
    Ok(cloud_mcp_background_sync_ack(
        "device_agent_installation_status",
        "device_agent_installation_status",
        &reason,
        json!({
            "stored": {
                "stored_count": agent_count,
                "agent_count": agent_count,
                "sent_count": sent_count,
                "skipped_count": skipped_count,
            },
            "stored_count": agent_count,
            "agent_count": agent_count,
            "sent_count": sent_count,
            "skipped_count": skipped_count,
        }),
    ))
}

fn cloud_mcp_sanitize_coding_agent_status(agent: &Value) -> Option<Value> {
    let raw_id = cloud_mcp_payload_text(agent, &["id", "agent_id"])?;
    let id = cloud_mcp_canonical_coding_agent_id(&raw_id)?;
    let label = cloud_mcp_payload_text(agent, &["label", "agent_label"])
        .unwrap_or_else(|| cloud_mcp_coding_agent_label(&id).to_string())
        .trim()
        .chars()
        .take(80)
        .collect::<String>();
    let installed = cloud_mcp_payload_bool(agent, &["installed"], false);
    let authenticated = cloud_mcp_payload_bool(agent, &["authenticated"], false);
    let npm_available = cloud_mcp_payload_bool(
        agent,
        &["npm_available"],
        cloud_mcp_payload_bool(agent, &["npm_available"], false),
    );
    let npm_installed = cloud_mcp_payload_bool(
        agent,
        &["npm_installed"],
        cloud_mcp_payload_bool(agent, &["npm_installed"], false),
    );
    let npm_package_version = cloud_mcp_payload_text(agent, &["npm_package_version"])
        .or_else(|| cloud_mcp_payload_text(agent, &["npm_package_version"]))
        .unwrap_or_default();
    let npm_latest_version = cloud_mcp_payload_text(agent, &["npm_latest_version"])
        .or_else(|| cloud_mcp_payload_text(agent, &["npm_latest_version"]))
        .unwrap_or_default();
    let npm_update_available = cloud_mcp_payload_bool(
        agent,
        &["npm_update_available"],
        cloud_mcp_payload_bool(agent, &["npm_update_available"], false),
    );
    let update_available = cloud_mcp_payload_bool(
        agent,
        &["update_available"],
        cloud_mcp_payload_bool(agent, &["update_available"], npm_update_available),
    );
    let update_known = cloud_mcp_payload_bool(
        agent,
        &["update_known"],
        cloud_mcp_payload_bool(agent, &["update_known"], false),
    );
    let up_to_date = cloud_mcp_payload_bool(
        agent,
        &["up_to_date"],
        cloud_mcp_payload_bool(agent, &["up_to_date"], false),
    );
    let installing = cloud_mcp_payload_bool(agent, &["installing"], false);
    let updating = cloud_mcp_payload_bool(agent, &["updating"], false);
    let operation = cloud_mcp_payload_text(agent, &["operation"]).unwrap_or_default();
    let package_status = cloud_mcp_payload_text(agent, &["package_status"])
        .or_else(|| cloud_mcp_payload_text(agent, &["package_status"]))
        .unwrap_or_else(|| {
            if installing {
                "installing".to_string()
            } else if updating {
                "updating".to_string()
            } else if update_available {
                "update_available".to_string()
            } else if up_to_date {
                "up_to_date".to_string()
            } else if installed {
                "installed".to_string()
            } else {
                "missing".to_string()
            }
        });
    let mut sanitized = json!({
        "id": id.clone(),
        "label": if label.is_empty() { cloud_mcp_coding_agent_label(&id) } else { label.as_str() },
        "installed": installed,
        "authenticated": authenticated,
        "version": cloud_mcp_payload_text(agent, &["version"]).unwrap_or_default(),
        "npm_available": npm_available,
        "npm_installed": npm_installed,
        "npm_package_version": npm_package_version,
        "npm_latest_version": npm_latest_version,
        "npm_update_available": npm_update_available,
        "update_available": update_available,
        "update_known": update_known,
        "up_to_date": up_to_date,
        "installing": installing,
        "updating": updating,
        "operation": operation,
        "package_status": package_status});
    if matches!(id.as_str(), "codex" | "claude") {
        if let Some(catalog) = agent
            .get("model_catalog")
            .cloned()
            .or_else(|| cloud_mcp_latest_agent_model_catalog_value(&id))
        {
            sanitized["model_catalog"] = catalog;
        }
    }
    Some(sanitized)
}

fn cloud_mcp_canonical_coding_agent_id(value: &str) -> Option<String> {
    match value
        .trim()
        .to_ascii_lowercase()
        .replace([' ', '_'], "-")
        .as_str()
    {
        "codex" | "openai-codex" => Some("codex".to_string()),
        "claude" | "claude-code" | "claudecode" => Some("claude".to_string()),
        "opencode" | "open-code" | "opencode-ai" | "open-code-ai" => Some("opencode".to_string()),
        _ => None,
    }
}

fn cloud_mcp_coding_agent_label(agent_id: &str) -> &'static str {
    match agent_id {
        "codex" => "Codex",
        "claude" => "Claude Code",
        "opencode" => "OpenCode",
        _ => "Coding Agent",
    }
}

fn cloud_mcp_workspace_snapshot_is_locally_archived(workspace: &Value) -> bool {
    let bool_flag = ["local_archived", "locally_archived"].iter().any(|key| {
        workspace
            .get(*key)
            .and_then(Value::as_bool)
            .unwrap_or(false)
    });
    if bool_flag {
        return true;
    }

    let archive_timestamp =
        cloud_mcp_payload_text(workspace, &["local_archived_at", "locally_archived_at"]).is_some();
    if archive_timestamp {
        return true;
    }

    cloud_mcp_payload_text(workspace, &["status", "workspace_status"])
        .map(|status| status.eq_ignore_ascii_case("archived"))
        .unwrap_or(false)
}

fn cloud_mcp_workspace_root_text(workspace: &Value) -> Option<String> {
    cloud_mcp_payload_text(
        workspace,
        &["workspace_root", "repo_path", "root_directory", "path"],
    )
}

fn cloud_mcp_json_collection_items(value: &Value) -> Vec<Value> {
    match value {
        Value::Array(items) => items.clone(),
        Value::Object(items) => items.values().cloned().collect(),
        Value::String(text) => serde_json::from_str::<Value>(text)
            .ok()
            .map(|parsed| cloud_mcp_json_collection_items(&parsed))
            .unwrap_or_default(),
        _ => Vec::new(),
    }
}

fn cloud_mcp_is_app_control_pane_id(pane_id: &str) -> bool {
    let pane_id = pane_id.trim();
    let pane_id_key = pane_id.to_ascii_lowercase();
    if pane_id_key == CLOUD_MCP_APP_CONTROL_PANE_ID {
        return true;
    }
    let Some(suffix) = pane_id_key.strip_prefix(CLOUD_MCP_APP_CONTROL_PANE_ID) else {
        return false;
    };
    let Some(index) = suffix.strip_prefix('-') else {
        return false;
    };
    !index.is_empty() && index.bytes().all(|byte| byte.is_ascii_digit())
}

fn cloud_mcp_terminal_value_is_device_orchestrator(value: &Value) -> bool {
    let terminal_scope =
        cloud_mcp_payload_text(value, &["terminal_scope", "scope", "terminal_scope_kind"])
            .unwrap_or_default()
            .trim()
            .to_ascii_lowercase();
    if terminal_scope == "device" {
        return true;
    }

    let terminal_kind = cloud_mcp_payload_text(value, &["terminal_kind", "surface_kind", "role"])
        .unwrap_or_default()
        .trim()
        .to_ascii_lowercase();
    if matches!(
        terminal_kind.as_str(),
        "terminal_orchestrator" | "device_terminal_orchestrator" | "app_control_orchestrator"
    ) {
        return true;
    }

    let workspace_id = cloud_mcp_payload_text(value, &["workspace_id"]).unwrap_or_default();
    if cloud_mcp_is_app_control_workspace_id(&workspace_id) {
        return true;
    }

    let pane_id = cloud_mcp_payload_text(value, &["pane_id", "terminal_id", "target_terminal_id"])
        .unwrap_or_default();
    cloud_mcp_is_app_control_pane_id(&pane_id)
}

fn cloud_mcp_normalize_device_terminal_orchestrator(
    terminal: &Value,
    fallback_index: usize,
    observed_at_ms: u64,
) -> Option<Value> {
    let pane_id =
        cloud_mcp_payload_text(terminal, &["pane_id", "target_terminal_id", "terminal_id"]);
    let terminal_id = pane_id
        .clone()
        .or_else(|| {
            cloud_mcp_payload_text(terminal, &["terminal_id", "target_terminal_id", "pane_id"])
        })
        .unwrap_or_else(|| format!("device-terminal-orchestrator-{}", fallback_index + 1));
    let pane_id = pane_id.unwrap_or_else(|| terminal_id.clone());
    if terminal_id.trim().is_empty() && pane_id.trim().is_empty() {
        return None;
    }

    let terminal_index = terminal
        .get("terminal_index")
        .or_else(|| terminal.get("index"))
        .and_then(Value::as_i64)
        .unwrap_or(fallback_index as i64)
        .clamp(0, 255);
    let display_name = format!("{}", fallback_index + 1);
    let status = cloud_mcp_payload_text(terminal, &["status", "state"])
        .unwrap_or_else(|| "running".to_string());
    let activity_status =
        cloud_mcp_payload_text(terminal, &["activity_status"]).unwrap_or_else(|| status.clone());
    let agent_kind =
        cloud_mcp_payload_text(terminal, &["agent_kind", "agent_id", "provider", "kind"])
            .unwrap_or_else(|| "terminal".to_string());
    let thread_id = cloud_mcp_payload_text(terminal, &["thread_id", "target_thread_id"]);
    let provider_session_id = cloud_mcp_payload_text(
        terminal,
        &["provider_session_id", "native_session_id", "session_id"],
    );

    let mut normalized = terminal.clone();
    let Some(object) = normalized.as_object_mut() else {
        return None;
    };
    object.insert(
        "workspace_id".to_string(),
        json!(CLOUD_MCP_APP_CONTROL_WORKSPACE_ID),
    );
    object.insert("terminal_scope".to_string(), json!("device"));
    object.insert("terminal_kind".to_string(), json!("terminal_orchestrator"));
    object.insert("workspace_scoped".to_string(), json!(false));
    object.insert("terminal_index".to_string(), json!(terminal_index));
    object.insert("index".to_string(), json!(terminal_index));
    object.insert("display_name".to_string(), json!(display_name.clone()));
    object.insert("terminal_name".to_string(), json!(display_name.clone()));
    object.insert("terminal_nickname".to_string(), json!(display_name));
    object.insert("terminal_id".to_string(), json!(terminal_id.clone()));
    object.insert("target_terminal_id".to_string(), json!(terminal_id));
    object.insert("pane_id".to_string(), json!(pane_id));
    if let Some(thread_id) = thread_id.filter(|value| !value.trim().is_empty()) {
        object.insert("thread_id".to_string(), json!(thread_id.clone()));
        object.insert("target_thread_id".to_string(), json!(thread_id));
    }
    if let Some(provider_session_id) = provider_session_id.filter(|value| !value.trim().is_empty())
    {
        object.insert(
            "provider_session_id".to_string(),
            json!(provider_session_id.clone()),
        );
        object.insert(
            "native_session_id".to_string(),
            json!(provider_session_id.clone()),
        );
        object.insert("session_id".to_string(), json!(provider_session_id));
    }
    object.insert("agent_kind".to_string(), json!(agent_kind));
    object.insert("status".to_string(), json!(status));
    object.insert("activity_status".to_string(), json!(activity_status));
    object
        .entry("commandable".to_string())
        .or_insert(json!(true));
    object.entry("connected".to_string()).or_insert(json!(true));
    object
        .entry("native_connected".to_string())
        .or_insert(json!(true));
    object.insert("updated_at_ms".to_string(), json!(observed_at_ms));
    object.insert("ts_ms".to_string(), json!(observed_at_ms));
    cloud_mcp_enforce_terminal_prompt_status_projection(&mut normalized);
    Some(normalized)
}

fn cloud_mcp_update_terminal_orchestrator_counts(snapshot: &mut Value) {
    let count = snapshot
        .get("terminal_orchestrators")
        .and_then(Value::as_array)
        .map(Vec::len)
        .unwrap_or_default();
    if let Some(object) = snapshot.as_object_mut() {
        object.insert("terminal_orchestrator_count".to_string(), json!(count));
    }
}

fn cloud_mcp_renumber_device_terminal_orchestrators(orchestrators: &mut [Value]) {
    for (index, terminal) in orchestrators.iter_mut().enumerate() {
        let display_name = format!("{}", index + 1);
        if let Some(object) = terminal.as_object_mut() {
            object.insert("display_name".to_string(), json!(display_name.clone()));
            object.insert("terminal_name".to_string(), json!(display_name.clone()));
            object.insert("terminal_nickname".to_string(), json!(display_name));
        }
    }
}

fn cloud_mcp_upsert_device_terminal_orchestrator(
    snapshot: &mut Value,
    terminal: &Value,
    observed_at_ms: u64,
) {
    let fallback_index = snapshot
        .get("terminal_orchestrators")
        .and_then(Value::as_array)
        .map(Vec::len)
        .unwrap_or_default();
    let Some(normalized) =
        cloud_mcp_normalize_device_terminal_orchestrator(terminal, fallback_index, observed_at_ms)
    else {
        return;
    };
    let terminal_id = cloud_mcp_payload_text(&normalized, &["terminal_id", "target_terminal_id"])
        .unwrap_or_default();
    let terminal_instance_id =
        cloud_mcp_payload_u64(&normalized, &["terminal_instance_id", "instance_id"])
            .unwrap_or_default();
    let removes_from_snapshot = cloud_mcp_terminal_state_removes_from_live_snapshot(&normalized);

    let Some(object) = snapshot.as_object_mut() else {
        return;
    };
    object
        .entry("terminal_orchestrators".to_string())
        .or_insert_with(|| json!([]));
    if !object
        .get("terminal_orchestrators")
        .and_then(Value::as_array)
        .is_some()
    {
        object.insert("terminal_orchestrators".to_string(), json!([]));
    }
    let Some(orchestrators) = object
        .get_mut("terminal_orchestrators")
        .and_then(Value::as_array_mut)
    else {
        return;
    };

    let existing_index = orchestrators.iter().position(|candidate| {
        cloud_mcp_presence_terminal_matches_instance(candidate, &terminal_id, terminal_instance_id)
    });
    if removes_from_snapshot {
        orchestrators.retain(|candidate| {
            !cloud_mcp_presence_terminal_matches_instance(
                candidate,
                &terminal_id,
                terminal_instance_id,
            )
        });
    } else if let Some(index) = existing_index {
        if let Some(existing) = orchestrators.get_mut(index) {
            cloud_mcp_live_state_merge_object(existing, normalized);
        }
    } else {
        orchestrators.push(normalized);
    }
    cloud_mcp_renumber_device_terminal_orchestrators(orchestrators);
    let mirror = Value::Array(orchestrators.clone());
    object.insert("terminal_orchestrators".to_string(), mirror);
    object.insert("updated_at_ms".to_string(), json!(observed_at_ms));
    object.insert("ts_ms".to_string(), json!(observed_at_ms));
    cloud_mcp_update_terminal_orchestrator_counts(snapshot);
}

#[tauri::command(rename_all = "snake_case")]
async fn cloud_mcp_sync_device_workspaces_snapshot(
    state: State<'_, CloudMcpState>,
    workspaces: Value,
    terminal_orchestrators: Option<Value>,
    reason: Option<String>,
) -> Result<Value, String> {
    cloud_mcp_sync_device_workspaces_snapshot_internal(
        state.inner(),
        workspaces,
        terminal_orchestrators,
        reason,
    )
    .await
}

async fn cloud_mcp_sync_device_workspaces_snapshot_internal(
    state: &CloudMcpState,
    workspaces: Value,
    terminal_orchestrators: Option<Value>,
    reason: Option<String>,
) -> Result<Value, String> {
    let clean_option = |value: Option<String>| {
        value
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
    };
    let reason = clean_option(reason).unwrap_or_else(|| "device_workspaces_snapshot".to_string());
    let reason_for_ack = reason.clone();
    let reported_workspace_items = workspaces
        .as_array()
        .ok_or_else(|| "Device workspace snapshot sync requires a workspaces array.".to_string())?;
    let input_workspace_count = reported_workspace_items.len();
    let authoritative_catalog = match cloud_mcp_authoritative_local_workspace_catalog() {
        Ok(Some(catalog)) => catalog,
        Ok(None) => {
            return Ok(cloud_mcp_background_sync_ack(
                "device_workspaces_snapshot",
                "device_workspaces_snapshot",
                &reason_for_ack,
                json!({
                    "queued": false,
                    "sent": false,
                    "skipped": true,
                    "skip_reason": "workspace_catalog_not_ready",
                    "input_workspace_count": input_workspace_count,
                    "workspace_count": 0,
                    "workspace_snapshot_authoritative": false,
                    "workspace_snapshot_complete": false,
                }),
            ));
        }
        Err(error) => {
            log_terminal_status_event(
                "backend.cloud_mcp.workspace_catalog.not_ready",
                json!({
                    "reason": reason_for_ack,
                    "error": clean_terminal_telemetry_text(&error),
                }),
            );
            return Ok(cloud_mcp_background_sync_ack(
                "device_workspaces_snapshot",
                "device_workspaces_snapshot",
                &reason_for_ack,
                json!({
                    "queued": false,
                    "sent": false,
                    "skipped": true,
                    "skip_reason": "workspace_catalog_invalid",
                    "input_workspace_count": input_workspace_count,
                    "workspace_count": 0,
                    "workspace_snapshot_authoritative": false,
                    "workspace_snapshot_complete": false,
                }),
            ));
        }
    };
    // The durable catalog owns membership. Runtime snapshots may only enrich rows
    // that still exist in that catalog, and the just-reported live update wins
    // over cached fields. This keeps W2/W3 live state intact when activation only
    // reports W1 without allowing a deleted cached workspace to reappear.
    let cached_catalog_rows = {
        let snapshots = state.runtime_snapshots.lock().await;
        [
            snapshots.workspace_catalog.as_ref(),
            snapshots.workspace_terminals.as_ref(),
            snapshots.workspace_servers.as_ref(),
        ]
        .into_iter()
        .flatten()
        .flat_map(|snapshot| cloud_mcp_payload_items(snapshot, &["workspaces"], usize::MAX))
        .collect::<Vec<_>>()
    };
    let complete_workspace_catalog = cloud_mcp_overlay_workspace_catalog_rows(
        cloud_mcp_overlay_workspace_catalog_rows(authoritative_catalog, &cached_catalog_rows),
        reported_workspace_items,
    );
    let workspace_items = complete_workspace_catalog.as_slice();
    let mut normalized_workspaces = Vec::new();
    let mut selected_workspace_id: Option<String> = None;
    let mut selected_workspace_name: Option<String> = None;
    let mut skipped_archived_count = 0usize;
    let mut normalized_terminal_orchestrators = Vec::new();
    let device_profile = cloud_mcp_desktop_device_profile();

    // Deactivating a workspace closes its PTYs, so the frontend reports it with zero
    // terminals; the device contract is that remote dashboards keep showing the last
    // known terminals read-only. Backfill inactive workspaces from the cached snapshots
    // instead of publishing an authoritative empty list that would clear them everywhere.
    let cached_last_known_workspaces: std::collections::BTreeMap<String, Value> = {
        let snapshots = state.runtime_snapshots.lock().await;
        let mut cached = std::collections::BTreeMap::new();
        for snapshot in [
            snapshots.workspace_terminals.as_ref(),
            snapshots.workspace_catalog.as_ref(),
        ]
        .into_iter()
        .flatten()
        {
            for workspace in cloud_mcp_payload_items(snapshot, &["workspaces"], usize::MAX) {
                let Some(workspace_id) =
                    cloud_mcp_payload_text(&workspace, &["workspace_id", "id"])
                        .filter(|value| !value.trim().is_empty())
                else {
                    continue;
                };
                let workspace_id = cloud_mcp_workspace_id_match_key(&workspace_id);
                if cached.contains_key(&workspace_id) {
                    continue;
                }
                if !cloud_mcp_workspace_snapshot_is_locally_archived(&workspace) {
                    cached.insert(workspace_id, workspace);
                }
            }
        }
        cached
    };
    let cached_last_known_terminals: std::collections::BTreeMap<String, Vec<Value>> =
        cached_last_known_workspaces
            .iter()
            .filter_map(|(workspace_id, workspace)| {
                let terminals = cloud_mcp_workspace_terminal_items(workspace);
                (!terminals.is_empty()).then(|| (workspace_id.clone(), terminals))
            })
            .collect();
    let cached_last_known_panels: std::collections::BTreeMap<String, Vec<Value>> =
        cached_last_known_workspaces
            .iter()
            .filter_map(|(workspace_id, workspace)| {
                let panels = cloud_mcp_workspace_panel_items(workspace);
                (!panels.is_empty()).then(|| (workspace_id.clone(), panels))
            })
            .collect();
    let registered_workspace_roots: std::collections::BTreeMap<String, String> = {
        let runtime = state.inner.lock().await;
        runtime
            .registered_workspaces
            .values()
            .filter_map(|workspace| {
                let root = workspace.root.trim();
                (!root.is_empty()).then(|| {
                    (
                        cloud_mcp_workspace_id_match_key(&workspace.workspace_id),
                        root.to_string(),
                    )
                })
            })
            .collect()
    };

    if let Some(orchestrators) = terminal_orchestrators.as_ref() {
        for terminal in cloud_mcp_json_collection_items(orchestrators)
            .into_iter()
            .take(32)
        {
            if let Some(normalized) = cloud_mcp_normalize_device_terminal_orchestrator(
                &terminal,
                normalized_terminal_orchestrators.len(),
                cloud_mcp_now_ms(),
            ) {
                normalized_terminal_orchestrators.push(normalized);
            }
        }
    }

    for (workspace_index, workspace) in workspace_items.iter().enumerate() {
        if cloud_mcp_workspace_snapshot_is_locally_archived(workspace) {
            skipped_archived_count += 1;
            continue;
        }

        let Some(workspace_id) = cloud_mcp_payload_text(workspace, &["workspace_id", "id"])
            .filter(|value| !value.trim().is_empty())
        else {
            continue;
        };
        let workspace_id = cloud_mcp_workspace_id_match_key(&workspace_id);
        let terminal_items = cloud_mcp_workspace_terminal_items(workspace);
        if cloud_mcp_is_app_control_workspace_id(&workspace_id) {
            for terminal in terminal_items {
                if let Some(normalized) = cloud_mcp_normalize_device_terminal_orchestrator(
                    &terminal,
                    normalized_terminal_orchestrators.len(),
                    cloud_mcp_now_ms(),
                ) {
                    normalized_terminal_orchestrators.push(normalized);
                }
            }
            continue;
        }
        let workspace_name = cloud_mcp_payload_text(workspace, &["workspace_name", "name"])
            .unwrap_or_else(|| workspace_id.clone());
        let workspace_root = cloud_mcp_workspace_root_text(workspace)
            .or_else(|| {
                cached_last_known_workspaces
                    .get(&workspace_id)
                    .and_then(cloud_mcp_workspace_root_text)
            })
            .or_else(|| registered_workspace_roots.get(&workspace_id).cloned())
            .unwrap_or_default();
        let workspace_selected = workspace
            .get("selected")
            .or_else(|| workspace.get("is_selected"))
            .or_else(|| workspace.get("workspace_selected"))
            .and_then(Value::as_bool)
            .unwrap_or(false);
        if workspace_selected {
            selected_workspace_id = Some(workspace_id.clone());
            selected_workspace_name = Some(workspace_name.clone());
        }
        let workspace_active = workspace
            .get("workspace_active")
            .or_else(|| workspace.get("active"))
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let workspace_status = cloud_mcp_payload_text(workspace, &["workspace_status", "status"])
            .unwrap_or_else(|| {
                if workspace_active {
                    "active".to_string()
                } else {
                    "deactivated".to_string()
                }
            });
        let terminals = terminal_items
            .iter()
            .enumerate()
            .filter_map(|(index, terminal)| {
                if cloud_mcp_workspace_panel_kind(terminal).is_some() {
                    return None;
                }
                if cloud_mcp_terminal_value_is_device_orchestrator(terminal) {
                    if let Some(normalized) = cloud_mcp_normalize_device_terminal_orchestrator(
                        terminal,
                        normalized_terminal_orchestrators.len(),
                        cloud_mcp_now_ms(),
                    ) {
                        normalized_terminal_orchestrators.push(normalized);
                    }
                    return None;
                }
                let terminal_index = terminal
                    .get("terminal_index")
                    .and_then(Value::as_i64)
                    .unwrap_or(index as i64)
                    .clamp(0, 255);
                let agent_kind = cloud_mcp_payload_text(
                    terminal,
                    &["agent_kind", "agent_id", "role", "provider", "binary", "kind"],
                )
                .unwrap_or_else(|| "terminal".to_string());
                let agent_label =
                    cloud_mcp_payload_text(terminal, &["agent_label", "label"])
                        .unwrap_or_else(|| agent_kind.clone());
                let terminal_nickname = cloud_mcp_terminal_nickname_text(
                    terminal,
                    &["terminal_nickname", "terminal_name", "display_name"],
                );
                let status = cloud_mcp_payload_text(terminal, &["status", "state"])
                    .unwrap_or_else(|| "active".to_string());
                let native_rail_state = cloud_mcp_payload_text(
                    terminal,
                    &["native_rail_state", "rail_state", "top_rail_state"],
                );
                let native_rail_label = cloud_mcp_payload_text(
                    terminal,
                    &["native_rail_label", "rail_label", "top_rail_label"],
                );
                let activity_status = cloud_mcp_payload_text(
                    terminal,
                    &["activity_status"],
                )
                .or_else(|| native_rail_state.clone())
                .unwrap_or_else(|| status.clone());
                let display_status = cloud_mcp_payload_text(
                    terminal,
                    &["display_status"],
                )
                .or_else(|| native_rail_label.clone())
                .or_else(|| native_rail_state.clone())
                .unwrap_or_else(|| activity_status.clone());
                let terminal_status = cloud_mcp_payload_text(
                    terminal,
                    &["terminal_status", "reported_status"],
                )
                .unwrap_or_else(|| status.clone());
                let provider_session_id = cloud_mcp_payload_text(
                    terminal,
                    &["provider_session_id", "native_session_id", "session_id"],
                );
                let session_state =
                    cloud_mcp_payload_text(terminal, &["session_state"])
                        .unwrap_or_else(|| "unknown".to_string());
                let terminal_instance_id = terminal
                    .get("terminal_instance_id")
                    .cloned()
                    .unwrap_or(Value::Null);
                let status_seq = terminal
                    .get("status_seq")
                    .cloned()
                    .unwrap_or(Value::Null);
                let status_source = terminal
                    .get("status_source")
                    .cloned()
                    .unwrap_or(Value::Null);
                let visible_terminal = terminal
                    .get("visible_terminal")
                    .cloned()
                    .unwrap_or(Value::Null);
                let input_ready = terminal
                    .get("input_ready")
                    .cloned()
                    .unwrap_or(Value::Null);
                let prompt_options = terminal
                    .get("prompt_options")
                    .cloned()
                    .unwrap_or(Value::Null);
                let allows_free_text = terminal
                    .get("allows_free_text")
                    .cloned()
                    .unwrap_or(Value::Null);
                let manual_approval_required = terminal
                    .get("manual_approval_required")
                    .cloned()
                    .unwrap_or(Value::Null);
                let provider_blocked_for_user = terminal
                    .get("provider_blocked_for_user")
                    .cloned()
                    .unwrap_or(Value::Null);
                let terminal_is_prompting_user = terminal
                    .get("terminal_is_prompting_user")
                    .cloned()
                    .unwrap_or(Value::Null);
                let pane_id = cloud_mcp_payload_text(
                    terminal,
                    &["pane_id", "target_terminal_id"],
                );
                let terminal_id = cloud_mcp_payload_text(
                    terminal,
                    &["terminal_id", "target_terminal_id", "pane_id"],
                );
                let mut normalized = json!({
                    "presence_agent_id": cloud_mcp_payload_text(
                        terminal,
                        &["presence_agent_id", "id"],
                    ),
                    "agent_kind": agent_kind,
                    "agent_label": agent_label,
                    "activity_status": activity_status,
                    "display_name": terminal_nickname.clone(),
                    "display_status": display_status,
                    "status": status,
                    "session_state": session_state,
                    "terminal_name": terminal_nickname.clone(),
                    "terminal_nickname": terminal_nickname,
                    "terminal_index": terminal_index,
                    "terminal_epoch": cloud_mcp_payload_text(terminal, &["terminal_epoch"]),
                    "terminal_instance_id": terminal_instance_id,
                    "terminal_lifecycle": cloud_mcp_payload_text(terminal, &["terminal_lifecycle", "lifecycle"]),
                    "native_rail_state": native_rail_state,
                    "native_rail_label": native_rail_label,
                    "readiness": cloud_mcp_payload_text(terminal, &["readiness", "terminal_readiness"]),
                    "terminal_status": terminal_status,
                    "status_source": status_source,
                    "visible_terminal": visible_terminal,
                    "prompt_id": cloud_mcp_payload_text(terminal, &["prompt_id"]),
                    "prompt_kind": cloud_mcp_payload_text(terminal, &["prompt_kind"]),
                    "prompt_options": prompt_options,
                    "allows_free_text": allows_free_text,
                    "prompt_default_option": cloud_mcp_payload_text(terminal, &["prompt_default_option"]),
                    "prompt_ttl_ms": terminal
                        .get("prompt_ttl_ms")
                        .cloned()
                        .unwrap_or(Value::Null),
                    "manual_approval_required": manual_approval_required,
                    "provider_blocked_for_user": provider_blocked_for_user,
                    "terminal_is_prompting_user": terminal_is_prompting_user,
                    "prompting_user_text": cloud_mcp_payload_text(terminal, &["prompting_user_text"]),
                    "command_phase": cloud_mcp_payload_text(terminal, &["command_phase"]),
                    "execution_phase": cloud_mcp_payload_text(terminal, &["execution_phase"]),
                    "turn_id": cloud_mcp_payload_text(terminal, &["turn_id", "latest_turn_id"]),
                    "turn_status": cloud_mcp_payload_text(terminal, &["turn_status", "latest_turn_status"]),
                    "status_seq": status_seq,
                    "input_ready": input_ready,
                    "parked": terminal
                        .get("parked")
                        .or_else(|| terminal.get("terminal_parked"))
                        .cloned()
                        .unwrap_or(Value::Null),
                    "parked_prompt_title": cloud_mcp_payload_text(
                        terminal,
                        &["parked_prompt_title", "parked_title"],
                    ),
                    "pane_id": pane_id,
                    "terminal_id": terminal_id.clone(),
                    "target_terminal_id": terminal_id,
                    "provider_session_id": provider_session_id.clone(),
                    "native_session_id": provider_session_id.clone(),
                    "session_id": provider_session_id,
                    "color": cloud_mcp_payload_text(terminal, &["color", "accent", "accent_color"]),
                    "dot_color": cloud_mcp_payload_text(terminal, &["dot_color", "color", "accent", "accent_color"]),
                    "color_slot": cloud_mcp_payload_text(terminal, &["color_slot", "color_index", "slot"]),
                    "last_known_runtime": terminal
                        .get("last_known_runtime")
                        .cloned()
                        .unwrap_or(Value::Null),
                    "runtime_read_only": terminal
                        .get("runtime_read_only")
                        .cloned()
                        .unwrap_or(Value::Null),
                    "commandable": terminal
                        .get("commandable")
                        .cloned()
                        .unwrap_or(Value::Null),
                    "connected": terminal
                        .get("connected")
                        .cloned()
                        .unwrap_or(Value::Null),
                    "native_connected": terminal
                        .get("native_connected")
                        .cloned()
                        .unwrap_or(Value::Null),
                    "waiting_on": terminal
                        .get("waiting_on")
                        .cloned()
                        .unwrap_or(Value::Null)});
                cloud_mcp_remove_unauthored_terminal_prompt_fields(terminal, &mut normalized);
                if let (Some(normalized), Some(authored)) =
                    (normalized.as_object_mut(), terminal.as_object())
                {
                    for (key, value) in authored {
                        normalized.insert(key.clone(), value.clone());
                    }
                }
                cloud_mcp_enforce_terminal_prompt_status_projection(&mut normalized);
                Some(normalized)
            })
            .collect::<Vec<_>>();
        let mut terminals = terminals;
        let requested_terminal_clear_reason =
            cloud_mcp_payload_text(workspace, &["terminal_clear_reason"]).unwrap_or_default();
        let terminal_empty_clear_explicit =
            cloud_mcp_workspace_inactive_terminal_empty_clear_is_explicit(
                workspace,
                &reason,
                &requested_terminal_clear_reason,
                workspace_active,
            );
        let mut terminal_list_last_known_fallback = false;
        if terminals.is_empty() && !terminal_empty_clear_explicit {
            if let Some(cached) = cached_last_known_terminals.get(&workspace_id) {
                terminals = cached
                    .iter()
                    .cloned()
                    .map(|mut terminal| {
                        cloud_mcp_mark_terminal_last_known_read_only(&mut terminal);
                        terminal
                    })
                    .collect();
                terminal_list_last_known_fallback = true;
            }
        }
        let panels = cloud_mcp_workspace_panel_items(workspace)
            .iter()
            .enumerate()
            .filter_map(|(index, panel)| {
                if !panel.is_object() {
                    return None;
                }
                let panel_kind = cloud_mcp_workspace_panel_kind(panel)?;
                if !cloud_mcp_workspace_panel_is_current(panel, workspace, workspace_active) {
                    return None;
                }
                let panel_last_known = cloud_mcp_workspace_panel_is_last_known(panel);
                let slot_index = panel
                    .get("slot_index")
                    .or_else(|| panel.get("terminal_index"))
                    .or_else(|| panel.get("index"))
                    .and_then(Value::as_i64)
                    .unwrap_or(index as i64)
                    .clamp(0, 255);
                let slot_index_value = if panel_kind == "docs" {
                    Value::Null
                } else {
                    json!(slot_index)
                };
                let display_name = cloud_mcp_payload_text(
                    panel,
                    &["display_name", "panel_name", "title", "label", "name"],
                )
                .unwrap_or_else(|| match panel_kind.as_str() {
                    "docs" => "Docs".to_string(),
                    "pcb" => "PCB".to_string(),
                    "vm" => "VM Sandbox".to_string(),
                    "video" => "Video editor".to_string(),
                    "swarm" => "Swarm agents".to_string(),
                    "web" => "Web".to_string(),
                    _ => "Web".to_string(),
                });
                let panel_id = cloud_mcp_payload_text(
                    panel,
                    &["panel_id", "target_panel_id", "pane_id", "id"],
                )
                .unwrap_or_else(|| {
                    if panel_kind == "docs" {
                        "workspace-document-panel".to_string()
                    } else {
                        format!(
                            "workspace-panel-{}-{}-{}",
                            workspace_id, panel_kind, slot_index
                        )
                    }
                });
                let status = cloud_mcp_payload_text(panel, &["status", "state", "lifecycle"])
                    .unwrap_or_else(|| {
                        if workspace_active {
                            "open".to_string()
                        } else {
                            "closed".to_string()
                        }
                    });
                Some(json!({
                    "active": panel
                        .get("active")
                        .cloned()
                        .map(|value| if panel_last_known { json!(false) } else { value })
                        .unwrap_or_else(|| json!(workspace_active && !panel_last_known)),
                    "commandable": panel
                        .get("commandable")
                        .cloned()
                        .unwrap_or_else(|| workspace
                            .get("commandable")
                            .cloned()
                            .unwrap_or(Value::Null)),
                    "connected": panel
                        .get("connected")
                        .cloned()
                        .map(|value| if panel_last_known { json!(false) } else { value })
                        .unwrap_or_else(|| json!(workspace_active && !panel_last_known)),
                    "display_name": display_name.clone(),
                    "kind": panel_kind.clone(),
                    "lifecycle": status.clone(),
                    "native_connected": panel
                        .get("native_connected")
                        .cloned()
                        .map(|value| if panel_last_known { json!(false) } else { value })
                        .unwrap_or_else(|| json!(workspace_active && !panel_last_known)),
                    "pane_id": panel_id.clone(),
                    "pane_kind": panel_kind.clone(),
                    "panel_id": panel_id.clone(),
                    "panel_kind": panel_kind.clone(),
                    "panel_name": display_name,
                    "panel_type": panel_kind.clone(),
                    "slot_index": slot_index_value.clone(),
                    "status": status,
                    "surface_kind": panel_kind.clone(),
                    "target_panel_id": panel_id,
                    "terminal_index": slot_index_value,
                    "terminal_kind": "workspace_panel"}))
            })
            .collect::<Vec<_>>();
        let mut panels = panels;
        let requested_panel_clear_reason =
            cloud_mcp_payload_text(workspace, &["panel_clear_reason"]).unwrap_or_default();
        let panel_empty_clear_explicit = cloud_mcp_workspace_panel_empty_clear_is_explicit(
            workspace,
            &reason,
            &requested_panel_clear_reason,
            workspace_active,
        );
        let mut panel_list_last_known_fallback = false;
        if panels.is_empty() && !panel_empty_clear_explicit {
            if let Some(cached) = cached_last_known_panels.get(&workspace_id) {
                panels = cached
                    .iter()
                    .cloned()
                    .map(|mut panel| {
                        cloud_mcp_mark_panel_last_known_read_only(&mut panel);
                        panel
                    })
                    .collect();
                panel_list_last_known_fallback = true;
            }
        }

        let (workspace_runtime_seq, workspace_runtime_epoch) =
            cloud_mcp_workspace_runtime_ordering(state, workspace);
        let pcb_projects = cloud_mcp_workspace_project_rows(workspace, &["pcb_projects"]);
        let video_projects = cloud_mcp_workspace_project_rows(workspace, &["video_projects"]);
        let pcb_active_project_id =
            cloud_mcp_workspace_project_active_id(workspace, &["pcb_active_project_id"]);
        let video_active_project_id =
            cloud_mcp_workspace_project_active_id(workspace, &["video_active_project_id"]);
        let servers = cloud_mcp_normalize_workspace_mcp_servers_for_snapshot(workspace);
        let workspace_order = cloud_mcp_payload_u64(
            workspace,
            &["workspace_order", "workspace_index", "sort_order", "order"],
        )
        .unwrap_or(workspace_index as u64);
        let terminal_list_authoritative = !terminal_list_last_known_fallback
            && (!terminals.is_empty() || terminal_empty_clear_explicit);
        let terminal_list_empty_authoritative =
            terminals.is_empty() && terminal_empty_clear_explicit;
        let panel_list_authoritative =
            !panel_list_last_known_fallback && (!panels.is_empty() || panel_empty_clear_explicit);
        let panel_list_empty_authoritative = panels.is_empty() && panel_empty_clear_explicit;
        let panel_clear_reason = if panels.is_empty() {
            if panel_empty_clear_explicit {
                if requested_panel_clear_reason.trim().is_empty() {
                    reason.clone()
                } else {
                    requested_panel_clear_reason
                }
            } else if workspace_active {
                "transient_empty_panel_snapshot".to_string()
            } else {
                "workspace_inactive".to_string()
            }
        } else {
            requested_panel_clear_reason
        };
        let terminal_clear_reason = if terminals.is_empty() {
            if terminal_empty_clear_explicit {
                if requested_terminal_clear_reason.trim().is_empty() {
                    reason.clone()
                } else {
                    requested_terminal_clear_reason
                }
            } else if workspace_active {
                "transient_empty_terminal_snapshot".to_string()
            } else {
                "workspace_inactive".to_string()
            }
        } else {
            requested_terminal_clear_reason
        };
        let mut workspace_value = json!({
            "device_id": device_profile["device_id"].clone(),
            "workspace_active": workspace_active,
            "workspace_id": workspace_id,
            "workspace_name": workspace_name,
            "repo_path": workspace_root.clone(),
            "workspace_root": workspace_root.clone(),
            "selected": workspace_selected,
            "workspace_selected": workspace_selected,
            "workspace_status": workspace_status,
            "workspace_runtime_seq": workspace_runtime_seq,
            "workspace_runtime_epoch": workspace_runtime_epoch,
            "workspace_order": workspace_order,
            "terminal_clear_reason": terminal_clear_reason,
            "terminal_list_empty_authoritative": terminal_list_empty_authoritative,
            "terminal_list_authoritative": terminal_list_authoritative,
            "last_known_terminal_fallback": terminal_list_last_known_fallback,
            "last_known_runtime": workspace
                .get("last_known_runtime")
                .cloned()
                .unwrap_or(Value::Null),
            "runtime_read_only": workspace
                .get("runtime_read_only")
                .cloned()
                .unwrap_or(Value::Null),
            "commandable": workspace
                .get("commandable")
                .cloned()
                .unwrap_or(Value::Null),
            "panel_count": panels.len(),
            "panel_clear_reason": panel_clear_reason,
            "panel_list_empty_authoritative": panel_list_empty_authoritative,
            "panel_list_authoritative": panel_list_authoritative,
            "last_known_panel_fallback": panel_list_last_known_fallback,
            "panels": panels,
            "pcb_projects": pcb_projects,
            "pcb_active_project_id": pcb_active_project_id,
            "video_projects": video_projects,
            "video_active_project_id": video_active_project_id,
            "servers": servers.clone(),
            "mcps": servers,
            "terminals": terminals,
        });
        if !workspace_root.trim().is_empty() {
            if let Some(object) = workspace_value.as_object_mut() {
                object.insert("workspace_root".to_string(), json!(workspace_root.clone()));
            }
        }
        normalized_workspaces.push(workspace_value);
        if let Some(app) = CLOUD_MCP_SYNC_STATUS_APP.get().cloned() {
            if !workspace_root.trim().is_empty() {
                agent_chat_session_sync_backfill_workspace_history(
                    app,
                    workspace_id.clone(),
                    Some(workspace_root.clone()),
                    "device_workspaces_snapshot_history_backfill",
                );
            }
        }
    }
    // Missing workspaces are never synthesized from runtime snapshots. The durable
    // local catalog above is the complete set; cached rows are consulted only for
    // per-workspace terminal/panel details and can therefore never resurrect a
    // workspace that the local catalog deleted.
    let workspace_snapshot_fallback_count = 0usize;
    let terminal_count = normalized_workspaces
        .iter()
        .map(|workspace| {
            workspace
                .get("terminals")
                .and_then(Value::as_array)
                .map(Vec::len)
                .unwrap_or_default()
        })
        .sum::<usize>();
    let panel_count = normalized_workspaces
        .iter()
        .map(|workspace| {
            workspace
                .get("panels")
                .and_then(Value::as_array)
                .map(Vec::len)
                .unwrap_or_default()
        })
        .sum::<usize>();
    let terminal_orchestrator_count = normalized_terminal_orchestrators.len();
    cloud_mcp_renumber_device_terminal_orchestrators(&mut normalized_terminal_orchestrators);

    let workspace_count = normalized_workspaces.len();
    let server_count = normalized_workspaces
        .iter()
        .map(|workspace| {
            workspace
                .get("servers")
                .and_then(Value::as_array)
                .map(Vec::len)
                .unwrap_or_default()
        })
        .sum::<usize>();
    let selected_workspace = selected_workspace_id
        .as_ref()
        .map(|workspace_id| {
            json!({
                "workspace_id": workspace_id,
                "workspace_name": selected_workspace_name.as_deref().unwrap_or(workspace_id),
            })
        })
        .unwrap_or(Value::Null);

    let provider_accounts = cloud_mcp_provider_accounts_live_state().await;
    let mut payload = json!({
        "source": "rust-diffforge-device-workspaces",
        "contract": "diffforge.device_workspaces.v1",
        "event_kind": "device_workspaces_snapshot",
        "sync_unit": "device_workspaces_snapshot",
        "client_id": CLOUD_MCP_RUST_CLIENT_ID,
        "device_id": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "platform": device_profile["platform"].clone(),
        "form_factor": device_profile["form_factor"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "app_update": app_update_device_payload(),
        "agent_id": "rust-diffforge",
        "agent_label": "Diff Forge Desktop",
        "reason": reason,
        "workspace_catalog_ready": true,
        "snapshot_full": true,
        "workspace_snapshot_complete": true,
        "workspace_catalog_complete": true,
        "workspace_snapshot_authoritative": true,
        "workspace_snapshot_input_count": input_workspace_count,
        "workspace_snapshot_fallback_count": workspace_snapshot_fallback_count,
        "workspace_count": workspace_count,
        "skipped_archived_workspace_count": skipped_archived_count,
        "terminal_count": terminal_count,
        "panel_count": panel_count,
        "terminal_orchestrator_count": terminal_orchestrator_count,
        "terminal_orchestrators": normalized_terminal_orchestrators,
        "provider_accounts": provider_accounts,
        "server_count": server_count,
        "selected_workspace_id": selected_workspace_id,
        "selected_workspace": selected_workspace,
        "workspaces": normalized_workspaces,
        "summary": "Desktop workspace and terminal state synced from the complete durable local workspace catalog.",
        "ts_ms": cloud_mcp_now_ms()});
    if workspace_count == 0 {
        payload["workspace_set_empty_authoritative"] = json!(true);
        payload["workspace_clear_reason"] = json!("complete_local_catalog_empty");
    }
    let payload = cloud_mcp_device_live_payload_with_sync_identity(payload);

    {
        let mut snapshots = state.runtime_snapshots.lock().await;
        snapshots.workspace_terminals = Some(payload.clone());
        snapshots.workspace_catalog = Some(payload.clone());
    }

    let mut sent = false;
    let mut queued = false;
    let mut skipped_reason = Value::Null;
    let mut cloud_event_id = Value::Null;
    let lifecycle_fast_lane = cloud_mcp_device_live_snapshot_lifecycle_fast_lane(&reason_for_ack);
    match if lifecycle_fast_lane {
        CloudMcpDeviceLiveSyncDecision::Enqueue
    } else {
        cloud_mcp_device_live_sync_decision(&payload)?
    } {
        CloudMcpDeviceLiveSyncDecision::CurrentAcked => {
            skipped_reason = json!("sync_unit_current");
        }
        CloudMcpDeviceLiveSyncDecision::CurrentPending => {
            queued = true;
            skipped_reason = json!("sync_unit_pending");
        }
        CloudMcpDeviceLiveSyncDecision::Enqueue => {
            cloud_mcp_device_live_mark_sync_pending(&payload)?;
            match cloud_mcp_send_event_over_app_ws_once(
                state,
                "device_workspaces_snapshot",
                &payload,
                "device-workspaces",
            )
            .await
            {
                Ok(response) => {
                    let _ = cloud_mcp_device_live_mark_sync_acked_from_payload(
                        Some(&payload),
                        &response,
                    );
                    cloud_event_id = Value::String(cloud_mcp_outbox_cloud_event_id(&response));
                    sent = true;
                }
                Err(error) => {
                    queued = true;
                    let fallback = if let Some(rebuild_reason) =
                        cloud_mcp_authoritative_workspace_snapshot_rebuild_reason(&error)
                    {
                        skipped_reason = json!(rebuild_reason);
                        cloud_mcp_publish_device_live_state_snapshot_debounced(
                            state,
                            "workspace_catalog_changed_during_workspace_send",
                        )
                        .await;
                        "catalog_rebuild"
                    } else {
                        cloud_mcp_enqueue_background_sync(
                            state,
                            "device_workspaces_snapshot".to_string(),
                            "device_workspaces_snapshot",
                            payload.clone(),
                            CLOUD_MCP_BACKGROUND_SYNC_PRIORITY_HIGH,
                            reason_for_ack.clone(),
                        )
                        .await;
                        "durable_outbox"
                    };
                    log_terminal_status_event(
                        "backend.cloud_mcp.device_workspaces.ws.queued",
                        json!({
                            "reason": reason_for_ack,
                            "error": clean_terminal_telemetry_text(&error),
                            "fallback": fallback,
                        }),
                    );
                }
            }
        }
    }

    let sync_key = "device_workspaces_snapshot".to_string();
    Ok(cloud_mcp_background_sync_ack(
        "device_workspaces_snapshot",
        &sync_key,
        &reason_for_ack,
        json!({
            "cloud_event_id": cloud_event_id,
            "queued": queued,
            "sent": sent,
            "skipped": !skipped_reason.is_null(),
            "skip_reason": skipped_reason,
            "stored": {
                "stored_count": workspace_count,
                "input_workspace_count": input_workspace_count,
                "workspace_snapshot_fallback_count": workspace_snapshot_fallback_count,
                "skipped_archived_workspace_count": skipped_archived_count,
                "server_count": server_count,
                "terminal_count": terminal_count,
                "terminal_orchestrator_count": terminal_orchestrator_count,
                "workspace_count": workspace_count,
            },
            "stored_count": workspace_count,
            "input_workspace_count": input_workspace_count,
            "workspace_snapshot_fallback_count": workspace_snapshot_fallback_count,
            "server_count": server_count,
            "terminal_count": terminal_count,
            "terminal_orchestrator_count": terminal_orchestrator_count,
            "workspace_count": workspace_count,
        }),
    ))
}

fn cloud_mcp_lifecycle_status_key(value: &str) -> String {
    value.trim().to_ascii_lowercase().replace([' ', '-'], "_")
}

fn cloud_mcp_terminal_lifecycle_value_is_awaiting_input(value: &str) -> bool {
    matches!(
        cloud_mcp_lifecycle_status_key(value).as_str(),
        "awaiting_input"
            | "awaiting_user"
            | "needs_input"
            | "prompting_user"
            | "requires_input"
            | "requires_user_input"
            | "provider_user_prompt_started"
    )
}

fn cloud_mcp_terminal_lifecycle_has_open_prompt(
    terminal_is_prompting_user: Option<bool>,
    prompt_id: Option<&str>,
    prompt_signals: &[&str],
) -> bool {
    let has_prompt_id = prompt_id
        .map(str::trim)
        .is_some_and(|value| !value.is_empty());
    let has_prompt_signal = prompt_signals
        .iter()
        .any(|value| cloud_mcp_terminal_lifecycle_value_is_awaiting_input(value));

    match terminal_is_prompting_user {
        Some(true) => has_prompt_id || has_prompt_signal,
        Some(false) => false,
        None => has_prompt_signal,
    }
}

fn cloud_mcp_terminal_lifecycle_state(
    event_type: &str,
    status: &str,
    activity_status: &str,
    readiness: &str,
    command_phase: &str,
    execution_phase: &str,
    turn_status: &str,
    terminal_is_prompting_user: Option<bool>,
    prompt_id: Option<&str>,
) -> &'static str {
    let event_type = cloud_mcp_lifecycle_status_key(event_type);
    let status = cloud_mcp_lifecycle_status_key(status);
    let activity_status = cloud_mcp_lifecycle_status_key(activity_status);
    let readiness = cloud_mcp_lifecycle_status_key(readiness);
    let command_phase = cloud_mcp_lifecycle_status_key(command_phase);
    let execution_phase = cloud_mcp_lifecycle_status_key(execution_phase);
    let turn_status = cloud_mcp_lifecycle_status_key(turn_status);
    let values = [
        event_type.as_str(),
        status.as_str(),
        activity_status.as_str(),
        readiness.as_str(),
        command_phase.as_str(),
        execution_phase.as_str(),
        turn_status.as_str(),
    ];

    if values
        .iter()
        .any(|value| matches!(*value, "closed" | "closing" | "exited" | "offline"))
    {
        return "closed";
    }
    if values
        .iter()
        .any(|value| matches!(*value, "error" | "failed" | "failure"))
    {
        return "error";
    }
    if cloud_mcp_terminal_lifecycle_has_open_prompt(terminal_is_prompting_user, prompt_id, &values)
    {
        return "awaiting_input";
    }
    if values
        .iter()
        .any(|value| matches!(*value, "paused" | "parked" | "resume_ready"))
    {
        return "paused";
    }
    if event_type == "provider_turn_interrupted"
        || values.iter().any(|value| {
            matches!(
                *value,
                "interrupted" | "interrupt" | "cancelled" | "canceled"
            )
        })
    {
        return "interrupted";
    }
    if values.iter().any(|value| {
        matches!(
            *value,
            "compacting" | "compaction" | "provider_turn_compacting" | "context_compaction_started"
        )
    }) {
        return "compacting";
    }
    if event_type == "provider_turn_completed"
        || matches!(turn_status.as_str(), "complete" | "completed" | "done")
    {
        return "idle";
    }
    if values.iter().any(|value| {
        matches!(
            *value,
            "active"
                | "busy"
                | "compacting"
                | "compaction"
                | "delegating"
                | "dispatched"
                | "editing"
                | "implementing"
                | "pending"
                | "queued"
                | "reasoning"
                | "resume_requested"
                | "resumed"
                | "running"
                | "submitted"
                | "thinking"
                | "tool_running"
                | "working"
        )
    }) {
        return "thinking";
    }
    if values.iter().any(|value| {
        matches!(
            *value,
            "complete"
                | "completed"
                | "done"
                | "idle"
                | "input_ready"
                | "interrupted"
                | "interrupt"
                | "cancelled"
                | "canceled"
                | "ready"
                | "provider_turn_completed"
                | "provider_turn_interrupted"
        )
    }) {
        return "idle";
    }

    "thinking"
}

fn cloud_mcp_terminal_value_projected_status(terminal: &Value, fallback_status: &str) -> String {
    let status = cloud_mcp_payload_text(terminal, &["status", "state"])
        .unwrap_or_else(|| fallback_status.to_string());
    let activity_status =
        cloud_mcp_payload_text(terminal, &["activity_status"]).unwrap_or_default();
    let readiness =
        cloud_mcp_payload_text(terminal, &["readiness", "terminal_readiness"]).unwrap_or_default();
    let command_phase = cloud_mcp_payload_text(terminal, &["command_phase"]).unwrap_or_default();
    let execution_phase =
        cloud_mcp_payload_text(terminal, &["execution_phase"]).unwrap_or_default();
    let turn_status = cloud_mcp_payload_text(terminal, &["turn_status", "latest_turn_status"])
        .unwrap_or_default();
    let event_type =
        cloud_mcp_payload_text(terminal, &["event_type", "hook_event_name"]).unwrap_or_default();
    let terminal_is_prompting_user = terminal
        .get("terminal_is_prompting_user")
        .and_then(Value::as_bool);
    let prompt_id = cloud_mcp_payload_text(terminal, &["prompt_id"]);
    if cloud_mcp_terminal_lifecycle_state(
        &event_type,
        &status,
        &activity_status,
        &readiness,
        &command_phase,
        &execution_phase,
        &turn_status,
        terminal_is_prompting_user,
        prompt_id.as_deref(),
    ) == "awaiting_input"
    {
        "awaiting_input".to_string()
    } else {
        status
    }
}

fn cloud_mcp_enforce_terminal_prompt_status_projection(terminal: &mut Value) {
    let status = cloud_mcp_terminal_value_projected_status(terminal, "");
    if status != "awaiting_input" {
        return;
    }
    if let Some(object) = terminal.as_object_mut() {
        object.insert("status".to_string(), json!("awaiting_input"));
    }
}

fn cloud_mcp_terminal_lifecycle_turn_status(
    event_type: &str,
    turn_status: &str,
    state: &str,
) -> &'static str {
    let event_type = cloud_mcp_lifecycle_status_key(event_type);
    let turn_status = cloud_mcp_lifecycle_status_key(turn_status);
    match turn_status.as_str() {
        "complete" | "completed" | "done" => "completed",
        "cancelled" | "canceled" => "cancelled",
        "interrupted" | "interrupt" => "interrupted",
        "failed" | "error" => "failed",
        "queued" | "submitted" | "pending" => "queued",
        "compacting" | "compaction" | "running" | "thinking" | "working" | "reasoning" => "running",
        _ => match event_type.as_str() {
            "provider_turn_completed" => "completed",
            "provider_turn_compacting" | "context_compaction_started" => "running",
            "provider_turn_error" => "failed",
            "provider_turn_interrupted" => "interrupted",
            "remote_control_close" | "closed" | "exited" => "interrupted",
            _ => match state {
                "idle" => "completed",
                "error" => "failed",
                "closed" => "interrupted",
                _ => "running",
            },
        },
    }
}

fn cloud_mcp_next_terminal_lifecycle_seq(state: &CloudMcpState, candidate: Option<u64>) -> u64 {
    let now = cloud_mcp_now_ms();
    let candidate = candidate.unwrap_or(0).max(now);
    let mut previous = state.terminal_lifecycle_seq.load(Ordering::SeqCst);
    loop {
        let next = previous.saturating_add(1).max(candidate);
        match state.terminal_lifecycle_seq.compare_exchange(
            previous,
            next,
            Ordering::SeqCst,
            Ordering::SeqCst,
        ) {
            Ok(_) => return next,
            Err(current) => previous = current,
        }
    }
}

fn cloud_mcp_next_workspace_runtime_seq(state: &CloudMcpState, candidate: Option<u64>) -> u64 {
    let now = cloud_mcp_now_ms();
    let candidate = candidate.unwrap_or(0).max(now);
    let mut previous = state.workspace_runtime_seq.load(Ordering::SeqCst);
    loop {
        let next = previous.saturating_add(1).max(candidate);
        match state.workspace_runtime_seq.compare_exchange(
            previous,
            next,
            Ordering::SeqCst,
            Ordering::SeqCst,
        ) {
            Ok(_) => return next,
            Err(current) => previous = current,
        }
    }
}

fn cloud_mcp_workspace_runtime_epoch(state: &CloudMcpState) -> String {
    let epoch = state.global_ws_epoch.load(Ordering::SeqCst).max(1);
    format!("workspace-runtime-{epoch}")
}

fn cloud_mcp_workspace_runtime_ordering(state: &CloudMcpState, workspace: &Value) -> (u64, String) {
    let seq = cloud_mcp_next_workspace_runtime_seq(
        state,
        cloud_mcp_payload_u64(workspace, &["workspace_runtime_seq", "runtime_seq"]),
    );
    let epoch = cloud_mcp_payload_text(workspace, &["workspace_runtime_epoch", "runtime_epoch"])
        .unwrap_or_else(|| cloud_mcp_workspace_runtime_epoch(state));
    (seq, epoch)
}

fn cloud_mcp_copy_workspace_runtime_ordering(target: &mut Value, source: &Value) {
    let seq = source
        .get("workspace_runtime_seq")
        .or_else(|| source.get("runtime_seq"))
        .cloned()
        .unwrap_or(Value::Null);
    let epoch = source
        .get("workspace_runtime_epoch")
        .or_else(|| source.get("runtime_epoch"))
        .cloned()
        .unwrap_or(Value::Null);
    let order = source
        .get("workspace_order")
        .or_else(|| source.get("workspace_index"))
        .or_else(|| source.get("sort_order"))
        .or_else(|| source.get("order"))
        .cloned()
        .unwrap_or(Value::Null);
    let Some(object) = target.as_object_mut() else {
        return;
    };
    object.insert("workspace_runtime_seq".to_string(), seq);
    object.insert("workspace_runtime_epoch".to_string(), epoch);
    object.insert("workspace_order".to_string(), order.clone());
    object.insert("workspace_index".to_string(), order);
}

async fn cloud_mcp_apply_terminal_state_to_device_live_snapshot(
    state: &CloudMcpState,
    payload: &Value,
    reason: &str,
) {
    let payload_is_runtime_shutdown =
        cloud_mcp_terminal_state_is_workspace_runtime_shutdown(payload);
    let workspace_id = cloud_mcp_payload_text(&payload, &["workspace_id"])
        .unwrap_or_else(|| "workspace".to_string());
    let repo_id = cloud_mcp_payload_text(payload, &["repo_id"]);
    let workspace_root = cloud_mcp_payload_text(payload, &["workspace_root"]);
    let workspace_name = cloud_mcp_payload_text(payload, &["workspace_name"]);
    let terminal_id =
        cloud_mcp_payload_text(payload, &["terminal_id", "pane_id", "target_terminal_id"])
            .unwrap_or_else(|| "terminal".to_string());
    let terminal_instance_id =
        cloud_mcp_payload_u64(payload, &["terminal_instance_id", "instance_id"])
            .unwrap_or_default();
    let observed_at_ms =
        cloud_mcp_payload_u64(payload, &["observed_at_ms"]).unwrap_or_else(cloud_mcp_now_ms);
    let device_profile = cloud_mcp_desktop_device_profile();

    let mut snapshots = state.runtime_snapshots.lock().await;
    if snapshots.workspace_terminals.is_none() {
        // A late close cannot close anything if no live snapshot exists. Do
        // not materialize a phantom workspace/terminal solely to carry the
        // stale tombstone.
        if payload_is_runtime_shutdown {
            return;
        }
        snapshots.workspace_terminals = Some(json!({
            "source": "rust-diffforge-device-live-terminals",
            "event_kind": "device_live_state_snapshot",
            "device": device_profile.clone(),
            "device_id": device_profile["device_id"].clone(),
            "device_name": device_profile["device_name"].clone(),
            "machine_id": device_profile["device_id"].clone(),
            "machine_name": device_profile["machine_name"].clone(),
            "platform": device_profile["platform"].clone(),
            "form_factor": device_profile["form_factor"].clone(),
            "client_kind": device_profile["client_kind"].clone(),
            "agent_id": "rust-diffforge",
            "agent_label": "Diff Forge Desktop",
            "reason": reason,
            "workspace_count": 0,
            "terminal_count": 0,
            "terminal_orchestrator_count": 0,
            "terminal_orchestrators": [],
            "workspaces": [],
            "summary": "Desktop workspace terminals synced.",
            "ts_ms": observed_at_ms,
        }));
    }
    let Some(snapshot) = snapshots.workspace_terminals.as_mut() else {
        return;
    };
    if cloud_mcp_terminal_value_is_device_orchestrator(payload) {
        cloud_mcp_upsert_device_terminal_orchestrator(snapshot, payload, observed_at_ms);
        if let Some(object) = snapshot.as_object_mut() {
            object.insert("reason".to_string(), json!(reason));
            object.insert(
                "summary".to_string(),
                json!("Desktop terminal orchestrator state synced."),
            );
        }
        return;
    }
    if !snapshot
        .get("workspaces")
        .and_then(Value::as_array)
        .is_some()
    {
        if let Some(object) = snapshot.as_object_mut() {
            object.insert("workspaces".to_string(), json!([]));
        }
    }
    let (workspace_count, total_terminal_count) = {
        let Some(workspaces) = snapshot.get_mut("workspaces").and_then(Value::as_array_mut) else {
            return;
        };
        let workspace_index = workspaces.iter().position(|workspace| {
            cloud_mcp_payload_text(workspace, &["workspace_id", "id"])
                .is_some_and(|value| value == workspace_id)
                || workspace_root.as_ref().is_some_and(|root| {
                    cloud_mcp_payload_text(workspace, &["workspace_root"])
                        .is_some_and(|value| value == *root)
                })
        });
        let workspace_index = match workspace_index {
            Some(index) => index,
            None => {
                if payload_is_runtime_shutdown {
                    return;
                }
                let mut workspace_value = json!({
                    "repo_id": repo_id.clone(),
                    "workspace_id": workspace_id.clone(),
                    "workspace_name": workspace_name.clone(),
                    "workspace_active": true,
                    "workspace_status": "active",
                    "terminal_count": 0,
                    "active_count": 0,
                    "terminals": [],
                });
                if let Some(workspace_root) = workspace_root.as_deref() {
                    if let Some(object) = workspace_value.as_object_mut() {
                        object.insert("workspace_root".to_string(), json!(workspace_root));
                    }
                }
                workspaces.push(workspace_value);
                workspaces.len().saturating_sub(1)
            }
        };
        let Some(workspace) = workspaces.get_mut(workspace_index) else {
            return;
        };
        if let Some(object) = workspace.as_object_mut() {
            if !payload_is_runtime_shutdown {
                object.insert("workspace_active".to_string(), json!(true));
                object.insert("workspace_status".to_string(), json!("active"));
            }
            if let Some(workspace_root) = workspace_root.as_deref() {
                object.insert("workspace_root".to_string(), json!(workspace_root));
            }
            object.insert("reason".to_string(), json!(reason));
            object.insert("ts_ms".to_string(), json!(observed_at_ms));
            object
                .entry("terminals".to_string())
                .or_insert_with(|| json!([]));
        }
        if !workspace
            .get("terminals")
            .and_then(Value::as_array)
            .is_some()
        {
            if let Some(object) = workspace.as_object_mut() {
                object.insert("terminals".to_string(), json!([]));
            }
        }
        let Some(terminals) = workspace.get_mut("terminals").and_then(Value::as_array_mut) else {
            return;
        };
        let mut terminal_value = payload.clone();
        if let Some(object) = terminal_value.as_object_mut() {
            object.insert("terminal_id".to_string(), json!(terminal_id.clone()));
            object.insert(
                "terminal_instance_id".to_string(),
                json!(terminal_instance_id),
            );
            object.insert("observed_at_ms".to_string(), json!(observed_at_ms));
        }
        cloud_mcp_enforce_terminal_prompt_status_projection(&mut terminal_value);
        let workspace_runtime_shutdown =
            cloud_mcp_terminal_state_is_workspace_runtime_shutdown(&terminal_value);
        if workspace_runtime_shutdown {
            cloud_mcp_mark_terminal_last_known_read_only(&mut terminal_value);
            cloud_mcp_clear_terminal_prompt_state(
                &mut terminal_value,
                None,
                reason,
                observed_at_ms,
            );
        }
        let terminal_removes_from_snapshot = !workspace_runtime_shutdown
            && cloud_mcp_terminal_state_removes_from_live_snapshot(&terminal_value);
        let existing_index = terminals.iter().position(|terminal| {
            if workspace_runtime_shutdown && terminal_instance_id > 0 {
                cloud_mcp_presence_terminal_matches_instance_for_close(
                    terminal,
                    &terminal_id,
                    terminal_instance_id,
                )
            } else {
                cloud_mcp_presence_terminal_matches_instance(
                    terminal,
                    &terminal_id,
                    terminal_instance_id,
                )
            }
        });
        if terminal_removes_from_snapshot {
            terminals.retain(|terminal| {
                !cloud_mcp_presence_terminal_matches_instance(
                    terminal,
                    &terminal_id,
                    terminal_instance_id,
                )
            });
        } else if let Some(existing_index) = existing_index {
            if let Some(existing) = terminals.get_mut(existing_index) {
                cloud_mcp_live_state_merge_object(existing, terminal_value);
            }
        } else if !workspace_runtime_shutdown {
            terminals.push(terminal_value);
        }
        let terminal_count = terminals.len();
        let active_count = terminals
            .iter()
            .filter(|terminal| {
                let status = cloud_mcp_payload_text(
                    terminal,
                    &[
                        "status",
                        "state",
                        "activity_status",
                        "terminal_lifecycle",
                        "session_state",
                    ],
                )
                .unwrap_or_default()
                .trim()
                .to_ascii_lowercase();
                !matches!(
                    status.as_str(),
                    "closed"
                        | "deleted"
                        | "removed"
                        | "exited"
                        | "terminated"
                        | "no_session"
                        | "offline"
                        | "deactivated"
                        | "disabled"
                )
            })
            .count();
        if let Some(object) = workspace.as_object_mut() {
            object.insert("terminal_count".to_string(), json!(terminal_count));
            object.insert("active_count".to_string(), json!(active_count));
        }
        let total_terminal_count = workspaces
            .iter()
            .filter_map(|workspace| workspace.get("terminals").and_then(Value::as_array))
            .map(Vec::len)
            .sum::<usize>();
        (workspaces.len(), total_terminal_count)
    };
    if let Some(object) = snapshot.as_object_mut() {
        object.insert("reason".to_string(), json!(reason));
        object.insert("workspace_count".to_string(), json!(workspace_count));
        object.insert("terminal_count".to_string(), json!(total_terminal_count));
        object.insert("ts_ms".to_string(), json!(observed_at_ms));
    }
}

/// Trailing latest-wins debounce in front of the device live-state snapshot
/// publisher. Every caller's delta is already merged into the snapshot state
/// before this runs, so collapsing a hook storm to one publish per
/// CLOUD_MCP_DEVICE_LIVE_SNAPSHOT_DEBOUNCE_MS window loses nothing: the flush
/// recomputes the snapshot from the latest state. The content dedup decision
/// inside cloud_mcp_publish_device_live_state_snapshot still applies.
async fn cloud_mcp_publish_device_live_state_snapshot_debounced(
    state: &CloudMcpState,
    reason: &str,
) {
    if cloud_mcp_device_live_snapshot_lifecycle_fast_lane(reason) {
        if let Ok(mut pending) = state.device_live_snapshot_debounce.lock() {
            *pending = None;
        }
        cloud_mcp_publish_device_live_state_snapshot(state, reason).await;
        return;
    }

    let mut lock_failed = false;
    let already_scheduled = match state.device_live_snapshot_debounce.lock() {
        Ok(mut pending) => {
            let already_scheduled = pending.is_some();
            *pending = Some(reason.to_string());
            already_scheduled
        }
        Err(_) => {
            lock_failed = true;
            false
        }
    };
    if lock_failed {
        cloud_mcp_publish_device_live_state_snapshot(state, reason).await;
        return;
    }
    if already_scheduled {
        return;
    }
    let state = state.clone();
    tauri::async_runtime::spawn(async move {
        sleep(Duration::from_millis(
            CLOUD_MCP_DEVICE_LIVE_SNAPSHOT_DEBOUNCE_MS,
        ))
        .await;
        let reason = state
            .device_live_snapshot_debounce
            .lock()
            .ok()
            .and_then(|mut pending| pending.take());
        if let Some(reason) = reason {
            cloud_mcp_publish_device_live_state_snapshot(&state, &reason).await;
        }
    });
}

async fn cloud_mcp_publish_terminal_state_live_update(
    state: &CloudMcpState,
    payload: &Value,
    reason: &str,
) {
    cloud_mcp_apply_terminal_state_to_device_live_snapshot(state, payload, reason).await;
    cloud_mcp_publish_device_live_state_snapshot_debounced(state, reason).await;
}

#[derive(Clone)]
struct CloudMcpAgentChatTurnGitSnapshot {
    repo_root: PathBuf,
    start_tree: String,
    started_at: String,
    started_at_ms: u64,
    turn_key: String,
}

struct CloudMcpAgentChatTurnGitDiff {
    file_change: Option<Value>,
    turn_diff: Option<AgentChatTurnDiffContext>,
    raw: Value,
}

#[derive(Clone, Default)]
struct CloudMcpAgentChatTurnGitStatusEntry {
    status: String,
    path: String,
    old_path: Option<String>,
}

#[derive(Clone)]
enum CloudMcpAgentChatTurnGitSnapshotState {
    Pending { started_at_ms: u64 },
    Ready(CloudMcpAgentChatTurnGitSnapshot),
    Failed { started_at_ms: u64 },
}

impl CloudMcpAgentChatTurnGitSnapshotState {
    fn started_at_ms(&self) -> u64 {
        match self {
            Self::Pending { started_at_ms } | Self::Failed { started_at_ms } => *started_at_ms,
            Self::Ready(snapshot) => snapshot.started_at_ms,
        }
    }
}

static CLOUD_MCP_AGENT_CHAT_TURN_GIT_SNAPSHOTS: OnceLock<(
    StdMutex<HashMap<String, CloudMcpAgentChatTurnGitSnapshotState>>,
    std::sync::Condvar,
)> = OnceLock::new();
static CLOUD_MCP_AGENT_CHAT_TURN_GIT_TEMP_INDEX_SEQ: AtomicU64 = AtomicU64::new(1);
const CLOUD_MCP_AGENT_CHAT_TURN_GIT_SNAPSHOT_MAX: usize = 512;
const CLOUD_MCP_AGENT_CHAT_TURN_GIT_SNAPSHOT_TTL_MS: u64 = 6 * 60 * 60 * 1000;
const CLOUD_MCP_AGENT_CHAT_TURN_DIFF_PATCH_MAX_CHARS: usize = 48_000;
const CLOUD_MCP_AGENT_CHAT_TURN_DIFF_MESSAGES_MAX_BYTES: usize = 384 * 1024;
const CLOUD_MCP_AGENT_CHAT_TURN_DIFF_MESSAGES_CAP_HEADROOM_BYTES: usize = 4 * 1024;
const CLOUD_MCP_AGENT_CHAT_TURN_DIFF_PATCH_TIMEOUT_MS: u64 = 3_000;

fn cloud_mcp_agent_chat_turn_git_snapshots() -> &'static (
    StdMutex<HashMap<String, CloudMcpAgentChatTurnGitSnapshotState>>,
    std::sync::Condvar,
) {
    CLOUD_MCP_AGENT_CHAT_TURN_GIT_SNAPSHOTS
        .get_or_init(|| (StdMutex::new(HashMap::new()), std::sync::Condvar::new()))
}

fn cloud_mcp_agent_chat_turn_iso_from_ms(ms: u64) -> String {
    let secs = (ms / 1000) as i64;
    let millis = ms % 1000;
    let days = secs.div_euclid(86_400);
    let secs_of_day = secs.rem_euclid(86_400);
    let z = days + 719_468;
    let era = if z >= 0 { z } else { z - 146_096 } / 146_097;
    let doe = z - era * 146_097;
    let yoe = (doe - doe / 1_460 + doe / 36_524 - doe / 146_096) / 365;
    let year = yoe + era * 400;
    let doy = doe - (365 * yoe + yoe / 4 - yoe / 100);
    let mp = (5 * doy + 2) / 153;
    let day = doy - (153 * mp + 2) / 5 + 1;
    let month = if mp < 10 { mp + 3 } else { mp - 9 };
    let year = if month <= 2 { year + 1 } else { year };
    format!(
        "{:04}-{:02}-{:02}T{:02}:{:02}:{:02}.{:03}Z",
        year,
        month,
        day,
        secs_of_day / 3_600,
        (secs_of_day % 3_600) / 60,
        secs_of_day % 60,
        millis,
    )
}

fn cloud_mcp_agent_chat_turn_hook_ms(payload: &TerminalActivityHookPayload) -> u64 {
    payload.hook_timestamp_ms.max(payload.observed_at_ms)
}

fn cloud_mcp_agent_chat_turn_started_at(payload: &TerminalActivityHookPayload) -> String {
    payload
        .prompt_ready_at
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
        .unwrap_or_else(|| {
            cloud_mcp_agent_chat_turn_iso_from_ms(cloud_mcp_agent_chat_turn_hook_ms(payload))
        })
}

fn cloud_mcp_agent_chat_turn_completed_at(payload: &TerminalActivityHookPayload) -> String {
    payload
        .completed_at
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
        .unwrap_or_else(|| {
            cloud_mcp_agent_chat_turn_iso_from_ms(cloud_mcp_agent_chat_turn_hook_ms(payload))
        })
}

fn cloud_mcp_agent_chat_turn_native_id(payload: &TerminalActivityHookPayload) -> String {
    payload
        .provider_turn_id
        .as_deref()
        .or(payload.turn_id.as_deref())
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or_default()
        .to_string()
}

fn cloud_mcp_agent_chat_turn_key_from_start(payload: &TerminalActivityHookPayload) -> String {
    let native = cloud_mcp_agent_chat_turn_native_id(payload);
    if !native.is_empty() {
        return native;
    }
    if let Some(started_at) = payload
        .prompt_ready_at
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        return format!("turn-start:{started_at}");
    }
    format!(
        "turn-start-ms-{}",
        cloud_mcp_agent_chat_turn_hook_ms(payload)
    )
}

fn cloud_mcp_agent_chat_turn_prompt_start_key(
    payload: &TerminalActivityHookPayload,
) -> Option<String> {
    payload
        .prompt_ready_at
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(|started_at| format!("turn-start:{started_at}"))
}

fn cloud_mcp_agent_chat_turn_snapshot_key(
    provider: &str,
    session_id: &str,
    turn_key: &str,
) -> String {
    format!(
        "{}:{}:{}",
        provider.trim(),
        session_id.trim(),
        turn_key.trim()
    )
}

fn cloud_mcp_agent_chat_turn_git_env(index_path: Option<&Path>) -> Vec<(String, String)> {
    let mut env_vars = vec![
        ("GIT_TERMINAL_PROMPT".to_string(), "0".to_string()),
        ("GCM_INTERACTIVE".to_string(), "Never".to_string()),
    ];
    if let Some(index_path) = index_path {
        env_vars.push((
            "GIT_INDEX_FILE".to_string(),
            index_path.to_string_lossy().to_string(),
        ));
    }
    env_vars
}

fn cloud_mcp_agent_chat_turn_git_run(
    root: &Path,
    args: &[&str],
    index_path: Option<&Path>,
) -> Result<CommandCapture, String> {
    cloud_mcp_agent_chat_turn_git_run_with_timeout(root, args, index_path, Duration::from_secs(2))
}

fn cloud_mcp_agent_chat_turn_git_run_with_timeout(
    root: &Path,
    args: &[&str],
    index_path: Option<&Path>,
    timeout: Duration,
) -> Result<CommandCapture, String> {
    let safe_directory = format!("safe.directory={}", root.to_string_lossy());
    let mut owned_args = Vec::with_capacity(args.len() + 4);
    owned_args.push("-c".to_string());
    owned_args.push(safe_directory);
    owned_args.push("-c".to_string());
    owned_args.push("core.quotepath=off".to_string());
    owned_args.extend(args.iter().map(|arg| (*arg).to_string()));
    let borrowed_args = owned_args.iter().map(String::as_str).collect::<Vec<_>>();
    let env_vars = cloud_mcp_agent_chat_turn_git_env(index_path);
    run_command_capture_with_env("git", &borrowed_args, None, timeout, Some(root), &env_vars)
}

fn cloud_mcp_agent_chat_turn_git_root(cwd: &str) -> Option<PathBuf> {
    let cwd = cwd.trim();
    if cwd.is_empty() {
        return None;
    }
    let cwd = PathBuf::from(cwd);
    if !cwd.is_dir() {
        return None;
    }
    let env_vars = cloud_mcp_agent_chat_turn_git_env(None);
    let output = run_command_capture_with_env(
        "git",
        &["rev-parse", "--show-toplevel"],
        None,
        Duration::from_secs(2),
        Some(&cwd),
        &env_vars,
    )
    .ok()?;
    if output.exit_code != Some(0) {
        return None;
    }
    let root = output.stdout.trim();
    (!root.is_empty()).then(|| PathBuf::from(root))
}

fn cloud_mcp_agent_chat_turn_temp_index_path() -> PathBuf {
    let seq = CLOUD_MCP_AGENT_CHAT_TURN_GIT_TEMP_INDEX_SEQ.fetch_add(1, Ordering::Relaxed);
    env::temp_dir().join(format!(
        "diffforge-turn-index-{}-{}-{seq}",
        std::process::id(),
        cloud_mcp_now_ms()
    ))
}

fn cloud_mcp_agent_chat_turn_cleanup_index(path: &Path) {
    let _ = fs::remove_file(path);
    let mut lock_path = path.to_path_buf();
    lock_path.set_extension("lock");
    let _ = fs::remove_file(lock_path);
}

fn cloud_mcp_agent_chat_turn_git_snapshot_tree(root: &Path) -> Option<String> {
    let index_path = cloud_mcp_agent_chat_turn_temp_index_path();
    let read_head =
        cloud_mcp_agent_chat_turn_git_run(root, &["read-tree", "HEAD"], Some(&index_path))
            .ok()
            .is_some_and(|output| output.exit_code == Some(0));
    if !read_head {
        let read_empty =
            cloud_mcp_agent_chat_turn_git_run(root, &["read-tree", "--empty"], Some(&index_path))
                .ok()
                .is_some_and(|output| output.exit_code == Some(0));
        if !read_empty {
            cloud_mcp_agent_chat_turn_cleanup_index(&index_path);
            return None;
        }
    }
    let added = cloud_mcp_agent_chat_turn_git_run(root, &["add", "-A"], Some(&index_path))
        .ok()
        .is_some_and(|output| output.exit_code == Some(0));
    if !added {
        cloud_mcp_agent_chat_turn_cleanup_index(&index_path);
        return None;
    }
    let tree = cloud_mcp_agent_chat_turn_git_run(root, &["write-tree"], Some(&index_path))
        .ok()
        .filter(|output| output.exit_code == Some(0))
        .map(|output| output.stdout.trim().to_string())
        .filter(|value| !value.is_empty());
    cloud_mcp_agent_chat_turn_cleanup_index(&index_path);
    tree
}

#[cfg(test)]
fn cloud_mcp_agent_chat_turn_git_record_start(
    provider: &str,
    session_id: &str,
    turn_key: &str,
    cwd: &str,
    started_at: &str,
    started_at_ms: u64,
) {
    cloud_mcp_agent_chat_turn_git_mark_start(provider, session_id, turn_key, started_at_ms);
    cloud_mcp_agent_chat_turn_git_record_start_after_mark(
        provider,
        session_id,
        turn_key,
        cwd,
        started_at,
        started_at_ms,
    );
}

fn cloud_mcp_agent_chat_turn_git_mark_start(
    provider: &str,
    session_id: &str,
    turn_key: &str,
    started_at_ms: u64,
) {
    let key = cloud_mcp_agent_chat_turn_snapshot_key(provider, session_id, turn_key);
    let (snapshots, wake) = cloud_mcp_agent_chat_turn_git_snapshots();
    if let Ok(mut snapshots) = snapshots.lock() {
        cloud_mcp_agent_chat_turn_git_prune_locked(&mut snapshots);
        snapshots.insert(
            key,
            CloudMcpAgentChatTurnGitSnapshotState::Pending { started_at_ms },
        );
        cloud_mcp_agent_chat_turn_git_prune_locked(&mut snapshots);
        wake.notify_all();
    }
}

fn cloud_mcp_agent_chat_turn_git_prune_locked(
    snapshots: &mut HashMap<String, CloudMcpAgentChatTurnGitSnapshotState>,
) {
    let now = cloud_mcp_now_ms();
    snapshots.retain(|_, state| {
        let started_at_ms = state.started_at_ms();
        started_at_ms == 0
            || started_at_ms > now
            || now.saturating_sub(started_at_ms) <= CLOUD_MCP_AGENT_CHAT_TURN_GIT_SNAPSHOT_TTL_MS
    });
    while snapshots.len() > CLOUD_MCP_AGENT_CHAT_TURN_GIT_SNAPSHOT_MAX {
        let Some(oldest_key) = snapshots
            .iter()
            .min_by_key(|(_, state)| state.started_at_ms())
            .map(|(key, _)| key.clone())
        else {
            break;
        };
        snapshots.remove(&oldest_key);
    }
}

fn cloud_mcp_agent_chat_turn_git_finish_start(
    provider: &str,
    session_id: &str,
    turn_key: &str,
    started_at_ms: u64,
    snapshot: Option<CloudMcpAgentChatTurnGitSnapshot>,
) {
    let key = cloud_mcp_agent_chat_turn_snapshot_key(provider, session_id, turn_key);
    let (snapshots, wake) = cloud_mcp_agent_chat_turn_git_snapshots();
    if let Ok(mut snapshots) = snapshots.lock() {
        if matches!(
            snapshots.get(&key),
            Some(CloudMcpAgentChatTurnGitSnapshotState::Pending { .. })
        ) {
            let state = snapshot
                .map(CloudMcpAgentChatTurnGitSnapshotState::Ready)
                .unwrap_or(CloudMcpAgentChatTurnGitSnapshotState::Failed { started_at_ms });
            snapshots.insert(key, state);
            cloud_mcp_agent_chat_turn_git_prune_locked(&mut snapshots);
            wake.notify_all();
        }
    }
}

fn cloud_mcp_agent_chat_turn_git_record_start_after_mark(
    provider: &str,
    session_id: &str,
    turn_key: &str,
    cwd: &str,
    started_at: &str,
    started_at_ms: u64,
) {
    let snapshot = cloud_mcp_agent_chat_turn_git_root(cwd).and_then(|repo_root| {
        cloud_mcp_agent_chat_turn_git_snapshot_tree(&repo_root).map(|start_tree| {
            CloudMcpAgentChatTurnGitSnapshot {
                repo_root,
                start_tree,
                started_at: started_at.to_string(),
                started_at_ms,
                turn_key: turn_key.to_string(),
            }
        })
    });
    cloud_mcp_agent_chat_turn_git_finish_start(
        provider,
        session_id,
        turn_key,
        started_at_ms,
        snapshot,
    );
}

fn cloud_mcp_agent_chat_turn_git_take_snapshot(
    provider: &str,
    session_id: &str,
    turn_key: &str,
) -> Option<CloudMcpAgentChatTurnGitSnapshot> {
    cloud_mcp_agent_chat_turn_git_take_snapshot_key(provider, session_id, turn_key, "")
}

fn cloud_mcp_agent_chat_turn_git_take_snapshot_key(
    provider: &str,
    session_id: &str,
    turn_key: &str,
    alias_turn_key: &str,
) -> Option<CloudMcpAgentChatTurnGitSnapshot> {
    if turn_key.trim().is_empty() {
        return None;
    }
    let (snapshots, wake) = cloud_mcp_agent_chat_turn_git_snapshots();
    let mut snapshots = snapshots.lock().ok()?;
    cloud_mcp_agent_chat_turn_git_prune_locked(&mut snapshots);
    let key = cloud_mcp_agent_chat_turn_snapshot_key(provider, session_id, turn_key);
    if !snapshots.contains_key(&key) {
        return None;
    }
    let deadline = Instant::now() + Duration::from_secs(2);
    loop {
        let Some(state) = snapshots.get(&key).cloned() else {
            return None;
        };
        match state {
            CloudMcpAgentChatTurnGitSnapshotState::Ready(mut snapshot) => {
                snapshots.remove(&key);
                let alias_turn_key = alias_turn_key.trim();
                if !alias_turn_key.is_empty() && alias_turn_key != snapshot.turn_key {
                    snapshot.turn_key = alias_turn_key.to_string();
                }
                return Some(snapshot);
            }
            CloudMcpAgentChatTurnGitSnapshotState::Failed { .. } => {
                snapshots.remove(&key);
                return None;
            }
            CloudMcpAgentChatTurnGitSnapshotState::Pending { started_at_ms } => {
                let now = Instant::now();
                if now >= deadline {
                    snapshots.insert(
                        key.clone(),
                        CloudMcpAgentChatTurnGitSnapshotState::Failed { started_at_ms },
                    );
                    continue;
                }
                let wait = deadline.saturating_duration_since(now);
                match wake.wait_timeout(snapshots, wait) {
                    Ok((guard, result)) => {
                        snapshots = guard;
                        if result.timed_out()
                            && matches!(
                                snapshots.get(&key),
                                Some(CloudMcpAgentChatTurnGitSnapshotState::Pending { .. })
                            )
                        {
                            snapshots.insert(
                                key.clone(),
                                CloudMcpAgentChatTurnGitSnapshotState::Failed { started_at_ms },
                            );
                        }
                    }
                    Err(_) => return None,
                }
            }
        }
    }
}

fn cloud_mcp_agent_chat_turn_git_take_completion_snapshot(
    payload: &TerminalActivityHookPayload,
    provider: &str,
    session_id: &str,
    native_turn_id: &str,
) -> Option<CloudMcpAgentChatTurnGitSnapshot> {
    let native_turn_id = native_turn_id.trim();
    if !native_turn_id.is_empty() {
        if let Some(snapshot) =
            cloud_mcp_agent_chat_turn_git_take_snapshot(provider, session_id, native_turn_id)
        {
            return Some(snapshot);
        }
    }
    if let Some(prompt_start_key) = cloud_mcp_agent_chat_turn_prompt_start_key(payload) {
        let alias = if native_turn_id.is_empty() {
            ""
        } else {
            native_turn_id
        };
        return cloud_mcp_agent_chat_turn_git_take_snapshot_key(
            provider,
            session_id,
            &prompt_start_key,
            alias,
        );
    }
    None
}

fn cloud_mcp_agent_chat_turn_git_clear_session(provider: &str, session_id: &str) {
    let prefix = format!("{}:{}:", provider.trim(), session_id.trim());
    if prefix == "::" {
        return;
    }
    let (snapshots, wake) = cloud_mcp_agent_chat_turn_git_snapshots();
    if let Ok(mut snapshots) = snapshots.lock() {
        snapshots.retain(|key, _| !key.starts_with(&prefix));
        wake.notify_all();
    }
}

#[cfg(test)]
fn cloud_mcp_agent_chat_turn_git_clear_all_snapshots() {
    let (snapshots, wake) = cloud_mcp_agent_chat_turn_git_snapshots();
    if let Ok(mut snapshots) = snapshots.lock() {
        snapshots.clear();
        wake.notify_all();
    }
}

fn cloud_mcp_agent_chat_turn_git_name_status_entries(
    name_status: &str,
) -> Vec<CloudMcpAgentChatTurnGitStatusEntry> {
    let mut entries = Vec::new();
    for line in name_status.lines() {
        let parts = line.split('\t').collect::<Vec<_>>();
        let status = parts.first().copied().unwrap_or_default().trim();
        if status.is_empty() {
            continue;
        }
        let (path, old_path) = if status.starts_with('R') || status.starts_with('C') {
            (
                parts.get(2).copied().unwrap_or_default().trim().to_string(),
                parts
                    .get(1)
                    .copied()
                    .map(str::trim)
                    .filter(|value| !value.is_empty())
                    .map(str::to_string),
            )
        } else {
            (
                parts.get(1).copied().unwrap_or_default().trim().to_string(),
                None,
            )
        };
        if !path.is_empty() {
            entries.push(CloudMcpAgentChatTurnGitStatusEntry {
                status: status.to_string(),
                path,
                old_path,
            });
        }
    }
    entries
}

fn cloud_mcp_agent_chat_turn_git_name_status_map(
    name_status: &str,
) -> HashMap<String, CloudMcpAgentChatTurnGitStatusEntry> {
    cloud_mcp_agent_chat_turn_git_name_status_entries(name_status)
        .into_iter()
        .map(|entry| (entry.path.clone(), entry))
        .collect()
}

fn cloud_mcp_agent_chat_turn_git_numstat_rename_path(path: &str) -> Option<String> {
    let path = path.trim();
    if path.is_empty() || !path.contains("=>") {
        return None;
    }
    if let Some(arrow) = path.find("=>") {
        if let Some(open) = path[..arrow].rfind('{') {
            if let Some(close_offset) = path[arrow + 2..].find('}') {
                let close = arrow + 2 + close_offset;
                let base = path[..open].trim_end();
                let renamed = path[arrow + 2..close].trim();
                let suffix = path[close + 1..].trim_start();
                if !renamed.is_empty() {
                    return Some(format!("{base}{renamed}{suffix}"));
                }
            }
        }
        let renamed = path[arrow + 2..].trim();
        if !renamed.is_empty() {
            return Some(renamed.to_string());
        }
    }
    None
}

fn cloud_mcp_agent_chat_turn_git_parse_numstat(
    repo_root: &Path,
    numstat: &str,
    name_status: &str,
) -> Vec<Value> {
    let status_by_path = cloud_mcp_agent_chat_turn_git_name_status_map(name_status);
    let status_entries = cloud_mcp_agent_chat_turn_git_name_status_entries(name_status);
    let mut files = Vec::new();
    for (line_index, line) in numstat.lines().enumerate() {
        let mut parts = line.splitn(3, '\t');
        let additions_text = parts.next().unwrap_or_default().trim();
        let deletions_text = parts.next().unwrap_or_default().trim();
        let raw_path = parts.next().unwrap_or_default().trim();
        let mut path = raw_path.to_string();
        if path.is_empty() {
            continue;
        }
        if !status_by_path.contains_key(&path) {
            if let Some(rename_path) = cloud_mcp_agent_chat_turn_git_numstat_rename_path(&path) {
                path = rename_path;
            }
        }
        let mut status_entry = status_by_path.get(&path).cloned();
        if status_entry.is_none() {
            if let Some(entry) = status_entries.get(line_index) {
                if entry.status.starts_with('R')
                    || entry.status.starts_with('C')
                    || raw_path.contains("=>")
                {
                    path = entry.path.clone();
                    status_entry = Some(entry.clone());
                }
            }
        }
        let additions = additions_text.parse::<i64>().ok();
        let deletions = deletions_text.parse::<i64>().ok();
        let binary = additions.is_none() || deletions.is_none();
        let status = status_entry
            .as_ref()
            .map(|entry| entry.status.as_str())
            .unwrap_or_default();
        let missing_path = !repo_root.join(&path).exists();
        let kind = if status.starts_with('R') {
            "rename"
        } else if status.starts_with('A') || status.starts_with('C') {
            "create"
        } else if status.starts_with('D')
            || (missing_path && additions.unwrap_or(0) == 0 && deletions.unwrap_or(0) >= 0)
        {
            "delete"
        } else {
            "edit"
        };
        let mut file = serde_json::Map::new();
        file.insert("path".to_string(), json!(path));
        file.insert("kind".to_string(), json!(kind));
        if let Some(old_path) = status_entry
            .as_ref()
            .and_then(|entry| entry.old_path.as_ref())
            .filter(|old_path| !old_path.trim().is_empty())
        {
            file.insert("old_path".to_string(), json!(old_path));
        }
        file.insert("additions".to_string(), json!(additions.unwrap_or(0)));
        file.insert("deletions".to_string(), json!(deletions.unwrap_or(0)));
        if binary {
            file.insert("binary".to_string(), json!(true));
        }
        files.push(Value::Object(file));
    }
    files
}

fn cloud_mcp_agent_chat_turn_git_diff_header_path(raw: &str) -> Option<String> {
    let mut path = raw.trim();
    if path == "/dev/null" || path.is_empty() {
        return None;
    }
    if let Some(stripped) = path.strip_prefix("a/").or_else(|| path.strip_prefix("b/")) {
        path = stripped;
    }
    Some(path.trim_matches('"').to_string())
}

fn cloud_mcp_agent_chat_turn_git_patch_section_path(section: &str) -> Option<String> {
    let mut deleted_path = None;
    for line in section.lines() {
        if line.starts_with("@@ ") {
            break;
        }
        if let Some(path) = line.strip_prefix("+++ ") {
            if let Some(path) = cloud_mcp_agent_chat_turn_git_diff_header_path(path) {
                return Some(path);
            }
        } else if let Some(path) = line.strip_prefix("--- ") {
            deleted_path = cloud_mcp_agent_chat_turn_git_diff_header_path(path);
        }
    }
    deleted_path
}

fn cloud_mcp_agent_chat_turn_git_unified_patch(section: &str) -> Option<String> {
    let start = section
        .find("\n--- ")
        .map(|index| index + 1)
        .or_else(|| section.find("--- "))?;
    let patch = section[start..].to_string();
    if patch.contains("\n@@ ") || patch.starts_with("@@ ") {
        Some(patch)
    } else {
        None
    }
}

fn cloud_mcp_agent_chat_turn_git_patch_map(patch_output: &str) -> HashMap<String, String> {
    let mut patches = HashMap::new();
    let mut section = String::new();
    let flush = |section: &mut String, patches: &mut HashMap<String, String>| {
        if section.trim().is_empty() {
            section.clear();
            return;
        }
        if let (Some(path), Some(patch)) = (
            cloud_mcp_agent_chat_turn_git_patch_section_path(section),
            cloud_mcp_agent_chat_turn_git_unified_patch(section),
        ) {
            patches.insert(path, patch);
        }
        section.clear();
    };
    for chunk in patch_output.split_inclusive('\n') {
        if chunk.starts_with("diff --git ") {
            flush(&mut section, &mut patches);
        }
        section.push_str(chunk);
    }
    flush(&mut section, &mut patches);
    patches
}

fn cloud_mcp_agent_chat_turn_diff_totals(files: &[Value]) -> (i64, i64) {
    let total_additions = files
        .iter()
        .filter_map(|file| file.get("additions").and_then(Value::as_i64))
        .sum::<i64>();
    let total_deletions = files
        .iter()
        .filter_map(|file| file.get("deletions").and_then(Value::as_i64))
        .sum::<i64>();
    (total_additions, total_deletions)
}

fn cloud_mcp_agent_chat_turn_diff_message(
    files: &[Value],
    files_omitted: usize,
    truncated: bool,
    total_additions: i64,
    total_deletions: i64,
) -> Value {
    let mut message = json!({
        "id": "cap-check",
        "role": "system",
        "kind": "turn_diff",
        "turn_id": "cap-check",
        "files": files,
        "total_additions": total_additions,
        "total_deletions": total_deletions,
    });
    if files_omitted > 0 {
        if let Some(object) = message.as_object_mut() {
            object.insert("files_omitted".to_string(), json!(files_omitted));
        }
    }
    if truncated {
        if let Some(object) = message.as_object_mut() {
            object.insert("truncated".to_string(), json!(true));
        }
    }
    message
}

fn cloud_mcp_agent_chat_turn_diff_messages_effective_max_bytes() -> usize {
    CLOUD_MCP_AGENT_CHAT_TURN_DIFF_MESSAGES_MAX_BYTES
        .saturating_sub(CLOUD_MCP_AGENT_CHAT_TURN_DIFF_MESSAGES_CAP_HEADROOM_BYTES)
}

fn cloud_mcp_agent_chat_turn_diff_messages_bytes(
    files: &[Value],
    files_omitted: usize,
    truncated: bool,
    total_additions: i64,
    total_deletions: i64,
) -> usize {
    serde_json::to_vec(&vec![cloud_mcp_agent_chat_turn_diff_message(
        files,
        files_omitted,
        truncated,
        total_additions,
        total_deletions,
    )])
    .map(|bytes| bytes.len())
    .unwrap_or(usize::MAX)
}

fn cloud_mcp_agent_chat_turn_git_attach_patches(
    files: Vec<Value>,
    patches: &HashMap<String, String>,
) -> (Vec<Value>, i64, i64, usize, bool, Value) {
    let original_file_count = files.len();
    let (total_additions, total_deletions) = cloud_mcp_agent_chat_turn_diff_totals(&files);
    let mut files = files;
    let mut per_file_truncated = 0usize;
    for file in files.iter_mut() {
        let binary = file.get("binary").and_then(Value::as_bool).unwrap_or(false);
        if binary {
            continue;
        }
        let Some(path) = file.get("path").and_then(Value::as_str) else {
            continue;
        };
        let Some(patch) = patches.get(path) else {
            continue;
        };
        let truncated = patch.chars().count() > CLOUD_MCP_AGENT_CHAT_TURN_DIFF_PATCH_MAX_CHARS;
        let patch = if truncated {
            per_file_truncated = per_file_truncated.saturating_add(1);
            cloud_mcp_truncate_chars(patch, CLOUD_MCP_AGENT_CHAT_TURN_DIFF_PATCH_MAX_CHARS)
        } else {
            patch.clone()
        };
        if let Some(object) = file.as_object_mut() {
            object.insert("patch".to_string(), json!(patch));
            if truncated {
                object.insert("patch_truncated".to_string(), json!(true));
            }
        }
    }

    let mut record_truncated = per_file_truncated > 0;
    let mut patches_dropped = 0usize;
    let effective_messages_max = cloud_mcp_agent_chat_turn_diff_messages_effective_max_bytes();
    while cloud_mcp_agent_chat_turn_diff_messages_bytes(
        &files,
        0,
        record_truncated,
        total_additions,
        total_deletions,
    ) > effective_messages_max
    {
        let largest = files
            .iter()
            .enumerate()
            .filter_map(|(index, file)| {
                file.get("patch")
                    .and_then(Value::as_str)
                    .map(|patch| (index, patch.chars().count()))
            })
            .max_by_key(|(_, len)| *len);
        let Some((index, _)) = largest else {
            break;
        };
        if let Some(object) = files.get_mut(index).and_then(Value::as_object_mut) {
            object.remove("patch");
            object.insert("patch_truncated".to_string(), json!(true));
            patches_dropped = patches_dropped.saturating_add(1);
            record_truncated = true;
        } else {
            break;
        }
    }

    let mut files_omitted = 0usize;
    let mut final_bytes = cloud_mcp_agent_chat_turn_diff_messages_bytes(
        &files,
        files_omitted,
        record_truncated,
        total_additions,
        total_deletions,
    );
    if final_bytes > effective_messages_max {
        record_truncated = true;
        let mut low = 0usize;
        let mut high = files.len();
        while low < high {
            let keep = low + (high - low).div_ceil(2);
            let omitted = original_file_count.saturating_sub(keep);
            let candidate_bytes = cloud_mcp_agent_chat_turn_diff_messages_bytes(
                &files[..keep],
                omitted,
                record_truncated,
                total_additions,
                total_deletions,
            );
            if candidate_bytes <= effective_messages_max {
                low = keep;
            } else {
                high = keep.saturating_sub(1);
            }
        }
        files.truncate(low);
        files_omitted = original_file_count.saturating_sub(files.len());
        final_bytes = cloud_mcp_agent_chat_turn_diff_messages_bytes(
            &files,
            files_omitted,
            record_truncated,
            total_additions,
            total_deletions,
        );
    }
    (
        files,
        total_additions,
        total_deletions,
        files_omitted,
        record_truncated,
        json!({
            "per_file_patch_chars": CLOUD_MCP_AGENT_CHAT_TURN_DIFF_PATCH_MAX_CHARS,
            "serialized_messages_bytes": final_bytes,
            "serialized_messages_limit_bytes": CLOUD_MCP_AGENT_CHAT_TURN_DIFF_MESSAGES_MAX_BYTES,
            "serialized_messages_effective_limit_bytes": effective_messages_max,
            "serialized_messages_cap_headroom_bytes": CLOUD_MCP_AGENT_CHAT_TURN_DIFF_MESSAGES_CAP_HEADROOM_BYTES,
            "original_file_count": original_file_count,
            "files_emitted": original_file_count.saturating_sub(files_omitted),
            "files_omitted": files_omitted,
            "per_file_patches_truncated": per_file_truncated,
            "patches_dropped_for_record_cap": patches_dropped,
            "files_dropped_for_record_cap": files_omitted,
            "files_omitted_for_record_cap": files_omitted,
            "record_truncated": record_truncated,
        }),
    )
}

fn cloud_mcp_agent_chat_turn_git_diff(
    snapshot: Option<CloudMcpAgentChatTurnGitSnapshot>,
) -> CloudMcpAgentChatTurnGitDiff {
    cloud_mcp_agent_chat_turn_git_diff_with_patch_timeout(
        snapshot,
        Duration::from_millis(CLOUD_MCP_AGENT_CHAT_TURN_DIFF_PATCH_TIMEOUT_MS),
    )
}

fn cloud_mcp_agent_chat_turn_git_diff_with_patch_timeout(
    snapshot: Option<CloudMcpAgentChatTurnGitSnapshot>,
    patch_timeout: Duration,
) -> CloudMcpAgentChatTurnGitDiff {
    let Some(snapshot) = snapshot else {
        return CloudMcpAgentChatTurnGitDiff {
            file_change: None,
            turn_diff: None,
            raw: json!({
                "skipped": "missing_start_snapshot",
            }),
        };
    };
    let Some(end_tree) = cloud_mcp_agent_chat_turn_git_snapshot_tree(&snapshot.repo_root) else {
        return CloudMcpAgentChatTurnGitDiff {
            file_change: None,
            turn_diff: None,
            raw: json!({
                "repo_root": snapshot.repo_root.to_string_lossy(),
                "start_tree": snapshot.start_tree,
                "skipped": "end_snapshot_failed",
            }),
        };
    };
    let numstat = cloud_mcp_agent_chat_turn_git_run(
        &snapshot.repo_root,
        &[
            "diff-tree",
            "-r",
            "--find-renames",
            "--numstat",
            &snapshot.start_tree,
            &end_tree,
        ],
        None,
    )
    .ok()
    .filter(|output| output.exit_code == Some(0))
    .map(|output| output.stdout)
    .unwrap_or_default();
    let name_status = cloud_mcp_agent_chat_turn_git_run(
        &snapshot.repo_root,
        &[
            "diff-tree",
            "-r",
            "--find-renames",
            "--name-status",
            &snapshot.start_tree,
            &end_tree,
        ],
        None,
    )
    .ok()
    .filter(|output| output.exit_code == Some(0))
    .map(|output| output.stdout)
    .unwrap_or_default();
    let files =
        cloud_mcp_agent_chat_turn_git_parse_numstat(&snapshot.repo_root, &numstat, &name_status);
    let additions = files
        .iter()
        .filter_map(|file| file.get("additions").and_then(Value::as_i64))
        .sum::<i64>();
    let deletions = files
        .iter()
        .filter_map(|file| file.get("deletions").and_then(Value::as_i64))
        .sum::<i64>();
    let file_change = (!files.is_empty()).then(|| {
        json!({
            "files": files.clone(),
            "summary": format!("{} file{} changed (+{} -{})", files.len(), if files.len() == 1 { "" } else { "s" }, additions, deletions),
        })
    });
    let mut patch_skip_reason = None::<String>;
    let mut patch_error = None::<String>;
    let patches = if files.is_empty() {
        HashMap::new()
    } else if patch_timeout == Duration::from_millis(0) {
        patch_skip_reason = Some("timeout".to_string());
        HashMap::new()
    } else {
        match cloud_mcp_agent_chat_turn_git_run_with_timeout(
            &snapshot.repo_root,
            &[
                "diff-tree",
                "-r",
                "--find-renames",
                "-p",
                &snapshot.start_tree,
                &end_tree,
            ],
            None,
            patch_timeout,
        ) {
            Ok(output) if output.exit_code == Some(0) => {
                cloud_mcp_agent_chat_turn_git_patch_map(&output.stdout)
            }
            Ok(output) => {
                patch_skip_reason = Some("patch_command_failed".to_string());
                patch_error = Some(clean_terminal_telemetry_text(&output.stderr));
                HashMap::new()
            }
            Err(error) => {
                patch_skip_reason = Some(if error.contains("timed out") {
                    "timeout".to_string()
                } else {
                    "patch_command_failed".to_string()
                });
                patch_error = Some(clean_terminal_telemetry_text(&error));
                HashMap::new()
            }
        }
    };
    let (
        turn_diff_files,
        turn_diff_total_additions,
        turn_diff_total_deletions,
        turn_diff_files_omitted,
        turn_diff_truncated,
        caps,
    ) = cloud_mcp_agent_chat_turn_git_attach_patches(files.clone(), &patches);
    let patch_generation = json!({
        "patch_timeout_ms": u64::try_from(patch_timeout.as_millis()).unwrap_or(u64::MAX),
        "patch_skipped": patch_skip_reason.is_some(),
        "patch_skip_reason": patch_skip_reason,
        "patch_error": patch_error,
        "patch_count": patches.len(),
        "caps": caps,
    });
    let raw = json!({
        "repo_root": snapshot.repo_root.to_string_lossy(),
        "start_tree": snapshot.start_tree,
        "end_tree": end_tree,
        "numstat": numstat,
        "name_status": name_status,
        "generation": patch_generation,
    });
    let turn_diff = (!turn_diff_files.is_empty()).then(|| AgentChatTurnDiffContext {
        turn_id: String::new(),
        turn_key: snapshot.turn_key,
        completed_at: String::new(),
        raw: raw.clone(),
        files: turn_diff_files,
        total_additions: turn_diff_total_additions,
        total_deletions: turn_diff_total_deletions,
        files_omitted: turn_diff_files_omitted,
        truncated: turn_diff_truncated,
    });
    CloudMcpAgentChatTurnGitDiff {
        file_change,
        turn_diff,
        raw,
    }
}

fn cloud_mcp_agent_chat_status_hook_is_relevant(
    payload: &TerminalActivityHookPayload,
    state_value: &str,
    turn_status: &str,
) -> bool {
    let event_type = cloud_mcp_lifecycle_status_key(&payload.event_type);
    let command_phase = cloud_mcp_lifecycle_status_key(&payload.command_phase);
    payload.input_ready
        || payload.terminal_is_prompting_user
        || payload.provider_blocked_for_user
        || payload.manual_approval_required
        || matches!(
            event_type.as_str(),
            "provider_turn_started"
                | "provider_turn_completed"
                | "provider_turn_error"
                | "provider_turn_interrupted"
                | "provider_permission_requested"
                | "provider_user_prompt_started"
                | "provider_user_prompt_completed"
                | "provider_user_prompt_answered"
        )
        || matches!(
            command_phase.as_str(),
            "awaiting_input"
                | "awaiting_permission"
                | "awaiting_user"
                | "needs_input"
                | "prompting_user"
        )
        || matches!(
            state_value,
            "paused" | "idle" | "error" | "interrupted" | "closed"
        )
        || matches!(
            turn_status,
            "completed" | "failed" | "interrupted" | "cancelled"
        )
}

fn cloud_mcp_agent_chat_status_from_hook(
    payload: &TerminalActivityHookPayload,
    state_value: &str,
) -> String {
    let command_phase = cloud_mcp_lifecycle_status_key(&payload.command_phase);
    if payload.input_ready
        || payload.terminal_is_prompting_user
        || payload.provider_blocked_for_user
        || payload.manual_approval_required
        || state_value == "paused"
        || matches!(
            command_phase.as_str(),
            "awaiting_input"
                | "awaiting_permission"
                | "awaiting_user"
                | "needs_input"
                | "prompting_user"
        )
    {
        return "awaiting_input".to_string();
    }
    match state_value {
        "thinking" | "compacting" => "running".to_string(),
        "error" => "error".to_string(),
        "interrupted" => "interrupted".to_string(),
        "idle" => "idle".to_string(),
        "closed" => "closed".to_string(),
        value if !value.trim().is_empty() => value.to_string(),
        _ => "running".to_string(),
    }
}

struct CloudMcpAgentChatStatusSyncRequest {
    provider: String,
    provider_session_id: String,
    cwd: String,
    context: AgentChatSessionSyncContext,
}

fn cloud_mcp_agent_chat_status_sync_request_from_hook(
    payload: &TerminalActivityHookPayload,
    context_entry: Option<&CloudMcpTerminalContextState>,
    workspace_root: &str,
    state_value: &str,
    turn_status: &str,
) -> Option<CloudMcpAgentChatStatusSyncRequest> {
    if !cloud_mcp_agent_chat_status_hook_is_relevant(payload, state_value, turn_status) {
        return None;
    }
    let provider_session_id = payload
        .provider_session_id
        .as_deref()
        .or(payload.native_session_id.as_deref())
        .map(str::trim)
        .filter(|value| !value.is_empty())?;
    let provider = [
        payload.provider.as_str(),
        payload.agent_kind.as_str(),
        payload.agent_id.as_str(),
    ]
    .into_iter()
    .find_map(agent_chat_session_sync_provider)?;
    let workspace_id = if payload.workspace_id.trim().is_empty() {
        context_entry
            .map(|entry| entry.workspace_id.clone())
            .unwrap_or_default()
    } else {
        payload.workspace_id.clone()
    };
    let workspace_id = cloud_mcp_workspace_id_match_key(&workspace_id);
    if workspace_id.trim().is_empty() {
        return None;
    }
    let cwd = if workspace_root.trim().is_empty() {
        payload.cwd.clone().unwrap_or_default()
    } else {
        workspace_root.to_string()
    };
    let context = AgentChatSessionSyncContext {
        workspace_id,
        workspace_name: if payload.workspace_name.trim().is_empty() {
            context_entry
                .map(|entry| entry.workspace_name.clone())
                .unwrap_or_default()
        } else {
            payload.workspace_name.clone()
        },
        thread_id: if payload.thread_id.trim().is_empty() {
            context_entry
                .and_then(|entry| entry.thread_id.clone())
                .unwrap_or_default()
        } else {
            payload.thread_id.clone()
        },
        pane_id: payload.pane_id.clone(),
        terminal_instance_id: Some(payload.instance_id),
        terminal_index: payload.terminal_index.map(i64::from),
        session_mode: context_entry
            .map(|entry| entry.session_mode.clone())
            .unwrap_or_default(),
        status: cloud_mcp_agent_chat_status_from_hook(payload, state_value),
        source: "terminal_activity_hook_status".to_string(),
        fork_from_provider_session_id: payload
            .fork_from_provider_session_id
            .clone()
            .unwrap_or_default(),
        metadata_only: true,
        ..AgentChatSessionSyncContext::default()
    };
    Some(CloudMcpAgentChatStatusSyncRequest {
        provider: provider.to_string(),
        provider_session_id: provider_session_id.to_string(),
        cwd,
        context,
    })
}

fn cloud_mcp_sync_agent_chat_session_status_from_hook(
    state: &CloudMcpState,
    payload: &TerminalActivityHookPayload,
    context_entry: Option<&CloudMcpTerminalContextState>,
    workspace_root: &str,
    state_value: &str,
    turn_status: &str,
) {
    let Some(request) = cloud_mcp_agent_chat_status_sync_request_from_hook(
        payload,
        context_entry,
        workspace_root,
        state_value,
        turn_status,
    ) else {
        return;
    };
    if cloud_mcp_agent_chat_turn_git_should_clear(payload, state_value, turn_status) {
        cloud_mcp_agent_chat_turn_git_clear_session(
            &request.provider,
            &request.provider_session_id,
        );
    }
    agent_chat_session_sync_spawn_with_state(
        state.clone(),
        request.provider,
        request.provider_session_id,
        request.cwd,
        request.context,
        "terminal_activity_hook_status",
    );
}

fn cloud_mcp_agent_chat_turn_git_should_clear(
    payload: &TerminalActivityHookPayload,
    state_value: &str,
    turn_status: &str,
) -> bool {
    let event_type = cloud_mcp_lifecycle_status_key(&payload.event_type);
    matches!(
        event_type.as_str(),
        "provider_turn_error" | "provider_turn_interrupted"
    ) || matches!(state_value, "error" | "interrupted" | "closed")
        || matches!(turn_status, "failed" | "interrupted" | "cancelled")
}

#[cfg(test)]
fn cloud_mcp_agent_chat_turn_summary_context_from_hook(
    payload: &TerminalActivityHookPayload,
    provider: &str,
    provider_session_id: &str,
) -> AgentChatTurnSummaryContext {
    let (summary, _) =
        cloud_mcp_agent_chat_turn_contexts_from_hook(payload, provider, provider_session_id);
    summary
}

fn cloud_mcp_agent_chat_turn_contexts_from_hook(
    payload: &TerminalActivityHookPayload,
    provider: &str,
    provider_session_id: &str,
) -> (
    AgentChatTurnSummaryContext,
    Option<AgentChatTurnDiffContext>,
) {
    let native_turn_id = cloud_mcp_agent_chat_turn_native_id(payload);
    let snapshot = cloud_mcp_agent_chat_turn_git_take_completion_snapshot(
        payload,
        provider,
        provider_session_id,
        &native_turn_id,
    );
    let started_at = snapshot
        .as_ref()
        .map(|snapshot| snapshot.started_at.clone())
        .unwrap_or_else(|| cloud_mcp_agent_chat_turn_started_at(payload));
    let started_at_ms = snapshot
        .as_ref()
        .map(|snapshot| snapshot.started_at_ms)
        .unwrap_or_else(|| cloud_mcp_agent_chat_turn_hook_ms(payload));
    let turn_key = if !native_turn_id.trim().is_empty() {
        native_turn_id.clone()
    } else {
        snapshot
            .as_ref()
            .map(|snapshot| snapshot.turn_key.clone())
            .unwrap_or_else(|| cloud_mcp_agent_chat_turn_key_from_start(payload))
    };
    let completed_at = cloud_mcp_agent_chat_turn_completed_at(payload);
    let completed_at_ms = cloud_mcp_agent_chat_turn_hook_ms(payload);
    let duration_ms = payload.duration_ms.or_else(|| {
        completed_at_ms
            .checked_sub(started_at_ms)
            .filter(|duration| *duration > 0)
    });
    let git_diff = cloud_mcp_agent_chat_turn_git_diff(snapshot);
    let hook_raw = json!({
        "event_type": payload.event_type.as_str(),
        "hook_event_name": payload.hook_event_name.as_str(),
        "source": payload.source.as_str(),
        "provider": provider,
        "provider_session_id": provider_session_id,
        "native_session_id": payload.native_session_id.clone(),
        "provider_turn_id": payload.provider_turn_id.clone(),
        "turn_id": payload.turn_id.clone(),
        "turn_key": turn_key.as_str(),
        "started_at": started_at.as_str(),
        "completed_at": completed_at.as_str(),
        "duration_ms": duration_ms,
        "hook_timestamp_ms": payload.hook_timestamp_ms,
        "observed_at_ms": payload.observed_at_ms,
    });
    let mut turn_diff = git_diff.turn_diff;
    if let Some(diff) = turn_diff.as_mut() {
        diff.turn_id = native_turn_id.clone();
        diff.turn_key = turn_key.clone();
        diff.completed_at = completed_at.clone();
        if let Some(object) = diff.raw.as_object_mut() {
            object.insert("hook".to_string(), hook_raw.clone());
        }
    }
    (
        AgentChatTurnSummaryContext {
            turn_id: native_turn_id,
            turn_key,
            started_at,
            completed_at,
            duration_ms,
            raw: json!({
                "hook": hook_raw,
                "git": git_diff.raw,
            }),
            file_change: git_diff.file_change,
        },
        turn_diff,
    )
}

fn cloud_mcp_agent_chat_turn_summary_has_stable_key(payload: &TerminalActivityHookPayload) -> bool {
    !cloud_mcp_agent_chat_turn_native_id(payload)
        .trim()
        .is_empty()
        || payload
            .prompt_ready_at
            .as_deref()
            .is_some_and(|value| !value.trim().is_empty())
}

fn cloud_mcp_sync_agent_chat_turn_summary_from_hook(
    state: &CloudMcpState,
    payload: &TerminalActivityHookPayload,
    context_entry: Option<&CloudMcpTerminalContextState>,
    workspace_root: &str,
    state_value: &str,
    turn_status: &str,
) {
    let event_type = cloud_mcp_lifecycle_status_key(&payload.event_type);
    if !matches!(
        event_type.as_str(),
        "provider_turn_started" | "provider_turn_completed"
    ) {
        return;
    }
    let Some(request) = cloud_mcp_agent_chat_status_sync_request_from_hook(
        payload,
        context_entry,
        workspace_root,
        state_value,
        turn_status,
    ) else {
        return;
    };
    if event_type == "provider_turn_started" {
        let started_at = cloud_mcp_agent_chat_turn_started_at(payload);
        let turn_key = cloud_mcp_agent_chat_turn_key_from_start(payload);
        let started_at_ms = cloud_mcp_agent_chat_turn_hook_ms(payload);
        cloud_mcp_agent_chat_turn_git_mark_start(
            &request.provider,
            &request.provider_session_id,
            &turn_key,
            started_at_ms,
        );
        tauri::async_runtime::spawn_blocking(move || {
            cloud_mcp_agent_chat_turn_git_record_start_after_mark(
                &request.provider,
                &request.provider_session_id,
                &turn_key,
                &request.cwd,
                &started_at,
                started_at_ms,
            );
        });
        return;
    }
    if !cloud_mcp_agent_chat_turn_summary_has_stable_key(payload) {
        return;
    }
    let payload = payload.clone();
    let state = state.clone();
    tauri::async_runtime::spawn_blocking(move || {
        let (summary, turn_diff) = cloud_mcp_agent_chat_turn_contexts_from_hook(
            &payload,
            &request.provider,
            &request.provider_session_id,
        );
        let mut context = request.context;
        context.metadata_only = false;
        context.source = "terminal_activity_hook_turn_summary".to_string();
        context.turn_summary = Some(summary);
        context.turn_diff = turn_diff;
        agent_chat_session_sync_spawn_with_state(
            state,
            request.provider,
            request.provider_session_id,
            request.cwd,
            context,
            "terminal_activity_hook_turn_summary",
        );
    });
}

fn cloud_mcp_agent_chat_hook_workspace_root(
    payload: &TerminalActivityHookPayload,
    context_entry: Option<&CloudMcpTerminalContextState>,
) -> String {
    payload
        .cwd
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
        .or_else(|| {
            context_entry
                .map(|entry| workspace_path_display(&entry.repo_root))
                .filter(|value| !value.trim().is_empty())
        })
        .unwrap_or_default()
}

fn cloud_mcp_provider_command_catalog(provider: &str) -> Value {
    let provider = provider.trim().to_ascii_lowercase();
    let commands: &[(&str, &str, &str)] = if provider.contains("claude") {
        &[
            ("/model", "Change the model", "model"),
            ("/permissions", "Review permission mode", "passthrough"),
            ("/compact", "Compact conversation context", "passthrough"),
            ("/clear", "Start a fresh conversation", "passthrough"),
            ("/context", "Inspect context usage", "passthrough"),
            ("/cost", "Show token cost", "passthrough"),
            ("/hooks", "Review configured hooks", "passthrough"),
            ("/mcp", "Review MCP servers", "passthrough"),
            ("/status", "Show provider status", "passthrough"),
        ]
    } else if provider.contains("opencode") {
        &[
            ("/models", "Change the model", "model"),
            ("/new", "Start a fresh conversation", "passthrough"),
            ("/sessions", "Browse sessions", "passthrough"),
            ("/compact", "Compact conversation context", "passthrough"),
            ("/share", "Share this session", "passthrough"),
            ("/unshare", "Stop sharing this session", "passthrough"),
            ("/help", "Show provider help", "passthrough"),
        ]
    } else {
        &[
            ("/model", "Change the model", "model"),
            ("/permissions", "Review permission mode", "passthrough"),
            ("/compact", "Compact conversation context", "passthrough"),
            ("/review", "Review current changes", "passthrough"),
            ("/status", "Show provider status", "passthrough"),
            ("/new", "Start a fresh conversation", "passthrough"),
            ("/resume", "Resume a saved session", "passthrough"),
            ("/mcp", "Review MCP servers", "passthrough"),
        ]
    };
    Value::Array(
        commands
            .iter()
            .map(|(id, hint, kind)| json!({ "id": id, "hint": hint, "kind": kind }))
            .collect(),
    )
}

pub(crate) async fn cloud_mcp_sync_terminal_activity_hook_delta(
    state: &CloudMcpState,
    payload: &TerminalActivityHookPayload,
) {
    let terminal_id = payload.pane_id.as_str();
    let terminal_key = cloud_mcp_terminal_key(terminal_id, payload.instance_id);
    let context_entry = {
        let runtime = state.inner.lock().await;
        runtime.terminal_contexts.get(&terminal_key).cloned()
    };
    let repo_id = context_entry
        .as_ref()
        .map(|entry| entry.repo_id.clone())
        .filter(|value| !value.trim().is_empty());
    let workspace_root = cloud_mcp_agent_chat_hook_workspace_root(payload, context_entry.as_ref());
    let direct_prompt_refs = context_entry.as_ref().and_then(|entry| {
        Some(CloudMcpDirectPromptTodoRefs {
            todo_id: entry.todo_id.clone()?,
            dispatch_id: entry.todo_dispatch_id.clone()?,
            command_id: entry.todo_command_id.clone()?,
        })
    });
    let prompt_event_id = context_entry
        .as_ref()
        .and_then(|entry| entry.prompt_event_id.as_deref());
    let turn_prompt_event_id = payload
        .turn_id
        .as_deref()
        .or(payload.provider_turn_id.as_deref())
        .or(prompt_event_id);
    let current_prompt = payload
        .user_message
        .as_deref()
        .or(payload.message.as_deref());
    let state_value = cloud_mcp_terminal_lifecycle_state(
        &payload.event_type,
        &payload.terminal_status,
        &payload.native_rail_state,
        &payload.readiness,
        &payload.command_phase,
        &payload.execution_phase,
        &payload.turn_status,
        Some(payload.terminal_is_prompting_user),
        payload.prompt_id.as_deref(),
    );
    let turn_status = cloud_mcp_terminal_lifecycle_turn_status(
        &payload.event_type,
        &payload.turn_status,
        state_value,
    );
    let reason = payload.source.as_str();
    let provider_session_id = payload.provider_session_id.clone();
    let fork_from_provider_session_id = payload.fork_from_provider_session_id.clone();
    let thread_id = if payload.thread_id.trim().is_empty() {
        context_entry
            .as_ref()
            .and_then(|entry| entry.thread_id.clone())
            .unwrap_or_default()
    } else {
        payload.thread_id.clone()
    };
    let device_terminal_orchestrator = cloud_mcp_is_app_control_workspace_id(&payload.workspace_id)
        || cloud_mcp_is_app_control_pane_id(terminal_id);
    let status_seq = cloud_mcp_next_terminal_lifecycle_seq(state, Some(payload.observed_at_ms));
    let workspace_runtime_seq = if device_terminal_orchestrator {
        None
    } else {
        Some(cloud_mcp_next_workspace_runtime_seq(
            state,
            Some(payload.observed_at_ms),
        ))
    };
    let workspace_runtime_epoch = if device_terminal_orchestrator {
        None
    } else {
        Some(cloud_mcp_workspace_runtime_epoch(state))
    };
    cloud_mcp_sync_agent_chat_session_status_from_hook(
        state,
        payload,
        context_entry.as_ref(),
        &workspace_root,
        state_value,
        turn_status,
    );
    cloud_mcp_sync_agent_chat_turn_summary_from_hook(
        state,
        payload,
        context_entry.as_ref(),
        &workspace_root,
        state_value,
        turn_status,
    );
    let terminal_state_summary = format!("Terminal {}.", state_value);
    let terminal_is_prompting_user = payload.terminal_is_prompting_user;
    let prompt_id = if terminal_is_prompting_user {
        payload.prompt_id.clone().unwrap_or_default()
    } else {
        String::new()
    };
    let prompt_options = if terminal_is_prompting_user {
        payload.prompt_options.clone()
    } else {
        Vec::new()
    };
    let mut delta = json!({
        "source": "rust-diffforge-activity-hook",
        "event_kind": if device_terminal_orchestrator { "device_terminal_orchestrator_update" } else { "terminal_state_update" },
        "v": 1,
        "repo_id": repo_id,
        "workspace_root": workspace_root,
        "workspace_id": payload.workspace_id,
        "workspace_name": payload.workspace_name,
        "terminal_scope": if device_terminal_orchestrator { "device" } else { "workspace" },
        "terminal_kind": if device_terminal_orchestrator { "terminal_orchestrator" } else { "workspace_terminal" },
        "workspace_scoped": !device_terminal_orchestrator,
        "display_name": payload.display_name.as_str(),
        "terminal_id": terminal_id,
        "target_terminal_id": terminal_id,
        "pane_id": terminal_id,
        "terminal_instance_id": payload.instance_id,
        "terminal_index": payload.terminal_index,
        "terminal_epoch": format!("{}:{}", terminal_id, payload.instance_id),
        "terminal_name": payload.terminal_name.as_str(),
        "terminal_nickname": payload.terminal_nickname.as_str(),
        "thread_id": thread_id.as_str(),
        "target_thread_id": thread_id.as_str(),
        "terminal_lifecycle": payload.terminal_lifecycle.as_str(),
        "agent_kind": payload.agent_kind,
        "agent_type": payload.agent_type.as_str(),
        "agent_display_name": payload.agent_display_name.as_str(),
        "provider": payload.provider,
        "command_catalog": cloud_mcp_provider_command_catalog(&payload.provider),
        "command_catalog_source": "provider_adapter",
        "command_catalog_revision": 1,
        "event_type": payload.event_type,
        "hook_event_name": payload.hook_event_name,
        "state": state_value,
        "status": state_value,
        "activity_status": payload.native_rail_state.as_str(),
        "display_status": payload.native_rail_label.as_str(),
        "native_rail_state": payload.native_rail_state.as_str(),
        "native_rail_label": payload.native_rail_label.as_str(),
        "readiness": payload.readiness.as_str(),
        "turn_status": turn_status,
        "raw_turn_status": payload.turn_status.as_str(),
        "command_phase": payload.command_phase,
        "execution_phase": payload.execution_phase.as_str(),
        "terminal_status": payload.terminal_status.as_str(),
        "terminal_work_state": payload.terminal_work_state.as_str(),
        "session_state": payload.session_state.as_str(),
        "input_ready": payload.input_ready,
        "status_seq": status_seq,
        "observed_at_ms": payload.observed_at_ms,
        "hook_timestamp_ms": payload.hook_timestamp_ms,
        "prompt_id": prompt_id,
        "interaction_id": payload.interaction_id.clone(),
        "interaction_revision": payload.interaction_revision,
        "interaction_source": payload.interaction_source.clone(),
        "interaction_response_mode": payload.interaction_response_mode.clone(),
        "provider_request_id": payload.provider_request_id.clone(),
        "prompt_kind": payload.prompt_kind.clone(),
        "prompt_default_option": payload.prompt_default_option.clone(),
        "prompt_ttl_ms": payload.prompt_ttl_ms,
        "prompt_options": prompt_options,
        "allows_free_text": payload.allows_free_text,
        "manual_approval_required": payload.manual_approval_required,
        "provider_blocked_for_user": payload.provider_blocked_for_user,
        "terminal_is_prompting_user": terminal_is_prompting_user,
        "prompting_user_kind": payload.prompting_user_kind.clone(),
        "prompting_user_source": payload.prompting_user_source.clone(),
        "prompting_user_confidence": payload.prompting_user_confidence.clone(),
        "prompting_user_text": payload.prompting_user_text.clone(),
        "turn_id": payload.turn_id,
        "provider_turn_id": payload.provider_turn_id,
        "provider_error": payload.provider_error.clone(),
        "attention_state": payload.provider_error.as_ref()
            .and_then(|error| error.get("category"))
            .and_then(Value::as_str)
            .map(|category| if category == "auth" { "auth" } else { "error" })
            .unwrap_or("none"),
        "provider_health": if payload.provider_error.is_some() { "fatal" } else { "healthy" },
        "provider_session_id": provider_session_id.clone(),
        "native_session_id": provider_session_id.clone(),
        "session_id": provider_session_id,
        "fork_from_provider_session_id": fork_from_provider_session_id,
        "prompt_event_id": turn_prompt_event_id,
        "user_message": current_prompt,
        "current_prompt": current_prompt,
        "last_prompt": current_prompt,
        "message": payload.message.as_deref(),
        "todo_id": direct_prompt_refs.as_ref().map(|refs| refs.todo_id.as_str()),
        "todo_dispatch_id": direct_prompt_refs.as_ref().map(|refs| refs.dispatch_id.as_str()),
        "command_id": direct_prompt_refs.as_ref().map(|refs| refs.command_id.as_str()),
        "reason": reason,
        "summary": terminal_state_summary,
        "ts_ms": cloud_mcp_now_ms()});
    if let Some(object) = delta.as_object_mut() {
        if let Some(seq) = workspace_runtime_seq {
            object.insert("workspace_runtime_seq".to_string(), json!(seq));
        }
        if let Some(epoch) = workspace_runtime_epoch.as_deref() {
            object.insert("workspace_runtime_epoch".to_string(), json!(epoch));
        }
    }
    cloud_mcp_publish_terminal_state_live_update(state, &delta, reason).await;
    if let (Some(refs), Some(status)) = (
        direct_prompt_refs.as_ref(),
        cloud_mcp_direct_prompt_dispatch_status_for_turn(turn_status),
    ) {
        if device_terminal_orchestrator {
            return;
        }
        cloud_mcp_record_direct_prompt_todo_dispatch_status(
            state,
            refs,
            &payload.workspace_id,
            status,
            json!({
                "reason": reason,
                "event_type": payload.event_type,
                "hook_event_name": payload.hook_event_name,
                "turn_status": turn_status,
                "state": state_value,
                "pane_id": terminal_id,
                "terminal_instance_id": payload.instance_id,
                "provider_session_id": payload.provider_session_id,
                "prompt_event_id": prompt_event_id,
            }),
        )
        .await;
    }
}

fn cloud_mcp_workspace_payload_matches_delete(
    value: &Value,
    workspace_id: &str,
    platform: &str,
) -> bool {
    cloud_mcp_payload_text(value, &["workspace_id", "id"])
        .as_deref()
        .is_some_and(|stored_id| {
            cloud_mcp_workspace_id_matches_canonical_or_legacy(workspace_id, stored_id, platform)
        })
}

fn cloud_mcp_mark_workspace_inactive_in_snapshot(
    snapshot: &mut Option<Value>,
    workspace_id: &str,
    platform: &str,
    reason: &str,
    observed_at_ms: u64,
) -> bool {
    let Some(snapshot_value) = snapshot.as_mut() else {
        return false;
    };
    let Some(object) = snapshot_value.as_object_mut() else {
        return false;
    };
    let Some(workspaces) = object.get_mut("workspaces").and_then(Value::as_array_mut) else {
        return false;
    };

    let mut changed = false;
    for workspace in workspaces {
        if !cloud_mcp_workspace_payload_matches_delete(workspace, workspace_id, platform) {
            continue;
        }
        changed = true;
        if let Some(workspace_object) = workspace.as_object_mut() {
            workspace_object.insert("workspace_active".to_string(), json!(false));
            workspace_object.insert("workspace_status".to_string(), json!("deactivated"));
            workspace_object.insert("status".to_string(), json!("deactivated"));
            workspace_object.insert("last_known_runtime".to_string(), json!(false));
            workspace_object.insert("runtime_read_only".to_string(), json!(false));
            workspace_object.insert("commandable".to_string(), json!(true));
            workspace_object.insert("reason".to_string(), json!(reason));
            workspace_object.insert("ts_ms".to_string(), json!(observed_at_ms));
            workspace_object.insert("updated_at_ms".to_string(), json!(observed_at_ms));
        }
        cloud_mcp_mark_workspace_terminals_last_known_read_only(workspace);
    }
    if changed {
        object.insert("reason".to_string(), json!(reason));
        object.insert("ts_ms".to_string(), json!(observed_at_ms));
        object.insert("updated_at_ms".to_string(), json!(observed_at_ms));
    }
    changed
}

fn cloud_mcp_deactivated_workspace_snapshot(
    workspace_id: &str,
    workspace_root: Option<&str>,
    reason: &str,
    observed_at_ms: u64,
) -> Value {
    let device_profile = cloud_mcp_desktop_device_profile();
    let mut snapshot = json!({
        "source": "rust-diffforge-workspace-runtime",
        "event_kind": "device_live_state_snapshot",
        "device": device_profile.clone(),
        "device_id": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "platform": device_profile["platform"].clone(),
        "form_factor": device_profile["form_factor"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "reason": reason,
        "workspace_count": 1,
        "workspaces": [{
            "workspace_id": workspace_id,
            "workspace_active": false,
            "workspace_status": "deactivated",
            "status": "deactivated",
            "last_known_runtime": false,
            "runtime_read_only": false,
            "commandable": true,
            "terminals": [],
            "terminal_count": 0,
            "active_count": 0,
            "reason": reason,
            "ts_ms": observed_at_ms,
            "updated_at_ms": observed_at_ms,
        }],
        "ts_ms": observed_at_ms,
        "updated_at_ms": observed_at_ms,
    });
    if let Some(workspace_root) = workspace_root
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        if let Some(workspace) = snapshot
            .get_mut("workspaces")
            .and_then(Value::as_array_mut)
            .and_then(|workspaces| workspaces.first_mut())
            .and_then(Value::as_object_mut)
        {
            workspace.insert("workspace_root".to_string(), json!(workspace_root));
        }
    }
    snapshot
}

pub(crate) async fn cloud_mcp_publish_workspace_deactivated_snapshot(
    state: &CloudMcpState,
    workspace_id: &str,
    reason: &str,
) {
    let workspace_id = cloud_mcp_workspace_id_match_key(workspace_id);
    if workspace_id.is_empty() {
        return;
    }
    let reason = {
        let trimmed = reason.trim();
        if trimmed.is_empty() {
            "workspace_deactivate".to_string()
        } else {
            trimmed.to_string()
        }
    };
    let observed_at_ms = cloud_mcp_now_ms();
    let platform = cloud_mcp_desktop_platform();
    let workspace_root = {
        let runtime = state.inner.lock().await;
        runtime
            .registered_workspaces
            .values()
            .find(|workspace| {
                cloud_mcp_workspace_id_match_key(&workspace.workspace_id) == workspace_id
            })
            .map(|workspace| workspace.root.trim().to_string())
            .filter(|root| !root.is_empty())
    };
    let mut changed = false;
    {
        let mut snapshots = state.runtime_snapshots.lock().await;
        changed |= cloud_mcp_mark_workspace_inactive_in_snapshot(
            &mut snapshots.workspace_catalog,
            &workspace_id,
            platform,
            &reason,
            observed_at_ms,
        );
        changed |= cloud_mcp_mark_workspace_inactive_in_snapshot(
            &mut snapshots.workspace_terminals,
            &workspace_id,
            platform,
            &reason,
            observed_at_ms,
        );
        changed |= cloud_mcp_mark_workspace_inactive_in_snapshot(
            &mut snapshots.workspace_servers,
            &workspace_id,
            platform,
            &reason,
            observed_at_ms,
        );
        if !changed {
            snapshots.workspace_catalog = Some(cloud_mcp_deactivated_workspace_snapshot(
                &workspace_id,
                workspace_root.as_deref(),
                &reason,
                observed_at_ms,
            ));
        }
    }
    cloud_mcp_publish_device_live_state_snapshot(state, &reason).await;
}

fn cloud_mcp_filter_deleted_workspace_snapshot(
    snapshot: &mut Option<Value>,
    workspace_id: &str,
    platform: &str,
    count_kind: &str,
) -> usize {
    let (removed, should_clear) = {
        let Some(snapshot_value) = snapshot.as_mut() else {
            return 0;
        };
        let Some(object) = snapshot_value.as_object_mut() else {
            return 0;
        };
        let Some(workspaces) = object.get_mut("workspaces").and_then(Value::as_array_mut) else {
            return 0;
        };

        let before = workspaces.len();
        workspaces.retain(|workspace| {
            !cloud_mcp_workspace_payload_matches_delete(workspace, workspace_id, platform)
        });
        let removed = before.saturating_sub(workspaces.len());
        if removed == 0 {
            return 0;
        }

        let workspace_count = workspaces.len();
        let terminal_count = (count_kind == "terminals").then(|| {
            workspaces
                .iter()
                .map(|workspace| {
                    workspace
                        .get("terminals")
                        .and_then(Value::as_array)
                        .map(Vec::len)
                        .unwrap_or_default()
                })
                .sum::<usize>()
        });
        let server_count = (count_kind == "mcps").then(|| {
            workspaces
                .iter()
                .map(|workspace| {
                    workspace
                        .get("servers")
                        .and_then(Value::as_array)
                        .map(Vec::len)
                        .unwrap_or_default()
                })
                .sum::<usize>()
        });
        object.insert("workspace_count".to_string(), json!(workspace_count));
        if let Some(terminal_count) = terminal_count {
            object.insert("terminal_count".to_string(), json!(terminal_count));
        }
        if let Some(server_count) = server_count {
            object.insert("server_count".to_string(), json!(server_count));
        }
        (removed, workspace_count == 0)
    };

    if should_clear {
        *snapshot = None;
    }

    removed
}

fn cloud_mcp_empty_workspace_snapshot(source: &str, reason: &str, count_kind: &str) -> Value {
    let device_profile = cloud_mcp_desktop_device_profile();
    let mut payload = json!({
        "source": source,
        "event_kind": "device_live_state_snapshot",
        "reason": reason,
        "client_id": CLOUD_MCP_RUST_CLIENT_ID,
        "device_id": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "platform": device_profile["platform"].clone(),
        "form_factor": device_profile["form_factor"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "agent_id": "rust-diffforge",
        "agent_label": "Diff Forge Desktop",
        "snapshot_id": format!("empty-workspaces-{}-{}", cloud_mcp_now_ms(), uuid::Uuid::new_v4()),
        "snapshot_full": true,
        "authoritative": true,
        "workspace_set_empty_authoritative": true,
        "workspace_clear_reason": reason,
        "workspace_count": 0,
        "workspaces": [],
        "summary": "Desktop workspace state cleared.",
        "ts_ms": cloud_mcp_now_ms(),
    });
    if let Some(object) = payload.as_object_mut() {
        match count_kind {
            "terminals" => {
                object.insert("terminal_count".to_string(), json!(0));
            }
            "mcps" => {
                object.insert("server_count".to_string(), json!(0));
            }
            _ => {}
        }
    }
    payload
}

fn cloud_mcp_restore_empty_workspace_snapshot_after_delete(
    snapshot: &mut Option<Value>,
    removed: usize,
    source: &str,
    reason: &str,
    count_kind: &str,
) {
    if removed > 0 && snapshot.is_none() {
        *snapshot = Some(cloud_mcp_empty_workspace_snapshot(
            source, reason, count_kind,
        ));
    }
}

fn cloud_mcp_post_workspace_revived_events(state: CloudMcpState, workspaces: Vec<Value>) {
    if workspaces.is_empty() {
        return;
    }
    tauri::async_runtime::spawn(async move {
        for workspace in workspaces {
            let workspace_id = cloud_mcp_payload_text(&workspace, &["id", "workspace_id"])
                .map(|workspace_id| {
                    cloud_mcp_canonical_workspace_id_from_value(
                        &workspace_id,
                        &workspace,
                        cloud_mcp_desktop_platform(),
                    )
                })
                .unwrap_or_default();
            if workspace_id.trim().is_empty() {
                continue;
            }
            if let Err(error) = cloud_mcp_post_workspace_revived_event(&state, &workspace).await {
                log_terminal_status_event(
                    "backend.cloud_mcp.workspace_revived_post_failed",
                    json!({
                        "workspace_id": workspace_id,
                        "error": error,
                    }),
                );
            }
        }
    });
}

async fn cloud_mcp_post_workspace_revived_event(
    state: &CloudMcpState,
    workspace: &Value,
) -> Result<Value, String> {
    let workspace_id = cloud_mcp_payload_text(workspace, &["id", "workspace_id"])
        .map(|workspace_id| {
            cloud_mcp_canonical_workspace_id_from_value(
                &workspace_id,
                workspace,
                cloud_mcp_desktop_platform(),
            )
        })
        .filter(|workspace_id| !workspace_id.is_empty())
        .ok_or_else(|| "Workspace revive requires a workspace id.".to_string())?;
    let workspace_name = cloud_mcp_payload_text(workspace, &["workspace_name", "name"])
        .unwrap_or_else(|| workspace_id.clone());
    let root_text = cloud_mcp_payload_text(
        workspace,
        &["root_directory", "workspace_root", "repo_path"],
    );
    let root = root_text
        .as_deref()
        .and_then(|root| resolve_workspace_root_directory(Some(root)).ok());
    let repo_id = root
        .as_ref()
        .map(|root| cloud_mcp_repo_id_for_root(root))
        .or_else(|| cloud_mcp_payload_text(workspace, &["repo_id"]));
    let repo_ids = repo_id.iter().cloned().collect::<Vec<_>>();
    let root_display = root
        .as_ref()
        .map(|root| workspace_path_display(root))
        .or_else(|| root_text.clone());
    let workspace_location_fingerprint = root
        .as_ref()
        .map(|root| cloud_mcp_workspace_location_fingerprint(root));
    let device_profile = cloud_mcp_desktop_device_profile();
    let payload = json!({
        "source": "rust-diffforge-workspace-revive",
        "event_kind": "workspace_revived",
        "repo_id": repo_id,
        "repo_ids": repo_ids,
        "workspace_id": workspace_id,
        "workspace_name": workspace_name,
        "workspace_location_fingerprint": workspace_location_fingerprint,
        "workspace_root": root_display,
        "device": device_profile.clone(),
        "device_id": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "platform": device_profile["platform"].clone(),
        "form_factor": device_profile["form_factor"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "agent_id": "rust-diffforge",
        "agent_label": "Diff Forge Desktop",
        "reason": "workspace_revive",
        "summary": "Desktop workspace revived in Diff Forge.",
        "ts_ms": cloud_mcp_now_ms(),
    });
    let _ = state
        .global_ws_events
        .send(cloud_mcp_event_envelope("workspace_revived", &payload));
    cloud_mcp_post_event_endpoint(state, "workspace_revived", &payload).await
}

#[tauri::command(rename_all = "snake_case")]
async fn cloud_mcp_delete_workspace(
    state: State<'_, CloudMcpState>,
    repo_path: String,
    workspace_id: String,
    workspace_name: Option<String>,
    include_child_projects: Option<bool>,
) -> Result<Value, String> {
    cloud_mcp_delete_workspace_internal(
        state.inner(),
        repo_path,
        workspace_id,
        workspace_name,
        include_child_projects,
    )
    .await
}

async fn cloud_mcp_delete_workspace_internal(
    state: &CloudMcpState,
    repo_path: String,
    workspace_id: String,
    workspace_name: Option<String>,
    include_child_projects: Option<bool>,
) -> Result<Value, String> {
    let workspace_id = cloud_mcp_workspace_id_match_key(&workspace_id);
    if workspace_id.is_empty() {
        return Err("Workspace delete requires a workspace id.".to_string());
    }
    let deleted_ledger_inserted = cloud_mcp_remember_deleted_workspace_id(&workspace_id)?;
    let platform = cloud_mcp_desktop_platform();
    let purged_todo_mirror_rows =
        cloud_mcp_todo_mirror_purge_workspace(&workspace_id, platform).unwrap_or(0);
    todo_store_orphan_sweep_trigger("workspace_deleted");
    let purged_agent_chat_sync_rows =
        cloud_mcp_agent_chat_purge_workspace_local_sync_state(&workspace_id, platform).unwrap_or(0);

    let root = resolve_workspace_root_directory(Some(&repo_path))?;
    let root_display = workspace_path_display(&root);
    let root_repo_id = cloud_mcp_repo_id_for_root(&root);
    let workspace_name = workspace_name
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| workspace_id.clone());
    let include_child_projects = include_child_projects.unwrap_or(false);
    let mounts = cloud_mcp_container_project_mounts(&root);
    let child_repo_ids = mounts
        .iter()
        .map(|mount| cloud_mcp_repo_id_for_root(&mount.root_path))
        .collect::<Vec<_>>();
    let mut cloud_delete_repo_ids = vec![root_repo_id.clone()];
    if include_child_projects {
        cloud_delete_repo_ids.extend(child_repo_ids.iter().cloned());
        cloud_delete_repo_ids.sort();
        cloud_delete_repo_ids.dedup();
    }

    let (removed_catalog_snapshots, removed_terminal_snapshots, removed_mcp_snapshots) = {
        let mut snapshots = state.runtime_snapshots.lock().await;
        let catalog_removed = cloud_mcp_filter_deleted_workspace_snapshot(
            &mut snapshots.workspace_catalog,
            &workspace_id,
            platform,
            "catalog",
        );
        let terminal_removed = cloud_mcp_filter_deleted_workspace_snapshot(
            &mut snapshots.workspace_terminals,
            &workspace_id,
            platform,
            "terminals",
        );
        let mcp_removed = cloud_mcp_filter_deleted_workspace_snapshot(
            &mut snapshots.workspace_servers,
            &workspace_id,
            platform,
            "mcps",
        );
        cloud_mcp_restore_empty_workspace_snapshot_after_delete(
            &mut snapshots.workspace_catalog,
            catalog_removed,
            "rust-diffforge-workspace-catalog",
            "workspace_deleted",
            "catalog",
        );
        cloud_mcp_restore_empty_workspace_snapshot_after_delete(
            &mut snapshots.workspace_terminals,
            terminal_removed,
            "rust-diffforge-device-live-terminals",
            "workspace_deleted",
            "terminals",
        );
        cloud_mcp_restore_empty_workspace_snapshot_after_delete(
            &mut snapshots.workspace_servers,
            mcp_removed,
            "rust-diffforge-device-live-workspace-mcp-servers",
            "workspace_deleted",
            "mcps",
        );
        (catalog_removed, terminal_removed, mcp_removed)
    };
    {
        let mut runtime = state.inner.lock().await;
        runtime.registered_workspaces.retain(|_, workspace| {
            !cloud_mcp_workspace_id_matches_canonical_or_legacy(
                &workspace_id,
                &workspace.workspace_id,
                platform,
            )
        });
        runtime.terminal_contexts.retain(|_, terminal| {
            !cloud_mcp_workspace_id_matches_canonical_or_legacy(
                &workspace_id,
                &terminal.workspace_id,
                platform,
            )
        });
    }

    let device_profile = cloud_mcp_desktop_device_profile();
    let payload = json!({
        "source": "rust-diffforge-workspace-delete",
        "event_kind": "workspace_deleted",
        "repo_id": root_repo_id,
        "repo_ids": cloud_delete_repo_ids,
        "workspace_id": workspace_id,
        "workspace_name": workspace_name,
        "workspace_location_fingerprint": cloud_mcp_workspace_location_fingerprint(&root),
        "workspace_root": root_display,
        "include_child_projects": include_child_projects,
        "child_repo_count": child_repo_ids.len(),
        "device": device_profile.clone(),
        "device_id": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "platform": device_profile["platform"].clone(),
        "form_factor": device_profile["form_factor"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "agent_id": "rust-diffforge",
        "agent_label": "Diff Forge Desktop",
        "reason": "workspace_delete",
        "summary": "Desktop workspace deleted from Diff Forge.",
        "ts_ms": cloud_mcp_now_ms(),
    });

    let _ = state
        .global_ws_events
        .send(cloud_mcp_event_envelope("workspace_deleted", &payload));
    let response = cloud_mcp_post_event_endpoint(state, "workspace_deleted", &payload).await?;
    Ok(json!({
        "ok": true,
        "workspace_id": payload["workspace_id"].clone(),
        "repo_ids": payload["repo_ids"].clone(),
        "include_child_projects": include_child_projects,
        "removed_terminal_snapshots": removed_terminal_snapshots,
        "removed_mcp_snapshots": removed_mcp_snapshots,
        "removed_catalog_snapshots": removed_catalog_snapshots,
        "deleted_workspace_suppressed": deleted_ledger_inserted,
        "todo_mirror_rows_purged": purged_todo_mirror_rows,
        "agent_chat_sync_rows_purged": purged_agent_chat_sync_rows,
        "server_response": response,
    }))
}

#[tauri::command(rename_all = "snake_case")]
async fn cloud_mcp_delete_agent_chat_session(
    state: State<'_, CloudMcpState>,
    workspace_id: String,
    workspace_name: Option<String>,
    provider: String,
    provider_session_id: String,
    agent_chat_session_id: Option<String>,
    thread_id: Option<String>,
    pane_id: Option<String>,
    reason: Option<String>,
) -> Result<Value, String> {
    let workspace_id = cloud_mcp_workspace_id_match_key(&workspace_id);
    if workspace_id.is_empty() {
        return Err("Agent chat session delete requires a workspace id.".to_string());
    }
    let provider = provider
        .trim()
        .to_ascii_lowercase()
        .replace(['-', ' '], "_");
    if provider.is_empty() {
        return Err("Agent chat session delete requires a provider.".to_string());
    }
    let provider_session_id = provider_session_id.trim().to_string();
    let agent_chat_session_id = agent_chat_session_id
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .unwrap_or_default();
    if provider_session_id.is_empty() && agent_chat_session_id.is_empty() {
        return Err(
            "Agent chat session delete requires a provider session id or cloud session id."
                .to_string(),
        );
    }

    let local_sync_rows = cloud_mcp_agent_chat_purge_local_sync_state(
        &workspace_id,
        cloud_mcp_desktop_platform(),
        &provider,
        &provider_session_id,
        &agent_chat_session_id,
    )
    .unwrap_or(0);
    let purged_mirror_rows = cloud_mcp_todo_mirror_purge_agent_chat_session(
        &workspace_id,
        cloud_mcp_desktop_platform(),
        &provider_session_id,
        &agent_chat_session_id,
    )
    .unwrap_or(0);

    let device_profile = cloud_mcp_desktop_device_profile();
    let reason = reason
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| "agent_chat_session_delete".to_string());
    let payload = json!({
        "source": "rust-diffforge-agent-chat-session-delete",
        "event_kind": "agent_chat_session_deleted",
        "workspace_id": workspace_id,
        "workspace_name": workspace_name.unwrap_or_default(),
        "provider": provider,
        "agent_kind": provider,
        "provider_session_id": provider_session_id,
        "native_session_id": provider_session_id,
        "session_id": provider_session_id,
        "agent_chat_session_id": agent_chat_session_id,
        "thread_id": thread_id.unwrap_or_default(),
        "pane_id": pane_id.unwrap_or_default(),
        "device": device_profile.clone(),
        "device_id": device_profile["device_id"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "rust_authoritative": true,
        "delete_mode": "purge",
        "reason": reason,
        "summary": "Desktop agent chat session deleted from Diff Forge.",
        "ts_ms": cloud_mcp_now_ms()});

    let _ = state.global_ws_events.send(cloud_mcp_event_envelope(
        "agent_chat_session_deleted",
        &payload,
    ));
    let response =
        cloud_mcp_post_event_endpoint(state.inner(), "agent_chat_session_deleted", &payload)
            .await?;
    Ok(json!({
        "ok": true,
        "workspace_id": payload["workspace_id"].clone(),
        "provider": payload["provider"].clone(),
        "provider_session_id": payload["provider_session_id"].clone(),
        "agent_chat_session_id": payload["agent_chat_session_id"].clone(),
        "local_sync_rows_purged": local_sync_rows,
        "todo_mirror_rows_purged": purged_mirror_rows,
        "server_response": response,
    }))
}

#[tauri::command(rename_all = "snake_case")]
async fn cloud_mcp_sync_tokenomics_state(
    app: AppHandle,
    state: State<'_, CloudMcpState>,
    _summary: Value,
    reason: Option<String>,
    delta: Option<bool>,
) -> Result<Value, String> {
    let is_delta = delta.unwrap_or(false);
    let clean_reason = reason
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| {
            if is_delta {
                CLOUD_MCP_TOKENOMICS_DEVICE_DELTA_EVENT.to_string()
            } else {
                CLOUD_MCP_TOKENOMICS_DEVICE_SNAPSHOT_EVENT.to_string()
            }
        });
    let queued_job = cloud_mcp_enqueue_tokenomics_sync(
        app,
        state.inner(),
        clean_reason.clone(),
        !is_delta,
        false,
    )
    .await;
    Ok(cloud_mcp_background_sync_ack(
        "tokenomics_sync",
        "tokenomics:scan",
        &clean_reason,
        json!({
            "delta": is_delta,
            "full": queued_job.force_full,
            "queued_reason": clean_reason,
            "queued": true,
            "local_only": false,
            "enqueued_ms": queued_job.enqueued_ms,
            "force_resync": queued_job.force_resync,
            "sync_protocol": CLOUD_MCP_TOKENOMICS_SYNC_PROTOCOL,
            "tokenomics_event_kind": if is_delta {
                CLOUD_MCP_TOKENOMICS_DEVICE_DELTA_EVENT
            } else {
                CLOUD_MCP_TOKENOMICS_DEVICE_SNAPSHOT_EVENT
            },
        }),
    ))
}

#[tauri::command(rename_all = "snake_case")]
async fn cloud_mcp_schedule_tokenomics_sync(
    app: AppHandle,
    state: State<'_, CloudMcpState>,
    reason: Option<String>,
    full: Option<bool>,
    resync_last_30_days: Option<bool>,
) -> Result<Value, String> {
    let clean_reason = reason
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| CLOUD_MCP_TOKENOMICS_DEVICE_DELTA_EVENT.to_string());
    let force_full = full.unwrap_or(false);
    let force_resync = resync_last_30_days.unwrap_or(false);
    let queued_job = cloud_mcp_enqueue_tokenomics_sync(
        app,
        state.inner(),
        clean_reason.clone(),
        force_full,
        force_resync,
    )
    .await;

    Ok(cloud_mcp_background_sync_ack(
        "tokenomics_sync",
        "tokenomics:scan",
        &clean_reason,
        json!({
            "full": queued_job.force_full,
            "resync_last_30_days": queued_job.force_resync,
            "queued_reason": clean_reason,
            "queued": true,
            "local_only": false,
            "enqueued_ms": queued_job.enqueued_ms,
        }),
    ))
}

#[tauri::command(rename_all = "snake_case")]
async fn cloud_mcp_reset_device_tokenomics(
    state: State<'_, CloudMcpState>,
) -> Result<Value, String> {
    let device_profile = cloud_mcp_desktop_device_profile();
    let device_id = cloud_mcp_payload_text(&device_profile, &["device_id", "machine_id"])
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .ok_or_else(|| "Unable to determine the native desktop device id.".to_string())?;
    let (billing_scope_type, team_id) = cloud_mcp_account_scope(state.inner()).await;
    let billing_scope_key =
        tokenomics_billing_scope_key(billing_scope_type.as_str(), team_id.as_deref());
    {
        let mut tokenomics_cursor = state.background_sync.tokenomics_cursor.lock().await;
        tokenomics_cursor.remove(&billing_scope_key);
    }
    let _ = cloud_mcp_tokenomics_clear_sync_state(&device_id, &billing_scope_key);
    Ok(json!({
        "ok": true,
        "local_only": true,
        "sync_queued": false,
        "device_id": device_id,
        "billing_scope_type": billing_scope_type,
        "billing_scope_key": billing_scope_key,
        "team_id": team_id,
        "sync": cloud_mcp_background_sync_ack(
            "tokenomics_sync",
            "tokenomics:scan",
            "tokenomics_device_local_reset",
            json!({
                "full": false,
                "resync_last_30_days": false,
                "queued": false,
                "local_only": true,
                "queued_reason": "tokenomics_device_local_reset",
            }),
        ),
    }))
}

fn cloud_mcp_tokenomics_cursor_from_summary(summary: &Value) -> Option<String> {
    let direct = summary
        .get("sc")
        .or_else(|| summary.get("sync_cursor"))
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string);
    if direct.is_some() {
        return direct;
    }

    summary
        .get("hourly")
        .and_then(Value::as_array)
        .and_then(|rows| {
            rows.iter()
                .filter_map(|row| {
                    row.get("updated_at")
                        .and_then(Value::as_str)
                        .map(str::trim)
                        .filter(|value| !value.is_empty())
                        .map(str::to_string)
                })
                .max()
        })
}

fn cloud_mcp_tag_tokenomics_summary_device(summary: &mut Value, device_profile: &Value) {
    let Some(device_id) = cloud_mcp_payload_text(device_profile, &["device_id", "machine_id"])
    else {
        return;
    };
    let device_name = cloud_mcp_payload_text(device_profile, &["device_name"]);
    for key in [
        "hourly",
        "limits",
        "limit_samples",
        "provider_accounts",
        "latest_windows",
    ] {
        if let Some(rows) = summary.get_mut(key).and_then(Value::as_array_mut) {
            for row in rows {
                let Some(object) = row.as_object_mut() else {
                    continue;
                };
                let has_device = object
                    .get("device_id")
                    .and_then(Value::as_str)
                    .map(str::trim)
                    .is_some_and(|value| !value.is_empty());
                if !has_device {
                    object.insert("device_id".to_string(), json!(device_id.as_str()));
                }
                if let Some(name) = device_name.as_deref() {
                    object
                        .entry("device_name".to_string())
                        .or_insert_with(|| json!(name));
                }
            }
        }
    }
}

#[tauri::command(rename_all = "snake_case")]
async fn cloud_mcp_reset_server_state(
    state: State<'_, CloudMcpState>,
    repo_path: String,
    workspace_id: String,
    workspace_name: Option<String>,
    reset_scope: Option<String>,
    repo_id_override: Option<String>,
    dry_run: Option<bool>,
) -> Result<Value, String> {
    let req = cloud_mcp_repo_request(
        repo_path.clone(),
        Some(workspace_id.clone()),
        workspace_name.clone(),
    );
    let device_profile = cloud_mcp_desktop_device_profile();
    let requested_reset_scope = reset_scope
        .as_deref()
        .map(str::trim)
        .filter(|scope| !scope.is_empty())
        .unwrap_or("repo")
        .to_ascii_lowercase();
    let reset_scope = match requested_reset_scope.as_str() {
        "repo" | "repository" | "git_repo" | "git-repo" => "repo",
        "repo_delete" | "repo-delete" | "repo_purge" | "repo-purge" => "repo_delete",
        "workspace" | "workspace_runtime" | "workspace-runtime" => "workspace",
        _ => "repo",
    };
    // Cloud-only repos have no local checkout, so the caller may address them
    // by the repo id recorded in the account catalog instead of a local path.
    let repo_id = repo_id_override
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
        .unwrap_or_else(|| req.repo_id.clone());
    let dry_run = dry_run.unwrap_or(false);
    let payload = json!({
        "source": "rust-diffforge-server-state-reset",
        "client_id": CLOUD_MCP_RUST_CLIENT_ID,
        "repo_id": repo_id,
        "repo_path": req.root_display,
        "workspace_root": req.root_display,
        "workspace_id": workspace_id,
        "workspace_name": workspace_name,
        "scope": reset_scope,
        "dry_run": dry_run,
        "confirm": "reset_server_state",
        "preserve": {
            "devices": true,
            "billing": true,
            "tokenomics": true,
        },
        "device": device_profile.clone(),
        "device_id": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "platform": device_profile["platform"].clone(),
        "form_factor": device_profile["form_factor"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "agent_id": "rust-diffforge",
        "self_agent_id": "rust-diffforge",
        "current_agent_id": "rust-diffforge",
        "ts_ms": cloud_mcp_now_ms(),
    });
    let response =
        cloud_mcp_post_json_endpoint(state.inner(), "/v1/cloud/server-reset", &payload).await?;
    if !dry_run {
        let mut snapshots = state.runtime_snapshots.lock().await;
        *snapshots = CloudMcpRuntimeSnapshots::default();
    }
    Ok(cloud_mcp_response_data(&response))
}

