    #[test]
    fn workspace_panel_kind_accepts_vm_and_swarm_aliases() {
        for (kind, expected) in [
            ("vm", "vm"),
            ("vm-sandbox", "vm"),
            ("virtual_machine", "vm"),
            ("swarm", "swarm"),
            ("swarm-panel", "swarm"),
            ("agent-swarm", "swarm"),
        ] {
            assert_eq!(
                cloud_mcp_workspace_panel_kind(&json!({ "panel_kind": kind })).as_deref(),
                Some(expected),
                "{kind} should map to {expected}",
            );
        }
    }

