    fn assert_account_document_snake_only(value: &Value) {
        fn visit(value: &Value, path: &str) {
            match value {
                Value::Object(object) => {
                    for (key, child) in object {
                        assert!(
                            !CLOUD_MCP_ACCOUNT_DOCUMENT_LEGACY_CAMEL_KEYS.contains(&key.as_str()),
                            "legacy account document key {key} at {path}"
                        );
                        let child_path = if path.is_empty() {
                            key.to_string()
                        } else {
                            format!("{path}.{key}")
                        };
                        visit(child, &child_path);
                    }
                }
                Value::Array(items) => {
                    for (index, child) in items.iter().enumerate() {
                        visit(child, &format!("{path}[{index}]"));
                    }
                }
                _ => {}
            }
        }

        visit(value, "$");
    }

    #[test]
    fn account_document_cache_writes_canonical_file_and_keeps_metadata_only() {
        let _guard = CLOUD_MCP_TEST_ENV_LOCK
            .get_or_init(|| StdMutex::new(()))
            .lock()
            .unwrap();
        let data_root = test_cloud_root("diffforge-account-document-data");
        let cache_root = test_cloud_root("diffforge-account-document-cache");
        let _data_env = ScopedCloudMcpEnv::set(CLOUD_MCP_LOCAL_DATA_DIR_ENV, &data_root);
        let _cache_env = ScopedCloudMcpEnv::set(CLOUD_MCP_LOCAL_CACHE_DIR_ENV, &cache_root);
        let content = "# Quarterly Plan\n\nShip account documents.\n";
        let input = json!({
            "scope_key": "Personal Account",
            "collection": "documents",
            "document_id": "Quarterly Plan",
            "title": "Quarterly Plan",
            "content": content,
            "metadata": {
                "content": "nested content should not be cached"
            }
        });

        let row = cloud_mcp_account_document_write_inline_content(&input)
            .unwrap()
            .unwrap();
        let path = cloud_mcp_account_document_local_path_for_parts(
            "Personal Account",
            "documents",
            "Quarterly Plan",
            "md",
        )
        .unwrap();

        assert_eq!(
            path,
            data_root
                .join("account-documents")
                .join("Personal-Account")
                .join("collections")
                .join("documents")
                .join("Quarterly-Plan.md")
        );
        assert_eq!(fs::read_to_string(&path).unwrap(), content);
        assert!(row.get("content").is_none());
        assert_account_document_snake_only(&row);

        let rows = cloud_mcp_account_document_cache_rows(
            &json!({
                "scope_key": "Personal Account",
                "collection": "documents",
                "document_id": "Quarterly Plan",
            }),
            10,
        )
        .unwrap();
        assert_eq!(rows.len(), 1);
        let cached = &rows[0];
        assert_eq!(cached["local_path"], json!(path.display().to_string()));
        assert!(cached.get("content").is_none());
        assert!(cached.get("content_md").is_none());
        assert!(cached.get("contentMd").is_none());
        assert!(cached["metadata"].get("content").is_none());
        assert_account_document_snake_only(cached);

        let projection = cloud_mcp_account_documents_projection(rows.clone(), None);
        assert_account_document_snake_only(&projection);

        let _ = fs::remove_dir_all(data_root);
        let _ = fs::remove_dir_all(cache_root);
    }

    #[test]
    fn account_document_remote_metadata_does_not_read_local_path_as_content() {
        let _guard = CLOUD_MCP_TEST_ENV_LOCK
            .get_or_init(|| StdMutex::new(()))
            .lock()
            .unwrap();
        let data_root = test_cloud_root("diffforge-account-document-remote-meta-data");
        let cache_root = test_cloud_root("diffforge-account-document-remote-meta-cache");
        let _data_env = ScopedCloudMcpEnv::set(CLOUD_MCP_LOCAL_DATA_DIR_ENV, &data_root);
        let _cache_env = ScopedCloudMcpEnv::set(CLOUD_MCP_LOCAL_CACHE_DIR_ENV, &cache_root);
        let stale_path = data_root.join("stale.md");
        fs::create_dir_all(stale_path.parent().unwrap()).unwrap();
        fs::write(&stale_path, "old local content").unwrap();
        let remote_hash = "f7381cee8a0478d958b5";
        let input = json!({
            "scope_key": "Personal Account",
            "collection": "documents",
            "document_id": "starter",
            "title": "starter",
            "local_path": stale_path.display().to_string(),
            "content_hash": remote_hash,
            "asset_id": "asset-account-document-starter-f7381cee8a04",
            "size_bytes": 34,
        });

        assert!(cloud_mcp_account_document_write_inline_content(&input)
            .unwrap()
            .is_none());
        let row = cloud_mcp_account_document_metadata_row(
            &input,
            None,
            None,
            None,
            Some("remote_metadata"),
        )
        .unwrap();
        cloud_mcp_store_account_document_metadata(&row).unwrap();
        let rows = cloud_mcp_account_document_cache_rows(
            &json!({
                "scope_key": "Personal Account",
                "collection": "documents",
                "document_id": "starter",
            }),
            10,
        )
        .unwrap();

        assert_eq!(rows.len(), 1);
        assert_eq!(rows[0]["content_hash"], json!(remote_hash));
        assert_account_document_snake_only(&row);
        assert_account_document_snake_only(&rows[0]);
        assert_ne!(
            rows[0]["content_hash"],
            json!(format!(
                "{:x}",
                Sha256::digest("old local content".as_bytes())
            ))
        );

        let _ = fs::remove_dir_all(data_root);
        let _ = fs::remove_dir_all(cache_root);
    }

    #[test]
    fn account_document_metadata_apply_materializes_current_local_file() {
        let _guard = CLOUD_MCP_TEST_ENV_LOCK
            .get_or_init(|| StdMutex::new(()))
            .lock()
            .unwrap();
        let data_root = test_cloud_root("diffforge-account-document-local-current-data");
        let cache_root = test_cloud_root("diffforge-account-document-local-current-cache");
        let _data_env = ScopedCloudMcpEnv::set(CLOUD_MCP_LOCAL_DATA_DIR_ENV, &data_root);
        let _cache_env = ScopedCloudMcpEnv::set(CLOUD_MCP_LOCAL_CACHE_DIR_ENV, &cache_root);
        let content = "Already here locally.";
        let content_hash = format!("{:x}", Sha256::digest(content.as_bytes()));
        let path = cloud_mcp_account_document_local_path_for_file_path(
            "Personal Account",
            "documents",
            "starter.md",
        )
        .unwrap();
        fs::create_dir_all(path.parent().unwrap()).unwrap();
        fs::write(&path, content).unwrap();

        let applied = cloud_mcp_apply_account_documents_sync_data(
            &json!({
                "c": "doc.sync",
                "d": "documents",
                "documents": [{
                    "scope_key": "Personal Account",
                    "collection": "documents",
                    "document_id": "starter",
                    "file_path": "starter.md",
                    "path_key": "starter.md",
                    "title": "starter",
                    "content_hash": content_hash,
                    "asset_id": "asset-account-document-starter",
                    "size_bytes": content.as_bytes().len(),
                }]
            }),
            "test_local_current_metadata",
        )
        .unwrap();

        assert_eq!(applied["upserted_count"], json!(1));
        assert_eq!(applied["documents"][0]["content_md"], json!(content));
        assert_eq!(applied["documents"][0]["has_content_payload"], json!(true));
        let rows = cloud_mcp_account_document_cache_rows(
            &json!({
                "scope_key": "Personal Account",
                "collection": "documents",
                "document_id": "starter",
            }),
            10,
        )
        .unwrap();
        assert_eq!(rows.len(), 1);
        assert!(rows[0].get("content_md").is_none());
        assert_account_document_snake_only(&applied);
        assert_account_document_snake_only(&rows[0]);

        let _ = fs::remove_dir_all(data_root);
        let _ = fs::remove_dir_all(cache_root);
    }

    #[test]
    fn account_document_prepare_draft_writes_overlay_without_touching_canonical() {
        let _guard = CLOUD_MCP_TEST_ENV_LOCK
            .get_or_init(|| StdMutex::new(()))
            .lock()
            .unwrap();
        let data_root = test_cloud_root("diffforge-account-document-draft-data");
        let cache_root = test_cloud_root("diffforge-account-document-draft-cache");
        let _data_env = ScopedCloudMcpEnv::set(CLOUD_MCP_LOCAL_DATA_DIR_ENV, &data_root);
        let _cache_env = ScopedCloudMcpEnv::set(CLOUD_MCP_LOCAL_CACHE_DIR_ENV, &cache_root);
        let canonical = cloud_mcp_account_document_local_path_for_file_path(
            "Personal Account",
            "documents",
            "DraftSource.md",
        )
        .unwrap();
        let original_content = "# Original\n";
        let draft_content = "# Draft\n";
        cloud_mcp_write_account_document_file(&canonical, original_content).unwrap();
        let original_hash = format!("{:x}", Sha256::digest(original_content.as_bytes()));

        let result =
            tauri::async_runtime::block_on(cloud_mcp_prepare_account_document_draft(json!({
                "document": {
                    "scope_key": "Personal Account",
                    "collection": "documents",
                    "document_id": "DraftSource",
                    "title": "DraftSource",
                    "file_path": "DraftSource.md",
                    "content": draft_content,
                    "content_md": draft_content,
                },
                "local_only": true,
                "reuse_existing": false,
            })))
            .unwrap();
        let draft_path = PathBuf::from(result["draft_path"].as_str().unwrap());

        assert!(draft_path.starts_with(
            data_root
                .join("account-documents")
                .join("drafts")
                .join("Personal-Account")
        ));
        assert_eq!(fs::read_to_string(&draft_path).unwrap(), draft_content);
        assert_eq!(fs::read_to_string(&canonical).unwrap(), original_content);
        assert_eq!(result["base_content_hash"], json!(original_hash));
        assert_eq!(result["document"]["draft"], json!(true));
        assert_eq!(result["document"]["sync_status"], json!("draft"));
        assert_ne!(result["draft_path"], result["canonical_local_path"]);

        let _ = fs::remove_dir_all(data_root);
        let _ = fs::remove_dir_all(cache_root);
    }

