    #[test]
    fn workspace_mcp_server_content_hash_ignores_runtime_ordering() {
        let workspace_a = json!({
            "workspace_id": "workspace-a",
            "workspace_name": "Workspace A",
            "workspace_active": true,
            "workspace_status": "active",
            "workspace_runtime_seq": 10,
            "workspace_runtime_epoch": "runtime-a",
            "workspace_order": 1
        });
        let workspace_b = json!({
            "workspace_id": "workspace-a",
            "workspace_name": "Workspace A",
            "workspace_active": true,
            "workspace_status": "active",
            "workspace_runtime_seq": 999,
            "workspace_runtime_epoch": "runtime-b",
            "workspace_order": 42
        });
        let server = json!({
            "server_key": "appwrite",
            "name": "Appwrite",
            "workspace_enabled": true,
            "tools": ["search", "create"],
            "tool_count": 2
        });
        let changed_server = json!({
            "server_key": "appwrite",
            "name": "Appwrite",
            "workspace_enabled": true,
            "tools": ["search", "delete"],
            "tool_count": 2
        });

        let first =
            cloud_mcp_workspace_mcp_server_content_hash("workspace-a", &workspace_a, &server);
        let second =
            cloud_mcp_workspace_mcp_server_content_hash("workspace-a", &workspace_b, &server);
        let changed = cloud_mcp_workspace_mcp_server_content_hash(
            "workspace-a",
            &workspace_b,
            &changed_server,
        );

        assert_eq!(first, second);
        assert_ne!(first, changed);
    }

    #[test]
    fn route_pending_errors_map_to_initializing_with_bounded_retry() {
        let error = "Cloud MCP route pending: route_state=assignment_booting; backend_status=booting; retry_after_ms=12000";
        assert_eq!(
            cloud_mcp_route_error_runtime_status(error),
            Some("route_initializing")
        );
        assert_eq!(cloud_mcp_route_error_retry_after_ms(error), Some(12000));
        assert_eq!(
            cloud_mcp_route_initializing_poll_delay(error),
            Duration::from_millis(CLOUD_MCP_ROUTE_INITIALIZING_MAX_POLL_MS)
        );

        let no_hint =
            "Cloud MCP route pending: route_state=route_not_configured; backend_status=active";
        assert_eq!(
            cloud_mcp_route_initializing_poll_delay(no_hint),
            Duration::from_millis(CLOUD_MCP_ROUTE_INITIALIZING_DEFAULT_POLL_MS)
        );

        let waiting_route = json!({
            "ok": false,
            "route_state": "waiting",
            "retry_after_ms": 5000
        });
        let waiting_error = cloud_mcp_direct_route_pending_error(&waiting_route)
            .expect("waiting routes should stay retryable");
        assert_eq!(
            cloud_mcp_route_error_runtime_status(&waiting_error),
            Some("route_initializing")
        );
        assert_eq!(
            cloud_mcp_route_error_retry_after_ms(&waiting_error),
            Some(5000)
        );

        let legacy_waiting_error = "Cloud MCP route rejected: route_state=waiting; route rejected";
        assert_eq!(
            cloud_mcp_route_error_runtime_status(legacy_waiting_error),
            Some("route_initializing")
        );

        let deactivated_error = "Cloud MCP route request returned 503: backend_status=deactivated";
        assert_eq!(
            cloud_mcp_route_error_runtime_status(deactivated_error),
            Some("route_initializing")
        );
    }

