    #[test]
    fn create_plan_is_plan_only_without_task() {
        let input = json!({
            "task_id": "ignored-task-id",
            "plan_id": "plan-1",
            "title": "Ship local todo plans",
            "steps": [
                "Inspect current create_plan",
                {
                    "title": "Patch create_plan",
                    "detail": "Render the plan in the Plans tab without generating todos."
                }
            ]
        });
        let rows = cloud_mcp_agent_create_plan_todo_rows(
            Some("repo-1"),
            Some("/repo"),
            Some("workspace-a"),
            Some("Workspace A"),
            Some("agent-a"),
            Some("session-a"),
            &input,
            &json!({"device_id": "device-a", "device_name": "Desktop A"}),
            "2026-06-08T00:00:00Z",
        )
        .unwrap();

        assert_eq!(rows.plan_id, "plan-1");
        assert_eq!(rows.compact_plan["plan_id"].as_str(), Some("plan-1"));
        assert_eq!(rows.compact_plan["todo_id"].as_str(), Some("plan-1-todo-1"));
        assert_eq!(
            rows.compact_plan["todo_ids"].as_array().map(Vec::len),
            Some(2)
        );
        assert_eq!(rows.todo_rows.len(), 2);
        assert!(cloud_mcp_validate_agent_create_plan_rows(&rows).is_ok());
        assert!(rows.todo_rows.iter().all(|row| {
            row["plan_id"].as_str() == Some("plan-1")
                && row["todo_id"]
                    .as_str()
                    .is_some_and(|value| !value.is_empty())
                && row["local_only"].as_bool() == Some(true)
                && row["server_sync_queued"].as_bool() == Some(false)
        }));
        assert!(rows
            .dispatch_rows
            .iter()
            .all(|row| row.get("task_id").is_none()));

        let mut invalid_rows = rows.clone();
        invalid_rows.todo_rows[0]
            .as_object_mut()
            .unwrap()
            .remove("todo_id");
        invalid_rows.todo_rows[0]
            .as_object_mut()
            .unwrap()
            .remove("id");
        assert!(cloud_mcp_validate_agent_create_plan_rows(&invalid_rows)
            .unwrap_err()
            .contains("todo_id"));

        let created = cloud_mcp_record_agent_create_plan_todos(
            Some("/repo"),
            Some("workspace-a"),
            None,
            Some("agent-a"),
            Some("session-a"),
            &input,
        )
        .unwrap();
        assert_eq!(created["plan_id"].as_str(), Some("plan-1"));
        assert_eq!(created["todo_id"].as_str(), Some("plan-1-todo-1"));
        assert_eq!(created["todos_generated"].as_bool(), Some(false));
        assert_eq!(created["server_sync_queued"].as_bool(), Some(false));
        assert_eq!(created["local_only"].as_bool(), Some(true));
        assert_eq!(created["todos"].as_array().map(Vec::len), Some(0));
        assert_eq!(created["dispatches"].as_array().map(Vec::len), Some(0));
        assert_eq!(created["step_count"].as_u64(), Some(2));
        assert_eq!(
            created["stored_in"],
            json!(["terminal_todo_plans", "terminal_todo_plan_steps"])
        );
        assert_eq!(
            created["compact_plan"]["steps"].as_array().map(Vec::len),
            Some(2)
        );
    }

    #[tokio::test]
    async fn remote_command_receipt_claim_dedupes_command_ids() {
        let state = CloudMcpState::new();
        let event = json!({
            "client_id": "client-1",
            "workspace_id": "workspace-1",
            "command_id": "remote-command-123",
            "command_kind": "todo_create",
            "event_kind": "remote_command_requested",
        });

        assert!(cloud_mcp_claim_remote_command_receipt(&state, &event).await);
        assert!(!cloud_mcp_claim_remote_command_receipt(&state, &event).await);

        let same_todo_delete = json!({
            "client_id": "client-1",
            "workspace_id": "workspace-1",
            "command_id": "remote-command-123",
            "command_kind": "todo_delete",
            "event_kind": "remote_command_requested",
        });
        assert!(cloud_mcp_claim_remote_command_receipt(&state, &same_todo_delete).await);

        let other_workspace = json!({
            "client_id": "client-1",
            "workspace_id": "workspace-2",
            "command_id": "remote-command-123",
            "command_kind": "todo_create",
            "event_kind": "remote_command_requested",
        });
        assert!(cloud_mcp_claim_remote_command_receipt(&state, &other_workspace).await);
    }

    #[test]
    fn duplicate_ui_commands_redeliver_without_replaying_rust_owned_work() {
        let workspace_activate = json!({
            "command_kind": "workspace_activate",
            "command_id": "activate-1",
        });
        assert!(cloud_mcp_duplicate_remote_command_is_ui_retry_for(
            &workspace_activate,
            true,
            false,
        ));
        assert!(!cloud_mcp_duplicate_remote_command_is_ui_retry_for(
            &workspace_activate,
            false,
            false,
        ));
        assert!(!cloud_mcp_duplicate_remote_command_is_ui_retry_for(
            &workspace_activate,
            true,
            true,
        ));

        let rust_owned_todo = json!({
            "command_kind": "todo_create",
            "command_id": "todo-1",
        });
        assert!(!cloud_mcp_duplicate_remote_command_is_ui_retry_for(
            &rust_owned_todo,
            true,
            false,
        ));

        for command_kind in ["agent_update", "update_agent", "cli_update"] {
            let rust_owned_update = json!({
                "command_kind": command_kind,
                "command_id": format!("{command_kind}-1"),
            });
            assert!(cloud_mcp_remote_command_is_rust_owned(&rust_owned_update));
            assert!(!cloud_mcp_duplicate_remote_command_is_ui_retry_for(
                &rust_owned_update,
                true,
                false,
            ));
        }
    }

