#[derive(Clone, Debug)]
struct CloudMcpProxyIdentity {
    base_url: Option<String>,
    repo_path: Option<PathBuf>,
    repo_id: Option<String>,
    workspace_id: Option<String>,
    workspace_name: Option<String>,
    agent_id: Option<String>,
    session_id: Option<String>,
    coordination_db_path: Option<PathBuf>,
    pane_id: Option<String>,
    terminal_instance_id: Option<String>,
    slot_key: Option<String>,
    agent_label: Option<String>,
    client_id: String,
}

impl CloudMcpProxyIdentity {
    fn from_args(args: &[String]) -> Self {
        let mut values = std::collections::HashMap::<String, String>::new();
        let mut index = 0;
        while index < args.len() {
            if let Some(key) = args[index].strip_prefix("--") {
                if let Some(value) = args.get(index + 1) {
                    if !value.starts_with("--") {
                        values.insert(key.to_string(), value.to_string());
                        index += 2;
                        continue;
                    }
                }
                values.insert(key.to_string(), "true".to_string());
            }
            index += 1;
        }

        let repo_path = values
            .get("repo-path")
            .cloned()
            .or_else(|| env::var("CLOUD_MCP_REPO_PATH").ok())
            .or_else(|| {
                env::current_dir()
                    .ok()
                    .map(|path| path.to_string_lossy().to_string())
            })
            .map(PathBuf::from);

        let repo_id = values
            .get("repo-id")
            .cloned()
            .or_else(|| env::var("CLOUD_MCP_REPO_ID").ok());

        let workspace_id = values
            .get("workspace-id")
            .cloned()
            .or_else(|| env::var("CLOUD_MCP_WORKSPACE_ID").ok());

        let workspace_name = values
            .get("workspace-name")
            .cloned()
            .or_else(|| env::var("CLOUD_MCP_WORKSPACE_NAME").ok());

        let agent_id = values
            .get("agent-id")
            .cloned()
            .or_else(|| env::var("CLOUD_MCP_AGENT_ID").ok())
            .or_else(|| env::var("DIFFFORGE_AGENT_ID").ok())
            .or_else(|| env::var("COORDINATION_AGENT_ID").ok());

        let session_id = values
            .get("session-id")
            .cloned()
            .or_else(|| env::var("CLOUD_MCP_SESSION_ID").ok())
            .or_else(|| env::var("DIFFFORGE_SESSION_ID").ok());

        let coordination_db_path = values
            .get("db-path")
            .cloned()
            .or_else(|| env::var("COORDINATION_DB_PATH").ok())
            .map(PathBuf::from);

        let pane_id = values
            .get("pane-id")
            .cloned()
            .or_else(|| env::var("CLOUD_MCP_PANE_ID").ok())
            .or_else(|| env::var("DIFFFORGE_PANE_ID").ok());

        let terminal_instance_id = values
            .get("terminal-instance-id")
            .cloned()
            .or_else(|| env::var("CLOUD_MCP_TERMINAL_INSTANCE_ID").ok())
            .or_else(|| env::var("DIFFFORGE_TERMINAL_INSTANCE_ID").ok());

        let slot_key = values
            .get("slot-key")
            .cloned()
            .or_else(|| env::var("COORDINATION_SLOT_KEY").ok())
            .or_else(|| env::var("CLOUD_MCP_SLOT_KEY").ok());

        let agent_label = values
            .get("agent-label")
            .cloned()
            .or_else(|| env::var("CLOUD_MCP_AGENT_LABEL").ok())
            .or_else(|| agent_id.as_deref().and_then(cloud_mcp_short_agent_label));

        let base_url = None;

        let client_id = values
            .get("client-id")
            .cloned()
            .or_else(|| env::var("CLOUD_MCP_CLIENT_ID").ok())
            .unwrap_or_else(|| "rust-diffforge-terminal".to_string());

        Self {
            base_url,
            repo_path,
            repo_id,
            workspace_id,
            workspace_name,
            agent_id,
            session_id,
            coordination_db_path,
            pane_id,
            terminal_instance_id,
            slot_key,
            agent_label,
            client_id,
        }
    }

    fn cloud_agent_id(&self) -> Option<String> {
        cloud_mcp_stable_agent_id(self.agent_id.as_deref())
    }

    fn log(&self, phase: &str, tool_name: &str, fields: Value) {
        let Some(repo_path) = self.repo_path.as_ref() else {
            return;
        };
        let repo_path_text = repo_path.to_string_lossy().to_string();
        let root = resolve_workspace_root_directory(Some(&repo_path_text))
            .unwrap_or_else(|_| repo_path.clone());
        let mut payload = serde_json::Map::new();
        payload.insert("tool".to_string(), json!(tool_name));
        payload.insert("client_id".to_string(), json!(self.client_id));
        if let Some(repo_id) = self.repo_id.as_deref() {
            payload.insert("repo_id".to_string(), json!(repo_id));
        }
        if let Some(agent_id) = self.agent_id.as_deref() {
            payload.insert("agent_id".to_string(), json!(agent_id));
        }
        if let Some(session_id) = self.session_id.as_deref() {
            payload.insert("session_id".to_string(), json!(session_id));
        }
        if let Some(pane_id) = self.pane_id.as_deref() {
            payload.insert("pane_id".to_string(), json!(pane_id));
        }
        if let Some(slot_key) = self.slot_key.as_deref() {
            payload.insert("slot_key".to_string(), json!(slot_key));
        }
        if let Some(agent_label) = self.agent_label.as_deref() {
            payload.insert("agent_label".to_string(), json!(agent_label));
        }
        if let Some(terminal_instance_id) = self.terminal_instance_id.as_deref() {
            payload.insert(
                "terminal_instance_id".to_string(),
                json!(terminal_instance_id),
            );
        }
        if let Some(extra) = fields.as_object() {
            for (key, value) in extra {
                payload.insert(key.clone(), value.clone());
            }
        }

        let _ = cloud_mcp_workspace_log(
            &root,
            phase,
            self.workspace_id.as_deref().unwrap_or(""),
            self.workspace_name.as_deref().unwrap_or(""),
            Value::Object(payload),
        );
    }
}

pub(crate) fn cloud_mcp_forward_agent_list_todo_targets(
    repo_path: Option<&str>,
    _db_path: Option<&Path>,
    workspace_id: Option<&str>,
    _base_url_override: Option<&str>,
    _agent_id: Option<&str>,
    _session_id: Option<&str>,
) -> Result<Value, String> {
    let repo_path_text = repo_path
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string);
    let repo_id = repo_path_text
        .as_deref()
        .map(|value| format!("repo-{}", cloud_mcp_short_hash(value)));
    Ok(cloud_mcp_todo_targets_from_file(
        repo_id.as_deref(),
        workspace_id,
    ))
}

pub(crate) fn cloud_mcp_forward_agent_list_assets(
    _repo_path: Option<&str>,
    _workspace_id: Option<&str>,
    input: &Value,
) -> Result<Value, String> {
    let limit = cloud_mcp_payload_i64(input, &["limit"])
        .unwrap_or(100)
        .max(1) as usize;
    let library = cloud_mcp_asset_library_from_file(limit);
    Ok(cloud_mcp_filter_asset_library_for_agent(input, library))
}

fn cloud_mcp_filter_asset_library_for_agent(input: &Value, library: Value) -> Value {
    let asset_ids = cloud_mcp_todo_mirror_text_values(input, &["asset_id", "asset_ids"]);
    let transfer_ids = cloud_mcp_todo_mirror_text_values(input, &["transfer_id", "transfer_ids"]);
    let device_ids =
        cloud_mcp_todo_mirror_text_values(input, &["device_id", "device_ids", "machine_id"]);
    let direction = cloud_mcp_payload_text(input, &["direction"])
        .map(|value| value.trim().to_ascii_lowercase());
    let transfer_status = cloud_mcp_payload_text(input, &["transfer_status"])
        .map(|value| value.trim().to_ascii_lowercase())
        .or_else(|| {
            cloud_mcp_payload_bool(input, &["active_only"], false).then(|| "active".to_string())
        });
    let asset_status =
        cloud_mcp_payload_text(input, &["status"]).map(|value| value.trim().to_ascii_lowercase());
    let kind =
        cloud_mcp_payload_text(input, &["kind"]).map(|value| value.trim().to_ascii_lowercase());

    let mut rows = library
        .get("items")
        .or_else(|| library.get("assets"))
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    rows.retain(|row| {
        if !asset_ids.is_empty() {
            let row_asset_id = cloud_mcp_asset_row_text(row, &["asset_id", "id"]);
            if !asset_ids.contains(&row_asset_id) {
                return false;
            }
        }
        if let Some(asset_status) = asset_status.as_deref() {
            let row_status =
                cloud_mcp_asset_row_text(row, &["cloud_status", "local_status", "status"])
                    .to_ascii_lowercase();
            if row_status != asset_status {
                return false;
            }
        }
        if let Some(kind) = kind.as_deref() {
            let row_kind =
                cloud_mcp_asset_row_text(row, &["kind", "asset_kind"]).to_ascii_lowercase();
            if row_kind != kind {
                return false;
            }
        }
        if !device_ids.is_empty() {
            let row_device_id = cloud_mcp_asset_row_text(row, &["origin_device_id", "device_id"]);
            if !device_ids.contains(&row_device_id) {
                return false;
            }
        }
        true
    });

    let visible_asset_ids = rows
        .iter()
        .map(|row| cloud_mcp_asset_row_text(row, &["asset_id", "id"]))
        .filter(|asset_id| !asset_id.is_empty())
        .collect::<HashSet<_>>();
    let mut transfers = library
        .get("transfers")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    transfers.retain(|transfer| {
        let transfer_asset_id = cloud_mcp_asset_row_text(transfer, &["asset_id"]);
        if !asset_ids.is_empty() && !asset_ids.contains(&transfer_asset_id) {
            return false;
        }
        let transfer_id = cloud_mcp_asset_row_text(transfer, &["transfer_id", "id"]);
        if !transfer_ids.is_empty() && !transfer_ids.contains(&transfer_id) {
            return false;
        }
        if !visible_asset_ids.is_empty() && !visible_asset_ids.contains(&transfer_asset_id) {
            return false;
        }
        if let Some(direction) = direction.as_deref() {
            if cloud_mcp_asset_row_text(transfer, &["direction"]).to_ascii_lowercase() != direction
            {
                return false;
            }
        }
        if !device_ids.is_empty() {
            let transfer_device_id =
                cloud_mcp_asset_row_text(transfer, &["device_id", "machine_id"]);
            if !device_ids.contains(&transfer_device_id) {
                return false;
            }
        }
        if let Some(status) = transfer_status.as_deref() {
            let row_status = cloud_mcp_asset_row_text(transfer, &["status"]).to_ascii_lowercase();
            if status == "active" {
                if !cloud_mcp_asset_transfer_status_is_active(&row_status) {
                    return false;
                }
            } else if row_status != status {
                return false;
            }
        }
        true
    });
    cloud_mcp_asset_library_response_from_rows(rows, transfers, None)
}

fn cloud_mcp_asset_transfer_status_is_active(status: &str) -> bool {
    matches!(
        status,
        "queued"
            | "preparing"
            | "prepared"
            | "uploading"
            | "downloading"
            | "verifying"
            | "committing"
            | "warming_cache"
    )
}

pub(crate) fn cloud_mcp_forward_agent_get_asset_root(
    _repo_path: Option<&str>,
    _workspace_id: Option<&str>,
    input: &Value,
) -> Result<Value, String> {
    let asset_id = cloud_mcp_payload_text(input, &["asset_id", "id"])
        .map(|value| cloud_mcp_sanitize_asset_id(&value))
        .unwrap_or_else(|| format!("asset-{}", uuid::Uuid::new_v4()));
    let filename = cloud_mcp_asset_filename_for_input(input, "asset");
    let raw_group = cloud_mcp_payload_text(input, &["group", "category", "source_kind"])
        .unwrap_or_else(|| "generated".to_string());
    if diffforge_asset_group_is_untracked(&raw_group) {
        return Err(
            "get_asset_root cannot create paths inside the untracked scratch folder.".to_string(),
        );
    }
    let group = cloud_mcp_asset_folder_from_value(input, "generated");
    let asset_root = cloud_mcp_managed_asset_root()?;
    let asset_dir = cloud_mcp_asset_dir_for_folder(&asset_root, &group, &asset_id);
    fs::create_dir_all(&asset_dir)
        .map_err(|error| format!("Unable to create managed asset directory: {error}"))?;
    let local_path = cloud_mcp_available_asset_download_path(&asset_dir, &filename);
    Ok(json!({
        "kind": "asset_root",
        "source": "managed_asset_library",
        "asset_id": asset_id,
        "asset_root": asset_root.display().to_string(),
        "folder": group,
        "group": group,
        "asset_folder": group,
        "local_path": local_path.display().to_string(),
        "path": local_path.display().to_string(),
        "relative_path": local_path.strip_prefix(&asset_root).ok().map(|path| path.display().to_string()).unwrap_or_default(),
        "instruction": "Write generated or reusable media under assetRoot, then call upload_asset with the written path.",
    }))
}

fn cloud_mcp_asset_registration_payload_from_row(reason: &str, row: &Value) -> Value {
    let mut payload = cloud_mcp_asset_payload_base(reason);
    if let Some(object) = payload.as_object_mut() {
        cloud_mcp_asset_wire_payload_text(object, "asset_id", row, &["asset_id", "id"]);
        cloud_mcp_asset_wire_payload_text(object, "name", row, &["name", "filename", "file_name"]);
        cloud_mcp_asset_wire_payload_text(object, "kind", row, &["kind", "asset_kind"]);
        cloud_mcp_asset_wire_payload_text(object, "mime_type", row, &["mime_type"]);
        cloud_mcp_asset_wire_payload_i64(object, "size_bytes", row, &["size_bytes"]);
        cloud_mcp_asset_wire_payload_text(object, "sha256", row, &["sha256"]);
        cloud_mcp_asset_wire_payload_text(object, "local_status", row, &["local_status"]);
        if let Some(value) = row.get("local_available").and_then(Value::as_bool) {
            object.insert("local_available".to_string(), json!(value));
        }
        if let Some(metadata) = row.get("metadata") {
            object.insert(
                "metadata".to_string(),
                cloud_mcp_sanitized_asset_metadata(Some(metadata.clone())),
            );
        }
        let folder = cloud_mcp_asset_folder_from_value(row, CLOUD_MCP_ASSET_FOLDER_DEFAULT);
        object.insert("folder".to_string(), json!(folder.clone()));
        object.insert("group".to_string(), json!(folder.clone()));
        object.insert("asset_folder".to_string(), json!(folder.clone()));
        object.insert("asset_group".to_string(), json!(folder));
        cloud_mcp_asset_wire_payload_text(object, "source_kind", row, &["source_kind", "source"]);
        object.insert("asset_scope".to_string(), json!("account"));
        object.insert("library_scope".to_string(), json!("account"));
    }
    cloud_mcp_asset_attach_sync_identity(&mut payload);
    payload
}

fn cloud_mcp_asset_local_deleted_registration_payload(reason: &str, row: &Value) -> Value {
    let mut payload = cloud_mcp_asset_registration_payload_from_row(reason, row);
    let now = cloud_mcp_rfc3339_now();
    if let Some(object) = payload.as_object_mut() {
        if cloud_mcp_asset_normalized_status(reason) == "asset-local-deleted"
            && (cloud_mcp_asset_cloud_copy_available(row)
                || cloud_mcp_asset_remote_copy_available(row))
        {
            object.insert("delete_scope".to_string(), json!("device_local"));
            object.insert("preserve_cloud_metadata".to_string(), json!(true));
            object.insert("cloud_copy_unchanged".to_string(), json!(true));
        }
        object.insert("local_status".to_string(), json!("local_deleted"));
        object.insert("local_available".to_string(), json!(false));
        object.insert("local_path".to_string(), json!(""));
        object.insert("local_deleted_at".to_string(), json!(now.clone()));
    }
    cloud_mcp_asset_attach_sync_identity(&mut payload);
    payload
}

fn cloud_mcp_forward_agent_asset_transfer_status(
    repo_path: Option<&str>,
    workspace_id: Option<&str>,
    base_url_override: Option<&str>,
    input: &Value,
    direction: &str,
    reason: &str,
) -> Result<Value, String> {
    let _ = (repo_path, workspace_id, base_url_override);
    let limit = cloud_mcp_payload_i64(input, &["limit"])
        .unwrap_or(100)
        .clamp(1, CLOUD_MCP_ASSET_LIBRARY_MAX_ROWS as i64) as usize;
    let library = cloud_mcp_asset_library_from_file(CLOUD_MCP_ASSET_LIBRARY_MAX_ROWS);
    Ok(cloud_mcp_asset_transfer_status_from_local(
        input, direction, reason, library, limit,
    ))
}

fn cloud_mcp_asset_transfer_status_from_local(
    input: &Value,
    direction: &str,
    reason: &str,
    library: Value,
    limit: usize,
) -> Value {
    let asset_ids = cloud_mcp_todo_mirror_text_values(input, &["asset_id", "asset_ids"]);
    let transfer_ids = cloud_mcp_todo_mirror_text_values(input, &["transfer_id", "transfer_ids"]);
    let device_ids =
        cloud_mcp_todo_mirror_text_values(input, &["device_id", "device_ids", "machine_id"]);
    let status = cloud_mcp_payload_text(input, &["status", "transfer_status"])
        .map(|value| value.trim().to_ascii_lowercase())
        .or_else(|| {
            cloud_mcp_payload_bool(input, &["active_only"], false).then(|| "active".to_string())
        });
    let mut transfers = library
        .get("transfers")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    transfers.retain(|transfer| {
        if cloud_mcp_asset_row_text(transfer, &["direction"]).to_ascii_lowercase() != direction {
            return false;
        }
        let transfer_asset_id = cloud_mcp_asset_row_text(transfer, &["asset_id"]);
        if !asset_ids.is_empty() && !asset_ids.contains(&transfer_asset_id) {
            return false;
        }
        let transfer_id = cloud_mcp_asset_row_text(transfer, &["transfer_id", "id"]);
        if !transfer_ids.is_empty() && !transfer_ids.contains(&transfer_id) {
            return false;
        }
        if !device_ids.is_empty() {
            let transfer_device_id =
                cloud_mcp_asset_row_text(transfer, &["device_id", "machine_id"]);
            if !device_ids.contains(&transfer_device_id) {
                return false;
            }
        }
        if let Some(status) = status.as_deref() {
            let row_status = cloud_mcp_asset_row_text(transfer, &["status"]).to_ascii_lowercase();
            if status == "active" {
                if !cloud_mcp_asset_transfer_status_is_active(&row_status) {
                    return false;
                }
            } else if row_status != status {
                return false;
            }
        }
        true
    });
    transfers.truncate(limit.clamp(1, CLOUD_MCP_ASSET_LIBRARY_MAX_ROWS));
    let transfer_asset_ids = transfers
        .iter()
        .map(|transfer| cloud_mcp_asset_row_text(transfer, &["asset_id"]))
        .filter(|asset_id| !asset_id.is_empty())
        .collect::<HashSet<_>>();
    let mut assets = library
        .get("items")
        .or_else(|| library.get("assets"))
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    assets.retain(|asset| {
        let asset_id = cloud_mcp_asset_row_text(asset, &["asset_id", "id"]);
        (!asset_ids.is_empty() && asset_ids.contains(&asset_id))
            || transfer_asset_ids.contains(&asset_id)
    });
    let mut response = cloud_mcp_asset_library_response_from_rows(assets, transfers, None);
    if let Some(object) = response.as_object_mut() {
        object.insert("kind".to_string(), json!("asset_library_status"));
        object.insert("source".to_string(), json!("local_asset_library"));
        object.insert("status_source".to_string(), json!("local_rust_mirror"));
        object.insert("reason".to_string(), json!(reason));
        object.insert("direction".to_string(), json!(direction));
    }
    response
}

